-- 全量清洗执行脚本（带回滚备份）
-- 生成日期：2026-03-27
-- 用途：先备份 herbs 表，再执行清洗更新

-- 0) 防重复执行：若备份表已存在则中止
do $$
begin
  if exists (select 1 from pg_tables where schemaname = 'public' and tablename = 'herbs_backup_20260327_clean_v1') then
    raise exception '备份表 herbs_backup_20260327_clean_v1 已存在，请先确认是否需要回滚或改用新版本备份名。';
  end if;
end $$;

-- 1) 建立全表快照（用于回滚）
create table public.herbs_backup_20260327_clean_v1 as
select * from public.herbs;

-- 2) 执行清洗
begin;
update herbs set taste='味辛；平；无毒。', channel='入肝、脾、胃经。', effect='①治一切痞块癥瘕，食次血气成积者：阿魏五钱，白芥子四两，白术三两，三棱、莪术各二两。后四味俱炒燥，研为细末，以阿魏热酒溶化，和入为丸，黍米大。每早晚各服二钱，白汤下。妇人病此，本方加当归、川芎、干漆，俱酒炒各-两。（《何日中手集》） ②治痞：阿魏、乳香、没药、芒硝各二两，俱研细，听用。外用大黄二两，白芥子三两，木鳖子二十一个（去壳），穿山甲、肉桂、川独活各一两五钱，乱发二两；用香油四十两，煎黑去渣，待油冷凝，入锅内，乘油冷时加水飞净细炒燥黄丹二十两，将油煎滚，用铁箸不住手搅，以黄丹黑熟，软硬得所，提起，将凝，加入阿魏、乳、没、硝四味细末在内搅匀，即成膏矣。凡贴膏药时，先用芒硝研细，随患处铺半指厚，以纸盖定，用热熨良久，如硝耗，再加熨之，二时许，方贴膏药。（《何日中手集》） ③治小儿食积，腹如蜘蛛状，肚痛，小便白浊：阿魏（醋浸一宿，研如泥）半两，黄连（炒）半两，花碱（研如粉）三钱，山查肉一两，连翘一两半，半夏（皂角浸一宿）一两。上为末，炒神曲糊丸，如萝卜子大。每服二十丸，空心米饮下。（《医学纲目》阿魏丸） ④治气积，肉积，心腹膨满，结块疼痛，或引胁肋疼痛，或痛连背膂，不思饮食：木香（不见火）、槟榔各半两，胡椒、阿魏（用醋化开）各二钱半。上为细末，用阿魏膏子，并粟米饭，杵和为丸，如桐子大。每服四十丸，不拘时候，生姜皮汤下。（《济生方》阿魏丸） ⑤治疟疾：胭脂、阿魏各一大豆许，同研。以大蒜肉研和为膏，用大核桃一枚，劈开去仁，取一片以药膏子填在核内。疟发时，用药核桃覆在手虎口上，男左女右，令药着肉，以绯帛系定，经宿乃去。（《圣济总录》扼虎膏）' where id=1642; -- 阿魏
update herbs set taste='味甘；性平。', channel='入肺、肝、肾经。', effect='①治小儿肺虚、气粗喘促：阿胶一两五钱（麸炒），黍粘子（炒香）、甘草（炙）各二钱五分，马兜铃五钱（焙），杏仁七个（去皮、尖，炒），糯米一两（炒）。上为末，每服一、二钱，水一盏，煎至六分，食后温服。（《小儿药证直诀》阿胶散，又名补肺散） ②治久咳嗽：阿胶（炙燥）一两，人参二两。上二味，捣罗为散，每服三钱匕，豉汤一盏，入葱白少许，同煎三沸，放温，遇嗽时呷三、五呷；依前温暖，备嗽时再呷之。（《圣济总录》阿胶饮） ③治大衄，口耳皆出血不止：阿胶半两（捣碎炒令黄燥），蒲黄一两。上药捣细罗为散，每服二钱，以水一中盏，入生地黄汁二合，煎至六分，不计时候，温服。（《圣惠方》） ④治便血如小豆汁：阿胶（炙令燥），赤芍药、当归（切，焙）各一两，甘草（炙，锉）半两。上四味，粗捣筛，每服五钱匕，水一盏半，入竹叶二七片，同煎至八分，去滓，食前温服。（《圣济总录》阿胶芍药汤） ⑤治妇人漏下不止：阿胶、鹿茸各三两，乌贼骨、当归各二两，蒲黄一两。上五味治下筛。空心酒服方寸匕，日三，夜再服。（《千金方》） ⑥治妇人有漏下者，有半产后因续下血，都不绝者，有妊娠下血者，假令妊娠腹中痛，为胞阻：芎藭、阿胶、甘草各二两，艾叶、当归各三两，芍药四两，干地黄六两。上七味，以水五升，清酒三升，合煮取三升，去滓，内胶令消尽，温服一升，日三服，不差更作。（《金匮要略》胶艾汤） ⑦治损动母（胎），去血腹痛：阿胶二两（炙），艾叶二两。上二味，以水五升，煮取二升半，分三服。（《小品方》胶艾汤） ⑧治妊娠腹痛，下痢不止：黄连、石榴皮、当归各三两，阿胶二两（炙），艾一两半。上，水六升，煎至二升，分为三服。忌生冷肥腻。（《经效产宝》） ⑨治产后下痢：粳米一合，蜡（如鸡子）一枚，阿胶、当归各六分，黄连十分。上五味切，以水六升半先煮米，令蟹目沸。去米内药煮，取二升，入阿胶、蜡消烊，温分三、二服。（《僧深集方》胶蜡汤） ⑩治产后虚羸，大便秘涩：阿胶（碎炒）、枳壳（浸去瓤，麸炒）各二两，滑石（研飞为衣）半两。上为末，炼蜜丸如梧桐子大。每服二十丸，温水下，半日来未通再服。（《局方》阿胶枳壳丸） ⑾治老人虚人大便秘涩：阿胶（炒）二钱，连根葱白三片，蜜二匙，新水煎，去葱，入阿胶、蜜溶开，食前温服。（《仁斋直指方》胶蜜汤） ⑿治摊缓风及诸风手足不遂，腰脚无力者：驴皮胶炙令微起，先煮葱豉粥一升别贮；又以水一升，煮香豉二合，去滓，内胶更煮六、七沸，胶烊如饧，顿服之；及暖吃前葱豉粥任意多少。如冷吃，令人呕逆。（《广济方》）', tips='脾胃虚弱者慎服。 ①《本草经集注》：得火良，畏大黄。 ③《本草经疏》：性粘腻，胃弱作呕吐者勿服；脾胃虚，食不消者亦忌之。 ④《本草汇言》：胃弱呕吐有寒痰留饮者当忌之。 ⑤《本草备要》：泻者忌用。' where id=1643; -- 阿胶
update herbs set taste='辛苦，温。', channel='入心、肝、脾经。', effect='①治大人小儿卒中风，恶气：安息香一钱，鬼臼二钱，犀角八分，牛黄五分，丹砂、乳香、雄黄各一钱二分。俱研极细末，石菖蒲。生姜各一钱，泡汤调服五分。（《方脉正宗》） ②治卒然心痛，或经年频发：安息香研末，沸汤服半钱。（《世医得效方》） ③治寒湿冷气，中霍乱阴证者：安息香一钱（为末），人参、制附子各二钱。煎汤调服。（《本草汇言》） ④治小儿肚痛，曲脚而啼：安息香酒蒸成膏；沉香、木香、丁香、藿香、八角茴香各三钱，香附子、缩砂仁、炙甘草各五钱，为末；以膏和炼蜜丸，芡子大.每服一钱，紫苏汤送下。（《全幼心鉴》安息香丸） ⑤治妇人产后血晕，血胀，口噤垂死者：安息香一钱，五灵脂（水飞净末）五钱。共和匀，每服一钱，炒姜汤调下。（《本草汇言》） ⑥治历节风痛：精猪肉四两，切片，裹安息香二两，以瓶盛灰，大火上著一铜版片隔之，安息香于上烧之，以瓶口对痛处熏之，勿令透气。（《圣惠方》）' where id=1644; -- 安息香
update herbs set taste='味辛；苦；性温。', channel='入脾、肝、肾经。', effect='①治卒心痛：白艾成熟者三升，以水三升，煮取一升，去滓，顿服之。若为客气所中者，当吐出虫物。（《补缺肘后方》） ②治脾胃冷痛：白艾末煎汤服二钱。（《卫生易简方》） ③治肠炎、急性尿道感染、膀胱炎：艾叶二钱，辣蓼二钱，车前一两六钱。水煎服，每天一剂，早晚各服一次。（江苏徐州《单方验方新医疗法选编》） ④治气痢腹痛，睡卧不安：艾叶（炒）、陈橘皮（汤浸去白，焙）等分。上二味捣罗为末，酒煮烂饭和丸，如梧桐子大。每服二十丸，空心。（《圣济总录》香艾丸） ⑤治湿冷下痢脓血，腹痛，妇人下血：干艾叶四两（炒焦存性），川白姜一两（炮）。上为末，醋煮面糊丸，如梧子大。每服三十丸，温米饮下。（《世医得效方》艾姜汤） ⑥治忽吐血一、二口，或心衄，或内崩：熟艾三鸡子许，水五升，煮二升服。（《千金方》） ⑦治鼻血不止：艾灰吹之，亦可以艾叶煎服。（《圣惠方》） ⑧治粪后下血：艾叶、生姜。煎浓汁，服三合。（《千金方》） ⑨治妇人崩中，连日不止：熟艾如鸡子大，阿胶（炒为末）半两，干姜一钱。水五盏，先煮艾、姜至二盏半，入胶烊化，分三服，空腹服，一日尽。（《养生必用方》） ⑩治功能性子宫出血，产后出血：艾叶炭一两，蒲黄、蒲公英各五钱。每日一剂，煎服二次。（内蒙古《中草药新医疗法资料选编》） ⑾治妇人白带淋沥：艾叶（杵如绵，扬去尘末并梗，酒煮一周时）六两，白肃、苍术各三两（俱米泔水浸，晒干炒），当归身（酒炒）二两，砂仁一两。共为末，每早服三钱，白汤调下。（《本草汇言》） ⑿治妊娠卒眙动不安，或但腰痛，或胎转抢心，或下血不止：艾叶一鸡子大，以酒四升，煮取二升，分为二服。（《肘后方》） ⒀治产后腹痛欲死，因感寒起者：陈蕲艾二斤，焙干，捣铺脐上，以绢覆住，熨斗熨之，待口中艾气出，则痛自止。（《杨诚经验方》） ⒁治盗汗不止：熟艾二钱，白茯神三钱，乌梅三个。水一钟，煎八分，临卧温服。（《纲目》） ⒂治痈疽不合，疮口冷滞：以北艾煎汤洗后，白胶熏之。（《仁斋直指方》） ⒃治头风面疮，痒出黄水：艾二两，醋一升，砂锅煎取汁，每薄纸上贴之，一日二、三上。（许国桢《御药院方》） ⒃治湿疹：艾叶炭、枯矾、黄柏等分。共研细末，用香油调膏，外敷。（内蒙古《中草药新医疗法资料选编》）', tips='阴虚血热者慎用。 ②《本草备要》：血热为病者禁用。 ③《本经逢原》：阴虚火旺，血燥生热，及宿有失血病者为禁。' where id=1645; -- 艾叶
update herbs set effect='①治鹅口疮：半春莲根三至五钱，水煎服。 ②治无名肿毒、毒蛇咬伤：鲜半春莲根适量，捣烂外敷。 ③治跌打损伤、骨折：鲜半春莲根一至二两，捣烂外敷。', tips='清热；消肿；解毒。主虚火牙痛；鹅口疮；无名肿毒；毒蛇咬伤；跌打损伤；风湿痹痛' where id=1646; -- 半春莲
update herbs set alias='土狗尾，长穗狸尾草，兔狗尾，猫公树', effect='①治丝虫病：布狗尾二两，水煎冲酒少许一次服。连服十余天。（《岭南草药志》） ⑦治疟疾：布狗尾二至三两，煎水和白糖少许冲服，日一次，连服数天。孕妇禁用。（《岭南草药志》）', tips='止血，解热，杀虫。治吐血，尿血，丝虫病，疟疾。 ①《岭南采药录》：清热消滞，理咳嗽，水煎服。 ②《岭南草药志》：解热，杀虫。治丝虫病，疟疾。 ③广州空军《常用中草药手册》：治吐血，咯血，尿血，刀伤出血，小儿疳积，感冒。' where id=1647; -- 布狗尾
update herbs set taste='苦辛，平，有毒。', channel='归肺；肝经。', effect='①治疔疮：八角莲二钱，蒸酒服；并用须根捣烂敷患处。（《贵阳民间药草》） ②治体虚弱，痨伤咳嗽，虚汗盗汗：八角莲三钱，蒸鸽子或炖鸡或炖猪肉半斤服。（《贵阳民间药草》） ③治瘰疬：八角莲一至二两，黄酒二两。加水适量煎服。（《福建民间草药》） ④治肿毒初起：八角莲加红糖或酒糟适量，共捣烂敷贴，日换两次。（《福建民间草药》） ⑤治带状疱疹：八角莲根研末，醋调涂患处。（《广西中草药》） ⑥治单双蛾喉痛：八角莲一钱，磨汁吞咽。（《广西中药志》） ⑦治痰咳：八角莲四钱，猪肺二至四两，糖适量。煲服。（《广西中药志》） ⑧治跌打损伤：八角莲根一至三钱，研细末，酒送服，每日二次。（《江西草药》） ⑨治毒蛇咬伤：㈠八角莲三至五钱，捣烂，冲酒服，渣敷伤处周围。（《广西中草药》）㈡八角莲根白酒磨涂患处；亦可内服，每服二钱。对神经性毒素，可取八角莲根五节，用75％酒精7毫升，浸泡七天，取浸出液一至二毫升，注入伤口内。（《江西草药》）' where id=1648; -- 八角莲
update herbs set taste='苦甘，凉。', channel='入肺经。', effect='①治肺痿：白及、阿胶、款冬、紫苑等分。水煎服。（《医学启蒙》白及散） ②治肺痿肺烂：猪肺一具，白及片一两，将猪肺挑去血筋血膜，洗净，同白及入瓦罐，加酒煮热，食肺饮汤，或稍用盐亦可。或将肺蘸白及末食更好。（《喉科心法》白及肺） ③治咯血：白及一两，枇杷叶（去毛，蜜炙）、藕节各五钱。上为细末，另以阿胶五钱，锉如豆大，蛤粉炒成珠，生地黄自然汁调之，火上炖化，入前药为丸如龙眼大。每服一丸，噙化。（《证治准绳》白及枇杷丸） ④治肺热吐血不止：白及研细末，每服二钱，白汤下。（《本草发明》） ⑤治疔疮肿毒：白及末半钱，以水澄之，去水，摊于厚纸上贴之。（《袖珍方》） ⑥治一切疮疖痈疽：白及、芙蓉叶、大黄、黄柏，五倍子。上为末，用水调搽四周。（《保婴撮要》铁箍散） ⑦治发背搭手：白及五钱（炙，末），广胶一两（烊化）。和匀，敷患处，空一头出气，以白蛰皮贴之。（《卫生鸿宝》白及膏） ⑧治瘰疬脓汁不干：白及、贝母、净黄连各半两，轻粉三十贴。前三味，锉焙为末，仍以轻粉乳钵内同杵匀，抄一钱至二钱，滴油调擦患处，用时先以槲皮散煮水侯温，洗净拭干，方涂药。（《活幼心书》白及散） ⑨治跌打骨折：酒调白芨末二钱服。（《永类铃方》） ⑩治刀斧损伤肌肉，出血不止：白及，研细末掺之。（《本草汇言》） ⑾治汤火伤灼：白及末，抽调敷。（《济急仙方》） ⑿治手足皲裂：白及末，水凋塞之，勿犯水。（《济急仙方》） ⒀治妇人子藏挺出：乌头（炮）、白及各四分。上二味捣散，取方寸匕，以绵裹内阴中，令入三寸，腹内热即止。日一度著，明晨仍须更著，以止为度。（《广济方》） ⒁治鼻渊：白及，末，酒糊丸。每服三钱，黄酉下，半月愈。（《外科大成》白及丸） ⒂治产后伤脬，小便淋敷不止：白及、凤凰庆，桑螺娟等分，入猪脬内，煮烂食之。（《梅氏验方新编》） ⒃治心气疼痛：白及、石榴皮各一钱。为末，炼蜜丸黄豆大，每服三丸，艾醋汤下。（《生生编》）', tips='外感咳血，肺痈初起及肺胃有实热者忌服。 ①《本草经疏》：痈疽已溃，不宜同苦寒药服。 恶理石。畏李核，杏人。 ③《蜀本草》：反乌头。' where id=1649; -- 白及
update herbs set taste='甘苦淡，凉。', channel='入肺、脾经。', effect='①治阴虚火炎，咳嗽无痰，骨蒸劳热，肌皮枯燥，口苦烦渴等证：真北沙参、麦门冬、知母、川贝母、怀熟地、鳖甲，地骨皮各四两。或作丸，或作膏，每早服三钱，白汤下。（《卫生易简方》） ②治一切阴虚火炎，似虚似实，逆气不降，消气不升，烦渴咳嗽，胀满不食：真北沙参五钱。水煎服。（《林仲先医案》）' where id=1650; -- 北沙参
update herbs set taste='辛甘，微温。', channel='入肺经。', effect='①治久患暇呷咳嗽，喉中作声，不得眠：白前，捣为末，温酒调二钱匕，服。（《梅师集验方》） ②主治肺实喘满，咳嗽，多痰。胃脘疼痛。白前100克、白酒0.5升。将白前捣成粗末，用白纱布袋盛之，置于净器中，入白酒浸泡，封口；7日后开启，去掉药袋，澄清备用。每日三次，每次10~15毫升，空心温饮。（白前酒《肘后备急方》） ③治久嗽兼唾血：白前三两，桑白皮、桔梗各二两，甘草一两（炙）。上四味切，以水二大升，煮取半大升，空腹顿服。若重者，十数剂。忌猪肉、海藻、菘菜。（《近效方》） ④治咳逆上气，身体浮肿，短气胀满，昼夜不得平卧，吼中如水鸣声：白前、紫菀、半夏、大蓟各6g。为粗末，水煎，分3次服。（白前汤《备急千金要方》） ⑤治疟母（脾肿大）：白前五钱。水煎服。（《福建中草药》） ⑥治胃脘痛，虚热痛：白前和重阳木根各五钱。水煎服。（《福建中草药》） ⑦治跌打胁痛：白前五钱，香附三钱，青皮一钱。水煎服。（《福建中草药》） ⑧治小儿疳积：白前、重阳木或兖州卷柏全草各三钱。水炖服。（《福建中草药》）' where id=1651; -- 白前
update herbs set taste='味辛；苦；性温。', channel='入肾经。', effect='①治脾肾虚弱，全不进食：破故纸四两（炒香），肉豆蔻二两（生）。上为细末，用大肥枣四十九个，生姜四两，切片同煮，枣烂去姜，取枣剥去皮核用肉，研为膏，入药和杵，丸如梧桐子大。每服三十丸，盐汤下。（《本事方》二神丸） ②治赤白痢及水泻：破故纸一两（炒香熟），罂粟壳四两（去穰、顶蒂，新瓦上煿燥）。上二味，为细末，炼蜜为丸如弹子大。每服一丸，水一盏化开，姜二片，枣一个，煎取七分，如小儿分作四服。（《百一选方》） ③治小儿遗尿：破故纸一两（炒）。为末，每服一钱，热汤调下。（《补要袖珍小儿方论》破故纸散） ④治男子女人五劳七伤，下元久冷，乌髭鬓，一切风病，四肢疼痛，驻颜壮气：补骨脂一斤，酒浸一宿，放干，却用乌油麻一升和炒，令麻子声绝即簸去，只取补骨脂为末，醋煮面糊丸如梧子大。早晨温酒、盐汤下二十丸。（《经验后方》） ⑤治下元虚败，脚手沉重，夜多盗汗。此药壮筋骨，益元气：补骨脂四两（炒香），菟丝子四两（酒蒸），胡桃肉一两（去皮），乳香、没药、沉香（各研）三钱半。炼蜜丸如梧子大。每服二、三十丸，空心盐汤温酒任下，自夏至起，冬至止，日一服。（《局方》补骨脂丸） ⑥定心，补肾：破故纸二两（隔纸炒令香熟），白茯苓一两（去皮）。上二味为细末，用没药半两，捶破，以无灰酒浸，高没药一指许，候如稠饧状，搜前二味，丸如梧桐子大。每服三、五十丸，随食汤下；如没药性燥难丸，再以少酒糊同搜丸，食前服。（《魏氏家藏方》返精丸） ⑦治肾气虚冷，小便无度：破故纸（大者盐炒）、茴香（盐炒）。上等分为细末，酒糊为丸如梧桐子大。每服五十丸或百丸，空心温酒、盐汤下。（《魏氏家藏方》破故纸丸） ⑧治打坠腰痛，瘀血凝滞：破故纸（炒）、茴香（炒）、辣桂等分。为末，每热酒服二钱。（《仁斋直指方》） ⑨治腰疼：破故纸为末，温酒下三钱匕。（《经验后方》） ⑩治肾气虚弱，风冷乘之；或血气相搏，腰痛如折，起坐艰难，俯仰不利，转侧不能；或因劳役过度，伤于肾经；或处卑湿，地气伤腰；或坠堕伤损，或风寒客搏，或气滞不散，皆令腰痛；或腰间似有物重坠，起坐艰辛者，悉能治之：胡桃（去皮膜）二十个，蒜（熬膏）四两，破故纸（洒浸炒）八两，杜仲（去皮，姜汁浸炒）十六两。上为细末，蒜膏为丸。每服三十丸，空心温酒下；妇女淡醋汤下。常服壮筋骨，活血脉，乌髭须，益颜色。（《局方》青娥丸） ⑾治妊娠腰痛，状不可忍：破故纸不以多少，瓦上炒香熟，为末，嚼胡桃肉一个，空心温酒调下三钱。（《伤寒保命集》通气散） ⑿治牙痛日久，肾虚也：补骨脂二两，青盐半两。炒，研，擦之。（《御药院方》）' where id=1652; -- 补骨脂
update herbs set taste='味苦；性寒。', channel='入大肠、肝、胃经。', effect='①治热痢下重：白头翁二两，黄连、黄柏、秦皮各三两。上四味，以水七升，煮取二升，去滓。温服一升，不愈更服。（《金匮要赂》白头翁汤） ②治休息痢，日夜不止，腹内冷痛：白头翁一两，黄丹二两（并白头翁入铁瓶内烧令通赤），干姜一两（炮裂，锉），莨菪子半升（以水淘去浮者，煮令芽出，曝干，炒令黄黑色），白矾二两（烧令汁尽）。上件药，捣罗为末，以醋煮面糊和丸，如梧桐子大。每服食前，以粥饮下十丸。（《圣惠方》白头翁丸） ③治冷劳泄痢及妇人产后带下：白头翁（去芦头）半两，艾叶二两（微炒）.上二味为末，用米醋一升，入药一半，先熬成煎，入余药末，和丸梧桐子丸每服三十丸，空心食前，米饮下。（《圣济总录》白头翁丸） ④治产后下利虚极：白头翁、甘草、阿胶各二两，秦皮、黄连、柏皮各三两.上六味以水七升，煮取二升半，内胶令消尽。分温三服。（《金匮要略》白头翁加甘草阿胶汤） ⑤治小儿热毒下痢如鱼脑：白头翁半两，黄连二两半（去须，微炒），酸石榴皮一两（微炙，锉）。上件药，捣租罗为散，每服一钱，以水一小盏，煎至五分，去滓。不计时侯，量儿大小，加减服之。（《圣惠方》白头翁散） ⑥治温疟发作，昏迷如死：白头翁一两，柴胡、半夏、黄芩、槟榔各二钱，甘草七分。水煎服。（《本草汇言》） ⑦治外痔肿痛：白头翁草以根捣涂之。（《卫生易简方》） ⑧治瘰疬延生，身发寒热：白头翁二两，当归尾、牡丹皮、半夏各一两。炒为末，每服三钱，白汤调下。（《本草汇言》） ⑨疗少小阴颓：生白头翁根，不问多少，捣之，随病处以敷之，一宿当作疮，二十日愈。（《小品方》）' where id=1653; -- 白头翁
update herbs set taste='苦辛，微温，有毒。', effect='①治水肿黄疸：白屈菜、蒲公英、商陆、臭草根，茵陈。水煎服。（《四川中药志》） ②治肠胃疼痛：白屈菜、丁香、乌贼骨、浙贝母、胆南星、冬瓜仁。水煎服。（《四川中药志》） ③治顽癣：鲜白屈菜用50％的酒精浸泡，擦患处。（《辽宁常用中草药手册》） ④治疮肿：鲜白屈菜捣烂敷患处。（《辽宁常用中草药手册》） ⑤治胃痛，泻痢腹痛，咳嗽：白屈菜五分至二钱，水煎服。（《东北常用中草药手册》） ⑥治稻田皮炎，毒虫咬伤，疥癣：白屈菜捣烂外敷或制成浸膏涂患处。（《东北常用中草药手册》）' where id=1654; -- 白屈菜
update herbs set taste='酸涩，平。', effect='①治咽部梗塞感（但无阳性体征）：绿萼梅二钱，橘饼二个。煎服。（苏医《中草药手册》） ②治唇上生疮：白梅瓣贴之，如开裂出血者即止。（《赤水玄珠》） ③治瘰疬：鸡蛋开一孔，入绿萼梅花将开者七朵，封口，饭上蒸热，去梅花食蛋，每日一枚，股七日。（《纲目拾遗》） ④预稀痘疹：每年腊月清晨，摘带露绿萼梅蕊一百朵，加上白糖，捣成小饼，令食之。（王玷桂《不药良方》） ⑤治疽已出未出，不起不发，隐在皮肤，并治麻症斑症：梅花一两，桃仁、辰砂、甘草各二钱，丝瓜五钱。为末，每服五分，参苏汤下。（《赤水玄珠》）', tips='舒肝，和胃，化痰。治梅核气，肝胃气痛，食欲不振，头晕，瘰疬。 ①《本草原始》：清头目，利肺气，去痰壅滞上热。 ②《百草镜》：开胃散郁。煮粥食，助清阳之气上升。 ③《纲目拾遗》：安神定魂，解痘毒。 ④《饮片新参》：红梅花清肝解郁，治头目痛；绿萼梅乎肝和胃，止脘痛，头晕，进饮食。' where id=1655; -- 白梅花
update herbs set effect='1．治久嗽咯血而致的肺痿，吐白涎，胸膈满闷，食少：白扁豆、生姜各15克，枇杷叶、半夏、人参、白术各0.3克,白茅根1克.上为粗末,水煎去渣,调槟榔末3克,分4次服。（《普济本事方》白扁豆散） 2．治水肿：扁豆32克。炒黄，研成粉，每早、午、晚各食前服，大人9克，小儿3克，灯心汤调。（《本草汇言》） 3．治赤白带下：白扁豆。炒为末，用米饮，每服6克。（《永类铃方》） 4．炒扁豆健脾化湿。用于脾虚泄泻，白带过多。', tips='健脾，化湿，消暑。主脾虚生湿，食少便溏，白带过多，暑湿吐泻，烦渴胸闷。用于脾胃虚弱，食欲不振，大便溏泻，白带过多，暑湿吐泻，胸闷腹胀。 炒扁豆：健脾化湿。用于脾虚泄泻，白带过多。' where id=1656; -- 白扁豆
update herbs set taste='苦辛；凉；小毒。', channel='脾；肺；肾经。', effect='①治咽喉肿痛：白药一两（捣罗为末），龙脑一分。同研令匀，炼蜜和丸，芡子大，常含一丸咽津。（《圣惠方》龙脑丸） ②治喉中热塞肿痛，散痰散血：白药、朴硝。为末，以小管吹入喉。（《仁斋直指方》白药散） ③治风痰上壅，咽喉不利：白药三两，黑丑五钱，同炒香，去黑丑一半为末，防风末三两，和匀，每茶服一钱。（《圣惠方》） ④治衄血不止：红枣、白药（各烧存性）等分。为末，糯米饮眼。或煎汤洗鼻，频频缩药令入。（《经验良方》） ⑤治衄血汗血：白药二两半，生地黄汁三合，生藕汁一合，生姜汁少许。上四味，捣白药为末，先煎三物汁令沸，每以半盏入熟水一合，白药末二钱匕，搅匀，食后温饮之。（《圣济总录》白药散） ⑥治心气痛，解热毒：白药根、野猪尾。二味洗净，去粗皮，焙干，等分，捣筛，酒调服钱匕。（《本草图经》） ⑦治诸疮痈肿不散：生白药根，捣烂敷贴，干则易之。无鲜生者，用末水调涂之亦可。（《本草图经》） ⑧治瘰疬疮：白药子不拘多少，为末，临卧冷米饮调下一钱。（《卫生家宝方》白药散） ⑨治一切天行：白药研如面，浆水一大盏，（冷调二钱）空腹顿服之，便仰卧。一食顷，候心头闷乱，或恶心，腹内如车鸣，疞刺痛，良久当有吐利数行，勿怪。欲服药时，先同煮浆水粥，于井中悬著待冷，若吐利过度，即吃冷粥一碗止之，不吃即困人。（《海上集验方》） ⑩治疳眼赤烂，目生翳膜，内外障疾，并小儿吐痢：白药子一两，甘草半两。上为末，用猪肝一叶，批开掺药五钱，水一大盏，煮熟，食后服。（《宣明论方》白药子散） ⑾安胎：白药子一两，白芷五钱。上为细末，每服二钱，紫苏汤调下。或胎热心烦闷，入砂糖少许煎。（《普济方》铁军散） ⑿治妊娠伤寒护胎：白药子不拘多少为末，用鸡子清调摊于纸上，可碗来大，贴在脐下胎存生处。干即以温水润之。（《经验后方》） ⒀治诸骨哽咽：白药锉细，煎米醋细细咽下，在上即吐出，在下即下出。（《经验良方》） ⒁治中暑腹痛：山乌龟鲜根一至二钱。去粗皮，嚼烂，冬酒送服。（《江西草药》） ⒂治胃及十二指肠溃疡：山乌龟根二斤，甘草一斤，研末，每日三次，每次一钱，开水送服。（《湖南药物志》） ⒃治肺脓疡：山乌龟根磨酒服，每次服二至三匙。（《湖南药物志》） ⒄治肝硬化腹水：山乌龟根三钱（用老糠炒制），车前五钱，过路黄、白花蛇舌草、瓜子金、丹参根各一两。水煎服。（《江西草药》） ⒅治风湿性关节炎：山乌龟根一两，蜈蚣兰、活血丹各五钱。黄酒一斤，浸三天。每天服二次，每次一调羹，饭后服。（《浙江民间常用草药》） ⒆治鹤膝风：山乌龟四两，大蒜一个，葱三根，韭菜蔸七个。先将山乌龟研末，后加大蒜、葱、韭菜蔸捣烂，蜂蜜调敷患处。敷患处可发泡流水，用纱布遮盖，让其自愈。（《湖南农村常用中草药手册》） ⒇治无名肿毒，毒蛇咬伤：山乌龟鲜根捣烂外敷；或用米泔水磨汁外敷。（《浙江民间常用草药》）' where id=1657; -- 白药子
update herbs set taste='味微苦，性平。', effect='①治淋巴结核：八月札、金樱子、海金砂根各四两，天葵子八两。煎汤分三天服。（苏医《中草药手册》） ②治胃肠胀闷：三叶木通根或果一两，水煎服。（《浙江民间常用草药》）' where id=1658; -- 八月札
update herbs set taste='味苦，微寒。', channel='入肝、胃、膀胱经。', effect='①治真元不足，下焦虚寒，小便白浊，频数无度，漩面如油，光彩不定，漩脚澄下，旋如膏糊；或小便频数，虽不白浊，亦能治疗：益智仁、川萆薢、石菖蒲、乌药各等分。为细末。每服三钱，水一盏半，入盐一捻，同煎至七分，温服，食前。（《杨氏家藏方》萆薢分清散） ②治小便频数：川萆薢（洗）为细末，酒和为丸如柄子大。每服七十丸，空心、食前，盐汤、盐酒任下。（《济生方》萆薢丸） ③治小肠虚冷，小便频数：牛膝（酒浸，切，焙），续断、芎藭各半两，萆薢二两。上四味，捣罗为末，炼蜜和丸如梧桐子大。空心盐汤下四十丸；或作汤，入盐煎服亦得。（《圣济总录》牛膝丸） ④治小便；昆浊：鲜萆薢根头刮去皮须，每次二两，水煎服。（《泉州本草》） ⑤治阴痿失溺：萆薢二钱，附子一钱五分。合煎汤内服。（《泉州本草》） ⑥治腰痛，脚气：破故纸（生）、续断，木瓜干、牛膝（酒浸）、杜仲（去皮锉，姜制炒断丝）各一两，萆薢二两。上为末，蜜丸如梧子大。每服五十丸，盐汤、盐酒任下。（《三因方》立安丸） ⑦治小肠气及腰痛：萆薢、杜仲（酥炒去丝）、葫芦巴（生脂麻炒）、破故纸（炒）、小茴香（盐水浸一宿）各一两，胡桃仁（汤去皮）二两。各为末，和丸如梧桐子大。每服三五十丸，空心盐酒送下，或盐汤亦可。（《瑞竹堂经验方》喝起丸） ⑧治脚气肿痛，不能动履，不论寒热虚实，久病暴发皆可：萆薢五钱，黄柏、苍术、牛膝、本瓜、猪苓、泽泻、槟梅各二钱。水二大碗，煎一碗。每日食前服一剂。（《本草切要》） ⑨治丈夫腰脚痹、缓急，行履不稳者：萆薢二十四分，杜仲八分。捣筛。每旦，温酒和服三钱匕，增至五钱匕。禁食牛肉。（《广利方》） ⑩沧风寒湿痹，腰骨强痛：干萆薢根，每次五钱，猪脊骨半斤合炖服。（《泉州本草》） ⑾治肠风，痔漏：萆薢、贯仲等分。捣罗为末。每服二钱，温酒调下，空心，食前服。（孙用和）', tips='肾虚阴亏者忌服。 畏葵根、大黄、柴胡牡蛎、前胡。 ②《本草经疏》：下部无湿，阴虚火炽，以致溺有余沥，茎中痛，及肾虚腰痛，并不宜服。 ③《本草备要》：忌茗、醋。 ④《本经逢原》：阴虚精滑及元气下陷不能摄精，小便频数，大便引急者，误用病必转剧。' where id=1659; -- 萆薢
update herbs set taste='甘苦，微温。', channel='入肺经。', effect='①治肺寒壅嗽，微有痰：百部三两（炒），麻黄，杏仁四十个。上为末，炼蜜丸如芡实大，热水化下，加松子仁肉五十粒，糖丸之，含化大妙。（《小儿药证直诀》百部丸） ②治寒邪侵于皮毛，连及于肺，令人咳：桔梗-钱五分，甘草（炙）五分，白前一钱五分，橘红一钱；百部一钱五分，紫菀一钱五分。水煎服。（《医学心悟》止嗽散） ③治卒得咳嗽：生姜汁，百部汁。和同合煎，服二合。（《补缺肘后方，） ④治暴嗽：百部藤根捣自然汁，和蜜等分，沸汤煎成膏咽之。（《续十全方》） ⑤治暴咳嗽：百部根渍酒，每温服一升，日三服。（张文仲） ⑥治久嗽不巳，咳吐痰涎，重亡津液，渐成肺痿，下午发热，鼻塞项强，脚胁胀满，卧则偏左其嗽少止，偏右嗽必连发，甚则喘急，病必危殆：百部、薏苡仁、百合、麦门冬各三钱，桑白皮、白茯苓、沙参、黄耆、地骨皮各-钱五分。水煎服。（《本草汇言》百部汤） ⑦治三十年嗽：百部根二十斤，捣取汁，煎如饴，服一方寸匕，日三服。（《千金方》） ⑧治遍身黄肿：掘新鲜百部根，洗捣，罨脐上，以糯米饭半升，拌水酒半合，揉软盖在药上，以帛包住，待一、二日后，口内作酒气，则水从小便中出，肿自消也。（《杨氏经验方》） ⑨治牛皮癣：百部、白鲜皮、萆蔴子（去壳）、鹤虱。黄柏、当归、生地各一两，黄蜡二两，明雄黄末五钱，麻油八两.先将百部等七味入袖熬枯，滤去渣，复将油熬至滴水成珠，再下黄蜡，试水中不散为度，端起锅来将雄黄末和入，侯稍冷，倾入磁盆中收贮，退火听用。（《外科十法》百部膏） ⑩治蚰蜒入耳：百部（切、焙），捣罗为末，以一字，生油调涂于耳门上。（《圣济总录》） (11)咳嗽。用百部根泡酒，每温服一升，一天服三次。又方：用百部、生姜，各捣汁，等分，取二合煎服。又方：用百部藤根捣自然汁，加蜜等分，以沸汤煎成膏，噙咽。 (12)遍身黄肿。用新鲜百部根，洗净，捣烂，敷脐上，以糯米饭半升，拌水酒半合，揉软，盖在药上，外用布包好。一、二天之后，口内有酒气，水从小便出，肿亦渐消。 (13)熏衣虱。和百部、秦艽，共研为末，烧烟熏衣，虱自落 。用上两药煮汤洗亦可。 (14)止嗽散(《医学心悟》)：止咳化痰，疏表宣肺，主治感受风寒，咳痰不爽，或微恶风寒，头痛。 (15)月华丸(《医学心悟》)：滋阴降火，消痰祛瘀，止咳定喘，保肺平肝，杀虫。主治阴虚咳嗽，劳瘵久嗽。 (16)百部丸(《鸡峰普济方》)：主治寒邪壅肺，咳嗽微喘。 (17)百部汤(《本草汇言》)：主治久咳不已，咳吐痰涎，重亡津液，渐成肺痿，下午发热，甚则喘急。 (18)百部膏(《外科十法》)：外用治牛皮癣。 (19)百部丸(《小儿药证直诀》)：主治肺寒咳嗽，微有痰。 (20)百部散(《太平圣惠方》)：主治小儿咳嗽，头热。' where id=1660; -- 百部
update herbs set effect='1. 治疗产后恶露七、八日不止：败酱草、当归各六分 续断、芍药各八分 芎藭、竹茹各四分 生地黄（炒）十二分．水二升 煮取八合 空心服．（《外台秘要》） 2. 治疗产后腰痛 乃气血流入腰腿 痛不可转者：败酱草、当归各八分 芎藭、芍药、桂心各六分．水二升 煮八合 分二服．忌葱．（《广济方》） 3. 治肠痈为病，其身甲错，腹皮急，按之濡如肿状，腹无积聚，身无热，脉数，此为肠内有痈脓：薏苡仁10份，附子2份，败酱5份。上3味，捣为末，取10g，以水2升，煎减半，顿服，小便当下。方中败酱草清热解毒，消痈排脓，祛瘀止痛，为君药。（《金匮要略》薏苡附子败酱散） 4. 治阑尾周围炎和阑尾脓肿：败酱草、生苡仁、冬瓜仁各15g，桃仁6g，丹皮9g，银花15g，连翘9g，秦皮6g，紫花地丁15g，延胡索6g。水煎每日一剂，分2次服。方中败酱草，消痈排脓，祛瘀止痛，为君药。（《中药临床应用》肠用房） 5. 治急性化脓性阑尾炎：败酱草、红藤、蒲公英、金银花各30g，桃仁9g，赤芍12g，大黄15g。水煎服。方中败酱草清热解毒，消痈排脓，祛瘀止痛，为君药。（《陕甘宁青中草药选》） 6. 治疗产后腹痛如锥刺：败酱草五两 水四升 煮二升 每服三合 日三服[1]．（《卫生易简方》）', usage='', tips='脾胃虚弱者慎用。 脾胃虚弱者慎用。' where id=1661; -- 败酱草
update herbs set taste='味咸；性微寒。', channel='入肝、脾经。', effect='①治男女骨蒸劳瘦：鳖甲一枚，以醋炙黄，入胡黄连二钱，为末。青蒿煎汤服方寸匕。（孙思邈） ②治骨蒸夜热劳瘦，骨节烦热，或咳嗽有血者：鳖甲一斤（滚水洗，去油垢净），北沙参四两，怀熟地、麦门冬各六两，白茯苓三两，陈广皮一两。水五十碗，煎十碗，渣再煎，滤出清汁，微火熬成膏，炼蜜四两收。每早晚各服数匙，白汤调下。（《本草汇言》） ③治热邪深入下焦，脉沉数，舌干齿黑，手指但觉蠕动，急防痉厥：炙甘草六钱，干地黄六钱，生白芍六钱，阿胶三钱，麦冬五钱（去心），麻仁三钱，生牡蛎五钱，生鳖甲八钱。水八杯，煮取八分三杯，分三次服。（《温病条辨》二甲复脉汤） ④治老疟久不断者：先炙鳖甲，捣末，方寸匕，至时令三服尽。（《补缺肘后方》） ⑤治温疟：知母，鳖甲（炙）、常山各二两，地骨皮三两，竹叶一升（切），石膏四两。上以水七升，煮二升五合，分温三服。忌蒜、热面、猪、鱼。（《补缺肘后方》） ⑥治疟母：鳖甲十二分（炙），乌扇三分（烧），黄芩三分，柴胡六分，鼠妇三分（熬），干姜三分，大黄三分，芍药五分，桂枝三分，葶苈一分（熬），石苇三分（去毛），厚朴三分，牡丹五分（去心），瞿麦二分，紫葳三分，阿胶三分（炙），蜂蜜四分（炙），赤硝十二分，蜣螂六分（熬），桃仁二分，半夏一分，人参一分，蟅虫五分（熬）。上二十三味，为末，取煅灶下灰一斗，清酒一斛五斗，浸灰，候酒尽一半，着鳖甲于中，煮令泛烂如胶漆，绞取汁，纳诸药煎为丸，如梧子大，空心服七丸，日三服。（《金匮要略》鳖甲煎丸） ⑦治癥癖：鳖甲、诃黎勒皮、干姜末。等分为丸，空心下三十丸，再服。（《药性论》） ⑧治心腹癥瘕血积：鳖甲一两（汤泡洗净，米醋浸一宿、火上炙干，再淬再炙，以甲酥为度，研极细），琥珀三锅（研极细），大黄五钱（酒拌炒）。上共研细作散。每早服二钱，白汤调下。（《甄氏家乘方》） ⑨治妇人月水不利，腹胁妨闷，背膊烦疼：鳖甲二两（涂醋炙令黄，去裙榈），川大黄一两（锉，微炒），琥珀一两半。上药捣罗为末，炼蜜和丸，如梧桐子大。以温酒下二十丸。（《圣惠方》鳖甲丸） ⑩治妇人漏下五色，羸瘦、骨节间痛：鳖甲烧令黄，为末，酒调服方寸匕，日三。（《肘后方》） ⑾治吐血不止：鳖甲一两（锉作片子），蛤粉一两（鳖甲相和，于铫内炒香黄色），熟干地黄一两半（暴干）。上三味捣为细散。每服二钱匕，食后腊茶清调下，服药讫，可睡少时。（《圣济总录》鳖甲散） ⑿治卒腰痛不得俯仰：鳖甲一枚（炙，捣筛）。服方寸匕，食后，日三服。（《补缺肘后方》） ⒀治石淋：鳖甲杵末，以酒服方寸匕，日二、三，下石子瘥。（《肘后方》） ⒁治上气喘急，不得睡卧，腹胁有积气：鳖甲一两（涂醋炙令黄，去裙襕），杏仁半两（汤浸，去皮、尖，麸炒微黄），赤茯苓一两，木香一两。上药捣筛为散，每服五钱，以水一中盏，入生姜半分，灯心一大束，煎至六分，去滓，不计时候，温服。（《圣惠方》） ⒂治阴虚梦泄：鳖甲烧研，每用一字，以酒半盏，童尿半盏，葱白七寸同煎，去葱，日晡时服之，出臭汗为度。（《医垒元戎》） ⒃治产后早起中风冷，泄痢及带下：鳖甲如手大，当归、黄连、干姜各二两，黄柏长一尺、广三寸。上五味细切，以水七升，煮取三升，去滓，分三服，日三。（《千金方》鳖甲汤） ⒄治小儿痫：鳖甲炙令黄，捣为末，取一钱，乳服，亦可蜜丸如小豆大服。（《子母秘录》） ⒅治肠痈内痛：鳖甲烧存性，研，水服一钱，日三。（刘禹锡《传信方》） ⒆治痈疽不敛，不拘发背一切疮：鳖甲烧存性，研掺。（《怪证奇方》） ⒇治痔，肛边生鼠乳，气壅疼痛：鳖甲三两（涂醋炙令黄，去裙襕），槟榔二两。上药捣细罗为散，每于食前，以粥饮调下二钱。（《圣惠方》鳖甲散） (21)治丈夫阴头痈肿：鳖甲一枚，上一味，烧焦末之，以鸡子白和敷之。（《千金翼方》） (22)治牙痛：鳖甲。焙干轧成细末，贮于干燥器皿内备用临用时，取鳖甲粉0.5克放在烟斗内烟叶的表面上，点燃当烟吸。（《全展选编·五宫科》）' where id=1662; -- 鳖甲
update herbs set taste='甘；性平。', channel='入心、肝、脾经。', effect='①治劳欲过度，心血亏损，精神恍惚，夜多怪梦，怔忡惊悸，健忘遗泄，常服宁心定志，补肾滋阴：柏子仁（蒸晒去壳）四两，枸杞子（酒洗晒）三两，麦门冬（去心）、当归（酒浸）、石菖蒲（去毛洗净）、茯神（去皮心）各一两，玄参、熟地（酒蒸）各二两，甘草（去粗皮）五钱。先将柏子仁、熟地蒸过，石器内捣如泥，余药研末和匀，炼蜜为丸，如梧桐子大。每服四，五十丸，早晚灯心汤或圆眼汤送下。（《体仁汇编》柏子养心丸） ②戢阳气，止盗汗，进饮食，退经络热：新柏子仁（研）、半夏曲各二两，牡蛎（甘锅子内火煅，用醋淬七次，焙）、人参（去芦）、白术、麻黄根（慢火炙，拭去汗）、五味子各一两，净麸半两（慢火炒）。上八味为末，枣肉丸如梧子大。空心米饮下三、五十丸，日二服。作散调亦可。（《本事方》柏子仁丸） ③治老人虚秘：柏子仁、大麻子仁、松子仁，等分。同研，熔白蜡丸桐子大。以少黄丹汤服二、三十丸，食前。（《本草衍义》） ④治肠风下血：柏子仁十四枚。燃破，纱囊贮，以好酒三盏，煎至八分服之，初服反觉加多，再服立止。非饮酒而致斯疾，以艾叶煎汤服之。（《世医得效方》） ⑤治血虚有火，月经耗损，渐至不通，羸瘦而生潮热，及室女思虑过度，经闭成痨：柏子仁（炒，另研）、牛膝、卷柏各五钱（一作各二两），泽兰叶、川续断各二两，熟地黄三两。研为细末，炼蜜和丸如梧桐子大。每服三三丸，空腹时米饮送下，兼服泽兰汤。（《妇人良方》柏子仁丸） ⑥治脱发：当归、柏子仁各一斤。共研细末，炼蜜为丸。每日三次，每次饭后服二至三钱。（《全展选编·皮肤科》）' where id=1663; -- 柏子仁
update herbs set taste='甘，辛，微温。', channel='入肝、肾经。', effect='①治虚羸阳道不举，五劳七伤百病。能食，下气：巴戟天、生牛膝各三斤。以酒五斗浸之，去滓温服，常令酒气相及，勿至醉吐。（《千金方》） ②治妇人子宫久冷，月脉不调，或多或少，赤白带下：巴戟三两，良姜六两，紫金藤十六两，青盐二两，肉桂（去粗皮）、吴茱萸各四两。上为末，酒糊为丸。每服二十丸，暖盐酒送下，盐汤亦得。日午、夜卧各一服。（《局方》巴戟丸） ③治风冷腰胯疼痛，行步不得：巴戟一两半，牛膝三两（去苗），羌活一两半，桂心一两半，五茄皮一两半，杜仲二两（去粗皮，炙微黄，判），干姜一两半（炮裂，判）。上药捣罗为末，炼蜜和捣三、二百杵，丸如梧桐子大。每于食前，以温酒饮下三十丸。（《圣惠方》巴戟丸） ④治小便不禁：益智仁、巴戟天（去心，二味以青盐、酒煮），桑螵蛸、兔丝子（酒蒸）各等分。为细末，酒煮糊为丸，如梧桐子大。每服二十丸，食前用盐酒或盐汤送下。（《奇效良方》） ⑤治白浊：菟丝子（酒煮一日，焙干）、巴戟（去心，酒浸煮），破故纸（炒）、鹿茸、山药、赤石脂、五味于各一两。上为末，酒糊丸。空心盐汤下。（《普济方》） ⑥治妇人子宫久冷，月脉不调，或多或少，赤白带下。巴戟90g，良姜180g，紫金藤1斤，青盐60g，肉桂（去粗皮）、吴茱萸各120g。上为末，酒糊为丸，每服20丸，温盐酒送下，盐汤亦得，日午、夜卧各1服。方中巴戟天与诸药配伍有治子宫虚冷的功效。（《太平惠民和剂局方》巴戟丸） ⑦治风冷腰胯疼痛，行步不得。巴戟45g，牛膝（去苗）90g，羌活、桂心、五加皮各45g，杜仲（去粗皮，炙微黄）60g，干姜45g。上药捣为末，炼蜜和捣200～300杵，丸如梧桐子大，每服30丸，食前温酒饮下。方中巴戟天配伍诸药有强筋骨、祛风湿等功效。（《太平圣惠方》巴戟丸） ⑧治冷痹，脚膝疼痛，行履艰难。巴戟天（去心）90g，附子（炮，去皮脐）、五加皮各60g，牛膝（酒浸，焙）、石斛（去根）、甘草（炙）、萆薢各45g，白茯苓（去皮）、防风（去叉）各31g。上剉如麻豆大，每服15g，生姜3片，水1.5盏，煎至1盏，去渣，空心温服（一方无生姜）。方中巴戟天配伍诸药有治腰膝疼痛等功效。（《奇效良方》巴戟汤）', tips='阴虚火旺者忌服。 恶朝生、雷丸、丹参。 ②《本草经疏》：凡病相火炽盛，便赤，口苦，目赤目痛，烦躁口渴，大便燥秘，法咸忌之。 ③《得配本草》：火旺泄精，阴虚水乏，小便不利，口舌干燥，四者禁用。' where id=1664; -- 巴戟天
update herbs set taste='甘；辛；平；有小毒。', channel='入大肠。肺经。', effect='①治疔疮脓肿：蓖麻子二十多颗，去壳，和少量食盐、稀饭捣匀，敷患处，日换两次。（《福建民间草药》） ②治痈疽初起：去皮蓖麻子一份，松香四份。将蓖麻子捣碎加入松香粉充分搅拌，用开水搅成糊状，置于冷水中冷却成膏状备用。用时将白膏药按疮面大小摊于纸或布上贴患处。（辽宁《中草药新医疗法资料选编》） ③治瘰疬：蓖麻子炒热，去皮，烂嚼，临睡服三、二枚，渐加至十数枚。（《本草衍义》） ④治咽中疮肿：萆麻子一枚（去皮），朴硝一钱。同研，新汲水作一服，连进二、三服效。（《医准》） ⑤治喉痹：萆麻子，取肉捶碎，纸卷作筒，烧烟吸之。（《医学正传》圣烟筒） ⑥治诸骨哽：蓖麻子七粒。去壳研细，入寒水石末，缠令干湿得所，以竹篾子挑二、三钱入喉中，少顷以水咽之即下。（《魏氏家藏方》） ⑦治疠风，手指挛曲，节间痛不可忍，渐至断落：蓖麻一两（去皮），黄连一两（锉如豆）。以小瓶子入水一升，同浸，春夏三日，秋冬五日，后取蓖麻子一枚，擘破，以浸药水，平旦时一股，渐加至四、五枚，微利不妨，瓶中水少更添。忌动风食。（《医准》） ⑧治汤火伤：蓖麻子、蛤粉等分。研膏。汤损用油调涂，火疮用水调涂。（《养生必用方》） ⑨治犬咬伤：蓖麻子五十粒。去壳，以井水研膏，先以盐水洗咬处，次以萆麻膏贴。（《袖珍方》） ⑩治风气头痛不可忍：乳香、蓖麻仁等分。捣饼，随左右贴太阳穴。（《纲目》） ⑾治小儿颓疝：蓖麻仁三枚，棘刚子（去皮）三十枚，石燕子（烧）一枚，滑石（末）二钱匕，麝香（研）半钱匕。上五味捣研匀，稀面糊和丸，如绿豆大，每服十五丸，空心，煎灯心汤下。（《圣济总录》蓖麻丸） ⑿治齁喘咳嗽：蓖麻子去壳炒热，拣甜者吃，多服见效。（《卫生易简方》） ⒀治难产及胞衣不下：蓖麻子七枚。研如膏，涂脚底心，子及衣才下，便速洗去。（《海上集验方》） ⒁催生并死胎不下：蓖麻子三个，巴豆四个。研细，入麝香少许，贴脐心上。（《卫生家宝方》） ⒂治子宫脱下：蓖麻仁、枯矾等分。为末，安纸上托入，仍以蓖麻仁十四枚，研膏涂顶心。（《摘元方》） ⒃治暴患脱肛：蓖麻子一两。烂杵为膏，捻作饼子，两指宽大，贴囟上；如阴证脱肛，生附子末、葱、蒜同研作膏，依前法贴之。（《活幼心书》蓖麻膏） ⒄治口眼歪斜；蓖麻子仁七七粒。研作饼，右歪安在左手心，左歪安在右手心，却以铜盂盛热水，坐药上，冷即换，五、六次即正也。（《妇人良方》）' where id=1665; -- 蓖麻子
update herbs set taste='味苦；咸；性寒。', channel='入肺、胃、肾经。', effect='①治体虚低烧，夜眠出汗：白薇、地骨皮各四钱，水煎服。（《河北中药手册》） ②治肺结核潮热：白薇三钱，葎草果实三钱，地骨皮四钱，水煎服。（南京《常用中草药》） ③治尿道感染：白薇五钱，车前草一两，水煎服。（南京《常用中草药》） ④治妇人乳中虚，烦乱呕逆：生竹茹二分，石膏二分，桂枝一分，甘草七分，白薇一分。上五味末之，枣肉和丸弹子大。以饮服一丸，日三夜二服。有热者倍白薇，烦喘者加柏实一分。（《金匮要略》竹皮大丸） ⑤治郁冒血厥，居常无苦，忽然如死，身不动，默默不知人，目闭不能开，口噤不能语，又或似有知，而恶闻人声，或但如眩冒，移时乃寤：白薇一两，当归一两，人参半两。上为散，每服五钱，水二盏，煎至一盏，去滓，温服。（《全生指迷方》白薇汤） ⑥治妇人遗尿，不知出时：白薇、芍药各一两。上二味，治下筛。酒服方寸匕，日三。（《千金方》） ⑦治火眼：白薇一两，水煎服。（《湖南药物志》） ⑧治肺实鼻塞，不知香臭：百部二两，款冬花、贝母（去心）、白薇各一两。上为散，每服一钱，米饮调下。（《普济方》） ⑨治金疮血不止：白薇末贴之。（《儒门事亲》） ⑩治瘰疬：鲜白薇、鲜天冬各等分，捣绒敷患处。（《贵州草药》） ⑾治风湿关节痛：白薇、臭山羊、大鹅儿肠根各五钱，泡酒服。（《贵州草药》）' where id=1666; -- 白薇
update herbs set taste='味辛；性温。', channel='入肺、脾经。', effect='①治胃口寒作吐及作痛者：白豆蔻仁三钱。为末，酒送下。（《赤水玄珠》白豆蔻散） ②治胃气冷，吃饭即欲得吐：白豆蔻子三枚，捣，筛，更研细，好酒一盏，微温调之，并饮三、两盏。（《随身备急方》） ③治脾胃气不和，止脾泄泻痢：白豆蔻二两（用仁，一半生一半熟），枳壳半斤（去瓤，以浆水煮软，麸炒令香止），肉桂二两（去皮），橘皮二两（去瓤，炒，切细），诃子二两（去核，半生半熟），当归二两（洗）。上六味，杵为末，每服-钱，水一中盏。姜、枣同煎至七分，稍温服。如要丸，用好枣，浆水煮，去皮核，细研，为丸如桐子大。以姜擘破，炒令黑色，入水煎汤，下十五丸。（《博济方》白豆蔻散） ④治气膈脾胃，全不进食：白豆蔻仁、缩砂各二两，陈米一升（淘洗，略燕过，铫内炒），丁香半两（不见火）。上为细末，枣肉为丸，如小赤豆大。每服五、七十丸至百丸，米饮下。（《魏氏家藏方》太仓丸） ⑤治妊娠呕吐：白豆蔻一钱，竹茹三钱，大枣三枚，鲜姜一钱。将生姜捣碎取汁，前三药煎取一茶杯（约50～60毫升）过滤，冲姜汁服。（《武汉医药卫生》（3）：288，1959） ⑥治小儿吐乳胃寒者：白豆蔻仁十四个，缩砂仁十四个，生甘草二钱，炙甘草二钱，为末，常掺入儿口中。（《世医得效方》） ⑦治呕吐哕：白蔻、藿香、半夏、陈皮、生姜。水煎服。（《沈氏尊生书》白豆蔻汤） ⑧治产后呃逆：白豆蔻、丁香各半两。研细，桃仁汤服一钱，少顷再服。（《乾坤生意》） ⑨治脾胃虚弱，不进饮食，及反胃呕吐：白豆蔻、砂仁各60g，丁香30g，陈仓米（土炒）1升。为细末，姜，汁为丸，梧桐子大，每服60-70丸，生姜煎汤送下。方中白豆蔻化湿行气，温中止呕，为君药。（《证治准绳》太仓丸） ⑩治虚劳，不思饮食，中满痞塞，大肠或秘或泄：白豆蔻（去皮）、白术（刹炒）、陈皮（去白）、人参各30g，干姜（炮）、甘草（炙）、丁香各15g，槟榔（剉）2枚，厚朴（去粗皮，姜汁制）60g，每服9g，水一盏，生姜3片，枣2枚，去渣，不拘时温服。方中白豆蔻化湿行气，温中止呕，为君药。 （《奇效良方》豆蔻汤） ⑾治脘闷腹胀，饮食停滞：白蔻仁、砂仁、木香各6g，枳壳9g，陈皮、厚朴各6g，泽泻15g，赤茯苓12g。水煎，每服一剂，日服2次。方中白豆蔻化湿行气，为君药。（时逸人方）加减仁香汤。 ⑿三仁汤《温病条辨》；黄芩滑石汤《温病条辨》；白豆蔻汤《圣济总录》；沉香汤《圣济总录》；补和汤《圣济总录》' where id=1667; -- 白豆蔻
update herbs set alias='僵蚕，天虫，僵虫。', taste='味辛；咸；性平。', channel='入肝、肺，胃经。', effect='①治中风口眼歪斜，半身不遂：白附子、白僵蚕、全蝎各等分（并生用）。为细末。每服一钱，热酒调下，不拘时候。（《杨氏家藏方》牵正散） ②治小儿惊风：白僵蚕、蝎梢等分，天雄尖、附子尖共一钱（微炮过）。为细末。每服一字或半钱，以生姜温水调，灌之。（《本草衍义》） ③治小儿撮口及发噤：白僵蚕二枚。为末。用蜜和，敷于小儿唇口内。（《小儿宫气方》） ④治头风：白僵蚕（去丝、嘴）、良姜等分。为细末。每服半钱，白梅茶清凋下，临发时服。（《百一选方》） ⑤治缠喉风并急喉闭喉肿痛者：白僵蚕一两（新瓦上炭火略炒微黄色）、天南星一两（炮裂，刮去粗皮，锉）。为细末。每服一字，用生姜自然汁少许调药末，以熟水投之，呷下，吐出涎痰即快，不时服之。（《魏氏家藏方》白僵蚕散） ⑥治喉闭牙关不开者：白僵蚕，微炒为末，生姜自然汁调下一钱。（《中藏经》） ⑦治瘰疬：白僵蚕，研末，水服五分匕，日三服。（《千金方》） ⑧治空洞性肺结核：白僵蚕、白芨各等分。共研细末；每次二钱，日服二次。（《吉林中草药》） ⑨治风，遍身瘾疹，疼痛成疮：白僵蚕，焙令黄色，细研为末，酒服。（《圣惠方》） ⑩治野火丹从背上两胁起：僵蚕二七枚，和慎火草捣涂之。（《产乳集验方》） ⑾治妇人崩中下血不止：衣中白鱼、僵蚕等分。为末。以井花水服之，日三服。（《千金方》） ⑿治肠风下血：僵蚕（炒，去嘴、足），乌梅肉（焙）各一两。为末，米糊丸，梧子大。每服百丸，食前白汤下，一日三服。（《卫生杂兴》） ⒀治重舌、木舌：僵蚕一钱，黄连（蜜炒）二钱。为末，掺之，诞出为妙。（《积德堂经验方》） ⒁下奶：白僵蚕末两钱。酒调下，少顷以脂麻茶一钱热投之。（《经验后方》）' where id=1668; -- 白僵蚕
update herbs set taste='味甘；性寒。', channel='入肺、胃经。', effect='①治太阴温病，口渴甚，吐白沫粘滞不快者：荸荠汁、梨汁、鲜苇根汁、麦冬汁，藕汁（或用蔗浆）。临时斟酌多少，和匀凉服，不甚喜凉者，重汤炖温服。（《温病条辨》五汁饮） ②治肝经热厥，少腹攻冲作痛：大荸荠四个，海宅（漂去石灰矾性）一两。上二味，水二钟，煎八分服。（《古方选注》雪羹） ③治黄疸湿热，小便不利：荸荠打碎，煎汤代茶，每次四两。（《泉州本草》） ④治下痢赤白：取完好荸荠，洗净拭干，勿令损破，于瓶内入好烧酒浸之，黄泥密封收贮。遇有患者，取二枚细嚼，空心用原酒送下。（《唐瑶经验方》） ⑤治痞积：荸荠于三伏时以火酒浸晒，每日空腹细嚼七枚，痞积渐消。（《本经逢原》） ⑥治腹满胀大：乌芋去皮，填入雄猪肚内，线缝，砂器煮糜食之，勿入盐。（《本草经疏》） ⑦治大便下血：荸荠捣汁大半钟，好酒半钟，空心温服。（《神秘方》） ⑧治妇人血崩：凫茈一岁一个，烧存性，研末，酒服之。（《纲目》） ⑨治咽喉肿痛：荸荠绞汁冷服，每次四两。（《泉州本草》） ⑩治小儿口疮：荸荠烧存性，研末掺之。（《简便单方》） ⑾治寻常疣：将荸荠掰开，用其白色果肉摩擦疣体，每日三至四次，每次摩至庞体角质层软化，脱掉，微有痛感并露出针尖大小的点状出血为止。连用七至十天。（《中华皮肤科杂志》' where id=1669; -- 荸荠
update herbs set taste='辛苦，凉。', channel='入心、肺经。', effect='①治急中风目瞑牙噤，不能下药：天南星（生捣为细末）、龙脑（别研）。上二味，各等分，重研细，以中指点散子，揩齿三、二十次在大牙左右，其口自开，始得下药。患者只使一字至半钱匕。（《圣济总录》开关散） ②治时疾发豌豆疮及赤疮子未透，心烦狂躁，气喘，妄语：龙脑一钱。细研，旋滴猪心血和丸，如鸡头肉大。每服一丸，紫草汤下，少时心神便定，得睡，疮复发透，依常将息取安。（《经验后方》） ③治伏热在心，昏瞀不省，或悮服热药，搐热冒昧不知人，及疮疹倒靥黑陷：生梅花脑子（研）半字或一字。取新杀猪心一个，取心中血同研作大丸，用新汲水少许化下，未省再服；如疮疹陷伏者，温酒化下。（《小儿药证直诀》） ④治伤寒舌出过寸者：梅花片脑半分，为末，掺之。（《夷坚志》） ⑤治头目风热上攻：龙脑末半两，南蓬砂末一两。频搐两鼻。（《御药院方》） ⑥治头脑疼痛：片脑一钱，纸卷作拈，烧烟熏鼻，吐出痰诞即愈。（《寿域神方》） ⑦治风热喉痹：灯心一钱，黄柏五分（并烧存性），白矾七分（煅过），冰片脑三分。为末。每以一、二分吹患处。（《濒湖集简方》） ⑧治咽喉口齿新久肿痛，及久嗽痰火咽哑作痛：冰片五分，朱砂六分，玄明粉、硼砂各五钱。共研极细末，吹搽患上，甚者日搽五、六次。（《外科正宗》冰硼散） ⑨治口疮咽燥：龙脑三钱，黄柏三两。为末，蜜丸梧子大，每麦门冬汤下十丸。（《摘元方》） ⑩治内外痔疮：片脑一、二分，葱汁化搽之。（《简便单方》） ⑾治眼赤痛，卒生浮白翳：龙脑一分，雄雀粪一分。上件药，研如粉，以人乳汁一合，相合，调匀成膏，每以铜箸取少许点之。（《圣惠方》龙脑膏） ⑿治酒皶鼻，赤疱注上面脸者：脑子，真酥调涂敷。（《海上方》） ⒀治牙齿疼痛：梅花脑、朱砂。末，各少许揩之。（《濒湖集简方》） ⒁治鼻中息肉垂下者：片脑点之。（《濒湖集简方》） ⒂治烫、烧伤：冰片10克，银朱5克，香油100毫升。先将香油倒入铝锅熬开，后把银朱、冰片放入，加热成红褐色，即成膏。将创面消毒后涂抹，一天一次。（辽宁《中草药新医疗法资料选编》） 16.治痰结咽喉，咯之不治，唾之不出。冰片（别研）0.9g，薄荷叶120g，孩儿茶60g，硼砂6g，乌梅肉120g，诃子10个，白砂糖250g。上为末，用白砂糖化开为丸，如芡实大，外用葛根为衣，含化甚妙。方中冰片配伍诸药有治咽喉肿痛的功效。（《医经会解》冰梅丸） 17.治咽喉肿痛。冰片0.18g，麝香0.12g，硼砂3g，牙硝0.9g。上为细末，每次少许，吹患处。用瓷瓶封固。方中冰片配伍诸药有治疗咽喉肿痛的功效。（《重楼玉钥》回生丹） 18.单味研细点鼻，治鼻中息肉。' where id=1670; -- 冰片
update herbs set taste='苦；咸；寒。', channel='入脾、胃经。', effect='①治肺藏风热，毒气攻皮肤瘙痒，胸膈不利，时发烦躁：白鲜皮、防风（去叉）、人参、知母（焙）、沙参各一两，黄苓（去黑心）三分。上六味捣罗为散。每服二钱匕，水一盏，煎至六分，温服，食后临卧。（《圣济总录》白鲜皮散） ②治痫黄：白鲜皮、茵陈蒿各等分。水二钟煎服，日二服。（《沈氏尊生书》白鲜皮汤） ③治鼠疫已有核，脓血出者：白鲜皮，煮服一升。（《补缺肘后方》） ④白鲜皮散（《太平圣惠方》）治小儿心肺风热壅滞，胸膈不利：白鲜皮、防风、犀角、黄芩、知母、沙参、人参各15g，炙甘草30g，每服3g，水煎服。方中白鲜皮清热解毒，祛风，为君药。 ⑤治疗产后中风，虚人不可服他药者：白鲜皮90g。以水3升，煮取1升，分服。耐酒者可酒、水等分煮之。方中白鲜皮祛风，为君药。 （《小品方》一物白鲜汤） ⑥治慢性湿疹，荨麻疹：白鲜皮9g，白蒺藜12g，乌梢蛇9g，生地12g，防风、当归各9g，甘草6g。水煎服。方中白鲜皮祛风，为君药。（《中药临床应用》双白祛风汤）' where id=1671; -- 白鲜皮
update herbs set alias='佛指柑，佛指甲，灵眼。', taste='甘；苦；涩；性平；小毒。', channel='入肺、肾经。', effect='①治鼩喘：白果二十一枚（去壳砸碎，炒黄色），麻黄三钱，苏子二钱，甘草一钱，款冬花三钱，杏仁一钱五分（去皮尖），桑皮三钱（蜜炙），黄芩一钱五分（微炒），法制半夏三钱（如无，用甘草汤泡七次，去脐用）。上用水三钟，煎二钟，作二服，每服一钟，不拘时。（《摄生众妙方》定喘汤） ②治梦遗：银杏三粒。酒煮食，连食四至五日。（《湖南药物志》） ③治赤白带下，下元虚惫：白果、莲肉、江米各五钱。为末，用乌骨鸡一只，去肠盛药煮烂，空心食之。（《濒湖集简方》） ④治小儿腹泻：白果二个，鸡蛋一个。将白果去皮研末，鸡蛋打破一孔，装入白果末，烧熟食。（内蒙古《中草药新医疗法资料选编》） ⑤治诸般肠风脏毒：生银杏四十九个。去壳膜，烂研，入百药煎末，丸如弹子大。每服三丸，空心细嚼米饮下。（《证治要诀》） ⑥治牙齿虫露：生银杏，每食后嚼一个，良。（《永类钤方》） ⑦治鼻面酒皶：银杏、酒酻糟。同嚼烂，夜涂旦洗。（《医林集要》） ⑧治头面癣疮：生白果仁切断，频擦取效。（《秘传经验方》） ⑨治下部疳疮：生白果，杵，涂之。（《济急仙方》） ⑩治乳痈溃烂：银杏半斤。以四两研酒服之，以四两研敷之。（《救急易方》） (11)治疗肺结核:对改善症状有一些作用。服药后部分病人的发热、盗汗、咳嗽、气喘、咳血、食欲不振等，可见不同程度的好转。用法：在中秋节前夕，将半青带黄的银杏（选取外表丝毫无损的大颗粒）摘下，不用水洗，亦不去柄，随即浸入生菜油内，浸满100天后即可使用。每日早、中、晚各服1粒（小儿酌减），饭前服，视病情连服1～3个月 (12)定喘汤《摄生众妙方》； (13)易黄汤《傅青主女科》；' where id=1672; -- 白果
update herbs set taste='味辛；微苦；性微寒。', effect='①治牙龈出血：鲜猪殃殃二至三两。水煎服。（江西《草药手册》） ②治急性阑尾炎：鲜猪殃殃三两。煎水内服。（江西《草药手册》） ③治感冒：鲜猪殃殃一两，姜三片。擂汁冲开水服。（江西《草药手册》） ④治妇女经闭：猪殃殃二钱。水煎服。（《湖南药物志》） ⑤治跌打损伤：鲜猪殃殃根、马兰根各四饯。水酒各半煎服。另以鲜猪殃殃全草、酢浆草等分，捣烂外敷。（江西《草药手册》） ⑥治疖肿初起：鲜猪殃殃适量，加甜酒捣烂外敷，日换二次。（江西《草药手册》） ⑦治乳癌：鲜猪殃殃四两。捣汁和以猪油敷于癌症溃烂处，亦可煎水内服。（江西《草药手册》） ⑧治五淋：八仙草三钱，滑石二钱，甘草一钱，双果草二钱。水煎点水酒服。（《滇南本草》） ⑨治中耳炎：鲜猪殃殃，捣汁滴耳。（《云南中草药》）' where id=1673; -- 八仙草
update herbs set effect='（1）用治感冒发热、乳痈等，可配合蒲公英、银花、一见喜等药同用。治疗湿热黄疸或腹水肿痛、小便不利者，可配合金钱草、茵陈等药同用，使水湿之邪从小便排泄。用于风湿痹痛，可与秦艽、枪活、独活等药同用。本品配伍蛇莓、龙葵、白花蛇舌草等药，用于肺癌以及胃肠道癌肿等症。', tips='清热解毒，利湿消肿，抗癌。全草：用于感冒发热，乳痈、恶疮，湿热黄疸、腹水，白带，肾炎水肿；外用治痈疖肿毒。根：风湿痹痛。' where id=1674; -- 白英
update herbs set taste='平；甘淡；无毒', effect='①治一切泄痢：白扁豆花正开者，择净勿洗，以滚汤瀹过，和小猪脊肉一条，葱一根，胡椒七粒，酱汁拌匀，就以瀹豆花汁和面包作小馄饨，炙熟食之。（《必用食治方》） ②治妇人白崩：白扁豆花（紫者勿用）焙干为末，炒米煮饮入烧盐，空心服。（《奇效良方》） ③治疗细菌性痢疾。干白扁豆花100g，制成100%煎液。口服剂量按每次每公斤体重0.5-1ml计算，每6小时1次，7天为一疗程。观察13例，经治3-7天后，痊愈(临床症状消失，大便培养连续二次阴性)7例，进步(临床症状部分消失或减轻)3例，无效3例。治程中未见副作用。据实验证明，每毫升含生药62.5mg的扁豆花煎液在试管内可抑制宋内氏型、弗氏型痢疾杆菌生长。', tips='解暑化湿，和中健脾。主夏伤暑湿，发热，泄泻，痢疾，赤白带下，跌打伤肿 ①《本草图经》：主女子赤白下，干末，米饮和服。 ②《纲目》：焙研服，治崩带；作馄饨食，治泄痢；擂水饮，解中一切药毒。功同扁豆。 ③《岭南采药录》；敷跌打伤，去瘀生新，消肿散青黑。 ④《四川中药志》：和胃健脾，清热除湿。治暑热神昏，湿滞中焦，下痢脓血，夏口腹泻及赤白带下。' where id=1675; -- 扁豆花
update herbs set taste='苦甘；寒；无毒。', channel='入胃、大肠、小肠经。', effect='①治痢疾、尿道炎：白花蛇舌草一两。水煎服。（《福建中草药》） ②治黄疸：白花蛇舌草一至二两。取汁和蜂蜜服。（厦门） ③治急性阑尾炎：白花蛇舌草二至四两，羊蹄草一至二两，两面针根三钱。水煎服。（广东《中草药处方选编》） ④治小儿惊热，不能入睡：鲜蛇舌癀打汁一汤匙服。（《闽南民间草药》） ⑤治疮肿热痛：鲜蛇舌癀洗净，捣烂敷之，干即更换。（《闽南民间草药》） ⑥治毒蛇咬伤：鲜白花蛇舌草一至二两。捣烂绞汁或水煎服，渣敷伤口。（《福建中草药》）' where id=1676; -- 白花蛇舌草
update herbs set taste='辛，热，有毒。', channel='入胃、大肠经。', effect='①治寒实结胸，无热症者：桔梗三分，巴豆一分（去心皮，熬黑，研如脂），贝母三分。三味为散，以白饮和服，强人半钱匕，羸者减之。病在膈上必吐，在膈下必利。不利，进热粥一杯，利过不止，进冷粥一杯。（《伤寒论》白散） ⑤治心腹诸卒暴百病，若中恶客忤，心腹胀满，卒痛如锥刺，气急口噤，停尸卒死者：大黄一两，干姜一两，巴豆一两（去皮心，熬，外研如脂）。上药各须精新，先捣大黄、干姜为末，研巴豆纳中，合治一千杵，用为散，蜜和丸亦佳。以暖水若酒服大豆许三、四丸，或不下，捧头起，灌令下咽，须臾当瘥；如未瘥，更与三丸，当腹中鸣，即吐下便瘗；若口噤，亦须折齿灌之。（《金匮要略）三物备急丸） ⑥治寒癖宿食，久饮不消，大便秘：巴豆仁一升，清酒五升。煮三日三夜，研，令大热，合酒微火煎之，丸如胡豆大，每服一丸，水下，欲吐者服二丸。（《千金方》） ④治痞结癥瘕：巴豆肉五粒（纸裹打去油），红曲三两（炒），小麦麸皮一两（炒）。俱研为细末，总和为丸，如黍米大，每空心服十丸，白汤下。（《海上方》） ⑤治阴毒伤寒心结，按之极痛，大小便秘，但出气稍暖者：巴豆十粒，研，入面一钱，捻作饼，安脐内，以小艾炷灸五壮。气达即通。（《仁斋直指方》） ⑥治小儿L痰喘：巴豆一粒，杵烂，绵裹塞鼻，痰即自下。（《古今医鉴》） ⑦治寒痰气喘：青橘皮一片，展开，入刚子一个，麻扎定，火上烧存性，研末，姜汁和酒一钟，呷服。（《医说》） ⑧治夏月水泻不止：大巴豆一粒（去壳）。上以针刺定，灯上烧存性，研细，化蜡和作一丸，水下，食前服。（《世医得效方，针头丸） ⑨治气痢：巴豆一两，去皮心，熬，细研，取热猪肝和丸，空心米饮下，量力加减服之。牛肝尤佳。或以蒸饼丸服。（《经验方》） ⑩治小儿下痢赤白：巴豆（煨熟，去油）一钱，百草霜二钱（研末），飞罗面煮糊丸，黍米大，量人用之。赤用甘草汤，白用米汤，赤白用姜汤下。（《全幼心鉴》） ⑴治伏暑伤冷，冷热不调，霍乱吐利，口干烦渴：巴豆大者二十五枚（去皮膜，研取油尽，如粉），黄丹（炒，研，罗过）取一两一分。上同研匀，用黄蜡熔作汁，为丸如梧桐子大，每服五丸，以水浸少顷，别以新汲水吞下，不拘时候。（《局方》水浸丹） ⑿治腹大动摇水声，皮肤黑，名曰水臌：巴豆九十枚（去皮心），杏仁六十枚（去皮尖）。并熬令黄，捣和之，服如小豆大一枚，以水下为度，勿饮酒。（《补缺肘后方》） ⒀治肝硬化腹水：巴豆霜一钱；轻粉五分。放于四、五层纱布上，贴在肚脐上，表面再盖二层纱布。经一至二小时后感到刺痒时即可取下，待水泻。若不泻则再敷。（内蒙古《中草药新医疗法资料选编》） ⒁治喉痹：白矾二两（捣碎），巴豆半两（略捶破）。同于铫器内炒，侯矾枯，去巴豆不用，碾矾为细末，遇病以水调灌，或干吹入咽喉中。（《百一选方》） ⒂治白喉：巴豆仁、朱砂等分，各研成细末，混和，每用3～5分，置膏药上，贴于眉间的上方（勿使药末掉入眼中）。约经8～12小时，局部皮肤发生大小不等的水泡时，便可揭去膏药，擦掉药末，涂上1％龙胆紫液，以防感染。（《江苏中医》（11）：23，1959巴豆朱砂膏） ⒃治耳卒聋：巴豆一粒，蜡裹，针刺令通透，用塞耳中。（《经验方》） ⒄治风虫牙痛：㈠巴豆一粒，研，绵裹咬之。㈡针刺巴豆，灯上烧令烟出，熏痛处。（《经验方》） ⒅治一切恶疮：巴豆三十粒，麻油煎黑，去豆，以油调雄黄、轻粉末，频涂取效。（《普济方》） ⒆治一切疮毒及腐化瘀肉：巴豆去壳，炒焦，研膏，点肿处则解毒，涂瘀肉则自腐化。（《痈疽神秘验方》乌金膏） ⒇治荷钱癣疮：巴豆仁三个，连油杵泥，以生绢包擦，日一、二次。（《秘传经验方》）', tips='无寒实积滞、孕妇及体弱者忌服。不宜与牵牛子同用。 恶蘘草。畏大黄、黄连、藜芦。 ②《药对》：畏芦笋、菰笋、酱鼓、冷水。得火良。与牵牛相反。 ③《药性论》：能落胎。 ④《本草衍义补遗》：无寒积者忌之。' where id=1677; -- 巴豆
update herbs set taste='甘、寒。', channel='入肺、胃、小肠经。', effect='①治吐血不止：白茅根一握。水煎服之。（《千金翼方》） ②治血热鼻衄：白茅根汁一台。饮之。（《妇人良方》） ③治鼻衄不止：茅根为末，米泔水服二钱。《圣惠方》） ④治喘：茅根一握（生用旋采），桑白皮等分。水二盏，煎至一盏，去滓温服，食后。（《圣惠方》如神汤） ⑤治温病有热，饮水暴冷哕者：茅根、葛根（各切）半升。以水四升，煮取二升，稍温饮之，啘止则停。（《小品方》茅根汤） ⑥治胃反，食即吐出，上气：芦根、茅根各二两。细切，以水四升，煮取二升，顿服之，得下，良。（《千金方》） ⑦治小便热淋：白茅根四升。水一斗五升，煮取五升，适冷暖饮之，日三服。（《肘后方》） ⑧治小便出血：茅根一把。切，以水一大盏，煎至五分，去滓，温温频服。（《圣惠方》） ⑨治劳伤溺血：茅根、干姜等分。入蜜一匙，水二钟，煎一钟，日一服。（《纲目》） ⑩治血尿：白茅根，车前子各一两，白糖五钱。水煎服。（内蒙古《中草药新医疗法资料选编》） ⑾治乳糜尿：鲜茅根半斤。加水2000毫升煎成约1200毫升，加糖适量。每日分三次内服，或代茶饮，连服五至十五天为一疗程。（《江苏省中草药新医疗法展览资料选编》） ⑿治肾炎：白茅根一两，一枝黄花一两，葫芦壳五钱，白酒药一钱。水煎，分二次服，每日一剂，忌盐。（《单方验方调查资料选编》） ⒀治阳虚不能化阴，小便不利，或有湿热壅滞，以致小便不利，积成水肿：白茅根一斤。掘取鲜者，去净皮与节间小根，细切，将茅根用水四大碗，煮一沸，移其锅置炉旁，候十数分钟，视其茅根若不沉水底，再煮一沸，移其锅置炉旁，须臾视其根皆沉水底，其汤即成，去渣温服，多半杯，日服五、六次，夜服两、三次，使药力相继，周十二时，小便自利。（《医学衷中参西录》白茅根汤） ⒁治卒大腹水病：白茅根一大把，小豆三升。水三升，煮干，去茅根食豆，水随小便下。（《补缺肘后方》） ⒂治黄疸、谷疸、酒疸、女疸、劳疸、黄汗：生茅根一把。细切，以猪肉一斤，合作羹，尽啜食之。（《补缺肘后方》） ⒃治血热经枯而闭：茅根、牛膝、生地黄，童便。煎服。（《本草经疏》） ⒄解曼陀罗中毒：白茅根一两，甘蔗一斤。捣烂，榨汁，用一个椰子水煎服。（《南方主要有毒植物》）' where id=1678; -- 白茅根
update herbs set alias='白根、昆仑，猫儿卵，鹅抱蛋，见肿消，', taste='苦；辛；性微寒。', channel='入心、肝、脾经。', effect='①治痈肿：㈠白蔹二分，藜芦一分。为末，酒和如泥，贴上，日三。（《补缺肘后方》） ㈡白蔹、乌头（炮）、黄芩各等分。捣末筛，和鸡子白敷上。（《普济方》白蔹散） ②敛疮：白蔹、白芨、络石各半两，取干者。为细末，干撒疮上。（《鸡峰普济方》白蔹散） ③治聤耳出脓血：白蔹、黄连（去须）、龙骨、赤石脂、乌贼鱼骨（去甲）各一两。上五味，捣罗为散。先以绵拭脓干，用药一钱匕，绵裹塞耳中。（《圣济总录》白蔹散） ④治白癜风，遍身斑点瘙痒：白蔹三两.天雄三两（炮裂去皮脐），商陆一两，黄芩二两，干姜二两（炮裂、锉），踯躅花一两（酒拌炒令干）。上药捣罗为细散，每于食前，以温酒调下二钱。（《圣惠方》白蔹散） ⑤治冻耳成疮，或痒或痛者：黄柏、白蔹各半两。为末。先以汤洗疮，后用香油调涂。（《仁斋直指方》白蔹散） ⑥治瘰疬生于颈腋，结肿寒热：白蔹、甘草、玄参、木香、赤芍药、川大黄各半两。上药捣细罗为散，以醋调为膏，贴于患上，干即易之。（《圣惠方》白蔹散） ⑦治皮肤中热痱、瘰疬：白蔹、黄连各二两，生胡粉一两。上捣筛，容脂调和敷之。（《刘涓子鬼遗方》白蔹膏） ⑧治扭挫伤：见肿消二个，食盐适量。捣烂外敷。（《全展选编·外科》） ⑨治汤火灼烂：白蔹末敷之。（《备急方》） ⑩治吐血、咯血不止：白蔹三两，阿胶二两（炙令燥）。上二味，粗捣筛，每服二镜匕，酒水共一盏，入生地黄汁二合，同煎至七分，去滓，食后温服。如无地黄汁。入生地黄一分同煎亦得。（《圣济总录》白蔹汤）' where id=1679; -- 白蔹
update herbs set alias='蕃荷菜，菝蔺、吴菝蔺，南薄荷，猫儿薄苛，升阳菜，薄苛，蔢荷，夜息花。', taste='味辛；性凉。', channel='入肺、肝经。', effect='①清上化痰，利咽膈，治风热：薄荷末炼蜜丸，如芡子大，每噙一丸。白沙糖和之亦可。（《简便单方》） ②治眼弦赤烂：薄荷，以生姜汁浸一宿，晒干为末，每用一钱，沸汤泡洗。（《明目经验方》） ③治瘰疬结成颗块，疼痛，穿溃，脓水不绝，不计远近：薄荷一束如碗大（阴干），皂荚十挺（长一尺二寸不蛀者，去黑皮，涂醋，炙令焦黄）。捣碎，以酒一斛，浸经三宿，取出曝干，更浸三宿，如此取酒尽为度，焙干，捣罗为散，以烧饭和丸，如梧桐子大。每于食前，以黄芪汤下二十丸，小儿减半服之。（《圣惠方》薄荷丸） ④治风气瘙痒：大薄荷、蝉蜕等分为末，每温酒调服一钱。（《永类钤方》） ⑤治血痢：薄荷叶煎汤单服。（《普济方》） ⑥治衄血不止：薄荷汁滴之。或以干者水煮，绵裹塞鼻。（《本事方》） ⑦治蜂虿螫伤：薄荷按贴之。（孟诜《必效方》） ⑧治火寄生疮如灸，火毒气入内，两股生疮，汁水淋漓者：薄荷煎汁频涂。（《医说》） ⑨治耳痛：鲜薄荷绞汁滴入。（《闽东本草》）' where id=1680; -- 薄荷
update herbs set taste='苦、酸，微寒。', channel='入肝、脾经。', effect='①治妇人胁痛：香附子四两（黄子醋二碗，盐一两，煮干为度），肉桂、延胡索（炒）、白芍药。为细末，每服二钱，沸汤调，无时服。（《朱氏集验医方》芍药汤） ②治下痢便脓血，里急后重，下血调气：芍药一两，当归半两，黄连半两，槟榔、木香二钱；甘草二钱（炒），大黄三钱，黄芩半两，官桂二钱半。上细切，每服半两，水二盏，煎至一盏，食后温服。（《素问病机保命集》芍药汤） ③治妇人怀妊腹中疞痛：当归三两，芍药一斤，茯苓四两，白术四两，泽泻半斤，芎藭半斤（一作三两）。上六味，杵为散。取方寸匕，酒和，日三服。（《金匮要略》当归芍药散） ④治产后血气攻心腹痛：芍药二两，桂（去粗皮）、甘草（炙）各一两。上三味，粗捣筛，每服三钱匕，水一盏，煎七分，去滓，温服，不拘时候。（《圣济总录》芍药汤） ⑤治痛经：白芍二两，干姜八钱。共为细末，分成八包，月经来时，每日服一包，黄酒为引，连服三个星期。（内蒙古《中草药新医疗法资料选编》） ⑥治妇女赤白下，年月深久不差者：白芍药三大两，干姜半大两。细锉，熬令黄，捣下筛.空肚，和饮汁服二钱匕，日再。（《广利方》） ⑦治金创血不止，痛：白芍药一两，熬令黄，杵令细为散。酒或米次下二钱，并得。初三服，渐加。（《广利方》） ⑧治脚气肿痛：白芍药六两，甘草一两。为末，白汤点服。（《岁时广记》） ⑨治风毒骨髓疼痛：芍药二分，虎骨一两（炙）。为末，夹绢袋盛，酒三升，渍五日。每服三合，日三服。（《经验后方》）', tips='虚寒腹痛泄泻者慎服。 恶石斛、芒消。畏消石、鳖甲、小蓟。反藜芦。 ②《本草经疏》：凡中寒腹痛，中寒作泄，腹中冷痛，肠胃中觉冷等证忌之。 ③《药品化义》：疹子忌之。 ④《得配本草》：脾气虚寒，下痢纯血禁用。' where id=1681; -- 白芍
update herbs set taste='甘；微苦；微寒。', channel='入心、肺经。', effect='①治咳嗽不巳，或痰中有血：款冬花、百合（焙，蒸）等分。上为细末，炼蜜为丸，如龙眼大。每服-丸，食后临卧细嚼，姜汤咽下，噙化尤佳。（《济生方》百花膏） ②治支气管扩张、咯血：百合二两，白及四两，蛤粉二两，百部一两。共为细末，炼蜜为丸，每重二钱，每次一丸，日三次。（《新疆中草药手册》） ③治肺病吐血：新百合捣汁，和水坎之，亦可煮食。（《卫生易简方》） ④治背心前胸肺慕间热，咳嗽咽痛，咯血，恶寒，手大拇指循白肉际间上肩背至胸前如火烙：熟地、生地、归身各三钱，白芍、甘草各一钱，桔梗、元参备八分，贝母、麦冬、百合各钱半。如咳嗽，初一、二服，加五味子二十粒。（《慎斋遗书》百合固金汤） ⑤治肺脏壅热烦闷：新百合四两，用蜜半叠，拌和百合，蒸令软，时时含如枣大，咽津。（《圣惠方》） ⑥治百合病发汗后者：百合七枚（擘），知母三两（切）。上先以水洗百合，渍一宿，当白沫出，去其水，更以泉水二升，煎取一升，去渣；别以泉水二升煎知母，取一升，去渣后，合和煎取一升五合，分温再服。（百合知母汤） ⑦治百合病吐之后者：百合七枚（擘），鸡子黄一枚。上先以水洗百合，渍一宿，当白沫出，去其水，更以泉水二升，煎取-升，去渣，内鸡子黄，搅匀，煎五分，温服。（百合鸡子汤） ⑧治百合病下之后者：百合七枚（擘），滑石三两（碎，绵裹），代赭石如弹丸大一枚（碎，绵裹）。上先以水洗百合，渍一宿，当白沫出，去其水，更以泉水二升，煎取-升，去渣；别以泉水二升煎滑石、代赭取-升，去渣后，合和重煎，取-升五合，分温服。（滑石代赭汤） ⑨治百合病不经吐下发汗，病形如初者：百合七枚（擘），生地黄汁一升。上以水洗百合，渍一宿，当白沫出，去其水，更以泉水二升煎取-升，去渣，内地黄汁煎取一升五合，分温再服，中病勿更服，大便当如漆。（百合地黄汤） ⑩治百合病变发热者：百合一两（炙），滑石三两。上为散，饮服方寸匕，日三服，当微利者止服，热则除。（百合滑石散。⑥方以下出《金匮要略》） ⑾治神经衰弱，心烦失眠，百合五钱，酸枣仁五钱，远志三钱。水煎服。（《新疆中草药手册》） ⑿治肺痈：白花百合，或煮或蒸，频食。拌蜜蒸更好。（《经验广集》百合煎） ⒀治疮肿不穿：野百合同盐捣泥敷之良。（《包会应验方》） ⒁治天疱湿疮：生百合捣涂，一、二日即安。（《濒湖集简方》） ⒂治耳聋、耳痛：干百合为末，温水服二钱，日二服。（《千金方》）' where id=1682; -- 百合
update herbs set alias='薛、芷，芳香，苻蓠、泽芬，白茝，香白芷（《夷坚志', taste='味辛；性温。', channel='入肺、髀、胃经。', effect='①治头痛及目睛痛：白芷四钱，生乌头一钱。上为末，每服一字，茶调服。有人患眼睛痛者，先含水，次用此搐入鼻中，其效更速。（《朱氏集验医方》白芷散） ②治诸风眩晕，妇人产前产后乍伤风邪，头目昏重及血风头痛，暴寒乍暖，神思不清，伤寒头目昏晕等证：香白芷（用沸汤泡洗四、五遍）为末，炼蜜和丸如弹子大。每服一丸，多用荆芥点腊茶细嚼下。（《百一选方》都粱丸） ③治半边头痛：白芷、细辛、石膏、乳香、没药（去油）。上各味等分，为细末，吹入鼻中，左痛右吹，右痛左吹。（《种福堂公选良方》白芷细辛吹鼻散） ④治眉框痛，属风热与痰：黄芩（酒浸炒），白芷。上为末，茶清调二钱。（《丹溪心法》） ⑤治鼻渊：辛夷、防风、白芷各八分，苍耳子一钱二分，川芎五分，北细辛七分，甘草三分。白水煎，连服四剂。忌牛肉。（《疡医大全》） ⑥治肠风：香白芷为细末，米坎调下。（《百一选方》） ⑦治大便风秘：香白芷炒为末，每服二钱，米饮入蜜少许，连进二服。（《十便良方》） ⑧治痔疮肿痛：先以皂角烟熏之，后以鹅胆汁调白芷末涂之。（《医方摘要》） ⑨治带下，肠有败脓，淋露不已，腥秽殊甚，脐腹冷痛，须此排脓：白芷一两，单叶红蜀葵根二两，芍药根（白者）、白矾各半两（矾烧枯，别研）。为末，同以蜡丸如梧子大，空肚及饭前，米饮下十丸或十五丸，候脓尽，仍别以他药补之。（《本草衍义》） ⑩治肿毒热痛：醋调白芷末敷之。（《卫生易简方》） ⑾治痈疽赤肿：白芷，大黄等分。为末，米饮服二钱。（《经验方》） ⑿治刀箭伤疮：香白芷嚼烂涂之。（《濒湖集简方》）', tips='阴虚血热者忌服。 恶旋覆花。 ②《本草经疏》：呕吐因于火者禁用。漏下赤白阴虚火炽血热所致者勿用。痈疽已溃，宜渐减去。' where id=1683; -- 白芷
update herbs set channel='入大肠、小肠、肝、肾经。', effect='①治痈疽，拔脓，痈疽不破，或破而肿硬无脓：斑蝥为末，以蒜捣膏，和水一豆许贴之，少顷脓出，即去药。（《仁斋直指方》） ②治疔肿：斑猫一枚，捻破，然后以针画疮上，作米字，以封上。（《备急方》） ③治干癣积年生痂，搔之黄水出，每逢阴雨即痒：斑猫半两，微炒为末，蜜调敷之。（《外台秘要方》） ④治牛皮癣：斑蝥一个，甘遂一钱。共研细末，以醋调和，日擦数次。（《吉林中草药》） ⑤治颜面神经麻痹：斑蝥一个。研细，水调贴颊上，向左歪斜贴右侧，向右歪斜贴左侧。起泡即取去。（《山东中草药手册》） ⑥治急性扁桃体炎，急性咽、喉炎：斑蝥适量。研末，取少许放清膏药中心，如是扁桃体炎贴患侧颈外压痛处，如是咽、喉炎贴两侧人迎穴，待皮肤起泡（约三至四小时），即可揭去。起泡处用酒精消毒，再用消毒过的针刺破水泡，放出液体，涂上红汞，外盖纱布，用胶布固定。（《河北中药手册》） ⑦治疟疾：斑蝥七只，麻黄、雄精各一钱二分，朱砂半钱。共研细末，每次用一至三分，调放在膏药上，贴头颈项第二骨节处。（《浙江中医杂志》（7）：39，1959） ⑧治剧烈头痛：斑蝥（去头、足）三至五个。研末布包，贴痛处。起泡后.用针刺破。使水流出。（江西《草药手册》） ⑨治疣痣黑子：斑蝥三个，人言少许。以糯米五饯，炒黄去米，入蒜一个，捣烂点之。（《纲目》） ⑩治耳卒聋：斑猫二枚（去翅、足，炒黄），巴豆一枚（去心、皮，生用）。同研令匀，绵裹塞耳中。（《圣惠方》） ⑾治大人小儿瘰疬内消方：斑猫一两，去翅、足，用粟米一升，同斑猫炒令米焦黄，去米不用，细研，入于薄荷末四两，同研令匀，以乌鸡子清丸如绿豆大。空心腊茶下一丸，加至五丸，却每日减一丸，减至一丸后，每日服五丸。（《经验方》） ⑿治一切瘘：斑猫三十枚（去头、足、翅，糯米拌炒令米黄），蜥蝎三枚（炙令黄），地胆四十枚（去头，足、翅，糯米拌炒令米黄）。搀罗为末，炼蜜和丸，如黑豆大。每日空心及晚食后，以温酒二十丸。（《圣惠方》） ⒀治疯狗咬伤：斑蝥三七枚，去头、翘、足，先以七枚，用糯米一勺，略炒过，去斑蝥；别以七枚，如前炒，色变复去之；别以七枚如前，至青烟为度，去蝥，只以米为粉。用冷水入清油少许，空心调服，须臾再进一服，以小便利下毒物为度；如不利，再进。利后肚疼，急用冷水调青靛服之，以解其毒，否则有伤。黄连水亦可解之。但不宜服一切热物也。（《医方大成论》） ⒁治经候闭塞及干血气：斑猫十个（糯米炒），桃仁四十九个（炒），大黄五钱。共为细末，酒糊为丸，如桐子大。空心酒下五丸，甚者十丸。如血枯经闭者，用四物汤送下。（《济阴纲目》斑猫通经丸） ⒂治血疝便毒，不拘已成未成，随即消散：斑蝥三个（去翅、足，炒），滑石三钱（同研）。分作三服，空心白汤下，日一服，毒从小便出，如痛，以车前、木通、泽泻、猪苓煎饮。（李杲·破毒散）' where id=1684; -- 斑蝥
update herbs set alias='山蓟、杨抱蓟，术，山姜，乞力伽，山精，山连，冬白术。', taste='味苦；甘；性温。', channel='归脾；胃经。', effect='①治虚弱枯瘦，食而不化：於术（酒浸，九蒸九晒）一斤，菟丝子（酒煮吐丝，晒干）一斤，共为末，蜜丸，梧子大。每服二、三钱。（《纲目拾遗》） ②治脾虚胀满：白术二两，橘皮四两。为末，洒糊丸，梧子大。每食前木香汤送下三十丸。（《全生指迷方》宽中丸） ③治痞，消食强胃：枳实（麸炒黄色）一两，白术二两。上为极细末，荷叶裹烧饭为丸，如绿豆一倍大。每服五十丸，白汤下，不拘时候，量所伤多少，加减服之。（《兰室秘藏》积术丸） ④服食滋补，止久泄痢：上好白术十两，切片，入瓦锅内，水淹过二寸，文武火煎至一半，倾汁入器内，以渣再煎，如此三次，乃取前后汁同熬成膏，入器中一夜，倾去上面清水，收之。每服二、三匙，蜜汤调下。（《千金良方》白术膏） ⑤治脾虚泄泻：白术一两，芍药半两（冬月不用芍药，加肉豆蔻，泄者炒）。上为末，粥丸。（《丹溪心法》白术丸） ⑥治小儿久患泄泻，脾虚不进饮食，或食讫仍前泻下，米谷不化：白术一分（米泔浸一时，切，焙干），半夏一钱半（浸洗七次），丁香半钱（炒）。上为细末，生姜自然汁糊丸，黍米大。每半岁儿三丸，三五岁儿五、七丸，淡生姜汤下，早晚各一。（《小儿卫生总微论方》温白丸） ⑦治湿泻暑泻：白术、车前子等分，炒为末，白汤下二、三钱。（《简便单方》） ⑧治肠风痔漏、脱肛泻血、面色萎黄，积年久不瘥：白术一斤（糯米泔浸三日，细研锉，炒焦为末），干地黄半斤（净洗，用碗盛于甑上蒸烂细研）。上相和，如硬，滴酒少许，众手丸梧桐子大，焙干。每服十五丸，空心粥饮下，加至二十丸。（《普济方》香术丸） ⑨治心下坚，大如盘，边如旋盘，水饮所作：枳实七枚，白术二两。上二味，以水五升，煮取三升，分温三服，腹中耍即当散也。（《金匮要赂）枳术汤） ⑩治伤寒八九日，风湿相搏，身体疼烦，不能自转侧，不呕不渴，脉浮虚而涩，大便坚，小便自利者：白术二两，附子一枚半（炮去皮），甘草一两（炙），生姜一两半（切），大枣六枚。上五味，以水三升，煮取一升去滓，分温三服，一服觉身痹半日许，再服。三服都尽，其人如冒状，勿怪，即是术、附并走皮中，逐水气未得除故耳。（《金匮要略》白术附子汤） ⑾治中湿，口噤，不知人：白术半两，酒三盏。煎一盏，顿服；不能饮酒，以水代之。日三，夜一。（《三因方》白术酒） ⑿治忽头眩运，经久不差，四体渐羸，食无味，好食黄土：白术三斤，曲三斤。上二味搀筛酒和，并手捻丸如梧子，暴干。饮服二十枚，日三。忌桃、李、雀肉等。（《外台》） ⒀治风虚，头重眩，苦极，不知食味。暖肌，补中，益精气：白术二两，附子一枚半（炮去皮），甘草一两（炙）。上三味，锉，每五钱匕，姜五片，枣一枚，水盏半，煎七分，去滓，温服。（《近效方》术附汤） ⒁治自汗不止：白术末，饮服方寸匕，日二服。（《千金方》） ⒂治盗汗：白术四两，分作四份，一份用黄芪同炒，一份用石斛同炒，一份用牡蛎同炒，一份用麸皮同炒。上各微炒黄色，去余药。只用白术，研细。每服二钱，粟米汤调下，尽四两。（《丹溪心法》） ⒃治老小虚汗：白术五钱，小麦一撮，水煮干，去麦为末，用黄芪汤下一钱。（《全幼心鉴》） ⒄治产后呕逆不食：白术五钱，姜六钱。水煎，徐徐温服。（《妇人良方》） ⒅治妇人血虚肌热，或脾虚蒸热，或内热寒热：白术、白茯苓、白芍药（炒）各一钱，甘草（炒）五分，姜、枣，水煎。（《妇人良方》乞力伽散） ⒆治三日疟：九制於术一斤，广皮八两。熬膏，用饴糖四两收。（《古今良方》） ⒇治四日两头疟，一、二年至三、四年不愈者，或愈而复发，连绵不巳者：於术一两，老姜一两。水煎，发日五更温服，重者二服。（《纲目拾遗》） （21）治牙齿逐日长，渐渐胀，开口难为饮食，盖髓溢所致：只服白术愈。（《夏子益治奇疾方》） （22）治儿童流涎：生白术捣碎，加水和食糖，放锅上蒸汁，分次口服，每天用三钱。（《江苏中医》（12）：1，1965）', tips='阴虚燥渴，气滞胀闷者忌服。 ②《药品化义》：凡郁结气滞，胀闷积聚，吼喘壅塞，胃痛由火，痈疽多脓，黑瘦人气实作胀，皆宜忌用。' where id=1685; -- 白术
update herbs set taste='辛，温，有毒。', channel='入脾、胃经。', effect='①治湿痰，咳嗽脉缓，面黄，肢体沉重，嗜卧不收，腹胀而食不消化：南星、半夏（俱汤洗）各一两，白术一两半。上为细末，糊为丸，如桐子大.每服五、七十丸，生姜汤下。（《紊问病机保命集》） ②治湿痰喘急，止心痛：半夏不拘多少，香油炒，为末，粥丸梧子大。每服三、五十丸，姜汤下。（《丹溪心法》） ③治痰饮咳嗽：大半夏一斤，汤泡七次，晒干，为细末，用生绢袋盛贮，于磁盆内用净水洗，出去粗柤，将洗出半夏末，就于盆内日晒夜露，每日换新水，七日七夜了，澄去水，晒干，每半夏粉一两，入飞过细朱砂末一钱，用生姜汁糊为丸，如梧桐子大。每服七十丸，用淡生姜汤下，食后服。（《袖珍方》辰砂半夏丸） ④治心下有支饮（呕家本渴，渴者为欲解，今反不渴）：半夏一升，生姜半斤。上二味，以水七升，煮取一升半，分温再服。（《金匮要略》小半夏汤） ⑤治肺胃虚弱，好食酸冷，寒痰停积，呕逆恶心，涎唾稠粘，或积吐，粥药不下，手足逆冷，目眩身重；又治伤寒时气，欲吐不吐，欲呕不呕，昏瞶闷乱，或饮酒过多，中寒停饮，喉中涎声，干哕不止：陈皮（去白）、半夏（煮）各七两。上二件，锉为粗散，每服三钱，生姜十片，水二盏，煎至一中盏，去滓温服，不拘时候。留二服滓并作一服，再煎服。（《局方》橘皮半夏汤） ⑥治卒呕吐，心下痞，膈间有水，眩悸者：半夏一升，生姜半斤，茯芩三两。上三味，以水七升，煮取一升五合，分温再服。（《金匮要略》小半夏加茯苓汤） ⑦治胃反呕吐者：半夏二升（洗完用），人参三两，白蜜一升。上三味，以水一斗二升，和蜜汤之二百四十遍，煮药取二升半，温服一升，余分再服。（《金匮要略》大半夏汤） ⑧治妊娠呕吐不止：干姜、人参各一两，半夏二两。上三味，末之，以生姜汁糊为丸，如梧子大。饮服十丸，日三服。（《金匮要略》干姜人参半夏丸） ⑨治小儿痰热，咳嗽惊悸：半夏、南星等分，为末，牛胆汁，入胆内和，悬风处待干，蒸饼丸，绿豆大。每服三、五丸，姜汤下。（《摘元方》） ⑩治霍乱心腹胀痛，烦满短气，未得吐下：桂、半夏等分。末，方寸匕，水一升，和服之。（《补缺肘后方》） ⑾除积冷，暖元藏，温脾胃，进饮食，治心腹一切痃癖冷气及年高风秘、冷秘或泄泻：半夏（汤浸七次，焙干，为细末）、硫黄（明净好者，研令极细）。上等分，以生姜自然汁同熬，入干蒸饼末搅和匀，入臼内杵数百下，丸如梧桐子大。每服空心温酒或生姜汤下十五丸至二十丸，妇人醋汤下。（《局方》半硫丸） ⑿治痰厥：半夏八两，防风四两，甘草二两。同为细末，分作四十服，每服用水一大盏半，姜二十片，煎至七分，去滓温服，不计时侯。（《卫生家宝方》省风汤） ⒀治目不瞑，不卧：以流水千里已外者八升，扬之万遍，取其清五升煮之，炊以苇薪火，沸，置秫米一升，治半夏五合，徐炊令竭，为一升半，去其滓，饮汁一小杯，日三，稍益，以知为度。（《灵枢》半夏秫米汤） ⒁治少阴病，咽中痛：半夏（洗）、桂枝（去皮）、甘草（炙）。上三味等分，各别捣筛已，合治之，白饮和服方寸匕，日三服。若不能服散者，以水一升，煎七沸，纳散两方寸匕，更煮三沸，下火令小冷，少少咽之。（《伤寒论》半夏散及汤） ⒂治痰结，咽喉不利，语音不出：半夏（洗）五钱，草乌一字（炒），桂一字（炙）。上同为末，生姜汁浸蒸饼为丸，如鸡头大，每服一丸，至夜含化。（《素问病机保命集》玉粉丸） ⒃治喉痹肿塞：生半夏末搐鼻内，涎出效。（《濒湖集简方》） ⒄治产后晕绝：半夏末，冷水和丸，大豆大，纳鼻中。（《肘后方》） ⒅治奶发，诸痈疽发背及乳方：末半夏，鸡于白和涂之，水磨敷。（《补缺肘后方》） ⒆治小儿惊风：生半夏一钱，皂角半钱。为末，吹少许入鼻。（《仁斋直指方》嚏惊散） ⒇治重舌木舌，肿大塞口：半夏煎醋，合漱之。（《纲目》） （21）治诸瘘五六孔相通：生半夏末，水调涂孔内，一日二次。（《外科小品》） （22）治外伤性出血：生半夏、乌贼骨等分，研细末，撒患处。（徐州《单方验方新医疗法选编》） （23）治蛇伤：鲜半夏、鸭食菜（苦麻菜）、香蒿尖各等量，混合捣碎成膏状，敷于伤处。（辽宁《中草药新医疗法资料选编》）', tips='阴虚燥咳、津伤口渴、血证及燥痰者禁服，孕妇慎服。 半夏使用不当可引起中毒，表现为口舌咽喉痒痛麻木，声音嘶哑，言语不清，流涎，味觉消失，恶心呕吐，胸闷，腹痛腹泻严重者可出现喉头痉挛，呼吸困难，四肢麻痹，血压下降，肝肾功能损害等，最后可因呼吸中枢麻痹而死亡。 恶皂荚。畏雄黄、生姜、干姜、秦皮、龟甲。反乌头。 ②《药性论》：忌羊血、海藻、饴糖。 ③张元素：诸血证及口渴者禁用。孕妇忌之，用生姜则无害。 ④《医学入门》：凡诸血证及自汗，渴者禁用。' where id=1686; -- 半夏
update herbs set taste='味苦；辛；性温。', channel='入脾、胃、大肠经。', effect='①治寸白虫： 槟榔二七枚。 治下筛。 以水二升半，先煮其皮，取一升半，去滓纳末，频服暖卧，虫出。出不尽，更合服，取瘥止。宿勿食，服之。(《千金方》) ②治诸虫在脏腑久不瘥者： 槟榔半两(炮)为末。每服二钱，以葱蜜煎汤调服一钱。 (《圣惠方》) ③治食积满闷成痰涎呕吐者： 槟榔、半夏、砂仁、萝卜子、麦芽、干姜、白术各二钱。水煎服。 (《方脉正宗》) ④治脾胃两虚，水谷不能以时消化，腹中为胀满痛者： 槟榔二两，白术三两，麦芽二两，砂仁一两。俱炒燥为末。每早服三钱，白汤调服。 (《方脉正宗》) ⑤治心脾疼： 高良姜、槟榔等分(各炒)。上为细末。米饮调下。 (《百一选方》) ⑥治伤寒发汗或下后痞满，或成寒实结胸，气塞不通： 槟榔二个(一生一煨)。细末。酒二盏，煎一盏四，分作两服，温饮之。 兼治蛔厥，心腹刺痛。 (《伤寒总病论》槟榔散) ⑦治大小便不通，亦治肠胃有湿，大便秘涩： 槟榔至大者半枚。用麦门冬煎水磨一钱，重汤烫热服之。 (《普济方》槟榔散。《纲目》以本方治血淋作痛) ⑧治干霍乱，上气冲急，欲闷绝，大小便不通： 槟榔七枚。锉，粗捣筛。每服五钱匕，水一盏，童子小便半盏，煎至一盏，去滓温服，日再。(《圣济总录》槟榔汤) ⑨治下痢脓血，里急后重，日夜无度： 芍药一两，当归五钱，大黄、黄芩、黄连、木香各一钱半，槟榔一钱。为末。每服三、五钱，水一盏，煎至七分，去滓，温服。如未止，再服，不后重则止。 (《素问病机保命集》导气汤) ⑩治脾、肺、肾三脏受伤，水气不化，积为肿满，渐成喘急，不能偃卧者：槟榔三钱，白芍药(炒)、茯苓、猪苓、泽泻、车前子各二钱，肉桂一钱。水煎服。(《方脉正宗》) (11)治五淋： 赤芍药一两，槟榔一个(面裹煨)。上为末，每服一钱，水煎，空心服。 (《博济方》) (12)治脚气冲心： 白槟榔一个(鸡心大者)。 为末。用童子小便、生姜汁、温酒共半盏凋，只作一服，无时服，(《简要济众方》) (13)治脚气累发，渐成水肿不消： 大腹子。 滚汤磨汁半盏，食前服，日二次。服二月。 (《本草汇言》) (14)治痰涎： 槟榔为末。 白汤点(服)一钱。(《御药院方》) (15)治醋心： 槟榔四两，橘皮二两。细捣为散。空心，生蜜汤下方寸匕。(《梅师集验方》) (16)治乌癞： 大腹生者二枚，如无生者，干者亦得，用皮全者，勿令伤动。以酒一升浸，缓火熬令酒尽药干，捣罗为末，炼腊月猪膏，调和如膏敷之。 (《圣济总录》大腹子膏) (17)治小儿头疮，积年不瘥： 槟榔水磨，以纸衬，晒干，以生油调涂之。 (《圣惠方》) (18)治口吻生白疮： 槟榔二枚。烧灰细研，敷疮上。(《圣惠方》) (19)治盯耳出脓： 槟榔研末吹之。 (《鲍氏小儿方》) (20)治丹毒从脐上起黄肿： 槟榔，为末，醋调涂。 (《续本事方》) (21)治金疮： 白槟榔、黄连少许，为末敷之。(《经验方》) (22)治阴毛生虱： 槟榔煎水洗。 (《本草备要》)' where id=1687; -- 槟榔
update herbs set taste='辛，温。', channel='入肺、胃经。', effect='①治高年咳嗽，气逆痰痞：紫苏子、白芥子、萝卜子。上三味各洗净，微炒，击碎，看何证多，则以所主者为君，余次之。每剂不过三钱，用生绢小袋盛之，煮作汤饮。（《韩氏医通》三子养亲汤） ②治风湿涎痰，结成痞块：外用白芥子为末，醋凋敷患上。内用白芥子为末，神曲打糊丸梧子大。每服三钱，清晨参枣汤下。（《方脉正宗》） ③治翻胃，吐食上气，及羸弱不欲动：白芥子，晒干，为末，酒服方寸匕。（《普济方》） ④治伤寒后，肺中风冷，失音不语：白芥子五合（研碎）。用酒煮令半热，带热包裹熨项颈周延，冷则易之。（《圣济总录》芥子酒熨方） ⑤治臂痛牵引背胛，或辍或作，由荣卫循行失度，痰滞经络，或似瘫痪：真白芥子、木鳖子各三两（麸炒），没药（另研）、桂心、木香各半两。上为末，每服一钱，温酒下。（《妇人良方》白芥子散） ⑥治风湿脚气肿疼无力：白芥子、芸薹子、蓖麻子、木鳖子（去壳）、白胶香各一两，胡桃五枚（去壳）。上六味，一处捣三千杵，成膏。每用皂子大，摩疼处。（《圣济总录》芥子膏） ⑦治肿毒初起：白芥子末醋调涂之。（《濒湖集简方》） ⑧治小儿乳癖：白芥子研末水调，摊膏贴之，以平为期。（《本草权度》） ⑨治牙痛：白芥子、舶上莎罗、芸薹子各一两。捣细罗为散。每用一字，如患左边疼，即吹右鼻中，如患右边，即吹左鼻中，仍先净洗鼻中，吹药。（《圣惠方》白芥子吹鼻散）' where id=1688; -- 白芥子
update herbs set taste='味咸；性寒；小毒。', effect='①治瘫痪，手足走痛不止（非痛勿用）：御米壳（蜜炒）一钱，陈皮五钱，壁虎（炙黄）、乳香、没药、甘草各二钱五分。上为末。每服三钱，煎服。（《医学正传》如神救苦散） ②治历节风，疼痛不可忍：蛴螬（湿纸裹煨熟，研）三枚，壁虎（研）三枚，地龙（去泥，研）五条，乳香一分（研），草乌头三枚（生，去皮），木香半两，麝香（研）一钱，虎脑（研）半钱。上八味，将草乌头、木香捣罗为末，合研匀，为丸，如干入少酒煮面糊，如梧桐子大。每服三十丸，临卧乳香酒下。（《圣济总录》麝香丸） ③治破伤风，如角弓反张，筋脉拘急，口噤：辟宫子七枚（微炙），天南星一两（炮裂），腻粉一两，白附子一两（炮裂）。上药捣罗为末，炼蜜和丸如绿豆大。每服不计时候，以温酒研下七丸，以汗出为效，未汗再服。（《圣惠方》） ④治久年惊痫，心血不足：守宫一两，珍珠、麝香、片脑各一字（研细）。上将守宫一个，以铁钤钤定，剪去四足，连血细研，入珍珠、麝香、片脑各一字许，研细，薄荷汤调作一服。先须用夺命散，逐下痰涎，或用吐法，次服此药。（《奇效良方》守宫膏） ⑤治心虚惊痫：褐色壁虎一枚。连血研烂，入朱砂、麝香少许，薄荷汤调服。继服二陈汤。（《仁斋直指方》） ⑥治疠风：蝎虎一条（焙干），大蚕沙五升（筛净，水淘二遍，晒干），白面四斤或五斤，拌蚕沙为络索，晒干。上为末，每服一、二合，熬柏叶汤调服，食前，日三服。（《卫生宝鉴》祛风散） ⑦治瘰疬初起：壁虎一枚，焙研。每日服半分，酒服。（《青囊杂纂》） ⑧治痈疮大痛：壁虎焙干研末，油调敷之。（《医方摘要》） ⑨治反胃膈气：地塘虫七个（砂锅炒焦），木香、人参、朱砂各-钱半，乳香一钱，为末；蜜丸梧子大。每服七丸，木香汤下，早晚各一服。（《摘元方》）' where id=1689; -- 壁虎
update herbs set taste='味辛；苦；性寒。', effect='①治吐血、咯血：鲜狭叶韩信草一至二两，捣烂绞汁，调蜜少许，炖热温服，日二次。（《泉州本草》） ②治尿道炎，小便尿血疼痛：鲜狭叶韩信草一两，洗净，煎汤，调冰糖服，日二次。（《泉州本草》） ③治热性血痢：小韩信草二两，煎服。（《广西药植图志》） ④治痢疾：鲜狭叶韩信草三至五两，捣烂绞汁服；或干全草一两，水煎服。（《福建中草药》） ⑤治肝炎：鲜半枝莲五钱，红枣五个。水煎服。（《浙江民间常用草药》） ⑥治胃气痛：干狭叶韩信草一两，和猪肚或鸡一只（去头及脚尖，内脏），水、酒各半炖热，分二、三次服。（《泉州本草》） ⑦治咽喉肿痛：鲜狭叶韩信草八钱，鲜马鞭草八钱，食盐少许。水煎服。（《福建中草药》） ⑧治咽喉炎、扁桃体炎：半枝莲、鹿茸草、一枝黄花各三钱。水煎服。（《浙江民间常用草药》） ⑨治肺脓疡：半枝莲、鱼腥草各一两。水煎服。（《浙江民间常用草药》） ⑩治蛇头疔、淋巴腺炎：鲜狭叶韩信草-至二两，调食盐少许，捣烂外敷。（《福建中草药》） ⑾治淋巴结核：半枝莲二两，水煎服。或半枝莲、水龙骨各一两，加瘦猪肉适量，煮熟，吃肉和汤。 ⑿治背痈：鲜半枝莲根捣烂外敷。要留出白头，一天敷二次。另取全草一两，水煎服，服四、五次即可排脓。排脓后，用根捣汁滴入孔内，并用纱布包扎，一天换二次。 ⒀治癌症：半枝莲、蛇葡萄根各一两，藤梨根四两，水杨梅根二两，白茅根、凤尾草、半边莲各五钱。水煎服。（⑾方以下出《浙江民间常用草药》） ⒁治跌打损伤：小韩信草捣烂，同酒糟煮热敷。（《广西药植图志》） ⒂治一切毒蛇咬伤：鲜狭叶韩信草，洗净捣烂，绞汁，调黄酒少许温服，渣敷患处。（《泉州本草》） ⒃治毒蛇咬伤：鲜半枝莲、观音草各-至二两，鲜半边莲、鲜一包针各四至八两。水煎服。另取上述鲜草洗净后加食盐少许，捣烂取汁外敷。（《浙江民间常用草药》）' where id=1690; -- 半枝莲
update herbs set taste='甘，平。', effect='①治寒齁气喘及疟疾寒热：半边莲、雄黄各二钱。捣泥，碗内覆之，待青色，以饭丸如梧子大。每服九丸，空心盐汤下。（《寿域神方》） ②治毒蛇咬伤：㈠半边莲浸烧酒搽之。（《岭南草药志》）㈡鲜半边莲一、二两，捣烂绞汁，加甜酒一两调服，服后盖被入睡，以便出微汗。毒重的-天服两次。并用捣烂的鲜半边莲敷于伤口周围。（《江西民间草药验方》） ③治疔疮，一切阳性肿毒：鲜半边莲适量，加食盐数粒同捣烂，敷患处，有黄水渗出，渐愈。（《江西民间草药验方》） ④治乳腺炎：鲜半边莲适量，捣烂敷患处。（《福建中草药》） ⑤治无名肿毒：半边莲叶捣烂加酒敷患处。（《岭南草药志》） ⑥治喉蛾：鲜半边莲如鸡蛋大一团，放在瓷碗内，加好烧酒三两，同擂极烂，绞取药汁，分三次口含，每次含约一、二十分钟吐出。 ⑦治时行赤眼或起星翳：㈠鲜半边莲，洗净，揉碎作一小丸，塞入鼻腔，患左眼塞右鼻，患右眼塞左鼻。三、四小时换一次。㈡鲜半边莲适量，捣烂，敷眼皮上，用纱布盖护，一日换药两次。 ⑧治跌打扭伤肿痛：半边莲一斤，清水三斤，煎剩一斤半过滤，将渣加水三厅再煎成一半，然后将两次滤液混合在一起，用慢火浓缩成一斤，装瓶备用。用时以药棉放在药液中浸透，取出贴于患处。 ⑨治黄疸，水肿，小便不利：半边莲一两，白茅根一两。水煎，分二次用白糖调服。（⑥方以下出《江西民间草药验方》） ⑩治单腹臌胀：半边莲、金钱草各三钱，大黄四钱，枳实六钱。水煎，连服五天，每天一剂；以后加重半边莲、金钱草二味，将原方去大黄，加神曲、麦芽、砂仁，连服十天；最后将此方做成小丸，每服五钱，连服半个月。在治疗中少食盐。（《岭南草药志》） ⑾治湿热泄泻：半边莲一两，水煎服。（江西《草药手册》） ⑿治痢疾：生半边莲二两，水煎和黄糖服。 ⒀治盲肠炎：半边莲八两，加双料酒适量，捣烂水煎，一日五次分服，渣再和入米酒少许，外敷患处。 ⒁治急性中耳炎：半边莲擂烂绞汁，和酒少许滴耳。（⑿方以下出《岭南草药志》） ⒂治晚期血吸虫病腹水、肾炎水肿：半边莲一至二两，煎服。（《上海常用中草药》） ⒃治由血防846或链霉素引起的眩晕等：半边莲一两，配墨旱莲、白芷、车前草、女贞子、紫花地丁煎服。（《上海常用中草药》）' where id=1691; -- 半边莲
update herbs set taste='酸涩，寒。有毒。', channel='入肺、脾、胃、大肠经。', effect='（1）治癫狂因忧郁而得，痰涎阻塞包络心窍者：白矾三两，川郁金七两。二药共为末，糊丸梧桐子大。每服五、六十丸，温汤下。（《本事方》白金丸） （2）治风痰痫病：生白矾一两，细茶五钱，为未，炼蜜丸如梧子大。一岁十丸，茶汤下。大人五十九，久服痰自大便中出。（《卫生杂兴》化痰丸） （3）治中风痰厥，四肢不收，气闭膈塞者：白矾一两，牙皂角五钱。为末，每服一钱，温水调下，吐痰为度。（《纲目》） （4）治初中风失音不语，昏冒不知人，先宜吐风痰，令省觉：白矾二两（生用），生姜一两（连皮擦碎，水二升，煮取一升二合）。上二味，先细研白矾为末，入浓煎生姜汤研滤。分三服，旋旋灌，须臾吐出痰毒，眼开风退，方可救治。若气衰力弱，不宜用猛性药吐之，设吐得痰毒，别增疾。（《圣济总录》白矾散） （5）治慢性胃炎、胃及十二指肠溃疡：明矾九份，淀粉一份。用冷水做丸，如黄豆粒大小。每日服三次，每次二至三钱。（内蒙古《中草药新医疗法资料选编》） （6）治肺壅热，止喘嗽，化痰涎，利胸膈，定烦渴：白矾（枯）、熟干地黄（焙）、玄参，知母（焙）、贝母（炒）、诃黎勒皮各一两。上六味，捣罗为末，面糊和丸如梧桐子大。每服十五丸至二十丸，煎生姜、枣汤下，食后临卧时服。（《圣济总录》白矾丸） （7）治喉痹、乳蛾、喉风：明矾二两，胆矾五钱。上研为极细，吹患处。（《普济方》吹喉散） （8）治急喉闭：白矾三钱，巴豆三个（去壳，作六瓣）。上将矾于铫内，慢火熬化为水，置巴豆其内，候干去巴豆，取矾研为末，每用少许，吹入喉中。（《玉机微义》白矾散） （9）治黄肿水肿：明矾二两，青矾一两，白面半斤。三味同炒令赤色，醋煮米糊丸，枣汤下三十丸。（《急救仙方》推车丸） （10）治妇人经水闭不利，藏坚癖不止，中有干血，下白物：矾石三分（烧），杏仁一分。上二味，末之，炼蜜和丸枣核大，内藏中，剧者再内之。（《金匮要略》矾石丸） （11）治妇人遗尿不知：矾石（熬）、牡蛎（熬）各三两，上二味，捣筛为散，酒服方寸匕。亦治丈夫。（《千金翼方》） （12）治肠炎：明矾研末，装入胶囊。每天服二次，每次两个胶囊，温开水送下。（辽宁《中草药新医疗法济科选编》） （13）治婴孩小儿伏暑泄泻：矾（净瓦盆合定，用火煅过）八两，为极细末，煮醋面和丸，如黍米大，用木瓜煎汤，食后服。（《补要袖珍小儿方论》玉华丹） （14）治老人久泻不止：诃黎勒三分（煨，用皮），白矾一两（烧灰）。上药，捣细罗为散。每服不计时候，以粥饮调下二钱。（《圣惠方》诃黎勒散） （15）治休息痢久不止，日渐黄瘦：白矾四两（烧令汁尽），硫黄二两，消石一两。上药同研，于铫子内，火上溶成汁，侯冷，研令极细，用软饭和丸如小豆大。每于食前，以粥饮下十丸。（《圣惠方》白矾丸） （16）治蛔虫病、蛲虫病：白矾五分，红葱三寸，花椒二十一粒。每日一剂，煎服二次。（内蒙古《中草药新医疗法资料选编》） （17）治心气疼痛：醋一盏，加生白矾一小块，如皂子大，同煎至七分，温服。（《儒门事亲》） （18）治反胃呕吐：枯白矾三两，蒸饼丸梧子大。每空心米饮服十五丸。（《普济方》） （19）治衄血不止：枯矾末吹之。（《圣济总录》） （20）治齿龂间津液、血出不止：矾石一两（烧），水三升，煮取一升，先拭血，乃含之。已后不用，朽人牙根。（《千金方》） （21）治小儿重舌舌强：白矾半两，桂心一分。上药，捣罗为末。每用少许，干敷舌下，日三上。（《圣惠方》） （22）治小儿鹅口并噤：白矾-分（烧灰），朱砂末一分。上药，和研极细。敷儿舌上，日三上，以乱发洗舌上垢，频令净，（《圣惠方》白矾散） （23）治急慢性化脓性中耳炎：枯矾二钱，冰片四分，五倍子五分。共研细末。将外耳道脓性分泌物用棉棒擦干后，吹入上药，一日三次。（《全展选编·五官科》） （24）治目翳及胬肉：矾石上上白者，纳如黍米大于翳上及胬肉上，即令泪出，以绵拭之，令得恶汁尽，日一，其疾逐恶汁尽，日日渐自薄。好上上矾石，无过绛矾色明净者，慎如疗眼常法。（《千金翼方》矾石散） （25）治赤目风肿：甘草水磨明矾敷眼胞上效，或用枯矾频擦眉心。（《濒湖集简方》） （26）治烂弦风眼：白矾（煅）一两，铜青三钱，研末，汤泡澄清，点洗。（《永类钤方》） （27）治一切疮痈恶毒（先服此丸护膜托里，使毒不攻心），或为毒虫蛇犬所伤：黄蜡二两，白矾一两。先将蜡溶化，侯少冷，入矾和匀，为丸。酒下，每服十丸、二十丸，渐加至百丸则有力。疮愈后服之亦佳。加雄黄名雄矾丸，治蛇、犬、虫咬毒。（《医方集解》蜡矾丸·一名黄矾丸） （28）治疔肿恶疮：白矾（生用）、黄丹各等分。上各另研，临用时各抄少许和匀，三棱针刺疮见血，待血尽上药，膏药盖之。（《卫生宝鉴》二仙散） （29）治瘰疬已取下：五倍子一两，矾石半两。上二味，为末。每用二钱匕，沸汤一碗，调匀令洗，汤温即止，每淋洗了，用软帛裹干，用生肌药掺于疮口上。（《圣济总录》） （30）治刀斧金疮：白矾，黄丹等分。为末敷之。（《急救仙方》） （31）治小儿脐中汁出不止兼赤肿：白矾烧灰，细研敷之。（《圣惠方》） （32）治黄水疮：枯白矾、熟松香、黄丹。三味等分，研极细末，真芝麻油调涂患处。（《本草原始》） （33）治疥：白矾（烧灰）一两，硫黄一两（细研），胡粉一两，黄连一两，雌黄一两（细研），蛇床子三分。上药，捣细罗为散，都研令匀，以猪膏和如稀面糊，每以盐浆水洗，拭干涂之。（《圣惠方》白矾散） （34）治烧伤：明矾、五倍子等量，芝麻油适量。将明矾、五倍子研成细末，麻油调成糊状。涂患处。（《新疆中草药单方验方选编》） （35）治鼻中患肉，不闻香臭：烧矾石末，以面脂和，绵裹着鼻中，数日息肉随药消落。（《千金方》） （36）治鼻痔臭不可近，痛不可摇：白矾（煅枯）二钱，硇砂五分。共为细末，每用少许点上。（《医学心悟》白矾散） （37）治腋下胡臭：矾石绢袋盛之，常粉腋下。（《纲目》） （38）治妇人阴痒脱：矾石，熬，末之。每日空腹酒和服方寸匕，日三服。（《千金翼方》）', tips='阴虚胃弱，无湿热者忌服，且不宜久服和多服，及泄痢日久，由于脾胃气虚；妇人白沃，由于中气下陷；营血不足以致寒热者，不宜用。 ①《吴普本草》：歧伯：久服伤人骨。 恶牡蛎。 ③《药性论》：畏麻黄。 ④《本草衍义》：不可多服，损心肺，却水故也。 ⑤《本草经疏》：凡阴虚内热，火炽水涸，发为咽喉痛者，不宜含此。目痛由阴虚血热者，亦不宜用。 ⑥《本草汇言》：泄痢日久，由于脾胃气虚；妇人白沃，由于中气下陷；营血不足以致寒热者，不宜用。' where id=1692; -- 白矾
update herbs set taste='苦，寒。', channel='归心、胃经。', effect='①治流行性感冒：板蓝根一两，羌活五钱。煎汤，一日二次分服，连服二至三日。（《江苏验方草药选编》） ②治大头天行，初觉憎寒体重，次传头面肿盛，目不能开，上喘，咽喉不利，口渴舌燥：黄芩（酒炒）、黄连（酒炒）五钱，陈皮（去白）、甘草（生用）、玄参二钱，连翘、板蓝根、马勃、鼠粘子、薄荷一钱，僵蚕、升麻七分，柴胡、桔梗二钱。为末汤调，时时服之，或蜜拌为丸，噙化。（李杲，普济消毒饮） ③预防流行性腮腺炎：板蓝根、山茨菇各一两，连翘八钱，甘草六钱，青黛一钱（冲服）。上药用水浸泡半小时，放入大砂锅内，放清水800～1000毫升，煎成500毫升，分为10份，装入小瓶。4岁以上儿童每天服一次，每次15毫升；1～3岁每次服10毫升，每天一次，温服。（《全展选编·爱国卫生》） ④治肝炎：板蓝根一两。水煎服。（《辽宁常用中草药手册》） ⑤治肝硬化：板蓝根一两，茵陈四钱，郁金二钱，苡米三钱。水煎服。（《辽宁常用中草药手册》） ⑥治痘疹出不快：板蓝根一两，甘草三分（锉，炒）。上同为细末，每服半钱或一钱，取雄鸡冠血三两点，同温酒少许，食后，同调下。（《阎氏小儿方论》）' where id=1693; -- 板蓝根
update herbs set alias='川乌', taste='辛，热，有毒。', channel='心；肝；脾；肾经', effect='①治风寒湿痹、麻木不仁：川乌（生，去皮尖为末）。用香熟白米粥半碗，药末四钱，同米用漫火熬熟，稀薄，不要稠，下姜汁一茶脚许，蜜三大匙，搅匀，空腹啜之，温为佳，如是中湿，更入薏苡仁末二钱，增米作一中碗服。（《本事方》川乌粥法） ②治风痹、荣卫不行，四肢疼痛：川乌头二两（去皮切碎，以大豆同炒，候豆汁出即住），干蝎半两（微炒）。上件药，捣罗为末，以酽醋一中盏，熬成膏，可丸，即丸如绿豆大，每服以温酒下七丸。（《圣惠方》） ③治风寒湿痹，挛痛不能步握：五灵脂、川乌（炮去皮、脐）、苍术（薄切酒浸，干）各二两，自然铜（烧热）一两。上为细末，水糊为丸，如梧桐子大，每服七丸，温酒下，渐加丸数；服至病除。（《普济方》乌术丸） ④治风腰脚冷痹疼痛，宜用贴熁：川乌头主分，去皮脐，生用。上捣细罗为散，以酽醋调涂，于故帛上撒之，须臾痛止。（《圣惠方》） ⑤治脚气疼痛，不可屈伸：麻黄、芍药、黄芪各三两，甘草三两（炙），川乌五枚（细切，以蜜二升，煎取一升，即出乌头）。上五味细切四味，以水三升煮取一升，去滓，内蜜煎中，更煎之，服七合，不知，尽服之。（《金旺要略》乌头汤） ⑥治瘫缓风，口眼歪斜，语言蹇涩，履步不正：川乌头（去皮脐）、五灵脂各五两。上为末，入龙脑、麝香，研令细匀，滴水丸如弹子大。每服一丸，先以生姜汁研化，次暖酒调服之，一日两服，空心晚食前服。（《梅师集验方》神验乌龙丹） ⑦治口眼歪斜：生乌头，青矾各等分。为末，每用一字，吸入鼻内，取涕吐涎。（《箧中秘宝方》通关散） ⑧治心痛彻背，背痛彻心：乌头一分（炮），赤石脂二分，干姜一分，附子一分，蜀椒二分。上五味，末之，蜜丸如梧子大。先食服一丸，日三丸，不知，稍加服。（乌头赤石脂丸） ⑨寒疝绕脐痛苦，发则白津出，手足厥冷，其脉沉紧者：乌头大者五枚（熬去皮），以水三升，煮取一升，去滓，内蜜二升，煎令水气尽，取二升。强人服七合，弱人服五合，不瘥，明日更服，不可一日再服。（大乌头煎） ⑾治寒疝腹中痛，逆冷，手足不仁，身疼痛：乌头，以蜜二斤，煎减半，去滓，以桂枝汤五合解之，令得一升，初服二合，不知，即服三合，又不知，复加至五合，其知者如醉状，得吐者为中病。（乌头桂枝汤，⑧方以下出《金匮要略》） ⑿治阴毒伤寒，手足逆冷，脉息沉细，头痛腰重：川乌头（炮）、干姜各半两。上二味同为粗散，炒令转色，放冷，再捣细末，每服一钱，水一盏，盐一捻，煎半盏、去滓、温服。（《博济方》退阴散） ⑿治小儿慢惊，搐搦涎壅厥逆：川乌头（生，去皮脐）一两，全蝎十个（去尾）。分作三服。水一盏，姜七片煎服。（《婴孩宝书》） ⒀治脾寒疟疾：川乌头大者一个（炮良久，移一处再炮，凡七处炮满，去皮脐），为细末，作一服。用大枣七个，生姜十片，葱白七寸，水一碗，同煎至一蛊。疾发前，先食枣次温服。（《苏沈良方》七枣散） ⒁治腹中雷鸣，脐下疴撮疼痛：苍术（东流水浸十日，去黑皮，片切，焙）半斤，乌头（米泔浸五日，逐日换泔，炮裂，去皮脐），青橘皮（汤浸去白焙）各三两，蜀椒（口开者，烧砖令红，以醋泼砖，安椒，盖出汗，取红用）三两，青盐（研）一两。上五味，捣罗四味为末，与盐拌匀，炼蜜和丸，捣一千杵，丸如梧桐子大，每服二十丸，空心食前盐酒下。（《圣济总录》乌术丸》 ⒂治冷气下泻：木香半两，川乌（生，去皮）一两。上为细末，醋糊灿口梧子大，陈皮、醋汤下三、五十丸。（《本事方》木香丸） ⒃治久赤白痢及泻水：川乌头二枚，-枚豆煮，一枚生用为末。上以黑豆半合，入水同煮；黑豆热为度，与豆同研烂，丸如绿豆大。每服，以黄连汤下五丸。（《圣惠方》） ⒄治年久头痛：川乌头、天南星等分。为末，葱汁凋涂太阳穴。（《经验方》） ⒅治头风：大川乌、天南星等分。上为细末，每服半钱，水一大盏，白梅一个，生姜五片，煎至五分服。（《百一选方》） ⒆理囟门陷：绵川乌（生用），绵附子（生用）各五钱，雄黄二钱。上件为末，用生葱和根叶细切烂杵，入前药末同煎，空心作成膏，贴陷处。（《活幼心书》乌附膏） ⒇治牙痛：川乌头一分（生用），附子一分（生用），上件药，捣罗为末，用面糊和丸，如小豆大。以绵裹一丸，于痛处咬之，以瘗为度。（《圣惠方》乌头丸） （21）治痈疽肿毒：川乌头（炒），黄柏（炒）各一两。为末，唾调涂之，留头，干则以米泔润之。（《僧深集方》） （22）治痈攻肿，若有息肉突出者：乌头五枚，以苦酒三升，渍三日，洗之，日夜三、四度。（《古今录验》） （23）治久生疥癣：川乌头七枚（生用），捣碎，以水三大盏，煎至一大盏，去滓，温温洗之。（，圣惠方》）', tips='阴虚阳盛，热证疼痛及孕妇禁服。反半夏、栝楼、天花粉、川贝母、浙贝母、白蔹、白及。酒浸、酒煎服，易致中毒，应慎服。 反半夏、栝楼、贝母、白蔹、白及。恶藜芦。 ②《药性论》：远志为使。忌豉汁。' where id=1694; -- 川乌头
update herbs set alias='堇，芨，乌头、乌喙、奚毒，鸡毒，茛、千秋、毒公、果负、耿子、帝秋，独白草，土附子，草乌，竹节乌头、金鸦，断肠草。', taste='辛；苦；热；大毒。', channel='入肝、脾、肺经。', effect='①治一切瘫痪风：草乌头（生，不去皮）、五灵脂各等分。为末，滴水为丸，如弹子大。四十岁以下一丸，分六服，病甚一丸分二服，薄荷酒磨下，觉微麻为度。（《本事方》黑神丸） ②治破伤风：草乌头（生用，去皮尖）、白芷（生用），二味等分为末。每服半钱，冷酒一盏，入葱白少许，同煎服之，如人行十里，以葱白热粥投之。（《儒门事亲》） ③治久患头风：草乌头尖（生用）一分，赤小豆三十五粒，麝香一字，为末。每服半钱，薄荷汤冷服。更随左右搐鼻。（《指南方》） ④治偏正头痛：草乌头四两，川芎藭四两，苍术半斤，生姜四两，连须生葱一把。捣烂，同入瓷瓶，封固，埋土中，春五夏三、秋五冬七日，取出晒干，拣去葱、姜，为末，醋、面糊和丸梧子大。每服九丸。临卧温酒下。（《戴古渝经验方》） ⑤治清浊不分，泄泻注下，或赤或白，脐腹疞痛，里急后重：草乌头三枚（去皮尖，一生、一炮，一烧作灰）。为细末，醋糊丸。如萝卜子大。大人五，七丸。小儿三丸；水泻倒流水下，赤痢甘草汤、白痢干姜汤下。（《局方》三神丸） ⑥治一切痈肿毒：草乌、贝母、天花粉、南星、芙蓉叶等分。为末，用醋调搽四围，中留头出毒，如干用醋润之。（《景岳全书》草乌揭毒散） ⑦治肿毒痈疽，未溃令内消，已溃令速愈：草乌头末，水调，鸡羽扫肿上，有疮者先以膏药贴定，无令药着入。初涂病人觉冷如水，府乃不痛。（《圣济总录》草乌头散） ⑧治发背、蜂窝、疔疮、便毒：草乌头一个，川乌头一个，瓦一块，新汲水一桶。将二乌并瓦浸于水桶内，候瓦湿透，即将川乌、草乌于瓦上磨成膏，用磨药手挑药贴于疮口四周；如未有疮口，一漫涂药如三、四重纸厚，上用纸条透孔贴盖，如药干，用鸡翎蘸水扫湿，如此不过三度。（《瑞竹堂经验方》二乌散） ⑨治阳虚上攻，头项俱痛，不可忍者：细辛、新茶芽（炒）。草乌头（大者，去皮尖，炮裂切如麻豆大，碎盐炒）各等分。上为粗末。每服二钱，入麝香末半钱，水一盏半，煎至八分，去滓，温服。（《本事方》乌香散） ⑩治脾胃虚弱及久积冷气，饮食减少：草乌头（净洗）一斤，苍术二斤，陈橘皮（去白）半斤，甘草（生，椎碎）四两，黑豆三升。上五味，用水一石，煮干为度，去却橘皮、黑豆、甘草，只取草乌头、苍术二味，曝干，粗捣筛焙干，捣罗为末，酒煮面糊为丸，如梧桐子大，焙干，收瓷器中。每日空心、晚食前，盐汤咸温酒下三十丸。（《圣济总录》） ⑾治一切诸疮未破者：草乌头为末，入轻粉少许，腊猪油和搽。（《普济方》） ⑿治淋巴结炎、淋巴结结核：草乌头一个，用烧酒适量磨汁，外搽局部，每日一次。（《单方验方调查资料选编》） ⒀治瘰疬初作未破，作寒热：草乌头半两，木鳖子二个。以米醋磨细，入捣烂葱头、蚯蚓粪少许。调匀敷上，以纸条贴令通气孔。（《医林正宗》） ⒁治一切风齿疼痛，饮食艰难：草乌头三枚（炮），胆矾（研）、细辛（去苗叶）各一钱。捣研为细散。每用一字，以指头揩擦，有涎吐之。（《圣济总录》草乌头散） ⒂治脑泄臭秽：草乌（去皮）半两，苍术一两，川芎二两。并生研末，面糊丸，绿豆大，每服十丸，茶下。忌一切热物。（《圣济总录》） ⒃治喉痹、口噤不开：草乌头、皂荚等分。为末，入麝香少许，擦牙，并搐鼻内，牙关自开也。（《纲目》）', tips='阴虚火旺、各种热证患者及孕妇禁服。 反栝楼、贝母、白敛、白及（一本有半夏）。恶藜芦。 忌豉汁。 ③《纲目》：畏饴糖、黑豆。冷水能解其毒。 ④《本草汇言》：平素禀赋衰薄，或向有阴虚内热吐血之疾，并老人、虚人、新产人，切宜禁用。' where id=1695; -- 草乌头
update herbs set taste='味甘；酸；性微寒。', channel='归心、小肠经。', effect='①治水肿坐卧不得，头面身体悉肿：桑枝烧灰、淋汁，煮赤小豆空心食令饱，饥即食尽，不得吃饭。（《梅师集验方》） ②治卒大腹水病：白茅根一大把，小豆三升，煮取干，去茅根食豆，水随小便下。（《补缺肘后方》） ③治水肿从脚起，入腹则杀人：赤小豆一升，煮令极烂，取汁四、五升，温渍膝以下；若已入腹，但服小豆，勿杂食。（《独行方》） ④治脚气：赤小豆五合，葫一头，生姜一分（并破碎），商陆根一条（切）。同水煮，豆烂汤成，适寒温，去葫等，细嚼豆，空腹食之，旋旋啜汁令尽。（《本草图经》） ⑤治脚气气急，大小便涩，通身肿，两脚气胀，变成水者：赤小豆半升，桑根白皮（炙，锉）二两，紫苏茎叶一握（锉，焙）。上三味除小豆外，捣罗为末。每服先以豆一合，用水五盏煮熟，去豆，取汁二盏半，入药末四钱匕，生姜一分，拍碎，煎至一盏半，空心温服，然后择取豆任意食，日再。（《圣济总录》赤小豆汤） ⑥治伤寒瘀热在里，身必黄：麻黄二两（去节），连轺二两，赤小豆一升，杏仁四十个（去皮、尖），大枣十二枚（擘），生梓白皮（切）一升，生姜二两（切），甘草二两（炙）。上八味，以水一斗，先煮麻黄再沸，去上沫，纳诸药，煮取三升，去滓，分温三服，半日服尽。（《伤寒论》麻黄连轺赤小豆汤） ⑦治急黄身如金色：赤小豆一两，丁香一分，黍米一分，瓜蒂半分，熏陆香一钱，青布五寸（烧灰），麝香一钱（细研）。上药捣细罗为散，都研令匀。每服不计时候，以清粥饮调下一钱；若用少许吹鼻中，当下黄水。（《圣惠方》赤小豆散） ⑧治肠痔大便常血：小豆一升，苦酒五升，煮豆熟，出干，复纳清酒中，候酒尽止，末。酒服方寸匕，日三度。（《肘后方》） ⑨治热毒下血，或因食热物发动：赤小豆杵末，水调下方寸匕。（《梅师集验方》） ⑩治疽初作：小豆末醋敷之，亦消。（《小品方》） ⑾治大小肠痈，湿热气滞瘀凝所致：赤小豆、薏苡仁、防己 、甘草，煎汤服。（《疡科捷径》赤豆薏苡汤） ⑿治小儿天火丹，肉中有赤如丹色，大者如手，甚者遍身，或痛或痒或肿：赤小豆二升。末之，鸡子白和如薄泥敷之，干则易。一切丹并用此方。（《千金方》） ⒀治腮颊热肿：赤小豆末和蜜涂之，或加芙蓉叶末。（《纲目》） ⒁治小儿重舌：赤小豆末，醋和涂舌上。（《千金方》） ⒂治舌上忽出血，如簪孔：小豆一升，杵碎，水三升，和搅取汁饮。（《肘后方》） ⒃下乳汁：煮赤小豆取汁饮。（《产书方》） ⒄治妇人吹奶：赤小豆酒研，温服，以滓敷之。（《妇人良方补遗》） ⒅治风瘙瘾疹：赤小豆、荆芥穗等分，为末，鸡子清调涂之。（《纲目》） ⒆治食六畜肉中毒：烧小豆一升，末，服三方寸匕。（《千金方》）' where id=1696; -- 赤小豆
update herbs set taste='味辛；性凉；有毒。', channel='心；肝；脾；肺经', effect='①治一切疮肿、痈疽、瘰疬等疾，经月不瘥，将作冷瘘：蟾蜍一枚（去头用），石硫黄（别U研）、乳香（别研）。木香、桂（去粗皮）各半两，露蜂房一枚（烧灰用）。上六味，捣罗为末，用清油一两，调药末，入瓷碗盛，于铫子内重汤熬，不住手搅，令成膏，绢上摊贴之。候清水出，更换新药，疮患甚者，厚摊药贴之。（《圣济总录》蟾蜍膏） ②治发背肿毒未成者：活蟾一个，系放疮上半日，蟾必昏愤，再易一个，如前法，其蟾必踉蹡；再易一个，其蟾如旧，则毒散矣。若势重者，以活蟾一个，或二三个，破开连肚乘热合疮上，不久必臭不可闻，再易二三次即愈。（《医林集要》） ③治早期瘰疽：蟾蜍，将其腹切开一厘米创口，不去内脏，放入少许红糖。将患指伸入其腹内，经二小时后，可另换一只蟾蜍，共用十只左右可愈。治其他炎症也有效。（广西《中草药新医疗法处方集》） ④治疔毒：蜘蜍一个，黑胡椒七粒，鲜姜一片，将上药装入蟾蜍腹内，再放砂锅或瓦罐内，慢火烧焦研细末。每次五厘，日服二次。（《吉林中草药》） ⑤治胸壁结核和淋巴结结核破溃成漏孔：癞蛤蟆一个，白胡椒三钱，硫黄二钱。先将胡椒、硫黄塞入蛤蟆腹内，后用黄泥包裹蛤蟆厚约一、二寸，火内煨透，取出去泥，研细末，香油调成糊状，灭菌后，涂于无菌纱布条放入漏孔内，外盖纱布，每二至四天换药一次。（辽宁《中草药新医疗法资料选编》） ⑥治气臌：大虾蟆一个，砂仁不拘多少。为末，将砂仁装入蟆内令满，缝口，用泥周身封固，炭火煅红，候冷，将蟆研末，作三服，陈皮汤送下。（《绛囊撮要》蟾砂散） ⑦治腹中冷癖，水谷阴结，心下停痰，两胁痞满，按之鸣转，逆害饮食：大蟾蜍一枚（去皮及腹中物，支解之），芒硝（大人一升，中人七合，瘦弱人五合）。以水六升，煮取四升，一服一升，一服后，未得下，更一升；得下则九日十日一作。（《补缺肘后方》） ⑧治破伤风：虾蟆二两半，切烂如泥，入花椒一两，同酒炒热，再入酒二盏半温热，去渣服之，通身汗出效。（《奇效良方》） ⑨治五疳八痢，面黄肌瘦，好食泥土，不思乳食：大干蟾蜍一枚（烧存性），皂角（去皮、弦，烧存性）一钱，蛤粉（水飞）三钱，麝香一钱。为束，糊丸粟米大。每空心米饮下三、四十丸，日二服。（《全婴方论》五疳保童丸） ⑩治小儿疳瘦成癖几危者：蟾蜍去头皮脏腑，以桑叶包裹，外加厚纸再裹，火内煨熟，口啖二支，十余日愈。若口渴，咽梨汁解之。（《本草蒙筌》） ⑾治大肠痔疾：蟾蜍一个，以砖砌四方，安于内，泥住，火煅存性，为末；以猪广肠一截，扎定两头，煮熟切碎，蘸蟾末食之，如此三、四次。（《纲目》） ⑿治小儿走马疳，牙斵臭烂，侵蚀唇鼻，亦治身上肥疮：蚵蛾（黄纸裹，煨焦）、黄连各末一两，青黛一钱。为末，入麝香少许研和。先以甘草汤洗去皮，令血出涂之。疮干好麻油调，湿则干用。（《全婴方论》田酥散） ⒀治癣：干蟾蜍烧灰，以猪脂和涂之。（《僧深集方》） ⒁治舌口生疮：胆矾一分，干蟾一分（炙）。上研为末，每取小豆大掺在疮上，良久，用新汲水五升漱，水尽为度。（《圣惠方》蟾矾散）' where id=1697; -- 蟾蜍
update herbs set taste='味辛；性温。', channel='归脾、胃经。', effect='①治脾胃虚弱，不思饮食，呕吐满闷、心腹痛：草豆蔻肉八两，生姜（和皮切作片子）一片，甘草四两（锉碎）。上三味匀和入银器内，用水过药三指许，慢火熬令水尽，取出，焙干，杵为末。每服一钱，沸汤点服。夏月煎之，作冷汤服亦妙。（《博济方》豆蔻汤） ②治胃口冷，吃食无味及脾泄泻不止，兼治酒后数囿如痢，心胸不快，不思饮食：草豆蔻半两（每个面裹煨，候面焦黄，去面用），甘草一两（炙），肉桂（去皮）一两，陈皮（去白）一两，蛮姜一两。上五味，同为细末。每服一钱半，更入陈米末一钱，水一盏，枣二枚，同煎七分，温服，其滓再煎服之。（《博济方》草豆蔻散） ③治呕逆不下食，腹中气逆：豆蔻子七枚（碎），生姜五两，人参一两，甘草一两（炙）。上四味切，以水四升，煮取一升五合，去滓。分温二服，相去如人行五，六里。忌海藻、菘菜。（《广济方》豆蔻子汤） ④治小儿藏寒泄泻不止：草豆蔻一枚，剥开皮，入乳香一块在内，复用白面裹，慢火烧令熟，去面及豆蔻皮不用；上为细末，以粟米饮丸如麻子大。每服五、七丸，米饮下，无时。（《史载之方》豆蔻丸） ⑤治冷痰呕逆，胸脯不利：草豆蔻（去皮）、半夏（汤洗去滑，切，焙）各半两，陈橘皮（汤浸去白，焙）三分。上三味，粗捣筛。每服三钱匕，水一盏，入生姜五片，煎至七分，去滓温眼，不拘时侯。（《圣济总录》豆蔻汤） ⑥治霍乱心烦渴，吐利不下食：草豆蔻（去皮）一分，黄连（去须）一两。上二味，粗捣筛。每胀三钱匕，水一盏，乌豆五十粒，生姜三片，煎至七分，去滓温服，日三。（《圣济总录》草豆蔻汤） ⑦治老疟久而不瘥，及山岚瘴气，远年不愈，兼治脾寒：草豆蔻、肉豆蔻各二个（并用面裹煨，一生一熟），厚朴方圆二寸（一半姜制，一半生用），甘草中指大（一半生，一半炙），生姜枣大二块（一块用湿纸裹煨，一块生用）。上分为二大剂，于发前临晓，用水一升，煎取八合，放至来早，再温服，留滓再煎二次。（《鸡峰普济方》草豆蔻散） ⑧香口辟臭：豆蔻、细辛，为末含之。（《肘后方》）', usage='', tips='阴虚血少，津液不足者禁服，无寒湿者慎服。 ①《本经逢原》：阴虚血燥者忌之。 ②《本草备要》：忌铁。 ③《本草经疏》：凡疟不由于瘴气；心痛胃脘痛由于火而不由于寒；湿热瘀滞，暑气外侵而成滞下赤白，里急后重，及泄泻暴注口渴，湿热侵脾，因作胀满，或小水不利，咸属暑气湿热，皆不当用。 内服，煎汤，2.4－4.5g，或入丸、散。阴虚血少者忌用。' where id=1698; -- 草豆蔻
update herbs set taste='味辛；性温。', channel='入肺、胃经。', effect='①治伤寒初觉头痛，肉热，脉洪起一，二日：葱白一虎口，豉一升。以水三升，煮取一升，顿服取汗。（《补缺肘后方》葱豉汤） ②治时疾头痛发热者：连根葱白二十根。和米煮粥，入醋少许，热食取汗即解。（《济生秘览》） ③治妊娠七月，伤寒壮热，赤斑变为黑斑，溺血：葱一把，水三升，煮令热服之，取扦，食葱令尽。（《伤寒类要》） ④治脱阳，或因大吐大泻之后，四肢逆冷，元气不接，不省人事，或伤寒新瘥，误与妇人交，小腹紧痛，外肾搐缩，面黑气喘，冷汗自出.须臾不救：葱白敷茎炒令热，熨脐下，后以葱白连须三七根，细锉，砂盆内研细，用酒五升，煮至二升。分作三服，灌之。（《华佗危病方》） ⑤治胃痛，胃酸过多，消化不良：大葱头四个，赤糖四两。将葱头捣烂，混入赤糖，放在盘里用锅蒸熟。每日三次，每次三钱。（内蒙古《中草药新医疗法资料选编》） ⑥治虫积卒心急痛，牙关紧闭欲绝：老葱白五茎。去皮须捣膏，以匙送入喉中，灌以麻油四两，虫积皆化为黄水而下。（《瑞竹堂经验方》） ⑦治霍乱烦躁，卧不安稳：葱白二十茎，大枣二十枚。水三升，煮取二升顿服之。（《补缺肘后方》） ⑧治小儿初生不小便：人乳四合，葱白一寸。上二味相和煎，分为四服。（《外台秘要方》） ⑨治小便难，小肠胀：葱白三斤。细锉，炒令热，以帕子裹，分作二处，更以熨脐下。（《本事方》） ⑩治小儿虚闭：葱白三根。煎汤，调生蜜、阿胶末服。仍以葱头染蜜，插入肛门。（《全幼心鉴》） ⑾治少阴病下利：葱白四茎，干姜一两，附子一枚（生，去皮，破八片）。上三味，以水三升，煮取一升，去滓分温再服。（《伤寒论》白通汤） ⑿治赤白痢：葱一握。细切，和米煮粥，空心食之，（《食医心镜》） ⒀治腹皮麻痹不仁者：多煮葱白食之。（《世医得效方》） ⒁治痈疖肿硬、无头、不变色者：米粉四两，葱白一两（细切）。上同炒黑色，杵为细末。每用，看多少，醋调摊纸上，贴病处，一伏时换一次，以消为度。（《外科精义》乌金散） ⒂治痈疮肿痛：葱全株适量，捣烂，醋调炒热，敷患处。（江西《草药手册》） ⒃治疔疮恶肿：刺破，（以）老葱、生蜜杵贴二时，疗出以醋汤洗之。（《圣济总录》） ⒄治阴囊肿痛：㈠葱白、乳香捣涂。㈡煨葱入盐，杵如泥，涂之。（《纲目》） ⒅治小儿秃疮：冷泔洗净，以羊角葱捣泥，入蜜和涂之。（《纲目》） ⒆治痔正发疼痛：葱和须，浓煎汤，置盆中坐浸之。（孟诜《必效方》） ⒇治磕打损伤，头脑破骨及手足骨折或指头破裂，血流不止：葱白捣烂，焙热封裹损处。（《日用本草》） (21)白通加猪胆汁汤（《伤寒论》）治少阴病，下利不止，厥逆无脉，面赤干呕而烦躁者：葱白4茎，干姜10g，生附子1枚，人尿5合，猪胆汁1合。水煎，去渣，入胆汁、人尿，搅匀，分2次服。方中葱白发汗解表，散寒通阳，为君药。' where id=1699; -- 葱白
update herbs set alias='侧柏又名：柏，扁柏，崖柏、香柏、黄心柏、扁松、云片柏，松蟠、片松、喜柏。', taste='苦；涩；性微寒。', channel='入心、肝、大肠经。', effect='①治吐血不止：柏叶、干姜各三两，艾三把。上三味，以水五升，取马通汁一升，合煮，取一升，分温再服。（《金匮要略》柏叶汤） ②治忧恚呕血，烦满少气，胸中疼痛：柏叶捣罗为散，不计时侯，以粥饮调下二钱。（《圣惠方》） ③治鼻衄出血数升，不知人事：石榴花、柏叶等分。为末，吹鼻中。（《普济方》） ④治小便尿血：柏叶，黄连（焙研）。酒服三钱。（《济急仙方》） ⑤治蛊痢，大腹下黑血，茶脚色，或脓血如靛色：柏叶（焙干为末）、黄连。二味同煎为汁服之。（《本草图经》） ⑥治小儿洞痢：柏叶煮汁，代茶饮之。（《经验方》） ⑦治痔、肠风、脏毒、下血不止：柏叶烧灰调服。（《百一选方》） ⑧治肠风、脏毒，酒痢，下血不止：嫩柏叶（九蒸九晒）二两，陈槐花一两（炒半黑色）。上为末，炼蜜丸，梧桐子大。每服四、五十丸，空心温酒下。（《普济方》侧柏散） ⑨治妇人月水久不断：芍药、柏叶（炙）各一两。上二味，粗捣筛。每服三钱匕，水、酒各半盏，煎至七分，去滓温服。（《圣济总录》芍药汤） ⑩治历节风痛，痛如虎咬，走注周身，不能转动，动即痛极，昼夜不宁：侧柏叶五钱，木通，当归、红花、羌活、防风各二钱。水煎服。（《本草切要》） ⑾治风痹历节作痛：侧柏叶煮汁，同曲米酿酒饮。（《纲目》柏叶酒） ⑿治大人及小儿汤火伤：侧柏叶，入臼中湿捣令极烂如泥，冷水调作膏，涂敷于伤处，用帛子系定，三，二日疮当敛，仍灭瘢。（《本草图经》） ⒀治高血压：侧柏叶五钱。切碎，水煎代茶饮，至血压正常为止。（《江苏省中草药新医疗法展览资料选编》） ⒁治深部脓肿：侧柏叶一两，白矾五钱，酒一两。先将侧柏叶捣碎，又将白矾细粉置酒中溶化，再将侧柏叶倒入酒内和匀，调敷患处，每日换药二次。（《江苏省中草药新医疗法展览资料选编》） ⒂治流行性腮腺炎：扁柏叶适量，洗净捣烂，加鸡蛋白调成泥状外敷，每天换药二次。（《草医草药简便验方汇编》） ⒃治鹅掌风：鲜侧柏叶，放锅内水煮二、三沸，先熏后洗，一日二、三次。（《河北中医药集锦》）' where id=1700; -- 侧柏叶
update herbs set taste='味甘；淡；性微寒。', channel='入肾、膀胱经。', effect='①治小便热秘不通：车前子一两，川黄柏五钱，白芍药二钱，甘草一钱。水煎徐徐服。（《普济方》） ②治小便赤涩，或癃闭不通，及热淋血淋：车前子、瞿麦，萹蓄、滑石、山栀子仁、甘草（炙）、木通、大黄（面裹煨，去面，切，焙）各一斤。上为散。每服二钱，水一盏，入灯心煎至七分，去滓温服，食后临卧。（《局方》八正散） ③治小便血淋作痛：车前子晒干为末，每服二钱，车前叶煎汤下。（《普济方》） ④治妊娠患淋，小便涩，水道热，不通：车前子五两，葵根（切）一升。以水五升，煎取一升半，分三服。（《梅师集验方》） ⑤治白浊：炒车前子四钱，白蒺藜三钱，水煎服。（《湖南药物志》） ⑥治小儿伏暑吐泻，烦渴引饮，小便不通：白茯苓（去皮）、木猪苓（去皮）、车前子、人参（去芦头）、香薷各等分。上件为细末，每服一钱，煎灯心汤调下。（《杨氏家藏方》车前子散） ⑦治风热目暗涩痛：车前子、黄连各一两。为末，食后温酒服一钱，日二服。 ⑧治久患内障：车前子、干地黄、麦门冬等分。为末，蜜丸如梧桐子大。服之。 ⑨治肝肾俱虚，眼常昏暗：菟丝子五两（酒浸五日，曝干别捣为末），车前子一两，熟干地黄三两。上药捣罗为末，炼蜜和捣，丸如梧桐子大。每于空心以温酒下三十丸，晚食前再服（驻景丸）。（⑦方以下出《圣惠方》） ⑩治阴痒痛：车前子以水三升，煮三沸，去滓洗痒痛处。（《外台》） ⑾血淋作痛。用车前子晒干研细，每服二钱，车前叶煎汤送下。 ⑿老人淋病（身体发热）。用车前子五合，煮汁，去渣，用汁煮米粥吃，有效。常服此方，亦可明目。 ⒀妊妇热淋。用车前子五两、葵根（切）一升，加水五升，煎成一升半，分三次服。 ⒁容易小产，用车前子研为末，每服一匙，酒送下。不饮酒者，可改用水送下。 ⒂阴囊冷痛。肿满即成险症，用车前子研细，每服一匙，水送下，一天服二次。 ⒃久患内障。用车前子、干地黄、麦门冬，等分为末，加蜜和丸，如梧子大。常服有效。 ⒄补虚明目（肝肾均虚，眼发黑共，或生障翳，迎风流泪）。用车前子、熟地黄（酒蒸后火焙）各三两，菟丝子（酒浸）五两，共研为末，加炼蜜和丸，如梧子大。每服三十丸，温酒送下。一天服二次，此方名驻景丸。 ⒅小便不通。用车前草一斤，加水三升煎取一升半，分三次，一方：上方再加冬瓜汁嗔或桑叶汁。 ⒆小便尿血。用车前草捣汁五合，空心服。 ⒇鼻血不止。用车前叶捣汁饮下。 (21)刀作。用车前叶捣烂敷伤处。 (22)湿气腰痛。和车前叶连根七棵、葱白连须七棵，枣七枚，煮酒一瓶常服。 (23)喉痹、乳蛾。用车前草、凤尾草捣烂，加霜梅肉少许煮酒，共研取汁。鸡乞求蘸取刷喉。 (24)两眼红痛。用车前草汗调眩硝末，临星时涂眼泡上，次日早晨洗去。 (25)目翳初起。用车前叶、敬杨叶等分，揉出汁，裹入两层桑叶中，悬阴处一夜。次日打开桑叶，以汁点眼。' where id=1701; -- 车前子
update herbs set taste='味苦；辛；性平。', channel='入肝、肺经。', effect='①治身体风痒，燥涩顽痹：刺蒺藜四两（带刺炒，磨为末），胡麻仁二两（泡汤去衣，捣如泥），葳蕤三两，金银花一两（炒磨为末）。四味炼蜜为丸。早晚各服三钱，白汤下。（《方龙潭家秘》） ②治眼疾，翳障不明：刺蒺藜四两（带刺炒），葳蕤三两（炒）。共为散。每早服食后三钱，白汤调服。（《方龙潭家秘》） ③治胸痹，膈中胀闷不通或作痛：刺蒺藜一斤，带刺炒，磨为细末。每早、午、晚各服四钱，白汤调服。（《方龙潭家秘》） ④治通身浮肿：杜蒺藜日日煎汤洗之。（《圣惠方》） ⑤治奔豚疝瘕：刺蒺藜十两（带刺炒），小茴香三两（炒），乳香、没药各五钱（瓦上焙出汗）。俱为末，每服三钱，白汤调服。（《方龙潭家秘》） ⑥治急引腰脊痛：捣蒺藜子末，蜜和丸。酒服如胡豆大二丸，日三服。（《外台》） ⑦治气肿痛：蒺藜子一升，熬令黄，为末，以麻油和之如泥，炒令焦黑，以敷故熟布上，如肿大小，勿开孔贴之。干易之。（《千金方》蒺藜散） ⑧治乳胀不行，或乳岩作块肿痛：刺蒺藜二、三斤，带刺炒，为末。每早、午、晚，不拘时，白汤作糊调服。（《方龙潭家秘》） ⑨行经：当归、杜蒺藜各等分。上为末，米饮汤调服，食前。（《儒门事亲》当归散） ⑩灭瘢：蒺藜子、山栀子仁各一合。上二味为散，醋浆和如泥，临卧时以涂之，旦洗之。（《救急方》） ⑾治牙齿出血不止，动摇：白蒺藜末旦旦擦之。（《纲目》） ⑿治牙齿动摇疼痛：土蒺藜，去角生研五钱，淡浆水半碗，蘸水入盐温漱。（《御药院方》）', tips='血虚气弱及孕妇慎服。 ②《本草汇言》：阴虚不足，精髓血津枯燥至疾者，俱禁用之。 ③《得配本草》：肝虚，受孕，二者禁用。' where id=1702; -- 刺蒺藜
update herbs set effect='1、治心胸中大寒痛，呕不能饮食，腹中寒，上冲皮起，出现有头足，上下痛而不可触近：蜀椒二合（去汗），干姜四两，人参二两。上三味，以水四升，煮取二升，去滓，纳胶饴一升，微火煮取一升半。分温再服，如一炊顷，可饮粥二升，后更服，当一日食糜，温覆之。（《金匮要略》大建中汤） 2、治冷虫心痛：川椒四两。炒出汗，酒一碗淋之，服酒。（《寿域神方》） 3、治呃噫不止：川椒四两。炒研，面糊丸，梧子大，每服十九，醋汤下。（《秘传经验方》） 4、治夏伤湿冷，泄泻不止：川椒一两（去目并闭口者，慢火炒香熟为度），肉豆蔻（面裹，煨）半两。上为细末，粳米饭和丸黍米大。每服十粒，米饮下，无时。（《小儿卫生总微论方》川椒丸） 5、治飧泄：苍术二两，川椒一两（去口。炒）。上为细末.醋糊丸，如梧子大。每服二、三十丸，食前温水下。恶痢久不愈者，弥佳。如小儿病，丸如黍米大。（《普济方》椒术丸） 6、治齿痛：蜀椒醋煎含之。（《食疗本草》） 7、治齿疼：川椒一两（去目），捣罗为末，以好白面丸如皂角子大，烧令热，于所痛处咬之。（《圣惠方》） 8、治伤寒呕血，继而齿缝皆流血不止：开口川椒四十九粒，用醋同煎，临熟入白矾少许，漱口含在口中，少顷吐出，再啜漱而含。（《仁斋直指方》） 9、治寒湿脚气：川椒二、三升，稀布囊盛之，日以踏脚。（《妇人良方》） 10、治肾风囊痒：川椒、杏仁。研膏，涂掌心，合阴囊而卧。（《仁斋直指方》） 11、治妇人阴痒不可忍，非以热汤抱洗有不能已者：花椒、吴萸、蛇床各一两，藜芦五钱，陈茶一撮，烧盐二两。水煎熏洗。（《医级》椒茱汤） 12、治手脚心风毒肿：生（花）椒末、盐末等分。以醋和敷。（《补缺肘后方》） 13、治久患口疮：蜀椒去闭口者，水洗，面拌，煮作粥，空腹吞之，以饭压下，重者可再服，以瘥为度。（《食疗本草》） 14、治头上白秃：花椒末，猪脂调敷。（《普济方》） 15、治手足皴裂：（花）椒四合，水煮之，去滓。渍之半食顷，出令燥，须臾复浸，干涂羊、猪髓脑。（《僧深集方》） 16、治漆疮：汉椒汤洗之。（《谭氏小儿方》） 17、治元藏伤惫，耳聋目睹：蜀椒（去目及闭口者，暴干捣罗取红秤一斤，再捣为末），生地黄七斤（肥嫩者）。上二味，先将地黄搀绞自然汁，铜器中煎至一升许，住火，候稀稠得所，即和前椒末为丸，如梧桐子大。每日空心暖酒下三十丸。（《圣济总录》椒红丸） 18、治好食生茶：（花）椒末不限多少，以糊丸如梧子大，茶下十丸。（《胜金方》） 19、蜀椒汤(《备急千金要方》)，治产后心痛，此大寒冷所为者。 20、大建中汤(《金蒉要略》)，治心胸中大寒痛，呕不能饮食，腹中寒，上冲皮起，出现有头足，上下痛而上可触近。 21、椒梅汤(《增补百病固春》)，治虫积腹痛，四肢冷，面白唇红，舌淡白。 22、治冷虫心痛方(《寿域神方》)：川椒四两，炒出汗，酒一碗淋之，服酒。 23、治飧泄丸(《普济方》)：苍术二两，川椒一两，上为强末，醋糊丸，如梧子大，每服二、三十丸，食前温水下。 24、治齿疼方(《圣惠方》)：川椒一两(去目)，捣罗为末，以好白面丸如皂角子大，烧令热，于所痛处咬之。 25、治肾风囊痒方(《仁斋直指》)：川椒，杏仁，研膏，涂掌心，合阴囊而卧。 26、椒红丸(《圣济总录》)：蜀椒，生地黄，上二味，先将地黄捣绞自然汁，铜器中煎至一升许，住火，候稀稠得所，即和前椒末为丸，如梧桐子大，每日空心酒下三十丸，治元藏伤惫，耳聋目暗。', usage='', tips='1、阴虚火旺者忌服。孕妇慎服。 2、畏款冬。恶枯楼、防葵。畏雌黄。 3、《名医别录》：多食令人乏气，口闭者杀人。 4、《千金·食治》：久食令人乏气失明。 5、《唐本草》：畏橐吾、附子、防风。 6、《本草经疏》：肺胃素有火热，或咳嗽生痰，或嘈杂醋心，呕吐酸水，或大肠积热下血，咸不宜用；凡泄泻由于火热暴注而非积寒虚冷者忌之；阴痿脚弱，由于精血耗竭而非命门火衰虚寒所致者，不宜入下焦药用；咳逆非风寒外邪壅塞者不宜用；字乳余疾由于本气自病者不宜用；水肿黄疸因于脾虚而无风湿邪气者不宜用；一切阴虚阳盛，火热上冲，头目肿痛，齿浮，口疮，衄血，耳聋，咽痛，舌赤，消渴，肺痿，咳嗽，咯血，吐血等证，法所咸忌。 7、《随息居饮食谱》：多食动人堕胎。 1、阴虚火旺者忌服。孕妇慎服。 2、畏款冬。恶枯楼、防葵。畏雌黄。 3、《名医别录》：多食令人乏气，口闭者杀人。 4、《千金·食治》：久食令人乏气失明。 5、《唐本草》：畏橐吾、附子、防风。 6、《本草经疏》：肺胃素有火热，或咳嗽生痰，或嘈杂醋心，呕吐酸水，或大肠积热下血，咸不宜用；凡泄泻由于火热暴注而非积寒虚冷者忌之；阴痿脚弱，由于精血耗竭而非命门火衰虚寒所致者，不宜入下焦药用；咳逆非风寒外邪壅塞者不宜用；字乳余疾由于本气自病者不宜用；水肿黄疸因于脾虚而无风湿邪气者不宜用；一切阴虚阳盛，火热上冲，头目肿痛，齿浮，口疮，衄血，耳聋，咽痛，舌赤，消渴，肺痿，咳嗽，咯血，吐血等证，法所咸忌。 7、《随息居饮食谱》：多食动人堕胎。' where id=1703; -- 川椒
update herbs set alias='赤苓，赤茯。', taste='甘；淡；平。', channel='入心、脾、膀胱经。', effect='①治小便白浊不利，时作痛：赤茯苓、沉香各一两。上为细末，每服二钱，白汤点，食后临卧服之。（《鸡峰普济方》茯苓汤） ②治心肾气虚，神志不守，小便淋沥或不禁，及遗泄白浊：赤茯苓、白茯苓各等分。上为末，以新汲水按洗，澄去新沫，控干，别取地黄汁，同好酒熬成膏，搜和为丸，如弹子大，空心盐酒嚼下。（《三因方》张真君茯苓丸） ③治胸胁逆满胀渴：赤茯苓（去黑皮）一两，人参半两。上二味粗捣筛，以水三盏，煎取一盏半，云滓，分温三服。（《圣济总录》茯苓汤） ④治血淋不可忍：陈皮、香附子、赤茯苓各等分．上锉散．每服三钱 水煎空心服．（《世医得效方》通秘散）' where id=1704; -- 赤茯苓
update herbs set alias='虻，黄虻，苘，贝母、空草，贝父、药实，苦花、苦菜、勤母，母龙精。', taste='味甘、苦；性微寒。', channel='归肺、心经。', effect='①治肺热咳嗽多痰，咽喉中干：见母（去心）一两半，甘草（炙）三分，杏仁（汤浸去皮、尖、炒）一两半。上三味，捣罗为末，炼蜜丸如弹子大。含化咽津。（《圣济总录》贝母丸） ②治伤风暴得咳嗽：贝母（安心）三分，款冬花、麻黄（去根节）、杏仁（汤浸，去皮、尖、双仁，炒研）各一两，甘草（炙锉）三分。上五味，粗捣筛，每服三钱匕，水一盏，生姜三片，煎至七分，去滓温服，不拘时。（《圣济总录》贝母汤） ③治伤寒后暴嗽、喘急；欲成肺萎、劳嗽：贝母一两半（煨令微黄）。桔梗一两（去芦头），甘草一两（炙微赤、锉），紫菀一两（洗去苗土），杏仁半两（汤浸，去皮、尖、双仁、麸炒微黄）。上药捣罗为末，炼蜜丸如梧桐子大。每服不计时候，以粥饮下二十丸；如弹子大，绵襄一丸，含咽亦佳。（《圣惠力》贝母丸） ④治小儿咳嗽喘闷：贝母（去心，麸炒）半两，甘草（炙）一分。上二味捣罗为散，如二、三岁儿，每一钱匕，水七分，煎���四分，去滓，入牛黄末少许，食后温分二服，更量儿大小加减。（《圣济总录》贝母散） ⑤治百日咳：川贝母五钱，黄郁金、葶苈子、桑白皮、白前、马兜铃各五分。共轧为极细末，备用。1．5～3岁，每次二分；4～7岁，每次五分；8～10岁，每次七分，均一日三次，温水调冲，小儿酌加白糖或蜜糖亦可。（《江苏中医》（2）：36，1965） ⑥治久嗽咽嗌妨闷，咽痛咯血：贝母不以多少，为细末炼蜜和丸，如弹子大，每服一丸，食后含化，日可三服。（《鸡峰普济方》贝母丸） ⑦治肺痈肺萎：川贝一两，天竺黄、硼砂各一钱，文蛤五分（醋炒）。为末，以枇杷叶刷净蜜炙，熬膏作丸，芡实大，噙咽之。（《医级》贝母括痰丸） ⑧治吐血衄血，或发或止，皆心藏积热所致：贝母一两（炮令黄）。捣细罗为散，不计时候，以温浆调下二钱。（《圣惠方》） ⑨治忧郁不伸，胸膈不宽：贝母去心，姜汁炒研，姜汁面糊丸，每次七十丸。（《集效方》） ⑩化痰降气，止咳解郁，消食除胀：贝母（去心）一两，姜制厚朴半两。蜜丸梧子大，每白汤下五十丸。（《卫生杂兴》） ⑾下乳：牡蛎、知母、贝母，三物为细末，同猪蹄汤调下。（《汤液本草》三母散） ⑿治瘰疬便毒：皿母、皂角子各半斤。为细末，用皂角半斤锉碎，搓揉浓水，滤过作膏子，和药末，丸如梧桐子大。每服五、七十丸，早晨酒下。（《昔济方》贝母丸） ⒀治喉痹肿胀：贝母、山豆根、桔梗、甘草、荆芥、薄荷，煎汤服。（《本草切要》） ⒁治乳痈初发：贝母为末，每服二钱，温酒调下，即以两手覆按于桌上，垂乳良久乃通。（《仁斋直指加） ⒂治冷泪目昏：贝母一枚，胡椒七粒，为末点之。（《儒门事亲》） ⒃治小儿鹅口，满口白烂：贝母去心为末，半钱，水五分，蜜少许，煎三沸，缴净抹之，日四、五度。（《圣惠方》）', tips='脾胃虚寒及有湿痰者不宜。 恶槐花。畏秦艽、矾石、莽草。反乌头。 ②《本草经疏》：寒湿痰及食积痰火作嗽，湿痰在胃恶心欲吐，痰饮作寒热，脾胃湿痰作眩晕及我厥头痛中恶呕吐，胃寒作泄并禁用。' where id=1705; -- 川贝母
update herbs set alias='蛤蚆皮，癞蟆皮。', effect='①治指头红肿生毒：活蟾一只生剥皮，将皮外面向患处包好，明日其毒一齐拔出，或发背、对口等症，毒忽收，内如又起，再贴。切记不可将其皮里面着肉，即咬牢难揭。凡痘疹后回毒，亦可用此治。（《行箧检秘》） ②治痈疮：大虾蟆一个，剥全身癞皮，盖贴疮口，于蟆皮上用针将皮刺数孔，以出毒气，自觉安静，且能爬住疮口，不令长大。（《灵秘丹药牋》） ③消肿退毒：干蟾皮不拘多少，研为末，金银花露调敷。（《药籢启秘》金蟾散） ④治肠头挺出：蟾蜍皮一片，瓶内烧熏挺处。（孙思邈）' where id=1706; -- 蟾皮
update herbs set taste='辛咸；平；无毒。', channel='入肾、肝、肺经。', effect='①补暖水脏，强益气力，明耳目，利腰脚：磁石十两（大火烧令赤，投于醋中淬之七度，细研，水飞过，以好酒一升，煎如饧），肉苁蓉二两（酒浸一宿，刮去皱皮，炙干），木香二两，补骨脂二两（微炒），槟榔二两，肉豆蔻二两（去壳），蛇床子二两。捣罗为束，与磁石煎相和，丸如梧桐子大。每日空心以温酒下二十丸。（《圣惠方》磁石丸） ②补肝肾虚，止冷泪，散黑花：磁石一两（煅，醋炙），菖蒲、川乌（焙，去皮、尖）、巴戟、黄芪、苁蓉、玄参各等分。为细末，炼蜜和丸，如梧桐子大。每服二十丸，盐酒汤下，空心服。（《卫生家宝方》磁石丸） ③明目，益眼力（《圣济总录》云：治肾藏风虚，眼生黑花）：神曲四两，磁石二两，光明砂一两。上三味，末之，炼蜜为丸，如梧子。饮服三十丸，日三，不禁。（《千金方》神曲丸，《纲目》名磁朱丸） ④治久患耳聋，养肾脏，强骨气：磁石一斤（捣研，水淘去赤汁，绵裹），猪肾一对（去脂膜，细切）。以水五升，煮磁石取二升，去磁石，投肾，调和以葱、豉、姜、椒作羹，空腹食之，作粥及入酒并得。（《圣惠方》磁石肾羹） ⑤治耳聋耳鸣，常如风水声：磁石（捣碎，绵裹）半两，木通、菖蒲（米泔浸一、二日，切，焙）各半斤。上三味，以绢囊盛，用酒一斗浸，寒七日，暑三日，每饮三合，日再。（《圣济总录》磁石酒） ⑥治阳不起：磁石五斤（研）。清酒三斗，渍二七日，一服三合，日夜一。（《千金方》） ⑦治小儿惊痫：磁石炼水饮。（《圣济总录》） ⑧治子宫不收，名瘣疾，痛不可忍：慈石酒浸，煅、研末，米糊丸梧子大。每卧时滑石汤下四十丸，次早用磁石散，米汤服二钱。散用磁石（酒浸）半两，铁粉二钱半，当归五钱，为末。（《纲目》磁石丸） ⑨治大肠虚冷脱肛：干蜗牛子一百枚（微炒，捣罗为末），磁石二两（捣碎，淘去亦汁）。上药，以水一大盏，煎磁石五钱，至五分，去滓，调蜗牛末一钱服之，日三服。（《圣惠方》） ⑩治诸般肿毒：吸铁石三钱，金银藤四两，黄丹八两，香油一斤。如常熬膏贴之。（《乾坤生意秘韫》） ⑾治疔肿：磁石捣为粉，碱、醋和封之，拔根出。（《古今录验方》） ⑿治金疮肠出，欲入之：磁石、滑石各三两。为末，以白米饮调方寸匕服，日再服。（《刘涓子鬼遗方》） ⑿治金疮，止痛，断血：磁石末敷之。（《千金方》） ⒀用于肝肾不足，虚阳上亢之头晕目眩，耳聋耳鸣，视物模糊：磁石味咸质重，性主沉降，能潜降上亢之肝阳，为治阴虚阳亢，头晕目眩所常用，与白芍、生地、天麻等同用，以滋阴潜阳、平肝熄风，如《医醇賸义》滋生清阳汤。 ⒁用于肾水不足，耳目昏聩：磁石能养肾益精，聪耳明目，治肾虚内障，视物模糊，常与朱砂、神曲为丸服，如《千金要方》之神曲丸(即磁朱丸)。若肾虚耳聋耳鸣，可与猪肾同煮服，如《圣惠方》磁石肾羹；若温热病后，肾虚精亏而耳聋耳鸣者，亦可用磁石与熟地黄、山萸肉、石菖蒲、五味子配用，以滋阴益肾，如《重订广温热论》耳聋左慈丸。 ⒂用于心神不安，惊悸、失眠：磁石质重能安神镇惊，与朱砂同用更佳，亦常与茯神、酸枣仁、远志等养心安神之药同用；小儿惊痫用之，既可安神，亦可镇惊，如《圣济总录》以磁石炼水饮。 ⒃用于肾不纳气，上气喘逆：磁石功能入肾，镇摄肾虚不纳之气，故虚喘肾不纳气，常配熟地、胡桃肉、五味子等同用。 ⒄此外，磁石研末外敷，可治痈疮肿毒及创伤出血。 ⒅耳聋左磁丸（《重订广温热论》）治肝肾阴亏，虚阳上扰，头晕目眩，耳鸣耳聋。六味地黄丸加磁石90g,石菖蒲45g,北五味15g。上药为末，练蜜为丸，每服三钱，淡盐汤送下。方中磁石潜阳。 ⒆磁朱丸（《备急千斤要方》）治心肾不交证。视物昏花，耳鸣耳聋，心悸失眠。亦治癫痫。磁石60g,朱砂30g,神曲120g.三味末之，练蜜为丸，如悟子大，饮服三丸，日三服。方中磁石镇摄安神，益阴潜阳，使香火不得扰，为君药。 ⒇生磁石（末煅）配新炭木（木炭末）、蜜蜂，调服，治误吞金属异物。', tips='恶牡丹、莽草。畏黄石脂。杀铁毒。 ②《本草从新》：重镇伤气，可暂用而不可久。' where id=1707; -- 磁石
update herbs set taste='味甘；咸；性凉。', channel='入肺、肝经。', effect='①治风温初起，风热新感，冬温袭肺，咳嗽：薄荷一钱五分，蝉退一钱（去足、翅），前胡一钱五分，淡豆豉四钱，瓜娄壳二钱，牛蒡子一钱五分。煎服。（《时病沦》辛凉解表法） ②治咳嗽，肺气壅滞不利：蝉壳（去土，微炒）、人参（去芦）、五味子各一两，陈皮、甘草（炙）各半两。共为细末。每服半钱，生姜汤下，无时。（《小儿卫生总微论方》蝉壳汤） ③治感冒、咳嗽失音：蝉衣一钱，牛蒡子三钱，甘草一钱，桔梗一钱五分。煎汤服。（《现代实用中药》） ④治痘疮出不快：紫草、蝉蜕、木通、芍药、甘草（炙）各等分。每服二钱，水煎服。（《小儿痘疹方论》快透散） ⑤治风气客皮肤瘙痒不已：蝉蜕、薄荷叶等分。为末。酒调一钱匕，日三服。（《姚僧坦集验方》） ⑥治痘后发热发痒抓破：蝉退、地骨皮各一两。为末。每服二，三匙，白酒服二、三次。（《赤水玄珠》蝉花散） ⑦治惊痫热盛发搐：蝉壳（去土，炒）半两，人参（去芦）半两，黄芩一分，茯神一分，升麻一分，以上细末；牛黄一分（另研），天竺黄一钱（研），牡蛎一分（研）。上同匀细，每用半钱，煎荆芥、薄荷汤调服，无时。（《小儿卫生总微论方》蝉壳散） ⑧治小儿天吊，头目仰视，痰塞内热：金牛儿，以浆水煮一日，晒干为末，每服一字，冷水调下。（《卫生易简方》） ⑨治小儿噤风，初生口噤不乳：蝉蜕二七枚，全蝎二七枚。为末，入轻粉末少许，乳汁调灌。（《全幼心鉴》） ⑩治小儿夜啼：蝉退二七枚，辰砂少许。为末，炼蜜丸，令儿吮。（《赤水玄珠》蝉退膏）或用蝉蜕四十九个，去前截，以后截研为末，分四次服，钩藤汤调下。 ⑾治破伤风：蝉蜕（去土）不以多少。为细末。掺在疮口上，毒气自散。（《杨氏家藏方》追风散） ⑿治癍疮入眼或病后生翳障：蝉蜕（洗净，去土）、白菊花各等分。每服二钱，水一盏，入蜜少许煎，乳食后，量儿大小与之。（《小儿痘疹方论》蝉菊散） ⒀治内障：龙退（即蛇皮）、蝉退、凤凰退（鸟花鸡卵壳），人退、佛蜕（即蚕纸）。上等分，不以多少，一处同烧作灰，研为细末。每服一钱，热猪肝吃，不拘时侯，日进三服。（《眼科龙木论》五退散） ⒁治疔疮：蝉退壳、白僵蚕各等分。上为末，醋调涂四围，留疮口，俟根出稍长，然后拔根出，再用药涂疮。一方不用醋，用油调涂。（《圣惠方》蝉蜕散）或用蝉蜕炒为末，蜜水调服一钱，另以唾液调末，涂搽患处。 ⒂治瘰疬：胡桃打开，掏出一半瓤，装满蝉蜕，外以黄土泥封妥，铁丝扎紧，置慢火上焙干，泥自脱落，再将胡桃研细面，用黄酒为引，开水冲服，每日早空心服一个，连服一百日。（《河北中医药集锦》） ⒃治聤耳出脓：蝉蜕半两（烧存性），麝香半钱（炒）。上为末，绵裹塞之，追出恶物。（《海上方》） ⒄治小儿阴肿：蝉蜕半两，煎水洗；仍服五苓散，即肿消痛止。（《世医得效方》）（多因坐地风袭，或为虫蚁所伤） ⒅小儿初生、口噤不乳。用蝉蜕十数枚、全蝎（去毒）十数枚，共研为末，加轻粉末少许，乳汁调匀灌下。 ⒆破伤风病（发热）。用蝉蜕炒过，研为末，酒送服一钱，极效。又方：有得意蜕研为末，加葱涎调匀，涂破处，流出恶水，立效。此方名追风散。 ⒇胃热吐食，用蝉蜕五十个（去泥）、滑石一两，共研为末，每服二钱，水一碗，加蜜调服，此方名清膈散' where id=1708; -- 蝉蜕
update herbs set effect='①治风气头风：臭梧桐花阴干，浇存性为末。每服二钱，临卧酒下。(《医方集听》) ②止痢：隔中臭梧桐花，煎汤服。(《纲目拾遗》) ③治疝气偏坠：鲜臭梧桐花五钱。捣烂泡酒服。(《泉州本草》)', tips='祛风；降压；止痢。主风气头痛；高血压病；痢疾；疝气。治头风，痢疾，疝气。' where id=1709; -- 臭梧桐花
update herbs set alias='枱耳实，牛虱子，胡寝子，苍郎种、棉螳螂，苍子、胡苍子，饿虱子，苍棵子、苍耳蒺藜。', taste='味苦；甘；辛；性温；小毒。', channel='入肺、肝经。', effect='①治诸风眩晕，或头脑攻痛：苍耳仁三两，天麻、白菊花各三钱。（《本草汇言》） ②除风湿痹，四肢拘挛：苍耳子三两。捣末，以水一升半，煎取七合，去滓呷。（《食医心镜》） ③治大麻风：苍术一斤，苍耳子三两。各为末，米饭为丸，如梧子大。日三服，每服二钱。忌房事三月。（《洞天奥旨》） ④治疥癞，消风散毒：苍耳子炒蚬肉食。（《生草药性备要》） ⑤治妇人风瘙瘾疹，身痒不止：苍耳花、叶、子等分，捣细罗为末。每服以豆淋酒调下二钱。（《圣惠方》） ⑥治鼻流浊涕不止：辛夷半两，苍耳子二钱半，香白芷一两，薄荷叶半钱。上并晒干，为细末。每服二钱，用葱、茶清食后调服。（《济生方》苍耳散） ⑦治目睹、耳鸣：苍耳子半分。捣烂，以水二升，绞滤取汁，和粳米半两煮粥食之，或作散煎服。（《圣惠方》苍耳子粥） ⑧治牙疼：苍耳子五升，以水一斗，煮取五升，热含之，疼则吐，吐复含。无子，茎、叶皆得用之。（《千金翼方》） ⑨治疔疮恶毒：苍耳子五钱。微炒为末，黄酒冲服；并用鸡子清涂患处，疔根拔出。（《经验广集》苍耳酒）' where id=1710; -- 苍耳子
update herbs set effect='1、治疗赤痢多腹痛不可忍：赤芍药100克 黄柏100克（以蜜拌合涂炙令尽 锉）．上药 捣筛为散 每服15克 以淡浆水一中盏 煎至五分 去滓 不计时候稍热服．（《太平圣惠方》赤芍药散） 2．治疗血痢腹痛：赤芍药、黄柏（去粗皮 炙）、地榆各50克．上三味捣筛 每服15克 以浆水一盏 煎至七分 去滓 不拘时温服．（《圣济总录》芍药汤） 3．治疗五淋：赤芍药50克 槟榔一个（面裹煨）．上为末 每服5克 水煎 空心服．（《博济方》） 4．治疗急性乳腺炎：赤芍50~100克 生甘草10克．水煎服．如发热加黄芩 另用白蔹根、食盐少许捣敷患处．（《单方验方调查资料选编》） 5．治疗妇人血崩不止、赤白带下：香附子、赤芍药．上等份 为末 盐一捻 水二盏 煎至一盏 去渣服 食前[3]．（《太平圣惠方》如神散） 6．犀角地黄汤（《备急千金要方》）主治热入血分证，热伤血络证。水牛角30g，生地黄24g，赤芍12g，牡丹皮9g上药四味，以水九升，煮取三升，分三服。方中赤芍苦酸微寒，养血敛阴，且助生地凉血和营泄热，于热盛出血者尤宜。 7．仙方活命饮（《校注妇人良方》）主治痈疡肿毒初起。白芷、贝母、防风、赤芍药、当归尾、甘草节、皂角刺、穿山甲、天花粉、乳香、没药各6g，金银花25g，陈皮9g。用酒一大碗，煎五七沸服。方中赤芍活血散瘀。' where id=1711; -- 赤芍
update herbs set taste='苦，寒，有毒。', channel='入肝、胃、小肠经。', effect='①治热厥心痛，或发或止，久不愈者：金铃子、玄胡索各一两。上为细末，每服二、三钱，酒调下，温汤亦得。（《活法机要》金铃子散） ②治膀胱疝气，闭塞下元，大小便不通，疼痛不可忍者：金铃子肉四十九枚（锉碎如豆大，不令研细，用巴豆四十九枚，去皮不令碎，与金铃子肉同炒至金铃子深黄色，不用巴豆），茴香一两（炒）。上件除巴豆不用外，将二味为细末，每服二钱，温酒调下，食前。（《杨氏家藏方》金铃子散） ③治寒疝，以及偏坠，小肠庙痛：川楝子三钱，小茴香五分，木香一钱，淡吴茱萸一钱。长流水煎服。（《医方简义》导气汤） ④治脏毒下血：苦楝子炒令黄。为末，蜜丸。米饮下十丸至二十丸。（《经验方》） ⑤治肾消膏淋，病在下焦：苦楝子、茴香等分。为末，每温酒服-钱。（《圣惠方》） ⑥治小儿五疳：川楝子肉、川芎等分。为末，猪胆汁丸。米次下。（《摘元方》） ⑦治耳有恶疮：楝于，捣，以绵裹塞耳内。（《圣惠方》）', tips='脾胃虚寒者忌服。' where id=1712; -- 川楝子
update herbs set effect='1、五加酒(《备急千金要方》)：用治产后癖瘦。 2、油煎散(《太平惠民和剂局方》)：治妇人血风劳，形容憔悴，肢体困倦，喘满虚烦，呼吸少气，发热汗多，口干舌涩，不思饮食。 3、五加皮汤(《三因极一病症方论》)：主治肾劳虚寒，恐虑失志，伤精损髓，嘘吸短气，遗泄白浊，小便赤黄，阴下湿痒，腰脊如折，颜色枯悴。 4、五皮散(《太平惠民和剂局方》)。 5、五加皮丸(《瑞竹堂经验方》)：主治男子妇人脚气，骨节皮肤肿湿疼痛。' where id=1713; -- 刺五加
update herbs set taste='酸苦，温。', channel='入肝、胃经。', effect='①治产后血晕：用铁器烧红，更迭淬醋中，就病人之鼻以熏之。（《随息居饮食谱》） ②治一切积聚，不拘远年近日皆治之：京三棱四两（醋煮，切片，晒干），川芎二两（醋煮微软，切片），大黄半两（醋湿纸裹，火煨过）。上三味，同为末，水煮和为丸，如桐子大。每服三十丸，温水送下，不拘时候。病甚者一月效，轻者半月效。（《普济方》醋煮三棱丸） ③治瘕癥：鳖甲、诃子皮、干姜各等分。为末，醋糊丸，梧子大，每三十丸，空心白汤下。（《医学入门》醋鳖丸） ④治过食鱼腥、生冷水菜果实成积者：生姜捣烂，和米醋调食之。（《日华子本草》） ⑤治黄汗病，身体肿，发热，汗出而渴，状如风水，汗沾衣，色正黄如檗汁，脉自沉。以汗出入水中浴，水从汗孔入得之：黄芪五两，芍药三两，桂枝三两。上三味，以苦酒一升，水七升，相和，煮取三升，温服一升，当心烦，服至六、七日乃解。若心烦不止者，以苦酒阻故也。（《金匮要略》黄芪芍药桂枝苦酒汤） ⑥治鼻血出不止：酢和胡粉半枣许服。（《千金方》） ⑦治疝气冲痛：育皮、小茴香各五钱，以米醋一碗煮干，加水二碗，煎八分，温和服。（《林氏家抄方》） ⑧治霍乱转筋入腹：酢煮青布搨之，冷复易之。（《千金方》） ⑨治痈疽初起：生附子，以米醋磨稠汁，围四衅，一日上十余次。（《方脉正宗》） ⑩治诸肿毒：醋调大黄末涂。（《随息居饮食谱》） ⑾治乳痈坚：以罐盛醋，烧石令热蚺中，沸止，更烧如前，少热，纳乳滇之，冷更烧石纳渍。（《千金方》） ⑿治少阴病，咽中伤生疮，不能语言，声不出者：半夏（洗、破如枣核）十四枚，鸡子一枚（去黄，纳苦酒，着鸡子壳中）。上二味纳半夏著苦酒中，以鸡子壳置刀环中，安火上，令三沸，去滓，少少含咽之，不瘥，更作三剂。（《伤寒论》苦酒汤） ⒀治锁喉风，胀闷不通：土牛膝捣汁半碗，加入真米醋半碗，用鹅毛翎尖挑少许入喉中，随吐涎痰，连挑十余次，吐痰碗许即通。（《本草汇言》） ⒁治牙齿疼痛：米醋煮枸杞白皮一升，取半升，含漱。（《肘后方》） ⒂治牙疼：陈醋四两，花椒二钱。水煎，去椒含漱。（内蒙古《中草药新医疗法资料选编》） ⒃治汤火伤：醋淋洗。（《随息居饮食谱》）' where id=1714; -- 醋
update herbs set taste='味辛；苦；性温', channel='归脾；胃；肝经', effect='①治脾胃不和，不思饮食，心腹胁肋胀满刺痛，口苦无味，呕吐恶心，常多自利：苍术（去粗皮，米泔浸二日）五斤，厚朴（去粗皮，姜汁制，炒香）、陈皮（去白）各三斤二两，甘草（炒）三十两。上为细末。每服二钱，以水一盏，入生姜二片，干枣两枚，同煎至七分，去姜、枣，带热服，空心食前；入盐一捻，沸汤点服亦得。（《局方》平胃散） ②治太阴脾经受湿，水泄注下，体微重微满，困弱无力，不欲饮食，暴泄无数，水谷不化，如痛甚者：苍术二两，芍药一两，黄芩半两。上锉，每服一两，加淡味桂半钱，水一盏半，煎至一盏，温服。（《素问病机保命集》苍术芍药汤） ③治时暑暴泻，壮脾温胃，进美饮食，及疗饮食所伤，胸膈痞闷：神曲（炒）、苍术（米泔浸一宿，焙干）各等分为末。面糊为丸，如梧桐子大。每服三十丸，不拘时，米饮吞下。（《局方》曲术丸） ④治飧泄：苍术二两，小椒一两（去目，炒）。上为极细末，醋糊为丸，如桐子大。每服二十丸，或三十丸，食前温水下。一法恶痢久不愈者加桂。（《素问病机保命集》椒术丸） ⑤治膈中停饮，已成癣囊：苍术一斤，去皮，切，末之，用生麻油半两，水二盏，研滤取汁，大枣十五枚，烂者去皮、核，研，以麻汁匀研成稀膏，搜和，入臼熟杵，丸梧子大，干之。每日空腹用盐汤吞下五十丸，增至一百丸、二百丸。忌桃李雀鸽。（《本事方》） ⑥治脾经湿气，少食，湿肿，四肢无力，伤食，酒色过度，劳逸有伤，骨热：鲜白苍术二十斤，浸去粗皮，洗净晒干，锉碎，用米泔浸一宿，洗净，用溪水一担，大锅入药，以慢火煎半干去渣，再入石楠叶三斤，刷去红衣，用楮实子一斤，川归半斤，甘草四两，切，研，同煎黄色，用麻布滤去渣，再煎如稀粥，方入好白蜜三斤，同煎成膏。每用好酒，空心食远，调三、五钱服，不饮酒用米汤。有肿气用白汤，呕吐用姜汤。（《活人心统》苍术膏） ⑦治湿温多汗：知母六两，甘草（炙）二两，石膏一斤，苍术三两，粳米三两。上锤如麻豆大。每服五钱，水一盏半，煎至八、九分，去滓取六分清汁，温服。（《类证活人书》白虎加苍术汤） ⑧治四时瘟疫，头痛项强，发热憎寒，身体疼痛，及伤风、鼻塞声重、咳嗽头昏：苍术（米泔浸一宿，切，焙）五两，藁本（去土）、香白芷、细辛（去叶、土）、羌活（去芦）、川芎、甘草（炙）各一两。上为细末。每服三钱，水一盏，生姜三片，葱白三寸，煎七分，温服，不拘时。如觉伤风鼻塞，只用葱茶调下。（《局方》神术散） ⑨治感冒：苍术一两，细辛二钱，侧柏叶三钱。共研细末，每日四次，每次一钱五分，开水冲服，葱白为引，生吃。（内蒙古《中草药新医疗法资料选编》） ⑩治湿气身痛：苍术，泔浸切，水煎，取浓汁熬膏，白汤点服。（《简便单方》） ⑾治筋骨疼痛因湿热者：黄柏（炒）、苍术（米泔浸炒）。上二味为末，沸汤入姜汁调服。二物皆有雄壮之气，表实气实者，加酒少许佐之。（《丹溪心法》二妙散，即《世医得效方》苍术散） ⑿补虚明目，健骨和血：苍术（泔浸）四两，熟地黄（焙）二两。为末，酒糊丸梧子大。每温酒下三、五十丸，日三服。（《普济方》） ⒀治牙床风肿：大苍术，切作两片，于中穴一孔，入盐实之，湿纸裹，烧存性，取出研细，以此揩之，去风涎即愈，以盐汤漱口。（《普济方）苍术散） ⒁控制疟疾症状或作预防：苍术、白芷、川芎、桂枝各等分为末，每用1克，以纱布四层包成长形，于疟发前1～2小时塞鼻孔内，5小时或1天。（《山西中草药》）', tips='阴虚内热，气虚多汗者忌服。 ②《药性论》：忌桃、李、雀肉、菘菜、青鱼。 ③《医学入门》：血虚怯弱及七情气闷者慎用。误服耗气血，燥津液，虚火动而痞闷愈甚。 ④《本草经疏》：凡病属阴虚血少、精不足，内热骨蒸，口干唇燥，咳嗽吐痰、吐血，鼻衄，咽塞，便秘滞下者，法咸忌之。肝肾有动气者勿服。 ⑤《本草正》：内热阴虚，表疏汗出者忌服。' where id=1715; -- 苍术
update herbs set taste='味咸；性微寒。', channel='入肝、胃经。', effect='①治痈疽无头：穿山甲、猪牙皂角（去皮、弦）各一两。共炙焦黄，为末。每用一钱，热酒调下。其疮破，以冬瓜藤为末敷，疮干即水调敷之，诸疖疮皆可用。（《小儿卫生总微论方》） ②治肿毒初起：穿山甲插入谷芒热灰中，炮焦为末二两，入麝香少许。每服二钱半，温酒下。（《仁斋直指方》） ③治痈疽，托毒排脓，五毒附骨在脏腑里，托出毒气，止痛内消：蜂房一两，穿山甲，蛇蜕、油发（并烧带生存性）各一分。上为末。每服二钱，入乳香末半钱，暖酒调下。（《普济方》穿山甲散） ④治吹奶痛不可忍：穿山甲（炙黄）、木通各一两，自然铜半两（生用）。三味捣罗为散。每服二钱，温酒调下，不计时候。（《本草图经》） ⑤治乳汁不通：穿山甲炮，研末，酒服方寸匕，日二服。（单骧·涌泉散） ⑥治便毒便痈：穿山甲半两，猪苓二钱。并以醋炙研末。酒服二钱。外用穿山甲末和麻油、轻粉涂之。（《仁斋直指方》） ⑦治聤耳出脓：穿山甲烧存性，入麝香少许吹之。（《鲍氏小儿方》） ⑧治瘰疬溃坏：鲮鲤甲二十一片。烧研敷之。（《姚僧坦集验方》） ⑨治蚁瘘疮多而孔小：烧鳢鲤甲。猪膏和敷。（《补缺肘后方》） ⑩治气痔脓血：穿山甲一两（烧存性），肉豆扣仁三个。同为末。米饮调二钱服。甚者加猬皮一两，烧入。中病即已，不必尽剂。（《本草衍义》） ⑾治喉癣：甲片五分（炙），白霜梅一个（炙），雄黄五分，枯矾一钱。上共研末。吹喉内。（《疡科遗编》穿山甲散） ⑿治中风，手足偏废不举：川山甲、红海蛤（如棋子者）、川乌头（大者，生用）各二两。上为末。每用半两，捣烈葱白汁，和成厚饼，约径一寸半，贴在所患一边脚中心，用旧帛裹紧缚定，于无风密室中椅子上坐，椅前用汤一盆，将贴药脚于汤内浸，候汗出，即急去了药，汗欲出，身麻木，得汗周遍为妙。切宜避风，自然手足可举，如病未尽除，候半月二十日以后，再依此法用一次。仍服治风补理药。忌口远欲以自养。（《三因方》趁痛膏） ⒀治但热不寒疟：穿山甲一两，干枣十枚。上同烧灰留性，研为细末。每服二钱，当发日，日未出时井水调下。（《杨氏家藏方》） ⒁治痢，里急后重：穿山甲，好蛤粉等分。上为细末。每服一钱，好酒空心调服。（《普济方》） ⒂治疝气膀胱疼痛：穿山甲（炒）三钱，茴香子二钱。为细末。每服二钱，滚水酒送下。（《滇南本草》） ⒃治妇人阴颓，硬如卵状：穿山甲五钱。以沙炒焦黄为末。每服二钱，酒下。（《摘元方》） ⒄治痘疮变黑：穿山甲，蛤粉炒。为末。每服五分，入麝香少许，温酒服。即发红色。（《仁斋直指方》）' where id=1716; -- 穿山甲
update herbs set effect='①治霍乱呕吐：陈皮三钱 藿香二钱．因寒者 配干姜、砂仁各一钱五分；因热者 配黄连、黄芩、滑石各一钱五分．水煎服．（《本草汇言》） ②治脾胃不调， 冷气暴折， 客乘于中， 寒则气收聚， 聚则壅遏不通， 是以胀满， 其脉弦迟：黄橘皮四两 白术二两．上为细末；酒糊和丸如桐子大．煎木香汤下三十丸， 食前．（《鸡峰普济方》宽中丸） ③治元气虚弱 饮食不消 或脏腑不调 心下痞闷：橘皮、枳实（麸炒黄色）各一两 白术二两．上为极细末 荷叶裹烧饭为丸 如绿豆一倍大．每服五十丸 白汤下 量所伤加减服之．（《兰室秘藏》橘皮枳术丸） ④治泄泻下痢：陈皮三钱， 藿香二钱．因虚者 加白术（土炒）三钱， 茯苓二钱， 甘草一钱；因实者 加枳实 （麸炒）三钱， 厚朴二钱， 木香一钱．水煎服．（《本草汇言》） ⑤治小儿脾疳泄泻：陈橘皮一两， 青橘皮、诃子肉、甘草（炙）各半两．上为粗末．每服二钱， 水一盏， 煎至六分， 食前温服．（《幼科类萃》益黄散） ⑥治干呕哕逆 手足厥冷：橘皮四两， 生姜半斤．二物以水七升， 煮取三升， 一服一升．（《医心方》引《小品方》橘皮汤） ⑦治寸白虫：橘皮四分， 牙子、芜荑各六分．上三味捣筛， 蜜丸如梧子．以浆水下三十丸， 先食， 日再服．（《外台》引《范汪方》橘皮丸） ⑧治产后大小便不通：陈皮、苏叶、枳壳（麸炒）、木通各等分．上锉散．每服四钱， 水煎温服．（《济阴纲目》通气散） ⑨治血淋不可忍：陈皮、香附子、赤茯苓各等分．上锉散．每服三钱， 水煎空心服．（《世医得效方》通秘散）' where id=1717; -- 陈皮
update herbs set taste='平；苦。', effect='①治腰腿酸痛，筋骨麻木：鲜穿山龙根茎二两，水一壶，可煎用五，六次，加红糖效力更佳。（《东北药植志》） ②治劳损：穿山龙五钱。水煎冲红糖、黄酒。每日早、晚各服一次。（《浙江民间常用草药》） ③治大骨节病，腰腿疼痛：穿山龙二两。白酒一斤，浸泡七天。每服一两，每天二次。（《河北中药手册》） ④治闪腰岔气，扭伤作痛：穿山龙五钱。水煎服。（《河北中药手册》） ⑤治疟疾：火藤根三钱，青蛙七、野棉花各二钱。发病前水煎服。（《陕西中草药》） ⑥治痈肿恶疮：鲜火藤根、鲜薴麻根等量。捣烂敷患处。（《陕西中草药》） ⑦治慢性气管炎：鲜穿山龙一两。削皮去根须，洗净切片加水，慢火煎二小时，共煎二次，合并滤液，浓缩至100毫升。分早晚二次服，十日为一疗程。（内蒙古《中草药新医疗法资料选编》） ⑧治风湿性腰腿痛，风湿性关节炎：穿山龙30g，骨碎补9g，淫羊藿9g，土茯苓9g。水煎服。方中穿山龙祛除风湿，活血通络，为君药。（《陕甘宁青中草药选》）', tips='祛风除湿；活血通络；止咳。主风湿痹前；肢体麻木；胸痹心痛；慢性气管炎；跌打损伤；虐疾；痈肿。用于风湿痛，风湿关节痛，筋骨麻木，大骨节病，跌打损伤，支气管炎。 ①《东北药植志》：舒筋活血，治腰腿疼痛，筋骨麻木。 ②《山东中药》：治风寒湿痹。 ③《陕西植药调查》：制疟，止疼，消肿。 ④《陕西中草药》：治咳嗽，风湿性关节炎，大骨节病关节痛，消化不良，疟疾，跌打损伤，痈肿恶疮。' where id=1718; -- 穿山龙
update herbs set effect='①治痢疾：椿皮一两，爵床三钱，凤尾草五钱。煎服。(江西《中草药学》) ②治慢性痢疾：椿皮四两。焙干研粉，每次二钱，每日二次，开水冲服。(《陕西中草药》) ③治肠风下血不止，兼医血痢：椿皮，不以多少，用水净洗锉碎，于透风处挂令干，杵，罗为细末，每称二两，入寒食面一两，搅拌令匀，再罗过，新汲水和丸如梧桐子大，阴干。每服二十丸，先以水湿药丸令润，后于碟子内用白面滚过，水煮五七沸，倾出，用煮药水放温下，不拘时候服。(《圣济总录》如神丸) ④治下血经年：椿皮三钱。水一盏，煎七分，入酒半盏服。(《仁存堂经验方》) ⑤治赤白带下，膀胱炎及尿路感染：川柏、椿皮、知母、白术、生甘草、泽泻、生黄芪片，煎水服。(江西《中草药学》) ⑥治赤白带：椿皮、鸡冠花各五钱。水煎服。(《陕西中草药》) ⑦治滴虫性阴道炎：椿皮五钱。煎服；另用千里光一两，薄荷五钱，蛇床子五钱。煎水，外洗。(江西《中草药学》) ⑧治遗精：良姜三钱(烧灰存性)，黄柏、芍药各二钱(烧灰存性)，樗树根皮一两五钱。上为末，面糊丸如梧桐子大。每服三十丸，空心茶汤下。(《摄生众妙方》樗树根丸) ⑨治产后肠脱不能收拾者：椿皮(取皮，焙干)一握。水五升，连根葱五茎，汉椒一撮，同煎至三升，去渣，倾盆内，乘热熏洗，冷则再热，一服可作五次用，洗后睡少时。忌盐、醉、酱、面、发风毒物，及用心、劳力等事。(《妇人良方》) ⑩治痔疮：椿皮三钱，蜂蜜一两。水煎服。(《陕西中草药》) (11)治疮癣：椿皮适量。煎水洗患处。(《陕西中草药》)' where id=1719; -- 椿皮
update herbs set taste='味辛；性温。', channel='归脾、胃经。', effect='①治疟疾，胃中寒痰凝结，不易开解:草果、常山、知母、乌梅、槟榔、甘草、穿山甲。水煎服。（《慈幼新书》草果饮） ②治瘅疟，脉采弦数，但热不寒，或热多寒少，膈满能食，口苦舌干，心烦，渴水，小便黄赤，大腑不利:青皮（去白）、厚朴（姜制炒）、白术、草果仁、柴胡（去芦）、茯苓（去皮）、半夏（汤泡七次）、黄芩、甘草（炙）各等分。细锉。每服四钱，水一盏半，姜五片，煎至七分，去滓，温服，不拘时侯。（《济生方》清脾汤） ③治肿寒疟疾不愈，振寒少热，面青不食，或大便溏泄，小便反多:草果仁、附子（炮，去皮脐）。上等分，细锉。每服半两，水二盏，生姜七片，枣一枚，煎至七分，去滓温服，不拘时候。（《济生方》果附汤） ④治脾痛胀满:草果仁二个。酒煎服之。（《仁斋直指方》） ⑤治肠胃冷热不和，下痢赤白，及伏热泄泻，脏毒便血:草果子、甘草、地榆、枳壳（去穰，麸炒）。上等分为粗末。每服二钱，用水一盏半，煨姜一块，拍碎，同煎七分，去滓服，不拘时候。（《传信适用方》草果饮） ⑥治瘟疫初起，先憎寒而后发热，日后但热而无憎寒，初起二、三日，其脉不浮不沉而数，昼夜发热，日哺益甚，头身疼痛:槟榔二钱，厚朴一钱，草果仁五分，知母一钱，芍药一钱，黄芩一钱，甘草五分。用水一钟，煎八分，午后温服。（《瘟疫论》达原饮）' where id=1720; -- 草果
update herbs set taste='味辛；性温。', channel='入肝、胆经。', effect='①治诸风上攻，头目昏重，偏正头痛，鼻塞声重，伤风壮热，肢体烦疼，肌肉蠕动，膈热痰盛，妇人血风攻疰，太阳穴疼，及感风气：薄荷叶（不见火）八两，川芎、荆芥（去梗）各四两，香附孑（炒）八两（别本作细辛去芦一两），防风（去芦）一两半，白芷、羌活、甘草（爁）各二两；上药为细末，每服一钱，食后茶清调下，常服头目清。（《局方》川芎茶调散） ②治偏头疼：京芎细锉，酒浸服之。（《斗门方》） ③治首风旋晕，眩急，外合阳气，风寒相搏，胃膈痰饮，偏正头疼，身拘倦：川芎一斤，天麻四两。上为末，炼蜜为丸，每两作十丸。每服一丸，细嚼，茶酒下，食后。（《宣明论方》川芎丸） ④治风热头痛：川芎一钱，茶叶二钱。水一钟，煎五分，食前热服。（《简便单方》） ⑤治妊娠腹中痛（胞阻）：芎劳二两，阿胶二两，甘草二两，艾叶三两，当归三两，芍药四两，干地黄六两。右七味以水五升，清酒三升合煮，取三升，去渣，纳胶令消尽，温服一升，日三服，不瘥，更作。（《金匮要略》胶艾汤） ⑥治妇人妊孕五七月，因事筑磕著胎，或子死腹中，恶露下，疼痛不止，口噤欲，用此药探之，若不损则痛止，子母俱安，若胎损立便逐下：当归六两（洗，去，切，焙干，秤）、川芎四两（洗）。上粗末，每服二钱，水一小盏，煎令泣泣干，酒一大盏，止一沸，去渣，温服，口噤灌之，如人行五、七里再进，不过三服便生。（《本事方》佛手歌） ⑦治产后血晕：当归一两，川芎五钱，荆芥穗（炒黑）二钱。水煎服。（《奇方类编》） ⑧治产后心腹痛：川芎（洗，锉）、桂心（不见火，锉）、木香（锉，怀干）、当归（去芦须，洗，锉，焙）、桃仁（去皮、尖并双仁，炒黄）各一两。上为细末。每服一钱，热酒调下，如不欲饮酒，即用水一盏，药末二钱，煎至七分，带热服。（《卫生家宝方》川芎散） ⑨治新产块痛：当归八钱，川芎三钱，桃仁十四粒（去皮，尖，研），黑姜五分，炙草五分．用黄酒、童便各半煎服。（《傅青主男女科》生化汤） ⑩治小儿脑热，好闭目，太阳痛或目赤肿：川芎、薄荷、朴硝各二钱，为末，以少许吹鼻中。（《全幼心鉴》）', tips='阴虚火旺，上盛下虚及气弱之人忌服。 1.恶黄连。 2.《品汇精要》：久服则走散真气。 3.《本草蒙筌》：恶黄芪、山茱、狼毒。畏硝石、滑石、黄连。反藜芦。 4.《本草经疏》：凡病人上盛下虚，虚火炎上，呕吐咳嗽，自汗、盗汗咽干口燥，发热作渴烦躁，法并忌之。 5.《本草从新》：气升痰喘不宜用。 6.《得配本草》：火剧中满，脾虚食少，火郁头痛皆禁用。' where id=1721; -- 川芎
update herbs set effect='①治细菌性痢疾，阿米巴痢疾，肠炎：穿心莲鲜叶十至十五片。水煎调蜜服。（《福建中草药》） ②治急性菌痢。胃肠炎：穿心莲三至五钱。水煎服，每日一剂，二次分服。（江西《草药手册》） ③治感冒发热头痛及热泻：一见喜研末。每次三分，日服三次，白汤送下。（《泉州本草》） ④治流行性感冒，肺炎：一见喜干叶研末。每次一钱，日三至四次。（《福建中草药》） ⑤治支气管炎、肺炎：穿心莲叶三钱。水煎服。（《江西草药》） ⑥治大叶性肺炎：一见喜六钱，梅叶冬青一两，麦门冬五钱，白茅根一两，金银花五钱。水煎，分二次服，每日一剂。（江西《草药手册》） ⑦治肺结核（轻症），发热：㈠一见喜干叶研末，蜜丸梧桐子大。每次十五至三十粒，日二至三次，开水下。（《福建中草药》） ㈡一见喜五钱，十大功劳叶五钱，丰城鸡血藤一两。水煎，分二次服，每日一剂，十五至三十天为一疗程。（江西《草药手册》） ⑧治百日咳：穿心莲叶三片。水泡，蜂蜜调服，日三次。 ⑨治胆囊炎：穿心莲五钱，六月雪二两，大青根一两半，黄栀子根一两，虎刺一两，阴行草一两。水煎服，如食欲不振，加野山楂果（炒）二两。 ⑩治高血压（充血型）：穿心莲叶五至七片。开水泡服，一日数次。（⑧方以下出《江西草药》） ⑾治口腔炎，扁桃体炎：一见喜干叶研末，一钱至一钱半。调蜜，开水送服。（《福建中草药》） ⑿治咽喉炎：穿心莲（鲜）三钱。嚼烂吞服。（《江西草药》） ⒀治急性阑尾炎：野菊花一两，一见喜五钱。水煎，每日二剂分服。（江西《草药手册》） ⒁治疖肿，蜂窝组织炎：三颗针五钱，一见喜五钱，金银花三钱，野菊花三钱，七叶一枝花二钱。水煎服。（江西《草药手册》） ⒂治鼻寞炎，中耳炎，结合膜炎，胃火牙痛：鲜一见喜全草三至五钱，水煎服；或捣汁滴耳。 ⒃治热淋：鲜一见喜叶十至十五片。捣烂，加蜜，开水冲服。 ⒄治汤火伤，一见喜干叶研末调茶油或鲜叶煎汤涂患处。 ⒅治毒蛇咬伤：㈠一见喜鲜叶捣烂调旱烟筒内的烟油外敷；另取鲜叶三至五钱，水煎服。（⒂方以下出《福建中草药》）㈡一见喜一两，七叶-枝花三钱，狭叶韩信草一两，白花蛇舌草一两。每日一至二剂，水煎服。（江西《草药手册》） ⒆治阴囊湿疹：一见喜粉三十克。甘油加至一百毫升，调匀涂患处。（江西《草药手册》）' where id=1722; -- 穿心莲
update herbs set taste='味苦；辛；性微寒。', channel='归肝；胆经。', effect='①治伤寒五、六日，中风，往来寒热，胸胁苦满，嘿嘿不欲食，心烦喜呕，或胸中烦而不呕，或渴，或腹中痛，或胁下痞鞕，或心下悸、小便不利，或不渴、身有微热，或咳者：柴胡半斤，黄芩三两，人参三两，半夏半升（洗），甘草（炙）、生姜各三两（切），大枣十二枚（擘）。上七味，以水一斗二升，煮取六升，去滓，再煎取三升，温服一升，日三服。（《伤寒论》小柴胡汤） ②治邪入经络，体瘦肌热，推陈致新；解利伤寒、时疾、中喝、伏暑：柴胡四两（洗，去苗），甘草一两（炙）。上细末。每服二钱，水一羔，同煎至八分，食后热服。（《本事方》柴胡散） ③治外感风寒，发热憨寒，头疼身痛；痎疟初起：柴胡一至三钱，防风一钱，陈皮一钱半，芍药二钱，甘草一钱，生姜三、五片。水一钟半，煎七、八分，热服。（《景岳全书》正柴胡饮） ④治肝气，左胁痛：柴胡、陈皮各-钱二分，赤芍、枳壳、醋炒香附各-钱，炙草五分。（《医医偶录》柴胡疏肝饮） ⑤治肝经郁火，内伤胁痛：柴胡、黄芩、山栀、青皮、白芍、枳壳。（《症因脉治》柴胡清肝饮） ⑥治血虚劳倦，五心烦热，肢体疼痛，头目昏重，心忪颊赤，口燥咽干，发热盗汗，减食嗜卧，及血热相搏，月水不调，脐腹胀痛，寒热如疟；又疗室女血弱阴虚，荣卫不和，痰嗽潮热，肌体羸瘦，渐成骨蒸：甘草半两（炙微赤）、当归（去苗，锉，微炒）、茯苓（去皮，白者）、白芍药、白术、柴胡（去苗）各一两。上为粗末。每服二钱，水一大盏，煨生姜一块切破，薄荷少许，同煎至七分，去渣热服，不拘时候。（《局方》逍遥散） ⑦治盗汗往来寒热：柴胡（去苗）、胡黄连等分，为末，炼蜜和膏，丸鸡头子大。每一、二丸，用酒少许化开，入水五分，重汤煮二、三十沸，放温服，无时。（《小儿卫生总微论方》柴胡黄连膏） ⑧治荣卫不顺，体热盗汗，筋骨疼痛，多困少力，饮食进退：柴胡二两，鳖甲二两，甘草、知母各一两，秦艽一两半。上五味杵为末。每服二钱，水八分，枣二枚，煎六分，热服。（《博济方》柴胡散） ⑨治黄疸：柴胡一两（去苗），甘草一分。上都细锉作一剂，以水一碗，白茅根一握，同煎至七分，绞去渣，任意时时服，一日尽。（《传家秘宝方》） ⑩治肝黄：柴胡一两（去苗），甘草半两（炙微亦，锉），决明子、车前子、羚羊角屑各半两。上药捣筛为散。每服三钱，以水一中盏，煎至五分，去滓，不计时候温服。（《圣惠方》柴胡散） ⑾治积热下痢：柴胡、黄芩等分。半酒半水，煎七分，浸冷，空心服之。（《济急仙方》）', tips='真阴亏损，肝阳上升者忌服。 恶皂荚。畏女菀、藜芦。 ②《医学入门》：元气下绝，阴火多汗者，误服必死。 ③《本草经疏》：病人虚而气升者忌之，呕吐及阴虚火炽炎上者，法所同忌。疟非少阳经者勿食。' where id=1723; -- 柴胡
update herbs set taste='辛苦，温。', channel='入肾、脾、胃经。', effect='①治胸膈痞塞，心腹胀满，喘促短气，干哕烦满，脚气上冲：香附（炒，去毛）四百两，沉香十八两半，缩砂仁四十八两，甘草（爁）一百二十两。上为细末。每服一钱，入盐少许，沸汤点服，空心食。（《局方》沉香降气丸） ②治阴虚肾气不归原：沉香磨汁数分，以麦门冬、怀熟地各三钱，茯苓、山药、山茱萸肉务二钱，牡丹皮、泽泻、广陈皮各一钱。水煎，和沉香汁服。（《本草汇言》） ③治脾肾久虚，水饮停积，上乘肺经，咳嗽短气，腹胁胀，小便不利：沉香一钱，乌药三钱，茯苓、陈皮、泽泻、香附子各半两，麝香半钱。上为细末，炼蜜和丸如梧子大。每服二、三十丸，熟水下。（《鸡峰普济方》沉香丸） ④治七情伤感，上气喘息，妨闷不食：人参、槟梅、沉香、天台乌药，上各浓磨，水和作七分盏，煎三、五沸，放温服。或下养正丹尤佳。（《济生方》四磨汤） ⑤治胸中痰热，积年痰火，无血者：半夏曲八两（用姜汁一小杯、竹沥一大盏制），黄连二两（姜汁炒），木香一两，沉香二两。为细末，甘草汤泛为丸。空心淡姜汤下二钱。（《张氏医通》沉香化痰丸） ⑥治伤寒虚痞，气逆呕吐：沉香（锉）一两，青橘皮、陈橘皮（并汤浸去白，焙）、胡椒、蘹香子（炒）、楝实（锉，炒）、荜澄茄（炒）各半两。上七味，粗捣筛。每服二钱匕，水半盏，酒半盏，入葱白一握，煎至半盏，去滓热服。（《圣济总录》沉香丸） ⑦治胃冷久呃：沉香、紫苏、白豆蔻各-钱。为末。每服五、七分，柿蒂汤下。（《活人心统》） ⑧治大肠气滞，虚闭不行：沉香磨汁八分，以当归、枳壳、杏仁泥、肉苁蓉各三钱，紫菀一两，水煎，和沉香汁服。（《方脉正宗》） ⑨治胞转不通，或过忍小便所致，当治其气则愈，非利药可通也：沉香、木香各二钱。为末。白汤空腹服之，以通为度。（《医垒元戎》）' where id=1724; -- 沉香
update herbs set effect='1．治小便不通：车前500克，水三升，煎取一升半，分三服（《肘后方》）；生车前捣取自然汁半钟，入蜜一匙调下。（《摄生众妙方》） 2．治尿血：车前捣绞，取汁五合，空腹服之。（《外台》）；车前、地骨皮、旱莲草各15克，汤炖服。（《闽东本草》） 3．治白带：车前根15克捣烂，用糯米淘米水兑服。（《湖南药物志》） 4．治热痢：车前叶捣绞取汁一盅，入蜜一合，同煎一、二沸，分温二服。（《圣惠方》） 5．治泄泻：车前20克，铁马鞭10克，共捣烂，冲凉水服。（《湖南药物志》） 6．治黄疸：车前25克，观音螺50克，加酒一杯炖服。（《闽东本草》） 7．治感冒：车前、陈皮各适量，水煎服。（内蒙古《中草药新医疗法资料选编》） 8．治衄血：车前叶生研，水解饮之。（《本草图经》） 9．治高血压：车前、鱼腥草各50克，水煎服。（《浙江民间常用草药》） 10．治目赤肿痛：车前自然汁，调朴硝末，卧时涂眼胞上，次早洗去。（《圣济总录》） 11．治火眼：车前根15克，青鱼草、生石膏各10克，水煎服。（《湖南药物志》） 12．治喉痹乳蛾：虾蟆衣、凤尾草。擂烂，入霜梅肉、煮酒各少许，再研绞汁，以鹅翎刷患处。（《养疴漫笔》） 13、治痄腮：车前65克，煎水服，温覆取汗。（《湖南药物志》） 14、治百日咳：车前15克，水煎服。（《湖南药物志》） 15．治痰嗽喘促，咳血：鲜车前100克（炖），加冬蜜25克或冰糖50克服。（《闽东本草》） 16．治惊风：鲜车前根、花野菊根各12.5克。水煎服。（《湖南药物志》） 17．治小儿痫病：鲜车前草250克绞汁，加冬蜜25克，开水冲服。（《闽东本草》） 18．治金疮血出不止：捣车前汁敷之。（《千金方》） 19．治疮疡溃烂：鲜车前叶，以银针密刺细孔，以米汤或开水泡软，整叶敷贴疮上，日换二至三次。有排脓生肌作用。（《福建民间草药》）' where id=1725; -- 车前草
update herbs set effect='①风湿性关节炎、类风湿性关节炎、坐骨神经痛：丁公藤制成注射液（每2毫升，相当原生药5克），肌肉注射，每日1～2次，每次2毫升，小儿酌减。' where id=1726; -- 丁公藤
update herbs set taste='味甘；性微寒。', channel='归脾、小肠经。', effect='①治肾脏炎，小便不利，全身浮肿：冬瓜皮六钱，西瓜皮六钱，白茅根六钱，玉蜀黍蕊四钱，赤豆三两。水煎，一日三回分服。（《现代实用中药》） ②治损伤腰痛：冬瓜皮烧研，酒服一钱。（《生生编》） ③治跌扑伤损：干冬瓜皮一两，真牛皮胶一两（锉）。入锅内炒存性，研末。每服五钱，好酒热服，仍饮酒一瓯，厚盖取微汗。（《摘元方》） ④治咳嗽：冬瓜皮五钱（要经霜者），蜂蜜少许。水煎服。（《滇南本草》） ⑤治巨大荨麻疹：冬瓜皮水煎，当茶喝。（江西赣州《草医草药简便验方汇编》）' where id=1727; -- 冬瓜皮
update herbs set taste='苦酸；寒；无毒。', channel='入肝、大肠经。', effect='①治便血：地榆四两，炙甘草三两。每末五钱，水二盏，入砂仁末一钱，煎盏半，分二服。（《沈氏尊生书》地榆甘草汤） ②治急性菌痢：水橄榄根研粉，成人每服三至六分，每天三次，儿童减半。（《全展选编·传染病》） ③治血痢不止：地榆二两，甘草（炙、锉）半两。上二味粗捣筛。每服五钱匕，以水一盏，煎取七分，去渣，温服，日二夜一。（《圣济总录》地榆汤） ④治久病肠风，痛痒不止；地榆五钱，苍术一两。水二钟，煎一钟，空心服，日一服。（《活法机要》） ⑤治烧烫伤：地榆根炒炭存性，磨粉，用麻油调成50％软膏，涂于创面，每日数次。（《单方验方调查资料选编》） ⑥治妇人漏下赤色不止，令人黄瘦虚渴：地榆二两（细锉），以醋一升，煮十余沸，去渣，食前稍热服一合。亦治呕血。（《圣惠方》） ⑦治湿疹：㈠地榆一两，加水两碗，煎成半碗，用纱布沾药液湿敷。㈡地榆面、煅石膏面各二十两，枯矾-两。研匀，加凡士林三十至四十两，调膏外敷。㈢地榆面十五两，密陀僧三十两。研匀，加凡士林三十至四十两，调膏外敷。（《全展选编·皮肤科》） ⑧治原发性血小板减少性紫瘢：生地榆、太子参各一两，或加怀牛膝一两，水煎服，连服二月。（内蒙古《中草药新医疗法资料选编》） ⑨治红白痢，禁口痢：白地榆二钱，炒乌梅五枚，山查一钱。水煎服。红痢红糖为引，白痢白糖为引。（《滇南本草》） ⑩治无名肿毒，疖肿，痈肿，深部脓肿：地榆500克，田基黄200克，研末，田七粉5～15克。调入700克凡士林中成膏，外敷患处。（广西《中草药新医疗法处方集》） ⑾治面疮赤肿焮痛：地榆八两（细锉），水一斗，煮至五升，去渣，适寒温洗之。（《小儿卫生总微方论》） ⑿治猘犬咬人：地榆根末，服方寸匕，日一、二，亦末敷疮上，生根捣敷佳。（《补缺肘后方》） ⒀治蛇毒：地榆根，捣绞取汁饮，兼以渍疮。（《补缺肘后方》）' where id=1728; -- 地榆
update herbs set taste='味苦；辛；性寒。', channel='归肺；肝；肾经。', effect='①治鼻出血：地胆头、猪肝各酌量。同煎服，连服三至四次。 ②治阳黄疸：地胆头连根叶洗净，鲜者四至六两。煮肉食，连服四、五天。 ③治单腹殿胀：苦地胆二两。煎水分早晚二次服，或和亦猪肉炖服。（①方以下出《岭南草药志》） ④治尿闭：地胆草五钱至一两。水煎服。（《福建中草药》） ⑤治脚气：苦地胆全草一至二两，豆腐二至四两。酌加开水炖服。（《福建民间草药》） ⑥治热淋：鲜地胆草三两，瘦猪肉四两，食盐少许。加水同煎，去渣，分四次服用。（《江西民间草药验方》） ⑦治扁桃体炎，咽喉炎：地苦胆二钱。泡入300毫升热开水中半小时，内服，每天一剂。亦可制成片剂含服。（广西《中草药新医疗法处方集》） ⑧治腋下生肿毒，散肿止痛，脓已成者亦安，亦治一切肿毒：天芥菜以盐醋同捣敷之。（《医林集要》） ⑨治痈肿：㈠鲜地胆草全草煎水，熏洗患处。㈡地胆草全草七钱，酒、水各半煎服。（《江西民间草药验方》） ⑩治指疔、乳痈：鲜地胆草全草适量，酌加甜酒酿糟同捣烂，敷于患处。（《江西民间草药验方》） ⑾治丝虫病淋巴管炎：地胆草一两。水煎服。（《福建中草药》） ⑿治蛇伤：天芥菜同金沸草入盐捣敷之。（《纲目》） ⒀治翼状胬肉：苦地胆十斤，醋二十斤，铜块一斤。先将铜烧红，立即放入醋中，取出烧红，再入醋，如此反复数十次，再将新鲜苦地胆放入醋中浸泡一个月，过滤，滴眼用（有刺激感不用特殊处理，半小时后恢复正常）。（广西《中草药新医疗法处方集》）' where id=1729; -- 苦地胆
update herbs set taste='甘咸，凉。', channel='脾；肾经。', effect='①治卒小便淋涩痛：大麦三两，以水二大盏，煎取一盏三分，去滓，入生姜汁半合，蜜半合，相和。食前分为三服服之。（《圣惠方》） ②治麦芒入目：煮大麦汁洗之。（孙思邈） ③治蠼螋尿疮：大麦研末调敷，日三上。（《伤寒类要》） ④治汤火灼伤：大麦炒黑，研末，油调搽之。（《纲目》）大麦面作稀糊。令咽之，既滑腻，容易下咽，以助胃气。', tips='①朱丹溪：大麦安装熟，人多炒食，此物有火，能生热病。（引自《纲目》）' where id=1730; -- 大麦
update herbs set taste='味甘，温。', effect='①治气滞呃逆，膈闷不舒：刀豆取老而绽者，每服二、三钱，开水下。（《医级》刀豆散） ②治肾虚腰痛：刀豆子二粒，包于猪腰子内，外裹叶，烧熟食。（《重庆草药》） ③治百日咳：刀豆子十粒（打碎），甘草一钱。加冰糖适量，水一杯半，煎至一杯，去渣，频服。（《江西中医药》（3）：21，1953） ④治鼻渊：老刀豆，文火焙干为末，酒服三钱。（《年希尧集验良方》） ⑤治小儿疝气：刀豆子研粉，每次一钱半，开水冲服。（《湖南药物志》）' where id=1731; -- 刀豆
update herbs set taste='味甘；性寒。', channel='入肺、肝、肾经.', effect='①治骨蒸肌热，解一切虚烦躁，生津液：地骨皮（洗，去心）、防风（去钗股）各一两，甘草（炙）一分。细末，每服二钱，水一盏，生姜三片，竹叶七片，煎服。（《本事方》地仙散） ②治热劳：地骨皮二两，柴胡（去苗）一两。上二味捣罗为散，每服二钱匕，用麦门冬（去心）煎汤调下。（《圣济总录》地骨皮散） ③治虚劳口中苦渴，骨节烦热或寒：枸杞根白皮（切）五升，麦门冬二升，小麦二升。上三味，以水二斗，煮麦熟，药成去滓，每服一升，日再。（《千金方》枸杞汤） ④治小儿肺盛，气急喘嗽：地骨皮、桑白皮（炒）各一两，甘草（炙）一钱。上锉散，入粳米一撮，水二小盏，煎七分，食前服。（《小儿药证直诀》泻白散） ⑤治吐、下血：枸杞根皮、子，为散，煎服。（《普济方》） ⑥治血淋：地骨皮，酒煎服。若新地骨皮加水捣汁，每盏入酒少许，空心温服更妙。（《经验广集》地骨酒） ⑦治消渴日夜饮水不止，小便利：地骨皮（锉）、土瓜根（锉）、栝楼根（锉）、芦根（锉）各一两半，麦门冬（去心，焙）二两，枣七枚（去核）。上六味锉如麻豆；每服四钱匕，水一盏，煎取八分，去滓温服。（《圣济总录》地骨皮饮） ⑧治消渴唇干口燥：枸杞根五升（锉皮），石膏一升，小麦三升。上三味切，以水煮，麦熟汤成，去滓，适寒温饮之。（《医心方》枸杞汤） ⑨治时行目暴肿痒痛：地骨皮（切）三斤。以水三斛，煮取三升，绞去滓，更内盐二两，煎取一升，洗目。（《圣济总录》地骨皮汤） ⑩治风虫牙痛：枸杞根白皮煎醋漱之。用水煎饮亦可。（《肘后方》） ⑾治膀胱移热于小肠，上为口糜，生疮溃烂，心胃壅热，水谷不下：柴胡、地骨皮各三钱。水煎服之。（《兰室秘藏》地骨皮汤） ⑿治耳聋，有脓水不止：地骨皮半两，五倍子一分。上二味捣为细末，每用少许，掺入耳中。（《圣济总录》地骨皮散） ⒀治瘭疽著手足、肩背，忽发累累如赤小豆，剥之汁出者：枸杞根、葵根叶。煮汁，煎如糖服之。（《千金方》） ⒁治肠风痔漏，下血不止：地骨皮、凤眼根皮各等分（同炒，微黄色）。捣为细末，每服三钱，空心温酒调服。忌油腻。（《经验方》地骨皮散） ⒂治痔疾：枸杞根、地龙（捣）。枸杞根旋取新者，刮去浮赤皮，只取第二重薄白皮，暴干捣罗为末，每秤一两，别入地龙末一钱，和匀，先以热虀汁洗煠患处，用药干掺，日可三次用。（《圣济总录》枸杞散） ⒃治气瘘疳疮，多年不愈：地骨皮不以多少，杵为细末，每用纸燃蘸絍疮口内，频用自然生肉，更用米饮调二钱，无时，日进三服。（《外科精义》应效散） ⒄治妇人阴肿或生疮：枸杞根煎水频洗。（《永类钤方》） ⒅肾经虚损，眼目昏花，或云翳遮睛。和枸杞子一斤，好酒润透。分作四份：一份用蜀椒一两炒，一份用小茴香一两炒，一份用芝麻一两炒，一份用川楝肉一两炒。炒后拣出枸杞，加熟地黄、白术、白茯苓各一两，共研为末，加炼蜜做成丸子，每天服适量。此方名四神丸。 ⒆壮筋骨，补精髓。用枸杞根、生地黄、甘菊花各一斤，捣碎，加水一石，煮取汁五斗，以汁炊糯米五斗，拌入细曲，照常法酿酒，待熟澄清，每日饮三碗。此方名地骨酒。 ⒇骨蒸烦熟（包括一切虚劳烦热及大病后烦热）。用地骨皮二两、防风一两，甘草（炙）半两，和匀后。每取五钱，加生姜五片，水煎服。此方名地仙散。 (21)肾虚腰痛。和枸杞根、杜仲、萆解和一斤，好酒三斗浸泡，蜜封土罐中再放锅内煮一天，常取饮服。 (22)赤眼肿痛。用地骨皮三斤，加水三斗，煮成三升，去渣，放进盐一两，再煮成二程式，频用洗眼和点眼。 (23)小便出血。用新地骨皮洗净，捣取自然汁。无汁则加水煎汁。每服一碗，加一点酒，饭前温服。 (24)风虫牙痛。用枸杞根白皮，煎醋含漱。 (25)口舌糜烂（膀胱移热于小肠，口舌生疮，心胃热，水谷不下）。用柴胡、地骨皮各三钱，水煎服。此方名地骨皮汤。 (26)男子下疳。先以浆水洗过。再搽地骨皮末，即可生肌止痛。 (27)妇女阴肿或生疮。用枸杞根煎水多洗。 (28)痈疽恶疮，脓血不止。有地骨皮不拘多少，洗净，刮去粗皮，取出细穰。以地骨皮煎汤洗，令脓血尽，以穰敷贴患处，很快见效。 (29)足趾鸡眼，作痛作疮。用地骨皮同红花研细敷涂。 (30)目涩有翳。用枸杞叶、车前叶各二两，捣出汁，以桑叶裹悬阴地一夜。取汁点眼，不过三、五次，即见效。 (31)五劳七伤，房事衰弱。用枸杞叶半斤，切细，加粳米二合，豉汁适量，一起煮成粥。每日食用，有效。 (32)治疗高血压病 每日用鲜枸杞根皮或全根2两（干品1两），水煎2次分服，连服30天为一疗程。观察1～3期患者36例，显效（按1964年兰州心血管会议拟订标准）20例，有效5例，无效11例。其中I期3例全部有效；Ⅲ期疗效最低，有效率62％。疗效出现时间最快4小时，最慢7天。全部病例自觉症状均有不同程度的改善。无体位性低血压及其它副作用。 (33)治疗青年扁平疣、掌跖疣、泛发性湿疹 地骨皮制成10％注射液，每次用2～3毫升，加自血2毫升，肌肉注射，每周2次，10次为一疗程。如未痊愈亦可继续一疗程。曾治疗青年扁平疣7例，6例痊愈，1例好转，皮疹大部消失；泛发性湿疹12例，痊愈9例，好转2例，无效1例。有的经2～4次治疗即有明显好转，5～6次即愈。个别注射后不久感觉轻度头痛及面部潮红。 (34)治疗牙髓炎疼痛 取地骨皮1两加水500毫升，煎至50毫升，过滤后以小棉球蘸药液填入已清洁之窝洞内即可。经治11例，均有明显止痛效果。有的用药后1分钟即止痛。 (35)治疗疟疾 取鲜地骨皮1两，茶叶1钱，水煎后于发作前2～3小时顿服。试用于150例患者，其中145例均控制发作，有的服1剂即见效。 (36)泻白散（《小儿药证直诀》）主治肺热咳喘证。地骨皮15g，桑白皮15g甘草3g。上药锉散，入粳米一撮，水二小盏，煎七分，食前服。方中地骨皮甘寒入肺，可助君药泻肺中伏火，且有养阴之功，君臣相合，清泻肺火，以复肺气之肃降。 (37)鲜品焙黄研末，香油调敷，治毛囊炎。 (38)单味用醋煎，漱口，治风虫牙痛。' where id=1732; -- 地骨皮
update herbs set effect='①治伤寒六、七日热极，心下烦闷，狂言，欲起走：大蚓一升破去(土)，以人溺煮，令熟，去滓服之。直生饺汁及水煎之，并善。(《补缺肘后方》) ②治风头痛及产后头痛。地龙（去土，炒）、半夏（生姜汁捣作饼，焙令干，再捣为末）、赤茯苓（去黑皮）各15g。上3味，捣为散，每服1g，生姜、荆芥汤调下。方中地龙与诸药配伍有清热熄风的功效。（《圣济总录》地龙散） ③治小儿急慢惊风：白颈蚯蚓，不拘多少，去泥焙干，为末，加朱砂等分，糊为丸，金箔为衣，如绿豆大。每服一丸，白汤下。(《摄生众妙方》) ④治小儿慢惊风，心神闷乱，烦懊不安，筋脉拘急，胃虚虫动，反折啼叫：乳香(研)半钱，胡粉一钱。上二味，合研匀细，用白颈蚯蚓生捏去土，烂研和就为丸，如麻子大。每服七丸至十丸，煎葱白汤下，更量儿大小加减。(《圣济总录》乳香丸) ⑤治抽筋：地龙一条，胡黄连一钱。水煎，日服三次。(《吉林中草药》)' where id=1733; -- 地龙
update herbs set taste='味甘；微苦；性凉。', channel='入肝、脾经。', effect='①治心热吐血、口干：刺蓟叶及根，捣，绞取汁，每服一小盏，频服。（《圣惠方》） ②治吐血衄血，崩中下血：大蓟一握。捣，绞取汁，服半升。（《本草汇言》） ③治肺热咳血：大蓟鲜根一两。洗净后杵碎，酌加冰糖半两，和水煎成半碗，温服，日服两次。（《福建民间草药》） ④治热结血淋：大蓟鲜根一至三两。洗净捣碎，酌冲开水炖一小时，饭前服，日服三次。（《福建民间草药》） ⑤治妇人红崩下血，白带不止：大蓟五钱，土艾叶三钱，白鸡冠花子二钱，木耳二钱，炒黄柏五钱（如白带，不用黄柏）。引水酒煨服。（《滇南本草》） ⑥治肠痈、内疽诸证：大蓟根叶、地榆、牛膝、金银花。俱生捣汁，和热酒服。如无生鲜者，以干叶煎饮亦可。（《本草汇言》） ⑦治肺痈：鲜大蓟四两。煎汤，早晚饭后服。（《闽东本草》） ⑧治疔疖疮疡，灼热赤肿：大蓟鲜根和冬蜜捣匀贴患处，日换两次。（《福建民间草药》） ⑨治跌扑损伤，瘀血作痛：大蓟汁，和热酒饮。（《本草汇言》） ⑩治结核于项左右，或栗子疮红肿溃烂出脓久不收口者：独根大蓟，不拘多少，或煮水牛肉，或猪肉，或单用，煨点水酒服。外用新鲜大蓟捣烂，入发灰、儿茶、血竭同拌，敷疮口，生肌。（《滇南本草》） ⑾治汤火烫伤：大蓟新鲜根，以冷开水洗净后捣烂，包麻布炖热绞汁涂抹，日二、三次。（《福建民间草药》） ⑿治妇女干血痨或肝痨，恶寒发热，头疼，形体消瘦，精神短少：新鲜大蓟二两，黄牛肉四两。共入罐内煮烂，天明吃毕后复熟睡。忌盐。（《滇南本草》） ⒀治漆疮：大蓟鲜根一握。洗净，加些桐油捣烂，用麻布包炖热绞汁涂抹，日三、四次。（《福建民间草药》） ⒁治副鼻窦炎：鲜大蓟根三两，鸡蛋二至三个。二味同煮，吃蛋喝汤。忌吃辛辣等刺激性食物。（《全展选编·五官科》） ⒂治带状疱疹：大蓟、小蓟、鲜牛奶各适量。将大、小蓟放在鲜牛奶中泡软后，捣成膏，外敷。（内蒙古《中草药新医疗法资料选编》）' where id=1734; -- 大蓟
update herbs set taste='味辛；微苦；性平。', effect='消肿止痛，接骨，并治风湿痹痛：大驳骨二两，泽兰一两，透骨消一两，双飞蝴蝶五钱，小驳骨二两，肉郎伞三两，鸡骨香五钱。共捣烂，酒炒热外敷。（《广西中药志》）' where id=1735; -- 大驳骨
update herbs set effect='1.治远年风赤眼肿痛 青盐、硇砂、石胆各一分。上药用醋浆水一小盏，于瓷器中浸，日中浸之，候其药着于瓷器四畔，干刮取如粟大，夜卧时着两眦，不过三四度。(《圣惠方》) 2.治风眼烂弦 戎盐化水点之。(《普济方》) 3.治肾脏虚冷，肝膈浮热上冲，两目生翳，黑花久不愈 青盐一两(明净者生研)，苍术一两(米泔浸)，木贼一两(小便浸)。上为细末，空心熟水调下一钱，如大不见物者不过十服，小可只二三服。(《古今医统》青盐煎) 4.治风热牙痛 青盐一斤，槐枝半斤。小四碗，煎汁二碗，煮盐至干，炒研，日用揩牙。(《唐瑶经验方》) 5.治肾虚齿痛 戎盐一分，地骨皮一两，细辛半两，生地黄(切，焙)一两。上四味粗捣筛。每服五钱匕，水一盏，煎十余沸，去滓热煠，日三。(《圣济总录》戎盐汤) 6.治咽喉疼痛，水谷不下 青盐、白矾、硇砂各等分。上为末，吹患处，有痰吐出立效。(《口齿类要》破棺丹) 7.治舌肿满口 青盐放铁器上烧红为末，掺之立效。(《奇验喉证明辨》) 8.治浸淫疮 戎盐二分，大黄四分，(艹闾)茹一分。上三味捣散，以酒和敷疮上，日三。(《古今录验方》戎盐散) 9.治痔疮漏疮 白矾四两，青盐四两，为末，猪尿脬一个，盛之，阴干。每服五钱，空心温水下。(《赵氏经验方》) 10.治腰疼痛，下脓水 石盐(一方作食盐)、干姜、杏仁(去尖)、酱瓣各等分。上为末，以锦裹，导之六七过，下脓水，腰下疼痛瘥止(一方无酱瓣)。(《普济方》) 11.治小便不利 茯苓半斤，白术二两，戎盐弹丸大一枚。上三味，以水五升，煮取三升，分温再服。(《金匮要略》茯苓戎盐汤) 12.治遗尿 戎盐三分，甘草半两(炙微赤，锉)，蒲黄一两，白矾三分(烧令汁尽)，龙骨一两，鹿角胶二两(捣碎，炒令黄燥)。上药捣细罗为散。每于食前，煎枣汤调下二钱。(《圣惠方》戎盐散) 13.治干霍乱 炒盐一钱，并河水各半盏，调饮，效。(《良方集腋》) 14.治小儿赤痢 青盐捣汁，每服半盏。(《丹溪治法心要》) 15.治中砒毒，烦燥，心腹疼痛，头旋，欲吐不吐，面青黑，四肢冷 青盐一握，细研，以井花水调下一碗灌之。(《古今医统》)。' where id=1736; -- 大青盐
update herbs set taste='酸辛，寒，有毒。', channel='入肝、胆经。', effect='①治缠喉风、急喉痹：鸭嘴胆矾二钱半，白僵蚕（炒、去丝嘴）半两。上为细末。每服少许，以竹管吹入喉中。（《济生方》二圣散） ②治口疮、喉闭、乳蛾：胆矾一钱，熊胆一钱，广木香三分。通为细末，以木鳖子一个，去壳，磨井水，以鹅翎蘸药敷之。（《摄生众妙方》） ③治初中风瘫缓，一日内：细研胆矾如面。每使一字许，用温醋汤下，立吐出涎。（《谭氏小儿方》） ④治牙疳：胡黄连五分，胆矾、儿茶各五厘。为末敷。（《沈氏尊生书》胆矾散） ⑤治走马牙疳：北枣一枚去核，入鸭嘴胆矾，纸包炼赤，出火毒，研末敷之。（《简便单方》） ⑥治口舌生疮：胆矾一分，干蟾一分（炙）。共研为末。每取小豆大，掺在疮上，良久，用新汲水五升漱口，水尽为度。（《圣惠方》） ⑦治小儿鼻疳蚀烂：胆矾烧烟尽，研末掺之。（《濒湖集简方》） ⑧治风眼赤烂：胆矾三钱。烧研，泡汤日洗。（《明目经验方》） ⑨治痔疮热肿：鸭嘴青胆矾（煅、研），蜜水调敷。（《仁斋直指方》） ⑩治肿毒不破：胆矾、雀屎各少许，点之。（《仁斋直指方》） ⑾治甲疽胬肉疼痛，脓血不止：石胆半两，煅过细研，敷疮上，日二、三度。（《圣济总录》石胆散） ⑿治风犬咬毒：胆矾末敷之。（《济急仙方》） ⒀治百虫入耳：胆矾末和醋灌之。（《千金方》） ⒁麝香矾雄散（《杨氏家藏方》）治大人小儿，牙齿动摇，龈腭宣露，骨槽风露，宣蚀溃烂，不能入食者：胆矾、雄黄、麝香（另研）、龙骨各3g。同研令极细。每用一字，以鹅毛蘸药，扫患处，每日1-2次；若小儿走马疳，先泡青盐汤洗净，后用新棉，拭干掺药。方中胆矾外用解毒，收涩，为君药。 ⒂含化丸（《外科正宗》）治梅核气：胆矾、硼砂、明矾、牙皂、雄黄各3g。为末，红枣煮烂，取肉为丸，芡实大。空心含化1丸。方中胆矾内服涌吐风痰，为君药。 ⒃吹喉散（《增补万病回春》）治咽喉肿痛，及喉舌垂下肿痛：胆矾、白矾、朴硝、冰片、山豆根、朱砂。先将鸡盹内皮烘燥，与上药为细末，吹喉。方中胆矾外用解毒，收涩，为君药。', tips='体虚者忌服。 畏牡桂，菌桂、芫花、辛夷、白薇。 ②《药性论》：陆英为使。' where id=1737; -- 胆矾
update herbs set taste='辛，平。', effect='①治脏毒赤白：地锦草采得后，洗，暴干，为末，米饮服一钱。（《经验方》） ②治细菌性痢疾：地锦草一两，铁苋菜一两，凤尾草一两。水煎服。（《单方验方调查资料选编》） ③治血痢不止：地锦草晒研，每服二钱，空心米饮下。（《乾坤生意》） ④治胃肠炎：鲜地锦草一至二两。水煎服。 ⑤治感冒咳嗽：鲜地锦草一两。水煎服。 ⑥治咳血、吐血、便血、崩漏：鲜地锦草一两。水煎或调蜂蜜服。（④方以下出《福建中草药》） ⑦治小便血淋：血风草，井水擂服。（《刘长春经验方》） ⑧治妇女血崩：草血竭嫩者蒸熟，以油、盐，姜腌食之，饮酒一、二杯送下，或阴干为末，姜、酒调服一、二钱。（《世医得效方》） ⑨治功能性子宫出血：地锦草二斤。水煎去渣熬膏。每日二次，每服一钱半，白酒送服。（内蒙古《中草药新医疗法资料选编》） ⑩治金疮出血不止：血见愁草研烂涂之。（《世医得效方》） ⑾治牙齿出血：鲜地锦草，洗净，煎汤漱口。（《泉州本草》） ⑿治湿热黄疸：地锦全草五、六钱。水煎服。（《江西民间草药》） ⒀治脾劳黄疸：草血竭、羊膻草、桔梗、苍术各一两，甘草五钱。为末，先以陈醋二碗入锅，下皂矾四两，煎熬良久，下药末，再入白面，不拘多少，和成一块，丸如小豆大，每服三、五十丸，空腹醋汤下，一日二服。（《乾坤生意秘韫》如圣丸） ⒁治奶汁不通：地锦草七钱。用公猪前蹄一只炖汤，以汤煎药，去渣，对甜酒二两，温服。（《江西民间草药》） ⒂治小儿疳积：地锦全草二、三钱。同鸡肝一具或猪肝三两蒸熟，食肝及汤。（《江西民间草药》） ⒃治项虎（对口疮）：鲜地锦草加醋少许，捣烂外敷。（《福建中草药，） ⒄治痈疮疔毒肿痛：鲜地锦草，洗净，和酸饭粒、食盐少许敷患处。（《泉州本草》） ⒅治风疮疥癣：血见愁草同满江红草捣末敷。（《乾坤生意秘韫》） ⒆治臁疮烂疮：斑鸠窝为末外搽。（《贵阳民间药草》） ⒇治缠腰蛇（带状疱疹）：鲜地锦草捣烂。加醋搅匀，取汁涂患处。（《福建中草药》） （21）治咽喉发炎肿痛：鲜地锦草五钱，咸酸甜草五钱。捣烂绞汁，调蜜泡服。日服三次。（《泉州本草》） （22）治火眼：斑鸠窝熬水洗，或蒸猪肝食。（《贵阳民间药草》） （23）治跌打肿痛：鲜地锦草适量，同酒糟捣匀，略加面粉外敷。（《湖南药物志》） （24）治蛇咬伤：鲜地锦草捣敷。（《湖南药物志》） （25赤白痢。用地锦草洗净、晒干，研为末，米汤送服一钱。 （26）妇女血崩。用嫩地锦草蒸熟，加油、盐、姜调食，并喝一、二杯送下。又言：地锦草阴干，研为末，姜、酒调服一、二钱，一服即可止崩。 （27）小便血淋。用地锦草加水捣服。 （28）刀伤出血不止。用地锦草捣烂涂上。 （29）风疮癣疥。用血见愁草同满江红草一起捣成末，敷患处。 （30）趾间鸡眼。先割破，令出血，用地锦草捣烂敷上，甚效。 （31）黄疸。用地锦草、羊 草、桔梗、苍术各一两，甘草五钱，共研为末；另以陕西省醋二碗与皂矾四两，同熬匀后，将近药末投入，再加白面适量和成丸子，如小豆大。每服三十至五十丸，空心服，醋汤送下。一天服二次。', tips='清热解毒；利湿退黄；活血止血。主痢疾；泄泻；黄疸；咳血；吐血；尿血；便血；崩漏；乳汁不下；跌打肿痛及热毒疮疡。 ①《别录》：主心气，女子阴疝血结。 ②《嘉祐本草》：主通流血脉，亦可用治气。 ③《品汇精要》：主调气和血。 ④《纲目》：主痈肿恶疮，金刃扑损出血，血痢，下血，崩中，能散血止血，利小便。 ⑤《民间常用草药汇编》：治胃部痞满疼痛，冷骨风，臭痰，痔疮及下乳。 ⑥《浙江民间草药》：健胃止泻，治小儿疳积。 ⑦《上海常用中草药》：止血，利尿，健胃，活血解毒。治黄疸，痢疾，腹泻，尿路感染，便血，尿血，子宫出血，痔疮出血，跌打肿痛，女人乳汁不通，蛇咬伤，头疮，皮肤疮毒。 ⑧《福建中草药》：清热凉血，消肿解毒。' where id=1738; -- 地锦草
update herbs set alias='白瓜、水芝（（本经）），蔬秬，白冬瓜，地芝，濮瓜（孟诜），蔬苽，东瓜，枕瓜。', taste='味甘；淡；性微寒。', channel='入肺、大小肠、膀胱经。', effect='①治水气浮肿喘满：大冬瓜一枚，先于头边切一盖子，取出中间瓤不用，赤小豆（水淘净），填满冬瓜中，再用盖子合了，用竹签签定，以麻线系，纸筋黄泥通身固济，窨干，用糯谷破取糠片两大箩，埋冬瓜在内，以火著糠内煨之，侯火尽取出，去泥，刮冬瓜令净，薄切作片子，并豆一处焙干。上为细末，水煮面糊为丸，如梧桐子大。每服五十丸，煎冬瓜子汤送下，不拘时候，小溲利为验，（《杨氏家藏方》冬瓜丸） ②治消渴：冬瓜一枚，削去皮，埋在湿地中，一月将出，破开，取清汁饮之。（《圣济总录》） ③治消渴能饮水，小便甜，有如脂麸片，日夜六、七十起：冬瓜一枚，黄连十两。上截瓜头去瓤，入黄连末.火中煨之，侯黄连熟，布绞取汁。一服-大盏，日再服，但服两、三枚瓜，以瘥为度。一方云，以瓜汁和黄连末，和丸如梧子大。以瓜汁空肚下三十丸，日再服，不差，增丸数。忌猪肉、冷水。（《近效方》） ④治小儿生-个月至五月，乍寒乍热渴者：绞冬瓜汁服之。（《千金方》） ⑤治小儿渴利：单捣冬瓜汁饮之。（《千金方》） ⑥治伤寒后痢，日久津液枯竭，四肢浮肿，口干：冬瓜一枚，黄土泥厚裹五寸，煨令烂熟，去土绞汁服之。（《古今录验方》） ⑦治发背砍死者：冬瓜截去头，合疮上，瓜当烂，截去更合之。（《补缺肘后方》） ⑧治痔疼痛：冬瓜汤洗。（《经验方》） ⑨治夏月生痱子：冬瓜切片，捣烂涂之。（《千金方》） ⑩治马汗入疮：干冬瓜烧研，洗净敷之。（《纲目》） ⑾治食鱼中毒：饮冬瓜汁。（《小品方》）' where id=1739; -- 冬瓜
update herbs set taste='酸甘，温。', effect='①治白带方(《浙江民间常用草药》)：杜鹃花，猪脚爪，同煮。 ②治鼻衄方(《贵州草药》)：映山红花，当归，水煎服。 ③治月家病，经闭干瘦：映山红二两。水煎服。 ④治跌打疼痛：映山红子（研末）五分。用酒吞报。 ⑤治流鼻血：映山红花（生的）五钱至一两。水煎服。（①方以下出《贵州草药》） ⑥治白带：杜鹃花（用白花）五钱，和猪脚爪适量同煮，吃汤和肉。（《浙江民间常用草药》）', tips='和血，调经，祛风湿。治月经不调，闭经，崩漏，跌打损伤，风湿痛，吐血、衄血。 ①《分类草药性》：治吐血，崩症，去风寒，和血。 ②《贵州民间方药集》：治月经不调，止红崩；浸酒内服，可治风湿。果实止伤痛。 ③《四川中药志》：治腹痛下痢，痔出血及内伤咳嗽。' where id=1740; -- 杜鹃花
update herbs set taste='甘淡，寒。', channel='入心、肺、小肠经。', effect='1.治五淋癃闭：灯心草一两，麦门冬、甘草各五钱。浓煎饮。（《方脉正宗》） 2.治水肿：灯心草四两。水煎服。（《方脉正宗》） 3.通利水道：灯心十斤（以米粉浆染，晒干，研末，入水澄之，浮者为灯心，取出，又晒干，入药用二两五钱，而沉者为米粉，不用矣），赤白茯苓（去皮，兼用茯神去木）五两，滑石（水飞过）五两，猪苓（去皮）二两，泽泻（去须）三两，人参一斤（去芦，切片，煮浓汤去渣，漉净，炼汤成膏如糖饧，用以和膏）。上灯心等五味各为细末，以人参膏和成丸如龙眼大，朱砂为衣，贴金箔。每用一丸，任病换引。（《韩氏医通》天一丸） 4.治热淋：鲜灯心草、车前草、凤尾草各一两。淘米水煎服。（《河南中草药手册》） 5.治膀胱炎、尿道炎、肾炎水肿：鲜灯心草一至二两，鲜车前二两，薏苡仁一两，海金沙一两。水煎服。（《河南��草药手册》） 6.治肾炎水肿：鲜灯心草一至二两，鲜车前草一两，鲜地胆草一两。水煎服。（《福建中草药》） 7.治失眠、心烦：灯心草六钱。煎汤代茶常服。（《现代实用中药》） 8.治小儿热惊：灯心草一至二钱，车前草三株。酌冲开水炖服。（《福建民间草药》） 9.治小儿心烦夜啼：灯心草五钱。煎二次，分二次服。（江西《中草药学》） 10.治黄疸：㈠灯心草、天胡荽各一两。水煎，加甜酒少许调服。㈡灯心草五钱，鲜枸杞根一两，阴行草五钱。水煎，糖调服。（江西《中草药学》） 11.治湿热黄疸：鲜灯心草一至二两，白英（鲜）一至二两。水煎服。（《福建中草药》） 12.治急性咽炎，咽部生颗粒或舌炎，口疮：灯心草一钱，麦门冬三钱，水煎服；亦可用灯心炭一钱，加冰片一分，同研，吹喉。（《河北中药手册》） 13.治走马喉痹：壁蟢窠（烧灰）、灯心（烧灰）、枯矾各等分。为细末吹之。（《村居救急方》） 14.治乳蛾：灯草（以咸卤浸透，入鸡子壳中封固，煅存性，研细）加粱上尘及青鱼胆、明矾、铜青，点咽喉。虚脱人及中寒人勿用。（《本草汇》） 15.治鼻衄不止：灯心（焙）一两。捣罗为散，入丹砂一钱，研。每服二钱匕，米饮调下。（《圣济总录》灯心散） 16.治破伤：灯心烂嚼，和唾贴之，用帛裹。（《胜金方》） 17.治乳痈乳吹：水灯心一两。酒水各半煎服。（《中医药实验研究》） 18.治阴疳：灯心草（烧灰），入轻粉、麝香（共研末涂敷）。（《纲目》） 19.伤口流血。用灯心草嚼烂敷患处。 20.鼻血不止。用灯心草一两为末，加丹砂一钱。每服二钱，米汤送下。 21.喉痹。用灯心草一把，瓦上烧存性，加炒盐一匙，每取少许吹入喉中。又方：用灯心草灰二钱，加硼砂粉一钱，和匀，吹喉。又方：用灯心草、箬叶烧灰，等分和匀，吹喉。又方：用灯心草、红花烧灰，酒送服一钱。 22.失眠。用灯心草煎水代茶喝。 23.湿热黄疸。用灯草根四两，加酒、水各半，煮半日，露一夜，温服。 24.灯心竹叶汤(《证治准绳》）治心热烦躁，失眠不寐，小儿夜啼：朱灯心草3，淡竹叶9g，水煎服。方中灯心草清心除烦，为君药。 25.通窍剂：散剂。主要成分：灯心草炭，荆芥炭，煅硼砂，细辛，闹羊花，猪牙皂，蟾酥，冰片，牛黄，麝香。有通关开窍，排秽避瘟的功能。用于受暑眩晕，头痛鼻塞。取少许吸鼻取嚏。方中灯心草清热，为君药。 26.验方：治急慢性咽炎、口腔炎。灯心草、麦冬，泡茶饮用。或灯心炭3g，冰片0.3g，共研细粉，吹入患处。方中灯心草清热解毒，为君药。 27.宣气散(《丹溪心法》)，主治癃闭急痛。 28.天一丸(《韩氏医通》)，具有通利水道之功。3.灯心散(《圣济总录》)，主治鼻衄不止。' where id=1741; -- 灯心草
update herbs set taste='苦，平。', effect='①治肠痈，生于小肚角，微肿而小腹隐痛不止者是，若毒气不散，渐大，内攻而溃，则成大患：红藤一两许，以好酒二碗，煎一碗，午前一服，醉，卧之。午后用紫花地丁一两许，亦如前煎服，服后痛必渐止为效。然后以当归五钱，蝉退、僵蚕各二钱，天龙、大黄各一钱，石礍蚆五钱（此草药），老蜘蛛二个（捉放新瓦上，以酒钟盖定，外用火煅干存性），共为末，每空心用酒调送一钱许，日逐渐服自消。（《景岳全书》） ②治急、慢性阑尾炎，阑尾脓肿：红藤二两，紫花地丁一两。水煎服。（《浙江民间常用草药》） ③治风湿筋骨疼痛，经闭腰痛：大血藤六钱至一两。水煎服。（《湖南农村常用中草药手册》） ④治风湿腰腿痛：虹藤、牛膝各三钱，青皮、长春七、朱砂七各二钱，水煎服。（《陕西中草药》） ⑤治肠胃炎腹痛：大血藤三至五钱，水煎服。（《浙江民间常用草药》） ⑥治钩虫病：大血藤、钩藤、喇叭花、凤叉蕨各三钱，水煎服。（《湖南农村常用中草药手册》） ⑦治小儿疳积，蛔虫或蛲虫症：红藤五钱，或配红石耳五钱，共研细末，拌白糖食。（《陕西中草药》） ⑧治小儿蛔虫腹痛：红藤根研粉，每次吞服一钱半。（《浙江中医杂志》6：1959） ⑨治跌打损伤：大血藤，骨碎补各适量共捣烂，敷伤处。（《湖南农村常用中草药手册》） ⑩治血虚经闭：大血藤五钱，益母草三钱，叶下红四钱，香附二钱。水煎，配红砂糖适量调服。（《闽东本草》） ⑾治血崩：红藤、仙鹤草、茅根各五钱。水煎服。（《湖南药物志》）' where id=1742; -- 大血藤
update herbs set taste='辛，温。', channel='入脾、胃、肺经。', effect='①治心腹冷痛：蒜，醋浸至二、三年，食至数颗。（《濒湖集简方》） ②治夜啼腹痛，面青，冷证也：大蒜一枚（煨、研、日干），乳香五分。捣，丸芥子大。每服七丸，乳汁下。（《世医褥效方》） ③治水气肿满：大蒜、田螺、车前子等分。熬膏，摊贴脐中，水从便漩而下。（《稗史》） ④治臌胀：大蒜，入自死黑鱼肚内，湿纸包，火内煨熟，同食之。忌用椒、盐，葱，酱。多食自愈。（姚可成《食物本草》） ⑤治脚转筋：急将大蒜磨脚心，令遍、热。（《摄生众妙方》） ⑥治寒疟，手足鼓颤，心寒面青：独蒜一枚，黄丹半两。上药相和，同捣一千杵，丸如黑豆大。未发时以茶下二丸。（《昔济方》蒜丸） ⑦治疟病：独头蒜，于白炭上烧之，末，服方寸匕。（《补缺肘后方》） ⑧治食蟹中毒：干蒜煮汁饮之。（《姚僧坦集验方》） ⑨治脏毒：鹰爪黄连末，用独头蒜一颗，煨香烂熟，研和入臼治丸，如梧子大。每服三，四十丸，陈米饮下。（《本事方》蒜连丸） ⑩治鼻衄不止，服药不应：蒜一枚，去皮，研如泥，作钱大饼子，厚一豆许，左鼻血出，贴左足心，右鼻血出，贴右足心，两鼻俱出，俱贴之。（《简要济众方》） ⑾治鼻衄，咯血，呕血，尿血。独头蒜两个，捣成泥状，分成两份。一份用八层麻纸包裹，置于百会穴。另一份用七层麻纸包裹，置于涌泉穴，然后在包裹之药上用热铁烙加温。（内蒙古《中草药新医疗法资料选编》） ⑿治肺结核：新鲜大蒜，每次一至二头，捣碎后以深呼吸吸其挥发气，每日二次，每次一至三小时。（辽宁《中草药新医疗法展览会资料选编》） ⒀治小儿百日咳：大蒜五钱，红糖二钱，生姜少许。水煎服，每日数次，用量视年龄大小酌用。（《贵州中医验方》） ⒁治脑漏鼻渊：大蒜切片，贴足心，取效止。（《摘元方》） ⒂治金疮中风，角弓反张：大蒜一升，破去心，无灰酒四升，煮蒜令极烂，并滓服一大升以来，须臾汗如雨出，则瘥。（孟诜《必效方》） ⒃治小儿脐风：独头蒜，切片，安脐上，以艾灸之，口中有蒜气即止。（《简易方论》） ⒄治背疽漫肿无头者（用湿纸贴肿处，但一点先干处，乃是疮头）：用大蒜十颗，淡豉半合，乳香钱许。研烂，置疮上，铺艾灸之，痛者灸令不痛，不痛者灸之令痛。（《外科精要》） ⒅治一切肿毒：独头蒜三、四颗，捣烂，入麻油和研，厚贴肿处，干再易之。（《食物本草会纂》） ⒆治神经性皮炎：蒜头适量，捣烂，以纱布包裹，外敷患处。另用艾条隔蒜灸患处到疼痛为止，隔日一次。（《单方验方调查资料选编》） ⒇治妇人阴肿作痒：蒜汤洗之，效乃止。（《永类钤方》） （21）治蜈蚣咬人，痛不止：独头蒜，摩螫处，痛止。（《梅师集验方》）' where id=1743; -- 大蒜
update herbs set alias='干枣、美枣，良枣，红枣。', taste='甘，温。', channel='入脾、胃经。', effect='①治脾胃湿寒，饮食减少，长作泄泻，完谷不化：白术四两，干姜二两。鸡内金二两，熟枣肉半斤。上药四味，白术、鸡内金皆用生者，每味各自轧细、焙熟，再将干姜轧细，共和枣肉，同捣如泥，作小饼，木炭火上炙干，空心时，当点心，细嚼咽之。（《医学衷中参西录》益脾饼） ②治反胃吐食：大枣一枚（去核），班蝥一枚（去头翅）入内喂热，去蝥，空心食之，白汤下。（《纲目》） ③补气：大南枣十枚，蒸软去核，配人参一钱，布包，藏饭锅内蒸烂，捣匀为丸，如弹子大，收贮用之。（《醒园录》枣参丸） ④治中风惊恐虚悸，四肢沉重：大枣七枚（去核），青粱粟米二合。上二味以水三升半，先煮枣取一升半，去滓，投米煮粥食之。（《圣济总录》补益大枣粥） ⑤治妇人脏躁，喜悲伤，欲哭，数欠伸：大枣十枚，甘草三两，小麦一升。上三味，以水六升，煮取三升，温分三服。（《金匮要略》甘麦大枣汤） ⑥治咳：杏仁一百二十枚（去皮尖，熬），豉一百枚（熬令干），干枣四十枚（去核）。上三味台捣如泥，丸如杏核，含咽令尽。日七、八度，尽，更作。（盂诜《必效方》） ⑦治悬饮：芫花（熬）、甘遂、大戟各等分。上三味捣筛，以水一升五合，先煮肥大枣十枚，取八合，去渣，纳药末，强人服一钱匕，羸人服半钱匕，平日温服之，不下者，明日更加半钱。得快利之后，糜粥自养。（《金匮要略》十枣汤） ⑧治虚劳烦闷不得眠：大枣二十枚，葱白七茎。上二味，以水三升，煮一升，去滓顿服。（《千金方》） ⑨治肺疽吐血并妄行：红枣（和核烧存性）、百药煎（煅）各等分。为细末，每服二钱，米汤调下。（《三因方》二灰散） ⑩治卒急心痛：乌梅一个，枣二个，杏仁七个。一处捣，男用酒、女用醋送下。（《海上方》） ⑾治非血小板减少性紫瘢：红枣，每天吃三次，每次10只，至紫瘢全部消退为止。一般每人约需红枣一至二斤。（《上海中医药》（4）：22，1962） ⑿治走马牙疳：枣（去核、包信石，烧）、黄柏。同为末，布患处。（《海上方》） ⒀治诸疮久不瘥：枣膏三升，水三斗，煮取一斗半，数洗取愈。（《千金方》》 ⒁治风沿烂眼：大黑枣二十个（去核），明矾末五分，和枣肉捣成膏，湿纸包，火内煨二刻，取出，去纸，水二碗，将枣膏煎汤，去渣，将汤洗眼。（《本草汇言》眼科方）' where id=1744; -- 大枣
update herbs set alias='地葵，地麦，益明，落帚子，竹帚子，千头子，帚菜子，铁扫把子。', taste='苦；性寒。', channel='入肾、膀胱经。', effect='①治阳虚气弱，小便不利：野台参四钱，威灵仙钱半，寸麦冬六钱（带心），地肤子一钱。煎服。（《医学衷中参西录》宣阳汤） ②治阴虚血亏，小便不利：怀熟地一两，生龟板五钱（捣碎），生杭芍五钱，地肤子一钱。煎服。（《医学衷中参西录》济阴汤） ③治妊娠患淋，小便数，去少，忽热痛酸索，手足疼烦：地肤子十二两，初以水四升，煎取二升半，分温三服。（《子母秘录》） ④治久血痢，日夜不止：地肤子一两，地榆三分（锉），黄芩三分。上药拇细罗为散。每服，不计时候，以粥饮调下二钱。（《圣惠方》） ⑤治目痛及眯忽中伤，因有热瞑者：取地肤子白汁注目中。（《僧深集方》） ⑥治雀目：地肤子五两，决明子一升。上二味捣筛，米饮和丸。每食后，以饮服二十丸至三十丸。（《广济方》地肤子丸） ⑦治肝虚目昏：地肤子一斤（阴干，捣罗为末），生地黄五斤（净汤捣，绞取汁）。上药相拌，日中曝干，捣细罗为散。每服，空心以温酒调下二钱，夜临卧，以温水调再服之。（《圣惠方》地肤子散） ⑧治胁痛，积年久痛，有时发动：六、七月取地肤子，阴干，末。服方寸匕，日五、六服。（《补缺肘后方》） ⑨治跳跃举重，卒得阴颓：白术五分，地肤子十分，桂心三分。上三物，捣末。服一刀圭，日三。（《肘后方》） ⑩治疝气：地肤子炒香，研末，每服一钱，酒下。（《简便单方》） ⑾治痔疾：地肤子不拘多少，新瓦上焙干，捣罗为散。每服三钱匕，用陈粟米饮调下，日三。（《圣济总录》地肤子散） ⑿治吹乳：地肤子为末。每服三钱，热酒冲服，出汗愈。（《经验广集》地肤酒） ⒀治雷头风肿：地肤子，同生姜研烂，热酒冲服，取汗愈。（《圣济总录》） ⒁治肢体疣目：地肤子，白矾等分。煎汤频洗。（《寿域神方》） ⒂治痈：地肤子、莱菔子各一两。文火煎水，趁热洗患处，每日二次，每次10～15分钟。（内蒙古《中草药新医疗法资料选编》）' where id=1745; -- 地肤子
update herbs set taste='味甘；性微寒。', channel='归肺；大肠经。', effect='①治咳有微热，烦满，胸中甲错，是为肺痈：苇茎（切，二升，以水二斗煮取五升去滓），薏苡仁半升，桃仁三十枚，瓜瓣（目前多用冬瓜仁）半升。上四味细切，内苇汁中煮取二升，服一升，当吐如脓。（《金匮要略》千金苇茎汤） ②治肠痈脓未成，少腹肿痞，按之即痛，如淋，小便自调，时时发热，自汗出，复恶寒，其脉迟紧者：大黄四两，牡丹皮一两，桃仁五十个，瓜子半斤，芒硝三合。上五味，以水六升，煮取一升，去滓，内芒硝；再煎沸，顿服之。有脓当下，如无脓当下血。（《金匮要略》大黄牡丹汤） ③治男子白浊，女子白带：陈冬瓜仁炒为末。每空心米饮服五钱。（《救急易方》） ④治消渴不止，小便多：干冬瓜子、麦门冬、黄连各二两。水煎饮之。《摘元方》 ⑤治男子五劳七伤，明目：白瓜子七升，绢袋盛，搅沸汤中三遍，暴干；以酢五升浸一宿，暴干；治下筛。酒服方寸匕，日三服之。（《千金方》）' where id=1746; -- 冬瓜子
update herbs set taste='味辛；性微温。', channel='入脾、胃、大小肠经。', effect='①治脚气，肿满腹胀，大小便秘涩：大腹皮一两（锉），槟榔一两，木香半两，木通二两（锉），郁李仁一两（汤浸去皮，微炒），桑根白皮二两（锉），牵牛子二两（微炒）。上药捣筛为散。每服四钱，以水一中盏，入生姜半分，葱白二七寸，煎至六分，去滓。不计时候，温服，以利为度。（《圣惠方》） ②治男子妇人脾气停滞，风湿客搏，脾经受湿，气不流行，致头面虚浮，四肢肿满，心腹膨胀，上气喘急，腹胁如鼓，绕脐胀闷，有妨饮食，上攻下疰，来去不定，举动喘乏：五茄皮、地骨皮、生姜皮、大腹皮、茯苓皮各等分。上为粗末。每眼三钱，水一盏半，煎至八分，去滓，稍热服之，不拘时候。切忌生冷油腻坚硬等物。（《局方》五皮散） ③治漏疮恶秽：大腹皮煎汤洗之。（《仁斋直指方》）' where id=1747; -- 大腹皮
update herbs set taste='辛、苦，微温。', channel='入肾、膀胱经。', effect='①治风痹：独活、石南各四两，防风三两，附子、乌头、天雄、茵芋各二两。以酒二斗，渍七日，服半合，日三，以知力度。（《干金方》独活酒） ②治风伤肾经，腰痛如掣，久不治，流入脚膝，为偏枯冷痹缓弱之患，及新产后腰脚挛痛，除风活血：独活二两半，桑寄生、杜仲（切，炒断丝）、北细辛、白芍药、桂心、芎藭、防风（去芦）、甘草、人参、熟地黄（洗）、大当归各二两。上锉散，每四钱，水二盏煎，空心服。（《世医得效方》独活寄生汤） ③治少阴寒湿腰痛：独活、苍术、防风、细辛、川芎、甘草。水煎服。（《症因脉治》独活苍术汤） ④治历节风四肢头面肿：黄芪十二分，独活八分，生地（切）三升（暴干），豆豉一升（熬），鼠粘子三升（暴干），上五味捣筛为散，一服方寸匕，饮汁下，日二服，加至二、三匕，忌芜荑、蒜、面、猪肉。（《延年方》） ⑤治惊瘫、鹤膝，及中风湿日久致腰背手足疼痛，昼轻夜重，及四肢痿痹不仁：川独活半两，当归（酒洗）、白术、黄芪（蜜水涂炙）、薄桂（去粗皮）、川牛膝（酒洗）各二钱半，甘草（炙）三钱。上件细切，每取二钱，水一盏，姜二片，薤白一根，煎七分，空心热服，或无时。（《活幼心书》独活汤） ⑥治产后百日中风，痉，口噤不开，并治血气痛，劳伤，补肾；独活一斤，大豆五升，酒一斗三升。上三味，先以酒渍独活再宿，若急须，微火煮之，令减三升，去滓，别熬大豆极焦，使烟出，以独活酒沃之，去豆服一升，日三夜一。（《千金方》独活紫汤） ⑦治产后中风，虚人不可服他药者：独活三两。以水三升，煮取一升，分服。耐酒者亦可以酒水等煮之。（《小品方》一物独活汤） ⑧治风著人面，引口偏著耳，牙车急，舌不得转：独活三两，生地黄汁一升，竹沥一升。上三味，合煎取一升，顿服之。（《千金方》） ⑨治头痛属少阴者：独活、细辛、川芎、秦艽、生地、羌活、防风、甘草，水煎服。（《症因脉治》独活细辛汤） ⑩治齿根动痛：生地黄、独活各三两。上二味细切，以酒一升渍一宿，含之。（《千金方》） ⑾浣洗一切痈疽：独活、黄芩、莽草、当归、川芎、大黄、赤芍药各-两。上为散，分作两次，先用猪蹄以水二升煮，令蹄熟，去蹄入药，再煎十余沸去滓，乘热洗疮。（《普济方》独活散）', tips='阴虚血燥者慎服。 ②《本经逢原》：气血虚而遍身痛及阴虚下体瘙弱者禁用。一切虚风类中，咸非独活所宜。' where id=1748; -- 独活
update herbs set taste='苦，微温。', channel='入心、肝经。', effect='①治妇人经脉不调，或前或后，或多或少，产前胎不安，产后恶血不下并治之。兼治冷热劳，腰脊痛，骨节颊疼：丹参（去芦）不以多少，为末。每服二钱，酒调下，经脉不调食前，冷热劳无时。（《妇人良方》丹参散） ②治经水不调：紫丹参一斤，切薄片，于烈日中晒脆，为细末，用好酒泛为丸。每服三钱，清晨开水送下。（《集验拔萃良方》调经丸） ③治经血涩少，产后瘀血腹痛，闭经腹痛：丹参、益母草、香附各三钱。水煎服。 ④治腹中包块：丹参、三棱、莪术各三钱，皂角刺一钱。水煎服。 ⑤治急、慢性肝炎，两胁作痛：茵陈五钱，郁金、丹参、板蓝根各三钱。水煎服。（③方以下出《陕甘宁青中草药选》） ⑥治妊娠胎堕，下血不止：丹参十二两，细切，以清酒五升，煮取三升，温服一升，日三。（《千金方》） ⑦治心腹诸痛，属半虚半实者：丹参一两，白檀香、砂仁各一钱半。水煎服。（《医学金针》丹参饮） ⑧治腰髀连脚疼：杜仲八两，丹参五两，独活、当归、芎劳、干地黄各四两。上六味切，以绢袋盛，上清酒二斗债之五宿，服二合，日再。忌芜荑。（张文仲） ⑨治神经衰弱：丹参五钱，五味子一两。水煎服。（《陕甘宁青中草药选》） ⑩治小儿汗出中风，身体拘急，壮热苦啼：丹参半两，鼠粪三七枚（微炒）。上药，捣细罗为散。每服，以浆水调下半钱，量儿大小，加减服之。（《圣惠方》丹参散） ⑾治妇人乳肿痛：丹参、芍药各二两，白芷一两。上三味，以苦酒渍一夜，猪脂六合，微火煎三上下，膏成敷之。（《刘涓子鬼遗方》丹参膏） ⑿治阴疼痛或肿胀：丹参一两，槟榔一两，青橘皮半两（汤浸去白瓤，焙），蘹香子半两。上药捣细罗为散。每于食前，以温酒调下二钱。（《圣惠方》丹参散） ⒀治寒疝，小腹及阴中相引痛，自汗出欲死：丹参半两，锉，捣细罗为散。每服，以热酒调下二钱。（《圣惠方》） ⒁治风热，皮肤生瘖癍，苦痒成疥：丹参四两（锉），苦参四两（判），蛇床子三合（生用）。上药以水一斗五升，煎至七升，去滓，乘热洗之。（《圣惠方》丹参汤） ⒂治热油火灼，除痛生肌：丹参八两，剉，以水微调，取羊脂二斤，煎三上三下，以涂疮上。（《肘后方》）' where id=1749; -- 丹参
update herbs set taste='苦，寒。', channel='入肝、心、胃经。', effect='①预防乙脑，流脑：大青叶五钱，黄豆一两，水煎服，每日一剂，连服七天。（《江西草药》） ②治乙脑，流脑，感冒发热，腮腺炎：大青叶五钱至一两，海金砂根一两.水煎服，每日二剂。（《江西草药》） ③治温毒发斑：大青四两，甘草、胶各二两，豉八合。以水一斗，煮二物，取三升半，去滓，纳豉煮三沸，去滓，乃纳胶，分作四服，尽又合。此治得至七、八日，发汗不解，及吐下太热，甚佳。（《补缺肘后方》） ④治时行壮热头痛，发疮如豌豆遍身：大青三两，栀子二七枚（擘），犀角（屑）一两，豉五合。上四味切，以水五升，煮取二升，分三服，服之无所忌。（《延年方》大青汤） ⑤治麻疹色太红，或微紫，或出太甚者：大青、元参、生地、石膏、知母、木通、地骨皮、荆芥、甘草、淡竹叶。水煎热服。（段希孟《痘疹心法》大青汤） ⑥治风疹，丹毒：大青捣烂，鼍之即散（先以磁锋砭去恶血）。（《本草汇言》） ⑦治热甚黄疸：大青二两，茵陈、秦艽各一两，天花粉八钱。水煎服。（《方脉正宗》） ⑧治无黄疽型肝炎：大青叶二两，丹参一两，大枣十枚。水煎服。（《山东中草药手册》） ⑨治热病不解，下痢困笃欲死者：大青四两，甘草、赤石脂三两，胶二两，豉八合。以水一斗，煮取三升，分三服，尽更作，日夜两剂。（《补缺肘后方》大青汤） ⑩治小儿赤痢：捣青蓝汁二升，分四服。（《子母秘录》） ⑾治热盛时疟，单热不寒者：大青嫩叶捣汁，和生白酒冲饮。（《方脉正宗》） ⑿治肺炎高热喘咳：鲜大青叶一至二两。捣烂绞汁，调蜜少许，炖热，温服，日二次。（《泉州本草》） ⒀治上气咳嗽，呷呀息气，喉中作声，唾粘：蓝实叶浸良久，捣绞取汁一升，空腹顿服，须臾以杏仁取汁煮粥食之，一两日将息，依前法更服，吐痰方瘥。（《梅师集验方》） ⒁治血淋，小便尿血：鲜大青叶一至二两，生地五钱。水煎调冰糖服。日二次。（《泉州本草》） ⒂治喉风，喉痹：大青叶捣汁灌之，取效止。（《卫生易简方》） ⒃治咽喉唇肿，口舌糜烂，口甘面热：大青、升麻、大黄（锉、炒）各二两，生干地黄（切、焙）三两。上四味粗捣筛。每服二钱匕，以水一盏，煎至七分，去滓，温服，利即愈。（《圣济总录》大青汤） ⒄治小儿口疮不得吮乳：大青十八铢，黄连十二铢。上二味细切，以水三升，煮取一升二合，一服一合。日再夜一。（《千金方》） ⒅治大头瘟：鲜大青叶洗净，捣烂外敷患处，同时取鲜大青叶一两，煎汤内服。（《泉州本草》） ⒆治脑热耳聋：大青、大黄（锉、炒）、栀子（去皮）、黄芪（制）、升麻、黄连（去须）各一两，朴硝二两。上七味，捣罗为末，炼蜜丸如梧桐子大。每服三十丸，温水下。（《圣济总录》大青丸） ⒇治淋巴腺炎；阑尾术后感染等炎症：大青叶、木芙蓉叶各半斤，蒲公英三两。水煎十二小时，取汁2000毫升，每服20毫升，每日三次。（《江西草药》） （21）防治疔、疖、痱子：㈠大青叶（鲜）三两。水煎服，每日一剂。㈡大青叶适量，水煎浓汁，加薄荷油适量，洗患处，每日二至三次。（《江西草药》）' where id=1750; -- 大青叶
update herbs set taste='苦甘；平；寒；无毒。', channel='入肝、胃、心胞经。', effect='①治伤寒发汗，若吐、若下，解后，心下痞梗，噫气不除者：旋覆花三两，人参二两，生姜五两，代赭一两，甘草三两（炙），半夏半升（洗），大枣十二枚（擘）。上七味，以水一斗，煮取六升，去滓，再煎取三升，温服二升，日三服。（《伤寒论》旋覆代赭汤） ②治宿食结于肠间，不能下行，大便多日不通。其证或因饮食过度，或因恣食生冷，或因寒火凝结，或因呕吐既久，胃气冲气皆上逆不下降：生赭石二两（轧细），朴硝五钱，干姜二钱，甘遂一钱半（轧细，药汁冲服）。热多者去干姜，寒多者酌加干姜数钱。呕多者，可先用赭石一两、干姜半钱煎服，以止其呕吐。呕吐止后再按原方煎汤，送甘遂末服之。（《医学衷中参西录》赭遂攻结汤） ③治逆气上冲奔逼，息道滞塞不通：代赭石（打碎）三两，陈皮二两，桃仁、桂、吴茱萸各半两。加姜、水煎。（《御药院方》代赭石汤） ④治诸呀呷有声，卧睡不得：土硃（朱）不拘多少，为极细末，米醋调，时时进一、二服。（《普济方》） ⑤治急慢惊风，吊眼撮口，搐搦不定：代赭石，火烧醋淬十次，细研水飞，日干。每服一钱或半钱，白汤调下，连进三服。见脚胫上有赤斑，即是惊气已出，病当安也。无斑点者不可治。（《仁斋直指方》） ⑥治吐血，衄血：血师一两（火煅、米醋淬、尽醋一升），捣罗为面。每服一钱，白汤下。（《斗门方》） ⑦治肠风血痢久不愈：代赭石二两（火烧、醋淬二次），柿饼一个（煮烂）。捣为丸，梧子大。每早服二钱，白汤下。（《方脉正宗》） ⑧治崩中淋沥不止：大赭石研为细末，醋汤调服。（《普济方》） ⑨治妊娠胎堕，下血不止：地黄汁和代赭末，服方寸匕。（《千金方》） ⑩治牙宣：赤土、荆芥。同为细末，揩齿上，以荆芥汤漱。（《百一选方》） ⑾治喉痹肿痛：紫朱煮汁饮。（《普济方》） ⑿治赤眼肿闭：土朱二分，石膏一分。为末，新汲水调敷眼头尾及太阳穴。（《仁斋直指方》） ⒀治一切疮疖：土朱、虢丹、牛皮胶等分。为末，好酒一碗冲之，澄清服。以渣敷之，干再上。（《朱氏集验医方》） ⒁治诸丹热毒：土朱、青黛各二钱，滑石、荆芥各一钱。为末，每服--钱半，蜜水调下，仍外敷之。（《仁斋直指方》）' where id=1751; -- 代赭石
update herbs set taste='甘；微辛；性温。', channel='肝；肾经。', effect='①治腰痛：杜仲一斤，五味子半升。二物切，分十四剂，每夜取一剂，以水一升，浸至五更，煎三分减一，滤取汁，以羊肾三、四枚，切下之，再煮三、五沸，如作羹法，空服顿服。用盐、醋和之亦得。（《箧中方》） ②治腰痛：川木香一钱，八角茴香三钱，杜仲（炒去丝）三钱。水一钟，酒半钟，煎服，渣再煎。（《活人心统》思仙散） ③治卒腰痛不可忍：杜仲二两（去粗皮，炙微黄，锉），丹参二两，芎藭一两半，桂心一两，细辛三分。上药捣粗罗为散，每服四钱，以水一中盏，煎至五分，去滓，次入酒二分，更煎三、两沸，每于食前温服。（《圣惠方》杜仲散） ④治中风筋脉挛急，腰膝无力：杜仲（去粗皮，炙，锉）一两半，芎藭一两，附子（炮裂，去皮。脐）半两；上三味，锉如麻豆，每服五钱匕，水二盏，入生姜一枣大，拍碎，煎至一盏，去滓，空心温服。如人行五里再服，汗出慎外风。（《圣济总录》杜仲饮） ⑤治小便余沥，阴下湿痒：川杜仲四两，小茴香二两（俱盐、酒浸炒），车前子一两五钱，山茱萸肉三两（俱炒）。共为末；炼蜜丸，梧桐子大。每早服五钱，白汤下。（《本草汇言》） ⑥治妇人胞胎不安：杜仲不计多少，去粗皮细锉，瓦上焙干，捣罗为末，煮枣肉糊丸，如弹子大，每服一丸，嚼烂，糯米汤下。（《圣济总录》杜仲丸） ⑦治频惯堕胎或三、四月即堕者：于两月前，以杜仲八两（糯米煎汤，浸透，炒去丝），续断二两（酒浸，焙干；为末），以山药五，六两为末，作糊丸，梧子大。每服五十丸，空心米饮下。（《简便单方》） ⑧治高血压：㈠杜仲、夏枯草各五钱，红牛膝三钱，水芹菜三两，鱼鳅串一两。煨水服，一日三次。（《贵州草药》）㈡杜仲、黄芩、夏枯草各五钱。水煎服。（《陕西中草药》） ⑩.杜仲酒（《外台秘要》）治卒腰痛。杜仲、丹参各25g，川芎15g。上3味切，以酒2斤渍5晚，随性少少饮之。方中杜仲配伍各药有补肝肾、强筋骨的功效。 ⑾.思仙续断丸（《本事方》）治肝肾风虚气弱，脚膝不可践地，腰脊疼痛，风毒流注下经，行止艰难，小便余沥，此药补五脏内伤，调中益精凉血，坚强筋骨，益智轻身。杜仲150g，五加皮、防风、薏苡仁、羌活、续断、牛膝各90g，萆薢120g，生干地黄150g。上为末，好酒3升，化青盐90g，用木瓜250g，以盐酒煮成膏，和杵丸如梧子大，每服50丸，空心食前，温酒盐汤下。方中杜仲配伍续断治肝肾不足之腰膝酸痛，腿软无力，行走不利等症。' where id=1752; -- 杜仲
update herbs set taste='味甘；性平。', channel='归脾；肺经。', effect='①清肺金，补元气，开声音，助筋力：党参一斤（软甜者，切片），沙参半斤（切片），桂圆肉四两。水煎浓汁，滴水成珠，用磁器盛贮.每用一酒杯，空心滚水冲服，冲入煎药亦可。（《得配本草》上党参膏） ②治泻痢与产育气虚脱肛：党参（去芦，米炒）二钱，炙耆、白术（净炒）、肉蔻霜、茯苓各一钱五分，怀山药（炒）二钱，升麻（蜜炙）六分，炙甘草七分。加生姜二片煎，或加制附子五分。（《不知医必要》参耆白术汤） ③治服寒潦竣剂，以致损伤脾胃，口舌生疮；党参（焙）、黄芪（炙）各二钱，茯苓一钱，甘草（生）五分，白芍七分。白水煎，温服。（《喉科紫珍集》参耆安胃散） ④治小儿口疮：党参一两，黄柏五钱。共为细末，吹撒患处。（《青海省中医验方汇编》） ⑤抑制或杀灭麻风杆菌：党参、重楼（蚤休）、刺包头根皮（楤木根皮）各等量。将党参、重楼研成细粉；再将刺包头根皮加水适量煎煮三次，将三次煎液浓缩成一定量（能浸湿党参、重楼细粉）的药液，加蜂蜜适量.再将重楼、党参细粉倒入捣匀作丸，每丸三钱重；亦可作成膏剂。日服三次，每次一丸，开水送服。（北京中医学院《新医疗法资料汇编》）' where id=1753; -- 党参
update herbs set taste='味甘、寒。', channel='入大小肠、膀胱经。', effect='①治卒关格，大小便不通，支满欲死：葵子二升，水四升，煮取一升，顿服。内猪脂如鸡子一丸则弥佳。（《肘后方》） ②治大便不通十日至一月者：葵子末入乳汁等分，和服。（《圣惠方》） ③治血淋及虚劳尿血：葵子一升，水三升，取汁，日三服。（《千金方》） ④治妊娠患子淋：英子一升，以水三升，煮取二升，分再服。（《千金方》） ⑤治产后淋沥不通：葵子一合，朴消八分。水二升，煎八合，下消服之。（《姚僧坦集验方》） ⑥妊娠有水气，身重，小便不利，洒渐恶寒，起即头眩：葵子一斤，茯苓三两。上二味，杵为散，饮服方寸匕，日三服，小便利则愈。（《金匮要略》葵子茯苓散） ⑦治难产，若生未得者：冬葵子一合，捣破，以水二升，煮取一升；已下，只可半升，去滓，顿服之。（《食疗本草》） ⑧治胎死腹中：葵子一升，阿胶五两。上二味，以水五升，煮取二升，顿服之。未出再煮服。（《千金方》） ⑨治胎死腹中，若母病欲下：牛膝三两，葵子一升。上二味，以水七升，煮取三升，分三服。（《千金方》） ⑩治乳妇气脉壅塞，乳汁不行，及经络凝滞，奶房胀痛，留蓄作痈毒：葵菜子（炒香）、缩砂仁等分。为末，热酒服二钱。（《妇人良方》） ⑾治血痢、产痢：冬葵子为末，每服二钱，入腊茶一钱，沸汤调服，日三。（《圣惠方》） ⑿治痎疟邪热：冬葵子阴干为末，酒服二钱。（《圣惠方》） ⒀治盗汗：冬葵子三钱，水煎兑白糖服。（江西《草药手册》） ⒁治面上疱疮：冬葵子、柏子仁、茯苓、瓜瓣各一两。为末，食后酒服方寸匕，日三服。（陶弘景）', tips='脾虚肠滑者忌服，孕妇慎服。 ②《得配本草》：气虚下陷，脾虚肠滑，二者禁用。' where id=1754; -- 冬葵子
update herbs set taste='苦，寒.', channel='入胃、大肠、肝经。', effect='①治伤寒阳明腑证，阳邪入里，肠中有燥屎，腹满痛，谵语，潮热，手足濈然汗出，不恶寒，痞满燥实全见者，，以此汤下之：大黄（酒洗）四两，厚朴（炙，去皮）半斤，枳实（炙）五枚，芒硝三合。上四味，以水一斗，先煮二物，取二升，去滓，纳大黄，更煮取二升，去滓，纳芒硝，更上微火一两沸，分温再服，得下，余勿服。（《伤寒论》大承气汤） ②治大便秘结：大黄二两，牵牛头末五钱。上为细末，每服三钱。有厥冷，用酒调三钱，无厥冷而手足烦热者，蜜汤调下，食后微利为度。（《素问病机保命集》大黄牵牛丸） ③治热病狂语及诸黄：川大黄五两（锉碎，微炒）。捣细罗为散，用腊月雪水五升，煎如膏，每服不计时侯，以冷水调半匙服之。（《圣惠方》雪煎方） ④治泄痢久不愈，脓血稠粘，里急后重，日夜无度，久不愈者：大黄一两，细锉，好酒二大盏，同浸半日许，再同煎至一盏半，去大黄不用，将酒分为二服，顿服之，痢止。一服如未止，再服，以利为度，服芍药汤和之，痢止，再服黄芩汤和之，以彻其毒也。（《素问病机保命集》大黄汤） ⑤治妇人经血不通，赤白带下，崩漏不止，肠风下血，五淋，产后积血，癥瘕腹痛，男子五劳七伤，小儿骨蒸潮热等证，其效甚速：锦纹大黄一斤，分作四份；一份用童尿一碗，食盐二钱，浸一日，切晒；一份用醇酒一碗，浸一日，切晒，再以巴豆仁三十五粒同炒，豆黄，去豆不用；一份用红花四两，泡水一碗，浸一日，切晒；一份用当归四两，入淡醋一碗，同浸一日，去归，切晒。为末，炼蜜丸梧子大，每服五十丸，空心温酒下，取下恶物为验。未下再服。（《医林集要》无极丸） ⑥治产后恶血冲心，或胎衣不下，腹中血块等：锦纹大黄一两，杵罗为末，用头醋半升，同熬成膏，丸如梧桐子大，用温醋化五丸服之，良久下。亦治马坠内损。（《千金方》） ⑦治久患腹内积聚，大小便不通，气上抢心，腹中胀满，逆害饮食：大黄、芍药各二两。上二味末之，蜜丸，服如梧桐子四丸，日三，不知，可加至六、七丸，以知为度。（《千金方》神明度命丸） ⑧治大人小儿脾癖，并有疳者：锦纹大黄三两，为极细末，陈醋两大碗，砂锅内文武火熬成膏，倾在新砖瓦上，日晒夜露三朝夜，将上药起下，再研为细末；后用硫黄一两，官粉一两，将前项大黄末一两，三味再研为细末。十岁以下小儿，每服可重半钱，食后临卧米饮汤调服。此药忌生硬冷荤鱼鸡鹅一切发物。服药之后，服半月白米软粥。如一服不愈时，半月之后再服。（《昔济方》于金散） ⑨去五脏湿热秽浊。治饮食停滞，胸脘胀痛，头晕口干，二便秘结：大黄十斤，切作小块，用泔水，浸透，以侧柏叶铺甑，入大黄，蒸过晒干，以好酒十斤浸之，再蒸收晒干。另用桑叶、桃叶、槐叶、大麦、黑豆、绿豆各一斤，每味煎汁蒸收，每蒸一次，仍用侧柏叶铺甑蒸过晒干，再蒸再晒。制后再用半夏、厚朴、陈皮、白术、香附、车前各一斤，每味煎汁蒸收如上法，蒸过晒干，再用好酒十斤，制透，炼蜜丸如梧子大，每服一、二钱，或为散亦可。（《银海指南》清宁丸） ⑩治时行头痛壮热一二日：桂心、甘草、大黄各二两，麻黄四两。上四味，治下筛，患者以生热汤浴讫，以暖水服方寸匕，日三，覆取汗，或利便瘥。丁强人服二方寸匕。（《千金方》水解散） ⑾治眼暴热痛，眦头肿起：大黄（锉，炒）、枳壳（去瓤，麸炒）、芍药各三两，山栀子仁、黄芩（去黑心）各二两。上五味粗捣筛，每服五钱匕，水一盏半，煎至七分，去滓，食后临卧服。（《圣济总录》大黄汤） ⑿治心气不足，吐血衄血：大黄二两，黄连、黄芩各一两。上三味，以水三升，煮取一升，顿服之。（《金匮要略》泻心汤） ⒀治虚劳吐血：生地黄汁半升，川大黄末一方寸匕。上二味，温地黄汁一沸，纳人黄（末）搅之，空腹顿服，日三，瘥。（《千金方》） ⒁治肠痈，少腹肿痞，按之即痛如淋，小便自调，时时发热，自汗出，复恶寒。其脉迟紧者，脓未成，可下之，当有血；脉洪数者，脓已成，不可下也：大黄四两，牡丹一两，桃仁五个个，瓜子半升，芒硝三合。上五味，以水六升，煮取一升，去滓，纳芒硝，再煮沸，顿服之，有脓当下，如无脓当下血。（《金匮要略》大黄牡丹汤） ⒂治肺壅，鼻中生疮，肿痛：㈠川大黄一分（生用），黄连一分（去须），麝香一钱（细研）。上药，捣细罗为散，研入麝香令匀，以生油旋调，涂于鼻中。㈠杏仁一分（汤浸，去皮、尖，研为膏），川大黄一分（生为末）。上药相和令匀，以猪脂调涂鼻中。（《圣惠方》） ⒃治奶痈：川大黄、粉草各一两。上为细末，以好酒熬成膏，倾在盏中放冷，摊纸上贴痛处，仰面卧至五更。贴时先用温酒调（服）一大匙，明日取下恶物，相度强弱用药，羸弱不宜服。（《妇人良方》金黄散） ⒄治痈肿振焮不可触：大黄捣筛，以苦酒和贴肿上，燥易，不过三，即瘥减不复作，脓自消除。（《补缺肘后方》） ⒅治口疮糜烂：大黄、枯矾等分。为末以擦之，吐涎。（《圣惠方》） ⒆诒火丹赤肿遍身：大黄磨水频刷之。（《救急方》） ⒇治冻疮皮肤破烂，痛不可忍：川大黄为末，新汲水调，搽冻破疮上。（《卫生宝鉴》如神散） （21）治汤火灼伤：庄浪大黄（生研），蜜调涂之，不唯止痛，又且灭瘢。（《夷坚志》） （22）治从高坠下，及木石所压，凡是伤损，瘀血凝积，气绝欲死，并久积瘀血，烦躁疼痛，叫呼不得及折伤等：大黄一两（酒蒸），杏仁三七粒（去皮、尖）.上研细，酒一碗，煎至六分，去滓，鸡鸣时服，次日取下瘀血即愈。若便觉气绝不能言，取药不及，急擘开口，以热小便灌之。（《三因方》鸡鸣散） （23）治打仆伤痕，瘀血滚注，或作潮热者：大黄末、姜汁调涂。一夜，黑者紫，二夜，紫者白也。（《濒湖集简方》）', tips='凡表证未罢，血虚气弱，脾胃虚寒，无实热、积滞、瘀结，以及胎前、产后，均应慎服。 ②《药性论》：忌冷水。恶干漆。 ③《本草经疏》：凡血闭由于血枯，而不由于热积；寒热由于阴虚，而不由于瘀血；癥瘕由于脾胃虚弱，而不由于积滞停留；便秘由于血少肠燥，而不由于热结不通；心腹胀满由于脾虚中气不运，而不由于饮食停滞；女子少腹痛由于厥阴血虚，而不由于经阻老血瘀结；吐、衄血由于阴虚火起于下，炎烁乎上，血热妄行，溢出上窍，而不由于血分实热；偏坠由于肾虚，湿邪乘虚客之而成，而不由于湿热实邪所犯；乳痈肿毒由于盱家气逆，郁郁不舒，以致营气不从，逆于肉里，乃生痈肿，而不由于膏粱之变，足生大疔，血分积热所发，法咸忌之，以其损伤胃气故耳。 ④《本草汇言》：凡病在气分，及胃寒血虚，并妊娠产后，及久病年高之人，并勿轻用大黄。 ⑤《本经逢原》：肾虚动气及阴疽色白不起等证，不可妄用。' where id=1755; -- 大黄
update herbs set taste='甘；温；香。', channel='归肺、肾经。', effect='①治病后虚损：夏草冬虫三、五枚，老雄鸭一只，去肚杂，将鸭头劈开，纳药于中，仍以线扎好，酱油酒如常蒸烂食之。（《纲目拾遗》） ②治虚喘：冬虫夏草五钱至一两，配老雄鸭蒸服。（《云南中草药》） ③治贫血，阳痿，遗精：冬虫夏草五钱至一两，炖肉或炖鸡服。（《云南中草药》）' where id=1756; -- 冬虫夏草
update herbs set taste='味辛；性温。', channel='入胃、脾、肾经。', effect='①治伤寒咳噫不止，及哕逆不定：丁香一两，干柿蒂一两。焙干，捣罗为散。每服一钱，煎人参汤下，无时服。（《简要济众方》） ②治小儿吐逆：丁香、半夏（生用）各一两。同研为细末，姜汁和丸，如绿豆大。姜汤下三、二十丸。（《百一选方》） ③治朝食暮吐：丁香十五个研末，甘蔗汁、姜汁和丸莲子大，噙咽之。（《摘元方》） ④治霍乱，止吐：丁香十四枚，以酒五合，煮取二合，顿服之。用水煮之亦佳。（《千金翼方》） ⑤治久心痛不止：丁香半两，桂心一两。捣细，罗为散，每于食前，以热酒调下一钱。（《圣惠方》） ⑥治痈疽恶肉：丁香末敷之，外用膏药护之。（《怪证奇方》） ⑦治食蟹致伤：丁香末，姜汤服五分。（《证治要诀》） ⑧治鼻中息肉：丁香绵裹纳之。（《圣惠方》）' where id=1757; -- 丁香
update herbs set taste='味甘；辛；苦；性温。', channel='入心、肝、脾经。', effect='①调益荣卫，滋养气血。治冲任虚损，月水不调，脐腹疞痛，崩中漏下，血瘕块硬，发歇疼痛，妊娠宿冷，将理失宜，胎动不安，血下不止，及产后乘虚，风寒内搏，恶露不下，结生瘕聚，少腹坚痛，时作寒热：当归（去芦，酒浸，炒）、川芎、白芍药、熟干地黄（酒洒蒸）各等分。共为粗末。每服三钱，水一盏半，煎至八分，去渣热服，空心食前。（《局方》四物汤） ②治室女月水不通：当归（切，焙）一两，干漆（炒烟出）、芎藭各半两。上三味捣罗为末，炼蜜和丸如梧桐子大。每服二十丸，温酒下。（《圣济总录》当归丸） ③治月经逆行从口鼻出：先以京墨磨汁服止之，次用当归尾、红花各三钱，水一种半，煎八分，温服。（《简便单方》） ④治血崩：当归一两，龙骨二两（炒赤），香附子三钱（炒），棕毛灰五钱。上为末，米饮调三四钱，空心服。（《儒门事亲》当归散） ⑤治血瘕痛胀，脉滞涩者：当归三两，桂心两半，白芍两半（酒炒），蒲黄二两（炒），血竭三两，延胡两半。为散，酒煎三钱，去渣温服。（《医略六书》当归蒲延散） ⑥治妇人带下五色，腹痛，羸瘦，食少：当归一两（锉，微炒），鳖甲一两（涂醋炙微黄，去裙稠），川大黄一两（锉碎，微炒），白术三分，胡椒半两，诃黎勒皮三分，槟榔三分，枳壳三分（麸炒微黄去瓤），荜茇半两。上件药捣罗为末，炼蜜和捣三二百杵，丸如梧桐子大，每于食前以温酒下三十丸.（《圣惠方》当归丸） ⑦治妇人怀娠，腹中疞痛：当归三两，芍药一斤，茯苓四两，白术四两，泽泻半斤，芎藭半斤（’半斤’一作’三两’）。上杵为散，取方寸匕，酒和，日三服。（《金匮要赂》当归芍药散） ⑧治妊娠小便难，饮食如故：当归、贝母、苦参各四两。三味末之，炼蜜丸如小豆大，饮服三丸，加至十丸。（《金匮要略》当归苦参丸） ⑨治妊娠胎动不安，腰腹疼痛：当归半两（锉），葱白一分（细切）。上二味，先以水三蛊，煎至二盏，入好酒一盏，更煎数沸，去滓，分作三服。（《圣济总录》安胎饮） ⑩治产后败血不散，结聚成块（俗呼儿枕），疼痛发歇不可忍：当归一两（锉，微炒），鬼箭羽一两，红蓝花一两。上药捣筛为散，每服三钱，以酒一中盏，煎至六分，去滓，不计时候温服。（《圣惠方》当归散） ⑾治瘈疭、或颤振，或产后不省人事，口吐痰涎：当归、荆芥穗等分。上为细末，每服三钱，水一盏，酒少许，煎至七分，灌下咽，即有生理。（《妇人良方》交加散） ⑿治产后腹中疞痛，并腹中寒疝虚劳不足：当归三两，生姜五两，羊肉一斤。上三味，以水八升，煮取三升，温服七合，日三服。（《金匮要略》当归生姜羊肉汤） ⒀治大便不通：当归、白芷等分为末，每服二钱，米汤下。（《圣济总录》） ⒁治肌热燥热，困渴引饮，目赤面红，昼夜不息，其脉洪大而虚，重按全无：黄耆一两，当归（酒洗）二钱。上药作一服，水二盏，煎至一盏，去滓，温服，空心食前。（《内外伤辨》当归补血汤） ⒂治白虎风，疼痛不止：当归一两，桂心一两，地龙一两（微炒），白僵蚕一两（微妙），威灵仙一两，漏芦一两，芎藭一两，白芷一两。上药，捣细罗为散，每服，不计时候，以热酒调下二钱。（《圣惠方》当归散） ⒃治血痢里急后重，肠中疼痛：当归三分（锉，微炒），黄连一两（去须，微炒），龙骨二两.上三味，捣罗为细散。每服二钱匕，粥饮调下，不拘时候，日二。（《圣济总录》当归散） ⒄治盗汗：当归、生地黄、熟地黄、黄蘗、黄芩、黄连各等分，黄芪加一倍。上为粗末，每服五钱，水二盏，煎至一盏，食前服，小儿减半服之。（《兰室秘藏》当归六黄汤） ⒅治诸疮肿，已破未破，焮肿甚：当归、黄耆、栝蒌，木香、黄连各等分，为粗末，煎一两。（《素问病机保命集》当归散） ⒆治附骨痈及一切恶疮：当归半两，甘草一两，山栀子十二枚，木鳖子一枚（去皮）。上为细末，每服三钱，冷酒调服。（《奇效良方》当归散） ⒇治汤泼火烧疮，疼痛甚者：白蜡一两，麻油四两，当归一两半（生锉）。先将油煎当归令焦黑，滤去滓，次入蜡，候消，相次急搅之，放冷入磁盒中收，以故帛子涂贴。（《圣惠方》神效白膏）' where id=1758; -- 当归
update herbs set effect='治一切劳，咳嗽壅滞，胸脯痞满: 鹅管石、雄黄、佛耳草、款冬花各等分。上为末。每服用药一钱，安在香炉子上焚着，以开口吸烟在喉中。(《宣明论方》焚香透膈散)' where id=1759; -- 鹅管石
update herbs set taste='味辛；性温。', channel='归肺；肝经。', effect='1.治伤风头痛、鼻塞，目翳：鹅不食草（鲜或干均可）搓揉，嗅其气，即打喷嚏，每日二次。（《贵阳民间药草》） 2.治寒痰齁喘：野园荽研汁和酒服。（《濒湖集简方》） 3.治脑漏：鲜石胡荽捣烂，塞鼻孔内。（《浙江民间草药》） 4.治单双喉蛾：鹅不食草一两，槽米一两。将鹅不食草捣烂，取汁浸糯米磨浆，给患者徐徐含咽。（《广西民间常用草药》） 5.治目病肿胀红赤，昏暗羞明，隐涩疼痛。风痒，鼻塞，头痛，脑酸，外翳攀睛，眵泪稠粘：鹅不食草二钱，青黛一钱，川芎一钱。为细末，先噙水满口，每用米许搐入鼻内，以泪出为度。不拘时候。（《原机启微》搐鼻碧云散） 6.治胬肉攀睛：鲜鹅不食草二两：捣烂，取汁煮沸澄清，加梅片一分调匀，点入眼内。（《广西民间常用草药》） 7.治脾寒疟疾：石胡荽一把，杵汁半碗，入酒半碗，和服。（《濒湖集简方》） 8.治间日疟及三日疟：鲜鹅不食草，捻成团，填鼻内，初感有喷嚏，宜稍忍耐，过一夜，效。（《现代实用中药》） 9.治阿米巴痢疾：石胡荽、乌韭根各五钱。水煎服，每日一剂；血多者加仙鹤草五钱。（《江西草药》） 10.治疳积腹泻：鲜石胡荽三钱。水煎服。（《湖南药物志》） 11.治痧症腹痛：球子草花序捣碎，以鼻闻之。使打嚏。（《浙江民间草药》） 12.治湿毒胫疮：野园荽（夏月采取，晒干为末）每以五钱，汞粉五分，桐油调作隔纸膏，周围缝定，以茶洗净，缚上膏药，黄水出。（《简便单方》） 13.治肿毒：野园荽一把，穿山甲（烧存性）七分，当归尾三钱。捣烂入酒一碗，绞汁服，以渣敷之。（《濒濒湖集简方》） 14.治痔疮肿痛：石胡荽捣贴之。（《濒湖集简方》） 15.治牛皮癣：鹅不食草捣涂。（《贵阳民间药草》） 16.治蛇伤：鲜石胡荽捣烂，外敷伤部。（《泉州本草》） 17.治跌打肿痛：鹅不食草适量，捣烂，炒热，敷患处。（《广西民间常用草药》） 18.治鸡眼：先将鸡眼厚皮削平，用鲜石胡荽捣烂包敷患处，三至五天取下。（《浙江民间常用草药》） 19.治疗疟疾 将石胡荽制成注射剂（每毫升含生药2克），在发作前2小时注射1次，连用3月。每次剂置：1～3岁2毫升，4～8岁3毫升，9～14岁4毫升，15岁以上5毫升。观察各型疟疾现症病人187例，经1～3次用药，痊愈175例（93.6％）。与氯喹、伯喹对照组相比，疗效无显著差别。治疗中有3例注射后发生恶心和轻度呕吐，停药后自行消失。 20.治疗百日咳 据300余例的观察，治愈率一般在90％左右。大都在用药后24小时内典型痉咳开始减轻。治愈时间，短者3～6天，长者10～15天。制剂及剂量：㈠取鲜品5两，制成煎液500毫升，再加入等量糖浆。按患儿年龄大小，每日用20～40毫升，4次分服。㈡取鲜生药1斤，制成煎液500毫升，再加入糖浆至1000毫升。1～4岁3～10毫升，5～8岁11～20毫升。每日3次。㈢取全草1500克，制成蒸馏液500毫升，再和入等量糖浆。1～5岁5～10毫升，5岁以上15毫升，日服3～4次 21.治疗软组织损伤 将鹅不食草研成粉末，成人每次用2～3钱（小儿减半），以黄酒6～8两（不饮酒者用酒水各半）、红糖1～2两同煮（沸后密盖勿令泄气），过滤后温服；药渣趁热敷于患部。亦可用粉剂每日3～6克，或以鲜草1～2两捣汁，分3次以温酒冲服。治疗胸、背、腰部等软组织损伤（包括跌伤、打伤、挫伤、扭伤等），均有效。据数十例观察，大多于用药后1～2天痊愈。除胃痛患者服酒煮剂后间有疼痛外，一般无副作用。亦有将鲜石胡荽制成注射剂（每1500克鲜药制成500毫升）作穴位注射，治疗关节扭伤、腰肌劳损、风湿疼痛等症，观察94例，痊愈31例，好转60例。有效率达97％。用法：于痛点或循经取穴注射，每次0.2～0.5毫升，隔日1次，一般3～5次为一疗程。 ④治疗鼻炎 包括急性鼻炎、慢性单纯性鼻炎、肥厚性鼻炎、变态反应性鼻炎等。大多数病例用药后头痛、鼻塞等症状消失或减轻。用法：将鹅不食草研成细粉吸入鼻孔，每日数次；或用棉花浸湿拧干后，包药粉少许，卷成细条塞鼻，20～30分钟后取出，每日1次；或制成油膏纱条，放置鼻腔内，1小时后取出。用药后除初起有喷嚏、流泪与流鼻涕外，余无不良反应。', tips='祛风通窃、解毒消肿。主感冒；头痛；鼻渊；鼻息肉；咳嗽；喉痹；耳聋；目赤翳膜；疟疾；风湿痹痛；跌打损伤；肿毒；疥癣。用于风寒头痛，咳嗽痰多，鼻塞不通，鼻渊流涕。 ①《本草拾遗》：去目翳，按塞鼻中，翳膜自落。 ②《四声本草》：通鼻气，利九窍，吐风痰。 ③《纲目》：解毒，明目，散目赤肿、云翳，耳聋，头痛脑酸，治痰疟齁蛤，鼻塞不通，塞鼻息自落，又散疮肿。 ④《生草药性备要》：理跌打折骨，上痛消肿。 ⑤《医林纂要》：通郁，去寒，截疟，止痢。以于末搐鼻，可发嚏去寒郁。 ⑥《植物名实图考》：治痧症。 ⑦《广西药植图志》：治疳积。 ⑧《广西中药物》：治喉毒。 ⑨《广东中药》Ⅱ：治百日咳。 ⑩广州部队《常用中草药手册》：治风湿性腰腿痛。' where id=1760; -- 鹅不食草
update herbs set taste='味甘；性温；有毒。', effect='①治大风及诸恶风，恶疮瘰疬，皮肤顽痹，半身枯死，皮肤手足脏腑间重疾并主之：蝮蛇一枚。活着器中，以醇酒一斗投之，埋于马溺处，周年以后开取，酒味犹存，蛇已消化。不过服一升已来，当觉举身习习，服讫，服他药不复得力。亦有小毒，不可顿服。（《本草拾遗》） ②治白癞：大蝮蛇一枚。切勿令伤，以酒渍之，大者一斗，小者五升，以糠火温，令下，寻取蛇一寸许，以腊月猪膏和，敷疮。（《肘后方》） ③治破伤风牙关紧急，口噤不开，口面歪斜，肢体弛缓：土虺蛇一条（去头、尾、肠、皮、骨，醋炙），地龙五条（醋炙），天南星一枚（重三分者，炮）。上为末，醋煮面和丸，如绿豆大。每服三至五丸，生姜酒下，稀葱粥投，汗出瘥。（《普济方》天南星丸） ④治一般肿毒，创伤溃烂久远等症：蝮蛇，去其首尾，剖腹除肠，锉，浸油中，五十日后，微蒸取用，外涂。（《外科调宝记》蝮蛇油） ⑤泊瘰疬搭背：蝮蛇一条，香油一斤。先将香油旗入瓷罐内，而后把蝮蛇放入浸泡，封口，埋地下，百日后取出，晒半干，捣成膏状物，敷患处。（《吉林中草药》） ⑥治胃痉挛：蝮蛇，酒浸一年以上，每食前饮一杯，一日三次，连续二十日有效。（《动植物民间药》） ⑦治遗溺：蝮蛇一钱，鸡舌香二分。上二味细末，临卧白汤送下。七岁至十五岁，每服五分；十五岁以上每服一钱。（《新本草纲目》）' where id=1761; -- 蝮蛇
update herbs set taste='甘；涩；性平。', channel='入肺、胃、大肠经。', effect='①治寸白虫：榧子日食七颗，满七日。（《食疗本草》） ②治白虫：榧子一百枚。去皮，火燃啖之，能食尽佳，不能者，但啖五十枚亦得，经宿虫消自下。（《救急方》） ③治十二指肠虫、蛔虫、蛲虫等：榧子（切碎）一两，使君子仁（切细）一两，大蒜瓣（切细）一两。水煎去滓，一日三回，食前空腹时服。（《现代实用中药》） ④治卒吐血出：先食蒸饼两三个，以榧子为末，白汤服三钱，日三服。（《圣济总录》）' where id=1762; -- 榧子
update herbs set alias='苓皮', effect='①治水肿:茯苓皮、椒目二味不拘多少。煎汤饮。（《经验良方》） ②治男子妇人脾胃停滞，头面四肢悉肿，心腹胀满，上气促急，胸膈烦闷，痰涎上壅，饮食不下，行步气奔，状如水病:生姜皮、桑白皮、陈橘皮、大腹皮、茯苓皮各等分。上为粗末。每服三钱，水一盏半，煎至八分，去滓，不计时候，温服。忌生冷油腻硬物。（《中藏经》五皮散）', tips='利水消肿。主水温肿满；小便不利。治水肿肤胀。 ①《纲目》:主水肿肤胀，开水道，开腠理。 ②《医林纂要》:行皮肤之水。' where id=1763; -- 茯苓皮
update herbs set taste='性温，味甘、酸。', channel='归肾、膀胱经。', effect='①治阳事不起：覆盆子，酒浸，焙研为末，每旦酒服三钱。（《濒湖集简方》） ②添精补髓，疏利肾气，不问下焦虚实寒热，服之自能平秘：枸杞子八两，菟丝子八两（酒蒸，捣饼），五味子二两（研碎），覆盆子四两（酒洗，去目）。车前子二两（扬净），上药，俱择精新者，焙晒干，共为细末，炼蜜丸，梧桐子大。每服，空心九十丸，上床时五十丸，百沸汤或盐汤送下，冬月用温酒送下。（《摄生众妙方》五子衍宗丸） ③治肺虚寒：覆盆子，取汁作煎为果，仍少加蜜，或熬为稀饧，点服。（《本草衍义》）' where id=1764; -- 覆盆子
update herbs set taste='味甘；性凉。', effect='①治盗汗及虚汗不止：浮小麦，文武火炒令焦，为末。每服二钱，米饮汤调下，频服为佳。一法取陈小麦用干枣煎服。（《卫生宝鉴》） ②治男子血淋不止：浮小麦加童便炒为末，砂糖煎水调服。（《奇方类编》）' where id=1765; -- 浮小麦
update herbs set effect='①治胃弱消化不良，便秘腹膨胀，胸闷：番泻叶一钱，生大黄六分，橘皮一钱，黄连五分，丁香六分。沸开水温浸二小时，去渣滤过，一日三次分服。（《现代实用中药》）' where id=1766; -- 番泻叶
update herbs set taste='味淡微苦，性寒。', channel='大肠；心；肝经。', effect='①治热性赤痢：凤尾草五份，铁线蕨一份，海金砂藤一份。炒黑，水煎服。（《广西药植图志》） ②治痢疾：鲜凤尾草二至三两。水煎或擂汁服，每日三剂。（《江西草药》） ③治急性肝炎：鲜凤尾草三两。捣汁服，每日三剂，五天为一疗程。（《江西草药》） ④治泌尿系炎症，血尿：鲜凤尾草二至四两，水煎服。（广州空军《常用中草药手册》） ⑤治热淋、血淋：凤尾草七钱至一两。用米泔水（取第二次淘米水）煎服。（《江西民间草药》） ⑥治白带及五淋白浊：凤尾草二至三钱，加车前草、白鸡冠花各三钱，萹蓄草、米仁根、贯众各五钱。同煎服。（《浙江民间草药》） ⑦治崩漏：凤尾草一两。切碎，用水酒各半煎服。（《矿西中草药》） ⑧治鼻衄：凤尾草七钱至一两，海带一两（洗净）。水煎服。（《江西民间草药》） ⑨治大便下血：凤尾草七钱至一两。同猪大肠炖熟去渣，食肠及汤。（《江西民间草药》） ⑩治肺热咳嗽：鲜凤尾草一两。洗净，煎汤调蜜服，日服二次。 ⑾治咽喉肿痛：鲜凤尾草五、六钱。洗净，煎汤，冲乌糖少许，日服二次。 ⑿治小儿口糜：鲜凤尾草二至三钱。洗净，水煎，调蜜和朱砂少许内服。（⑩方以下出《泉州本草》） ⒀治羊毛疔：鲜凤尾草一两，捣汁服；或晒干磨粉，每服三钱，温开水调服。有寒者加姜汁服。（《衡山民间草药》） ⒁治五毒发背：小金星凤尾和根，洗净，用慢火焙干，称四两，入生甘草一钱。捣末分作四服，每服用酒一升煎三、二沸后，更以冷酒三、二升相和，入瓶器内封却，时时饮服。忌生冷油腻毒物。（《履巉岩本草》） ⒂治汤火伤：凤尾草，焙干研末，麻油调敷。（《湖南药物志》） ⒃治狂犬咬伤：凤尾草二两，水煎服；或捣烂外敷。（《湖南药物志》） ⒄治磷中毒（亦适用于鸦片、砷、毒蕈中毒）：风尾草（鲜）四两。切碎，加泉水一碗，擂汁服。（《江西草药》） ⒅治荨麻疹：风尾草适量，食盐少许。水煎洗。（《江西草药》） ⒆治面神经麻痹：凤尾草三钱。水煎服。（《陕西中草药》） ⒇治秃发：小金星凤尾草根，浸油涂头。（《履巉岩本草》）' where id=1767; -- 凤尾草
update herbs set alias='铜芸，茴芸、茴草、百枝、闾根、百蜚，屏风，风肉。', taste='味辛；甘；性微温。', channel='入膀胱、肺、脾经。', effect='①治风邪伤卫，有汗恶风：防风、荆芥、葛根。（《症因脉治》防风汤） ②治偏正头痛，年深不愈，风湿热上塑损目，及脑痛不止：川芎五钱，柴胡七钱，黄连（炒）、防风（去芦）、羌活各一两，炙甘草一两五钱，黄芩三两（去皮，锉，一半酒制，一半炒）。上为细末，每服二钱匕，于盏内入茶少许，汤调如膏，抹在口内，少用白汤送下。临卧，如苦头痛，每服加细辛二分。（《兰室秘藏》清空膏） ③治偏正头风，痛不可忍者：防风、白芷各四两。上为细末，炼蜜和丸，如弹子大。如牙风毒，只用茶清为丸，每服一丸，茶汤下。如偏正头风，空心服。如身上麻风，食后服。未愈连进三服。（《普济方》） ④治风热拂郁，筋脉拘倦，肢体焦痿，头目昏眩，腰脊强痛，耳鸣鼻塞，口苦舌干，咽嗌不利，胸膈痞闷，咳呕喘满，涕唾稠粘，肠胃燥，热结，便溺淋闭等症：防风、川芎、当归、芍药、大黄、薄荷叶、麻黄、连翘，芒硝各半两，石膏、黄芩、桔梗各一两，滑石三两，甘草二两，荆芥、白术、栀子各-分。上为末，每服二钱，水一大盏，生姜三片，煎至六分，温服。（《宜明论方》防风通圣散） ⑤治白虎风，走转疼痛，两膝热肿：防风一（二）两（去芦头，微炒），地龙二两（微炒），漏芦二两，上件药，捣细罗为散，每服，不计时候，以温酒调下二钱。（《圣惠方》防风散） ⑥治痈疽最难收口者：防风、白芷、甘草、赤芍、川芎、归尾各二钱，雄猪蹄一节。加连须葱白五根，用水三大碗煎，以绢片蘸水洗之，拭干，然后上药，其深曲处，以羊毛笔洗之。（《外科十法》防风汤） ⑦治一切风疮疥癣，皮肤瘙痒，搔成瘾疹：防风（去叉）、蝉壳、猪牙皂荚（酥炙，去皮、子）各一两半，天麻二两。上四味捣为细末，用精羊肉煮熟捣烂，以酒熬为膏，丸如绿豆大，每服三十丸，荆芥酒或茶汤下。（《圣济总录》防风丸） ⑧治破伤风及打扑伤损：天南星（汤洗七次）、防风（去叉股）各等分。细末。如破伤以药敷贴疮口，然后以温酒调下一钱。如牙关急紧，角弓反张，用药二钱，童子小便调下，或因斗伤相打，内有伤损之人，以药二钱，温酒调下。（《本事方》玉真散） ⑨治自汗：防风、黄芪各一两，白术二两。每服三钱，水一钟半，姜三片煎服。（《丹溪心法》玉屏风散） ⑩治盗汗：防风五钱，川芎二钱半，人参一钱二分半。为细末，每服二钱，临卧米饮调下。（《世医得效方》防风散） ⑾消风顺气，治老人大肠秘涩：防风、枳壳（麸炒）各一两，甘草半两。为末，每食前白汤服二钱。（《简便单方》） ⑿治崩中：防风去芦头，炙亦为末，每服二钱，以面糊、酒调下，更以面糊、酒投之。（《经验后方》） ⒀治霉菌性阴道炎：防风、大戟、艾叶各五钱。水煎，熏洗，每日一次。（徐州《单方验方新医疗法》）' where id=1768; -- 防风
update herbs set taste='辛甘，热，有毒。', channel='入心、脾、肾经。', effect='①治吐利汗出，发热恶寒，四肢拘急，手足厥冷者：甘草二两（炙），干姜一两半，附子一枚（生用，去皮，破八片）。上三味，以水三升，煮取一升二合，去滓，分温再服。强人可大附子-枚，干姜三两。（《伤寒论》四逆汤） ②治伤寒阴盛格阳，其人必躁热而不欲饮水者：大附子一枚烧为灰，存性，为末；蜜水调服。（《传家秘宝方》霹雳散） ③治阴毒伤寒，面青，四肢厥逆，腹痛身冷，一切冷气：大附子三枚（炮裂，去皮脐）为末。每服三钱，姜汁半盏，冷酒半盏，调服。良久脐下如火暖为度。（《济生方》回阳散） ④治伤寒已经转下，又曾发汗，内外俱虚，邪气未解，表证不见，身无大热，昼日烦躁，不得眠睡，夜即安静，不呕不渴，脉候沉微者，宜服之。又治暴中风冷，久积痰水，心腹冷痛，霍乱转筋，一切虚寒，并皆治之：干姜（研粗末）一两，附子（生，去皮脐，细切）一枚。上合匀。每服三钱，水一盏半，煎至一盏，去滓温服，食前。（《局方》姜附汤） ⑤治呕逆翻胃：大附子一个，生姜一个（细锉）。煮研如面糊，米饮下。（《经验方》） ⑥治一切厥心痛，小肠膀胱痛，不可止者：附子一两（炮），郁金、橘红各一两。上为末，醋面糊为丸，如酸枣大，以朱砂为衣。每服一丸，男子酒下，妇人醋汤下。（《宣明沦方》辰砂一粒丹） ⑦治七疝，心腹冷痛，肠鸣气走，身寒白汗，大腑滑泄：木香（不见火）半两，玄胡索（炒，去皮）、附子（炮，去皮脐）各一两。上为粗末，每服四钱，水一盏半，生姜七片，煎至七分，去滓，温服。（《济生方》玄附汤） ⑧治休息痢及赤白痢：附子（炮裂，去皮脐）半两，鸡子二枚（去黄取白）。上二味，先将附子捣罗为末，以鸡子白和为丸，如梧桐子大。一时倾入沸汤内，煮数沸滤出，分作两眼，米饮下，空心、日午各一服。（《圣济总录》附子丸） ⑨治脏寒脾泄，及老人中气不足，久泄不止：肉豆蔻二两（煨热），大附子（去皮脐）一两五钱。为末，粥丸，梧子大。每服八十丸，莲肉煎汤下。（《纲目》） ⑩治脾虚受湿发肿，一切虚肿：大附子十枚（生，削去皮，破四块），赤小豆半升，藏附子于中，慢火煮附子透熟软，去豆，焙干附子碾末，以薏苡仁粉打糊丸如梧子大。每服十丸，冬瓜汤或萝卜汤下。（《朱氏集验医方》） ⑾治肿疾喘满，肿因积得，既取积而肿再作，小便不利者：生附子一个（去皮脐，切片），生姜十片，入沉香一钱，磨水同煎，食前冷饮，小儿每服三钱，水煎服。（《朱氏集验医方》沉附汤） ⑿治风湿相搏，骨节疼烦掣痛，不得屈伸，近之则痛剧，汗出短气，小便不利，恶风不欲去衣，或身微肿者：甘草（炙）二两，附子（炮去皮，破）二枚，白术二两，桂枝（去皮）四两。上四味，以水六升，煮取三升，去滓温服一升，日三服。（《伤寒论》甘草附子汤） ⒀治少阴病，身体痛，手足寒，骨节痛，咏沉者：附子二枚（炮，去皮，破八片），茯苓三两，人参二两，白术四两，芍药三两。上五味以水八升，煮取三升，去滓，温服一升，日三服。（《伤寒论》附子汤） ⒁治中风偏废：附子一个（去皮脐），羌活、乌药各一两。上为粗末，每服四钱，水一盏，煎七分，去滓温服。（《简易方论》羌活散） ⒂治风寒流注，偏正头痛，年久不愈：大附子一个，生切四片，以姜汁一盏，浸炙，再浸再炙，汁尽乃止；高良姜，等分，为末。每服一钱，腊茶清调下，忌热物少时。（《三因方》必效散） ⒃治气虚头痛：大附子一枚，全蝎二枚（去毒），钟乳粉二（三）钱半。上用附子剜去心，安全蝎在附于内，却以全附为末，同钟乳粉面少许，水和作剂，包裹煨令熟，并为细末，葱涎为丸，如梧桐子大。每服七十丸，空心食前，同椒盐汤下。一作散，葱茶汤下。（《澹寮方》蝎附丸） ⒄治头痛：附子（炮）、石膏（煅）等分。为末，入脑、麝少许，茶酒下半钱。（《传家秘宝方》） ⒅治经侯不调，血脏冷痛：当归、附子（炮）各等分。为粗末。每服三钱，水一盏，煎至八分，空腹温服。（《简易方论》小温经汤） ⒆治吐血：生地黄一斤（净洗，细研取汁，其滓再入好酒少许，又取汁令尽），附子一两（炮，去皮脐，切片子，入地黄汁内，用银器熬成膏，取出附子焙干）。上以山药三两为末，以地黄膏子和成剂，丸如桐子大。每服三十丸，米饮空心服。（《朱氏集验医方》地黄丸） ⒇治肾气上攻，项背不能转侧：大附子一枚，六钱以上者，炮，去皮脐，末之。每末二大钱，好川椒二十粒，用白面填满，水一盏半，生姜七片，同煎至七分，去椒入盐，空心服。（《本事方》椒附散） （21）治小便不通，两尺脉俱沉微，用淋闭通滑之剂不效者：附子一两（重炮，去皮，盐水内浸良久），泽泻（不蛀者）一两。上锉散，每服四钱，水一盏半，灯心七茎，煎服。（《普济方》附子散） （22）少阴伤寒（初得二、三日，脉微细，但昏昏欲睡，小便白色）。用麻黄（去节）二两、甘草（炙）二两、附子（炮，去皮）一枚，水七升。先煮麻黄去沫，再加入其余二药，煮汁成三升，分作三次服下。令病人发微汗。引方名麻黄附子甘草汤。 （23）少阴发热（少阴病初得，反发热而脉沉）。用麻黄（去节）二两、附子（炮）去皮一枚、细辛二两，水一斗。先煮麻黄去沫，再加入其余二药，煮汁成三长，分作三次服下。令病人发微汗。此方名麻典附子细辛汤。 （24）少阴下利（下得清谷，里寒外热，手足厥逆，脉微欲绝。身不恶寒，反而面赤，或腹痛，或干呕，或咽痛）。用大附子一个（去皮，切成片）、甘草（炙）二两、干姜三两，加不沽升，煮成一升，分两次温服，脉出现即愈。面赤，加葱九根；腹痛，加芍药二两；干呕，加生姜二两；咽痛，加桔梗一两；利止，而脉不出，加人参二两。此方名脉四逆汤。 （25）阴病恶寒（伤寒已发汗，不解，反恶寒，是体虚的现象）。芍药三两、甘草（炙）三两、附子（炮，去皮）一枚，加水五程式，煮成一升五合。分次服下。此方名芍药甘草附子汤。 （26）阴盛格阳（病人躁热面饮水、脉沉、手足厥逆）。用大附子一枚，烧存性，研为末，蜜水调服。逼散寒气后使热气上升，汗出乃愈此方名霹雳散。 （27）中风痰厥（昏不积压人，口眼歪斜）。用生川乌头、生附子，都去掉皮脐，各取半两，和一南星一两，生木香二钱五分。各药混合后，每取五钱，加生姜十片、水二碗，煎成一碗温服。此方名五生饮。 （28）风病瘫缓（手足软垂，口眼歪斜，语音蹇涩，步履不正）。用川乌头（去皮脐），五灵脂各五两，共研为末，加龙脑、麝香温酒送下。一天服三次。服至五、七丸，便觉手能抬动。脚能移步，吃至十丸，可以梳头，此方名神验乌龙丹。 （29）风寒湿痹（麻木不仁，或手足不遂）。用香白米煮粥一碗，加入生川乌头末四钱，慢熬适当，下姜汗一匙、蜜三大匙，空腹服下。或加薏苡末二亦可。 （30）风痫。用生川乌头（去皮）二钱半、五灵脂半两，共研为末，加猪心血和成丸子，如梧子大。每服一丸，姜汤送下。 （31）小儿慢惊（抽筋，涎壅厥逆）。用生川乌头（去皮脐）一两、全蝎十个（去尾），分作三他，每服用水一碗、姜七片煎药饮下。 （32）小儿囟陷。用乌头附子（生，去皮脐）二鲷、雄黄八分，共研为末。以葱根捣和作饼巾2陷处。 （33）脚气肿痛。用黑附子一个（生，去皮脐），研为末，加生姜汁调成膏涂肿痛处。药干再涂，到肿消为止。 （34）多年头痛。用川乌头、天南星，等分为末，葱汁调涂太阳穴。 （35）耳鸣不止。用乌头（烧作灰）、菖蒲，等分为末棉花裹着塞耳内。一天换药两次。 （36）牙痛。用附子一两（烧灰）、枯矾一分，共研为末，擦牙。又方：川乌头、川附子，生三匣面糊成丸子，如小豆在。每次以制包一丸咬口中，又方；用炮附子末纳牙孔中，痛乃止。 （37）虚寒腰痛。用鹿茸（去毛，酥炙微黄）、附子（炮，去皮脐）各二两，盐花三分，共三工业区末，加枣肉和丸，如梧子大。每服三十丸，空心服，温酒送下。 （38）寒热疟疾。用附子一枚重五钱者，裹在面中火煨，然后去面，加人参、丹砂各一钱，共研为末，加炼蜜做成丸子，如梧子大。每服二十丸，未发病前连进三服。如药有效，则有呕吐现象或身体有麻木感觉，否则次日须再次服药。 （39）水泄久痢。用川乌头二枚，一枚生用，另一枚以黑豆半合同煮熟，一起研为丸，如绿豆大。每服五丸，黄连汤送下。 （40）阳虚吐血。用生地黄一斤，捣成汁，加酒少许。另以熟附子一两半，去皮脐，切成片，放入地黄汁内，石器中煮成膏，取出附片焙干，同山药三两研为末，再以膏调末成为丸子，如梧子大。每服三十丸，空心服，米汤送下。 （41）白浊。用熟附子研为末。每服二钱，加姜三片、水一碗煮至六成，温服。 （42）月经不调。用熟附子（去皮）当归等分。每服三钱，水煎服。 （43）痈疽肿毒辣。用川乌头（炒）、黄蘖（炒）各一两，研末唾液调涂患处。留头。药干则以淘米水润湿。 （44）疔疮肿痛。用醋和附子末涂患处。药干再涂。 （45）疥癣，用川乌头生切，煎水洗，甚验。 （46）手足冻裂。用附子去皮，研为末，以水、面调涂，有效。', tips='阴虚阳盛，真热假寒及孕妇均禁服。本品辛热燥烈，凡阴虚阳亢及孕妇忌用。反半夏、瓜蒌、贝母、白蔹、白及。因有毒，内服须经炮制。若内服过量，或炮制、煎煮方法不当，可引起中毒。 恶蜈蚣。畏防风、甘草、黄芪、人参、乌韭、大豆。 ②《品汇精要》：妊娠不可服。 ③《纲目》：畏绿豆、乌韭、童溲、犀角。忌豉汁、稷米。得蜀椒、食盐，下达命门。 ④《本草汇言》：若病阴虚内热或阳极似阴之证，误用之，祸不旋踵。' where id=1769; -- 附子
update herbs set taste='苦，寒。', channel='入膀胱、脾、肾经。', effect='①治皮水为病，四肢肿，水气在皮肤中，四肢聂聂动者：防已三两，黄芪三两，桂枝三两，茯苓六两，甘草二两。上五味，以水六升，煮取二升，分温三服。（防己茯苓汤，《金匮要略》） ②治风水脉浮，身重汗出恶风者：防己一两，甘草半两（炒），白术七钱半，黄芪一两一分（去芦）。上锉麻豆大，每抄五钱匕，生姜四片，大枣一枚，水盏半，煎八分，去滓。温服，良久再服。服后当如虫行皮中，从腰下如冰，后坐被上，又以一被绕腰下，温令微汗。（防己黄芪汤，《金匮要略》） ③治膈间支饮，其人喘满，心下痞坚，面色黧黑，其脉沉紧，得之数十日，医吐下之不愈：木防己三两，石膏十二枚（鸡子大），桂枝二两，人参四两。上四味，以水六升，煮取二升，分温再服。（木防己汤，《金匮要略》） ④治膀胱水蓄胀满，几成水肿：汉防己二钱，车前、韭菜子、泽泻各三钱。水煎服。（《本草切要》） ⑤治水臌胀：汉防己一两，生姜五钱。同炒，随入水煎服，半饥时饮之。（《本草汇言》） ⑥治脚气肿痛：汉防己、木瓜、牛膝各三钱，桂枝五分，枳壳一钱。水煎服。（《本草切要》） ⑦治肺痿喘嗽：汉防己为细末。每服三钱，浆水一盏，同煎至七分，和滓温服之。（《儒门事亲》） ⑧治肺痿咯血多痰者：汉防己、葶苈等分。为末。糯米饮，每服一钱。（《古今录验方》） ⑨治遍身虫癣瘑疥：汉防己三两，当归、黄芪各二两，金银花一两。煮酒饮之。（《本草切要》） ⑩治遗尿，小便涩：防己、葵子、防风各一两。上三味，以水五升，煮取二升半，分三服，散服亦佳。（《千金方》）', tips='阴虚而无湿热者慎服。 恶细辛。畏萆薢。杀雄黄毒。 ②《药性论》：木防己：畏女菀、卤咸。 ③李杲：上焦湿热者，不可用。 ④《本草经疏》：凡胃虚阴虚，自汗盗汗，口苦舌干，肾虚小水不利，及胎前产后血虚，虽有下焦置热，均忌。 ⑤《得配本草》：气分风热，小便不通，禁用。' where id=1770; -- 防己
update herbs set taste='甘淡，平。', channel='入心、脾经。', effect='①治心神不定，恍惚不乐:茯神二两（去皮），沉香半两。并为细末，炼蜜丸，如小豆大。每服三十丸，食后人参汤下。（《百一选方》朱雀丸） ②治心虚血少，神不守舍，多惊恍惚，睡卧不宁:人参（去芦头）、茯神（去木）、黄耆（蜜炙）、熟干地黄（洗，焙）、当归（洗，焙）、酸枣仁（去皮，炒）、朱砂（别研，一半入药，一半为衣）。上件各等分，为细末，炼蜜为丸，如梧桐子大。每服三十丸，煎人参汤下。（《杨氏家藏方》茯神丸） ③治虚劳烦躁不得眠:茯神（去木）、人参各一两，酸枣仁（炒，去皮，别研）五两。上三味粗捣筛。每服三钱匕，以水一盏，入生姜半分，拍碎，煎至七分，去滓，空腹温服，日二夜一。（《圣济总录》茯神汤）' where id=1771; -- 茯神
update herbs set taste='味甘；性平。', channel='入肺、牌、大肠经。', effect='①治咳嗽：白蜜一斤，生姜二斤（取汁）。上二味，先秤铜铫，知斤两讫，纳蜜复秤知数，次纳姜汁，以微火煎令姜汁尽，惟有蜜斤两在，止。旦服如枣大，含一丸，日三服。禁一切杂食。（《千金方》） ②治上气咳嗽，喘息，喉中有物，唾血：杏仁、生姜汁各二升，糖、蜜各-升，猪膏二合。上五味，先以猪膏煎杏仁黄，出之，以纸拭令净，捣如膏，合姜汁、蜜、糖等，合煎令可丸。服如杏核一枚，日夜六、七服，渐渐加之。（《千金方》） ③治阳明病，自汗出，若发汗，小便自利者，此为津液内竭，虽鞕不可攻之，当须自欲大便：食蜜七合。于铜器内，微火煎，当须凝如饴状，搅之勿令焦著，欲可丸，并手捻作铤，令头锐，大如指，长二寸许，当热时急作，冷则鞕。以纳谷道中，以手急抱，欲大便时乃去之。（《伤寒论》） ④治高血压，慢性便秘：蜂蜜一两八钱，黑芝麻一两五钱。先将芝麻蒸熟捣如泥，搅入蜂蜜，用热开水冲化，一日二次分服。（《现代实用中药》） ⑤治胃及十二指肠溃疡：蜂蜜一两八钱，生甘草三钱，陈皮二钱。水适量，先煎甘草、陈皮去渣，冲入蜂蜜。一日三次分服。（《现代实用中药》） ⑥治蛔虫病，吐涎心痛，发作有时，毒药不止：甘草二两，粉一两重，蜜四两。上三味，以水三升，先煮甘草取二升，去滓，纳粉、蜜，搅令和，煎如薄粥，温服一升，瘥即止。（《金匮要略》甘草粉蜜汤） ⑦治疔肿恶毒：生蜜与隔年葱研膏，先刺破涂之，如人行五里许，则疔出，后以热醋汤洗去。（《济急仙方》） ⑧治口疮：蜜浸大青叶含之。（《药性论》） ⑨治男子阴疮：蜜煎甘草末，涂之。（《肘后方》） ⑩治痘疮痒甚，误搔成疮，及疮痂欲落不落者：白蜜不拘多少，涂于疮上，其痂自落，且无疤痕，亦不臭秽。（《普济方》百花膏） ⑾治风疹，风癣：沙蜜一斤，糯饭一斤，面曲五两，熟水五升，同入瓶内封七日成酒，寻以蜜入酒代之，亦良。（《纲目》蜜酒） ⑿治热油烧外痛：白蜜涂之。（《梅师集验方》） ⒀治鼾：白蜜和茯苓，涂上。（《补缺肘后方》） ⒁解乌头毒：白蜂蜜每次一至四汤匙，温开水冲服。（《上海常用中草药》）' where id=1772; -- 蜂蜜
update herbs set taste='辛；温；无毒。', channel='入脾、胃经。', effect='①治反胃：灶中土，用十余年者，为细末，米饮调下三、二钱许。（《百一选方》） ②治心痛冷热：伏龙肝末，煮水服方寸匕。若冷，以酒和服，瘥。（《救急方》） ③治吐血、泻血，心腹痛：多年垩壁土、地炉中土、伏龙肝。上等分，每服一块如拳大，水二碗，煎一碗，澄清服，白粥补之。（《普济方》伏龙散） ④治吐血、鼻血不止：伏龙肝半升。以新汲水一大升，淘取汁和蜜顿服。（《广利方》） ⑤治下血先便后血：甘草、干地黄、白肃、附子（炮）、阿胶、黄芩各三两，灶中黄土半斤。上七味，以水八升煮取三升，分温二服。（《金匮要略》黄土汤） ⑥治妇人血露：炒伏龙肝半两，蚕沙一两，阿胶一两。同为末，温酒调，空肚服二、三钱，以知为度。（《本草衍义》） ⑦治产后血气攻心痛，恶物不下：灶中心土研末，酒服二钱，泻出恶物效。（《救急方》） ⑧治小儿丹毒：多年灶下黄土末，和屋漏水傅之，新汲水亦可，鸡子白或油亦可，干即易。（《肘后方》） ⑨治小儿重舌：灶月下黄土末，苦酒和涂舌上。（《千金方》） ⑩治小儿脐疮，久不瘥：伏龙肝，细研末敷之。（《圣惠方》） ⑾治臁疮久烂：灶内黄土（年久者研细末）、黄柏、黄丹、赤石脂、轻粉末等分。清油调，入油绢中贴之，勿动，纵痒，忍之良。（《济急仙方》） ⑿治聤耳：伏龙肝细研半两，以猪膏和拈如枣核大，绵裹塞耳中，日再易，夜一易。（《圣济总录》） ⒀治痈肿：伏龙肝以大酢和作泥，涂布上贴之，干则易之。（《千金翼方》）' where id=1773; -- 伏龙肝
update herbs set taste='甘；淡；平。', channel='入心、脾、肺经。', effect='①治太阳病，发汗后，大汗出，胃中干，烦躁不得眠，脉浮，小便不利，微热消渴者:猪苓十八铢（去皮），泽泻一两六铢，白术十八铢，茯苓十八铢，桂枝半两（去皮）。上五味，捣为散。以白饮和，服方寸匕，日三服。（《伤寒论》五苓散） ②治小便多、滑数不禁:白茯苓（去黑皮）、干山药（去皮，白矾水内湛过，慢火焙干）。上二味，各等分，为细末。稀米饮调服之。（《儒门事亲》） ③治水肿:白水（净）二钱，茯苓三钱，郁李仁（杵）一钱五分。加生姜汁煎。（《不知医必要》茯苓汤） ④治皮水，四肢肿，水气在皮肤中，四肢聂聂动者:防己三两，黄耆三两，桂枝三两，茯苓六两，甘草二两。上五味，以水六升，煮取二升，分温三服。（《金匮要略》防己茯苓汤） ⑤治心下有痰饮，胸胁支满目眩:茯苓四两，桂枝，白术各三两，甘草二两。上四味，以水六升，煮取三升，分温三服，小便则利。（《金匮要略》苓桂术甘汤） ⑥治卒呕吐，心下痞，膈间有水，眩悸者:半夏一升，生姜半斤，茯苓三两（一法四两）。上三味，以水七升煮取一升五合，分温再服，（《金匮要略》小半夏加茯苓汤） ⑦治飧泄洞利不止:白茯苓-两，南木香半两（纸裹炮）。上二味，为细末，煎紫苏木瓜汤调下二钱匕。（《百一选方》） ⑧治湿泻:白术一两，茯苓（去皮）七钱半。上细切，水煎一两，食前服。（《原病式》获苓汤） ⑨治胃反吐而渴，欲饮水者:茯苓半斤，泽泻四两，甘草二两，桂枝二两，白术三两，生姜四两。上六味，以水一斗，煮取三升，纳泽泻再煮取二升半，温服八合，日三服（《金匮要略》茯苓泽泻汤） ⑩治丈夫元阳虚惫，精气不固，余沥常流，小便白浊，梦寐频泄，及妇人血海久冷，白带、白漏、白淫，下部常湿，小便如米泔，或无子息（不育）:黄蜡四两，白茯苓四两（去皮、作块，用猪苓一分，同于瓷器内煮二十余沸，出，日干，不用猪苓）。上以茯苓为末，熔黄蜡为丸，如弹子大。空心细嚼，满口生津，徐徐咽服，以小便清为度。（《局方》威喜丸） ⑾治心虚梦泄，或白浊:白茯苓末二钱。米汤调下，日二服。（《仁斋直指方》） ⑿治心汗，别处无汗，独心孔一片有汗，思虑多则汗亦多，病在用心，宜养心血:以艾汤调茯苓末服之。（《证治要诀》） ⒀治下虚消渴，上盛下虚，心火炎烁，肾水枯涸，不能交济而成渴证:白茯苓一斤，黄连一斤。为末，熬天花粉作糊，丸梧桐子大。每温汤下五十丸。（《德生堂经验方》） ⒁治头风虚眩，暖腰膝，主五劳七伤:茯苓粉同曲米酿酒饮。（《纲目》茯苓酒） ⒂治皯:白蜜和茯苓涂上，满七日。（《补缺肘后方》）', tips='虚寒精滑或气虚下陷者忌服。恶白敛。畏牡蒙、地榆、雄黄、秦艽、龟甲。 ②《药性论》:忌米醋。 ③张元素:如小便利或数，服之则损人目。如汗多入服之，损元气。 ④《本草经疏》:病人肾虚，小水自利或不禁或虚寒精清滑，皆不得服。 ⑤《得配本草》:气虚下陷、水涸口干俱禁用。' where id=1774; -- 茯苓
update herbs set effect='1.治痰气咳嗽；陈佛手6-9g。水煎饮。方中佛手和胃化痰，为君药。（《闽南民间草药》） 2.治妇女白带：佛手15-30g，猪小肠1尺。水煎服。方中佛手行气，燥湿，疏肝解郁，为君药。（《闽南民间草药》） 3.佛手露（《全国中药成药处方集》）治胁肋疼痛，心烦易怒，胸闷不舒，嗳气泛恶，纳谷不香，消化不良等症：佛手120g，五加皮30g，木瓜、青皮各12g，栀子、陈皮各15g，良姜、砂仁、肉桂各9g，木香、公丁香各6g，当归18g，白酒20斤，冰糖5斤。上药为粗末，装入绢袋内，入酒浸，文火煮之，滤清入冰糖即成。每服约30g，1日3次。孕妇忌服。方中佛手行气止痛，和胃化痰，为君药。', tips='行气止痛，和胃化痰。用于胸胁胀满作痛，食欲不佳，呕吐，咳嗽痰多。' where id=1775; -- 佛手
update herbs set taste='苦，凉。', channel='归肝、肾经。', effect='①治肺痨：枸骨嫩叶一两。烘干，开水泡，当茶饮。（《湖南药物志》） ②治腰及关节痛：枸骨叶，浸酒饮。（《湖南药物志》）', tips='补肝肾，养气血，祛风湿。治肺劳咳嗽，劳伤失血，腰膝痿弱，风湿痹痛，跌打损伤。清热养阴，平肝，益肾。用于肺痨咯血，骨蒸潮热，头晕目眩；高血压。 ①《本草从新》：生津止渴，用叶代茶甚妙，祛风。 ②《本草拾遗》：枝叶烧灰，淋取汁，涂白癜风。亦可作稠煎敷之。 ③《本经逢原》：治劳伤失血痿软，能调养气血。 ④《中国药植志》：枝叶:和以亦糖、红枣或乌枣同煎煮，补肝肾，健腰膝。 ⑤《广西中药志》：治跌打，洗风湿。' where id=1776; -- 枸骨叶
update herbs set taste='味苦；甘；性凉。', effect='①治五劳七伤，房事衰弱：枸杞叶半斤（切），粳米二合。上件以豉汁相和，煮作粥，以五味末葱白等，调和食之。（《圣惠方》枸杞粥方） ②治阳气衰，腰脚疼痛，五劳七伤：枸杞叶一斤，羊肾一对（细切），米三合，葱白十四茎。上四味细切，加五味煮粥，如常法，空腹食。（《圣济总录》枸杞羊肾粥） ③治急性结膜炎：枸杞叶二两，鸡蛋一只。稍加调味，煮汤吃，每日一次。（广西《中草药新医疗法处方集》） ④治跟涩痛，兼有翳者：枸杞叶二两，车前叶二两。上件药熟挼之，使汁欲出，又别取大桑叶三两，重裹之，悬于阴地，经宿，乃轻压取汁，点目中，不过三，五度瘥。（《圣惠方》枸杞汁点眼方） ⑤治视力减退及夜盲：枸杞菜二两，柄猫草一两，夜明砂三钱，猪肝四两。水煎服。（《陆川本草》） ⑥治痔疮炎肿：鲜枸杞茎叶一握。煎汤熏洗。（《福建民间草药》） ⑦治年少妇人白带：枸杞尖作菜，同鸡蛋炒食。（《滇南本草》）' where id=1777; -- 枸杞叶
update herbs set taste='苦甘，寒，有毒。', channel='归肺、肾、大肠经。', effect='①治卒肿满，身面皆洪大：甘遂一分，粉之，猪肾一枚，分为七脔，入甘遂于中，以火炙之令熟。日一食，至四，五，当觉腹胁鸣，小便利。（《补缺肘后方》） ②治水肿腹满：牵牛子半两（生用），甘遂（微炒）一钱。上二味粗捣筛，分作二服。每服，水一盏，煎至五分，放温细呷，不计时。（《圣济总录》二气汤） ③治卒身面浮肿，上气喘息：甘遂半两（煨令微黄），蒜瓣半两（煨熟，研），黑豆半两（炒热）。上药除蒜外，捣罗为末，用蒜并枣肉和丸，如梧桐子大。每服以木通汤下十丸，日二服。（《圣惠方》甘遂丸） ④治太阳中风，下利，呕逆，表解里来和，其人漐漐汗出，发作有时，头痛，心下痞粳满，引胁下痛，干呕短气，汗出不恶寒：芫花（熬）、甘遂、大戟。上三味，等分，各别捣为散，以水一升半，先煮大枣肥者十枚，取八合，去滓，纳药末。强人服一钱匕，羸人服半钱，温服之，平且服。若下少，病不除者，明日更服，加半钱，得快下利后，糜粥自养。（《伤寒论》十枣汤） ⑤治病者脉伏，其人欲自利，利反快，虽利，心下续坚满，此为留饮欲去故也：甘遂（大者）三枚，半夏十二枚（以水一升，煮取半升，去滓），芍药五枚，甘草如指大一枚（炙）。上四味，以水二升，煮取半升，去滓，以蜜半升，和药汁煎取八合，顿服之。（《金匮要略》甘遂半夏汤） ⑥治风热喘促，闷乱不安，俗谓之马脾风者：辰砂二钱半，轻粉半钱，甘遂一钱半（面襄煮，焙干）。上为细末，每服一字，用温浆水少许，上滴油一小点，抄药在上，沉下去，却以浆水灌之。（《田氏保婴集》无价散） ⑦治风痰迷心癫痫，及妇人心风血邪：甘遂二钱，为末，以猪心取三管血，和药，入猪心内，缚定，纸裹煨熟，取末，入辰砂末一钱，分作四丸。每服-丸，将心煎汤调下，大便下恶物为效，不下再服。（《济生方》遂心丹） ⑧治膈气哽噎：甘遂（面煨）五钱，南木香一钱，为末，壮者一钱，弱者五分，水酒调下。（《怪证奇方》） ⑨妇人少腹满如敦状，小便微难而不渴，生后者，此为水与血俱结在血室也：大黄四两，甘遂二两，阿胶二两。上三味，以水三升，煮取一升，顿服之，其血当下。（《金匮要略》大黄甘遂汤） ⑩治宿食结于肠间，不能下行，大便多日不通。其证或因饮食过度，或因恣食生冷，或因寒火凝结，或因吐泻既久，胃气冲气，皆上逆不下降：生赭石二两（轧细），朴硝五钱，干姜二钱，甘遂钱半（轧细药汁送服）。热多者，去干姜；寒多者，酌加干姜数钱；呕多者，可先用赭石一两，干姜半钱煎服，以止其呕吐。呕吐止后，再按原方煎汤，送甘遂末服之。（《医学衷中参西录》） ⑾治二便不通：甘遂末以生面糊调，敷脐中及丹田内，仍艾灸三壮，饮甘草汤，以通为度。（《圣惠方》） ⑿治小便转脬：甘遂末一钱，猪苓汤调下。（《卫生杂兴》） ⑶治麻木疼痛：甘遂二两，蓖麻仁四两，樟脑一两。捣作饼贴之，内饮甘草（汤）。（《摘元方》万灵膏） ⒁治消渴：甘遂半两（用麸炒透里黄褐色），黄连（去须）一两。上件为细末，水漫蒸饼为丸，如绿豆大。每服二丸，薄荷汤下，不拘时候。忌甘草三日。（《杨氏家藏方》缩水丸） ⒂治偏肿：茴香、甘遂。上二味，各等分，为末。酒调二钱，食前服之。（《儒门事亲》） ⒃治脚气肿痛，肾脏风气，攻注下部疮痒：甘遂半两，木鳖子四个。为末，猪腰子一个，去皮膜，切片，用药四钱，掺在内，涅纸包，煨熟，空心食之，米饮下，服后须伸两足，大便行后，吃白粥二、三日为妙。（《本事方》）', usage='', tips='气虚、阴伤、脾胃衰弱者及孕妇忌服。体弱及孕妇禁用；不宜与甘草同用。 气虚、阴伤、脾胃衰弱者及孕妇忌服。体弱及孕妇禁用；不宜与甘草同用。' where id=1778; -- 甘遂
update herbs set taste='苦，温。', channel='入肝、肾经。', effect='①治腰脚疼痛不止：骨碎补一两，桂心一两半，牛膝三分（去苗），槟榔二两，补骨脂三两（微炒），安息香二两（入胡桃仁捣熟）。捣罗为末，炼蜜入安息香，和捣百余杵，丸如梧桐子大。每于食前，以温酒下二十丸。（《圣惠方》） ②治耳鸣，亦能止诸杂痛：骨碎补去毛细切后，用生蜜拌，蒸，从巳至亥，暴干，捣末，用炮猪肾空心吃。（《雷公炮炙论》） ③治肾虚耳鸣耳聋，并齿牙浮动，疼痛难忍：骨碎补四两，怀熟地、山茱萸，茯苓各二两，牡丹皮一两五钱（俱酒炒），泽泻八钱（盐水炒）。共为末，炼蜜丸。每服五钱，食前白汤送下。（《本草汇言》） ④治牙痛：鲜槲蕨一至二两（去毛）。打碎，加水蒸服。勿用铁器打煮。（《单方验方调查资料选编》） ⑤治金疮，伤筋断骨，疼痛不可忍：骨碎补（去毛，麸炒微黄）、自然铜（细研）、虎胫骨（涂酥炙黄）、败龟（涂酥炙微黄）各半两，没药一两，上件药，捣细罗为散。每服一钱，以胡桃仁半个，一处嚼烂，用温酒一中盏下之，日三、四服。（《圣惠方》骨碎补散） ⑥治打扑伤损：胡狲姜不以多少，生姜半之。上同捣烂，以罨损处，用片帛包，干即易之。（《百一选方》） ⑦接骨续筋：骨碎补四两，浸酒一斤，分十次内服，每日二次；另晒干研末外敷。（《泉州本草》） ⑧治挫闪：骨碎补二两，杵烂，同生姜母、菜油、茹粉少许，炒敷患处。（《闽东本草》） ⑨治关节脱位，骨折：在关节复位或正骨手术后，取槲蕨（去毛）和榔榆皮捣烂，加面粉适量，捣成糊状，敷伤处，二至三日换药一次。（《浙江民间常用草药》） ⑩治跌打损伤，腰背、关节酸痛：槲蕨（去毛）五钱至一两。水煎服。（《浙江民间常用草药》） ⑾治阑尾炎：鲜槲蕨（去毛）八两，切碎，加大血藤五钱，红枣四两。水煎服。（《浙江民间常用草药》） ⑿治斑秃：鲜槲蕨五钱，斑蝥五只，烧酒三两，浸十二天后，过滤擦患处，日二至三次。（《福建中草药》）' where id=1779; -- 骨碎补
update herbs set taste='苦；涩；微寒；有小毒。', channel='入肝、胃经。', effect='①解一切诸热毒，或中食毒、酒毒、药毒等：贯众、黄连、甘草各三钱，骆驼峰五钱。上为细末。每服三钱，冷水调下。（《普济方》贯众散） ②预防麻疹：贯众五钱，银花五钱，鬼灯笼三钱。水煎服，连服五剂以上，每日服一剂。（《陆川本草》） ③治钩虫病：贯众三两，苦楝皮、山紫苏、土荆芥各五钱。煎汤，成人-次服用。（《中医杂志》（3）:3，1959） ④治蛔虫攻心，吐如醋水，痛不能止：贯众一两，鹤虱一两（纸上微炒），狼牙一两，麝香一钱（细研），芜荑仁一两，龙胆一两（去芦头）。上药捣细罗为散。每于食前以淡醋汤调下二钱。（《圣惠方》贯众散） ⑤治钩虫病：㈠贯众三斤，黄荆叶二斤，蜂蜜六斤四两，槟榔、鹤虱各半斤，霍丸四两；㈡贯众三斤，黄荆叶二斤，蜂蜜六斤，陈皮一斤；㈢贯众三斤，黄荆叶二斤，蜂蜜七斤，槟榔、榧子各半斤，雷丸三两，鹤虱四两。各方制法，均是各研细末，充分和匀，先将蜂蜜熬至滴水结块为度，搅拌药粉，放在清洁捣臼里捣二千杵左右，制丸。每丸潮重二钱五分左右。均在晚饭后一至二小时服，十至十二岁，一次服四丸；十三至十六岁，服六丸；十六岁以上服八丸。（《浙江医学》2（9）:384，1961） ⑥治疮疹出快肥红：贯众一两（拣，洗净，焙干），赤芍药一两，甘草半两，川升麻半两，枳壳（麸炒，去穰）半两。上为末。每服-钱，水一小盏，入竹叶七片，煎至五分，去滓温服，无时。（《小儿卫生总微论方》快斑散） ⑦治年深咳嗽，出脓血：贯众、苏方木等分。每服三钱，水一盏，生姜三片，煎服，日二服。（《圣惠方》） ⑧预防流行性感冒：㈠贯众每天三钱。水煎，分二次服，儿童酌减。（湖北《中草医药经验交流》）；㈡贯众三钱，南瓜蔓一尺。水煎服，可连服三日。（内蒙古《中草药新医疗法资料选编》） ⑨预防流行性脑脊髓膜炎：贯众二两，雄黄三钱，生明矾八钱。放入饮水缸内，作饮水消毒用，七天换一次。（《全展选编。爱国卫生》） ⑩治久咳渐成劳瘵：凤尾草为末，用鱼鲊蘸食之。（《圣惠方》） ⑾治暴吐血嗽血：贯众一两，黄连（去须）年老者半两、年少者三分。上二味捣罗为细散，每服二钱匕，浓煎糯米饮调下。（《圣济总录》贯众散） ⑿治鼻大衄：贯众根为末，水调服一钱匕。（《本草图经》） ⒀治吐血成斗，命在须臾：管仲二钱（净末），血余五钱（烧灰），侧柏叶（捣汁）一碗.上将药末两味、入柏汁内搅匀，于大碗内盛之，重汤煮一炷香时，取出待温，入童便一小盅，黄酒少许，频频温服。（《万病回春》管仲汤） ⒁治肠风便血，久痢下血水，妇人崩淋沥血，并积年白带：贯众一分（酒漫一日，连须并内肉，俱切碎，曝干，微炒），黑蒲黄、丹参各减半（俱酒洗，炒）。共为末。每早晚食前白酒下。（《本草汇言》） ⒂治肠风酒痢下血及鼠于痔出血、血痔：贯仲二两。去芦头，烧灰存性，用瓦合地上去火毒，为末，入麝香一字研匀。米饮调服二钱。（《普济方》经效散） ⒃治血痢不止：凤尾草根五钱。煎酒服。（《濒湖集简方》） ⒄治妇人崩漏：管仲同米炒。每服二钱，酒、醋下。（《海上方》） ⒅治崩漏血色紫而有块，少腹胀痛，脉沉，有瘀血者：贯众、五灵脂各三钱。均炒黑研末。用水冲服。（《中医杂志》（6）:224，1961） ⒆治功能性子宫出血，对消化道出血、尿血、小量咯血亦有疗效：贯众炭一两，乌贼骨四钱。共为细末，打片，加阿胶一钱，每片0.5克。每日三次，每次八片。（《教育革命简报》1:33，1972） ⒇治产妇恶露d淋沥，体倦面黄，食少恶寒，昼夜不寐，惊悸汗出:贯众（醋蘸炙干）为末。每服二钱，米饮调下。（《妇人良方》） (21)治漆疮：贯众，治末以涂上，干以油和之。（《千金方》） (22)治便毒肿痛：贯众，酒服二钱。（《多能鄙事》） (23)治火烧疮：贯众煅灰，和香油调涂，止痛。（《岭南采药录》） (24)解轻粉毒，齿缝出血臭肿：贯众、黄连各半两。煎水，入冰片少许，时时漱之。（《积德堂经验方》） (25)治骨鲠：缩砂仁、甘草、贯众等分。上捣为粗末。如一切鲠，以绵裹少许含之，旋旋咽津，久则随痰出。（《普济方》缩砂散） (26)治流行性感冒、腮腺炎，乙型脑炎，病毒性肝炎等病毒性疾患：贯众9g，大青叶、板蓝根、紫草根各15g，山豆根、茵陈各9g，桔梗、甘草各6g。水煎，每日分2-3次服。方中贯众清热解毒，为君药。（《中药临床应用》抗毒汤）', tips='阴虚内热及脾胃虚寒者不宜，孕妇慎用。 ①《药性论》：赤小豆为使。 ②《云南中草药》：孕妇忌服。 ④《本草经疏》：病人虚寒无实热者禁用。' where id=1780; -- 贯众
update herbs set alias='白姜、均姜、干生姜。', taste='味辛；性热。', channel='入脾、胃、肺经。', effect='①治卒心痛：干姜末，温酒服方寸匕，须臾，六、七服，瘥。（《补缺肘后方》） ②治少阴病，下利清谷，里寒外热，手足厥逆，脉微欲绝，身反不恶寒，其人面色赤，或腹痛，或干呕，或咽痛，或利止脉不出者：甘草二两（炙），附子大者一枚（生用，去皮，破八片），干姜三两（强人可四两）。上三味，以水三升，煮取一升二合，去滓，分温再服，其脉即出者愈。（《伤寒论》通脉四逆汤） ③治中寒水泻：干姜（炮）研末，饮服二钱。（《千金方》） ④治头目旋晕吐逆：川干姜二两（炮），甘草一两（炙赤色）。上二味，为粗末。每服四、五钱，用水二盏，煎至八分，食前热服。（《传信适用方》止逆汤） ⑤治妊娠呕吐不止：干姜、人参各一两，半夏二两。上三味，末之，以生姜汁糊为丸，如梧子大。每服十丸，日三服。（《金匮要略》干姜人参半夏丸） ⑥治伤寒下之后，复发汗，昼日烦躁不得眠，夜而安静，不呕不渴，无表证，脉沉微，身无太热者：干姜一两，附子一枚（生用，去皮，切八片）。二味以水三升，煮取一升，去滓，顿服。（《伤寒论》干姜附子汤） ⑦治脾寒疟疾：㈠干姜、高良姜等分。为末。每服一钱，水一盏，煎至七分服。㈡干姜炒黑为末，临发时以温酒服三钱匕。（《外台》） ⑧治寒痢青色：干姜切豆大，海米饮服六、七枚，日三夜一。（《补缺肘后方》） ⑨治吐血不止：干姜为末，童子小便调服一钱。（《千金方》） ⑩治吐、下血：当归、阿胶各八分，川芎五分，蒲黄一钱，柏叶一钱五分，炒姜炭七分。上水煎，百草霜末点服。（《观聚方要补》断红饮） ⑾治脾胃虚弱，饮食减少，易伤难化，无力、肌瘦：干姜（频研）四两，以白饧切块，水浴过，入铁铫溶化，和丸梧子大。每空心米饮下三十丸。（《十便良方》） ⑿治肾若之病，其人身体重，腰中冷，如坐水中，形如水状，反不渴，小便自利，饮食如故，病属下焦，腰以下冷痛，腹重如带五千钱：甘草、白术各二两，干姜、茯苓各四两。上四味，以水五升，煮取三升，分温三服。（《金匮要略》干姜苓术汤） ⒀治暴赤眼：白姜末，水调，贴脚心。（《普济方》） ⒁治痈疽初起：干姜一两。炒紫，研末，醋调敷周围，留头。（《诸症辨疑》）' where id=1781; -- 干姜
update herbs set taste='甘，寒。', channel='入肺、胃经。', effect='①治发热口干，小便涩：甘蔗，去皮尽令吃之，咽汁。若口痛，捣取汁服之。（《外台》） ②治胃反，朝食暮吐，暮食朝吐，旋旋吐者：甘蔗汁七升，生姜汁一升。二味相和，分为三服。（《梅师集验方》） ③治卒干呕不息：蔗汁，温令热，服一升，日三。（《补缺肘后方》） ④治虚热咳嗽，口干涕唾：甘蔗汁一升半，青粱米四合。煮粥，日食二次，极润心肺。（《纲目》）' where id=1782; -- 甘蔗
update herbs set taste='性温，味苦、甘。', channel='入肝、肾经。', effect='①治五种腰痛，利脚膝：狗脊二两，萆薢二两（锉），兔丝子一两（酒浸三日，曝干别捣）。上药捣罗为末，炼蜜和丸，如梧桐子大。每日空心及晚食前服三十丸，以新萆薢渍酒二七日，取此酒下药。（《圣惠方》狗脊丸） ②治男女一切风疾：金毛狗脊（盐泥固济，火煅红，去毛用肉，出火气，剉）、萆薢、苏木节、川乌头（生用）。上各等分，为细末，米醋糊为丸，如梧桐子大，每服二十丸，温酒或盐汤下。病在上，食后服；病在下，空心服。（《普济方》四宝丹） ③治风湿骨痛、腰膝无力：金毛狗脊根茎六钱，香樟根、马鞭草各四钱，杜仲、续断各五钱，铁脚威灵仙三钱，红牛膝二钱。泡酒服。（《贵州草药》） ④固精强骨：金毛狗脊、远志肉、白茯神、当归身等分。为末，炼蜜丸，梧子大。每酒服五十丸。（《濒湖集简方》） ⑤治病后足肿：用狗脊煎汤渍洗。并节食以养胃气。（《伤寒蕴要》） ⑥治腰痛及小便过多：金毛狗脊、木瓜、五加皮、杜仲。煎服。（《四川中药志》） ⑦治年老尿多：金毛狗脊根茎、大夜关门、蜂糖罐根、小棕根各五钱。炖猪肉吃。（《贵州草药》） ⑧治室女冲任虚寒、带下纯白：鹿茸（醋蒸，焙）二两，白蔹、金毛狗脊（燎去毛）各一两。上为细末，用艾煎醋汁，打糯米糊为丸，如桐子大。每服五十丸，空心温酒下。（《普济方》白蔹丸）', tips='阴虚有热，小水不利或短涩赤黄，口苦舌干皆忌之。 ②《本草经疏》：肾虚有热，小水不利或短涩赤黄，口苦舌干皆忌之。 ③《本草汇言》：肝虚有郁火忌用。' where id=1783; -- 狗脊
update herbs set taste='味辛；性湿。', channel='入膀胱经。', effect='①治寒邪郁于足太阳经，头痛及巅顶痛：藁本、川芎、细辛、葱头。煎服。（《广济方》） ②治一切风偏正头痛，鼻塞脑闷，大解伤寒及头风，遍身疮癣，手足顽麻：川芎、细辛、白芷、甘草、藁本各等分。为末，每药四两，入煅了石膏末一斤，水和为丸，每一两作八丸。每服一丸，食后薄荷茶嚼下。（《普济方》白龙丸） ③治胃痉挛、腹痛：藁本五钱，苍术三钱，水煎服。（《新疆中草药手册》） ④治疥癣：藁本煎汤浴之，及用浣衣。（《小儿卫生总微论方》） ⑤干洗头屑：藁本、白芷等分。为末，夜掺发内，明早梳之，垢自去。（《便民图纂》） ⑥治鼻上面上赤：藁本研细末，先以皂角水擦动赤处，拭干，以冷水或蜜水调涂，干再用。（《鸡峰普济方》藁本散）' where id=1784; -- 藁本
update herbs set taste='味辛；甘；性温。', channel='入脾、胃经。', effect='①治各种肠胃疼痛：甘松香、木香、厚朴。煎服。（《四川中药志》） ②治神经性胃痛：甘松香、香附、沉香。煎服。（《四川中药志》） ③治痰眩：半夏曲、天南星各二两，甘松一两，陈橘皮一两半。上为细末，水煮面和为丸，如梧桐子大。每服二十丸，生姜汤下，食后。（《鸡峰普济方》松香丸） ④治癔病，神经衰弱，肠胃痉挛等：甘松六钱，广皮一钱半。水500毫升，浸于沸水内三小时（每半小时内煮沸一次）。分十二次服，日服六次。（江西《中草药学》） ⑤治肾虚齿痛：甘松、硫黄等分。为细末，百沸汤泡，漱口。（《普济方》） ⑥治湿脚气，收湿拔毒：甘松、荷叶心、藁本。三味煎汤，洗之。（《普济方》甘松汤）' where id=1785; -- 甘松
update herbs set taste='味酸；甘；性寒。', channel='归肺；肾经。', effect='①治百日咳：酸浆果实，瓦上烧存性。每服一分，白砂糖送下。（《江西中医药》（3）：22，1953） ②治喉炎：天泡果研末一钱，加冰片一分，吹喉部。（《贵阳民间药草》） ③治尿结石：天泡果五钱，龙胆一钱，草药（红茯苓）三钱.香樟根一钱，生车前草五钱。煎水服。（《贵阳民间药草》） ④治天泡湿疮：天泡草铃儿生捣敷之，亦可为末，油调敷。（《卫生杂兴》） ⑤治天蛇头（指尖痛）：天泡果套在指上患处。（《贵阳民间药草》）' where id=1786; -- 挂金灯
update herbs set alias='蘖米，谷蘖，稻蘖，稻芽。', taste='味甘、平。', channel='入脾、胃经。', effect='①启脾进食：谷蘖四两，为末，入姜汁、盐少许，和作饼，焙干；入炙甘草、砂仁、白术（麸炒）各一两。为末，白汤点服之，或丸服。（《澹寮方》谷神丸） ②脾胃虚弱泄泻：茯苓、芡实、建曲、查肉、扁豆、泽泻、谷芽、甘草。（《麻疹集成》健脾止泻汤） ③消食，健脾，开胃，和中，生津液，益元气。治病后脾土不健者：谷芽蒸露，用以代茶。（《中国医学大辞典》谷芽露） ④启脾进食：谷芽120g，为末，入姜汁、盐少许，和作饼烘干；入炙甘草、砂仁、白术（麸炒）各30g。为末，白汤点服之，或丸服。方中谷芽消食健脾，为君药。谷神丸（《金匮要略》） ⑤外感风滞方（《中药临床应用》）治小儿外感风滞，有呕吐，发热者：谷芽15g，藿香6g，蝉蜕、防风各4.5g，云苓9g，苏梗15g，薄荷（后下）3g，川连2.1g。水煎服。方中谷芽消食健脾，为君药。' where id=1787; -- 谷芽
update herbs set taste='味辛；性热。', channel='入脾，胃经。', effect='①治卒心腹绞痛如刺，两胁支满，烦闷不可忍：高良姜五两，厚朴二两，当归、桂心各三两。上四味，以水八升，煮取一升八合，分三服，日二。若一服痛止，便停，不须再服，若强人为二服，劣人分三服。（《千金方》高良姜汤） ②养脾温胃，去冷消痰，大治心脾疼痛，宽胸下气，进美饮食，疗一切冷物所伤：良姜（去芦）、干姜（炮）等分。上为细末，面糊为丸，如梧桐子大。每服十五丸至二十丸，食后橘皮汤下。妊娠妇人忌服。（《局方》二姜丸） ③治心脾痛：高良姜、槟榔等分，各炒。上为细末，米次调下。（《百一选方》） ④治心口一点痛，乃胃脘有滞或有虫，多因恼怒及受寒而起，遂致终身不瘥：高良姜（酒洗七次，焙，研）、香附子（醋洗七次，焙，研）。上二味，须要各焙、各研、各贮。如病因寒而得者，用高良姜二钱，香附末一钱；如病因怒而得者，用高良姜一钱，香附末二钱，如因寒怒兼有者，用高良姜一钱五分，香附末一钱五分，以米饮汤加入婪汁一匙，盐一撮，为丸服之。（《良方集腋》良附丸） ⑤治霍乱吐痢腹痛：高良姜，火炙令焦香。每用五两，打破，以酒一升，煮取三、四沸，顿服。（《备急方》） ⑥治霍乱呕吐不止：高良姜（生锉）一味，粗捣筛。每服三钱匕，水一盏，枣一枚（去核），煎至五分，去滓，用水沉冷，顿服。（《圣济总录》冰壶汤） ⑦治诸寒疟疾：良姜、白姜各等分。二味火上煅，留性，为末。每服三钱，雄猪胆一个，水一盏，温和胆汁调下。（《续本事方》） ⑧治风牙疼痛，不拘新久，亦治腮颊肿痛：良姜一块（约二寸），全蚂一枚（瓦上焙干）。上为末。以手指点药，如齿药用，须擦令热彻，须臾吐出少涎，以盐汤漱口。（《百一选方》逡巡散） ⑨脚气欲吐（患脚气病的人，容易发吐。日常生活，注意早餐多食，午餐少食，晚餐不食，或喝一点豉粥。有发吐感觉时，立即服药）。用高良姜一两，加水三升，煮成一升，一次服完。如急切间找不到高良姜，可以母姜一两代替，清水煎服。疗效较差，然亦有效。 ⑩心脾冷痛（按：即胃痛）。用高良姜四两，切片，分成四份：一两以陈米半合炒黄，去米；一两以陈壁土半两炒黄，去土；一两以巴豆三十四个炒黄，去豆；一两以斑蝥三十四个炒黄，去蝥。另取吴茱萸一两，酒浸一夜后，同高良姜一起再炒，共研为末，以浸吴茱萸的酒调药做成丸子，如梧子大。每服十五丸，空心服，姜汤送下。此方名高良姜丸。又方：高良姜三钱，五灵脂六钱，共研为末。每服三钱，醋汤调下。 ⑾养脾温胃，去冷消痰，宽胸下气。用高良姜、干姜等分，炮过，研细，加面糊做成丸子，如梧子大。每服十五丸，饭后服，桔皮汤送下。妊妇忌服。 ⑿脾虚寒疟（寒多热少，不思饮食）。用高良姜（麻油炒）、干姜（炮）各一两，共研为末。每服五钱，以猪胆汁调成膏子，临发病前，热酒调服。又方：上方所制的药末，加胆汁和丸，每服四十丸，酒送下。又方：高良姜、干姜，半生半炮各半两，穿山四三钱，共研为末。每服二钱，猪肾煮酒送下。 ⒀双目突然红痛。用小管吹高良姜末入鼻。使打喷嚏，红痛即消。 ⒁治产后却，腹痛阵作，或如锥刀所刺，洞泻肠鸣：良姜、当归、桂心、芍药、附子、川芎各10g，甘草5g。水煎，每日1剂，分2次服。方中高良姜散热止痛，为君药。（《产育宝庆集》调中汤） ⒂治肝郁气滞，胃有寒凝之胃脘痛，胸闷胁痛，经痛等：高良姜（酒洗，烘研）、香附（醋洗，烘研）各3g。为末，以米饮汤加入生姜汁1匙，盐1点为丸，每服6g，每日2次，温水下。方中高良姜散热止痛，行气，为君药。（《良方集腋》良附丸） ⒃治餐食生冷，久为积：良姜、辣桂、香附、乌药、益智仁各30g，甘草15g。上为末，每服6g，入少许盐沸汤点服。方中高良姜温中行气，为君药。(《直指方论》鸡舌香散)' where id=1788; -- 高良姜
update herbs set alias='暂美草、蜜甘，蜜草、蕗草，国老（陶弘景），灵通，粉草，甜草，甜根子，棒草。', taste='甘，平。', channel='入脾、胃、肺经。', effect='①治荣卫气虚，脏腑怯弱，心腹胀满，全不思食，肠鸣泄泻，呕哕吐逆：人参（去芦）、茯苓（去皮）、甘草（炙）、白术各等分。上为细末，每服二钱，水一盏，煎至七分，通口服，不拘时。入盐少许，白汤点亦得。（《局方》四君子汤） ②治肺痿吐涎沫而不咳者：甘草四两（炙），干姜二两（炮）。上药细切，以水三升，煮取一升五合，去滓，分温再服。（《金匮要略》甘草干姜汤） ③治热嗽：甘草二两，猪胆汁浸五宿，漉出炙香，捣罗为末，炼蜜和丸，如绿豆大，食后薄荷汤下十五丸。（《圣济总录》凉膈丸） ④治伤寒脉结代，心动悸：甘草（炙）四两，生姜（切）三两，人参二两，生地黄一斤，桂枝（去皮）三两，阿胶二两，麦门冬（去心）半斤，麻仁半升，大枣（擘）三十枚。右九味，以清酒七升，水八升，先煮八味，取三升，去滓，内胶烊消尽，温服一升，日三服。（《伤寒论》炙甘草汤，一名复脉汤） ⑤治少阴病二、三日，咽痛，与甘草汤不差者：桔梗一两。甘草二两。上二味，以水三升，煮取一升，去渣，温分再服。（《伤寒论》桔梗汤） ⑥治失眠、烦热、心悸：甘草一钱，石菖蒲五分至一钱。水煎服。每日一剂，分二次内服。（江西赣州《草医草药简便验方汇编》） ⑦治疟疾：甘草二份，甘遂一份。共研细末，于发作前二小时取用一分放肚脐上，以胶布或小膏药贴之。（徐州市《单方验方新医疗法选编》） ⑧治胃及十二指肠溃疡：㈠瓦楞子五两（煅研细末），甘草一两（研细末）。混匀，每服2钱，每日3次。（辽宁（中草药新医疗法资料选编》甘楞散）㈡甘草粉1.0克，鸡蛋壳粉1.5克，曼陀罗叶粉0.05克。混匀，饭前或痛时服，每服3克，日服三次。（辽宁《中草药新医疗法资料选编》甘壳散） ⑨治妇人脏躁，喜悲伤，欲哭，数欠伸：甘草三两，小麦一升，大枣十枚。上三味，以水六升，取三升，温分三服。亦补脾气。（《金匮要略》甘麦大枣汤） ⑩治痘疮烦渴：粉甘草（炙）、栝楼根等分。水煎服之。（《仁斋直指方》） ⑾治婴儿目涩，月内目闭不开，或肿，羞明，甚至出血者，名慢肝风：甘草一截，以猪胆汁炙，为末，每用米泔调和少许灌之。（《幼幼新书》） ⑿治汤火灼疮：甘草煎蜜涂。（《怪证奇方》） ⒀治阴下湿痒：甘草一尺，并切，以水五升，煮取三升，渍洗之，日三、五度。（《养生必用方》） ⒁治农药（1059、1605、4049等有机磷制剂）中毒：甘草四两，滑石粉五钱。用时将甘草煎汤，冷后冲滑石粉顿服。一日连服三次。（徐州市《单方验方新医疗法选编》） ⒂治饮馔中毒，中砒毒：甘草伴黑豆煮汁，恣饮无虞。（《本草蒙筌》）', tips='实证中满腹胀忌服。不宜与甘遂、大戟、芫花、海藻同用。 ①《药品化义》：味厚而太甜，补药中不宜多用，恐恋膈不思食也。 ②《本草正》：中满者勿加，恐其作胀，速下者勿入，恐其缓功。恶远志。反大戟、芫花、甘遂、海藻四物。 ④《医学入门》：痢疾初作，不可用。' where id=1789; -- 甘草
update herbs set taste='性寒，味甘，微苦。', channel='归肺、胃、大肠经。', effect='①治胸痹喘息咳唾，胸背痛，短气，寸口脉沉而迟，关上小紧数者：瓜蒌实24g，薤白12g，白酒适量。水煎，分两次服。方中瓜蒌涤痰散结，宽胸利膈，为君药。（《金匮要略》瓜蒌薤白白酒汤） ②治产后口渴：瓜蒌12g，麦门冬、人参、干地黄各9g，炙甘草6g，土瓜根15g，大枣20枚。水煎，分3次服。方中瓜蒌配伍诸药有清热化痰，利咽喉滑肠等功效。（《外台秘要》瓜蒌汤） ③治乳痈及各种痈疽：瓜蒌1个，金银花、当归各9g，炒乳香、炒没药、甘草、青皮各1.5g，白芷3g。水煎服。方中瓜蒌配伍金银花等治乳痈初起，红肿热痛。（《傅青主女科》瓜蒌散）', tips='不宜与乌头类药材同用。 恶干姜。畏牛膝、干漆。反乌头。” ②《本草便读》：“冷滑大肠，脾虚无火、大便不实者不可用。” ③《本经逢原》：“脾胃虚及呕吐自利者不可用。”' where id=1790; -- 瓜蒌
update herbs set taste='辛，温，有毒。', channel='入肝、脾经。', effect='①治妇人血气疼痛不可忍，丈夫小肠气撮痛：干漆一两（为末），湿漆一两。先将湿漆入铫子内熬，如一食饭间已来住火，与干漆末一处拌和，丸如半皂子大；每服一九，温酒吞下，无时。如小肠膀胱气痛，牙关紧急，但斡开牙关，温酒化一丸灌下。（《经验方》二圣丸） ②治妇人脐下结物，大如杯升，月经不通，发作往来，下痢羸瘦，此为气瘕，按之若牢强肉癥者不可治，末者可治：末干漆一斤，生地黄三十斤（捣绞取汁），火煎干漆，令可丸，食后服，如梧子大三丸，日三服。（《补缺肘后方》） ③治胞衣不出，及恶血不行：干漆（碎，炒令烟），当归（切，焙）一两。上二味捣罗为散。每服二钱匕，用荆芥酒调下，时一服，以下为度。（《圣济总录》干漆散） ④治九种心痛，及腹胁积聚滞气：筒子干漆二两。捣碎，炒烟出，细研，醋煮面糊和丸，如梧桐子大，每服五丸至七丸，热酒下，醋汤亦得，无时服。（《简要济众方》） ⑤治小儿蛔虫心痛：干漆一两（捣碎，炒令烟出）。捣细，罗为散，每服以新汲水一合，生油一橡斗子，空心调下一字，不过三服，当取下虫。（《圣惠方》） ⑥治五劳七伤：干漆、柏子人、山茱萸、酸枣仁各等分。为末蜜丸，如梧子大。服二七丸，温酒下，日二服。（《千金方》） ⑦治喉痹欲绝不可针药者：干漆烧烟，以筒吸之。（《圣济总录》）', tips='孕妇及体虚无瘀者均宜慎服。 畏鸡子。 ②《经验方》：怕漆人不可服。 ③《本草从新》：虚人及惯生大疮者戒之。 ④《本草求原》：胃虚人忌之。' where id=1791; -- 干漆
update herbs set alias='蛤蟹，仙蟾，大壁虎，蚧蛇、德多、握儿、石牙。', taste='味咸；性平', channel='入肺、肾经。', effect='①治虚劳咳嗽及肺壅上气：蛤蚧一对（头尾全者，涂酥炙令黄），贝母一两（煨微黄），紫菀一两（去苗、土），杏仁一两（汤浸，去皮、尖、双仁，麸炒微黄），鳖甲二两（涂醋炙令黄，去裙襕），皂荚仁一两（炒令焦黄）。桑根白皮一两（锉）。上药捣罗为末，炼蜜和捣三、二百杵，丸如梧桐子大。每服以枣汤下二十丸，日三、四服。忌苋菜。（《圣惠方》蛤蚧丸） ②治肺劳咳嗽：蛤蚧一对（用醋少许涂，炙令亦色），白羊肺一两（分为三分），麦门冬半两（去心，焙），款冬花一分，胡黄连一分。上药除羊肺外，捣细罗为散，先将羊肺一分，于沙盆内细研如膏，以无灰酒一中盏，暖令鱼眼沸，下羊肺，后入药末三钱，搅令匀，令患者卧，去枕，用衣簟腰，仰面徐徐而咽，勿太急。（《圣惠方》蛤蚧散） ③治肺嗽，面浮，四肢浮：蛤蚧一对（雌雄头尾全者，净洗，用法酒和蜜涂炙熟），人参一株（紫团参）。上二味，捣罗为末，熔蜡四两，滤去滓，和药末，作六饼子。每服，空心，用糯米作薄粥一盏，投药一饼，趁热，细细呷之。（《圣济总录》独圣饼） ④蛤蚧一对连尾，涂以蜜、酒，放火上烤脆，研细末，加东北红参等量，共研匀，蜂蜜炼为丸如小豆大，每服3克，一日两次，治咳嗽面浮，老人肺虚咳喘。 ⑤蛤蚧焙干10克，党参、山药、麦冬、百合各30克，共研末蜜丸，每服3克，一日两次，温开水送服，治久咳肺痨。 ⑥人参蛤蚧酒：蛤蚧一对连尾，放火上烤熟，人参（或红参）10-20克，同浸于2000克米酒中，七日后开始饮用，每日酌量饮20-50毫升。有补肾壮阳，益气安神作用。适用于身体虚弱，食欲不振，失眠健忘，阳痿早泄，肺虚咳喘，夜多小便等症。' where id=1792; -- 蛤蚧
update herbs set effect='治心痛，辟寒邪胃痛：桂丁研细，酒下三钱。(《百草镜》' where id=1793; -- 桂丁
update herbs set taste='甘；辛；平。', channel='入脾、胃经。', effect='①治大阳病，项背强几几，无汗恶风：葛根四两，麻黄三两（去节），桂枝二两（去皮），生姜三两（切），甘草二两（炙），芍药二两，大枣十二枚（擘）。上七味，以水一斗，先煮麻黄、葛根，减二升，去白沫，纳诸药，煮取三升，去渣，温服一升，覆取微似汗。（《伤寒论》葛根汤） ②治太阳病，桂枝证，医反下之，利遂不止，脉促（表未解也），喘而汗出：葛根半斤，甘草二两（炙），黄芩三两，黄连三两。上四味，以水八升，先煮葛根，减二升，纳诸药，煮取二升，去滓，分温再服。（《伤寒论》葛根黄芩黄连汤） ③治伤寒温疫，风热壮热，头痛、肢体痛，疮疹已发未发：升麻、干葛（细锉）、芍药、甘草（锉，炙）各等分。同为粗末，每服四钱，水一盏半，煎至一盏，量大小与之，温服无时。（《阎氏小儿方》升麻葛根汤） ④治癍疹初发，壮热，点粒未透：葛根、升麻、桔梗、前胡、防风各一钱，甘草五分。水煎服。（《全幼心鉴》） ⑤治热毒下血，或因吃热物发动：生葛根二斤，捣取汁一升，并藕汁一升，相和服。（《梅师集验方》） ⑥治心热吐血不止：生葛根汁半大升，顿服。（《广利方》） ⑦治鼻衄，终日不止，心神烦闷：生葛根，捣取汁，每服一小盏。（《圣惠方》） ⑧治妊娠热病心闷：葛根汁二升，分作三服。（《伤寒类要》） ⑨治卒干呕不息：捣葛根，绞取汁，服一升差。（《补缺肘后方》） ⑩治酒醉不醒：葛根汁一斗二升，饮之，取醒，止。（《千金方》） ⑾治食诸菜中毒，发狂烦闷；吐下欲死：煮葛根饮汁。（《补缺肘后方》） ⑿治服药失度，心中苦烦：饮生葛根汁大良。无生者，干葛为末，水服五合，亦可煮服之。（《补缺肘后方》） ⒀治急性肠梗阻：葛根、皂角各1斤，加水4000毫升，煎煮40分钟，去渣，置药汁锅于火炉上保持适当温度（以不致烫伤为度）。另以1市尺见方之10层纱布垫4块，浸以药液后，稍稍除去水分，交替置腹部作持续热敷，每次1小时，每天2至3次。（《河南医学院学报》9（4）：203，1965） ⒁治金疮中风，痉欲死：捣生葛根一斤，细切，以水一斗，煮取五升，去滓，取一升服，若干者，捣末，温酒调三指撮，若口噤不开，但多服竹沥，又多服生葛根自愈，食亦妙。（《肘后方》） （15）伤寒（初觉头痛，内热脉洪）。用葛根四两，加水两升、豉一升，同煮成半升服。加生姜汁更好。 （16）烦躁热渴。用葛粉四两，拌入泡过粟米一夜的水中，煮熟，加米汤同服。 （17）疖子初起。用葛蔓烧灰，水调敷涂。' where id=1794; -- 葛根
update herbs set alias='天星草，戴星草，移星草，文星草、流星草，珍珠草，鱼眼草，佛顶珠、灌耳草。', taste='辛甘，凉。', effect='①治风热目翳，或夜晚视物不清：谷精草一至二两，鸭肝一至二具（如无鸭肝用白豆腐）。酌加开水炖一小时，饭后服，日一次。（《福建民间草药》） ②治目中翳膜：谷精草、防风等分。为末，米饮服之。（《纲目》） ③治小儿痘疹眼中生翳：谷精草一两，生蛤粉五分，黑豆皮二钱，加白芍三钱（酒微炒）。上为细末，用猪肝一叶，以竹刀批作片子，掺药末在内，以草绳缚定，磁器内慢火煮熟，令儿食之，不拘时，连汁服，服至一、二月。（《摄生众妙方》） ④治小儿雀盲至晚忽不见物：羯羊肝一具，不用水洗，竹刀剖开，入谷精草一撮，瓦罐煮熟，日食之。忌铁器。如不肯食，炙熟捣作丸，如绿豆大，每服三十丸，茶下。（《卫生家宝方》） ⑤治偏正头痛：谷精草一两，为末，用白面调摊纸花子上，贴痛处，干又换。（《姚僧坦集验方》） ⑥治脑风头痛：谷精草（末）、铜绿（研）各一钱，消石半钱（研）。上三味，捣研和匀，每用一字，吹入鼻内，或偏头痛随病左右吹鼻中。（《圣济总录》谷精草散） ⑦治牙齿风疳、齿龈宣露：谷精草一分（烧灰），白矾灰一分，蟾酥一片（炙），麝香少许。上药，同研为散，每取少许，敷于患处。（《圣惠方》谷精草散） ⑧治鼻衄，终日不止，心神烦闷：谷精草，捣罗为末，以热面汤，调下二钱。（《圣惠方》） ⑨治小儿肝热，手足掌心热：谷精草全草二至三两，猪肝二两。加开水炖一小时服，日一至二次。（《福建民间草药》） 10.谷精龙胆散（《证治准绳》）治目赤翳障，头风牙痛：谷精草、龙胆草、生地、赤勺、红花、牛蒡子、茯苓、荆芥、木通、甘草。水煎服。方中谷精草明目退翳，为君药。 11.谷精草散（《太平圣惠方》）治牙齿风疳、齿断宣露：谷精草0.3g（烧碳），白矾灰0.3g，蟾酥1片（炙），麝香少许上药，同研为散，每取少许，敷于患处。方中谷精草疏散风热，为君药。 12.（《卫生家宝方》）治小儿雀盲至晚忽不见物：羊肝1具，不用水洗，竹刀切开，入谷精草1把，瓦罐煮熟，日食之。忌铁器。如不肯食，炙熟捣作丸，如绿豆大，每服30丸，茶下。方中谷精草明目退翳，为君药。' where id=1795; -- 谷精草
update herbs set taste='甘，凉。', effect='①治饮酒太过，呕吐痰逆，心神烦乱，胸膈痞塞，手足战摇，饮食减少，小便不利： 莲花青皮(去穰)三分，木香五分，橘皮(去白)、人参(去芦)、猪苓(去黑皮)、白茯苓各一钱五分，神曲(炒黄)、泽泻、干生姜、白术各二钱，白豆蔻仁、葛花、砂仁各五钱。为极细末，秤和匀，每服三钱匕，白汤调下，但得微汗，酒病去矣。(《脾胃论》葛花解酲汤) ②治饮酒积热，毒伤脾胃，呕血吐血，发热烦渴，小便赤少： 葛花一两，黄连一钱，滑石一两(水飞)，粉草五钱。为细末，水合为丸，每服一钱，滚水下。(《滇南本草》葛花清热丸)', tips='解酒醒脾；止血。主伤酒烦热口渴；头痛头晕；脘腹胀满；呕逆吐酸；不思饮食；吐血；肠风下血。 ①《别录》：消酒。 ②《滇南本草》：治头晕，憎寒，壮热，解酒醒脾，酒痢，饮食不思，胸膈饱胀，发呃，呕吐酸痰，酒毒伤胃，吐血，呕血，消热。 ③《纲目》：治肠风下血。 ④《医林纂要》：清肺。' where id=1796; -- 葛花
update herbs set effect='1.导赤散(《小儿药证直诀》)，清心养阴，利水通淋，主治心经热盛，心胸烦热，口渴面赤，意欲饮冷，以及口舌生疮，或心热移小肠，小便赤涩刺痛。 2.八正散(《太平惠民和剂局方》)，清热泻火，利水通淋，主治湿热下注，之热淋、血淋等。 3.木通汤(《圣济总录》)，主治产后乳汁不下。 4.木通散(《圣惠方》)，主治喉痹，心胸气闷，咽喉堵塞不通。 5.木通散（《证治准绳》）治脚气，肾炎等引起的水肿：木通4.5g，苏叶9g，桑白皮、猪茯苓各6g，赤茯苓、槟榔各9g。研末，加生姜、葱白，水煎服。方中木通清热利水，为臣药。 6.万全木通散（《医学入门》）治膀胱有热，小便难而黄：木通、滑石、茯苓、车前子叶各30g，瞿麦15g。水煎，分2次服。方中木通清热利水，为君药。 7.木通散（《医学统旨》）治妊娠四肢浮肿，或遍身面目俱浮，谓之子肿：木通、条茯苓各2.4g，木香、槟榔、紫苏、枳壳、白术、茯苓各2.1g。姜，水煎，分2次服。方中木通清热利水，为君药。' where id=1797; -- 关木通
update herbs set taste='苦，寒，有毒。', channel='入脾、胃经。', effect='①治病如桂枝证，头不痛，项不强，寸脉微浮，胸中痞粳，气上冲咽喉，不得息者，此为胸中有寒也，当吐之：瓜蒂一分（熬黄），赤小豆一分。上二味，各别捣筛，为散已，合治之，取-钱匕，以香豉一合，用热汤七合，煮作稀糜，去滓，取汁和散，温顿服之，不吐者，少少加，得快吐乃止。（《伤寒论》瓜蒂散） ②治风涎暴作，气塞倒卧：甜瓜蒂（曝极干），不限多少，为细末。量疾，每用一、二钱匕：腻粉一钱匕，以水半合同调匀，灌之。服之良久，涎自出，或涎未出，含砂糖一块，下咽，涎即出。（《本草衍义》） ③治诸风膈痰，诸痫涎涌：瓜蒂炒黄为末，量人以酸薤水一盏调下，取吐。（《活法机要》） ④治风痢、缠喉风、咳嗽、遍身风疹、急中涎潮：瓜蒂不限多少，细碾为末，壮年一字，十五（岁）以下及老怯半字，早晨井花水下，一食顷，含砂糖一块，良久涎如水出；年深，涎尽有一块如涎，布水上如鉴矣。涎尽，食粥一、两日。如吐多困甚，咽麝香汤一盏即止矣。麝细研温水调下。（《经验后方》） ⑤治发狂欲走：瓜蒂末，井水服一钱，取吐。（《圣惠方》） ⑥治齁喘痰气：苦丁香三个为末，水调服，吐痰即止。（《朱氏集验医方》） ⑦治太阳中暍，身热疼重而脉微弱，此以夏月伤冷水，水行皮中所致。又治诸黄：瓜蒂二七个，锉，以水一升，煮取五合，去渣顿服。（《金匮要略》一物瓜蒂汤） ⑧治黄疸目黄不除：瓜丁细末如一大豆许，内鼻中，令病人深吸取入，鼻中黄水出。（《千金翼方》瓜丁散） ⑨治癊黄黄疸及暴急黄：瓜蒂、丁香各七枚，小豆七粒。为末，吹黑豆许刁：鼻中，少时黄水出。（《食疗本草》） ⑩治湿家，头中寒湿，头疼鼻塞而烦者：瓜蒂末，口含水，搐一字许入鼻中，出黄水。（《类证活人书》） ⑾治鼻中息肉：陈瓜蒂一分，捣罗为末，以羊脂和，以少许敷息肉上，日三用之。（《圣惠方》瓜蒂膏） ⑿治牙齿痛：瓜蒂七枚，炒黄碾散，以麝香相和，新绵裹，病牙处咬之。（《圣济总录》瓜蒂散） ⒀治疟，无问新久：瓜蒂二七枚，捣，水渍一宿服之。（《千金方》）' where id=1798; -- 瓜蒂
update herbs set taste='苦；辛；寒。', channel='肝经。', effect='①治产后败血不散，儿枕块硬，疼痛发歇，及新产乘虚，风寒内搏，恶露不快，脐腹坚胀（痛）：红蓝花、鬼箭（去中心木）、当归（去苗，炒）各一两。上为粗散。每服三钱，酒一大盏，煎至七分，去滓，粥食前温服。（《局方》当归散） ②治产后血运欲绝：当归一两，鬼箭羽二两。上二味，粗捣筛。每服三钱匕，酒一盏，煎至六分，去滓温服，相次再服。（《圣济总录》当归饮） ③治恶疰心痛，或疞刺腹胁，或肩背痛无常处：鬼箭羽、桃仁（汤浸，去皮、尖，麸炒微黄）、赤芍药、鬼臼（去须）、陈橘皮（汤浸，去白瓤，焙）、当归（锉，微妙）、桂心、柴胡（去苗）、朱砂（细研）各一两，川大黄二两（锉，研，微炒）。上药，捣细罗为散，入朱砂，研令匀。每服，不计时侯，以温酒调下一钱。（《圣惠方》鬼箭羽散） ④疗乳无汁：鬼箭五两。水六升，煮取四升，去滓。服八合，日三服。亦可烧灰作末，水服方寸匕，日三。（《广济方》单行鬼箭汤） ⑤治疟疾：鬼箭羽、鲮鲤甲（烧存性）各一分。上二味，捣罗为细散。每服一字，搐在鼻中，临发时用。（《圣济总录》一字散）' where id=1799; -- 鬼箭羽
update herbs set taste='甘苦；微寒。', channel='入肝、心经。', effect='①治小儿惊热：钩藤一两，硝石半两，甘草一分（炙微赤，锉）。上药捣细，罗为散。每服，以温水调下半钱，日三、四服。量儿大小，加减服之。（《圣惠方》延龄散） ②治小儿惊痫，仰目嚼舌，精神昏闷：钩藤半两，龙齿一两，石膏三分，栀子仁一分，子芩半分，川大黄半两（锉碎，微炒），麦门冬三分（去心，焙）。上药粗捣，罗为散。每服一钱，水一小盏，煎至五分，去滓，量儿大小分减，不计时候温服。（《圣惠方》钩藤散） ③治诸痫啼叫：钩藤、蝉壳各半两，黄连（拣净）、甘草、川大黄（微炮）、天竺黄各一两。上捣罗为末。每服半钱至一钱，水八分盏，入生姜、薄荷各少许，煎至四分，去滓，温服。（《普济方》钩藤饮子） ④治小儿盘肠内钓，啼哭而手足上撒，或弯身如虾者：钩藤、枳壳、延胡各五分，甘草三分。水半盅，煎二分服。（《幼科指靠》钩藤汤） ⑤治高血压，头晕目眩，神经性头痛：钩藤二至五钱，水煎服。（广州部队《常用中草药手册》） ⑥治伤寒头痛壮热，鼻衄不止：钩藤、桑根白皮（锉）、马牙硝各一两，栀子仁、甘草（炙）各三分，大黄（锉，炒）、黄芩（去黑心）各一两半。上七味，粗捣筛。每服三钱匕，水一盏，竹叶三七片，煎至六分，去滓，下生地黄汁一合，搅匀，食后温服。（《圣济总录》钩藤汤） ⑦治全身麻木：钩藤茎枝、黑芝麻、紫苏各七钱。煨水服，一日三次。（《贵州草药》） ⑧治半边风：钩藤茎枝、荆芥各四钱，排风藤一两。煨水服，一日三次。（《贵州草药》） ⑨治面神经麻痹：钩藤二两，鲜何首乌藤四两。水煎服。（《浙江民间常用草药》） ⑩治胎动不安，孕妇血虚风热，发为子痫者：钩藤、人参、当归、茯神、桑寄生各一钱，桔梗一钱五分。水煎服。（《胎产心法）钩藤汤）' where id=1800; -- 钩藤
update herbs set taste='味甘；性平。', channel='入肝、肾经。', effect='①治肝肾不足，生花歧视，或干涩眼痛:熟地黄、山萸肉、茯苓、山药、丹皮、泽泻、枸杞子、菊花。炼蜜为丸。（《医级》杞菊地黄丸） ②治劳伤虚损:枸杞子三升，干地黄（切）一升，天门冬一升。上三物，细捣，曝令干，以绢罗之，蜜和作丸，大如弹丸，日二。（《古今录验方》枸杞丸） ③治肾经虚损眼目昏花，或云翳遮睛:甘州枸杞子一斤。好酒润透，分作四分，四两用蜀椒一两炒，四两用小茴香一两炒，四两用脂麻一两炒，四两用川楝肉炒，拣出枸杞，加熟地黄、白术、白茯苓各一两，为末，炼蜜丸，日服。（《瑞竹堂经验方》四神丸） ④补虚，长肌肉，益颜色，肥健人:枸杞子二升。清酒二升，搦碎，更添酒浸七日，漉去滓，任情饮之。（《延年方》拘杞子酒） ⑤治虚劳，下焦虚伤，微渴，小便数:枸杞子一两，黄芪一两半（锉），人参一两（去芦头），桂心三分，当归一两，白芍药一两。捣筛为散。每服三钱，以水一中盏，入生姜半分，枣三枚，饧半分，煎至六分，去滓，食前温服。（《圣惠方》枸杞子散） ⑥安神养血，滋阴壮阳，益智，强筋骨，泽肌肤，驻颜色:枸杞子（去蒂）五升，圆眼肉五斤。上二味为一处，用新汲长流水五十斤，以砂锅桑柴火慢慢熬之，渐渐加水煮至杞圆无味，方去渣，再慢火熬成膏，取起，磁罐收贮。不拘时频服二、三匙。（《摄生秘剖》杞圆膏） ⑦治肝虚或当风眼泪:枸杞二升。捣破，纳绢袋中。置罐中，以酒一斗浸干，密封勿泄气，三七日。每日饮之，醒醒勿醉。（《圣惠方》） ⑧治目赤生翳:枸杞子捣汁，日点三、五次。（《肘后方》） ⑨治注夏虚病:枸杞子、五味子。研细，滚水泡封三日，代茶饮。（《摄生众妙方》）' where id=1801; -- 枸杞子
update herbs set effect='1.治阴虚动风证。温病后期，脉气虚弱，舌绛苔少，有时时欲脱之势者：生白芍18g，阿胶9g，生龟板12g，干地黄18g，麻仁6g，五味子6g，生牡蛎12g，麦冬18g，炙甘草12g，鸡子黄2个，鳖甲12g。上以水八杯，煮取三杯，去渣，入阿胶烊化，再入鸡子黄，分三次服。方中龟甲滋阴潜阳，为臣药。（《温病条辨》大定风珠） 2.治温病热邪久羁下焦，热深厥甚，脉细促，心中痛者：炙甘草、干地黄、生白芍18，麦冬、生牡蛎15，阿胶9，麻仁9，生鳖甲24，生龟板30。水煎服。方中龟甲滋阴潜阳。（《温病条辨》三甲复脉汤）。 3.治阴虚火旺证。骨蒸潮热，盗汗遗精，咳嗽咯血，心烦易怒，足膝疼热，舌红少苔，尺脉数而有力：熟地黄18g，龟板18g，黄柏12g，知母12g。上为细末，猪脊髓蒸熟，连蜜为丸，每服70丸，空心盐白汤送下。方中龟甲滋阴潜阳，状水制火，为君药。（《丹溪心法》大补阴丸）。', tips='滋阴潜阳，益肾强骨，养血补心。用于阴虚潮热，骨蒸盗汗，头晕目眩，虚风内动，筋骨痿软，心虚健忘。' where id=1802; -- 龟甲
update herbs set taste='辛；甘；性温。', channel='入膀胱、心、肺经。', effect='①治太阳中风，阳浮而阴弱，阳浮者，热自发，阴弱者，汗自出，啬啬恶寒，渐渐恶风，翕翕发热，鼻鸣干呕者：桂枝三两（去皮），芍药三两，甘草二两（炙），生姜三两（切），大枣十二枚（擘）。上五味，细切三味，以水七升，微火煮取三升，去滓，适寒温，服一升；服巳须臾，吸热稀粥一升余，以助药力，温覆令一时许，遍身漐漐微似有汗者益佳。（《伤寒论》桂枝汤） ②治伤寒八九日，风湿相搏，身体疼烦，不能自转侧，不呕不渴，脉浮虚而涩者：桂枝四两（去皮），附子三枚（炮，去皮，破），生姜三两（切），大枣十二枚（擘），甘草二两（炙）。上五味，以水六升，煮取二升，去滓，分温三服。（《伤寒论》桂枝附子汤） ③治诸肢节疼痛，身体尪羸，脚肿如脱，头眩短气，温温欲吐：桂枝四两，芍药三两，甘草二两，麻黄二两，生姜五两，白术五两，知母四两，防风四两，附子一枚（炮）。上九味，以水七升，煮取二升，温服七合，日三服。（《金匮要略》桂枝芍药知母汤） ④治心中痞，诸逆，心悬痛：桂枝、生姜各三两，枳实五枚。上三味，以水六升，煮取三升，分温三服。（《金匮要略》桂枝生姜枳实汤） ⑤治伤寒发汗后，其人脐下悸者，欲作奔豚：茯苓半斤，桂枝四两（去皮），甘草二两（炙），大枣十五枚（擘）。上四味，以甘澜水一斗，先煮茯苓，减二升；纳诸药，煮取三升，去滓，温服一升，日三服。（《伤寒论》茯苓桂枝甘草大枣汤） ⑥治血痹阴阳俱微，寸口关上微，尺中小紧，外证身体不仁，如风痹状：黄芪三两，芍药三两，桂枝三两，生姜六两，大枣十二枚。上五味，以水六升，煮取二升，温服七合，日三服。（黄芪桂枝五物汤） ⑦治失精家少腹弦急，阴头寒，目眩，发落，脉极虚、芤迟，为清谷亡血失精，脉得诸芤动微紧：桂枝、芍药、生姜各三两，甘草二两，大枣十二枚，龙骨、牡蛎各三两。上七味，以水七升，煮取三升，分温三服。（桂枝龙骨牡蛎汤） ⑧治虚劳里急悸衄，腹中痛，梦失精，四肢酸疼，手足烦热，咽干口燥：桂枝三两（去皮），甘草二两（炙），大枣十二枚，芍药六两，生姜三两，胶饴一升。上六味，以水七升，煮取三升，去滓，内胶饴，更上微火消解，温服一升，日三服。（小建中汤） ⑨治妇人宿有癥病，经断未及三月而得漏下不止，胎动在脐上者，为癥痼害，妊娠六月动者，前三月经水利时，胎也。下血者，后断三月，衃也。所以血不止者，其癥不去故也，当下其癥：桂枝、茯苓、牡丹（去心）、桃仁（去皮、尖，熬）、芍药各等分。上五味，末之，炼蜜和丸如兔屎大。每日食前服一丸，不知，加至三丸。（桂枝茯苓丸，⑥方以下出《金匮要略》）' where id=1803; -- 桂枝
update herbs set taste='味苦；性寒。', channel='入肝、胃、大肠经。', effect='①治肥疳热：川黄连五钱，胡黄连五饯，朱砂一钱（另研）。上二物为细末，入朱砂末，都填入猪胆内，用淡浆水煮，以杖于铫子上用线钓之，勿著底，候一炊久取出，研入芦荟、麝香各一分，饭和丸如麻子大。每服五、七丸至二、三十丸，米饮下，食后。（《小儿药证直诀》胡黄连丸） ②治吐血、衄血：生地黄、胡黄连各等分。上为末，用猪胆汁为丸如梧桐子大。每服五十丸，临卧煎茅花汤送下。（《普济方》胡黄连散） ③治小儿疳热，肚胀，潮热，发焦：胡黄连五钱，灵脂一两。为末，雄猪胆汁和丸绿豆大。米饮服，每服一、二十丸。（《全幼心鉴》） ④治伤寒劳复身热，大小便赤如血色者：胡黄连一两，山栀子二两（去皮，入蜜半两拌和，炒令微焦）。二味捣罗为末，猪胆汁和丸如梧桐子大。每服用生姜二片，乌梅一个，童子小便三合，漫半日，去滓，食后暖小便令温下十丸，临卧再服。（《本草图经》） ⑤治痢血：胡黄连、乌梅肉、灶下土等分。为末。腊茶清调下，食前、空腹温服。（《苏沈良方》三物散） ⑥治小儿盗汗，潮热往来：胡黄连，柴胡等分。罗极细，炼蜜和丸如鸡头大。每服二丸至三丸，银器中用酒少许化开，更入水五分，重汤煮三二十沸，放温，食后和滓服。（孙用和） ⑦治热痢腹痛：胡黄连末，饭丸梧子大。每米汤下三十丸。（《鲜于枢钩玄》） ⑧治婴儿赤目：茶调胡黄连末，涂手足心。（《济急仙方》） ⑨治痔疮疼肿，不可忍者：胡黄连末，鹅胆汁调涂之.（《孙天仁集效方》） ⑩治痔漏成管：胡黄连（净末）一两，穿山甲（麻油内煮黄色）、石决明（煅）、槐花（微炒）各末五钱。炼蜜丸如麻子大。每服一钱，空心，清米汤送下，早、晚日进二服，至重者四十日而愈。此方不用针刀挂线，不受苦楚。如漏之四边有硬肉突起者，加蚕茧二十个炒末，和入药中，比及遍身诸漏皆效。（《外科正宗》黄连闭管丸） ⑾治痈疳疮肿，已溃未溃者皆可用之：胡黄连、穿山甲（烧存性）等分为末。以茶或鸡子清调涂。（《简易方论》） ⑿治杨梅疮毒：胡黄连、猪胰同煮服。（《本草求原》）' where id=1804; -- 胡黄连
update herbs set taste='味甘；咸；性平。', channel='肾；肺经。', effect='①治腰痛、梦遗、泄精：海参一斤，全当归（酒炒）、巴戟肉、牛膝（盐水炒）、破故纸、龟版、鹿角胶（烊化）、枸杞子各四两，羊肾（去筋生打）十对，杜仲（盐水炒）、菟丝子各八两，胡桃肉一百个，猪脊髓十条（去筋）。共研细末，鹿角胶和丸。每服四钱，温酒送下。（《中国医学大辞典》海参丸） ②治虚火燥结：海参、木耳（切烂），入猪大肠煮食。（《药性考》） ③治休息痢：海参每日煎汤服。（《纲目拾遗》）' where id=1805; -- 海参
update herbs set taste='味苦；酸；涩；性平。', channel='入肺、胃、大肠经。', effect='①治久咳语声不出：诃子（去核）一两，杏仁（泡，去皮、尖）一两，通草二钱五分。上细切，每服四钱，水一盏，煨生姜切五片，煎至八分，去滓，食后温服。（《济生方》诃子饮） ②治嗽，气嗽久者亦主之：生诃黎一枚，含之咽汁。瘥后口爽不知食味，却煎槟榔汤一碗服之。（《经验方》） ③治失音，不能言语者：诃子四个（半炮半生），桔梗一两（半炙半生），甘草二两（半炙半生）。上为细末，每服二钱，用童子小便一盏，同水一盏，煎至五七沸，温服。（《宣明论方》诃子汤） ④治结膜炎：诃子、栀子、楝子各等量。共研细末，每次二钱，水煎服，每日服三次。（内蒙古《中草药新医疗法资料选编》） ⑤治老人久泻不止：诃黎勒三分（煨，用皮），白矾一两（烧灰）。上药捣细罗为散。每服不计时候，以粥饮调下二钱。（《圣惠方》诃黎勒散） ⑥治气利：诃黎勒十枚（煨），为散，粥饮和，顿服。（《金匮要略》诃黎勒散） ⑦治脱肛日久，服药未验，复下赤白脓痢，作里急后重，白多赤少，不任其苦：御米壳（去蒂萼，蜜炒）、橘皮各五分，干姜（炮）六分，诃子（煨，去核）七分。上为细末，都作一服，水二盏，煎至一盏，和渣空心热服。（《兰室秘藏》诃子皮散） ⑧治肠风泻血：诃黎勒十个（酒润，草纸裹，煨熟，肉与核共捣细），白芷、防风、秦艽各-两。俱微炒，研为末，米糊丸，梧桐子大.每早晚各服三钱，白汤下。（《本草汇言》） ⑨治白带白淫，因虚寒者：诃黎勒十个（酒润，草纸裹，煨熟，内与核共捣细），白术、黄芪、当归、杜仲、蛇床子、北五味子、山茱萸肉各二两。俱炒研为末，炼蜜丸，梧桐子大。每早服三钱，白汤下。（《医林集要》） ⑩治老人气虚不能收摄，小水频行，缓放即自遗下，或涕泪频来，或口涎不收：诃黎勒，不用煨制，取肉，时时干嚼化，徐徐含咽。（《本草汇言》） ⑾治口疮经久不愈：诃黎勒五个（酒润，草纸裹煨熟，肉与核共捣细），好冰片一分。共研匀细，不时掺入少许，口含徐徐咽下。（《本草汇言》）' where id=1806; -- 诃子
update herbs set taste='苦；辛；温；小毒。', effect='①治蛾子：虎掌草根及叶少许，捣绒，放患者口内含咽（不可久含，以免起泡，蛾子破即吐出）。（《贵州草药》） ②治喉炎：虎掌草全草三至五钱，煎水含漱。（《云南中草药选》） ③治痰结瘰疬绕项而生：虎掌草二两，小九枯牛一两，紫夏枯一两，灵仙五钱，白头翁一两。烧酒浸，重汤煎。每晚炖服三杯，服二十一日。虚弱者忌服。（《滇南本草》） ④治无名肿毒：虎掌草根炕干研末，调醋搽患处。（《贵州草药》） ⑤治风湿痛：见风青五钱，加酒煎服。 ⑥治疟疾：见风青根一两。捣烂（忌刀切），冲二次淘米水调匀澄清后，倾上层药液，于发病前二小时服。捣烂后包寸口亦可。 ⑦治体虚盗汗、咳嗽：见风青五钱，蘘荷根五钱.炖猪肉四两，内服。连用三剂。（⑤方以下出《贵阳民间药草》） ⑧治肝硬化，慢性肝炎：虎掌草根三钱，红糖适量煎服。（《云南中草药选》） ⑨治胃痛：虎掌草根二两。泡酒一斤，浸泡一周。每次服五毫升，每日三次。或用根三钱，煎汤服。（《云南中草药选》）' where id=1807; -- 虎掌草
update herbs set effect='①红参熟地汤：主治老年人阳痿。红参lOg，熟地30g，黄芪25g，白术15g，巴戟15g，山茱萸 lOg，柏子仁lOg，五味子5g，远志5g，肉桂5g，枸杞15g，乌药15g。水煎服，每日1剂，早晚分服，l周为l疗程。 ②枸杞红参酒：（《临床验方集》）。身体虚弱、阳病、耳鸣、目花等症。枸杞子80克，熟地黄60克，红参15克，首乌50克，茯苓20克，白酒1000毫升。将前5味共研为粗末，入布袋，置容器中，加入白酒，密封，隔日振摇1次，浸泡14天后，即可取用。酒尽添酒，味薄即止。口服。每次服20毫升，日服2次。', usage='', tips='不宜与藜芦同用。 不宜与藜芦同用。' where id=1808; -- 红参
update herbs set taste='辛；性温；小毒。', channel='入脾、肺、肾经。', effect='①治心胸中大寒痛，呕不能饮食，腹中寒，上冲皮起，出现有头足，上下痛而不可触近：蜀椒二合（去汗），干姜四两，人参二两。上三味，以水四升，煮取二升，去滓，纳胶饴一升，微火煮取一升半。分温再服，如一炊顷，可饮粥二升，后更服，当一日食糜，温覆之。（《金匮要略》大建中汤） ②治冷虫心痛：川椒四两。炒出汗，酒一碗淋之，服酒。（《寿域神方》） ③治呃噫不止：川椒四两。炒研，面糊丸，梧子大，每服十九，醋汤下。（《秘传经验方》） ④治夏伤湿冷，泄泻不止：川椒一两（去目并闭口者，慢火炒香熟为度），肉豆蔻（面裹，煨）半两。上为细末，粳米饭和丸黍米大。每服十粒，米饮下，无时。（《小儿卫生总微论方》川椒丸） ⑤治飧泄：苍术二两，川椒一两（去口。炒）。上为细末.醋糊丸，如梧子大。每服二、三十丸，食前温水下。恶痢久不愈者，弥佳。如小儿病，丸如黍米大。（《普济方》椒术丸） ⑥治齿痛：蜀椒醋煎含之。（《食疗本草》） ⑦治齿疼：川椒一两（去目），捣罗为末，以好白面丸如皂角子大，烧令热，于所痛处咬之。（《圣惠方》） ⑧治伤寒呕血，继而齿缝皆流血不止：开口川椒四十九粒，用醋同煎，临熟入白矾少许，漱口含在口中，少顷吐出，再啜漱而含。（《仁斋直指方》） ⑨治寒湿脚气：川椒二、三升，稀布囊盛之，日以踏脚。（《妇人良方》） ⑩治肾风囊痒：川椒、杏仁。研膏，涂掌心，合阴囊而卧。（《仁斋直指方》） ⑾治妇人阴痒不可忍，非以热汤抱洗有不能已者：花椒、吴萸、蛇床各一两，藜芦五钱，陈茶一撮，烧盐二两。水煎熏洗。（《医级》椒茱汤） ⑿治手脚心风毒肿：生（花）椒末、盐末等分。以醋和敷。（《补缺肘后方》） ⒀治久患口疮：蜀椒去闭口者，水洗，面拌，煮作粥，空腹吞之，以饭压下，重者可再服，以瘥为度。（《食疗本草》） ⒁治头上白秃：花椒末，猪脂调敷。（《普济方》） ⒂治手足皴裂：（花）椒四合，水煮之，去滓。渍之半食顷，出令燥，须臾复浸，干涂羊、猪髓脑。（《僧深集方》） ⒃治漆疮：汉椒汤洗之。（《谭氏小儿方》） ⒄治元藏伤惫，耳聋目睹：蜀椒（去目及闭口者，暴干捣罗取红秤一斤，再捣为末），生地黄七斤（肥嫩者）。上二味，先将地黄搀绞自然汁，铜器中煎至一升许，住火，候稀稠得所，即和前椒末为丸，如梧桐子大。每日空心暖酒下三十丸。（《圣济总录》椒红丸） ⒅治好食生茶：（花）椒末不限多少，以糊丸如梧子大，茶下十丸。（《胜金方》）', tips='阴虚火旺者忌服。孕妇慎服。 畏款冬。恶栝楼、防葵。畏雌黄。 ②《别录》：多食令人乏气，口闭者杀人。 ③《千金·食治》：久食令人乏气失明。’ ④《唐本草》：畏橐吾、附子、防风。 ⑤《本草经疏》：肺胃素有火热，或咳嗽生痰，或嘈杂醋心，呕吐酸水，或大肠积热下血，咸不宜用；凡泄泻由于火热暴注而非积寒虚冷者忌之；阴痿脚弱，由于精血耗竭而非命门火衰虚寒所致者，不宜入下焦药用；咳逆非风寒外邪壅塞者不宜用；字乳余疾由于本气自病者不宜用；水肿黄疸因于脾虚而无风湿邪气者不宜用；一切阴虚阳盛，火热上冲，头目肿痛，齿浮，口疮，衄血，耳聋，咽痛，舌赤，消渴，肺痿，咳嗽，咯血，吐血等证，法所咸忌。 ⑥《随息居饮食谱》：多食动火堕胎。' where id=1809; -- 花椒
update herbs set taste='苦、辛，凉。有小毒。', channel='肺；肝经。', effect='①治吐血不止：黄药子（万州者）一两，捣碎，用水二盏，煎至一盏，去滓温热服。（《圣济总录》黄药汤） ②治吐血：真蒲黄，黄药子等分。用生麻油调，以舌舐之。（《百一选方》） ③治鼻衄不止：黄药子一两，捣罗为散。每服二钱匕，煎阿胶汤调下。良久，以新汲水调生面一匙投之。（《圣济总录》黄药散） ④治疮：黄药子四两，为末，以冷水调敷疮上，干而旋敷之。（《简要济众方》） ⑤治天泡水疮：黄药子末搽之。（《濒湖集简方》） ⑥治缩脚肠痈，干黄独一两，煎服。不可多用。（《浙江民间草药》） ⑦治缠喉风，颐颔肿及胸膈有痰，汤水不下者：黄药子一两，为细末。每服一钱，白汤下。吐出顽痰。（《扁鹊心书》黄药子散） ⑧治热病、毒气攻咽喉肿痛：黄药一两，地龙一两（微炙），马牙消半两。上药捣细罗为散，以蜜水调下一钱。（《圣惠方》） ⑨治瘿气：黄药子一斤，浸洗净，酒一斗浸之。每日早晚常服一盏。忌一切毒物及不得喜怒。（《斗门方》） ⑩降气治胃痛：黄药（炒过）、陈皮、苍术、金钱草各二钱，土青木香一钱五分。研粉服或煎服。（《浙江民间草药》） ⑾治鱼口，腰膝疼痛：黄独根五至八钱。水煎服。（《湖南药物志》） ⑿治睾丸炎：黄独根三至五钱，猪瘦肉四两。水炖，服汤食肉，每日一剂。（《江西草药》） ⒀治扭伤：黄独根、七叶一枝花（均鲜用）各等量，捣烂外敷。（《江西草药》） ⒁治腹泻：黄药子研末，每次一钱，开水吞服。（《贵州草药》） ⒂治疝气、甲状腺肿、化脓性炎症：黄药子根五钱至一两。水煎服。（《云南中草药》） ⒃治瘰疬：黄独鲜块茎二至三两，鸭蛋1枚。水煎，调些酒服。（《福建中草药》） ⒄治百日咳。黄药子三至五钱。冰糖为引，水煎分三至五次服。（江西《草药手册》）' where id=1810; -- 黄药子
update herbs set taste='甘，平。', channel='入心、肝、小肠经。', effect='①治小儿诸惊，四时感冒，风寒温疫邪热，致烦躁不宁，痰嗽气急及疮疹欲出发搐：真琥珀、天竺黄、檀香、人参、白茯苓各一两半，粉草三两，枳壳（麸炒）、枳实（麸炒）二昧各一两，水飞朱砂五两，山药一斤（锉作小块，慢火炒令热透），胆南星一两，金箔百片（去护纸，取见成药一两，同在乳钵内极细杵，仍和匀前药末用）。前十二味，除朱砂、金箔不入研，内余十味，檀香不过火外，九味或晒或焙，同研为末，和匀，朱砂、金箔每一两重，取新汲井水一两，重入乳钵内略杵匀，随手丸如绿豆大一粒，阴干。用葱汤化服，百日内婴儿每丸分三次投，二岁以上者止一丸或二丸。（《活幼心书》琥珀抱龙丸） ②治天吊惊风发搐：琥珀末一分，真珠末一分，朱砂末半分，铅霜半分，赤芍药末一分半。上拌匀，每服一字，煎金、银、薄荷汤调下，无时。（《小儿卫生总微论方》琥珀散） ③治小儿胎惊：琥珀、防风各一钱，朱砂半钱。为末，猪乳调一字，入口中。（《仁斋直指方》） ④治小儿胎痫：琥珀、朱砂各少许，全蝎一枚。为末，麦门冬汤调一字服。（《仁斋直指方》） ⑤治健忘恍惚，神虚不寐：琥珀、羚羊角、人参、白茯神、远志（制）、甘草等分。上为细末，猪心血和炼蜜丸，芡实大，金箔为衣。每服一丸，灯心汤嚼下。（《景岳全书》琥珀多寐丸） ⑥治病后虚烦不睡：琥珀、真珠、生地、甘草各一钱，当归、黄连各三钱，朱砂二钱。上为末，米糊丸，如粟米大。每服三十丸，食后，麦门冬汤下。（《活人心统》琥珀安神丸） ⑦治心经之火，移于小肠，溲溺淋浊或涩或痛：琥珀一钱，天冬一钱五分，麦冬一钱五分，生地五钱，丹参二钱，丹皮二钱，赤芍、木通各一钱，甘草梢五分，淡竹叶二十张，灯心三尺。（《医醇剩义》琥珀导赤汤） ⑧治心经蓄热，小便赤涩不通，淋沥作痛：琥珀为细末，每服半钱，浓煎萱草根调下，食前。（《杨氏家藏方》忘忧散） ⑨治小便尿血：琥珀为末，每服二钱，灯芯汤下。（《仁斋直指方》） ⑩治妇人月候不通：琥珀一两（细研，以醋三升熬如膏），虻虫半两（去翅足，炒黄），水蛭半两（炒黄），肉桂三两（去皱皮），桃仁一两（去皮、尖、双仁，别研，生用），川大黄三两（生用）。上药捣罗为末，以琥珀膏和丸，如梧桐子大，每服空心以温酒下三十丸。（《圣惠方》琥珀煎丸） ⑾治经水或前或后或血崩及瘀血死胎，并养胎，镇心安神：琥珀、乳香、没药、辰砂各一钱三分，麝香少许。各研细，灯心汤为丸，芡实大。每服一丸，如腹痛，姜汁、童便、酒冲下。（《女科万金方》琥珀丸） ⑿治产后恶露不下，气攻心腹，烦闷刺痛：琥珀、姜黄、牛膝（酒浸，切，焙）、虎杖、牡丹皮各半两，当归（切，焙）、生干地黄（焙）、桂（去粗皮）、桃仁（汤浸，去皮、尖、双仁，麸炒）各三分，大黄（锉，焙）一两，虻虫（去翅、足，炒黄）一分，芒硝一两。上十��味，粗捣筛。每服二钱匕，水一盏，煎取七分，去滓温服。（《圣济总录》琥珀汤） ⒀止血生肌，镇心明目，破癥瘕气块，产后血晕闷绝，儿枕痛：琥珀一两，鳖甲一两，京三棱一两，延胡索半两，没药半两，大黄六铢。熬捣为散，空心酒服三钱匕，日再服。（《海药本草》） ⒁治痈疽发背，已成未脓之际，恐毒气不能外出，必致内攻，预服此丸，护膜护心，亦且散血解毒：白矾一两二钱，雄黄一钱二分，琥珀一钱（另研极细），朱砂一钱二分，黄蜡一两，蜂蜜二钱临入。上四味，先研极细，另将蜜、蜡铜杓内溶化，离火片时，候蜡四边稍凝时，方入上药搅匀，共成一块，以一人将药火上微烘，众手急丸，小绿豆大，用朱砂为衣，磁罐收贮。每服二、三十丸，白汤食后送下，病甚者早晚日进二次。（《外科正宗》琥珀蜡矾丸） ⒂治从高坠下，有瘀血在内：刮琥珀屑，酒服方寸匕，或入蒲黄三、二匕，日服四、五次。（《外台秘要方》）' where id=1811; -- 琥珀
update herbs set taste='咸，平。', channel='①《本草汇言》：入手足太阳、阳明经。', effect='①治咳喘痰多：海蛤壳、半夏、桑皮、苏子、贝母各三钱，栝蒌五钱。水煎服。（《山东中草药手册》） ②治痰饮心痛：海蛤（烧为灰，研极细，过数日，火毒散，用之）、瓜蒌仁（蒂穰同研）。上以海蛤入瓜蒌内，干湿得所为丸。每服五十丸。（《医学纲目》） ③治水肿，咳逆上气，坐卧不得：海蛤一两（细研），甜葶苈一两（隔纸炒令紫色），汉防己一两，杏仁一分（汤浸。去皮、尖、双仁，麸炒微黄），甘遂一两（煨令微黄），桑根白皮一两（锉）。上药，捣罗为末，以枣肉和，捣二三百杵，丸如梧桐子大。每于食前，以大麻子汤下七丸。（《圣惠方》） ④治小儿疳永，肿满气息：海蛤、泽泻、防己各一分，萝卜子三十粒。上为末。三岁一钱，酒调下，连进二服，小便利，即效。（《普济方》海蛤散） ⑤治水气头面浮肿，坐卧不安或嗽喘者：海蛤（捣研如面）一两，甘遂三分（为末，绢罗如面，用白面和作剂），郁李仁（汤浸去皮，微炒，研）一两一分。上三味，以桑根白皮一两，用水二升煮，如嫩，即加干枣三十枚，擘破，同煮取一升，去滓，取入前件药，和，如作索饼法，煮令熟，看冷暖得所，空腹服食。须臾快利，小便甚多。勿怪。（《圣济总录》海蛤索饼） ⑥治瘿瘤：海蛤（研）、人参、海藻（马尾者，汤洗去咸，焙）、白茯苓（去黑皮）、半夏（水煮一、二沸，去滑，切，焙）各半两。上五味，捣罗为散，每服一钱匕，入猪靥子末一钱匕，甜藤一尺（去根五寸取之），甘草一寸，水五盏，同煎取一盏半，分三次。每次调散二钱匕，临卧服。（《圣济总录》海蛤散） ⑦治淋巴结结核，甲状脓肿大：海蛤壳四钱，海藻、牡蛎各五钱，夏枯草六钱。水煎服。（《山东中草药手册》） ⑧治妇人伤寒血结胸膈，揉而痛不可抚近：海蛤、滑石、甘草（炙）各一两，芒硝半两。上捣罗为散。每服二钱，鸡子清调下。（《类证活人书》海蛤散） ⑨治血痢内热：海蛤末，蜜水调服二钱，日二。（刘禹锡《传信方》） ⑩治鼻衄不止：蛤粉一两（研极细，罗五、七遍），槐花半两（炒令焦，碾为末）。上研令极匀细。每服一钱，新汲水调下。如小可只用半钱。兼治便血不止，不拘时候。（《杨氏家藏方》神白散） ⑾治外阴炎、外阴湿疹、外阴溃疡：煅蛤粉一钱、漳丹一钱四分，冰片四分。上药研成细粉，用液体石蜡合成药膏。清洗患部后，将上药涂于患部，覆盖纱布，每天两次。（《全展选编·妇产科》）', tips='气虚有寒、中阳不运者慎用。 畏狗胆、甘遂、芫花。 ②《本草汇言》：病因热邪痰结气闭者宜之，若气虚有寒，中阳不运而为此证者，切勿轻授。' where id=1812; -- 海蛤壳
update herbs set taste='味咸；性平。', channel='肝；肾；肺经。', effect='①治痞：大荸荠一百个，海蜇一斤，皮硝四两，烧酒三斤。共浸七日后，每早吃四钱（个），加至十个止。（《同寿录》） ②治小儿一切积滞：荸荠与海蜇同煮，去蜇食荠。（《纲目拾遗》） ③治阴虚痰热，大便燥结：海蜇一两，荸荠四枚。煎汤服。（《古方选注》雪羹汤）' where id=1813; -- 海蜇
update herbs set taste='甘；性平。', channel='入脾、胃、大肠经。', effect='①治伤寒趺阳脉浮而涩，浮则胃气强，涩则小便数，浮涩相搏，大便则硬，其脾为约：麻于仁二升，芍药半斤，枳实半斤（炙），大黄一斤（去皮），厚朴一尺（炙，去皮），杏仁一升（去皮，炙、熬，别作脂）。上六味，蜜和丸，如梧桐子大。饮服十丸，日三服，渐加，以知为度。（《伤寒沦》麻子仁丸） ②治大便不通：研麻子，以米杂为粥食之。（《肘后方》） ③治虚劳，下焦虚热，骨节烦疼，肌肉急，小便不利，大便数少，吸吸口燥少气：大麻仁五合，研，水二升，煮去半分，服。（《外台》） ④治产后郁冒多汗，便秘：紫苏子、大麻仁各半合，净洗，研极细，用水再研，取汁一盏，分二次煮粥喂之。此粥不惟产后可服，大抵老人、诸虚人风秘，皆得力。（《本事方》麻子苏子粥） ⑤治大渴，日食数斗，小便赤涩者：麻子一升，水三升，煮三、四沸，取汁饮之。（《肘后方》） ③治五淋，小便赤少，茎中疼痛：冬麻子一升，杵研，滤取汁二升，和米三合，煮粥，着葱、椒及熟煮，空心服之。（《食医心镜》） ⑦治脚气肿渴：大麻子熬令香，和水研，取-大升，别以三大升水煮一大升赤小豆，取一升汁，即纳麻汁，更煎三、五拂，渴即饮之，冷热任取，饥时啖豆亦佳。（《外台》） ⑧治风水腹大，脐腰重痛，不可转动：冬麻子半升，碎，水研滤取汁，米二合，以麻子汁煮作稀粥，着葱、椒、姜、豉，空心食之。（《食医心镜》） ⑨治骨髓风毒疼痛，不可运动者：大麻仁水中浸取沉者一大升，漉出曝干，炒，待香热，即入木臼捣极细如白粉，平分为十帖。每用一帖，取无灰酒一大瓷汤碗研麻粉，旋滤取白酒，直令麻粉尽，余壳即去之，都合酒一处，煎取一半，待冷热得所，空腹顿服，日服一帖。（《箧中方》大麻仁酒） ⑩治白痢：麻子汁，煮取绿豆，空腹饱服。（孟诜《必效方》） ⑾治小儿赤白痢，体弱不堪，困重者：麻子一合，炒令香熟，末服一钱匕，蜜、浆水和服。（《子母秘录》） ⑿治妇人月水不利，或至两三月、半年、一年不通者：桃仁二升，麻孑仁二升，合捣，酒一斗，渍一宿，服一升，日三夜一。（《肘后方》） ⒀治产后血不去：麻子五升，捣，以酒一斗渍一宿，明旦去滓，温服一升，先食服，不瘥，夜服一升。忌房事一月，将养如初产法。（《千金方》麻子酒） ⒁治妊娠损动后腹痛：冬麻子一升，杵碎熬，以水二斗，煮取汁，热沸，分为三、四服。（《食医心镜》） ⒂治寸白由：吴茱萸细根一把（熟捣），大麻子三升（熬，捣末）。上二味，以水三升和搦取汁，旦顿服之，至巳时，与好食令饱，须臾虫出，不瘥，明且更合服之，不瘥，三日服。（《千金方》） ⒃治呕逆：麻仁三合，熬，捣，以水研取汁，着少盐吃。（《近效方》） ⒄治小儿头面疮疥：麻子五升末之，以水和绞取汁，与蜜和敷之。（《千金方》） ⒅治小儿疳疮：捣麻子敷之，日六、七度。（《子母秘录》） ⒆治金疮腹中瘀血：大麻子三升，大葱白二十枚。各捣令熟，著九升水，煮取一升半，顿服之。若血出不尽，腹中有脓血，更合服，当吐脓血耳。（二物汤） ⒇治瘭疽着手足肩背，忽发累累如赤豆，剥之汁出者：麻子熬作末，摩上良。 （21）治赤流肿丹毒：捣大麻子水和敷之。（⒆方以下出《千金方》） （22）治汤火伤：火麻仁、黄柏、黄栀子，共研末，调猪脂涂。（《四川中药志》） （23）治聘耳，脓水不止：麻子一合，花臙脂一分。都研为末，满耳塞药，以绵轻拥。（《圣惠方》） （24）麻仁苏子粥（《大同方剂学》）治产后大便不通及老人峰秘等证：火麻仁、紫苏子各等分。上2味，洗净合研，再水研取汁，煮粥服用。方中火麻仁润燥滑肠，为君药。 （24）麻仁汤（《圣济总录》）治痢后四肢浮肿：大麻仁、商路、防风、附子、陈橘皮、防己各3g，赤小豆100粒。水煎，分2-3次服。方中火麻仁润燥滑 （25）麻仁丸（《证治准绳》）治产后大便秘涩：麻仁（研和泥）、枳壳、人参各30g，大黄15g。上为细末，炼蜜为丸，梧桐子大，每服20丸，空腹温酒送下。方中火麻仁润燥滑肠，为君药' where id=1814; -- 火麻仁
update herbs set alias='白皮子，白皮纸、秋风子，姹皮，罗皮。', taste='味咸；性平。', channel='归肝；肾经。', effect='①消痞：㈠白皮子、荸荠，烧酒浸服。㈡白皮子、荸荠同煮，止食荸荠。（《王圣俞手集》） ②治头风：白皮子贴两太阳。（《纲目拾遗》） ③治膝髌风湿：白皮子贴之。（《纲目拾遗》） ④治无名肿毒，重者溃，轻者散；又止痛：白皮子一片，白糖霜揉软，中开一孔贴上。（《医方集听》） ⑤治流火：海蜇皮薄者贴上，燥则易之。（《文堂集验方》） ⑥治烂腿：白皮子照疮大小，剪作膏贴，内掺银朱。（《救生苦海》）', tips='化痰消积；祛风解毒。主咳嗽痰喘；痞积；头风；风湿关节痛；白带过多；疮疡肿毒。治痞块，头风，白带，膝髌风湿，无名肿毒。 ①《纲目拾遗》：消痰行积，止带祛风。' where id=1815; -- 海蜇皮
update herbs set effect='治中暑神昏不语，身热汗微，气喘等证：黄连一钱二分，香薷一钱，扁豆衣三钱，厚朴一钱（姜汁炒），杏仁二钱（去皮、尖，研），陈皮一钱五分，制夏一钱五分，益元散三钱入煎，加荷梗七寸为引。汗多除去香薷。（《时病论》）', tips='解暑清热；理气化湿。主暑湿胸闷不舒；泄泻；痢疾；淋病；带下。用于中暑头昏，胸闷，气滞。 ①《本草再新》：通气消暑，泻火清心。 ②《随息居饮食谱》：通气舒筋，升津止渴，霜后采者，清热止盗汗，行水愈崩淋。 ③《现代实用中药》：为收敛药。用于慢性衰弱的肠炎、久下痢、肠出血。妇人慢性子宫炎、赤白带下、男子遗精或夜尿证。又为解毒药。' where id=1816; -- 荷梗
update herbs set taste='味咸；涩；性温。', channel='入肝、肾经。', effect='①治胃痛，吐酸：㈠海螵蛸五钱，贝母、甘草各二钱，瓦楞子三钱。共研细末。每次服二钱。㈡海螵蛸一两（研末），阿胶三钱。共炒，再研末。每次服一钱，每日三次。（《山东中草药手册》） ②治胃出血：海螵蛸五钱，白芨六钱。共研细末。每次服一钱五分，日服三次。（《山东中草药手册》） ③治吐血及鼻衄不止：乌贼骨，捣细罗为散，不计时候，以清粥饮调下二钱。（《圣惠方》） ④治鼻血不止：乌贼鱼骨、槐花等分。举生半炒，为末吹鼻。（《世医得效方》） ⑤治积年肠风下血，面色萎黄，下部肿疼，或如鼠妳，或如鸡冠，常似虫咬，痛痒不息：绿矾二两（烧令赤），乌贼鱼骨一两（炙令微黄），釜底墨一两。捣罗为末，用粟米饭和丸如梧桐子大。每于食前，煎赤糙米汤下三十丸。（《圣惠方》） ⑥治小便血淋：海螵蛸末一钱。生地黄汁调服。（《经验方》） ⑦治妇人漏下不止：乌贼骨、当归各二两，鹿茸、阿胶各三两，蒲黄一两。上五味治下筛。空心酒服方寸匕。日三，夜再服。（《千金方》） ⑧治妇人久办白带下：乌贼骨一两（烧灰），白矾三两（烧汁尽），釜底墨二两。捣罗为末，用软饭和丸，如梧桐子大，每于食前，以粥饮下三十丸。（《圣惠方》） ⑨治跌破出血：乌贼鱼骨末敷之。（《仁斋直指方》） ⑩治各种外伤出血：骨粉、海螵蛸、蒲黄炭各等分。研细末，过150目筛，混合即得。撒于创面，稍加压即可凝固止血。（辽宁《中草药新医疗法资料选编》） ⑾治外伤出血：海螵蛸、煅猪皮、人中白各一两，石灰一两半。共研细粉。消毒，撒于创面处，包扎即可。（内蒙古《中草药新医疗法资料选编》） ⑿治血枯：四乌鲗骨、一蔖茹。二物并合之，丸以雀卵，大如小豆，以五丸为后饭，饮以鲍鱼汁。（《素问》） ⒀治哮喘：海螵蛸，焙干研成细末。每日三次。每次一钱五分，温开水送服。（徐州《单方验方新医疗法选编》） ⒁治诸疳疮：海螵蛸三分，白及三分，轻粉一分。为末。先用浆水洗，拭干贴。（《小儿药证直诀》白粉散） ⒂治疬疡：三年醋磨乌贼骨，先布摩肉赤，敷之。（《千金方》） ⒃治小儿脐疮出脓及血：海螵蛸、胭脂，为末，油调搽之。（《圣惠方》） ⒄治头上生疮：海螵蛸、白胶香各二钱，轻粉五分。为末。先以油润净乃搽末。（《卫生易简方》） ⒅治耳底出脓：海螵蛸半钱，麝香一字。为末。以绵杖缴净，吹入耳中。（《澹寮方》） ⒆治阴囊湿痒：乌贼骨、蒲黄、扑之。（《医宗三法》） ⒇治目中一切浮翳：乌贼鱼骨，细研和蜜点之。（《食疗本草》） (21)治疳眼：乌贼鱼骨、牡蛎等分。为末，糊丸如皂子大。每服用猪子肝一具，药一丸，清米泔内煮，肝熟为度，和肝食，用煮肝泔水下三两服。（《经验方》）' where id=1817; -- 海螵蛸
update herbs set taste='性温，味甘。', channel='归肾、肺、大肠经。', effect='①治湿伤于内外，阳气衰绝，虚寒喘嗽，腰脚疼痛：胡桃肉二十两（捣烂），补骨脂十两（酒蒸）。研末，蜜调如饴服。（《续传信方》） ②治久嗽不止：核桃仁五十个（煮热，去皮），人参五两，杏仁三百五十个（麸炒，汤浸去皮）。研匀，入炼蜜，丸梧子大。每空心细嚼一丸，人参汤下，临卧再服。（《纲目》） ③治产后气喘：胡桃仁（不必去皮）、人参各等分。上细切，每服五钱，水二盏，煎七分，频频呷服。（《普济方》） ④治肾气虚弱，腰痛如折，或腰间似有物重坠，起坐艰辛者：胡桃二十个（去皮膜），破故纸（酒浸，炒）八两，蒜四两（熬膏），杜仲（去皮，姜汁浸，炒）十六两。上为细末，蒜膏为丸。每服三十丸，空心温酒下，妇人淡醋汤下。常服壮筋骨，活血脉，乌髭须，益颜色。（《局方》青娥丸） ⑤益血补髓，强筋壮骨，明目，悦心，滋润肌肤：故纸、杜仲、萆薢、胡桃仁各四两。上三味为末，次入胡桃膏拌匀，杵千余下，丸如梧子大。每服五十丸，空心，温酒、盐汤任下。（《御药院方》） ⑥治消肾，唇口干焦，精溢自出，或小便赤黄，五色浑浊，大便燥实，小便大利而不甚渴：白茯苓、胡桃肉（汤去薄皮，别研）、附子大者一枚（去皮脐，切作片，生姜汁一盏，蛤粉一分，同煮干，焙）。上等分，为末，蜜丸如梧子大，米饮下三、五十丸；或为散，以米饮调下，食前服。（《三因方》胡桃丸） ⑦治肾虚耳鸣遗精：核桃仁三个，五味子七粒，蜂蜜适量。于睡前嚼服。（《贵州草药》） ⑧治石淋：胡桃肉一升。细米煮浆粥一升，相和顿服。（《海上集验方》） ⑨治小便频数：胡桃煨熟，卧时嚼之，温酒下。（《纲目》） ⑩治醋心：烂嚼胡桃，以干姜汤下。或只嚼胡桃，或只吃干姜汤亦可治。（《传信适用方》） ⑾治赤痢不止：枳壳、胡桃各七枚，皂荚（不蛀者）一挺。上三味，就新瓦上以草灰烧令烟尽，取研极细，分为八服。每临卧及二更、五更时各一服，荆芥茶调下。（《圣济总录》枳壳散） ⑿治脏躁病：胡桃仁一两。捣碎，和糖开水冲服，每日三次。（《卫生杂志》4（1）:6，1936） ⒀治火烧疮：取胡桃穰烧令黑，杵如脂，敷疮上。（《梅师集验方》） ⒁治瘰疬疮：胡桃瓤烧令黑，烟断，和松脂研敷。（《开宝本草》） ⒂治鼠瘘痰核:连皮胡桃肉，同贝母、全蝎枚数相等，蜜丸服。（《本经逢原》）', usage='', tips='有痰火积热或阴虚火旺者忌服。 ①《干金食治》：不可多食，动痰饮，令人恶心，吐水吐食。 ②汪颖《食物本草》：多食生痰，动肾火。 ③《本草经疏》：肺家有痰热，命门火炽，阴虚吐衄等证皆不得施。 ④《得配本草》：泄泻不已者禁用。 有痰火积热或阴虚火旺者忌服。 ①《干金食治》：不可多食，动痰饮，令人恶心，吐水吐食。 ②汪颖《食物本草》：多食生痰，动肾火。 ③《本草经疏》：肺家有痰热，命门火炽，阴虚吐衄等证皆不得施。 ④《得配本草》：泄泻不已者禁用。' where id=1818; -- 核桃仁
update herbs set taste='甘；寒；无毒。', effect='①治热淋急痛：海金沙草阴干为末，煎生甘草场，调服二钱；或加滑石。（《夷坚志》） ②治血淋：左转藤、小萹蓄，水煎服。（《四川中药志》） ③治妇女白带：海金沙茎一两，猪精肉四两。加水同炖，去渣，取肉及汤服。（《江西民间草药验方》） ④治小便不利：海金沙全草二至三两。和冰糖，酌加水煎服；或代茶常饮。（《福建民间草药》） ⑤治赤痢：海金沙全草二至三两。水煎，日服一至三次。（《福建民间草药》） ⑥治腹泻：海金沙全草，水煎服。（《闽南民间草药》） ⑦治湿热黄疸：金砂蕨叶、田基黄，鸡骨草各一两。水煎服。（《广西中草药》） ⑧治梦遗：海金沙藤烧灰存性。用净灰一钱五分至二钱，开水冲服。（《福建民间草药》） ⑨治火烫伤：海金沙鲜叶捣烂。调入乳外敷火伤处。（《福建民间草药》） ⑩治缠腰火丹：鲜海金沙叶切碎捣烂。酌加麻油及米泔水，同擂成糊状，涂搽患处。（《江西民间草药验方》） ⑾治赘疣：海金沙全草一握，水煎洗；在洗时用其藤擦赘疣处，日洗二至三次。（《福建民间草药》） ⑿治黄蜂螫伤：金砂蕨叶一两。捣烂；取汁擦患处。（《广西中草药》）' where id=1819; -- 海金沙草
update herbs set taste='甘；平；无毒。', channel='脾；肺经。', effect='①治久咳、秋燥，小儿百日咳：花生（去嘴尖），文冰煎汤调服。（《杏林医学》） ②治脚气：生花生肉（带衣用）三两，赤小豆三两，红皮枣三两。煮汤，一日数回饮用。（《现代实用中药》） ③治乳汁少：花生米三两，猪脚一条（用前腿）。共炖服。（《陆川本草》）' where id=1820; -- 落花生
update herbs set taste='性温，味辛、苦。', effect='1. 二陈汤(《太平惠民和剂局方》)：燥湿化痰，理气和中，治湿痰咳嗽。 2. 导痰汤(《妇人良方》)：燥湿祛痰，行气开郁，主治痰涎壅盛，胸膈痞塞，或咳嗽恶心，饮食少思，以及肝风挟痰，呕不能食，头痛头晕，甚或痰厥者。 3. 贝母瓜蒌散(《医学心悟》)：润肺清热，理气化痰，治肺燥有痰。 4. 涤痰汤(《济生方》)：涤痰开窍，治中风痰迷心窍，舌强不能言。' where id=1821; -- 化橘红
update herbs set alias='昧履支，浮椒，玉椒。', taste='味辛、热。', channel='入胃、大肠经。', effect='①治五脏风冷，冷气心腹痛，吐清水:胡椒酒服之，亦宜汤服。（《食疗本草》） ②治心下大痛:胡椒四十九粒，乳香一钱。研匀，男用生姜、女用当归，酒下。（《寿域神方》） ③治胃痛:大红枣（去核）七个，每个内入白胡椒七粒，线扎好，饭锅上蒸七次，共捣为丸，如绿豆大。每服七丸，温滚水下，如壮实者用十丸。服后痛止，而胃中作热作饥，以粥饭压之即安。此寒食痰次皆治。（《百草镜》） ④治反胃呕哕吐食，数日不定:胡椒三分（末），生姜一两（微煨切）。上件药，以水二大盏，煎取一盏，去滓，分温三服。（《圣惠方》） ⑤治翻胃及不怕饮食:半夏（汤洗十遍）、胡椒。上等分，为细末，姜汁为丸，如梧桐子大。每服三、五十丸，姜汤下。（《百一选方》） ⑥治翻胃:胡椒一味，醋浸之，晒干，醋浸不计遍数，愈多愈好，碾末醋糊为丸。淡醋汤下十丸，加至三、四十丸。（《证治要诀》） ⑦治夏月冷泻及霍乱:胡椒碾末，饭丸梧子大。每米饮下四十丸。（《卫生易简方》） ⑧治霍乱吐泻:胡椒四十九粒，绿豆一百四十九粒。研匀，木瓜汤服一钱。（《仁斋直指方》） ⑨治疟疾一日一次，或隔日一次:白胡椒，研细末，用小瓶装好，不令泄气，再用蝉蜕研末，亦以瓶装之（蝉退要用全的，连头、足用）。用时每药分量只要如黄豆大，合成一处，用普通膏药一张，将药放在中间，在期前两小时至四小时以内，贴于背后天柱穴，愈后再将膏药撕去。（《中医杂志》（9）:500，1956） ⑩治缺钙抽搐:白胡椒二十粒，鸡蛋皮两个。将上药焙黄后共研成粉，分为十四包。每日一包，开水冲服。（内蒙古《中草药新医疗法资料选编》） ⑾治小肠淋，沙石难出，疼痛:胡椒、朴硝各一两。上二味，捣罗为细散。温汤调下二钱匕，并二服。（《圣济总录》二拗散） ⑿治阴囊湿疹:胡椒十粒。研成粉，加水2000毫升，煮沸。外洗患处，每天二次。（《草医草药简便验方汇编》） ⒀治风虫牙痛:胡椒、荜拨等分。为末，蜡丸，麻子大。每用一丸，塞蛀孔中。（《卫生易简方》） ⒁治风虫客寒，三般牙痛，呻吟不止:胡椒九粒，绿豆十一粒，布裹捶碎，以丝绵包作一粒，患处咬定，涎出吐去。（《韩氏医通》） ⒂治冻伤:胡椒10％，白酒90％。把胡椒浸于白酒内，七天后过滤使用。涂于冻伤处，每日一次。（内蒙古《中草药新医疗法资料选编》） ⒃治蜈蚣咬伤:胡椒，研末调敷。（《多能鄙事》） ⒄治三焦咳，肺胃虚寒，咳逆呕吐，腹胁胀满，不能饮食：胡椒、荜茇、款冬花、甘草、干姜、陈橘皮各60g，白术75g，细辛、高良姜各60g。上为末，炼蜜丸，如梧子大，每服15g，温水下。方中胡椒温中散寒，止咳，为君药。（《圣济总录》胡椒理中丸） ⒅治诸呕、逆膈气，反胃吐食：胡椒、砂仁、丁香、红豆各21粒。上为细末，姜汁为丸，皂角子大，每服1丸，以枣1个去核，填药，面裹煨熟，空腹细嚼，白水送下，每日3次。方中胡椒温中散寒，降逆止呕，为君药。（《卫生宝鉴》红豆丸）' where id=1822; -- 胡椒
update herbs set taste='性平，味甘。', channel='入脾、肺、肾经。', effect='①壮筋骨，益精髓，变白发：黄精、苍术各四斤，枸杞根、柏叶各五斤，天门冬三斤。煮汁一石，同曲十斤，糯米一石，如常酿酒饮。（《纲目》） ②补精气：枸杞子（冬采者佳），黄精等分。为细末，二味相和，捣成块，捏作饼子，干复捣为末，炼蜜为丸，如梧桐子大。每服五十丸，空心温水送下。（《奇效良方》枸杞丸） ③治脾胃虚弱，体倦无力：黄精、党参、淮山药各一两，蒸鸡食。（《湖南农村常用中草药手册》） ④治肺劳咳血，赤白带：鲜黄精根头二两，冰糖一两，开水炖服。（《闽东本草》） ⑤治肺结核，病后体虚：黄精五钱至一两。水煎服或炖猪肉食。（《湖南农村常用中草药手册》） ⑥治小儿下肢痿软：黄精一两，冬蜜一两。开水炖服。（《闽东本草》） ⑦治胃热口渴：黄精六钱，熟地、山药各五钱，天花粉，麦门冬各四钱。水煎服。（《山东中草药手册》） ⑧治眼，补肝气，明目：蔓菁子一斤（以水淘净），黄精二斤（和蔓菁子水蒸九次，曝干）。上药，捣细罗为散。每服，空心以粥饮调下二钱，日午晚食后。以温水再调服。（《圣惠方》蔓菁子散） ⑨治荣气不清，久风入脉，因而成癞，鼻坏色败，皮肤痒溃：黄精根（去皮洗净）二斤。日中曝令软，纳粟米饭甑中同蒸之，二斗米熟为度，不拘时服。（《圣济总录》） ⑩治蛲虫病：黄精八钱，加冰糖二两，炖服。（《福建中医药》（6）：44，1965）' where id=1823; -- 黄精
update herbs set taste='辛；苦；微温。', channel='心；肾经', effect='①治跌打损伤：海风藤、大血藤、竹根七、山沉香、红牛膝、地乌龟。泡酒服。（《四川中药志》） ②治支气管哮喘，支气管炎：海风藤、追地风各二两。用白酒一斤，浸泡一周。日服二次，每次10毫升，早晚空腹服。服时不可加温，否则失效。心脏病人及孕妇忌服，感冒及月经期暂停服。（《全展选编·内科》） ③治跌打损伤：海风藤、大血藤、竹根七、山沉香、红牛膝、地乌龟。泡酒服。方中海风藤通经络，为君药。（《四川中药志》） ④治支气管哮喘，支气管炎：海风藤、追地风各60g。用白酒1斤，浸泡1周，日服2次，每次10毫升，早晚空腹服。服时不可加温，否则失效。心脏病人和孕妇忌服，感冒和月经期暂停用。方中海风藤祛风湿，通经络，为君药。（《全展选编》） ⑤治风热感冒，头痛目赤，咽喉肿痛，肺热咳嗽，消渴盗汗等：海风藤84.375g，鸡血藤、葳灵仙68.75g，五加皮、防己、苏木各50g,只草乌34.6875g，甘草18.75g。防己、苏木依法渗漉，五加皮一味蒸汽蒸馏，收集馏液，残渣与其余甘草等6味，用水煎3次，至煎出液味尽，去渣，将煎出液分次过滤合并，浓缩至稠膏状，加入上述馏液与防己、苏木的渗出液，混合均匀，滤清，使成1000毫升。每服1匙，1日3次，温开水冲服。方中海风藤祛风湿，为君药。（《浙江省药品标准》祛风骨痛露）', tips='祛风湿；通经络；理气；止痛。主风寒湿痹；肢节疼痛；筋脉拘挛；脘腹冷痛；水肿。治风寒湿痹，关节疼痛，筋脉拘挛，跌打损伤，哮喘，久咳。 ①《本草再新》：行经络，和血脉，宽中理气，下湿除风，理腰脚气，治疝，安胎。 ②《浙江中药手册》：宣痹，化湿，通络舒筋。治腿膝痿痹，关节疼痛。' where id=1824; -- 海风藤
update herbs set alias='西洋人参，洋参，西参，花旗参、广东人参。', taste='味甘；微苦；性寒', channel='归肺；胃；心；肾经', effect='①治肠红：西洋参蒸桂圆服之。（《类聚要方》）' where id=1825; -- 西洋参
update herbs set taste='苦，平。', effect='①治毒攻手足肿，疼痛欲断：虎杖根，锉，煮，适寒温以渍足。（《补缺肘后方》） ②治筋骨痰火，手足麻木，战摇，痿软：斑庄根一两，川牛膝五钱，川茄皮五钱，防风五钱，桂枝五钱，木瓜三钱。烧酒三斤泡服。（《滇南本草》） ③治胆囊结石：虎杖一两，煎服；如兼黄疸可配合连钱草等煎服。（《上海常用中草药》） ④治五淋：苦杖不计多少，为末.每服二钱，用饭饮下，不拘时候。（《姚僧坦集验方》） ⑤治月经闭不通，结瘕，腹大如瓮，短气欲死：虎杖根百斤（去头去土，曝干，切），土瓜根、牛膝各取汁二斗。上三味细切，以水一斛，浸虎杖根一宿，明日煎取二斗，内土瓜、牛膝汁，搅令调匀，煎令如饧。每以酒服一合，日再夜一。宿血当下，若病去，止服。（《千金方》） ⑥治妇人月水不利，腹胁妨闷，背膊烦疼：虎杖三两，凌霄花一两，没药一两。上药，捣细罗为散。不计时候，以热酒调下一钱。（《圣惠方》） ⑦治产后瘀血血痛，及坠扑昏闷：虎杖根，研末，酒服。（《纲目》） ⑧治腹内积聚，虚胀雷鸣，四肢沉重，月经不通，亦治丈夫病：高地虎杖根细切二斛，以水二石五斗，煮取一大斗半，去滓，澄滤令净，取好淳酒五升和煎，令如饧。每服一合，消息为度，不知，则加之。（《千金方》虎杖煎） ⑨治肠痔下血：虎杖根，洗去皴皮，锉焙，捣筛，蜜丸如赤豆，陈米饮下。（《本草图经》） ⑩治红白痢：酸汤秆三钱，何首乌三钱，红茶花三钱，天青地白二钱。煎水兑红糖吃。（《贵阳民间药草》） ⑾治诸恶疮：虎杖根，烧灰贴。（《本草图经》） ⑿治痈肿疼痛：酸汤秆、土大黄为末。调浓茶外敷。（《贵阳民间药草》）' where id=1826; -- 虎杖
update herbs set alias='蘧。', taste='苦；涩；平；', channel='入心、肝、脾经。', effect='①治秋时晚发之伏暑，并治湿温初起：连翘三钱（去心），杏仁二钱（去皮、尖，研），瓜蒌壳三钱，陈皮一钱五分，茯苓三钱，制半夏一钱，甘草五分，佩兰叶一钱。加荷叶二钱为引，水煎服。（《时病论》） ②治阳水浮肿：败荷叶烧存性，研末。每服二钱，米饮调下，日三服。（《证治要诀》） ③治雷头风证，头面疙宿肿痛，憎寒发热，状如伤寒：荷叶一枚，升麻五钱，苍术五钱。水煎温服。（《内经类编试效方》清震汤） ④治阳乘于阴，以致吐血衄血：生荷叶、生艾叶、生柏叶、生地黄各等分。上研，丸鸡子大。每服一丸，水煎服。（《妇人良方》四生丸） ⑤治吐血不止：㈠经霜败荷叶，烧存性，研末，新水服二钱。（《肘后方》）㈡嫩荷叶七个，擂水服。（《纲目》） ⑥治吐血咯血：荷叶焙干，为末，米饮下二钱匕。（《经验后方》） ⑦治崩中下血：荷叶（烧研）半两，蒲黄、黄芩各一两。为末。每空心酒服三钱。（《纲目》） ⑧治下痢赤白：荷叶烧研，每服二钱：红痢蜜、白痢沙糖汤下。（《纲目》） ⑨治产后血运，烦闷不识人。或狂言乱语，气欲绝：荷叶三片，蒲黄二两，甘草二两（炙微赤，锉）。上药捣筛为散。每服三钱，以水一中盏，煎至五分，入生地黄汁一合，蜜半匙，更煎三，五沸，去滓，不计时候温服。（《圣惠方》荷叶散） ⑩治妊娠伤寒，大热闷乱，燥渴，恐伤胎脏：卷荷叶嫩者（焙干）一两，蚌粉花半两。上为末。每服二钱，入蜜少许，新汲水调下，食前服。（《三因方》罩胎散） ⑾治脱肛不收：贴水荷叶，焙，研，酒服二钱，仍以荷叶盛末坐之。（《经验良方》） ⑿治遍身风宿：荷叶三十枚，石灰一斗，淋汁，合煮渍之，半日乃出，数日一作。（《圣惠方》） ⒀治赤游火丹：新生荷叶，捣烂，入盐涂之。（《摘元方》） ⒁治黄水疮：荷叶烧炭，研细末，香油调匀，敷患处，一日二次。（《单方验方新医疗法选编》） ⒂治脚胫生疮，浸淫腿膝，脓水淋漓，热痹痒痛：干荷叶四个，藁本二钱半。上细切，水二斗，煎至五升，去渣。温热得所，淋渫，仍服大黄左经汤。（《证治准绳》荷叶藁本汤） ⒃治漆疮：荷叶（燥者）一斤。以水一斗，煮取五升。洗了，以贯众末掺之，干则以油和涂。（《圣济总录》荷叶汤） ⒄治扑打坠损，恶血攻心，闷乱疼痛：火干荷叶五斤。烧令烟尽，细研，食前以童子热小便-小盏，调三钱匕，日三服。（《圣惠方》） ⒅治斧伤疮：荷叶烧研擦之。（《濒湖集简方》）' where id=1827; -- 荷叶
update herbs set alias='水马，虾姑，龙落子、马头鱼。', taste='味甘；咸；性温。', channel='入肝、肾经。', effect='①治远年虚实积聚瘕块：木香一两，海马子一对（雌者黄色，雄者青色），大黄（炒、锉）、青橘皮（汤浸，去白，焙）、白牵牛（炒）各二两，巴豆四十九粒。上六味，以童子小便浸青橘皮软，裹巴豆，以线系定，入小便内再浸七日，职出，麸炒黄，去巴豆，只使青橘皮并余药粗捣筛。每服二钱匕，水一盏，煎三、五沸，去滓，临睡温服。（《圣济总录》木香汤） ②治发背诸恶疮，兼治疔疮：海马一双（炙），穿山甲（黄土炒）、水银、朱砂各二钱，雄黄三钱，轻粉一钱，脑子、麝香各少许。上除水银外，各研为末和合，入水银再研至无星。针破疮口，点药入内，一日一点。（《急救仙方》海马拔毒散）' where id=1828; -- 海马
update herbs set taste='味苦；辛；寒；有小毒。', effect='①治中耳炎：鲜虎耳草叶捣汁滴入耳内。（《浙江民间常用草药》） ②治荨麻疹：虎耳草、青黛。煎服。（《四川中药志》） ③治风丹热毒，风火牙痛：鲜虎耳草一两，水煎服。（《南京地区常用中草药》） ④治风疹瘙痒，湿疹：鲜虎耳草五钱至一两。煎服。（《上海常用中草药》） ⑤治湿疹，皮肤瘙痒：鲜虎耳草一斤，切碎，加95％酒精拌湿，再加30％酒精1000毫升浸泡一周，去渣，外敷患处。（《南京地区常用中草药》） ⑥治肺热咳嗽气逆：虎耳草三至六钱，冰糖半两。水煎服。 ⑦治百日咳：虎耳草一至三钱，冰糖三钱。煎服。 ⑧治肺痈吐臭脓：虎耳草四钱，忍冬叶一两。水煎二次，分服。 ⑨治吐血：虎耳草三钱，猪皮肉四两。混同剁烂；做成肉饼，加水蒸熟食。（⑥方以下出《江西民间草药》） ⑩治血崩：鲜虎耳草一至二两，加黄酒、水各半煎服。（《浙江民间常用草药》） ⑾治痔疮：虎耳草一两，水煎，加食盐少许，放罐内，坐熏，一日二次，（《江西民间草药》） ⑿治冻疮溃烂：鲜虎耳草叶捣烂敷患处。（《南京地区常用中草药》） ⒀治中耳炎方《浙江民间常用草药》；治荨麻疹方《四川中药志》；虎耳草煎汤《南京地区常用中草药》；' where id=1829; -- 虎耳草
update herbs set taste='甘，寒，有毒。', effect='①治神经衰弱，失眠：含羞草一至二两（干品）。水煎服。（广州部队《常用中草药手册》） ②治带状疱疹：含羞草鲜叶捣烂外敷。（广州部队《常用中草药手册》）' where id=1830; -- 含羞草
update herbs set taste='甘，平。', effect='1.夜合花丸(圣惠方)，主治腰脚疼痛久不差。 2.经验方：合欢花、官桂、黄连、夜交藤。用于心肾不交失眠。 3.验方(子母秘录)，夜合花，为末，酒调服，主治跌打损伤疼痛。 4.治心肾不交失眠：合欢花、官桂、黄连、夜交藤。煎服。 5.治风火眼疾：合欢花配鸡肝、羊肝或猪肝，蒸服。 6.治眼雾不明：合欢花、一朵云，泡酒服。（①方以下出《四川中药志》） 7.治打搕损疼痛：夜合花末，酒调服二钱匕。（《子母秘录》） 8.治腰脚疼痛久不差：夜合花四两，牛膝一两（去苗），红蓝花一两，石盐一两，杏仁半两（汤浸去皮，麸炒微黄），桂心一两。上药捣罗为末，炼蜜和捣百余杵，丸如梧桐子大。每日空心，以温酒下三十丸，晚食前再服。（《圣惠方》夜合花丸） 9.树皮（合欢皮）含皂甙、鞣质，有解郁安神、活血消肿的功能；用于心神不安、忧郁失眠、肺痈疮肿、跌打伤痛，叶含鞣质、槲皮甙。' where id=1831; -- 合欢花
update herbs set alias='红蓝花，刺红花，草红花。', taste='味辛；性温。', channel='入心、肝经。', effect='①治女子经脉不通，如血膈者：好红花（细擘）、苏枋木（捶碎）、当归等分。细切，每用一两，以水一升半，先煎花、木：然后入酒一盏，并当归再煎，空心食前温服。（《朱氏集验医方》） ②治热病胎死：红花酒煮汁，饮二、三盏。（《妇人良方补遗》） ③治胎衣不下：红花酒煮汁，饮二、三盏。（《产乳集验方》） ④治妇人六十二种风及腹中血气刺痛：红蓝花一两。以酒一大升，煎减半，顿服一半，未止再服。（《金匮要略》红蓝花酒） ⑤治一切肿：红蓝花，熟揉捣取汁服之。（《外台秘要方》） ⑥治喉痹壅塞不通者：红蓝花捣绞取汁一小升，服之，以差为度。如冬月无湿花，可浸干者浓绞取汁，如前服之。（《海上集验方》） ⑦治聤耳，累年脓水不绝，臭秽：红花一分，白矾一两（烧灰）。上件药，细研为末，每用少许，纳耳中。（《圣惠方》） ⑧治跌打及墙壁压伤：川麻一分，木香二分，红花三分，甘草四分。均生用，研末，黄酒送下。（《急救便方》） ⑨治褥疮：红花适量，泡酒外搽。（《云南中草药》）' where id=1832; -- 红花
update herbs set taste='味苦；性寒。', channel='入心、肺、胆、大肠经。', effect='①治小儿心热惊啼：黄芩（去黑心）、人参各一分。捣罗为散。每服一字匕，竹叶汤调下，不拘时候服。（《圣济总录》黄芩散） ②泻肺火，降膈上热痰：片子黄芩，炒，为末，糊丸，或蒸饼丸梧子大。服五十丸。（《丹溪心法》清金丸） ③治慢性气管炎：黄芩、葶苈子各等分，共为细末，糖衣为片，每片含生药0.3克，每日三次，每次五片。（内蒙古《中草药新医疗法资料选编》） ④治上呼吸道感染，肠炎：黄芩切碎，加四倍量水浸泡四小时，过滤残渣，再加二倍水浸泡两次，合并滤液，用20％明矾液倒入浸液中，调节pH为3.5（每100公斤黄芩，需明矾6～8公斤），产生黄色沉淀，静置四小时，弃去上层清液，将沉淀物装入布袋中加水过滤，烘干，粉碎，造粒打片。每次服二至三片。（辽宁《中草药新医疗法资料选编》） ⑤治少阳头痛及太阳头痛，不拘偏正：片黄芩，酒浸透，晒干为末。每服一钱，茶、酒任下。（《兰室秘藏》小清空膏） ⑥治太阳与少阳合病，自下利者：黄芩三两，芍药二两，甘草二两（炙），大枣十二枚（擘）。上四味，以水一斗，煮取三升，去滓。温服一升，日再夜一服。（《伤寒论》黄芩汤） ⑦治淋，亦主下血：黄芩四两，细切，以水五升，煮取二升，分三服。（《千金翼方》） ⑧治吐血衄血，或发或止，皆心脏积热所致：黄芩一两（去心中黑腐），捣细罗为散。每服三钱，以水一中盏，煎至六分。不计时候，和滓温服。（《圣惠方》黄芩散） ⑨治崩中下血：黄芩，为细末。每服一钱，烧秤锤淬酒调下。（《本事方》） ⑩治妇人四十九岁已后，天癸却行，或过多不止：黄芩心枝条者二两（重用米醋，浸七日，炙干，又浸又炙，如此七次）。为细末，醋糊为丸，如梧桐子大。每服七十丸，空心温酒送下，日进二服。（《瑞竹堂经验方》芩心丸） ⑾安胎：白术、黄芩、炒曲。上为末，粥丸，服。（《丹溪心法》） ⑿治肝热生翳，不拘大Z’bJL：黄芩一两，淡豉三两，为末。每服三钱，以热猪肝襄吃，温扬送下，日二撮。忌酒，面。（（卫生家宝方）） ⒀治眉眶痛，属风热与痰：黄芩（酒漫，炒）、白芷。上为末，茶清调二钱。（（丹溪心法）） ⒁治灸疮血出：酒炒黄芩二钱。为末，酒服。（（怪证奇方》） ⒂治火丹：杵黄芩末，水调敷之。（（G阴沸验方）） ⒃治产后血渴，饮水不止：黄芩（新瓦上焙干）、麦门冬（去心）各半两。上件，细切。每服三钱，水一盏半，煎至八分，去滓温服，不拘时候。（倘氏家藏方）', tips='恶葱实。畏丹砂、牡丹、藜芦。 ②《本草经疏》：脾肺虚热者忌之。凡中寒作泄，中寒腹痛，肝肾虚而少腹痛，血虚腹痛，脾虚泄泻，肾虚溏泻，脾虚水肿，血枯经闭，气虚小水不利，肺受寒邪喘咳，及血虚胎不安，阴虚淋露，法并禁用。' where id=1833; -- 黄芩
update herbs set taste='苦；甘；涩；性微温。', channel='入肝、肾经。', effect='①乌须发，壮筋骨，固精气：赤、白何首乌各-斤（米泔水浸三、四日，瓷片刮去皮，用淘净黑豆二升，以砂锅木甑铺豆及首乌，重重铺盖，蒸至豆熟取出，去豆、暴干，换豆再蒸，如此九次，暴干为末），赤、白茯苓各一斤（去皮，研末，以水淘去筋膜及浮者，取沉者捻块，以人乳十碗浸匀，晒干，研末），牛膝八两（去苗，酒浸一日，同何首乌第七次蒸之，至第九次止，晒干），当归八两（酒浸，晒），枸杞子八两（酒浸，晒），菟丝子八两（酒浸生芽，研烂，晒），补骨脂四两（以黑脂麻炒香，并忌铁器，石臼捣为末）。炼蜜和丸弹子大一百五十丸，每日三丸，侵晨温酒下，午时姜汤下，卧时盐汤下。其余并丸梧子大，每日空心酒服一百丸，久服极验。（《积善堂经验方》七宝美髯丹） ②治骨软风，腰膝疼，行履不得，遍身瘙痒：首乌大而有花纹者，同牛膝（锉）各-斤。以好酒一升，浸七宿，曝干，于木臼内捣末，蜜丸。每日空心食前酒下三五十丸。（《经验方》） ③治久疟阴虚，热多寒少，以此补而截之：何首乌，为末，鳖血为丸，黄豆大，辰砂为衣，临发，五更白汤送下二丸。（《赤水玄珠》何首乌丸） ④治气血俱虚，久疟不止：何首乌（自三钱以至一两，随轻重用之），当归二、三钱，人参三、五钱（或一两，随宜），陈皮二、三钱（大虚不必用），煨生姜三片（多寒者用三、五钱）。水二钟，煎八分，于发前二、三时温服之。若善饮者，以酒浸一宿，次早加水一钟煎服亦妙，再煎不必用酒。（《景岳全书》何人饮） ⑤治遍身疮肿痒痛：防风、苦参、何首乌、薄荷各等分。上为粗末，每用药半两，水、酒各一半，共用一斗六升，煎十沸，热洗，于避风处睡一觉。（《外科精要》何首乌散） ⑥治颈项生瘰疬，咽喉不利：何首乌二两，昆布二两（洗去咸味），雀儿粪一两（微炒），麝香一分（细研），皂荚十挺（去黑皮，涂酥，炙令黄，去子）。上药，捣罗为末，入前研药一处，同研令匀，用精白羊肉一斤，细切，更研相和，捣五、七百杵，丸如梧桐子大。每于食后，以荆芥汤下十五丸。（《圣惠方》何首乌丸） ⑦治瘰疬延蔓，寒热羸瘦，乃肝（经）郁火，久不治成劳：何首乌如拳大者一斤，去皮如法制，配夏枯草四两，土贝母、当归、香附各三两，川芎一两。共为末，炼蜜丸。每早、晚各服三钱。（《本草汇言》） ⑧治疥癣满身：何首乌、艾各等分，锉为末。上相度疮多少用药，并水煎令浓，盆内盛洗，甚解痛生肌。（《博济方》） ⑨治大肠风毒，泻血不止：何首乌二两，捣细罗为散，每于食前，以温粥饮调下一钱。（《圣惠方》） ⑩治自汗不止：何首乌末，水调。封脐中。（《濒湖集简方》） ⑾治破伤血出：何首乌末敷之即止。（《卫生杂兴》）' where id=1834; -- 何首乌
update herbs set taste='味辛；性微温。', channel='入肺、脾、胃经。', effect='①治伤寒头疼，寒热，喘咳，心腹冷痛，反胃呕恶，气泻霍乱，脏腑虚鸣，山岚瘴疟，遍身虚肿，产前、后血气刺痛，小儿疳伤：大腹皮、白芷、紫苏、茯苓（去皮）各一两，半夏曲、白术、陈皮（去白）、厚朴（去粗皮，姜汁炙）、苦梗各二两，藿香（去土）三两，甘草（炙）二两半。上为细末，每服二钱，水一盏，姜三片，枣一枚，同煎至七分，热服。如欲出汗，衣被盖，再煎并服。（《局方》藿香正气散） ②治暑月吐泻：滑石（炒）二两，藿香二钱半，丁香五分。为末，每服一、二钱，淅米泔调服。（《禹讲师经验方》） ③治霍乱吐泻：陈皮（去白）、藿香叶（去土）。上等分，每服五钱，水一盏半，煎至七分，温服，不拘时候。（《百一选方》回生散） ④治疟：高良姜、藿香各半两。上为末，均分为四服，每服以水一碗，煎至一盏，温服，未定再服。（《鸡峰普济方》藿香散） ⑤香口去臭：藿香洗净，煎汤，时时噙漱。（《摘元方》） ⑥治小儿牙疳溃烂出脓血，口臭，嘴肿：土藿香，入枯矾少许为末，搽牙根上。（《滇南本草》） ⑦治胎气不安，气不升降，呕吐酸水：香附、藿香、甘草各二钱。为末，每服二钱，入盐少许，沸汤调服之。（《圣惠方》） ⑧治冷露疮烂：藿香叶、细茶等分。烧灰，油调涂叶上贴之。（《包会应验方》） ⑨治刀伤流血：土藿香、龙骨，少许为末，外敷。（《滇南本草》）' where id=1835; -- 藿香
update herbs set taste='味苦；性微寒', channel='肝；肺；心；大肠经', effect='①治大肠下血：槐花、荆芥穗等分。为末，酒服一钱匕。（《经验方》） ②治脏毒，酒病，便血：槐花（半两炒，半两生），山栀子一两（去皮，炒）。上为末。每服二钱，新汲水调下。食前服。（《经验良方》槐花散） ③治暴热下血：生猪脏一条，洗净，控干，以炒槐花末填满扎定，米醋炒，锅内煮烂，擂，丸弹子大，日干。每服一丸，空心，当归煎酒化下。（《永类钤方》） ④治诸痔出血：槐花二两，地榆、苍术各一两五钱，甘草一两。俱微炒，研为细末，每早晚各食前服二钱。气痔（因劳损中气而出血者）人参汤调服；酒痔（因酒积毒过多而出血者）陈皮、干葛汤调服；虫痔（因痒而内有虫动出血者）乌梅汤调服；脉痔（因劳动有伤，痔窍血出远射如线者）阿胶汤调服。（《杜氏家抄方》） ⑤治小便尿血：槐花（炒）、郁金（煨）各一两。为末。每服二钱，淡豉汤下。（《箧中秘宝方》） ⑥治血淋：槐花烧过，去火毒，杵为末。每服一钱，水酒送下。（《滇南本草》） ⑦治血崩：陈槐花一两，百草霜半两。为末。每服三、四钱，温酒调下；若昏愦不省人事，则烧红秤锤淬酒下。（《良朋汇集》槐花散） ⑧治白带不止：槐花（炒）、牡蛎（煅）等分。为末。每酒服三钱，取效。（《摘元方》） ⑨治衄血不止：槐花、乌贼鱼骨等分。半生半炒，为末，吹鼻。（《世医得效方》） ⑩治吐血不止：槐花不拘多少。火烧存性，研细，入麝香少许。每服三钱匕，温糯米饮调下。（《圣济总录》槐香散） ⑾治舌出血不止，名曰舌衄：槐花，晒干研末，敷舌上，或火炒，出火毒，为末敷。（《奇效良方，，槐花敢） ⑿治赤白痢疾：槐花（微炒）三钱，白芍药（炒）二钱，枳壳（麸炒）一钱。甘草五分。水煎服。（《本草汇言》） ⒀治疔疮肿毒，一切痈疽发背，不问已成未成，但焮痛者皆治：槐花（微炒）、核桃仁二两，无灰酒一钟。煎千余沸，热服。（《医方摘要》） ⒁治疮疡：槐花二合，金银花五钱。酒二碗煎服之，取汗。（《医学启蒙》槐花金银花酒） ⒂治杨梅疮，棉花疮毒及下疳，初感或毒盛经久难愈者：槐花蕊（拣净，不必炒），每食前清酒吞下三钱许，早中晚每日三服。如不能饮酒，滚水盐汤俱可送下。（《景岳全书》） ⒃治中风失音：炒槐花，三更后仰卧嚼咽。（《世医得效方》）' where id=1836; -- 槐花
update herbs set taste='甘苦，寒，有毒。', channel='心；肝经。', effect='①治传染性肝炎：黄藤一至二两，酸咪咪（大叶酸浆草）五钱。煮猪骨或鸡肉服，也可蒸甜酒服。（广西《中草药新医疗法处方集》） ②治天泡疮：黄藤五钱，山东管五钱。共研末，开茶油调涂患处。（《陆川本草》）' where id=1837; -- 黄藤
update herbs set effect='1、体虚自汗（玉屏风散）：黄芪5钱，白术3钱，防风2钱。水煎服。 2、脾胃虚弱以及气虚下陷引起的胃下垂，肾下垂，子宫脱垂，脱肛（补中益气汤）：黄芪4钱，党参、白术、当归各3钱，炙甘草、陈皮、升麻、柴胡各1.5钱。水煎服。 3．黄芪建中汤：黄芪15g，大枣10个，白芍15g，桂枝、生姜、甘草各10g，饴糖50g。黄芪等六种煎水取汁，入饴糖待溶化后饮用。 4．黄芪补肺饮：黄芪30g，麦冬15g，五味子、乌梅各6g。煎水取汁，以蜂蜜调味。 本方以黄芪补肺益气、固表，以五味子补肾敛肺，乌梅助五味子敛肺止咳，麦冬养阴润肺。用于气虚阴伤，自汗口渴，咳嗽久不止。 5．黄芪桂枝五物汤：黄芪30g，赤芍、桂枝各15g，生姜10g，大枣10个，煎汤饮。 6．用于气虚里寒，腹中拘急疼痛，喜温慰，自汗，脉虚：本方以黄芪、大枣、甘草补脾益气，桂枝、生姜温阳散寒，白芍缓急止痛，饴糖补脾缓急。（《金匮要略》）。 7．用于气虚血滞，肌肤麻木，或肢体疼痛，或半身不遂：本方重用黄芪补气，并鼓舞气血运行，以赤芍活血行滞，桂枝温通血脉。源于《金匮要略》。' where id=1838; -- 黄芪
update herbs set alias='檗木，檗皮，黄檗。', taste='苦，寒。', channel='入肾、膀胱经。', effect='①治小儿热痢下血：黄檗半两，赤芍药四钱。上同为细末，饭和丸，麻子大。每服一、二十丸，食前米饮下，大者加丸数。（《阎氏小儿方论》） ②治痢疾：黄柏300克，翻白草450克，秦皮300克。将翻白草、秦皮全部及黄柏200克，共水煎两次，合并煎液，用文火浓缩成膏状，将剩余100克黄柏研细粉加入膏中，搅匀，低温烘干，研细粉。每服一、二克，日三次。（辽宁《中草药新医疗法资料选编》） ③治妊娠及产后寒热下痢：黄檗一斤，黄连一升，栀子二十枚。上三味，细切，以水五升，渍一宿，煮三拂，服一升，一日一夜令尽。呕者加橘皮一把，生姜二两。（《千金翼方》） ④治小儿热泻：黄檗，焙为末，用米汤和丸粟米大，每服一、二十丸，米汤下。（《十全博救方》） ⑤治消渴尿多能食：黄檗一斤，水一升，煮三、五沸，渴即饮之，恣饮数日。（《独行方》） ⑥治伤寒身黄，发热：肥栀子十五个（擘），甘草一两（炙），黄柏二两。上三味，以水四升，煮取一升半，去滓，分温再服。（《伤寒论》栀子柏皮汤） ⑦治筋骨疼痛，因湿热者：黄檗（炒）、苍术（米泔浸、炒）。上二味为末，沸汤入姜汁调服。二物皆有雄壮之气，表实气实省，加酒少许佐之。（《丹溪心法》二妙散） ⑧治热甚梦泄，怔忪恍忽，膈壅舌干：黄檗（去粗皮）一两。搀罗为末，入龙脑一钱匕，同研匀，炼蜜和丸如梧桐子大。每服一丸至十九丸，浓煎麦冬汤下。（《圣济总录》清心丸） ⑨治白淫，梦泄遗精及滑出而不收：黄檗一斤（放新瓦上烧令通赤为度），真蛤粉一斤。上为细末，滴水为丸，如桐子大。每服一百丸，空心酒下。（《素问病机保命集》珍珠粉丸） ⑩治下阴自汗，头晕腰酸：黄柏三钱，苍术四钱，川椒三十粒，加水2000毫升，煎至600毫升。每次100毫升，一日三次，二日服完。（《中级医刊》（3）：177，1966） ⑾降阴火、补肾水：黄檗（炒褐色）、知毋（洒浸，炒）各四两，热地黄（酒蒸）、龟板（酥炙）各六两。上为末，猪脊髓、蜜丸。服七十丸，空心盐白汤下。（《丹溪心法》大补丸） ⑿降心火，益肾水：黄檗三两，砂仁一两半，甘草一两。上为细末，稀糊为丸，如梧棍子大。每服五个丸，用肉苁蓉半两，切碎，用酒一大盏，浸一宿，次日早空心煎三、四沸，去滓，以清酒送下。（《奇效良方》封髓丹） ⒀治时行赤目：黄檗，去粗皮，为末，湿纸包裹，黄泥固，煨干。每用一弹子大，纱帕包之，浸水一盏，饭上蒸熟，乘热熏洗。一丸可用三、五次。（《眼科龙木论》五行汤） ⒁治小儿蓐内赤眼：黄檗，以乳浸，点之。（《小品方》） ⒂治口中及舌上生疮：捣黄檗含之。（《千金方》） ⒃治小儿重舌：黄檗，以竹沥渍取，细细点舌上。（《千金方》） ⒄治口疳臭烂：黄檗五钱，铜绿三钱。共为末掺之，去涎，愈。（《小品方》） ⒅治唇疮痛痒：黄檗末，以野蕾薇根捣汁调涂。（《圣济总录》） ⒆治肺壅，鼻中生疮，肿痛：黄檗、槟榔等分。捣罗为末，以猪脂调敷之。（《圣惠方》） ⒇治奶发，诸痈疽发背及妒乳：捣黄檗末，筛，鸡子白和，厚涂之。干，复易。（《补缺肘后方》） （21）治痈疽肿毒；黄檗皮（炒）、川乌头（炮）等分。为末调涂之，留头，频以米泔水润湿。（《濒湖集简方》） （22）治男子阴疮损烂：㈠煮黄檗洗之，又白蜜涂之。㈡黄连、黄檗等分，末之，煮肥猪肉汁，渍疮讫，粉之。（《补缺肘后方》） （23）治小儿脐疮不合：黄檗末涂之。（《子母秘录》） （24）治小儿脓疮，遍身不干：黄檗末，入枯矾少许掺之。（《简便单方》） （25）黄连解毒汤 （《外台秘要》）主治一切实热火毒，三焦热盛之证。黄连9g，黄芩6g，黄柏6g，栀子9g。上四味切，以水六升，煮取二升，分二服。方中以大苦大寒之黄连清泻心火为君，兼泻中焦之火。 （26）白头翁汤（《伤寒论》）主治热毒痢疾。主治热入营分证。白头翁15g，黄柏12g，黄连6g，秦皮12g。上药四味，以水七升，煮取二升，去滓，温服一升，不愈再服一升。方中黄柏泻下焦湿热。 （27）当归六黄汤（《兰氏秘藏》）主治阴虚有火，发热盗汗，面赤，心烦，口干唇燥，大便秘结，舌红，脉数。当归9g，生地15g，熟地12g，黄芩9g，川连8g，黄柏8g，黄芪15g。上药为粗末，每服15g，水二盏，煎至一盏，食前服，小儿减半服之。方中川连、黄芩、黄柏泻火坚阴，使火不内扰' where id=1839; -- 黄柏
update herbs set taste='甘；平。', channel='入心、肝经。', effect='①治咳有微热，烦满，胸心甲错，是为肺痈。黄昏（是合昏皮也）手掌大一片。细切，以水三升，煮取一升，分三服。（《千金方》黄昏汤） ②治肺痈久不敛口：合欢皮、白蔹。二味同煎服。（《景岳全书》合欢饮） ③治打扑伤损筋骨：夜合树皮四两（炒干，末之），入麝香、乳香各一钱。每服三大钱，温酒调，不饥不饱时服。（《续本事方》） ④治打扑伤损骨折：夜合树（去粗皮，取白皮，锉碎，炒令黄微黑色）四两，芥菜子（炒）一两。上为细末，酒调，临夜服；粗滓罨疮上，扎缚之。此药专按骨。（《百一选方》） ⑤治蜘蛛咬疮：合欢皮，捣为末，和铛下墨，生油调涂。（《本草拾遗》）', tips='安神解郁，活血消痈。主心神不安；忧郁，不眠，内外痈疡，跌打损伤。用于心神不安，忧郁失眠，肺痈疮肿，跌扑伤痛。 ①《本经》：主安五脏，和心志，令人欢乐无忧。 ②《本草拾遗》：杀虫。 ③《日华子本草》：煎膏，消痈肿并续筋骨。 ④《纲目》：和血，消肿，止痛。 ⑤《分类草药性》：消瘰疬。 ⑥《动植物民间药》：治咳嗽。 ⑦南川《常用中草药手册》：治心气躁急、失眠及筋挛。' where id=1840; -- 合欢皮
update herbs set taste='苦，寒。', channel='归心、脾、胃、肝、胆、大肠经。', effect='①治心烦懊憹反复，心乱，怔忡，上热，胸中气乱，心下痞闷，食入反出：朱砂四钱，黄连五钱，生甘草二钱半。为细末，汤浸蒸饼，丸如黍米大。每服一十丸，食后时时津唾咽下。（《仁斋直指方》黄连安神丸） ②治少阴病，得之二三日以上，心中烦，不得卧：黄连四两，黄芩二两，芍药二两，鸡子黄二枚，阿胶三两（一云三挺）。上五味，以水六升，先煮三物，取二升，去滓，纳胶烊尽，小冷，纳鸡子黄，搅令相得。温服七合，日三服。（《伤寒论》黄连阿胶汤） ③治心肾不交，怔忡无寐：生川连五钱，肉桂心五分。研细，白蜜丸。空心淡盐汤下。（《四科简效方》交泰丸） ④治心经实热：黄连七钱，水一盏半，煎一盏，食远温服。小儿减之。（《局方》泻心汤） ⑤治心下痞，按之濡，其脉关上浮者：大黄二两，黄连一两。上二味，以麻沸汤二升渍之，须臾绞去滓。分温再服。（《伤寒论》大黄黄连泻心汤） ⑥治小结胸病，正在心下，按之则痛，脉浮滑者：黄连一两，半夏半升（洗），栝楼实大者一枚。上三味，以水六升，先煮栝楼，取三升，去滓，内诸药，煮取二升，去滓。分温三服。（《伤寒论》小陷胸汤） ⑦治大热盛，烦呕，呻吟，错语，不得卧：黄连三两，黄芩、黄柏各二两，栀子十四枚（擘）。上四味，切，以水六升，煮取二升，分二服。忌猪肉、冷水。（《外台秘要方》黄连解毒汤） ⑧治伤寒胸中有热，胃中有邪气，腹中痛，欲呕吐者：黄连三两，甘草三两（炙），干姜三两，桂枝三两（去皮），人参二两，半夏半升（洗），大枣十二枚（擘）。上七味。以水一斗，煮取六升，去滓。温服，昼三夜二。（《伤寒论》黄连汤） ⑨治呕吐酸水，脉弦迟者：人参、白术、干姜、炙甘草、黄连，水煎服。（《症因脉治》连理汤） ⑩治肝火：黄连六两，吴茱萸一两或半两。上为末，水丸或蒸饼丸。白汤下五十丸。（《丹溪心法》左金丸一名回令丸） ⑾治诸痢牌泄，脏毒下血：雅州黄连半斤，去毛，切，装肥猪大肠内，扎定，入砂锅中，以水酒煮烂，取连焙，研末，捣肠和丸梧子大。每服百丸，米汤下。（《仁斋直指方》） ⑿治下痢：宣黄连、青木香，同捣筛，白蜜丸，如梧子。空腹饮下二、三十丸，日再。其久冷人，即用煨熟大蒜作丸。婴孺用之亦效。（《兵部手集方》香连丸） ⒀治大冷洞痢肠滑，下赤白如鱼脑，日夜无节度，腹痛不可堪忍者：黄连六两，干姜二两，当归、阿胶各三荫。上四味，末之，以大醋八合烊胶和之，并手丸如大豆许，干之。大人饮服三十丸，小儿百日以还三丸，期年者五丸，余以意加减，日三服。（《千金方》驻车丸） ⒁治脏毒：鹰爪黄连末，用独头蒜一颗，煨香烂熟，研和入臼，治丸如梧子大。每服三、四十丸，陈米饮下。（《本事方释义》蒜连丸） ⒂治脾受湿气，泄利不止，米谷迟化，脐腹刺痛，小儿有疳气下痢，亦能治之：黄连（去须）、吴茱萸（去梗，炒）、白芍药各五两。上为细末，面糊为丸，如梧桐子大。每服二十丸，浓煎米饮下，空心日三服。（《局方》戊己丸） ⒃治心气不足，吐血衄血，亦治霍乱：大黄二两，黄连、黄芩各一两。上三味，以水三升，煮取一升。顿服之。（《金匮要略》泻心汤） ⒄治消渴能饮水，小便甜，有如脂麸片，日夜六、七十起：冬瓜一枚，黄连十两。上截冬瓜头去穰，入黄连末，火中煨之，候黄连熟，布绞取汁。一服一大盏，日再服，但服两三枚瓜，以差为度。（《近效方》） ⒅治妇人热劳羸瘦：黄连三两（去须），人参一两（去芦头），赤茯苓一两，黄芪一两（锉），木香半两，鳖甲一两半（涂醋，炙令黄，去裙襕），柴胡一两（去苗），地骨皮半两，桃仁一两半（汤浸去皮、尖、双仁，麸炒微黄）。上药，捣细罗为散，用好嫩猪肚一枚，将前药末安猪肚内，以线子缝合，蒸令烂熟，砂盆内研令如膏，为丸加梧桐子大。食前，以粥饮下三十丸。（《圣惠方》黄连猪肚丸） ⒆治小儿胃热吐乳：黄连二钱，清半夏二钱。共为细末，分100等分，日服三次，每次一分。（辽宁《中草药新医疗法资料选编》） ⒇治甲赤痛，除热：黄连半两，大枣一枚（切）。上二味，以水五合，煎取一合，去滓，展绵取如麻子注目，日十夜再。（《僧深集方》黄连煎） （21）治痈疽肿毒，已溃未溃皆可用：黄连、槟榔等分，为末，以鸡子清调搽之。（《简易方论》） （22）治脓疱疮，急性湿疹：黄连、松香、海螵蛸各三钱。共研细末，加黄蜡二钱，放入适量熟胡麻油内溶化，调成软膏。涂于患处，每日三次。涂药前用热毛巾湿敷患处，使疮痴脱落。（内蒙古《中草药新医疗法资料选编》） （23）治口舌生疮：黄连煎酒，时含呷之。（《肘后方》） （24）治小儿口疳：黄连、芦荟等分，为束。每蜜汤眼五分。走马牙疳，入蟾灰等分，青黛减半，麝香少许。（《简便单方》） （25）治醇酒厚味，唇齿作痛，或齿龈溃烂，或连头面颈项作痛：黄连（炒）一钱五分，生地黄、牡丹皮、当归各一钱，升麻二钱。上水煎服，实热便秘加大黄。（《妇人良方》清胃散） （26）治妊娠子烦，口干不得卧：黄连末，每服一钱，粥饮下，或酒蒸黄连丸，亦妙。（《妇入良方》） （27）治火烫伤：川连研末，调茶油搽之。（《中医杂志》（2）：170，1922） （28）治药中巴豆，下痢不止：末干姜、黄连，服方寸匕。（《补缺肘后方》）', tips='凡阴虚烦热，胃虚呕恶，脾虚泄泻，五更泄泻慎服。 恶菊花、芫花、玄参、白鲜皮。畏款冬。胜乌头。 ②《药性论》：恶白僵蚕。忌猪肉。 ③《蜀本草》；畏牛膝。 ④朱震亨：肠胃有寒及伤寒下早，阴虚下血，及损脾而血不归元者，皆不可用。 ⑤《本草经疏》：凡病人血少气虚，脾胃薄弱，血不足，以致惊悸不眠，而兼烦热躁渴，及产后不眠，血虚发热，泄泻腹痛；小儿痘疮阳虚作泄，行浆后泄泻；老人脾胃虚寒作泻；阴虚人天明溏泄，病名肾泄；真阴不足，内热烦躁诸证，法咸忌之，犯之使人危殆。' where id=1841; -- 黄连
update herbs set taste='甘；淡；寒；无毒。', channel='入小肠、膀胱经。', effect='①治小便不通，脐下满闷：海金沙一两，腊面茶半两。二味捣研令细。每服三戗，生姜、甘草汤调下。（《本草图经》） ②治热淋急痛：海金沙为末，生甘草汤冲服。（《泉州本草》） ③治膏淋：海金沙、滑石各一两（为末），甘草二钱半（为末）。上研匀。每服二钱，食前，煎麦门冬汤调服，灯心汤亦可。（《世医得效方，海金沙散） ④治尿酸结石症：海金沙、滑石共研为末。以车前子、麦冬、木通煎水调药末，并加蜜少许，温服。（《广西中药志》） ⑤治小便出血：海金沙为末，以新汲水调下。一方用砂糖水调下。（《普济方》） ⑥治肝炎：海金砂五钱，阴行草一两，车前六钱。水煎服，每日一剂。（《江西草药》） ⑦治脾湿太过通身肿满，喘不得卧，腹胀如鼓：牵牛一两（半生半炒），甘遂、海金沙各半两。上为细末。每服二钱，煎水一盏，食前调下，得利止后服。（《医学发明》海金沙散） ⑧治脾湿胀满：海金沙一两，白术二钱，甘草五分，黑丑一钱五分，水煎服。（《泉州本草》）' where id=1842; -- 海金沙
update herbs set taste='辛咸，寒。', channel='入心、胃、肾经。', effect='①治五脏六腑积热，天行时气疫热，以致烦满消渴：凝水石、石膏、滑石各五钱，甘草二钱。研末。每服一钱，白汤调服。（《方脉正宗》） ②治伤寒发狂，或弃衣奔走，逾墙上屋：寒水石、黄连（去须）各等分。上细末，每服二钱，浓煎甘草汤，放冷调服。（《本事方》鹊石散） ③除热瘫痫：大黄、干姜、龙骨各四两，桂枝三两，甘草、牡蛎各二两，寒水石、滑石、亦石脂、白石脂、紫石英、石膏各六两。上十二味，杵，粗筛，以韦囊盛之，取三指撮，井花水三升，煮三沸，温服一升。（《金匮要略》风引汤） ④治风热心躁，口干狂言，浑身壮热及中诸毒：寒水石半斤（烧半日，净地坑内，盆合，四面湿土壅起，候经宿取出），入甘草末、天竺黄各二两，龙脑二分。糯米膏丸，弹子大，蜜水磨下。（《姚僧坦集验方》龙脑甘露丸） ⑤治男女转脬，不得小便：寒水石二两，滑石一两，葵子一合。为末。水一斗，煮五升，时服，一升即利。（《永类钤方》） ⑥治小儿丹毒，皮肤热赤：凝水石五钱，水调和猪胆汁涂之。（《本草汇言》） ⑦治牙齿内血出，并有窍眼，时时吐血：寒水石粉、朱砂、甘草、脑子。上等分，为细末。每用少许，干掺有窍处。（《普济方》） ⑧治汤火伤灼：寒水石烧研敷之。（《卫生易简方》）' where id=1843; -- 寒水石
update herbs set taste='苦；辛；性温。', channel='入脾、胃、大肠经。', effect='①治腹满痛大便闭者:厚朴八两，大黄四两，枳实五枚。上三味，以水一斗二升，先煮二味，取五升，内大黄煮取三升。温服一升，以利为度。（《金匮要略》厚朴三物汤） ②治久患气胀心闷，饮食不得，因食不调。冷热相击，致令心腹胀满:厚朴火上炙令干，又蘸姜汁炙，直待焦黑为度，捣筛如面。以陈米饮调下二钱匕，日三服。亦治反胃，止泻。（《斗门方》） ③治脾胃气不和，不思饮食:厚朴（去粗皮，姜汁涂，炙令香净）二两半，甘草（炙）一两半，苍术（米泔水浸二日，刮去皮）四两，陈皮（去白）二两半。上四味，为末。每服一钱，水一盏，入生姜、枣子同煎七分，去滓温服，空心服之。或杵细末，蜜为丸，如梧桐子大。每服十丸，盐汤嚼下，空心服。（《博济方》平胃散） ④治因喜怒悲思忧恐惊之气，痰涎郁结，状如破絮，或如梅核，在咽喉之间，咯不出，咽不下，或中脘痞满，气不舒快，或痰涎壅盛，上气喘急，或因痰饮中结，呕逆恶心:紫苏叶二两，厚朴三两，茯苓四两，半夏五两。上细切。每服四钱，水盏半，生姜七片，枣一个，煎至六分，去滓，热服，不拘时候。（《易简方》四七汤即《金匮要略》半夏厚朴汤） ⑤治虫积:厚朴、槟榔各二钱，乌梅二个。水煎服。（《保赤全书》） ⑥治中寒洞泄:干姜、厚朴等分。上为末，蜜丸梧子大。任下三十丸。（《鲍氏小儿方》） ⑦治水谷痢久不瘥:厚朴三两，黄连三两。锉，水三升，煎取一升。空心细服。（《梅师集验方》）', tips='孕妇慎用。恶泽泻、寒水石、消石。 ②《药性论》:忌豆，食之者动气。 ③《品汇精要》:妊娠不可服。 ④《本草经疏》:凡呕吐不因寒痰冷积，而由于胃虚火气炎上；腹痛因于血虚脾阴不足，而非停滞所致；泄泻因于火热暴注，而非积寒伤冷；腹满因于中气不足、气不归元，而非气实壅滞；中风由于阴虚火炎、猝致僵仆，而非西北真中寒邪；伤寒发热头疼，而无痞塞胀满之候；小儿吐泻乳食，将成慢惊；大人气虚血槁，见发膈证；老人脾虚不能运化，偶有停积；妊妇恶阻，水谷不入；娠妇胎升眩晕；娠妇伤食停冷；娠妇腹痛泻利；娠妇伤寒伤风；产后血虚腹痛；产后中满作喘；产后泄泻反胃，以上诸证，法所咸忌。' where id=1844; -- 厚朴
update herbs set taste='甘、淡，寒。', channel='归膀胱、肺、胃经。', effect='①治身热吐痢泄泻，下痢赤白，癃闭，石淋；生津液，去留结，消蓄水，止渴宽中，除烦热心躁，腹胀痛闷，口疮，牙齿疳蚀，中暑，伤寒，疫疠：滑石六两，甘草一两(炙)。上为末。每服三钱，温水调下，日三服。惟孕妇不宜服，滑胎也。(《伤寒标本》六-散) ②治热淋，小便赤涩热痛：滑石四两。捣罗为散。每服二钱匕，煎木通汤调下，不拘时候。(《圣济总录》滑石散) ③治气塑关格不通，小便淋结，脐下妨闷兼痛：滑石八分。研如面。以水五大合和搅，顿服。(《广利方》) ④治产后淋：滑石五两，通草、车前子、葵子各四两。上四味，治下筛。酢浆水服方寸匕，稍加至二匕。(《千金方》滑石散) ⑤治小便不利，茎中疼痛，少腹急痛：滑石、蒲黄等分。上二味，治下筛。酒眼方寸匕，日三服。(《千金方》) ⑥治小便不利：滑石二分，乱发二分(烧)，白鱼二分。上三味，杵为散。饮服半钱匕，日三服。(《金匮要略》滑石白鱼散) ⑦治小便不通：滑石末一升，以车前汁和涂脐四畔，方四寸，热即易之，冬月水和亦得。(《产乳集验方》) ⑧治黄疸，日哺所发热恶寒，少腹急，身体黄，额黑，大便溏黑，足下热，此为女劳，腹满者难治：滑石、石膏各等分。上二味，治下筛。以大麦粥汁饮方寸匕，日三，小便极利则瘥。(《千金方》) ⑨治感冒久在太阳，致热蓄膀胱。小便赤涩，或因小便秘而大便滑泻。兼治湿温初得，憎寒壮热，舌苔灰色滑腻者：滑石一两，甘草二钱，连翘三钱，蝉退三钱(去足、土)，生杭芍四钱。若滑泻者，甘草须加倍。(《医学衷中参西录》宣解汤) ⑩治伤寒衄血：滑石末不拘多少。饭丸如桐子大。每服十丸，微嚼破，新水咽下。只用药末一大钱，饭少许，同嚼下亦得。老幼皆可服。(《本事方》滑石丸) ⑾治暴得吐逆不下食：生滑石细末二钱匕。温水服，仍急以热面半盏，押定。(《本草衍义》) ⑿治热毒怪病，目赤鼻胀，大喘，浑身出斑，毛发如铁，乃因中热，毒气结于下焦：滑石、白矾各-两。为末，作一服，水三碗，煎减半，不住饮之。(《夏子益治奇疾方》) ⒀治妇人脬转，小便数日不通：滑石二两，寒水石二两，葵子一合。上药捣碎。以水三中盏，煎至一盏半，去滓，食前分温二服。(《圣惠方》滑石散) ⒁治天泡湿热等疮：滑石、粉甘草(此当半用为是)、上等分为末，搽敷。或加绿豆末，以治湿热肥疮。(《景岳全书》金黄散) ⒂治小儿体热痱疮：滑石末三两，白矾灰一两，枣叶四两。上药捣罗为末。先以温浆水洗疮，后取药敷之。(《圣惠方》滑石散) ⒃治脚趾缝烂：滑石一两，石膏(煅)半两，枯白矾少许。研掺之，亦治阴下湿汗。(《濒湖集简方》)', tips='脾虚气弱，精滑及热病津伤者忌服。孕妇慎服。 恶曾青。 ②《本草经疏》：病人因阴精不足、内热以致小水短少赤涩或不利，烦渴身热由于阴虚火炽水涸者，皆禁用。脾胃俱虚者，虽作泄勿服。 ③《药品化义》：渴而小便自利者，是内津液少也；小便不利而口不渴者，是热在下焦血分也，均不宜用。且体滑，胎前亦忌之。 ④《本经逢原》：元气下陷，小便清利及精滑者勿服。' where id=1845; -- 滑石粉
update herbs set effect='1．治脱肛：鲜天荞麦、苦参各300g。水煎，趁热熏患处。方中金荞麦清热解毒，活血，为君药。（《浙江天目山药植志》） 2．治闭经：野荞麦鲜叶90g（干叶30g），捣烂，调鸡蛋4个，用茶油煎熟，加米酒共煮，内服。方中金荞麦，活血，为君药。（《全国中草药汇编》） 3．治鼻咽癌：鲜野荞麦、鲜汗防己、鲜土牛膝各30g。水煎服。另取灯心捣碎口含，用垂盆草捣烂外敷。方中金荞麦清热解毒，活血祛风湿，为君药。（《全展选编*肿瘤》）', tips='清热解毒；活血消痈；祛风除湿疮毒；蛇虫咬伤。主肺痈；肺热咳喘；咽喉肿痛；痢疾；风湿痹证；跌打损伤；痈肿癌。清热解毒，排脓祛瘀。用于肺脓疡，麻疹肺炎，扁桃体周围脓肿。' where id=1846; -- 金荞麦
update herbs set taste='辛，平。', effect='①治妇人血闭成瘕，寒热往来，子嗣不育者：卷柏四两，当归二两（俱浸酒炒），白术、牡丹皮各二两，白芍药一两，川芎五钱。分作七剂，水煎服；或炼蜜为丸，每早服四钱，白汤送。（《本草汇言》） ②治肠毒下血：卷柏、嫩黄芪各等分。为末，米饮调。每服三钱。（《本草汇言》） ③治跌打损伤，局部疼痛：鲜卷柏每次一两（干五钱）。每日一次，煎服。（《泉州本草》） ④治腹痛、喘累及吐血：卷柏、小血藤、白花草、地胡椒。用酒泡-周，中午空腹服。（《四川中药志》） ⑤治血崩、白带：卷柏五钱。水煎服。（《湖南药物志》） ⑥治汤火伤：鲜卷柏捣烂敷。（《湖南药物志》） ⑦治胃痛：垫状卷柏二两。水煎服。（《江西草药》） ⑧治吐血、便血、尿血：㈠垫状卷柏（炒焦）一两，瘦猪肉二两。水炖，服汤食肉。㈡垫状卷柏（炒焦）一两，仙鹤草一两。水煎服。（《江西草药》） ⑨治哮喘：垫状卷柏、马鞭草各五钱。水煎服，冰糖为引。（《江西草药》） ⑩治癫痫：垫状卷柏二两，淡竹叶卷心一两，冰糖二两。水煎服。（《江西草药》） ⑾治大肠下血：卷柏、侧柏、棕榈等分。烧存性为末。每服三钱，酒下；也可饭丸服。（《仁存堂经验方》）' where id=1847; -- 卷柏
update herbs set effect='1、绞股蓝交藤饮：绞股蓝10克，夜交藤15克，麦冬12克。煎水，或沸水浸泡饮。 本方以绞股蓝益气安神，夜交藤养心安神，麦冬养阴清心。用于气虚、心阴不足，心悸失眠，烦热不宁。 2、绞股蓝杜仲茶：绞股蓝15克，杜仲叶10克。沸水浸泡饮。 本方用二者降血压，绞股蓝兼以清热、安神。用于高血压病，眩晕头痛，烦热不安，失眠烦躁。 3、绞股蓝金钱草饮：绞股蓝15克，金钱草50克。加红糖适量，煎水饮。 本方以绞股蓝清热解毒，金钱草清热利湿、退黄。用于病毒性肝炎，症见湿热发黄，小便黄赤短少。 4、绞股蓝红枣汤：绞股蓝10 克、红枣5 枚。洗净后加水，文火煮至红枣熟。', tips='清热；补虚；解毒。主体虚乏力；虚劳失精；白细胞减少症；高脂血症；病毒性肝炎；慢性胃肠炎；慢性气管炎。清热解毒，止咳祛痰。用于慢性支气管炎，传染性肝炎，肾炎炎，胃肠炎。' where id=1848; -- 绞股蓝
update herbs set taste='苦，平。', channel='入肝、肾经。', effect='①治四种颓病，卵核肿胀，偏有大小；或坚硬如石；或引脐腹绞痛，甚则肤囊肿胀；或成疮毒，轻则时出黄水，甚则成痈溃烂：橘核（炒）、海藻（洗）、昆布（洗）、海带（洗）、川楝子（去肉，炒）、桃仁（麸炒）各一两，厚朴（去皮，姜汁炒）、木通、枳实（麸炒）、延胡索（炒、去皮）、桂心（不见火）、木香（不见火）各半两。为细末，酒糊为丸如桐子大，每服七十丸，空心盐酒、盐汤任下。虚寒甚者，加炮川乌一两；坚胀久不消者，加硇砂二钱（醋煮），旋入。（《济生方》橘核丸） ②治乳痈初起来溃：橘核（略炒、五钱，黄酒煎，去滓温服，不能饮酒者，用水煎，少加黄酒。（《光华医药杂志》（3）6：53，1935） ③治腰痛：橘核、杜仲各二两。炒研末，每服二钱，盐酒下。（《简便单方》） ④治酒齄风，鼻上赤：橘子核（微妙）为末，每用一钱匕，研胡桃肉一个，同以温酒调服，以知为度。（《本草衍义》）' where id=1849; -- 橘核
update herbs set taste='味甘；咸；性平。', channel='入脾、肾经。', effect='①治食积腹胀，嗳气：生豇豆适量，细嚼咽下，或捣绒泡冷开水服。（成都《常用草药治疗手册》） ②治白带，白浊：豇豆、藤藤菜。炖鸡肉服。（《四川中药志》） ③治蛇咬伤：豇豆、山慈姑、樱桃叶、黄豆叶。捣绒外敷。（成都《常用草药治疗手册》）' where id=1850; -- 豇豆
update herbs set taste='甘，温。', effect='①治关节风湿痛：铁刺苓、活血龙、山楂根各三钱至五钱。煎服。（《浙江民间草药》） ②治患脚，积年不能行，腰脊挛痹及腹屈内紧急者：菝葜净洗，锉之，一斛，以水三斛，煮取九斗，以渍曲及煮去滓，取一斛渍饭，酿之如酒法，熟即取饮，多少任意。（《补缺肘后方》） ③治筋骨麻木：菝葜浸酒服。（《南京民间药草》） ④治消渴，饮水无休：菝葜（锉，炒），汤瓶内碱各一两，乌梅二个（并核捶碎，焙干）。上粗捣筛。每服二钱，水一盏，瓦器煎七分，去滓，稍热细呷。（《普济方》菝葜饮） ⑤治小便多，滑数不禁：金刚骨为末，以好酒调三钱，服之。（《儒门事亲》） ⑥治下痢赤白：金刚根和好腊茶等分，为末，白梅肉丸如鸡头大。每服五丸至七丸，小儿三丸。赤痢甘草汤下，白痢乌梅汤下，赤白痢乌梅甘草汤下。（《履巉岩本草》） ⑦治沙石淋：菝葜二两。捣罗为细散。每服一钱匕，米饮调下。服毕用地椒煎汤浴，连腰浸。（《圣济总录》菝葜散） ⑧治乳糜尿：楤木（鸟不宿）根、菝葜根茎各一两。水煎，分早晚二次服。（《全展选编·传染病》） ⑨治食道癌：鲜菝葜一斤。用冷水三斤，浓缩成一斤时，去渣，加肥猪肉二两，待肥肉熟后即可。此系一日量，分三次服完。（《中草药治肿瘤资料选编》） ⑩治赤白带下：菝葜半斤，捣碎煎汤，加糖二两。每日服。（《江苏药材志》） ⑾治流火：铁刺苓煎汁与猪脚煮食，或配土牛膝二钱煎服。（《浙江民间草药》） ⑿治疗外科急性感染 菝葜根1斤切碎，甘草25克，水煎两次，滤液合并文火浓缩至1000毫升左右，菝葜根浓度相当于50％。每次50毫升，日服2次。门诊治疗疖痈67例，随访27例均获显效；蜂窝织炎、淋巴结炎、乳腺炎63例，随访48例，显效43例，效果不明显5例；腹部炎性包块、阑尾脓肿8例，随访7例，显效6例，效果不明显1例。 ⒀治疗风湿性关节炎 取鲜菝葜根2斤，用乙醇提取法制成300毫升注射液，每安瓿2毫升。每次肌注2毫升，每日1次。治疗52例，痊愈15例，显效10例，好转23例，无效4例。 ⒁治疗牛皮癣 取菝葜根20～40克，用温开水1500毫升浸泡10小时，煮沸40～80分钟，每日分2～3次饭后服。治疗107例，痊愈（症状消失，皮损消失，或尚留几小块损害）13例，显效（症状基本消失，皮损消退约60～80％）26例，有效（症状明显减轻，皮损消失约30～60％，或皮损普遍变平、缩小，红色减退，鳞屑减少）46例，无效23例。痊愈病例停药后，部分有复发，但一般较轻，再服菝葜仍然有效。 ⒂治疗癌肿 取菝葜根块洗净、切片、晾干，每日用干品0.5～1斤浸入6～7斤水中，1小时后用文火煎煮3小时去渣，加入肥肉1～2两再煎1小时，约得煎液500毫升，于1日内多次饮服。适用于胃癌、食管癌、直肠癌、乳腺癌、宫颈癌、鼻咽癌，其中以胃癌和食管癌效果较好。具有增进食欲、减少呕吐、疏通狭窄食管，以及利尿消肿、增强体力、提高红细胞及血红蛋白，和一定的止痛安眠作用。据200例（病情轻重不一）的观察，约45％的患者可获得近期疗效，症状缓解；个别病例可获得根治；有的控制1年多，没有症状；少数病例肿瘤缩小，但多数未见变化。本品对脾胃虚寒体质者较为适宜；此类病人服药后，感到胃肠舒适，胀气减轻，食量增加，食道癌患者粘液涎沫明显减少。反之阴亏偏热体质者，服后常易引起口干、烦躁、便秘、尿赤、口粘膜破溃，或便血、胃肠道出血。故对应用放射治疗后引起的一系列热性反应不宜应用。实践中观察到，本药对消化道致病菌有抑制作用，对肠道粘膜发炎的充血、水肿有收敛作用。因此，应用于宫颈癌放射治疗后的直肠结肠反应，出现粘液血便者，有良好效果。由于本品含有皂素及鞣酸等杂质，对胃肠道粘膜有一定的刺激性，所以加用猪肉同煎以中和皂素及杂质，以免刺激胃肠引起恶心、呕吐。', tips='祛风湿，利小便，消肿毒。治关节疼痛，肌肉麻木，泄泻，痢疾，水肿，淋病，疔疮，肿毒，瘰疬，痔疮。 ①《别录》：主腰背寒痛，风痹，益血气，止小便利。 ②《日华子本草》：治时疾瘟瘴。 ③《品汇精要》：散肿毒。 ④《纲目》：治消渴，血崩，下利。 ⑤《本草原始》：利小便。 ⑥《医林纂要》：缓肝坚肾，清小肠火，化膀胱水。治恶疮，毒疮，虫毒。 ⑦《南京民间药草》：化痰止咳。浸酒服，可治筋骨麻木。 ⑧《福建民间草药》：治疝气。 ⑨《江苏植药志》：泡酒服治心头痛。 ⑩《浙江民间草药》：治流火。 ⑾《四川中药志》：清热，除风毒。治崩、带，血淋，瘰疬，跌打损伤。 ⑿广州部队《常用中草药手册》：祛风除湿。治腰腿疼痛，风湿性关节炎，肠炎腹泻。 ⒀江西《中草药学》：解毒祛风，为疮痈要药。治历节痛风（类风湿性关节炎），肌肉麻痹，食道癌，牛皮癣。' where id=1851; -- 金刚藤头
update herbs set taste='甘酸；平。', effect='①治气郁胸闷，胃痛：鸡屎藤根一至二两。水煎服。 ②治食积腹泻：鸡屎藤一两。水煎服。 ③治小儿疳积：鸡屎藤干根五钱，猪小肚一个。水炖服。（①方以下出《福建中草药》） ④治妇女虚弱咳嗽，白带腹胀：鸡屎藤根四两，红小芭煎头四两。炖鸡服。（《重庆草药》） ⑤治红痢：鸡屎藤根四两，路边姜二两。炖肉服。（《重庆草药》） ⑥治小儿脱肛：皆治藤近根之头，老者，酒蒸晒十次，和羊肠煮食之。（《岭南采药录》） ⑦治关节风湿痛：鸡屎藤根或藤一至二两。酒水煎服。 ⑧治阑尾炎：鲜鸡屎藤根或茎叶一至二两。水煎服。 ⑨治背疽：鲜鸡屎藤二两，酒水煎服；渣或另用鲜叶捣烂敷患处。 ⑩治跌打损伤：鸡屎藤根、藤一两。酒水煎服。（⑧方以下出《福建中草药》） ⑾治有机磷农药中毒：鸡屎藤三两，绿豆一两。水煎成三大杯，先服一大杯，二至三小时服一次。药后有呕吐腹泻反应。（《单方验方调查资料选编》）', tips='祛风除湿；消食化积；解毒消肿；活血止痛。主治风湿痹痛；食积腹胀；小儿疳积；腹泻；痢疾；中暑；黄疸；肝炎；肝脾肿大；咳嗽；瘰疬；肠痈；无名肿毒；脚湿肿烂；烫火伤；湿疹；皮炎；跌打损伤；蛇蛟蝎螫。 ①汪连仕《采药书》：治风痛肠痈，跌打损伤，流注风火瘴毒，散郁气。洗疝，合紫苏煎汤。 ②《李氏草秘》：煎洗腿足诸风，寒湿痛，拘挛不能转舒。 ③《生草药性备要》：其头治新内伤，煲肉食，补虚益肾，除火补血；洗疮止痛，消热散毒。其叶擂米加糖食，止痢。 ④《纲目拾遗》：中暑者以根、叶作粉食之。虚损者杂猪胃煎服。治瘰疬用.裉煎酒，未破者消，已溃者敛。 ⑤《本草求原》：理脚湿肿烂，蛇伤，同米擂食并敷。 ⑥《植物名实图考》：为洗药，解毒，去风，清热，散寒。敷无名肿毒，并补筋骨。 ⑦《草木便方》：补虚劳，调理脾胃元气，治病后虚肿、耳鸣。 ⑧《四川中药志》：治失眠，久咳。 ⑨《重庆草药》：健脾除湿，益气补虚。常用于小儿瘦弱，脾弱气虚，食积疳积，及成人气虚浮肿，臌胀，耳呜，腹泻，遗尿，妇女虚弱白带，干病。并虚弱劳伤，虚痢，痒子瘰疬之由于气虚不愈者。 ⑩《上海常用中草药》：祛风，活血，止痛，消肿。治风湿酸痛，跌打损伤，肝脾肿大，无名肿毒。' where id=1852; -- 鸡屎藤
update herbs set taste='辛，温。', channel='①《得配本草》：入手太阴经。', effect='①治牙龈肿烂，出臭水者：芥菜杆，烧存性，研末，频敷之。（《纲目》） ②治漆疮瘙痒：芥菜煎汤洗之。（《千金方》） ③治痔疮肿痛：芥叶，捣饼，频坐之。（《谈野翁试验方》）' where id=1853; -- 芥菜
update herbs set taste='辛苦，温。', channel='入脾、肝经。', effect='①治心痛不可忍：姜黄（微炒）、当归（切，焙）各一两，木香、乌药（微炒）各半两。上四味，捣罗为散，每服二钱匕，煎茱萸醋汤调下。（《圣济总录》姜黄散） ②治九种心痛，发作无时，及虫痛不可忍者：姜黄三分，槟榔半两，干漆（捣碎，炒令烟出）半两，石灰（炒令黄色）一两。上药为细末，每服二钱，温酒调下，不拘时候。（《杨氏家藏方》姜黄散） ③治胃炎，胆道炎，腹胀闷，疼痛，呕吐，黄疸：姜黄一钱五分，黄连六分，肉桂三分，延胡索一钱二分，广郁金一钱五分，绵茵陈一钱五分。水煎服。（《现代实用中药》） ④治臂背痛，非风非痰：姜黄、甘草、羌活各一两，白术二两。每服一两，水煎。腰以下痛，加海桐皮、当归、芍药。（《赤水玄珠》姜黄散） ⑤治室女月水滞涩，调顺营气：姜黄、丁香、当归（切，焙）、芍药各半两。上四味，捣细罗为散，每服二钱匕，温酒调下。经脉欲来，先服此药，不拘时候。（《圣济总录》姜黄散） ⑥治经水先期而至，血涩少，其色赤者：当归、熟地、赤芍、川芎、姜黄、黄芩、丹皮、延胡索、香附（制）各等分。水煎服。（《医宗金鉴》姜芩四物汤） ⑦治妊娠胎漏，下血不止，腹痛：姜黄一两，当归一两（锉，微炒），熟干地黄一两，艾叶一两（微妙），鹿角胶一两（捣碎，炒令黄燥）。上药，捣筛为散，每服四钱，以水一中盏，入生姜半分，枣三枚，煎至六分，去滓，每于食前温服。（《圣惠方》姜黄散） ⑧治产后腹痛：姜黄二分，没药一分。上为末，以水及童子小便各一盏，入药煎至一盏半，分作三服，通口服，约人行五、七里，再进一服。（《普济方》姜黄散） ⑨治一切跌打：桃仁、兰叶、丹皮、姜黄、苏木、当归、陈皮、牛膝、川芎、生地、肉桂、乳香、没药。水、酒、童便煎服。（《伤科方书》姜黄汤） ⑩治牙痛不可忍：姜黄、细辛、白芷等分。上为细末，并擦二、三次，盐汤漱。（《百一选方》姜黄散） ⑾治诸疮癣初生时痛痒：姜黄敷之。（《千金方》） ⑿心痛难忍。用姜黄一两、桂三两，共研为末，每服一钱，醋汤送下。 ⒀胎寒腹痛（婴儿啼哭吐乳，大便色青，状如惊风，出冷汗）。用姜黄一钱，没药、没香、乳香各二钱，共研为末，加蜜调成丸了，如芡子大。每服一丸，钩藤煎汤化下。 ⒁产后血痛（腹内有血块）。用姜黄、桂心，等分为末，酒冲服一匙，血下尽后即愈。 ⒂疮癣初发。用姜黄研末擦上，甚效。 ⒃治心疼：姜黄、玄索、乳香、没药。上各等分为末，好酒用一盏，（心疼如手捉，一方用水煎）。每服6g，不拘时温酒调服。方中姜黄破血行气，通经止痛，为君药。 （《奇效良方》） ⒄治风热虫牙痛：姜黄、细辛、白芷。上为末，擦牙，须臾吐出，盐汤漱口。方中姜黄止痛，为君药。（《杂病源流犀烛》姜黄散） ⒅治妇人血气樶痛，月经不行，经先呕吐疼，及月信不通：姜黄120g，牡丹皮、莪术、红花、桂心、当归、芍药、川芎、延胡索各15g。上为末，每服6g，水一盏，酒三分，煎七分温服。方中姜黄破血行气，通经止痛，为君药。（《妇人良方大全》瑞金散）' where id=1854; -- 姜黄
update herbs set taste='味咸；性温。', channel='入肝、肾经。', effect='①利膈间滞气，助肝肾亏损；九香虫一两（半生半熟），车前于四钱（微炒），陈皮四钱，白术五钱，杜仲八钱（酥炙）。上为细末，炼蜜丸如梧桐子大。每服一钱五分，盐白汤或盐酒送下，空心服，临卧仍服一次。（《摄生众妙方》乌龙丸） ②治胸脘胁痛：九香虫三两，炙全蝎二两。研末，蜜丸，每丸一钱重。每次半丸，日服二次。（《吉林中草药》） ③利膈间滞气，助肝肾亏损：九香虫（半生半熟）30g，车前子（微炒）、陈皮各12g，白术15g，杜仲（酥炙）24g。上为细末，炼蜜为丸，如梧子大，每服4.5g，盐白汤或黄酒送下，空心服，临卧再服1次。方中九香虫补肾助阳，温运脾阳，理气止痛，为君药。（《摄生众妙方》乌龙丸） ④治胸脘胁痛：九香虫90g，炙全蝎60g。上细末，蜜丸，每丸重3g，每服半丸，日服2次。方中九香虫，温运脾阳，理气止痛，为君药。（《吉林中草药》） ⑤治胸脘闷痛：九香虫30g，车前子12g，杜仲24g。上为细末，炼蜜为丸，如梧子大，空心服，临卧再服1次。方中九香虫温运脾阳，理气止痛，为君药。（《摄生众妙方》乌龙散）' where id=1855; -- 九香虫
update herbs set taste='苦辛，寒。', channel='入肝、脾、肾经。', effect='①治湿热黄疸：积雪草一两，冰糖一两。水煎服。（《江西民间草药》） ②治中暑腹泻：积雪草鲜叶搓成小团，嚼细开水吞服一、二团。（《浙江民间常用草药》） ③治砂淋：积雪草一两。第二次的淘米水煎服。（《江西民间草药验方》） ④治血淋：积雪草头、草益根各-把。捣烂绞汁和冰糖一两，一次炖服。（《闽东本草》） ⑤治小便不通：鲜积雪草一两，捣烂贴肚脐，小便通即去药。（《闽东本草》） ⑥治肝脏肿大：崩大碗每次约八两至一斤。煎水服。（《岭南草药志》） ⑦治麻疹：积雪草一至二两。水煎服。（广州部队《常用中草药手册》） ⑧治乳痈初起：老公根茎叶和槟梅衣一个。酒煎服。（《岭南采药录》） ⑨治疔疮：㈠鲜积霄草，洗净，捣烂敷患处。（《江西民间草药》）㈡鲜积雪草一至二两。水煎服。（《福建中草药》） ⑩治缠腰火丹：鲜积雪草，洗净，捣烂绞汁，同适量的生糯米粉调成稀糊状，搽患处。（《江西民间草药》） ⑾治跌打损伤：积雪草八钱至一两，和红酒半斤至十二两，炖一小时，内服；渣捣烂后贴伤部。（《福建民间草药》） ⑿治刀伤出血：崩大碗，酌量，捣烂外敷伤口。（《岭南草药志》） ⒀治臁疮：鲜积雪草洗净，捣烂敷患处，一日一换。（《江西民间草药》） ⒁治目赤肿痛：鲜积雪草捣烂敷寸口处，或捣烂绞汁点患眼，一日三、四次。（《江西民间草药》） ⒂治麦粒肿：鲜积雪草洗净捣烂，掺红糖敷之。（《泉州本草》） ⒃治咽喉肿痛：鲜积雪草二两。洗净，放碗中捣烂，开水冲出汁，侯温，频频含咽。（《江西民间草药》） ⒄治百日咳：崩大碗三两，瘦猪肉一两。同煎一小时，分两次服，连服数天。 ⒅治误食砒霜或其他食物中毒：老公根四两，胆矾一钱。煎水服。此方亦治钩吻及蕈中毒。 ⒆治骨鲠：老公根煎水内服，服时须慢慢咽下。（⒄方以下出《岭南草药志》） ⒇解大茶药中毒：取崩大碗捣烂，加茶油灌服。 （21）解木薯中毒：取崩大碗捣烂，温开水冲服。 （22）解毒蕈中毒：崩大碗四两，片糖二两，煎水内服；或崩大碗四两，萝卜一斤，捣烂榨汁内服。（⒇方以下出《南方主要有毒植物》） （23）治咳血、吐血、鼻出血：鲜积雪草二至三两，水煎或捣汁服。（《福建中草药》） （24）治跌打肿痛：鲜积雪草捣烂绞汁一两，调酒，炖温服；渣敷患处。（《福建中草药》） （25）用于止痛 取积雪草晒干研细，每日1～1.5钱，3次分服。治疗胸、背及腰部外伤性疼痛42例，27例止痛，14例好转，1例无效。 （26）治疗传染性肝炎 取鲜积雪草4两，加水500毫升，浓煎成250毫升，趁热加入冰糖2两溶化，分2次空腹服，7天为一疗程。治疗10例，服药4天黄疸消退、食欲改善、恶心呕吐消失者3例，服药1周黄疸消退、消化道症状好转、胃纳增进者5例。肝肿大于服药二疗程消退2例，三疗程消退5例，四疗程消退3例。 （27）处理流行性脑脊髓膜炎带菌者 取积雪草（干）1000克，水煎2次，合并滤液，浓缩至1000毫升，加防腐剂，pH调至8左右。每服10毫升，5岁以下儿童减半，每日3次，空腹服，连服3天。处理30例流脑带菌者，3天后连续3次作鼻咽分泌物采样培养，结果转阴24例，较磺胺噻唑对照组的转阴率高' where id=1856; -- 积雪草
update herbs set taste='甘、苦；凉；无毒。', effect='①治黄疸：鸡骨草二两，红枣七、八枚。煎服。（《岭南草药志》） ②治瘰疬：鸡骨草六斤，稀莶草四斤。研末，蜜为丸，每丸重一钱。日服三次，每次二丸，连服二至四周。（广西《中草药新医疗法处方集》） ③治疗急性传染性肝炎:取干鸡骨草全草2～3两（儿童1～2两），瘦猪肉2两，加水1000毫升同煎。沸后文火再煎至300毫升，每日3次分服，直至痊愈为止.治疗44例，治愈42例，治愈时间平均为21天。黄疸消失平均为15天；肝功能恢复一般为18～21天；肝肿大随肝功能的恢复逐渐恢复正常。治程中未见不良反应。对慢性肝炎效果不佳。曾报道1例重症肝炎（严重黄疸合并昏睡）患者，服鸡骨草煎剂每次60毫升，日服3次，4天后，神志开始清楚，小便增多，第5天自觉症状显著减轻，第14天自觉症状消失，黄疸不显，第19天一般情况恢复正常，停药观察，肝功能逐渐恢复。住院共38天痊愈出院。' where id=1857; -- 鸡骨草
update herbs set taste='苦辛，凉。', effect='①治黄疸、臌胀：连钱草七至八钱，白茅根、车前草各四至五钱，荷包草五钱。共煎服。（《浙江民间草药》） ②治肾炎水肿：连钱草、萹蓄草各一两，荠菜花五钱。煎服。（《上海常用中草药》） ③利小便，治膀胱结石：连钱草、龙须草、车前草各五钱。煎服。（《浙江民间草药》） ④治疟疾：㈠疟发前用连钱草七叶为丸塞鼻中。（《质问本草》） ㈡连钱草一两五钱至三两。水煎，分两次服，每日一剂，连服三天。（《单方验方调查资料选编》） ⑤治伤风咳嗽：鲜连钱草五至八钱（干的三至五钱）（洗净），冰糖半两。酌加开水，炖一小时，日服二次。（《福建民间草药》） ⑥治胎咳、子肿：团经药、尖惊药、大苋菜、花蝴蝶各三至五钱。炖肉或鸡吃。 ⑦治白带：团经药五钱，杜仲三钱，木通一钱五分。煎水加白糖服。 ⑧治月经不调，小腹作胀：团经药、对叶莲各三钱，大叶艾二钱。泡酒吃。 ⑨治风湿性关节炎：团经药，捶绒酒炒热，外敷。（⑥方以下出《贵阳民间药草》） ⑩治小儿疳积：连钱草三钱，加动物肝脏适量，炖汁服。（《上海常用中草药》） ⑾治疮疖、腮腺炎、皮肤撞伤青肿：鲜连钱草捣烂外敷。（《上海常用中草药》） ⑿治白虎丹：鲜车前草、遍地香。洗净捣烂，少加白酒，绞取汁，鹅毛蘸搽患处。（《祝穆试效方》） ⒀治湿疹、脓庖疮。稻田皮炎：鲜连钱草、野菊花各半斤。加水煮沸，乘热反复擦洗患处（有脓疱者必须挑破脓疱），再用痱子粉或牙粉撒布溃破处，每天一次。如三次见效不显，可加木槿皮或叶半斤同煎洗。（《江苏省中草药新医疗法展览资料选编》） ⒁治疮疥：钹儿草，加盐少许，搓熟频擦，全化，然后洗浴。若用煎冼，反不见效。（《救生苦海》） ⒂治蛇咬：连钱草生药鲜吃，并捣烂敷伤口。（《浙江民间草药》） ⒃治疗腮腺炎 将连钱草洗净，加少量食盐捣烂，敷于肿处，不论一侧或两侧腮腺肿大，均须两侧同时敷药。治疗50例，全部治愈；腮腺肿大消退及体温下降平均为12小时。 ⒄治疗烧伤 新鲜连钱草1把，洗净，用较厚的黄草纸包2～3层，水中浸湿后置旺火中烤熟，约20～30分钟取出，去纸，乘热将药草揉烂绞汁，盛于杯中，用消毒鸭毛蘸药汁涂搽伤面，每天搽数次至数十次，以保持伤面湿润为度；伤势严重的，药汁中加入适量冰片或麝香（研成细粉），可加速痊愈（但加麝香每易遗留瘢痕）；如创面感染化脓，须先经清洗消毒处理，然后搽药。治疗Ⅱ、Ⅲ度烧伤30例，烧伤面积1～30％不等，其中已感染化脓者17例，引起全身症状者3例。结果均治愈，且无功能障碍。制药时要注意掌握火候，药草既要充分烤熟，但亦不能烤焦，否则将无法绞汁。治疗时创面要暴露，不能覆盖，也不能和其它药物混合施治；涂药汁时最好用鸭毛，如用棉花，其纤维每易脱落，可能影响创面愈合。在治疗期间，忌食豆荚、丝瓜、鸡蛋、鱼类等食物。' where id=1858; -- 金钱草
update herbs set alias='金罂子，灯笼果，刺梨子，黄刺果，刺榆子，山石榴，山鸡头子，糖莺子，棠球、糖罐，糖果，蜂糖罐、槟榔果，金壶瓶，野石榴、糖橘子，小石榴，黄茶瓶、藤勾子、螳螂果、糖刺果。', taste='酸涩；平；无毒。', channel='入肾、膀胱、大肠经。', effect='①治梦遗，精不固：金樱子十斤，剖开去子毛，于木臼内杵碎。水二升，煎成膏子服。（《明医指掌》金樱子膏） ②治小便频数，多尿小便不禁：金樱子（去净外刺和内瓤）和猪小肚一个。水煮服。（《泉州本草》） ③治男子下消、滑精，女子白带：金樱子去毛、核一两。水煎服，或和猪膀胱，或和冰糖炖服。（《闽东本草》） ④治白浊：金樱子（去子洗净捣碎，入瓶中蒸令热，用汤淋之，取汁慢火成膏）、芡实肉（研为粉）各等分。上以前膏同酒糊和芡粉为丸，如梧桐子大.每服三十丸，酒吞，食前服。一方用妇人乳汁丸为妙。一方盐汤下。（《仁存堂经验方》水陆二仙丹） ⑤治脾泄下利，止小便利，涩精气：金樱子，经霜后以竹夹子摘取，擘为两爿，去其子，以水淘洗过，烂捣，入大锅以水煎，不得绝火，煎约水耗半，取出澄滤过，仍重煎似稀饧。每服取一匙，用暖酒一盏，调服。（《寿亲养老新书》金樱子煎） ⑥治久虚泄泻下痢：金樱子（去外刺和内瓤）一两，党参三钱。水煎服。（《泉州本草》） ⑦治久痢脱肛：金樱子（去刺、仁）一两，鸡蛋一枚炖服。（《闽东本草》） ⑧治阴挺：金樱果（去内毛和种子）一两。水煎服。（《闽东本草》） ⑨补血：金樱子（干了，擦刺令净，捶碎去子，切焙）、缩砂一半。蜜丸梧子大。空心，酒或盐汤下五十丸。（《朱氏集验医方》金樱子丸）' where id=1859; -- 金樱子
update herbs set alias='鸡食皮，鸡肫内黄皮，鸡毗胫里黄皮，鸡肶胵，鸡肫皮，鸡黄皮，鸡嗉子，鸡合子，鸡中金、化石胆、化骨胆。', taste='味甘；性平。', channel='入脾、胃经。', effect='①治食积腹满：鸡内金研末，乳服。（《本草求原》） ②治痞气积：黄牛脑子一个（同鸡肶胵酒浸一宿），公鸡毗腥一个，朴硝一碗（提净），轻粉、沉香、砂仁、木香~_---钱.上件牛脑用铜锅焙干，将各项药入杵千下，焙。每服一钱，烧酒调下，日三服。（《圣惠方》） ③治反胃，食即吐出，上气：鸡肶胵烧灰，酒服。（《千金方》） ④治脾胃湿寒，饮食减少，长作泄泻，完谷不化：白术四两，干姜二两，鸡内金二两，熟枣肉半斤。上药四味，白术、鸡内金各自轧细焙熟；再将干姜轧细，共和枣肉，同捣如泥，作小饼，木炭火上炙干。空心时，当点心，细嚼咽之。（《医学衷中参西录》益脾饼） ⑤治噤口痢疾：鸡内金焙研，乳汁服之。（《纲目》） ⑥治小儿疳病：鸡肫皮廿个（勿落水，瓦焙干，研末），车前子四两（炒，研末）。二物和匀，以米糖溶化，拌入与食。忌油腻、面食、煎炒。（《寿世新编》） ⑦治痟肾，小便滑数白浊，令人羸瘦：鸡肶胵一两（微炙），黄耆半两，五味子半两。上药，粗捣，以水三大盏，煎至一盏半，去滓，食前分温三服。（《圣惠方》） ⑧治虚劳，上焦烦热，小便滑数，不可禁止：鸡肶胵黄皮二两（微炙），菟丝子二两（酒浸三宿，曝干，捣为末），鹿茸一两（去毛，涂酥炙微黄），桑螵蛸半两（微炒）。上药捣细罗为散，每服以沮清粥饮调下二钱。（《圣惠方》） ⑨治小便淋沥，痛不可忍：鸡肫内黄皮五钱。阴干，烧存性。作一服，白汤下。（《医林集要》） ⑩治遗精：鸡内金六钱，炒焦研末，分六包，早晚各服一包，以热黄酒半盅冲服。（《吉林中草药》） ⑾治走马牙疳：鸡肫黄皮（不落水者）五枚，枯矾五钱。研搽。（《经验方》） ⑿治一切口疮：鸡内金烧灰，敷之。（《活幼新书》） ⒀治喉闭乳蛾：鸡肫黄皮勿洗，阴干烧末，用竹管吹之。（《青囊杂纂》） ⒁治小儿温疟：烧鸡肶胵中黄皮，末，和乳与服。（《千金方》） ⒂治发背已溃：鸡肫黄皮，同绵絮焙末搽之。（《纲目》） ⒃治骨结核，肠结核：鸡内金炒焦研末，每次三钱，日服三次，空腹用温黄酒送下。（《吉林中草药》）' where id=1860; -- 鸡内金
update herbs set taste='辛；苦；温。', channel='归肺、脾经。', effect='①治嘈杂吐水：真橘皮（去白）为末，五更安五分于掌心舐之，即睡。（《怪证奇方》） ②治痰饮为患，或呕吐憨心，或头眩心悸，或中脘不快。或发为寒热，或因食生冷，脾胃不和：半夏（汤洗七次）、橘红各五两，白茯苓三两，甘草（炙）一两半。上细锉，每服四钱，用水一盏，生姜七片，乌梅一个，同煎六分，去滓热服，不拘时候。（《局方》二陈汤） ③治途中心痛：橘皮（去白），煎扬饮之，甚良。（《谈野翁试验方》） ④治风痰麻木：橘红一斤，逆流水五碗，煮烂去滓，再煮至一碗。顿服取吐。不吐加瓜蒂末。（《摘元方》） ⑤治产后脾气不利，小便不通：橘红为末，每服二钱，空心，温酒下。（《妇人良方》） ⑥治乳痈，未结即散，已结即溃，极痛不可忍者：陈皮（汤浸去白，日干，面炒黄）为末，麝香研，酒调下二钱。（《圣惠方》橘香散）' where id=1861; -- 橘红
update herbs set taste='甘；微苦；性凉。', effect='治痢疾，夏季腹泻：鸡蛋花干品四至八钱，水煎服。（广州部队《常用中草药手册》）' where id=1862; -- 鸡蛋花
update herbs set taste='味辛；微苦；性微湿。', channel='入肺、肝经。', effect='①治风热头痛：荆芥穗、石膏等分。为末。每服二钱，茶调下。（《永类钤方》） ②治头目诸疾，血劳，风气头痛，头旋目眩：荆芥穗为末。每酒服三钱。（《眼科龙木论》） ③治风热肺壅，咽喉肿痛，语声不出，或如有物哽：荆芥穗半两，桔梗二两，甘草（炙）一两。上为粗末。每服四钱，水一盏，姜三片，煎六分，去渣，食后温服。（《局方》荆芥汤） ④治一切风，口眼偏斜：青荆芥一斤，青薄荷一斤。一处砂盆内研，生绢绞汁于磁器内，煎成膏；余滓三分，去一分，将二分滓日干为末，以膏和为丸，如梧桐子大。每服二十丸，早至暮可三服。忌动风物。（《经验后方》） ⑤治大便下血：㈠荆芥，炒，为末。每米饮服二钱，妇人用酒下。亦可拌面作馄饨食之。（《经验方》） ㈡荆芥二两，槐花一两。炒紫为末。每服三钱，清茶送下。（《简便单方》） ⑥治产后血晕，筑心，眼倒，风缩欲死者：干荆芥穗，捣筛。每用末二钱匕，童子小便一酒盏，调热服，口噤者挑齿，闭者灌鼻中。（《本草图经》） ⑦治小便尿血：荆芥、缩砂，等分。为末。糯米饮下三钱日三服。（《濒湖集简方》） ⑧治痔漏肿痛：荆芥煮汤，日日洗之。（《简便单方》） ⑨治癃闭不通，小腹急痛，肛门肿疼，无问新久：大黄（小便不通减半）、荆芥穗（大便不通减半），等分。各别为末。每服一、二钱，温水调下，临时加减服。（《宜明论方》倒换散） ⑩治一切疮疥：荆芥、金银花、土茯苓，等分。为末，熟地黄熬膏为丸，梧子大。每旦、晚各服百丸，茶酒任下。（《本草汇言》） ⑾治风毒寡疬、赤肿痛硬：鼠粘子一升（微炒），荆芥穗四两。捣粗罗为散。每服三钱，以水一中盏，煎至五分，去滓，入竹沥半合，搅匀服之，日三服。（《圣惠方》） ⑿治脚桠湿烂：荆芥叶捣敷之。（《简便单方》）' where id=1863; -- 荆芥
update herbs set taste='味辛；微苦；性温；小毒。', channel='心；肝；肺经。', effect='治湿疹：九里香鲜枝叶，水煎，擦洗患处。（《福建中草药》） 《岭南采药录》：患百子痰打，用叶一撮，捣烂煮粥，和糖服之。 治肚痈，以九里香草捣碎浸酒服，疑即本品。《本草纲目》引傅滋《医学集成》' where id=1864; -- 九里香
update herbs set taste='辛、苦，微温；有小毒。', channel='入肝、肺经。', effect='①治通身浮肿：杜蒺藜日日煎汤洗之。（《圣惠方》） ②治气肿痛：蒺藜子一升，熬令黄，为末，以麻油和之如泥，炒令焦黑，以敷故熟布上，如肿大小，勿开孔贴之。干易之。（《千金方》蒺藜散） ③治身体风痒，燥涩顽痹：刺蒺藜四两（带刺炒，磨为末），胡麻仁二两（泡汤去衣，捣如泥），葳蕤三两，金银花一两（炒磨为末）。四味炼蜜为丸。早晚各服三钱，白汤下。（《方龙潭家秘》） ④行经：当归、杜蒺藜各等分。上为末，米饮汤调服，食前。（《儒门事亲》当归散） ⑤治眼疾，翳障不明：刺蒺藜四两（带刺炒），葳蕤三两（炒）。共为散。每早服食后三钱，白汤调服。（《方龙潭家秘》） ⑥治胸痹，膈中胀闷不通或作痛：刺蒺藜一斤，带刺炒，磨为细末。每早、午、晚各服四钱，白汤调服。（《方龙潭家秘》） ⑦治奔豚疝瘕：刺蒺藜十两（带刺炒），小茴香三两（炒），乳香、没药各五钱（瓦上焙出汗）。俱为末，每服三钱，白汤调服。（《方龙潭家秘》） ⑧治乳胀不行，或乳岩作块肿痛：刺蒺藜二、三斤，带刺炒，为末。每早、午、晚，不拘时，白汤作糊调服。（《方龙潭家秘》） ⑨治急引腰脊痛：捣蒺藜子末，蜜和丸。酒服如胡豆大二丸，日三服。（《外台》） ⑩灭瘢：蒺藜子、山栀子仁各一合。上二味为散，醋浆和如泥，临卧时以涂之，旦洗之。（《救急方》） ⑾治牙齿出血不止，动摇：白蒺藜末旦旦擦之。（《纲目》） ⑿治牙齿动摇疼痛：土蒺藜，去角生研五钱，淡浆水半碗，蘸水入盐温漱。（《御药院方》）', tips='血虚气弱及孕妇慎服。 ②《得配本草》：肝虚，受孕，二者禁用。 ③《本草汇言》：阴虚不足，精髓血津枯燥至疾者，俱禁用之。' where id=1865; -- 蒺藜
update herbs set taste='味苦；辛；性平。', channel='入肺、胃经。', effect='①治肺痈，咳而胸满，振寒脉数，咽干不渴，时出浊唾腥臭，久久吐脓如米粥者：桔梗一两，甘草二两。上二味，以水三升，煮取一升，分温再服，则吐脓血也。(《金匮要略》桔梗汤) ②治痰嗽喘急不定：桔梗一两半。捣罗为散，用童子小便半升，煎取四合，去滓温服。(《简要济众方》) ③治喉痹及毒气：桔梗二两。水三升，煮取一升，顿服之。(《千金方》) ④治寒实结胸，无热证者：桔梗三分，巴豆一分(去皮、心，熬黑，研如脂)，贝母三分。上三味为散，以白饮和服，强人半钱匕，羸者减之。病在膈上必吐，在膈下必利，不利，进热粥一杯，利过不止，进冷粥一杯。(《伤寒论》白散) ⑤治伤寒痞气，胸满欲死：桔梗、枳壳(炙，去穰)各一两。上锉如米豆大，用水一升半，煎减半，去滓，分二服。(《苏沈良方》枳壳汤) ⑥治牙疳臭烂：桔梗、茴香等分。烧研敷之。(《卫生易简方》)' where id=1866; -- 桔梗
update herbs set taste='甘；凉；无毒。', channel='肝；肾经', effect='①治五痔肛边肿痛，或窜乳，或窜穴，或作疮，久而不愈，变成漏疮：鸡冠花、风眼草各一两。上为粗末。每用粗末半两，水碗半，煎三、五沸，热洗患处。（《卫生宝鉴》淋渫鸡冠散） ②治赤白下痢：鸡冠花煎酒服，赤用红，白用白。（《濒湖集简方》） ③治下血脱肛：㈠鸡冠花、防风等分。为末，糊丸，梧子大。空心米饮每服七十丸。㈡白鸡冠花（炒）、椶榈灰、羌活（各）一两。为末，每服二钱，米饮下。（《永类钤方》） ④治吐血不止：白鸡冠花，醋浸煮七次，为末。每服二钱，热酒下。（《经验方》） ⑤治咳血，吐血：鲜白鸡冠花五至八钱（干者二至五钱），和猪肺（不可灌水）冲开水约炖一小时许，饭后分二，三次服。（《泉州本草》） ⑥治经水不止：红鸡冠花一味，干晒为末。每服二钱，空心酒调下。忌鱼腥猪肉。（《孙天仁集效方》） ⑦治产后血痛：白鸡冠花酒煎服之。（《怪证奇方》） ⑧治白带、砂淋：白鸡冠花、苦壶芦等分。烧存性，空心火酒服之。（《摘元方》） ⑨治血淋：白鸡冠花一两，烧炭，米汤送下。（《湖南药物志》） ⑩治妇人白带：白鸡冠花，晒干为末。每旦空心酒服三钱，赤带用红者。（《孙天仁集效方》） ⑾治风疹：白鸡冠花、向日葵各三钱，冰糖一两。开水炖服。（《闽东本草》） ⑿治青光眼：干鸡冠花、干艾根、干牡荆根各五钱。水煎服。（《福建中草药》） ⒀治额疽：鲜鸡冠花、一点红、红莲子草（苋科）各酌量，调红糖捣烂敷患处。（《福建中草药》）', tips='凉血；止血。主痔漏下血；赤白下痢；吐血；咳血；血淋；妇女崩中；赤白带下。用于吐血，崩漏，便血，痔血，赤白带下，久痢不止。 ①《滇南本草》：止肠风下血，妇人崩中带下，赤痢。 ②《纲目》：治痔漏下血，办白下痢，崩中，亦白带下，分赤白用。 ③《玉楸药解》：清风退热，止衄敛营。治吐血，血崩，血淋诸失血证。' where id=1867; -- 鸡冠花
update herbs set taste='咸苦；平凉；无毒。', channel='入肝、肾经。', effect='①治失明，目中无他病，无所见，如绢中视：马蹄决明二升，捣筛，以粥坎服方寸匕。忌鱼、蒜、猪肉、辛菜。（《僧深集方》决明散） ②治目赤肿痛：决明子炒研，茶调，敷两太阳穴，干则易之。亦治头风热痛。（《摘元方》） ③治雀目：决明子二两，地肤子一两。上药，捣细罗为散。每于食后，以清粥饮调下一钱。（《圣惠方》） ④治眼补肝，除暗明目：决明子一升，蔓荆子一升（用好酒五升，煮酒尽，曝干）。上药，捣细罗为散。每服，以温水调下二钱，食后及临卧服。（《圣惠方》决明子散） ⑤治急性结膜炎：决明子、菊花各三钱，蔓荆子、木贼各二钱，水煎服。（《河北中药手册》） ⑥治高血压：决明子五钱，炒黄，水煎代茶饮。（《江西草药》） ⑦治小儿疳积：草决明子三钱，研末，鸡肝一具，捣烂，白酒少许，调和成饼，蒸熟服。（《江西草药》） ⑧治癣：决明子不以多少，为末，少加水银粉，同为散。先以物擦破癣，上以散敷之。（《苏沈良方》） ⑨多年失明。用决明子二升研为末，每服一匙，饭后服，稀粥送下。 ⑩青盲、雀目（按：青盲是外观正常，但不见物，雀目即夜盲）。用决明一程式、地肤子五两，共研为末，加米汤做成丸子，如梧子大，每服二、三十丸，米汤送下。 ⑾眼睛红肿。用决明子炒过，研细，加茶调匀敷太阳穴，药干即换，一夜肿消。 ⑿头风热痛。治方同上。 ⒀鼻血不止。用决明子三工业区末，加水调交，敷胸口处。 ⒁癣疮蔓延。用决明子一两，三工业区末。加水银、轻粉少许，研至极细，看不到水银星。擦破癣疮后再敷药。 ⒂背疮初起。用决明子一升（捣碎）、生甘草一两，加水三升，煮成一升，分二次服下。', tips='泄泻和血压低者慎用。 恶大麻子。' where id=1868; -- 决明子
update herbs set taste='味甘；苦；性平。', effect='①治打损接骨：接骨木半两，好乳香半钱，赤芍药、川当归、川芎、自然铜各一两。上为末，用黄蜡四两溶入前药末，搅匀，候温软，众手丸如大龙眼。如打伤筋骨及闪枘疼痛不堪忍者，用药一丸，好旧无灰酒一盏浸药，候药渍失开，承热呷之，痛绝便止。（《续本事方》） ②治肾炎水肿：接骨木三至五钱，煎服。（《上海常用中草药》） ③治创伤出血：接骨木研粉，外敷。（《上海常用中草药》） ④治漆疮：接骨木茎叶四两，煎汤待凉洗患处。（《山西中草药》） ⑤产后血晕。用接骨木碎块一把，加水一升煮成半升，分次服下。' where id=1869; -- 接骨木
update herbs set taste='味辛；性温。', channel='入肝、胃、肾经。', effect='①治胸痹，心中急痛如锥刺，不得俯仰，自汗出或痛彻背上，不治或至死：生韭或根五斤（洗），捣汁。灌少许，即吐胸中恶血。（《孟诜方》） ②治阳虚肾冷，阳道不振，或腰膝冷疼，遗精梦泄：韭菜白八两，胡桃肉（去皮）二两。同脂麻油炒熟，日食之，服一月。（《方脉正宗》） ③治翻胃：韭菜汁二两，牛乳一盏。上用生姜汁半两，和匀。温服。（《丹溪心法》） ④治喉卒肿不下食：韭一把，捣熬薄之，冷则易。（《千金方》） ⑤治吐血、唾血、呕血、衄血、淋血、尿血及一切血证：韭菜十斤，捣汁，生地黄五斤（切碎）浸韭菜汁内，烈日下晒干，以生地黄黑烂，韭菜汁干为度；入石臼内，捣数千下，如烂膏无渣者，为丸，弹子大。每早晚各服二丸，白萝卜煎汤化下。（《方脉正宗》） ⑥下肠中瘀血：韭汁冷饮，甚验。（朱震亨） ⑦治过敏性紫癜：鲜韭菜一斤，洗净，捣烂绞汁，加健康儿童尿50毫升。日一剂，分二次服。（《福建省中草药新医疗法资料选编》） ⑧止水谷痢：韭作羹粥，煠炒。任食之。（《食医心镜》） ⑨治消渴引饮无度：韭苗日吃三、五两。或炒或作羹，无入盐，但吃得十斤即佳。过清明勿吃。（《政和本草》） ⑩治痔疮：韭菜不以多少，先烧热汤，以盆盛汤在内，盆上用器具盖之，留一窍，却以韭菜于汤内泡之，以谷道坐窍上，令气蒸熏；候温，用韭菜轻轻洗疮数次。（《袖珍方》） ⑾治产后血晕：韭菜（切）入瓶内，注热醋，以瓶口对鼻。（《妇人良方》） ⑿治脱肛不缩：生韭一斤。细切，以酥拌炒令熟，分为两处，以软帛裹，更互熨之，冷即再易，以入为度。（《圣惠方》） ⒀治金疮出血：韭汁和风化石灰，日干，每用为末，敷之。（《濒湖集简方》） ⒁治聤耳出汁：韭汁日滴三次。（《圣惠方》） ⒂治百虫入耳不出：捣韭汁，灌耳中。（《千金方》） ⒃治跌打损伤：鲜韭菜三份，面粉一份。共捣成糊状。敷于患处，每日二次。 ⒄治荨麻疹：韭菜、甘草各五钱，煎服；或用韭菜炒食。 ⒅治子宫脱垂：韭菜半斤。煎汤熏洗外阴部。 ⒆治中暑昏迷：韭菜捣汁，滴鼻。（⒃方以下出苏医《中草药手册》） ⒇治漆疮作痒：韭叶杵敷。（《斗门方》）' where id=1870; -- 韭菜
update herbs set effect='1．治黄疸、臌胀：连钱草七至八钱，白茅根、车前草各四至五钱，荷包草五钱。共煎服。(《浙江民间草药》) 2．治肾炎水肿：连钱草、扁蓄草各一两，荠菜花五钱。煎服。(《上海常用中草药》) 3．利小便，治膀胱结石：连钱草、龙须草、车前草各五钱。煎服。(《浙江民间草药》) 4．治疟疾：一疟发前用连钱草七叶为丸塞鼻中。(《质问本草》) 二连钱草一两五钱至三两。水煎，分两次服，每日一剂，连服三天。(《单方验方调查资料选编》) 5．治伤风咳嗽：鲜连钱草五至八钱(干的三至五钱)(洗净)，冰糖半两。酌加开水，炖一小时，日服二次。(《福建民间草药》) 6．治胎咳、子肿：团经药、尖惊药、大苋菜、花蝴蝶各三至五钱。炖肉或鸡吃。《贵阳民间药草》) 7．治白带：团经药五钱，杜仲三钱，木通一钱五分。煎水加白糖服。《贵阳民间药草》) 8．治月经不调，小腹作胀：团经药、对叶莲各三钱，大叶艾二钱。泡酒吃。《贵阳民间药草》) 9．治风湿性关节炎：团经药，捶绒酒炒热，外敷。《贵阳民间药草》) 10．治小儿疳积：连钱草三钱，加动物肝脏适量，炖汁服。(《上海常用中草药》) 11．治疮疖、腮腺炎、皮肤撞伤青肿：鲜连钱草捣烂外敷。(《上海常用中草药》) 12．治白虎丹：鲜车前草、遍地香。洗净捣烂，少加白酒，绞取汁，鹅毛蘸搽患处。(《祝穆试效方》) 13．治湿疹、脓庖疮。稻田皮炎：鲜连钱草、野菊花各半斤。加水煮沸，乘热反复擦洗患处(有脓疱者必须挑破脓疱)，再用痱子粉或牙粉撒布溃破处，每天一次。如三次见效不显，可加木槿皮或叶半斤同煎洗。(《江苏省中草药新医疗法展览资料选编》) 14．治疮疥：钹儿草，加盐少许，搓熟频擦，全化，然后洗浴。若用煎冼，反不见效。(《救生苦海》) 15．治蛇咬：连钱草生药鲜吃，并捣烂敷伤口。(《浙江民间草药》)', tips='清热解毒，利尿排石，散瘀消肿。用于尿路结石、肝胆结石、湿热黄疸、跌扑损伤。 1．治跌打损伤，疟疾，产后惊风，肚痈，便毒，痔漏；擦鹅掌风；汁漱牙疼。《百草镜》 2．发散头风风邪。治脑漏，白浊热淋，玉茎肿痛，捣汁冲酒吃。王安卿《采药志》 3．去风散毒。煎汤洗一切疮疥。《纲目拾遗》 4．祛风湿，止骨痛。浸酒舒筋活络，止跌打闪伤(痛)，取汁调酒更效。《本草求原》 5．治吐血、下血。《植物名实图考》 6．可作强壮剂。治慢性肺炎。《中国植物图鉴》 7．解热，镇咳，止渴，止血，利尿。治小儿痫热，疳病，瘰疬；研汁点暴赤眼；以盐揉贴肿毒并风癣。《现代实用中药》 8．治膀胱结石。《安徽药材》 9、鲜草捣汁外敷撑耳寒(腮腺炎)。《民间常用草药汇编》 10．消肿止痛，破积。治妇人小腹痛。《陆川本草》 11．治红崩带下，肺结核。《贵阳民间药草》 12．治高血压。《浙江民间草药》 13．治风湿麻木，筋骨疼痛，黄疸，肺痈。《四川中药志》' where id=1871; -- 连钱草
update herbs set taste='味苦；性微寒。', effect='①治慢性扁桃体炎：金莲花一钱。开水泡，当茶常喝并含漱。如是急性，用量加倍，或再加鸭跖草等量用。（《河北中药手册》） ②治急性中耳炎，急性鼓膜炎，急性结膜炎，急性淋巴管炎：金莲花、菊花各三钱，生甘草一钱。水煎服。（《河北中药手册》）' where id=1872; -- 金莲花
update herbs set effect='大紫金皮散《奇效良方》；治痈疽恶毒《濒湖集简方》' where id=1873; -- 降香
update herbs set taste='味苦；微甘；性温。', channel='归肝、肾经。', effect='①治放射线引起的白血病：鸡血藤一两。长期煎服。（江西《中草药学》） ②治生障碍性贫血：鸡血藤30g，首乌24g，丹皮9g，熟地15g，五爪龙各30g，云苓、白术各15g，当归12g。水煎服（必要时加阿胶9g）。（再障方《中药临床应用》） ③治血不养筋而致的筋骨疼痛，手足麻木，及月经衰少：鸡血藤4800g，冰糖2400g。将鸡血藤水煎3-4次，取汁过滤，浓缩，再加冰糖制成稠膏，每服15-24g，用温开水冲服。方中鸡血藤补血行血，舒经活络，为君药。（鸡血藤膏《中药制剂手册》） ④治风湿痹痛：鸡血藤15g，半枫荷30g，当归15g，牛膝9g，枫香寄生、海风藤、姜各15g。水煎服。方中鸡血藤，舒经活络，为臣药。（鸡血藤汤《中药临床应用》）' where id=1874; -- 鸡血藤
update herbs set taste='味甘；苦；性微寒。', effect='①治风热头痛：菊花、石膏、卅穹各三钱。为未。每服一钱半，茶调下。(《简便单方》) ②治太阴风温，但咳，身不甚热，微渴者：杏仁二钱，连翘一钱五分，薄荷八分，桑叶二钱五分，菊花一钱，苦桔梗二钱，甘草八分，苇根二钱，水二杯，煮取一杯，日三服。(《温病条辨》桑菊饮) ③冶风眩：甘菊花暴干。作未，以米馈中，蒸作酒服。(徐嗣伯·菊花酒) ④治热毒风上攻，目赤头旋，眼花面肿：菊花(焙)、排风子(焙)、甘草(炮)各一两。上三味，捣罗为散。夜卧时温水调下三钱匕。(《圣济总录》菊花散) ⑤治眼目昏暗诸疾：蜀椒(去目并闭口，炒出汗，一斤半捣罗取未)一斤，甘菊花(未)一斤，上二味和匀，取肥地黄十五斤，切，捣研，绞取汁八、丸斗许，将前药未拌浸，令匀，暴稍干，入盘中，摊暴三、四日内取干，候得所即止，勿令大燥，入炼蜜二斤，同捣数千杵，丸如梧桐子大。每服三十丸，空心日午，熟水下。(《圣济总录》夜光丸) ⑥治肝肾不足，虚火上炎，目赤肿痛，久视昏暗，迎风流泪，伯日羞明，头晕盗汗，潮热足软：枸杞子、甘菊花。熟地黄、山萸肉、怀山药、白茯苓、牡丹皮、泽泻。炼蜜为丸。(《医级》杞菊地黄丸) ⑦治肝肾不足，眼目昏暗：甘菊花四两，巴戟(去心)一两，苁蓉(酒浸，去皮，炒，切，焙)二两)枸杞子三两。上为细未，炼蜜丸，如梧桐子大。每服三十丸至五十丸，温酒或盐汤下，空心食前服。( 《局方》菊睛丸) ⑧治病后生翳：白菊花、蝉蜕等分。为散。每用二、三钱，入蜜少许，水煎服。(《救急方》) ⑨治疗：白菊花四两，甘草四钱。水煎，顿服，渣再煎服。(《外科十法》菊花甘草汤)⑩治膝风：陈艾、菊花。作护膝，久用。(《扶寿精方》)', tips='气虚胃寒，食少泄泻之病，宜少用之。凡阳虚或头痛而恶寒者均忌用。 ②《本草汇言》：气虚胃寒，食少泄泻之病，宜少用之。' where id=1875; -- 菊花
update herbs set taste='甘，寒。', channel='入肺、胃经。', effect='①预防乙脑、流脑：金银花、连翘。大青根、芦根、甘草各三钱。水煎代茶饮，每日一剂，连服三至五天。（《江西草药》） ②治太阴风温、温热，冬温初起，但热不恶寒而渴者：连翘一两，银花一两，苦桔梗六钱，薄荷六钱，竹叶四钱，生甘草五钱，荆芥穗四钱，淡豆豉五钱，牛蒡子六钱。上杵为散，每服六钱，鲜苇根汤煎服。（《温病条辨》银翘散） ③治痢疾：金银花（入铜锅内，焙枯存性）五钱。红痢以白蜜水调服，白痢以沙糖水调服。（《惠直堂经验方》忍冬散） ④治热淋：金银花、海金沙藤、天胡荽、金楔子根、白茅根各一两。水煎服，每日一剂，五至七天为一疗程。（《江西草药》） ⑤治胆道感染，创口感染：金银花一两，连翘、大青根、黄芩、野菊花各五钱。水煎服，每日一剂。（《江西草药》） ⑥治疮疡痛甚，色变紫黑者：金银花连枝叶（锉）二两，黄芪四两，甘草一两。上细切，用酒一升，同入壶瓶内，闭口，重汤内煮三、二时辰，取出，去滓，顿服之。（《活法机要》回疮金银花散） ⑦治一切肿毒，不问已溃未溃，或初起发热，并疔疮便毒，喉痹乳蛾：金银花（连茎叶）自然汁半碗，煎八分服之，以滓敷上，败毒托里，散气和血，其功独胜。（《积善堂经验方》） ⑧治痈疽发背初起：金银花半斤，水十碗煎至二碗，入当归二两，同煎至一碗，一气服之。（《洞天奥旨》归花汤） ⑨治一切内外痈肿：金银花四两，甘草三两。水煎顿服，能饮者用酒煎服。（《医学心悟》忍冬汤） ⑩治大肠生痈，手不可按，右足屈而不伸：金银花三两，当归二两，地榆一两，麦冬一两，玄参一两，生甘草三钱，薏仁五钱，黄芩二钱。水煎服。（《洞天奥旨》清肠饮） ⑾治深部脓肿：金银花、野菊花、海金沙、马兰、甘草各三钱，大青叶一两。水煎服。亦可治疗痈肿疔疮。（《江西草药》） ⑿治气性坏疽，骨髓炎：金银花一两，积雪草二两，一点红一两，野菊花一两，白茅根一两，白花蛇舌草二两，地胆草一两。水煎服。另用女贞子、佛甲草（均鲜者）各适量，捣烂外敷。（《江西草药》） ⒀治初期急性乳腺炎：银花八钱，蒲公英五钱，连翘、陈皮各三钱，青皮、生甘草各二钱。上为一剂量，水煎二次，并分二次服，每日一剂，严重者可一日服两剂。（《中级医刊》（3）：167，1964） ⒁治乳岩积久渐大，色赤出水，内溃深洞：金银花、黄芪（生）各五钱，当归八钱，甘草一钱八分，枸橘叶（即臭橘叶）五十片。水酒各半煎服。（《竹林女科》银花汤） ⒂治杨梅结毒：金银花一两，甘草二钱，黑料豆二两，土茯苓四两。水煎，每日一剂，须尽饮。（《外科十法》忍冬汤） ⒃解农药（1059、1605、4049等有机磷制剂）中毒：银花二至三两，明矾二钱，大黄五钱，甘草二至三两。水煎冷服，每剂作一次服，一日二剂。（徐州《单方验方新医疗法选编》）' where id=1876; -- 金银花
update herbs set taste='味苦；性寒。', channel='归心；脾；肺经。', effect='①治中暑发热：鲜苦瓜一个，截断去瓤，纳入茶叶，再接合，悬挂通风处阴干。每次二至三钱。水煎或泡开水代茶饮。 ②治烦热口渴：鲜苦瓜一个，剖开去瓤，切碎，水煎服。 ③治痢疾：鲜苦瓜捣烂绞汁一杯，开水冲服。（①方以下出《福建中草药》） ④治眼疼：苦瓜煅为末，灯草汤下。（《滇南本草》） ⑤治痈肿：鲜苦瓜捣烂敷患处。（《泉州本草》） ⑥治胃气疼：苦瓜煅为末，开水下。（《滇南本草》）' where id=1877; -- 苦瓜
update herbs set taste='苦；寒。', channel='心；脾经。', effect='①治急性传染性肝炎：苦地丁一两，水煎服。（《河北中药手册》） ②治痢疾：地丁草配火线草、地榆，煎汤服。（《高原中草药治疗手册》） ③治指头感染初起，淋巴管炎（红丝疔）红肿热痛：苦地丁、野菊花各一两。水煎服。（《河北中药手册》） ④治疔肿：鲜苦地丁、葱白、生蜂蜜捣敷。（《辽宁常用中草药手册》） ⑤治湿热疮疡：苦地丁一两，金银花一两，蒲公英一两，大青叶三钱。水煎服。（《辽宁常用中草药手册》） ⑥治实热肠痈下血：苦地丁八钱至一两（干的五至八钱），和水煎成半碗，饭前服，日服二次。（《福建民间草药》） ⑦治黄疸内热：地丁末。酒服三钱。（《乾坤生意秘韫》） ⑧治肠炎、痢疾：苦地丁、红藤各一两，蚂蚁草二两，黄芩三钱。煎服。（苏医《中草药手册》） ⑨治前列腺炎：苦地丁、紫参、车前草各五钱，海金沙一两。煎汤，每日一剂，分二次服，连服数日。（苏医《中草药手册》） ⑩治喉痹：苦地丁叶，研，入酱少许，笔蘸入喉中，吐。（《普济方》） ⑾治小儿走马牙疳，溃烂腥臭：苦地丁根不拘多少。用新瓦焙，为末，搽患处。（《滇南本草》） ⑿治小儿肝热鼻衄：苦地丁（鲜）二至三两。加蜂蜜一两，水煎服，连服数日。（湖北《中草药土方土法》） ⒀治毒蛇咬伤：一鲜苦地丁捣汁一酒杯，内服；药渣加雄黄少许，调敷患处。（苏医《中草药手册》）二鲜地丁、鲜瓜子金、鲜半边莲各适量。共捣如泥，敷患处。（《河南小草药手册》） ⒁治跌打损伤：苦地丁（鲜）捣烂，配方外敷。（湖北《中草药土方土法》） ⒂治疥癞：苦地丁与大枫子油、水银、硫黄合捣外用。（《岭南采药录》） ⒃治各种疔毒，痈疮疔肿，局部红肿热痛，或发热，舌红脉数者：金银花9g，野菊花、苦地丁、紫花地丁、紫背天葵子各3.6g。先水煎，后加五灰酒半盏；药渣再加如法煎服，盖被取汗。方中紫花地丁清热解毒，为臣药。（《医宗金鉴-外科心法要诀》五味消毒饮） ⒄治喉痹：苦地丁叶，研，入酱少许，笔蘸入喉中，吐。方中苦地丁清热解毒，为君药。（《普济方》） ⒅治如炊饼一切毒：苦地丁、紫花地丁各240g。以长流水洗净，用水煎汁去渣，又成膏摊贴。方中紫花地丁清热解毒，为君药。（《惠直堂经验方》地丁膏） ⒆治稻芒粘咽不得出者：苦地丁，嚼咽下。（《乾坤生意秘韫》）', tips='清热解毒；消痈肿。主流行性感冒；上呼吸道感染；扁桃体炎；传染性肝炎；肠炎；痢疾；肾炎；腮腺炎；结膜炎；急性阑尾炎；疔疮痈肿；瘰疬。治温病高热烦躁，流感，传染性肝炎，肾炎，瘰疬，腮腺炎，疔疮及其它化脓性感染。 ①《辽宁常用中草药手册》：清热解毒。治痈疽疔肿，淋巴结结核。 ②《河北中药手册》：治急性传染性肝炎。③《高原中草药治疗手册》：消炎解毒。治黄疸肝炎，高热烦躁。 ④《岭南采药录》：作泻药及吐药。 ⑤《上海常用中草药》：清热解毒，外用拔毒消肿。治目赤肿痛，麦粒肿，疗疮肿毒，乳痈，肠炎腹泻，毒蛇咬伤。 ⑥苏医《中草药手册》：治一切化脓性感染，毒蛇咬伤，淋巴结核，黄疸，肾炎，膀胱炎，关节肿痛，便血，鼻出血，眼结膜炎，前列腺炎。 ⑦《滇南本草》：破血，解痈疽疥癞，九种痔疮，诸疮毒症。 ⑧《纲目》：主治一切痈疽发背，疔肿瘰疬，无名肿毒，恶疮。 ⑨《本草求原》：凉血，消肿毒。治血热筋痿，敷疮妙。' where id=1878; -- 苦地丁
update herbs set taste='苦，寒，有毒。', effect='①治小儿蛔虫：㈠樟木，削上苍皮，以水煎取汁饮之，量大小多少。此为有小毒。（《千金方》）㈡樟根白皮，去粗，二斤，切。水一斗，煮取三升，砂锅（熬）成膏，五更初温酒服一匙，以虫下为度。（《简便单方》） ②治小儿虫痛不可忍者：苦楝根白皮二两，白芜荑半两。为末，每服一钱，水-小盏，煎取半盏，放冷，待发时服，量大小加减，无时。（《小儿卫生总微论方》抵圣散） ③杀蛲虫：楝根皮二钱，苦参二钱，蛇床子一钱，皂角五分。共为末，以蜜炼成丸，如枣大，纳入肛门或阴道内。（《药物图考》楝皮杀虫丸） ④治钩虫病：苦楝皮（去粗皮）十斤，加水五十斤，熬成十斤；另用石榴皮八两，加水五斤，熬成二斤，两种药水混合搅匀，成人每次服一两。（《湖南药物志》） ⑤治瘾疹：楝皮浓煎浴。（《斗门方》） ⑥治疥疮风虫：楝根皮、皂角（去皮子）等分。为末，猪脂调涂。（《奇效良方》） ⑦治顽固性湿癣：楝根皮，洗净晒干烧灰，调茶抽涂抹患处，隔日洗去再涂，如此三、四次。（《福建中医药》（2）：43，1959） ⑧治瘘疮：楝树白皮、鼠肉、当归各二两，薤白三两，生地黄五两，腊月猪脂三升。煎膏成，敷之孔上，令生肉。（《刘涓子鬼遗方》坐肉膏） ⑨治小儿秃疮及诸恶疮，蠷螋疮：楝树枝皮烧灰，和猪膏敷之。（《千金方》） ⑩治虫牙痛：苦楝树皮煎汤漱口。（《湖南药物志》） ⑾治蛇咬伤：苦楝树二层皮、韭菜各四两，加米酒半斤、醋四两，炖热放凉后用。伤口先行扩创，用药酒自上而下外擦，药渣外敷，内服少许药酒。（广东《中草药处方选编》） 苦楝皮驱蛔虫，民间使用已久，疗效确实。解放后，各地临床报道，病例数以万计。但在实践过程中，对药用部分的选择、制备、剂量、服法等均不一致，其驱虫效果及毒性反应差距也很大。现根据部分临床报道，综述于下： ①药用部分及采集季节 苦楝树的干皮、根皮都可驱蛔。从唐《千金方》等历代有关23种方书查考，其中有16种主要采用根皮。明代以后的记载更多采用根皮。根据近年临床应用结果证明，根皮比树皮疗效高1倍；近根的树皮（约在地面之上5寸处）较上层树皮为优，其疗效与根皮近似。在时间上以冬季或春季抽芽前采集的根皮，疗效最高。此外，楝属植物的各地品种不同，一般均认为以四川产的川楝为佳。 ②制备方法、剂量与服法 一般采用煎剂，亦可制成片剂。苦楝皮有效成分难溶于水，需用文火久煎，才有确实疗效。有人作对比试验，分别以2、4、6两用文火煎11小时，其疗效比以8两用武火煎4小时者为高。剂量：根据1963年版《中国药典》规定和有关记载，苦楝皮的成人剂量为1.5～3.0钱（干皮），但实际用量颇不-致，高的竟有用至9～11克／公斤体重者。有人建议成人用4～6两（鲜皮），小儿按3～6克／公斤体重计算。川楝片每片含川楝素结晶0.025克，成人剂量为6～8片，2～4岁2片，4～8岁3～4片。苦楝素片每片含苦楝素25～50毫克，用于儿童以5毫克／公斤体重疗效最好。或每2岁服用1片（4岁用2片……14岁用7片），16岁以上用10片。服法：睡前或晨间空腹顿服，或在睡前和次晨分服。煎剂服时可加糖矫味，不必另服泻药。有主张在服药前先吃些油类食物，以减少药物对胃粘膜的刺激，防止胃肠道反应的发生。 ③驱虫效果 根据采用苦楝皮（或粗制苦楝片）治疗的20000余例，及川（苦）楝素片治疗约5000例肠蛔虫病的临床分析来看，一般在服药后数小时或2～3天内排出蛔虫，以24～48小时排出者居多。排虫率20.2～100％不等，大便阴转率5.5～92.8％不等。曾有介绍，以苦楝皮煎剂治疗小儿蛔虫性肠梗阻50例，获得显效。方法以25％煎剂200毫升作保留灌肠，半小时后再用300～500毫升作第2次灌肠，1小时后再用600毫升行第3次灌肠，此为一疗程。若经24小时未见排出，可再进行第二疗程。对严重失水者可先补液矫正脱水。也有用川楝片内服治疗蛔虫性肠梗阻，剂量：1岁2片，2～4岁2～3片，5～8岁4片，9～12岁5片，均日服2次，并可根据情况给予50％硫酸镁25毫升。此外，用鲜苦楝根4～6两（不去皮）煎成100％煎剂治疗胆道蛔虫病，亦取得一定疗效；12岁以下每日1剂，分3次服，12岁以上每日1剂分2次服，2～3剂为一疗程。一般服药后2～3小时痛即减轻，从第1次大便开始，即有蛔虫排出。一个疗程后，尚有轻度症状者，可隔1～2日后再续服一个疗程。又苦楝根皮对驱除蛲虫、绦虫、鞭虫，亦有一定效果。 ④毒性反应 苦楝皮的副作用，一般在服药后1～6小时尚未排虫之前发生，通常为头晕、头痛、思睡、恶心、腹痛等，其发生率高者可达100％，低者不到1％，持续时间大多在数分钟或1～3小时，最长16小时，可自行消失。严重反应或严重中毒时，可出现呼吸中枢麻痹、类似莨菪类植物中毒症状及内脏出血、中毒性肝炎、精神失常、视力障碍等，严重者可导致死亡。川楝素240系从川楝皮中提出的白色晶体，具有蓄积作用，对胃肠有刺激性，对肝脏亦有损害；为了避免中毒，不宜连续服用。苦楝根外层紫褐色皮，古人曾指出有毒，但经近人试用，并未见副作用增加。引起上述各种严重反应或中毒现象，多因药物过量，或因患者机体的特殊敏感性所致，临床应用时务须注意。' where id=1879; -- 苦楝皮
update herbs set alias='冬花，款花，看灯花，艾冬花，九九花。', taste='味辛；微甘；性温', channel='入肺经。', effect='①治暴发咳嗽：款冬花二两，桑根白皮（锉）、贝母（去心）、五味子、甘草（炙，锉）各半两，知母一分，杏仁（去皮尖，炒，研）三分。上七味，粗捣筛，每服三钱匕，水-盏，煎至七分，去滓温服。（《圣济总录》款冬花汤） ②治久嗽不止：紫菀三两，款冬花三两。上药粗捣罗为散，每服三钱，以水一中盏，人生姜半分，煎至六分，去滓温服，日三、四服。（《圣惠方》紫菀散） ③治肺痈嗽而胸满振寒，脉数，咽干，大渴，时出浊唾腥臭，臭久吐脓如粳米粥状者：款冬花一两五钱（去梗），甘草一两（炙），桔梗二两，薏苡仁一两。上作十剂，水煎服。（《疮疡经验全书》款花汤） ④治喘嗽不巳，或痰中有血：款冬花、百合（蒸，焙）。上等分为细末，炼蜜为丸，如龙眼大。每服一丸，食后临卧细嚼，姜汤咽下，噙化尤佳。（《济生方》百花膏） ⑤款冬花汤（《圣济总录》）：治暴发咳嗽。款冬花60g，贝母、甘草、桑白皮各15g，知母0.3g，杏仁1g，五味子15g。水煎，每日1剂，分2次服。方中款冬花配伍五味子治湿痰、水饮的咳嗽气喘，吐痰清稀量多等症。 ⑥安眠散（《奇效良方》）：治上喘咳嗽，久而不愈者。款冬花、麦门冬（去心）、乌梅肉、佛耳草各7.5g，陈皮（去白）15g，粟壳（蜜炙）23g，甘草（炙）12g。上为细末，每服9g，水1盏，入黄腊如枣核许，同煎至八分，去渣，临睡温服。方中款冬花配伍诸药有润肺下气，止咳化痰之功效。 ⑦芦吸散（《张氏医通》）：治冷哮寒嗽，喘促痰清。款冬花、川贝母、肉桂、甘草（炙）各9g，煅鹅管石15g。细为末，每次少许，噙化，每日5～7次。方中紫菀配伍川贝母有治久咳劳嗽的功效。' where id=1880; -- 款冬花
update herbs set taste='味苦；性寒', channel='入肝、肾、大肠、小肠经。', effect='①治血痢不止：苦参炒焦为末，水丸梧子大。每服十五丸，米饮下。（《仁存堂经验方》） ②治痔漏出血，肠风下血，酒毒下血：苦参（切片，酒浸湿，蒸晒九次为度，炒黄为末，净）一斤，地黄四两（酒浸一宿，蒸熟，捣烂）。加蜂蜜为丸。每服二钱，白滚汤或酒送下，日服二次。（《外科大成》苦参地黄丸） ③治谷疸，食毕头旋，心怫郁不安而发黄，由失饥大食，胃气冲熏所致：苦参三两，龙胆一合（末）。牛胆丸如梧子。以生姜汁服五丸，日三服。（《补缺肘后方》） ④治赤白带下：苦参二两，牡蛎一两五钱。为末，以雄猪肚一个，水三碗煮烂，捣泥和丸，梧子大。每服百丸，温酒下。（《积德堂经验方》） ⑤治下部疮漏：苦参煎汤，日日洗之。（《仁斋直指方》） ⑥治大肠脱肛：苦参、五倍子、陈壁土等分。煎汤洗之，以木贼末敷之。（《医方摘要》） ⑦治心肺积热，肾脏风毒攻于皮肤，时生疥癞，瘙痒难忍，时出黄水，及大风手足烂坏，眉毛脱落，一切风疾：苦参三十二两，荆芥（去梗）十六两。上为细末，水糊为丸，如梧桐子大。每服三十丸，好茶吞下，或荆芥汤下，食后服。（《局方》苦参丸） ⑧治漏脓肥疮，脓窠疮，腊梨头，遍身风癞，瘾疹疥癣，瘙痒异常，麻木不仁，诸风手足酸痛，皮肤破烂，阴囊痒极，并归人阴痒、湿痒：苦参一斤（为末），鹅毛（香油炒存性）六两。黄米糊丸，朱砂为衣。茶汤送下，日进二次。或随病作散擦或洗、贴。（《王秋泉家秘》神功至宝丹） ⑨治瘰疬：苦参四两，捣末，生牛膝和丸如梧子。食后暖水下十丸，日三服。（《随身备急方》） ⑩治鼠瘘诸恶疮：苦参二斤，露蜂房二两，曲二斤。水三斗，渍药二宿，去滓，黍米二升，酿熟梢饮，日三。一方加猬皮，更佳。（《补缺肘后方》） ⑾治汤熨火烧疼痛：苦参不以多少，为细末，用香油调搽。（《卫生宝鉴》绿白散） ⑿治旋耳疮（又名月蚀疮）初起在耳轮上或耳后，耳垂处发一黄色米粒样疙瘩，周围发红，顶白透脓，奇痒难忍，破后脓水外溢，蔓延传染，不几日耳前后成为一片，脓水淋漓，此疮小儿最易传染：苦参、黄柏各五钱，苍术、海螵蛸各三钱。各研极细，和匀。用温开水调敷患部，每日早晚各换药一次。（《浙江中医杂志》（6）：27，1958） ⒀治齿缝出血：苦参一两，枯矾一钱。为末，日三揩之。（《普济方》） ⒁治毒热足肿作痛欲脱者：苦参煮酒渍之。（《姚僧坦集验方》）', tips='脾胃虚寒者忌服。不宜与藜芦同用。 ①《本草经集注》；恶贝母、漏芦、菟丝子。反藜芦。 ②《医学入门》：胃弱者慎用。 ③《本草经疏，：久服能损肾气，肝、肾虚而无大热者勿服。' where id=1881; -- 苦参
update herbs set effect='①导赤散(《小儿药证直诀》)：清心养阴，利水通淋，主治心经热盛，心胸烦热，口渴面赤，意欲饮冷，以及口舌生疮，或心热移小肠，小便赤涩刺痛。 ②八正散(《太平惠民和剂局方》)：清热泻火，利水通淋，主治湿热下注，之热淋、血淋等。 ③苦木汤(《圣济总录》)：主治产后乳汁不下。 ④木通散(《圣惠方》)：主治喉痹，心胸气闷，咽喉堵塞不通。' where id=1882; -- 苦木
update herbs set taste='咸；寒；无毒。', channel='归肝、胃、肾经。', effect='①治瘿气结核，癳癳肿硬：昆布一两（洗去成味）。捣罗为散。每用一钱，以绵裹于好醋中浸过，含咽津觉药味尽，即再含之。（《圣惠方》） ②治颈下卒结囊，渐大欲成瘿：昆布、海藻等分。末之，蜜丸如杏核大，含，稍稍咽汁，日四、五。（《肘后方》） ③治瘿气初结，咽喉中壅闷，不治即渐渐肿大：槟榔三两，海藻二两（洗去咸），昆布三两（洗去咸水）。上药，捣罗为末，炼蜜和丸，如小弹子大，常含一丸咽津。（《圣惠方》） ④治气瘿，胸膈满塞，咽喉项颈渐粗：昆布二两（洗去咸汁），通草一两，羊靥二具（炙），海蛤一两（研），马尾海藻一两（洗去咸汁）。上五味，蜜丸如弹子，细细含咽汁。忌生菜、热面、炙肉、蒜、笋。（《广济方》昆布丸） ⑤治膈气噎塞不下食：昆布（洗净，焙，末）一两，桩杵头细糠一合，共研。用老牛涎一合，生百合汁一合，慢煎入蜜搅成膏，与末杵丸，如芡实大。每服一丸，含化咽下。（《圣济总录》昆布方） ⑥治气，膀胱急妨，宜下气：昆布一斤，白米泔汁浸一宿，洗去咸味，以水一斗，煮令向熟，擘长三寸、阔四、五分，仍取葱白一握，二寸切断擘之，更合熟煮令昆布极烂，仍下盐、酢、豉、糁调和，一依臛法，不得令咸酸，以生姜、橘皮、椒末等调和，宜食粳米饭、粳米粥，海藻亦依此法，极下气，大效，无所忌。（《广济方》昆布臛法）' where id=1883; -- 昆布
update herbs set effect='⑴：宽筋藤100g，蒂达50g，诃子肉100g，余甘子(去核)80g，毛诃子70g。共研成粗粉，过筛混匀，能干黄水，消炎；用于风湿关节炎、黄水病。一次3～5g，一日2～3次，煎服。 ⑵：藏木香、诃子、毛诃子、余甘子各100g，悬钩子茎200g，宽筋藤125g，尕架(干姜或山柰)35g。共研成粗粉，过筛混匀。能解表、散寒；用于风寒感冒、热病初起、恶寒发热，头及关节疼痛。一次3～5g，一日2次，煎服(《四部医典·后续本》)。又七珍汤去三果(诃子、毛诃子、余甘子)称四味藏木香汤，能解表发汗，用于流感及发热的传染病初起，恶寒头病，关节酸痛。一次3～5g，一日2次，煎服。 ⑶：降香150g，藏紫草120g，紫草茸、茜草、洪连、宽筋藤、藏木香、巴夏嘎各100g，悬钩木200g，山柰60g。十味共研成粗粉，过筛混匀。能清血热、降压；用于高血压引起的口干、音哑、头痛、眼花、背痛、头昏、全身麻木。一次2～2.5g，一日2～3次，煎服。', tips='祛风止痛；舒筋活络。主风湿痹痛；腰肌劳损；跌打损伤。用于风湿痹痛，坐骨神经痛，腰肌劳损，跌打损伤。' where id=1884; -- 宽筋藤
update herbs set taste='性温，味苦；有小毒。', channel='归肺、大肠经。', effect='①治肺寒卒咳嗽：细辛半两（捣为末），杏仁半两（汤浸，去皮尖、双仁，麸炒微黄，研如膏）。上药，于铛中熔蜡半两，次下酥一分，入细辛、杏仁，丸如羊枣大。不计时候，以绵裹一丸，含化咽津。（《圣惠方》） ②治咳逆上气：杏仁三升，熟捣如膏，蜜一升，为三分，以一分内杏仁捣，令强，更内一分捣之如膏，又内一分捣熟止。先食已含咽之，多少自在，日三。每服不得过半方寸匕，则痢。（《千金方》杏仁丸） ③治久患肺喘，咳嗽不止，睡卧不得者：杏仁（去皮尖，微炒）半两，胡桃肉（去皮）半两。上件入生蜜少许，同研令极细，每一两作一十丸。每服一丸，生姜汤嚼下，食后临卧。（《杨氏家藏方》杏仁煎） ④治上气喘急：桃仁、杏仁（并去双仁、皮尖，炒）各半两。上二味，细研，水调生面少许，和丸如梧桐子大。每服十丸，生姜、蜜汤下，微利为度。（《圣济总录》双仁丸） ⑤治气喘促浮肿，小便淋沥：杏仁一两，去皮尖，熬研，和米煮粥极熟，空心吃二合。（《食医心镜》） ⑥治肺病咯血：杏仁四十个，以黄蜡炒黄，研，入青黛一钱，作饼，用柿饼一个，破开包药，湿纸裹，煨熟食之。（朱震亨） ⑦利喉咽，去喉痹，痰唾咳嗽，喉中热结生疮：杏仁去皮熬令赤，和桂末，研如泥，绵裹如指大，含之。（《本草拾遗》） ⑧治久病大肠燥结不利：杏仁八两，桃仁六两（俱用汤泡去皮），蒌仁十两（去壳净），三味总捣如泥；川贝八两，陈胆星四两（经三制者），同贝母研极细，拌入杏、桃、蒌三仁内。神曲四两研末，打糊为丸，梧子大。每早服三钱，淡姜汤下。（《方脉正宗》） ⑨治暴下水泻及积痢：杏仁二十粒（汤浸去皮尖），巴豆二十粒（去膜油令尽）。上件研细，蒸枣肉为丸，如芥子大，朱砂为衣。每服一丸，食前。（《杨氏家藏方》朱砂丸） ⑩治上气，头面风，头痛，胸中气满贲豚，气上下往来，心下烦热，产妇金疮：杏仁一升，捣研，以水一斗滤取汁，令尽，以铜器螗火上从旦煮至日入，当熟如脂膏，下之。空腹酒服一方寸匕，日三，不饮酒者，以饮服之。（《千金方》杏仁膏） ⑾治眼疾翳膜遮障，但瞳子不破者：杏人三升（汤浸去皮尖、双人）。每一升，以面裹，于煻灰火中炮热，去面，研杏仁压取油，又取铜绿一钱与杏油同研，以铜箸点眼。（《圣济总录》杏仁膏） ⑿治鼻中生疮：捣杏仁乳敷之；亦烧核，压取油敷之。（《千金方》） ⒀治诸疮肿痛：杏仁去皮，研滤取膏，入轻粉、麻油调搽，不拘大人小儿。（《纲目》） ⒁治犬啮人：熬杏人五合，令黑，碎研成膏敷之。（《千金方》）' where id=1885; -- 苦杏仁
update herbs set taste='苦咸，寒。', channel='归胃；大肠；肝经。', effect='①治疽作二日后，退毒下脓：黄芪（生用）、连翘各一两，大黄一分（微炒），漏芦一两（有白茸者），甘草半两（生用），沉香一两。上为末，姜、枣汤调下。（《集验背疽方》漏芦汤） ②治乳妇气脉壅塞，乳汁不行，及经络凝滞，乳内胀痛，留蓄邪毒，或作痈肿：漏芦二两半，瓜蒌十个（急火烧焦存性），蛇蜕十条（炙）。上为细散，每服二钱，温酒调服，不拘时，良久吃热羹汤助之。（《局方》漏芦散） ③治瘰疬，排脓、止痛、生肌：漏芦、连翘、紫花地丁、贝母、金银花，甘草、夏枯草各等分。水煎服。（《本草汇言》） ④治皮肤瘙痒，阴疹，风毒，疮疥：漏芦、荆芥、白鲜皮、浮萍、牛膝、当归、蕲蛇，枸杞子各一两，甘草六钱，苦参二两。浸酒蒸饮。（《本草汇言》） ⑤治流行性腮腺炎：板蓝根一钱，漏芦一钱半，牛蒡子四分，甘草五分。水煎服。（《新疆中草药手册》） ⑥治历节风，筋脉拘挛，骨节疼痛：漏芦半两（去芦头，麸炒），地龙（去土，炒）半两。上二味捣罗为末。先用生姜二两取汁，蜜二两，同煎三、五沸，入好酒五合，以瓷器盛。每用七分盏调药末一钱半匕，温服不拘时。（《圣济总录》古圣散） ⑦治小儿无辜疳痢，羸弱，不欲饮食，及腹内虫动作，多吐清水：漏芦二两，猪肝一两（煿干），楮树根白皮一两（锉）。上药，捣罗为末，炼蜜和捣一、二百杵，丸如弹子大。每服以温水研一九，不计时候，量儿大小，分减服之。（《圣惠方》漏芦丸） ⑧治冷劳泄痢，及妇人产后带下诸疾：漏芦（去芦头）一两，艾叶（去梗炒）四两。上二味，捣罗为末，用米醋三升，入药末一半，先熬成膏，后入余药和丸如梧桐子大。每服三十丸，温米饮下，食前服。（《圣济总录》漏芦丸） ⑨治室女月术不调：漏芦（去芦头）、当归（切，焙）、红花子、枳壳（去瓤，麸炒）、白茯苓（去黑皮）、人参各半两。上六味，粗捣筛，每服三钱匕，水一盏，煎七分，去滓，温服，不拘时。（《圣济总录》漏芦汤） ⑩治白秃：五月收漏芦草，烧作灰，膏和使涂之，先用盐汤洗。乃敷。（《补缺肘后方》）' where id=1886; -- 漏芦
update herbs set alias='白胶，鹿胶。', taste='味甘；咸；性温。', channel='入肝、肾经。', effect='①治虚劳：鹿角胶（以酒浸胶数日，煮糊丸众药）、鹿角霜（碾为细末）、菟丝子（净洗，酒浸两宿，蒸，研）、柏子仁（别研）、熟地黄（酒浸两宿，蒸，焙，余酒入在胶内）各十两。先焙鹿角霜、菟丝子、地黄干，碾为细末，枯子仁在众药内研，却将鹿角胶酒约三、四升，煮作糊，于石臼内杵二千余下，令熟，丸如梧子大。早晚空心五十丸至一百丸止，逐日早晚服，盐汤或酒任下。（《百一选方》斑龙丸） ②治五劳七伤，身无润泽，腰脊疼痛，四肢沉重，久服填骨髓，好颜色，祛风气，润鬓发：鹿角胶三两（捣碎，炒令黄燥，捣罗为末），牛乳一升，白蜜一合，牛酥一合，生姜汁一合。上五味，先煎乳，欲熟，即下胶，消讫，次下姜汁，次下蜜，唯须缓八，煎十余沸，倾于瓷器中，仍数数搅，勿令酥浮于上，待凝，以竹刀割为小片。每食后，细细含咽之。（《圣惠方》鹿角胶煎方） ③治虚劳梦泄：鹿角胶一两（研碎，炒令黄燥），覆盆子一两，车前子一两。上药捣细，罗为散。每于食前，以温酒调下二钱。（《圣惠方》鹿角胶散） ④治虚劳尿精：鹿角胶三两。末之，以酒二升和，分温为三服，瘥止。（《干金方》） ⑤治吐血不止：鹿角胶一两（炙黄，为末），生地黄汁一升二合。同于铜器中盛蒸之，令胶消，分温二服。（《圣惠方》鹿角胶方） ⑥治吐血后虚热，胸中痞，口燥：鹿角胶（炙燥）、黄蘖（蜜炙）各十两，杏仁四十九枚（麸炒）。上三味，捣罗为细散。每服一钱匕，用温水调下，不拘时服。（《圣济总录》鹿角胶散） ⑦治溺血，阳虚血走，脉细者：鹿角胶三两，大熟地五两，血余炭三两。二味为末，溶鹿胶代蜜丸。��盐汤下三钱。（《医略六书》鹿角胶丸） ⑧治妊娠胎动，漏血不止：鹿角胶（炙燥）一两，人参、白茯苓各半两。上三味，粗捣筛。每服三钱匕，水一盏，煎至七分，去滓温服。（《圣济总录》鹿角胶汤） ⑨治妇人白带下不止，面色萎黄，绕脐冷痛：鹿角胶一两（捣碎，炒令黄燥），白龙骨一两，桂心一两，当归一两（微炒），附子二两（炮裂），白术一两。上药捣，细罗为散。每于食前，以粥饮调下二钱。（《圣惠方》鹿角胶散） ⑩治鹤膝风，贴骨疽及-切阴疽：鹿角胶三钱，熟地一两，肉桂一钱（研粉），麻黄五分，白芥子二钱，姜炭五分，生甘草一钱。煎服。（《外科全生集》阳和汤） ⑾治汤火疮：水煎鹿角胶令稀稠得所，待冷涂疮。（《斗门方》）' where id=1887; -- 鹿角胶
update herbs set taste='味咸；性寒；小毒。', channel='归膀胱、大肠、小肠经。', effect='①治水病肿满喘促，不得眠卧：蝼蛄五枚，晒令干，研为末。食前，以暖水调下半钱至一钱，小便通利为效。（《圣惠方》） ②治面浮水肿：土狗一枚，轻粉一字。共为细末。每用少许，搐鼻中，其黄水尽从鼻中出。（《杨氏家藏方》分水散） ③治石淋，导水：蝼蛄七枚，盐二两。同于新瓦上铺盖焙干，研末。温酒调一钱匕服。（《本草图经》） ④治小便不通：蝼蛄三枚（微妙），苦瓠子三十粒（微炒）。捣细罗为散。每服以冷水调下一钱。（《圣惠方》） ⑤治颈项瘰疬：带壳蝼蛄七枚，生取肉，入丁香七粒，于壳内烧过，与肉同研，用纸花贴之。（《救急方》） ⑥治小儿脐风汁出：甘草（炙，锉）、蝼蛄（炙焦）各一分。上二味，捣罗为散，掺敷脐中。（《圣济总录》甘草散） ⑦治紧唇：自死蝼蛄，灰，敷之。（《千金方》） ⑧治齿牙疼痛：土狗一个，旧糟裹定，湿纸包煨焦，去糟，研末敷之。（《本事方》） ⑨水肿病（腹满，喘急，不能安卧）。用蝼蛄五枚，焙干为末，饭前用开水送服一钱，以小便通畅为效，有人加甘遂末一钱、商陆汁一匙，忌盐一百日。又方：不便不通者，用蝼蛄下截焙研，水磁服半钱，立通。又方：用蝼蛄一个、葡萄心七个，捣烂，露一领先，晒干，共研为末，酒送服。又方：夏季收集蝼蛄阴干，分头、腹、尾，焙过收存，治上身水肿，用头末七个；治身体中部水肿，用腹末七个；治下身水肿，用尾末七个，饭前服，酒送下。 ⑩大腹水肿。用蝼蛄炙热，每天吃十个。又方：用大戟、芫花、甘遂、大黄各三钱，共研为末。以蝼蛄七个，加捣烂的葱，在新瓦上焙干，去掉翅足，每个剪作左右两半。退左侧水肿时，即以虫的左侧七片焙研加上述的药末二钱，黎明时，用淡竹叶、天门冬煎激发调服。三天后，照这种方法服虫的右侧七片。 ⑾大小便不通。用蝼蛄、蜣螂各七个，男取虫头，女取虫身，瓦上焙焦，研为末。以樗皮煎汁送服。极效。 ⑿胞衣不下。用归蝼蛄一个，水煎开二十次，灌入即下。' where id=1888; -- 蝼蛄
update herbs set taste='味酸；性微寒。', channel='归肝、心包经。', effect='①治妇人、室女月候不通，脐腹疞痛，一切血疾：紫葳二两，当归、茂（蓬莪术）各一两。上为细末。空心冷酒调下二镇，如行十里许，更用热酒调一服。（《鸡峰普济方》紫葳散） ②治女经不行：凌霄花为末。每服二钱，食前温酒下。（《徐氏胎产方》） ③治崩中漏下血：凌霄花末，温酒服方寸匕，日三。（《广利方》） ④治通身痒：凌霄花为末，酒调，卜钱。（《医学正传》） ⑤治皮肤湿癣：凌霄花、羊蹄根各等量，酌加桔矾，研末搽患处。（《上海常用中草药》） ⑥治肺有风热，鼻生瘙疱：凌霄花半两（取末），硫黄一两（别研），腻粉一钱，胡桃四枚（去壳）。先将前三味和匀，后入胡桃肉，同研如膏子，用生绢蘸药频频揩之。（《杨氏家藏方》紫葳散） ⑦治酒齄鼻：㈠凌霄花、山栀子。上等分，为细末。每服二钱，食后茶调下，日进二服。（《百一选方》）㈡以凌霄花研末，和密陀僧末，调涂。（《岭南采药录》） ⑧治痫疾：凌霄花，为细末。每服三钱，温酒调下，空心服。（《传信适用方》） ⑨治大便后下血：凌霄花，浸酒饮服。（《浙江民间草药》） ⑩治误食草药毒者：每用凌霄花同黑豆一处蒸热，拣去花，只服豆三、五粒。（《履巉岩本草》）' where id=1889; -- 凌霄花
update herbs set taste='甘；涩；平。', channel='入心，脾、肾经。', effect='①治久痢不止：老莲子二两（去心），为末，每服一钱，陈米汤调下。（《世医得效方》） ②治下痢饮食不入，俗名噤口痢：鲜莲肉一两，黄连五钱，人参五钱。水煎浓，细细与呷。（《本草经疏》） ③治噤口痢：石莲不以多少，不炒，剥去壳，将肉并心，碾为细末。铡艮二钱，米饮调下。（《百一选方》） ④治心火上炎，湿热下盛，小便涩赤，淋浊崩带，遗精等证：黄芩、麦门冬（去心）、地骨皮、车前子、甘草（炙）各半两，石莲肉（去心）、白茯苓、黄芪（蜜炙）、人参各七钱半。上锉散。每三钱，麦门冬十粒，水一盏半，煎取八分，空心食前服。（《局方》清心莲子饮） ⑤治心经虚热，小便亦浊：石莲肉（连心）六两，炙甘草一两。细末。每服二钱，灯心煎汤调下。（《仁斋直指方》莲子六一汤） ⑥治小便白浊，梦遗泄精：莲肉、益智仁、龙骨（五色者）各等分。上为细末。每服二钱，空心用清米饮调下。（《奇效良方》莲肉散） ⑦补虚益损：莲实（去皮）不以多少，用好酒浸一宿，入大猪肚内，用水煮熟，取出焙干。上为极细末，酒糊为丸，如鸡头大。每服五、七十丸，食前温酒送下。（《医学发明》水芝丸） ⑧治病后胃弱，不消水谷：莲肉、粳米各炒四两，茯苓二两。共为末，砂糖调和。每用两许，白汤送下。（《士材三书》莲肉糕） ⑨治翻胃：石莲肉，为末，入些豆蔻末，米汤乘热调服。（《仁斋直指方》莲子散） ⑩治产后胃寒咳逆，呕吐不食，或腹作胀：石莲肉两半，白茯苓一两，丁香五钱。上为末。每服二钱，不拘时，用姜汤或米饮调下，日三服。（《妇人良方》石莲散）' where id=1890; -- 莲子
update herbs set taste='味辛；微苦；性温。', channel='入心、脾经。', effect='①治血气胀满：刘寄奴穗实为末。每服三钱，煎酒服。（《卫生易简方》） ②治产后恶露不尽，脐腹疞痛，壮热憎寒。咽干烦渴：刘寄奴、知母（焙）各一两，当归（切，焙）、鬼箭羽各二两，桃仁（去皮、尖、双仁，炒）一两半。上五味粗捣筛。每服四钱匕，水一盏半，煎至八分，去渣，温服，空心食前。（《圣济总录》刘寄奴汤） ③治产后百病血运：刘寄奴、甘草。上二味等分，锉如麻豆大。每服五钱匕，先以水二盏，入药煎至一盏，再入酒一盏，再煎至一盏，去渣，温服。（《圣济总录》刘寄奴汤） ④治被打伤破，腹中有瘀血：刘寄奴、延胡索、骨碎补各一两。上三味细切，以水二升，煎取七合，复内酒及小便各一合，热温顿服。（《千金方》） ⑤敛金疮口，止疼痛：刘寄奴一味为末，掺金疮口，裹。（《本事方》刘寄奴散） ⑥治风入疮口肿痛：刘寄奴为末，掺之。（《圣惠方》） ⑦治汤火疮：刘寄奴为末，先以糯米浆，用鸡翎扫伤著处，后掺药末在上，并不痛，亦无痕。大凡伤著，急用盐末掺之，护肉不坏，然后药敷之。（《本事方》） ⑧治赤白下痢：刘寄奴、乌梅、白姜等分。水煎服，赤加梅，白加姜。（《如宜方》） ⑨治霍乱成痢：刘寄奴草煎汁饮。（《圣济总录》） ⑩治大小便血：刘寄奴为末，茶调，空心服二钱。（《濒湖集简方》） ⑾（《江西民间草药》）治毒蛇咬伤：刘寄奴15，天胡妥30，青木香15。水、酒煎服。方中刘寄奴清热解毒，活血消肿，为君药。 ⑿（《福建民间草药》）治跌打损伤：刘寄奴15-24g，酌加黄酒或酒、水各半，炖1小时，温服日2次。方中刘寄奴清热解毒，活血消肿，为君药。 ⒀（《浙江民间常用草药》）治小儿惊风，疳积泻：刘寄奴30g。水煎服；疳积泻，加鸡肝煎服。方中刘寄奴利湿退黄，清热解毒，活血消肿，为君药。' where id=1891; -- 刘寄奴
update herbs set taste='甘，寒。', channel='入肺、胃经。', effect='①治太阴温病，口渴甚，吐白沫粘滞不快者：梨汁、荸荠汁、鲜苇根汁、麦冬汁、藕汁（或用蔗浆），临时斟酌多少，和匀凉服，不甚喜凉者，重汤炖温服。（《温病条辨》五汁饮） ②治五噎心膈气滞，烦闷吐逆，不下食：芦根五两。锉，以水三大盏，煮取二盏，去滓，不计时，温服。（《金匮玉函方》） ③治呕哕不止厥逆者：芦根三斤。切，水煮浓汁，频饮。（《肘后方》） ④治伤寒后呕哕反胃，及干呕不下食：生芦根（切）、青竹茹各一升，粳米三合，生姜三两。上四味，以水五升，煮取二升半，随便饮。（《千金方》芦根饮子） ⑤治骨蒸肺痿，烦躁不能食：芦根（切讫秤）、麦门冬（去心）、地骨白皮各十两，生姜十两（合皮切），橘皮、茯苓各五两。上六味，切，以水二斗，煮取八升，绞去滓，分温五服，服别相去八、九里，昼三服，夜二服，覆取汗。忌酢物。（《玄感传尸方》） ⑥霍乱烦闷：芦根三钱，麦门冬一钱。水煎服。（《千金方》） ⑦治食鱼中毒，面肿，烦乱，及食鲈鱼中毒欲死者：芦根汁，多饮良，并治蟹毒。（《千金方》） ⑧治牙龈出血：芦根水煎，代茶饮。（《湖南药物志》） ⑨治肺痈。吐腥臭脓痰，胸中隐隐作痛，肌肤干燥粗糙，舌质红，苔黄腻，脉滑数。鲜芦根60g，薏苡仁15～30g，冬瓜仁15～30g，桃仁9g。日服一剂，水煎，分2次服。方中芦根配伍薏苡仁治肺痈咳吐脓痰腥臭带血。（《千金方》苇茎汤） ⑩单味捣烂取汁服，治河豚中毒。 ⑾单味捣汁1碗，饮服，并煎汤浴体，治中马肉毒。' where id=1892; -- 芦根
update herbs set taste='味咸；性寒。', channel='入肝、心经。', effect='①治伤寒时气，寒热伏热，汗、吐、下后余热不退，或心惊狂动，烦乱不宁，或谵语无伦，人情颠倒，脉仍数急，迁延不愈：羚羊角磨汁半盏，以甘草、灯芯各一钱，煎汤和服。（《方脉正宗》） ②治中风手颤，亸曳语涩：羚羊角（镑）一两，犀角（镑）三分，羌活（去芦头）、防风（去叉）各一两半，薏苡仁（炒）、秦艽（洗）各二两。共研细末，炼蜜丸，如梧桐子大。每服二十丸，煎竹叶汤下，渐加至三十丸。（《圣济总录》羚羊角丸） ③治偏风，手足不随，四肢顽痹：羚羊角（镑）一两，独活（去芦头）二两，乌头（炮裂，去皮、脐）三分，防风（去叉）一分。锉如麻豆。每服五钱匕，以水二盏，煎取一盏，去滓，分温二服，空腹、夜卧各一。（《圣济总录》羚羊角汤） ④治阳厥气逆、多怒：羚羊角、人参各三两，赤茯苓二两（去皮），远志（去心）、大黄（炒）各半两，甘草一分（炙）。上为末。每服三钱，水一盏半，煎至八分，去滓温服，不计时候。（《宣明论方》羚羊角汤） ⑤治血虚筋脉挛急，或历节掣痛：羚羊角磨汁半盏，以金银花一两五钱，煎汤一碗，和服。（《续青囊方》） ⑥治产后中风，身体反张如角弓：羚羊角屑三分，独活一两，当归三分（锉，微炒），防风一两（去芦头），人参半两（去芦头），赤芍药半两，细辛半两，桂心半两，麻黄一两（去根、节）。捣，粗罗为末。每服四钱，以水一中盏，入生姜半分，煎至六分，去滓，不计时候温服。（羚羊角散） ⑦治小儿夜啼及多惊热：羚羊角屑一分，黄芩一分，犀角屑一分，甘草一分（炙微赤，锉），茯神一分，麦门冬半两（去心，焙）。捣，粗罗为散。每服一钱，以水一小盏，煎至五分，去滓，量儿大小，分减服之。（羚羊角散） ⑧治时气七日，心神烦热，胸膈不利，目赤，不得睡卧：羚羊角屑、黄芩、柱子仁、黄连（去须）、川升麻、枳壳（麸炒微黄，去瓤）各一两。捣罗为末，炼蜜和丸，如梧桐子大。每服不计时候，以竹叶汤下三十丸。（羚羊角丸，⑥方以下出《圣惠方》） ⑨治心肺风热冲目，生胬肉：羚羊角（镑）、黄芩（去黑心）、柴胡（去苗）、升麻各三分，甘草（生锉）一两。粗捣筛，每服五钱匕，水一盏半，煎至一盏，去滓，食后服。（《圣济总录》羚羊角汤） ⑩治眼卒生白翳膜：羚羊角屑半两.泽泻半两，甘菊花一两，葳蕤半两，菟丝子半两（酒浸三日，曝干，别捣为末）。捣，粗罗为散，每服三钱，以水一中盏，煎至六分，去滓，不计时候，温服。（《圣惠方》羚羊角散） ⑾治痘唐后馀毒未清，随处痛肿：羚羊角磨汁半盏，以黄耆、金银花各二两，煎汤和服。（《本草汇言》） ⑿治肝热生风证。高热不退，烦闷躁扰，手足抽搐，发为痉厥，甚则神昏，舌绛而干，或舌焦起刺，脉弦而数。羚角片4.5g，双钩藤9g，霜桑叶6g，滁菊花9g，鲜生地15g，生白芍9g，川贝母12g，淡竹茹15g，茯神木9g，生甘草3g。水煎服。方中羚羊角咸寒，入肝、心经，最擅长清肝热、熄肝风、止痉定搐，为君药。（《通俗伤寒论》羚角钩藤汤） ⒀治温热病，热邪内陷心包，热盛动风证。高热烦躁，神昏谵语，痉厥，斑疹吐妞，口渴引饮，唇焦齿燥，尿赤便秘，舌红绛苔干黄，脉数有力或弦数，以及小儿热盛惊厥。石膏、寒水石、滑石、磁石各3斤，犀角羚羊角、沉香、青木香各5两，玄参、升麻各1斤，甘草8两，丁香1两，芒硝10斤，硝石4升，麝香5分，朱砂3两，黄金100两。病人强壮者，一服2分。老弱人或热毒微甚者，一服1分，以意节之。方中羚羊角长于凉肝息风止痉，为热传心肝两经之良药，为君药。（《外台秘要》紫雪丹） ⒁治肝热生风之小儿天钓。惊悸火热，牙关紧闭，手足抽搐，头目仰视等。钩藤9g，羚羊角0.3g，全蝎1g，人参3g，天麻6g，甘草2g。水煎服。方中羚羊角咸寒，入肝、心经，最擅长清肝热、熄肝风、止痉定搐，为君药。（《医宗金鉴》钩藤饮）' where id=1893; -- 羚羊角
update herbs set taste='味苦；辛；性平，有毒。', channel='肺经。', effect='①治积聚，心腹胀如故者：狼毒四两（锉碎，醋拌炒干），附子三两（炮裂，去皮脐），防葵三两。上药捣罗为末，炼蜜和捣三、二百杵，丸如梧桐子大。每于食前，以粥饮下五丸，以利为度。（《圣惠方》狼毒丸） ②治卒心腹癥坚，两胁下有气结者：狼毒二两，旋覆花一两，附子二两（炮）。捣筛，蜜和丸如梧子大。服二丸，稍加至三丸。 ③治心腹相连胀痛：狼毒二两，附子半两。捣筛，蜜丸如梧子大。日一服一丸，二日二丸，三日后服三丸，再一九，至六日，服三丸，自一至三以常服。 ④治阴疝，阴丸卒缩入腹，急痛欲死：狼毒四两，防风二两，附子三两（烧）。蜜丸如桐子大，服三丸，日夜三度。（②方以下出《补缺肘后方》） ⑤治水肿：绵大戟细末，每股五分，滚水服。忌盐一百日，乃泻去黄水，其肿自消，如泻不止，冷粥补之。（《滇南本草》） ⑥治一切食积、痰积、虫积、气积、痞块疼痛，胸膈肚腹膨胀，饮食不消，面皮黄瘦，单腹胀：绵大戟为末，米糊为丸。如马豆子大，每服七丸，滚水送下，以利为度。（《滇南本草》） ⑦治淋巴结结核：㈠未溃或已溃者：狼毒切片，用水煮烂，除渣取药液，加热浓缩成膏，洗净伤口，外敷。㈡已溃者拔脓毒：狼毒一斤，蛇蜕八分，花椒一两，松香五钱。将狼毒煎制成膏，其他药研成细末，撒入并搅拌均匀。外敷。㈢愈合淋巴结结核伤口：狼毒一两，蒲公英根一两。煎成膏外敷。（内蒙古《中草药新医疗法资料选编》） ⑧治睾丸结核：狼毒、核桃、白矾各等量。烧存性，共研细末。每日一次，每次一钱三分，开水送服。（内蒙古《中草药新医疗法资料选编》） ⑨治疠风癞疮：狼毒，童便浸炒，研末。每早晚各服五分，温酒下。（《张三丰仙传方》） ⑩治干癣积年生痂，搔之黄水出，每逢阴雨即痒；狼毒，醋磨涂之。（《圣惠方》） ⑾治久年干疥干癣及一切癞疮：狼毒（微炒研细末），轻粉减半。和匀，干疥癣癞疮，搔破搽之；湿者干掺，数次效。（《永类钤方》） ⑿治脏腑内一切虫病：川狼毒杵末，每服一大钱，用饧一皂子大，沙糖少许，以水同化，临卧空腹服之，来日早取下虫效。（《集效方》） ⒀治外伤出血：绵大戟研末撒于伤口。（《云南中草药选》）', tips='本品有毒，内服宜慎；体弱及孕妇忌服。 恶麦句姜。 ②《药对》：畏占斯、密陀僧。 ③《本草汇言》：脾元不足，真气日乏者，不可妄施。 ④《得配本草》：畏醋。 ⑤《高原中草药治疗手册》：孕妇忌用，慢性胃肠溃疡慎用。' where id=1894; -- 狼毒
update herbs set taste='甘；辛；温；无毒。', channel='入脾、胃经。', effect='①治脾胃俱虚，不能消化水谷，胸膈痞闷，腹胁时胀，连年累月，食减嗜卧，口苦无味，虚羸少气：乌梅（去核焙干）、干姜（炮）各四两，小麦蘖（炒黄）三两，神曲（捣末炒）六两二钱。上件为末，炼蜜和搜为丸如梧桐子大，每服十五丸加至二十丸，米饮下，日二服，不计时候。（《局方》消食丸） ②治脾虚不能磨食：神曲四两，白爪三两，人参一两（俱炒），枳实（麸拌炒）五钱，砂仁（炒）四钱。共为末。饴糖为丸，梧子大。每早晚各服三钱，白汤下。（《方脉正宗》） ③治时暑暴泻及饮食所伤，胸膈痞闷：神曲（炒）、苍术（米泔浸一宿焙干）各等分。为末，面糊为丸，如梧桐子大。每服三十丸，不拘时，米饮吞下。（《局方》曲术丸） ④治暴泻：神曲（微炒），吴茱萸（绿色者拣净，泡洗七遍）各一两。上二味为细末，以酸米醋为丸如梧桐子大。每服五十丸至一百丸，空心食前米饮汤下。（《百一选方》孙盈仲·断下丸） ⑤治休息痢，日夜不止，腹内冷痛：神曲、芜荑、吴茱萸各等分。熬，生姜自然汁和丸，如梧桐子大。食前粥饮下三十丸，（《普济方》神曲丸） ⑥治产后冷痢，脐下疞痛：神曲三两（微妙令黄），熟干地黄二两，白术一两半。上件药捣细罗为散。每服，以粥饮调下二钱，日三、四服。（《圣惠方》神曲散） ⑦治食积心痛：陈神曲一块。烧红，淬酒二大碗服之。（《摘元方》） ⑧治产乳运绝，亦治产难：神曲末，水服方寸匕。（《千金方》） ⑨治产后瘀血不运，肚腹胀闷，渐成臌胀：陈久神曲一斤。捣碎，微炒磨为末。每早晚各服三钱，食前砂仁汤调服。亦可治小儿食臌胀。（《本草汇言》）' where id=1895; -- 神曲
update herbs set alias='斑龙珠。', taste='味甘；咸；性温。', channel='入肝、肾经。', effect='①治精血耗竭，面色黧黑，耳聋目昏，口干多渴，腰痛脚弱，小便白浊，上燥下寒，不受峻补：鹿茸（酒浸）、当归（酒浸）等分。为细末，煮乌梅膏子为丸，如梧桐子大。每服五十丸，空心用米饮送下。（《济生方》黑丸） ②治精血俱虚，营卫耗损，潮热自汗，怔忡惊悸，肢体倦乏，一切虚弱之症：鹿茸（酒蒸）、附子（炮）各一两。上细切，分作四付，水二盏，生姜十片，煎至八分，去渣，食前温服。（《世医得效方》茸附汤） ③治虚弱阳事不举，面色不明，小便频数，饮食不思：好鹿茸五钱，多用一两（去皮，切片），干山药一两（为末）。上以生薄绢裹，用酒浸七日后，饮酒，日三盏为度。酒尽，将鹿茸焙干，留为补药用之。（《普济方》鹿茸酒） ④治眩晕之甚，抬头则屋转，眼常黑花，观见常如有物飞动，或见物为二：鹿茸，每服半两，用无灰酒三盏，煎至一盏，去滓，入麝香少许服。（《证治要诀》） ⑤治湿久不治，伏足少阴，舌白身痛，足跗浮肿：鹿茸五钱，附子三钱，草果一钱，菟丝子三钱，茯苓五钱。水五杯，煮取二杯，日再服，渣再煮一杯服。（《温病条辨》鹿附汤） ⑥治小肠虚冷，小便数多：鹿茸二两（酥炙令微黄），白龙骨一两（烧过），桑螵蛸三分（微炒），椒红一两（微炒），附子一两半（炮），山茱萸一两。上药捣罗为末，炼蜜和捣一、二百杵，丸如梧桐子大。每服，空心及晚食前，以盐汤下二十丸。（《圣惠方》鹿茸丸） ⑦治崩中漏下，赤白不止：鹿茸十八铢，桑耳二两半。上二味，以醋五升渍，炙燥渍尽为度，治下筛，服方寸匕，日三。（《千金方》） ⑧治室女冲任虚寒，带下纯白：鹿茸（醋蒸，焙）二两，白敛、金毛狗脊（燎去毛）各一两。上为细末，用艾煎醋汁，打糯米糊为丸，如梧桐子大。每服五十丸，空心温酒下。（《济生方》白敛丸） ⑨治尿血：鹿茸（炙）、当归、干地黄各二两，葵子五台，蒲黄五合。上五味，捣筛为散。酒服方寸匕，日三服。忌芜荑。（《古今录验方》鹿茸散） ⑩治下痢危困：麝香半钱（别研，临时入），鹿茸一两（酥炙）。上鹿茸为细末，方入麝香，以灯心煮枣肉为丸，如梧桐子大。每服五十丸，空心服。（《百一选方》香茸丸） 11.治房黄，眼赤身黄，体虚无力，夜多梦泄，神思不安，腰脚酸痛。鹿茸、熟干地黄、黄芪、山茱萸、五味子、牡蛎各30g。上为散，以温酒调下6g。方中鹿茸配伍熟地治肾阳不足。（《太平圣惠方》鹿茸散） 12.治肾阳虚损，精血不足证。面色黧黑，足冷足肿，耳鸣耳聋，肢体形瘦，足膝软弱，小便不利，腰脊疼痛。附子、五味子、山茱萸、山药、牡丹皮、熟地黄各9g，鹿茸3g，肉桂3g，白茯苓、泽泻各6g。上为细末，炼蜜为丸，每次服9g，盐汤服下。方中鹿茸为温肾壮阳、填精益髓之用。（《严氏济生方》十补丸）', tips='凡阴虚阳亢者，血分有热，胃火盛或肺有痰热以及外感热病者均禁服。 ②《本草经疏》：肾虚有火者不宜用，以其偏于补阳也；上焦有痰热及胃家有火者不宜用，以其性热复腻滞难化也。凡吐血下血，阴虚火炽者概不得服。' where id=1896; -- 鹿茸
update herbs set taste='味苦；微辛；性平。', effect='①治疗郁冒血厥，居常无苦，忽然如死，身不动，默默不知人，目闭不能开，口噤不能语，又或似有知，而恶闻人声，或但如眩冒，移时乃寤：老君须一两，当归一两，人参半两。上为散，每服五钱，水二盏，煎至一盏，去滓，温服。（《全生指迷方》老君须汤） 治疗肺实鼻塞，不知香臭：百部二两，款冬花、贝母（去心）、老君须各一两。上为散，每服一钱，米饮调下。（《普济方》） ②治疗金疮血不止：老君须末贴之。（《儒门事亲》） ③治疗妇人乳中虚，烦乱呕逆：生竹茹二分，石膏二分，桂枝一分，甘草七分，老君须一分。上五味末之，枣肉和丸弹子大。以饮服一丸，日三夜二服。有热者倍老君须，烦喘者加柏实一分。（《金匮要略》竹皮大丸） ④治疗妇人遗尿，不知出时：老君须、芍药各一两。上二味，治下筛。酒服方寸匕，日三。（《备急千金要方》）' where id=1897; -- 老君须
update herbs set effect='①治风湿关节炎：雷公藤根、叶，捣烂外敷，半小时后即去，否则起泡。（江西《草药手册》） ②治皮肤发痒：雷公藤叶，捣烂，搽敷。（《湖南药物志》） ③治腰带疮：雷公藤花、乌药，研末凋擦患处。（《湖南药物志》）' where id=1898; -- 雷公藤
update herbs set taste='味咸、涩、性温。', effect='①治肾寒羸瘦，生阳气，补精髓：鹿角霜，肉苁蓉（酒浸，去皴皮，切，焙）、附子（炮裂，去皮、脐）、巴戟天（去心）、蜀椒（去目及闭口，炒出汗）各一两。上五味，捣罗为末，酒煮面糊和丸如梧桐子大。每服二十丸，空心温酒下。（《圣济总录》鹿角霜丸） ②治诸虚百损，羸弱不堪者：用铜甑一具，着底铺薄荷末二两，上铺山药末八两，上铺鳗鱼（去头、尾）一斤，上铺鹿角霜四两，再以薄荷细末二两盖之，蒸极烂，将鱼骨炙脆为末，共一处捣和丸。每服五钱，白汤下。（《何氏济生论》鹿角霜丸） ③治盗汗遗精：鹿角霜二两，生龙骨（炒）、牡蛎（煅）各一两。为末，酒糊丸梧子大。每盐汤下四十丸。（《普济方》） ④治小便频数：鹿角霜、白茯苓等分。为末，酒糊丸梧子大。每服三十丸，盐汤下。（《梁氏总要方》） ⑤治五种腰痛，夜多小便，膀胱宿冷：鹿角霜，细研如面，每日空腹时以温酒调下二钱，晚食前再服。（《圣惠方》鹿角霜方） ⑥治膏淋：鹿角霜、白茯苓、秋石各等分。为末，糊丸梧子大。每服五十丸，米汤下。（《三因方》鹿角霜丸）' where id=1899; -- 鹿角霜
update herbs set taste='味辛；性热。', channel='归脾；胃经。', effect='①治痢积水泻：辣茄一个。为丸，清晨热豆腐皮裹，吞下。（《医宗汇编》） ②治疟疾：辣椒子，每岁一粒，二十粒为限，一日三次，开水送服，连服三至五天。（吴县《单方验方选编》） ③治冻瘃：剥辣茄皮，贴上。（《纲目拾遗》） ④治毒蛇伤：辣茄生嚼十一、二枚，即消肿定痛，伤处起小泡，出黄水而愈。食此味反甘而不辣。或嚼烂敷伤口，亦消肿定痛。（《百草镜》）' where id=1900; -- 辣椒
update herbs set taste='甘；微苦；性凉。', effect='①治肝炎腹胀：罗布麻二钱，甜瓜蒂一钱五分，延胡索二钱，公丁香一钱，木香三钱。共研末，一次五分，一日二次，开水送服。（《新疆中草药手册》） ②治神经衰弱，眩晕，脑震荡后遗症，心悸，失眠，高血压，肝硬化腹水，浮肿：罗布麻一至三钱。开水冲泡当茶喝，不可煎煮。（《新疆中草药手册》）' where id=1901; -- 罗布麻
update herbs set taste='味辛；甘；性平。', channel='入肺、胃经。', effect='①治积年上气咳嗽，多痰喘促，唾脓血：莱菔子一合，研，煎汤，食上服之。（《食医心镜》） ②治百日咳：白萝卜种子，焙燥，研细粉。白砂糖水送服少许，一日数回。（《江西中医药》（12）：1963） ③治齁喘痰促，遇厚味即发者：萝卜子淘净，蒸熟，晒研，姜汁浸蒸饼丸绿豆大。每服三十丸，以口津咽下，日三服。（傅滋《医学集成》清金丸） ④治高年咳嗽，气逆痰痞：紫苏子、白芥子、萝卜子。上三味各洗净，微炒，击碎，用生绢小袋盛之，煮作汤饮。随甘旨，代茶水啜用，不宜煎熬大过。（《韩氏医通》三子养亲汤） ⑤治一切食积：山查六两，神曲二两，半夏，茯苓各三两，陈皮、连翘、萝卜子各一两。上为末，炊饼丸如梧子大。每服七、八十丸，食远，白汤下。（《丹溪心法》保和丸） ⑥治气胀气臌：莱菔子，研，以水滤汁，浸缩砂一两，一夜，炒干，又浸又炒，凡七次，为末。每米饮服一钱。（《朱氏集验医方》） ⑦治痢疾有积，后重不通：莱菔子五钱，白芍药三钱，大黄一钱，木香五分。水煎服。（《方脉正宗》） ⑧治风秘气秘：萝卜子（炒）一合，擂水，和皂荚末二钱服。（《寿域神方》） ⑨治中风口噤：萝卜子、牙皂荚各二钱。以水煎服，取吐。（朱震亨） ⑩治风头痛及偏头痛：莱菔子半两，生姜汁半合。上相和研极细，绞取汁，入麝香少许，滴鼻中搐入，偏头痛随左右用之。（《普济方》） ⑾治小儿盘肠气痛：萝卜子炒黄，研末。乳香汤服半钱。（《仁斋直指访》） ⑿治牙疼：萝卜子二七粒，去赤皮，细研。以人乳和，左边牙痛，即于右鼻中点少许，如右边牙疼，即于左鼻中点之。（《圣惠方》） ⒀治跌打损伤，瘀血胀痛：莱菔子二两，生研烂，热酒调敷。（《方脉正宗》） (14)治小儿盘肠气痛：萝卜子，炒黄，研末，每服1.5g，乳香汤送下。方中莱菔子消食去胀，祛痰降气，为君药。（《仁斋直指方》）' where id=1902; -- 莱菔子
update herbs set taste='甘涩，平。', channel='入心、肝、肾、大肠经。', effect='①治大人、小儿一切癫狂，惊搐，风痫，神志不宁：龙骨一两（火煅，研极细末），犀角、丹砂、琥珀、天竺黄各五钱（俱研极细末），钩藤、怀生地、茯苓各一两五钱（俱微炒燥，为极细末），苏合香三钱，牛黄二钱（俱用酒溶化）。共十味，总和一处，用胆星八钱，研细末，竹沥一碗，打糊为丸，如梧子大。大人服十丸，小儿服二、三丸，俱用生姜汤调灌。（《方脉正宗》） ②治伤寒脉浮，医以火迫劫之，亡阳，必惊狂，卧起不安者：桂枝（去皮）三两，甘草（炙）二两，生姜三两（切），大枣十二枚（擘），牡蛎（熬）五两，蜀漆（去腥）三两，龙骨四两。上七味，以水一斗二升，先煮蜀漆，减二升，纳诸药，煮取三升，去滓。温服一升。（《伤寒论》桂枝去芍药加蜀漆龙骨牡蛎救逆汤） ③治好忘：龙骨、虎骨、远志各等分。上三味，治下筛。食后服方寸匕，日二。（《千金方》） ④治心虚盗汗：龙骨五钱（火煅），茯苓一两，人参六钱，莲肉三两（俱微炒），共研为末，麦门冬（去心）四两，酒煮，捣烂成膏为丸梧子大。每早晚各服三钱，白汤下。（《方脉正宗》） ⑤治产后虚汗不止：龙骨一两，麻黄根一两。上件药，捣细罗为散。不计时候，以粥饮调下二钱。（《圣惠方》） ⑥治遗尿淋沥：白龙骨、桑螵蛸等分。为末。每盐汤服二钱。（《梅师集验方》） ⑦治失精家少腹弦急，阴头寒，目眩，发落，脉极虚芤迟，为清谷，亡血失精，脉得诸芤动微紧，男子失精，女子梦交：桂枝、芍药、生姜各三两，甘草二两，大枣十二枚，龙骨、牡蛎各三两。上七味，以水七升，煮取三升。分温三服（《金匮要略》桂枝加龙骨牡蛎汤） ⑧治失精，暂睡即泄：白龙骨四分，韭子五合。上件为散子。空心，酒调方寸匕服。（《梅师集验方》） ⑨治劳心梦泄：龙骨、远志等分。为末，炼蜜丸如梧子大。每服三十丸，莲子汤下。（《活人心统》） ⑩治白浊：糯米饭（晒干）四两，赤石脂（炒令焦黄）、龙骨（煅，别研）、白茯苓（去皮）各二两。上为细末，醋煮面糊儿焙干。每服五十丸，空心盐汤送下，食前服。（《魏氏家藏方》龙骨丸） ⑾治鼻衄出血多，眩冒欲死：龙骨研细。吹入鼻耳中。凡衄者并吹。（《梅师集验方》） ⑿治妇人无故尿血：龙骨五两。治下筛。酒服方寸匕，空腹服，日三（《千金方》） ⒀治血崩不止：龙骨（煅）、当归、香附（炒）各一两，棕毛灰五钱。上为细末。每服四钱，空心，米饮调下。忌油腻、鸡、鱼、炙博物。（《景岳全书》龙骨散） ⒁治金疮出血：龙骨一两（五色紧者），诃子一两，白石脂半两，苧麻叶半两（系五月采来阴干者）。上为细末。水调服之。（《普济方》神仙止血散） ⒂治泄泻不止：白龙骨、白石脂等分。为末，水丸梧子大。紫苏、木瓜汤下，量大人小儿用。（《全幼心鉴》） ⒃治久痢休息不止者：龙骨四两。打碎，水五升，煮取二升半。分五服，冷饮。仍以米饮和丸。每服十九（《肘后方》） ⒄治小儿因痢脱肛：白龙骨粉扑之.（姚和众） ⒅治两耳湿烂，久不收敛：龙骨、亦石脂（俱火煅）、海螵蛸（水煮过）各三钱。共研细末。先用绵纸条拭干脓水，后吹末药。（《本草汇言》） ⒆治阴囊汗痒：龙骨、牡蛎粉扑之。（《医宗三法》） ⒇治小儿脐疮久不差：龙骨煅。细研为末，敷之。（《圣惠方》） （21）治淋巴结结核（适应于干酪化者，或结核破溃者）：煅龙骨、煅石膏、滑石各等量。共研末。将已炼好的猪油溶化，投入药末，搅拌成糊状，贮存备用。先将病灶清除干净，再用上药膏制成的油纱布条填塞创面。每日换药一次。开始时脓汁增多，一般3～4天后创面干净。连续应用1～2周。（内蒙古《中草药新医疗法资料选编》） （22）治汤火伤：龙骨、生石膏、大黄、儿茶各等分，共研极细末，冷茶水调稀糊状。敷患处，敷后用纱布盖好（面部可不盖），每隔一日换药一次。（《中医杂志》 （23）镇肝息风汤（《医学衷中参西录》）治肝阳上亢，气血上逆之类中风。头目眩晕，目胀耳鸣，脑部热痛，心中烦热，面色如醉，或时常噫气，或肢体渐觉不利，口角渐形歪斜；甚或眩晕颠仆，昏不知人，移时始醒；或醒后不能复原，脉弦长有力。怀牛膝30g，生赭石30g，生龙骨15g，生牡蛎15g，生龟板15g，生杭芍15g，玄参15g，天冬15g，川楝子6g，生麦牙6g，茵陈6g，甘草4.5g。水煎服。方中龙骨质重性降，既可潜降摄纳上亢之肝阳，又可平镇上逆之气血，为牛膝之助，是为臣药。 （24）金锁固金丸（《医方集解》）治肾虚精关不固，遗精滑泻。腰酸耳鸣，四肢酸软，神疲乏力，舌淡苔白，脉细弱。沙苑蒺藜12g，芡实12g，莲须12g，龙骨15g，牡蛎15g。莲子粉糊为丸，盐汤下。方中龙骨煅制而用，涩性增强以涩精止遗，为佐药。 （25）桑螵蛸散（《本草衍义》）治心肾两虚的尿频或滑精证。小便频数，或尿色白浊如米泔水，或遗尿、滑精，心神恍惚，健忘，舌淡苔白，脉细弱。桑螵蛸9g，远志6g，菖蒲6g，龙骨15g，人参9g，茯神12g，当归9g，龟甲15g。以上为末，夜卧人参汤调下2钱。方中龙骨宁心安神，收涩固精，为臣药。' where id=1903; -- 龙骨
update herbs set taste='味苦；辛；性凉。', effect='①治咳血，吐血，尿血:鲜荔枝草根五钱至一两，瘦猪肉二两。炖汤服。（江西《中草药学》） ②治喉痛或生乳蛾:荔枝草捣烂，加米醋，绢包裹，缚箸头上，点入喉中数次。（《救生苦海》） ③治双单蛾:雪里青一握，捣汁半茶钟，滚水冲服，有痰吐出；如无痰，将鸡毛探吐。若口干，以盐汤、醋汤止渴。切忌青菜、菜油。（《集效方》） ④治风火牙痛:癞子草含口中。 ⑤治耳心痛:耳心灌脓:癞子草捣汁滴耳。 ⑥治痔疮便毒，口腔白泡疮，走马牙疳；大五倍子一个。贯穿一孔，将瘫子草炕干，打成粉注入，装满封口，在火上煅后研粉，外加冰片，调麻油搽患处。（④方以下出《重庆草药》） ⑦治痔疮:雪里青汁，炒槐米为末，柿饼捣，丸如桐子大。每服三钱、雪里青煎汤下。（《慈航活人书》） ⑧治痔疮:荔枝草一、二两（或加乌梅七个）。水煎，先熏后洗。亦治脱肛。（《江西中医药》（6）:57，1957） ⑨治鼠疮:过冬青五，六枚，同鲫鱼入锅煮熟，去草及鱼，饮汁数次。（《经验广集》冬青汁） ⑩治红肿痈毒:荔枝草鲜草同酒酿糟捣烂，敷患处；或晒干研末，同鸡蛋清调敷。（《江西中医药》（6）:57，1957） ⑾治乳痈初起:㈠雪见草连根一两。酒水各半煎服，药渣敷患处。（《江西民间草药验方》）㈡鲜荔枝草叶二片，揉软后塞鼻，如右侧乳腺炎塞左鼻孔，左侧塞右鼻孔。每次塞20分钟，一日塞二次。（徐州《单方验方新医疗法选编》） ⑿治疥疮、诸种奇痒疮:癞子草嫩尖叶捣烂取汁涂。（《重庆草药》） ⒀治跌打伤:荔枝草一两，捣汁，以滚甜酒冲服，其渣杵烂，敷伤处。（《江西中医药》（6）:57，1957） ⒁治蛇咬、犬伤及破伤风:荔枝草一握，约三两，以酒二碗，煎一碗服，取汗出，效。（《卫生易简方》） ⒂治白浊:雪里青草，生白酒煎服。（《纲目拾遗》） ⒃治急惊:荔枝草汁半钟，水飞过朱砂半分，和匀服之。（《医方集听》） ⒄治小儿疳积:荔枝草汁入茶杯内，用不见水鸡软肝一个，将银针钻数孔，浸在汁内，汁浮于肝，放饭锅上薰熟食之。（《医方集听》） ⒅治红白痢疾:癞子草（有花全草）二两，墨斗草一两，过路黄一两。煎水服，每日三次；现坠胀者，外加土地榆、臭椿根皮各一两。（《重庆草药》）', tips='凉血，利水，解毒，杀虫。治咳血，吐血，尿血，崩漏，腹水，白浊，咽喉肿痛，痈肿，痔疮。 ①《生草药性备要》:治跌打伤，去瘀，洗痔疮。 ②汪连仕《采药书》:凉血，止崩漏，散一切痈毒。 ③《纲目拾遗》；《葛祖遗方》，治咽喉十八症，消痈肿，杨梅、痔疮。 ④《草木便方》:解毒。治白秃，疥癞，风癣；除脚胫疮痒黄水，杀虫，调油涂。 ⑤《分类草药性》:治一切久年癍疮，洗痔疮，痒疮。 ⑥《药物图考》:治湿热风疹，阴痒、肾囊风，消肿利水。 ⑦《江苏植药志》:水煎服，治腹胀。 ⑧《中国药植图鉴》:捣烂敷肚脐上，除臌胀病腹水。 ⑨《四川中药志》:清肺热，除风湿。治咳嗽，痢疾，牙痛及痒疹，疮毒。' where id=1904; -- 荔枝草
update herbs set taste='甘涩，平。', channel='入心、肾经。', effect='①治遗精梦泄：熟地八两，山茱萸二两，山药、茯苓各三两，丹皮、龙骨三钱（生研，水飞），莲须一两，芡实二两，线胶四两（同牡蛎炒热，去牡蛎）。为末，蜜丸梧子大。每服四钱，空心淡盐汤下。（《经验广集》固精丸） ②治精滑不禁：沙苑蒺藜（炒）、芡实（蒸）、莲须各二两，龙骨（酥炙）、牡蛎（盐水煮一日一夜，煅粉）各一两。莲子粉糊为丸，盐汤下。（《医方集解》金锁固精丸） ③治久近痔漏，三十年者：莲须、黑牵牛（头末）各一两半，当归五钱。为末。每空心酒服二钱。忌热物。（《孙天仁集效方》） ④治上消口渴，饮水不休：白莲须一钱，粉干葛一钱，白茯苓一钱，大生地一钱，真雅连五分，天花粉五分，官拣参五分，北五味五分，净知母五分，炙甘草五分，淡竹叶五分，灯心十茎。水煎热服。（《幼幼集成》莲花饮）' where id=1905; -- 莲须
update herbs set taste='苦辛，平。', effect='①治筋骨瘫痪：老鹳草、筋骨草、舒筋草，炖肉服。（《四川㈡，药志》） ②治筋骨疼痛，通行经络，去诸风：新鲜老鹳草洗净，置一百斤于铜锅内，加水煎煮二次，过滤，再将滤液浓缩至约三十斤，加饮用酒五两，煮十分钟，最后加入熟蜂蜜六斤，混合拌匀，煮二十分钟，待冷装罐。（《中药形性经验鉴别法》老鹳草膏） ③治腰扭伤：老鹳草根一两，苏木五钱，煎汤，血余炭三钱冲服，每日一剂，日服二次。（内蒙古《中草药新医疗法资料选编》） ④治急慢性肠炎下痢：牻牛儿苗六钱，红枣四枚。煎浓汤，一日三回分服。（《现代实用中药》） ⑤治肠炎，痢疾：老鹳草一两，凤尾草一两，煎成90毫升，一日三次分服，连服一至二剂。（《浙江省中草药抗菌消炎经验交流会资料选编》） ⑥治妇人经行受寒，月经不调，经行发热，腹胀腰痛，不能受胎：五叶草五钱，川芎二钱，大蓟二钱，白芷二钱。水酒各一钟，合煎，临卧服，服后避风。（《滇南本草》）', tips='祛风通络；活血；清热利湿。主风湿痹痛；肌肤麻木；筋骨酸楚；跌打损伤；泄泻痢疾；疮毒 ①《滇南本草》：祛诸风皮肤发痒。治筋骨疼痛，痰火痿软，手足筋挛，麻木，利小便，泻膀胱积热，攻散诸疮肿毒，退痨热发烧，治风火虫牙，痘疹疥癞等症。 ②《纲目拾遗》：去风，疏经活血，健筋骨，通络脉。治损伤，痹症，麻木，皮风，浸酒常饮。 ③《现代实用中药》：止久痢，厚肠胃，调中健脾。 ④《贵州民间方药集》：治跌打损伤，止刀伤出血，又可止咳，益肺气。 ⑤《药材学》：清热解毒。治热病消渴，痈疽疮肿。' where id=1906; -- 老鹳草
update herbs set taste='甘，温，', channel='心；肾；肝；脾经。', effect='①治思虑过度，劳伤心脾，健忘怔忡：白术、茯苓（去木）、黄芪（去芦）、龙眼肉、酸枣仁（炒，去壳）各一两，人参、木香（不见火）各半两，甘草（炙）二钱半。上细切，每服四钱，水一盏半，生姜五片，枣一枚，煎至七分，去滓温服，不拘时候。（《济生方》归脾汤） ②大补气血：以剥好龙眼肉，盛竹筒式瓷碗内，每肉一两，入白糖一钱，素体多火者，再加入西洋参片一钱，碗口罩以丝绵一层，日日于饭锅上蒸之，蒸至多次。凡衰羸老弱，别无痰火便滑之病者，每以开水瀹服一匙，大补气血，力胜参芪，产妇临盆，服之尤妙。（《随息居饮食谱》玉灵膏，一名代参膏） ③温补脾胃，助精神：龙眼肉不拘多少，上好烧酒内浸百日，常饮数杯。（《万氏家抄方》龙眼酒） ④治脾虚泄泻：龙眼干十四粒，生姜三片。煎汤服。（《泉州本草》） ⑤治妇人产后浮肿：龙眼干、生姜、大枣。煎汤服。（《泉州本草》）' where id=1907; -- 龙眼肉
update herbs set alias='丹荔，火山荔，荔支，离支，丽枝，勒荔', taste='甘；酸；温。', channel='脾；肝经。', effect='①治呃逆不止:荔枝七个，连皮核烧存性；为末，白汤调下。（《医方摘要》） ②治瘰疬溃烂:荔肉敷患处。（《泉州本草》） ③治疔疮恶肿:荔枝肉、白梅各三个。捣作饼子，贴于疮上。（《济生秘览》） ④治风火牙痛:大荔枝一个，剔开，填盐满壳，煅研，搽之。（《孙天仁集效方》） ⑤止外伤出血，并防止疮口感染溃烂，得以迅速愈合:荔枝晒干研末（浸童便晒更佳）备用。每用取末掺患处。（《泉州本草》） ⑥治老人五更泻，粪便溏软:荔枝干，每次五粒，春米一把，合煮粥食，连服三次；酌加山药或莲子同煮更佳。（《泉州本草》） ⑦治孕妇堕胎后下血不止及产后出血：荔枝干七个（连壳和核一起打破），用两碗水煎至一碗服下。 ⑧治小儿遗尿：每天吃荔枝干十个。 ⑨治妇女虚弱贫血：荔枝干、大枣各七个，水煎服，每日一剂。 ⑩治气虚寒痛：荔枝肉5枚，煮酒1杯服用，屡服有效。 ⑾荔枝莲子淮山粥：干荔枝肉50克，淮山、莲子各10克（捣碎），水煮至软烂时，加入大米100克，同煮粥，用油盐或白糖调味食用，可治老人晨起腹泻（五更泻），大便溏稀等症。' where id=1908; -- 荔枝
update herbs set alias='拉汗果、假苦瓜。', taste='味甘；性凉', effect='治百日咳：罗汉果一个，柿饼五钱。水煎服。' where id=1909; -- 罗汉果
update herbs set taste='苦，平。', channel='归肝、肾经。', effect='①治风湿肢节痛：路路通、秦艽、桑枝、海风藤、橘络、苡仁。水煎服。（《四川中药志》） ②治脏毒：路路通一个。煅存性，研末酒煎服。（《古今良方》） ③治癣：枫木上球十个（烧存性），白砒五厘。共末，香油搽。（《德胜堂经验方》） ④治荨麻疹：枫球一斤。煎浓汁，每天三次，每次六钱，空心服。（《湖南药物志》） ⑤治耳内流黄水：路路通五钱。煎服。（《浙江民间草药》）' where id=1910; -- 路路通
update herbs set taste='苦辛，寒，有毒。', channel='肺；胃；肝经', effect='①治诸风痰饮：藜芦十分，郁金一分，为末。每以一字，温浆水一盏，和服探吐。（《经验方》） ②治中风不语，喉中如曳锯声，口中涎沫：藜芦一分，天南星一个（去浮皮，于脐子上陷一个坑子，纳入陈醋二橡斗子，四面用火逼令黄色）。同一处捣，再研极细，用生面为丸，如赤豆大，每服三丸，温酒下。（《经验后方》） ③治头痛不可忍：藜芦一茎，暴干，捣罗为散，入麝香麻子许，研匀吹鼻中。（《圣济总录》吹鼻麝香散） ④治头痛鼻塞脑闷：藜芦（研）半两，黄连（去须）三分。上二味，捣研为散，每用少许，搐入鼻中。（《圣济总录》通顶散） ⑤治黄疸：藜芦着灰中炮之，小变色，捣为末，水服半钱匕，小吐，不过数服。（《肘后方》） ⑥治老疟久不断者：藜芦、皂荚（炙）各一两，巴豆二十五枚（熬令黄）。依法捣，蜜丸如小豆。空心服一丸，未发时一丸，临发时又一丸，勿次食。（《补缺肘后方》） ⑦治久疟不能饮食，胸中郁郁如吐，欲吐不能吐者，宜吐，则已：大藜芦末半钱，温虀水调下，以吐为度。（《素问病机保命集》藜芦散） ⑧治诸瘑疮，经久则生虫：藜芦（去芦头）、白矾（烧灰细研）、松脂（细研）、雄黄（细研）、苦参各二两（锉）。上药，先捣藜芦、苦参为末，入猪脂一斤相和，煎十余沸，绵滤去滓，次入松脂、雄黄、白矾等末，搅令匀，待冷，收于瓷合中，旋取涂之，以瘥为度。（《圣惠方》藜芦散） ⑨治鼻中息肉渐大，气息不通：藜芦三分（去芦头，捣罗为末），雄黄一分（细研），雌黄一分（细研）。上药，同研令匀，每用时以蜜调敢，用纸拈子，展药，点于息肉上，每日三度，则自消化，不得涂药在于两畔，恐涕落于药上。（《圣惠方》） ⑩治牙疼：纳藜芦末于牙孔中，勿咽汁。（《千金翼方》） ⑾治白秃：末藜芦，以腊月猪膏和涂之，先用盐汤洗，乃敷。（《补缺肘后方》） ⑿治头生虮虱：藜芦末掺之。（《仁斋直指方》） ⒀治疥癣：藜芦，细捣为末，以生油调敷之。（《斗门方》） ⒁中风，牙关紧闭。用藜芦一两，去苗头，在浓煎的防风汤中泡过，焙干，切细，炒成微褐色，研为末。每服半钱，小儿减半。温水调药灌下。以吐风涎为效，末吐再服。 ⒂误吞水蛭。用藜芦炒过。研为末，水送服一钱将水蛭吐出。', tips='体虚气弱及孕妇忌服。 反细辛、芍药、五参，恶大黄。 ②《纲目》：畏葱白。服之吐不止，饮葱汤即止。 ③《本草从新》：服之令人烦闷吐逆，大损津液，虚者慎之。' where id=1911; -- 藜芦
update herbs set taste='苦；性微寒。', channel='入心、肝、胆经。', effect='①治太阴风温、温热、温疫、冬温，初起但热不恶寒而渴者：连翘一两，银花一两，苦桔梗六钱，薄荷六钱，竹叶四钱，生甘草五钱，芥穗四钱，淡豆豉五钱，牛蒡子六钱。上杵为散，每服六钱，鲜苇根汤煎，香气大出，即取服，勿过煮。病重者，约二时一服，日三服，夜一服；轻者三时一服，日三服，夜一服；病不解者，作再服。（《温病条辨》银翘散） ②治小儿一切热：连翘、防风、甘草（炙）、山栀子各等分。上捣罗为末，每服二钱，水一中盏，煎七分，去滓温服。（《类证活人书》连翘饮） ③治赤游癍毒：连翘一味，煎汤饮之。（《玉樵医令》） ④治乳痈，乳核：连翘、雄鼠屎、蒲公英、川贝母各二钱。水煎服。（《玉樵医令》） ⑤治瘰疬结核不消：连翘、鬼箭羽、瞿麦、甘草（炙）各等分。上为细末，每服二钱，临卧米泔水调下。（《杨氏家藏方》连翘散） ⑥治舌破生疮：连翘五钱，黄柏三钱，甘草二钱。水煎含漱。（《玉樵医令》）' where id=1912; -- 连翘
update herbs set taste='甘；微苦；性温。', channel='入肝、肾经。', effect='①治心腹胃脘久痛，屡触屡发者:荔枝核一钱，木香八分。为末。每服一钱，清汤调服。（《景岳全书》荔香散） ②治心痛及小肠气:荔枝核一枚。煅存性，酒调服。（《本草衍义》） ③治肾大如斗:舶上茴香、青皮（全者）、荔枝核等分。锉散，炒，出火毒，为末。酒下二钱，日三服。（《世医得效方》荔核散） ④治疝气颓肿:荔枝核四十九个，陈皮（连白）九钱，硫黄四钱。为末，盐水打面糊丸绿豆大。遇痛时，空心酒服九丸，良久再服，亦治诸气痛。（《坦仙皆效方》玉环来复丹） ⑤治血气刺痛:荔枝核（烧存性）半两，香附子一两。上为末。每服二钱，盐酒送下。（《妇人良方》蠲痛散）' where id=1913; -- 荔枝核
update herbs set taste='味苦；性寒。', channel='入肝、心、脾经。', effect='1.当归龙荟丸(《丹溪心法》)，治肝胆实火之眩晕，胁痛，惊悸，抽搐，谵语发狂，便秘溲赤。 2.芦荟消疳饮(《外科正宗》)，治小儿走马牙疳，身热气粗，牙龈腐烂，气味作臭，甚则穿腮破唇者。 3.芦荟肥儿丸(《医宗金鉴·幼科心法要诀》)，治小儿肝疳，面目爪甲皆青者，其人目生眵泪，隐涩难睁，腹大青筋，身体赢瘦，燥渴烦急，粪青如苔。 4.芦荟丸(《太平圣惠方》)，治小儿疳积，面目萎黄，头发成穗，鼻痒口干，脘腹虚胀，青筋暴露，四肢壮热。 5.芦荟丸(《普济方》)，治伤中，赤白带下。 6.芦荟丸(《外科正宗》)，治下疳溃烂作痛，又治妇人阴蚀疮作痒，及小儿肝积发热，口舌生疮，牙龈蚀烂。 7.芦荟散(《太平圣惠方》)，治小儿鼻疳，痒痛不止者。 8.芦荟散(《证治准绳》)，治口舌生疮。 9.更衣丸(《先醒斋医学广笔记》)，治肠胃燥热，大便不通。 10.治大便不通：臭芦荟（研细）七钱，朱砂（研如飞面）五钱。滴好酒和丸，每服三钱，酒吞。（《本草经疏》） 11.治小儿急惊风：芦荟、胆星、天竺黄、雄黄各一钱。共为末，甘草汤和丸，如弹子大。每遇此证，用灯芯汤化服一丸。（《本草切要》） 12.治大人小儿五种癫痫：芦荟三钱，生半夏一两（切碎，姜汁拌炒），白术一两（酒炒），甘草五钱（炒）。共为细末，水泛为丸，如黍米大。每服一钱五分，姜汤送下。（《本草切要》） 13.治小儿脾疳：芦荟、使君子。以上各等分，为细末。米饮调下一、二钱。（《儒门事亲》） 14.治五种臌胀：芦荟、蟾酥各三钱（酒一盏，浸一日，蒸化如膏）。以生半夏为末二两，巴霜三分，和丸如黍米大。每服十丸，淡姜汤早晚吞下。忌盐、糖百日。（《本草切要》） 15.治痔瘘胀痛、血水淋漓：芦荟数分，白酒磨化，和冰片二、三厘，调搽。（《本草切要》） 16.治匿齿：芦荟四分，杵末，先以盐揩齿令洗净，然后敷少末于上。（《海上集验方》）' where id=1914; -- 芦荟
update herbs set effect='①治久咳：铁筷子花三钱。泡开水服。(《贵阳民间药草》) ②治汤火伤：蜡梅花(以)茶油浸(涂)。(《岭南采药录》)' where id=1915; -- 蜡梅花
update herbs set alias='鹿茎筋，鹿鞭、鹿阴茎，鹿冲，鹿冲肾（《四', taste='甘咸，温。', effect='①治五劳七伤，阳气衰弱，益气力：鹿肾一对（去脂膜，细切），肉苁蓉二两（酒浸一宿，刮去皱皮，切），粳米二合。先以水二大盏，煮米作粥，欲熟，下鹿肾、苁蓉、葱白、盐、椒食之。（《圣惠方》鹿肾粥） ②治肾气损虚，耳聋：鹿肾一对（去脂膜，切），粳米二合。于豉汁中相和，煮作粥，入五味，如法调和，空腹食之；作羹及入酒并得，食之。（《圣惠方》鹿肾粥） ③治阳事不举：鹿肾、枸杞、菟丝子、巴戟、狗肾，为丸服。（《四川中药志》） ④治妇人血虚，淋带，腰膝酸痛，不能受孕者：鹿肾熬胶，与阿胶撺入服之。（《中国医学大辞典》）', tips='补肾，壮阳，益精。治劳损，腰膝酸痛，肾虚耳聋，耳鸣，阳痿，宫冷不孕。用于肾虚，性神经衰弱，遗精，滑精。 ①《别录》：主补肾气。 ②《千金·食治》：主劳损。 ③《日华子本草》：补中，安五藏，壮阳气，作酒及煮粥服。 ④《日用本草》：补腰脊。 ⑤《河北药材》：补肾益精，活血催乳。 ⑥《四川中药志》：治阳萎，肾虚耳呜，妇人子宫寒冷，久不受孕，慢性睾丸发炎。' where id=1916; -- 鹿肾
update herbs set taste='苦，寒。', channel='归心、肾经。', effect='①治太阴温病，发汗过多，神昏谵语者：元参心三钱，莲子心五分，竹叶卷心二钱，连翘心二钱，犀角尖二钱（磨，冲），连心麦冬三钱。水煎服。（《温病条辨》情宫汤） ②治劳心吐血：莲子心、糯米。上为细末，酒调服。（《百一选方》） ③治遗精：莲子心一撮，为末，八层砂一分。每服一钱，白汤下，日二。（《医林纂要》）', tips='清心火；平肝火，止血；固精。主神昏谵语；烦燥不眠；眩晕止赤；吐血；遗精。用于热入心包，神昏谵语，心肾不交，失眠遗精，血热吐血。 ①《食性本草》：生取为末，以米饮调下三钱，疗血渴疾、产后渴疾。 ②《日华子本草》：止霍乱。 ③《大明一练志》：清心去热。 ④《医林纂要》：泻心，坚肾。 ⑤《本革再新》：清心火，平肝火，泻脾火，降肺火。消暑除烦，生律止渴，治目红肿。 ⑥《随息居饮食谱》：敛液止汗，靖热养神，止血固精。' where id=1917; -- 莲子心
update herbs set taste='苦;辛;性微寒', channel='入肝、肾经。', effect='①治筋骨痛：络石藤一至二两。浸酒服。（《湖南药物志》） ②治关节炎：络石藤、五加根皮各一两，牛膝根五钱。水煎服，白酒引。 ③治肺结核：络石藤一两，地菍一两，猪肺四两。同炖，服汤食肺，每日一剂。 ④治吐血：络石藤叶一两，雪见草、乌韭各五钱。水煎服。（②方以下出《江西草药》） ⑤治肿疡毒气凝聚作痛：鬼系腰一两（洗净晒干），皂角刺一两（锉，新瓦上炒黄），瓜蒌大者一个（杵，炒，用仁），甘草节五分，没药、明乳香各三钱（另研）。上每服一两，水酒各半煎。溃后慎之。（《外科精要》止痛灵宝散） ⑥治喉痹咽塞，喘息不通，须臾欲绝：络石草二两。切，以水一大升半，煮取一大盏，去滓，细细吃。（《近效方》） ⑦治外伤出血：络石藤适量。晒干研末。撒敷，外加包扎。（《江西草药》）', tips='恶铁落，畏菖蒲、贝母。 ②《药性论》：恶铁精。杀殷孽毒。 ③《本草经疏》：阴脏人畏寒易泄者勿服。' where id=1918; -- 络石藤
update herbs set effect='⒈龙胆泻肝汤（《医方集解》）治肝胆实火上炎证，头痛目赤，胁痛口苦，耳聋，耳肿，舌红苔黄，脉弦数有力。肝经湿热下注证。阴肿，阴痒，筋萎阴汗，小便淋浊，或妇女带下黄臭等，舌红苔黄腻。龙胆草6g，黄芩9克，栀子9克，泽泻12克，木通9克，车前子9克，当归3克，生地黄9克，柴胡6克，生甘草6克。水煎服。亦可用丸剂，每服6～9克，日二次，温开水送下。方中龙胆草大苦大寒，泻火除湿，为君药。 ⒉龙胆散（《太平圣惠方》）治劳黄，额上汗出，手足中热，四肢烦疼，薄暮寒热，小便自利等证。龙胆草0.6克，麦冬、甘草、柴胡、麻、犀角各1克，牡蛎30克。上7味为散，水煎，入生地黄汁0.5合，温服。方中龙胆草配伍诸药有泻肝胆实火，除下焦湿热之功。 ⒊单味研末，煎汤服，或开水送服，治肝火上冲所致的鼻衄。' where id=1919; -- 龙胆草
update herbs set alias='青小豆', taste='味甘；性寒。', channel='入心、胃经。', effect='①解暑：绿豆淘净，下锅加水，大火一滚，取汤停冷色碧食之。如多滚则色浊，不堪食矣。（《遵生八笺》绿豆汤） ②治消渴，小便如常：绿豆二升，净淘，用水一斗，煮烂研细，澄滤取汁，早晚食前各服一小盏。（《圣济总录》绿豆汁） ③治十种水气：绿豆二合半，大附子一只（去皮、脐，切作两片）。水三碗，煮熟，空心卧时食豆，次日将附子两片作四片，再以绿豆二合半，如前煮食，第三日别以绿豆、附子如前煮食，第四日如第二日法煮食，水从小便下，肿自消，未消再服。忌生冷毒物盐酒六十日。（《朱氏集验医方》） ④治小便不通，淋沥：青小豆半升，冬麻子三合（捣碎，以水二升淘，绞取汁），陈橘皮一合（末）。上以冬麻子汁煮橘皮及豆令热食之。（《圣惠方》） ⑤治赤痢经年不愈：绿豆角蒸熟，随意食之。 ⑥治小儿遍身火丹并赤游肿：绿豆、大黄。为末，薄荷蜜水调涂。 ⑦治痈疽：赤小豆、绿豆、黑豆、川姜黄。上为细末，未发起，姜汁和井华水调敷；已发起，蜜水调敷。（⑤方以下出《普济方》） ⑧治金石丹火药毒，并酒毒，烟毒、煤毒为病：绿豆一升，生捣末，豆腐浆二碗，调服。一时无豆腐浆，用糯米泔顿温亦可。（《本草汇言》） ⑨解乌头毒：绿豆四两，生甘草二两，煎服。（《上海常用中草药》）', usage='', tips='1. 孟诜：今人食绿豆皆挞去皮，即有少壅气，若愈病须和皮，放不可去。 2.《本草拾遗》：反榧子壳，害人。 3.《本草经疏》：脾胃虚寒滑泄者忌之。 1. 孟诜：今人食绿豆皆挞去皮，即有少壅气，若愈病须和皮，放不可去。 2.《本草拾遗》：反榧子壳，害人。 3.《本草经疏》：脾胃虚寒滑泄者忌之。' where id=1920; -- 绿豆
update herbs set taste='味咸；性温。', channel='入肝、肾经。', effect='①治奶发，诸痈疽发背：烧鹿角，捣末，以苦酒和涂之。（《补缺肘后方》） ②治下注脚疮：鹿角，烧存性，入轻粉同研，油调涂之。（《医林集要》） ③治妊娠忽下血，腰痛不可忍：鹿角（锉）一两，当归（锉）一两。上二味作一服，以水二盏，煎至一盏，去滓，温服，食前。（《洪氏集验方》） ④治产后下血不尽，烦闷腹痛：鹿角，烧成炭，捣筛，煮豉汁，服方寸匕，日三夜再，稍加至二匕。不能用豉清，煮水作汤用之。（《千金方》） ⑤治胞衣不下：鹿角屑三分。为末，姜汤调下。（《产乳集验方》） ⑥治腰痛：鹿角屑，熬令黄赤，研，酒服方寸匕，日五、六服。（《产乳集验方》） ⑦治筋骨疼痛：鹿角，烧存性，为末，酒服一钱，日二。（《纲目》） ⑧治骨虚极，面肿垢黑，脊痛不能久立，气衰发落齿槁，腰脊痛，甚则喜唾：鹿角二两，川牛膝（去芦，酒浸，焙）一两半。上为细末，炼蜜为丸，如梧桐子大。每服七十丸，空心盐汤送下。（《济生方》鹿角丸） ⑨治妇人白浊，滑数虚冷者：鹿角屑，炒黄，为末，酒服二钱。（《妇人良方》） ⑩治消中，日夜尿七八升：鹿角，炙令焦，末，以酒服五分匕，日二，渐加至方寸匕。（《千金方》） ⑾治溺血久不止，脉细数者：鹿角八两（烧灰），秋石一两（煅灰）。共为末，蜜丸，乌梅汤下三钱。（《医略六书》鹿角秋石丸）', tips='阴虚阳亢者忌服。 ②《本草经疏》：无瘀血停留者不得服，阳盛阴虚者忌之，胃火齿痛亦不宜服。 ③《得配本草》：命门火炽，疮毒宜凉者，并禁用。' where id=1921; -- 鹿角
update herbs set taste='酸，热，有毒。', channel='入肾、脾经。', effect='①治男子腰肾久冷，心腹积聚，胁下冷癣，腹中诸虫，失精遗溺，形羸力劣，脚膝疼弱，冷风顽痹，霍乱转筋，虚滑下利；又治妇人血结寒热，阴蚀疽痔：硫黄十两。净拣去沙石，研细飞过，用瓷盒子盛，以水和赤石脂封口，以盐泥固济晒干，地内先埋一小罐子，盛水令满，安合子在上，用泥固济讫，慢火养七日七夜，侯足，加顶火一斤煅，侯冷取出，研为细末，以药末一两，用蒸饼一两，汤浸握去水，搜为丸，如梧桐子大。每服三十丸，多至百丸，温米饮下，空心服之。（《局方》金液丹） ②治阴毒面色青，四肢逆冷，心躁腹痛：硫黄末，新汲水调下二钱，良久，或寒一起，或热一起，更看紧慢，再服，汗出差。（《本事方》还阳散） ③治脾虚下白，脾胃虚冷，停水滞气，凝成白涕下出：舶上硫黄一两（研末），炒面一分。同研，滴冷热水丸梧子大。每米汤下五十丸。（《杨氏护命方》） ④治水泻不止，伤冷虚极：硫黄一两。研细，先熔黄蜡，入硫黄末打匀，丸如梧桐子大，每履五丸，新汲水下，（《圣济总录》黄蜡丸） ⑤治心腹一切痃癖冷气，及年高风秘、冷秘或泄泻等：硫黄（明净好者，研令极细，用柳木槌子杀过）、半夏（汤浸七次，焙干，为细末）。上等分，以生姜自然汁同熬，入干蒸讲末搅和匀，入臼内杵数百下，丸如梧桐子大。每服空心温酒或生姜汤下十五丸至廿丸，妇人醋汤下。（《局方》半硫丸） ⑥治胃气，冷痛尤效：元胡索、胡椒、五灵脂、白豆蔻各五钱，硫黄一两，木香（切片、晒干）二钱五分。研细末，拌匀收贮，体壮者服一分，弱者八厘，老人幼童五厘，取温烧酒半小盅调服，待次日，吃稀米汤，至五日后方可吃干饭。孕妇忌服。（《经验广集》剪根丸） ⑦治卒得疥疮：麻油摩硫黄涂之。（《肘后方》） ⑧治一切干湿癣：石硫黄半钱，风化石灰半两，铅丹二钱，腻粉一钱。同研如粉，用生油调，先以布揩破癣涂之。未涂药间，煎葱白、甘草汤淋洗，如换时亦依此。（《圣济总录》如圣散） ⑨治慢性湿疹，神经性皮炎：硫黄一两，银珠一钱，陈醋半斤。将硫黄放在铁勺内熔化后，放入银珠拌匀，在地上挖个二至三寸深的坑，将醋和溶化的硫黄液先后倒在坑内，等凝固后取出再熔化，如此处理三次，捣细粉，用植物油调匀，以布包药搽患处，一日两次。（内蒙古《中草药新医疗法资料选编》） ⑩治疠风：硫黄末，酒调少许，饮汁，或加大枫子油更好。（《仁斋直指方》） ⑾治疬疡风病，白色成片：以布拭醋，磨硫黄、附子涂之，或硫黄、白矾擦之。（《姚僧坦集验方》） ⑿治阴生湿疱疮：石硫黄，研如粉，敷疮上，日三度。（《梅师集验方》） ⒀治小儿聤耳：末石碱黄，以粉耳中，日一夜一。（《千金方》） ⑾治咳逆打呃：硫黄，烧烟熏之。（《医方摘要》） ⑿治酒皶赤鼻：舶上硫黄、鸡心槟榔等分，片脑少许。为末，绢包，日日擦之，加蓖麻油更妙。（《瑞竹堂经验方》） ⒀治耳聋：硫黄、雄黄各等分。为末，绵裹纳耳中。（《千金方》） ⒁治烫伤，烧伤，能止痛，抗感染，保护创面，促进愈合：硫黄，烧酒。将硫黄粉碎放入磁器内（不可用金属容器），兑入烧酒，以没过硫黄为度。把酒点着烧成炭灰色。因酒含有水分，如烧后还余水分，可用慢火将硫磺烤干，然后研面，用时撒于患部。如有水泡，将水泡挑破再上药粉。（辽宁省《中草药新医疗法资料选编》）' where id=1922; -- 硫黄
update herbs set taste='甘、微苦，微寒。', channel='归肺、脾、肝经。', effect='①治白带初起：土人参（切片）三两，用陈绍酒饭上蒸熟，分作三服。（《百草镜》） ②补阴虚：土人参、对配茯苓。熬膏。（王安卿《采药志》） ③治杨梅结毒：土人参，酒煎服。（王安卿《采药志》）' where id=1923; -- 明党参
update herbs set taste='酸，温。', channel='入肝、脾经。', effect='①治吐泻转筋：㈠木瓜一枚（大者，四破），陈仓米一合。上件药，以水二大盏，煎至一盏半，去滓，时时温一合服之。（《圣惠方》）㈡木瓜汁一盏，木香末一钱匕。上二味，以热酒调下，不拘时。（《圣济总录》）㈢木瓜干一两，吴茱萸半两（汤七次），茴香一分，甘草（炙）一钱。上锉为散，每服四大钱，水一盏半，姜三片，紫苏十叶，煎七分，去滓，食前服。（《三因方》木瓜汤） ②止吐：木瓜（末）、麝香、腻粉，木香（末）、槟榔（末），各一字。上同研，面糊丸，如小黄米大，每服一二丸，甘草水下，无时服。（《小儿药证直诀》木瓜丸） ③治泻不止：米豆子二两，木瓜、干姜、甘草各一两。为细末，每服二钱，米饮调，不以时。（《鸡峰普济方》木瓜汤） ④治风湿客搏，手足腰膝不能举动：木瓜一枚，青盐半两。上用木瓜去皮脐，开窍填吴茱萸一两，去枝，将线系定，蒸热细研，入青盐半两，研令匀，丸梧桐子大，每服四十丸，茶酒任下，以牛膝浸酒服之尤佳。食前。（《杨氏家藏方》水瓜丸） ⑤治腰痛，补益壮筋骨：牛膝二两（温酒浸，切，焙），木瓜一枚（去顶、穰，入艾叶一两蒸熟），巴戟（去心）、茴香（炒）、木香各一两，桂心半两（去皮）。上为细末，入熟木瓜并艾叶同杵千下，如硬，更下蜜，丸如梧子大，每服二十丸，空心盐汤下。（《御药院方》木瓜丸） ⑥治脚膝筋急痛：煮木瓜令烂，研作浆粥样，用裹痛处，冷即易，一宿三、五度，热裹便差。煮木瓜时，入一半酒同煮之。（《食疗本草》） ⑦治筋急项强，不可转侧：宣州木瓜二个（取盖去穰），没药二两（研），乳香一两（研）。上二味纳木瓜中，用盖子合了，竹签定之，饭上蒸三、四次，烂，研成膏子，每服三、五匙，地黄酒化下（生地黄汁半盏，无灰上酝二盏和之，用八分一盏，热暖化膏）。（《本事方》水瓜煎） ⑧治一切脚气，腿膝疼痛：花木瓜一个（切下顶作盖，去穰），附子一只，炮去皮，晒，为细末。上将附子末安在木瓜内，再以熟艾实之，将顶盖之，用竹签签定，复以麻线缚之。用米醋不拘多少，于瓷器内煮烂，石器中烂研为膏，即用二、三只碗，以匙摊于碗内，自看厚薄得所，连碗覆于焙笼上慢火焙，时时以手摸，如不沾手，以匙抄转依前摊开，勿令面上焦干，恐成块子，如此数次，看干湿得所，方可为丸，空心用温酒送下三、五十丸。（《魏氏家藏方》木瓜丸） ⑨治干脚气，痛不可忍者：干木瓜一个，明矾-两，煎水，乘热熏洗，（《奇效良方》） ⑩治湿脚气，上攻心胸，壅闷痰逆：木瓜一两（干者），陈橘皮一两（汤浸，去白瓤，焙），人参一两（去芦头），桂心半两，丁香半两，槟榔二两。上件药，捣罗为末，炼蜜和捣三、二百杵，丸如梧桐子大，每服不计时候，以生姜汤下三十丸。（《圣惠力》木瓜丸） ⑾治脚气疼痛，不问男女皆可服。如人感风湿流注，脚足痛不可忍，筋脉浮肿，宜服之：槟榔七枚，陈皮（去白）、本瓜各一两，吴茱萸、紫苏叶各三钱，桔梗（去芦）、生姜（和皮）各半两。上细切，只作一遍煎，用水三大碗，慢火煎至一碗半，去渣，再入水二碗煎渣，取一小碗，两次药汁相和，安置床头，次日五更，分作三、五服，只是冷服，冬月略温服亦得。（《证治准绳》鸡鸣散） ⑿治脚气冲心，胸膈痞滞，烦闷：大腹皮一枚，紫苏一分，干木瓜一分，甘草一分（炙），木香一分，羌活一分。细锉为饮子，分作三服。每服，用水一升煎至三分，通口服之。（《传冢秘宝方》木瓜散） ⒀治赤白痢：本瓜、车前子、罂粟壳各等分。上为细末，每服二钱，米饮调下。（《昔济方》木瓜散） ⒁治脐下绞痛：木瓜一、二片，桑叶七片，大枣三枚，（碎之）。以水二升，煮取半升，顿服之。（《孟诜方》） ⒂治积年气块，脐腹疼痛：木瓜一两（三枚），硇砂二两（以醋一盏，化去夹石）。上件木瓜切开头，去瓤子，纳硇砂，醋入其间，却以瓷碗盛，于日中晒，以木瓜烂为度，却研。更用米醋五升，煎上件药如稀汤，以一瓷瓶子盛，密盖，要时旋以附子末和丸，如弹子大，每服，以热酒化一丸服之。（《圣惠方》木瓜丸） ⑩治荨麻疹：木瓜六钱，水煎，分二次服，每日一剂。（内蒙古《中草药新医疗法资料选编》）' where id=1924; -- 木瓜
update herbs set taste='味苦；微酸涩；性凉。', channel='归心；肝经。', effect='治崩中，赤白带下：墓头回一把，酒水各半盏，新红花一捻，煎七分，卧时温服。日近者一服，久则三服。（《董炳集验方》）', tips='燥湿止带；收敛止血；清热解毒。主赤白带下；崩漏；泄泻痢疾；黄疸；疟疾；肠痈；疮疡肿毒；跌打损伤；子宫颈癌；胃癌。用于子宫糜烂，早期宫颈癌，白带，崩漏，疟疾。 ①《本草原始》：治伤寒，温疟。 ②《河南中药手册》：洗脚，治脚痛。 ③《山西中药志》：敛肝燥湿，止血。治妇人髋疽，赤白带下。 ④《广西中药志》：祛瘀，消肿。治跌打。' where id=1925; -- 墓头回
update herbs set taste='苦，性寒，有毒。', effect='①治喉痹作痛：番木鳖，青木香、山豆根等分。为末吹。（《医方摘要》） ②治缠喉风肿：番木鳖仁一个，木香三分。同磨水，调熊胆三分，胆矾五分，以鸡毛扫患处。（《唐瑶经验方》） ③治痈疽初起，跌扑内伤，风痹疼痛：番木鳖（入砂锅内，黄土拌炒焦黄为度，石臼中捣磨，筛去皮毛，拣净末）、山芝麻（去壳，酒炒）、乳香末（箬叶烘出汗）各五钱，穿山甲（黄土炒脆）一两。共研末。每服一钱，酒下，不可多服，服后避风，否则令人发战栗不止，如人虚弱，每服五分。（《救生苦海》马前散） ④治中耳炎：㈠番木鳖一个，以井水磨汁滴耳内。（《光华医学杂志》11：38，1933）㈡马钱子五钱，焙黄去毛皮，然后用胡麻油一两煎之，至漂起为度，去马钱子，留油备用。治疗时先洗去脓垢，然后漓入药油两滴。一日二次。（内蒙古《中草药新医疗法资料选编》） ⑤治脚气，手足麻痹，半身不遂，小便不禁或自遗：番木鳖（去皮，磨细粉）六分，甘草（细粉）六分。炼蜜为丸40粒，每日三次，每次1～2粒，食后温水送服，连服七日，停七日再服。（《现代实用中药》） ⑥治骨折：马钱子、枳壳。每斤生马钱子加甘草一两，同置缸内用冷水浸泡，每日换水一次，16天后将马钱子毛刮净，切片晒干，用细砂炒成黄色，再浸在童便中（冬季2～3周，夏季4～5天），然后用流水冲洗一天半，阴干碾细。枳壳（生熟皆可），用童便浸泡2～3天，取出用水洗净，阴干碾细。将马钱子粉与枳壳粉按1：2混合即可，也可制为蜜丸。成人日服三次，每次2克，极量一日8克。儿童酌减。同时进行断骨复位，小夹板固定。孕妇、高血压、高烧及精神病人慎用。服药量大时，出现肌肉抽搐，患处跳动感，头晕，可大量饮水（或甘草水）解之。（《全展选编·外科》） ⑦治热牙痛不可忍：番木鳖半个，井花水磨一小盏，含漱，热即吐去，水完则疼止。（《握灵本草》） ⑧治癍疮入目：苦实把豆儿半个，轻粉、水花银朱各五分，片脑、麝香、枯矾少许。为末，左目吹右耳，右目吹左耳，日二次。（《飞鸿集》） ⑨治狂犬病：马前子一粒，酒磨成粉末，开水吞服。（《贵州省中医验方秘方》） ⑩治腰痛，闪腰岔气：马钱子（水浸去毛，切片晾干，油炸成酱色）。为细末，面糊为丸，绿豆大，朱砂为衣，每服0.3-0.6g，每日2次，用杜仲3g，煎水送下。（《正骨经验汇萃》舒筋丸） ⑾治坐骨神经痛、风湿病肌肉、关节痉挛疼痛，半身不遂，肌肉瘫痪，疮疡，外伤肿痛：马钱子1份，穿山甲、僵蚕10份。每次2.4克，每日2次。（《药物与方剂》马钱子散）' where id=1926; -- 马钱子
update herbs set alias='金丝黄连马尾黄连，，草黄连。', taste='味苦；性寒。', channel='归心；肝；大肠经。', effect='①治小儿伤风发热及麻疹将出：马尾黄连、蝉蜕、菊花、大力子、防风、薄荷、甘草，煎汤服。（《四川中药志》） ③治痢疾，肠炎：马尾黄连九钱，木香三钱。共为细末。每次一至二钱，一日三次服。（《新疆中草药手册》） ③治湿热呕吐：马尾连一钱半，吴茱萸四分，煎服。（《青海常用中草药手册》） ④治热病烦渴：马尾连、焦山栀各三钱，煎服。（《青海常用中草药手册》） ⑤治口舌生疮，结膜炎，扁桃体炎：马尾黄连三钱，黄芩二钱，刺黄柏三钱，栀子三钱，牛蒡子二钱，连翘五钱，甘草二钱。水煎服。（《新疆中草药手册》） ⑥治红肿疮痈：马尾黄连二钱，水煎服及研末外撒或制成软膏外用。（《云南中草药》） ⑦治渗出性皮炎：马尾黄连适量，焙干研末，撒患处。或与松花粉各等分同用。如撒后患处于燥起裂，可用香油调敷。（《新疆中草药手册》） ⑧治脚癣：马尾黄连五钱，黄柏一两，新鲜猪胆汁一个，冰片三分。先将马尾黄连、黄柏水煎成糊状，去渣，再下猪胆汁，微火煎1～2分钟，离火，待温加冰片搅匀，每晚擦患处。（《新疆中草药手册》）' where id=1927; -- 马尾连
update herbs set effect='对痈肿疔毒、瘰历结核，内服、外敷，均可应用。用于食道癌，常与急性子、制半夏、地鳖虫、石见穿等配合应用；用于淋巴肿瘤，常与昆布、海藻、夏枯草、象贝等配合应用。', usage='', tips='《四川常用中草药》：“本品较地胆毒性大，多外用。” 《四川常用中草药》：“本品较地胆毒性大，多外用。”' where id=1928; -- 毛慈菇
update herbs set taste='甘苦；平；无毒。', channel='入肺、肝、胆经。', effect='①治目障昏矇多泪：木贼草（去节）一两，为末，和羊肝捣为丸，早晚各食后服二钱，白汤下。（《方脉正宗》） ②治目昏多泪：木贼（去节），苍术（泔浸）各一两。为末，每服二钱，茶凋下，或蜜丸亦可。（《圣惠方》） ③治风寒湿邪，欲发汗者：木贼草（去节）一两，生姜、葱白各五钱。水煎热饮，即汗。（《圣惠方》） ④治肠风下血：木贼（去节，炒）一两，木馒（炒）、枳壳（制）、槐角（炒）、茯苓、荆芥各五钱。上为末，每服二钱，浓煎枣汤调下。（《仁斋直指方》木贼散） ⑤治血痢不止：木贼五钱，水煎温服。一日一服。（《圣惠方》） ⑥治脱肛历年不愈：木贼不以多少，烧存性，为末，掺肛门上，按之。（《三因方》） ⑦治月水不断：木贼（炒）三钱，水一盏煎七分，温服。日一服。（《圣惠方》） ⑧治外伤出血，消化道出血，妇科出血及其它出血：木贼50％，黄柏20％，益母草20％，五倍子10％。分别研末，过120目筛，混匀。外用：将药粉撒布创面，用纱布压迫。内服；每次二克，每四至六小时一次。（内蒙古《中草药新医疗法资料选编》） ⑨治胎动不安：木贼（去节）、川芎等分。为末，每服三钱，水一盏，入金银花一钱煎服。（《圣济总录》） ⑩治咽喉红痛：鲜木贼草捣绞汁调蜜服。（《泉州本草》） ⑾治浮肿型脚气、皮肤病性肾炎、水肿：木贼草四钱五分，浮萍三钱，赤豆三两，红枣六枚。水煎，一日三次分服。（《现代实用中药》） ⑿治舌硬出血：木贼煎水，漱之。（《圣惠方》） ⒀目昏多泪：用木贼（去节）、苍术（淘米水泡过）各一两，共研为末。每服二钱，茶调下。或加蜜做成丸子吞服亦可。 ⒁急喉痹塞：用木贼在牛粪火上烧存性，每服一钱，冷水送下，血出即安。 ⒂血痢不止：用木贼五钱，水煎，温服。一天服一次。 ⒃泻血不止：方同上，一天服二次。 ⒄肠痔下血：用木贼、枳壳各二两，干姜一两，大黄二钱半，一起在锅内炒黑存性，研细。每服二钱，粟米汤送下。甚效。 ⒅大肠脱肛：用木贼（烧存性）研为末，敷肛部，并把它托入体内。药中加龙骨亦可。 ⒆妇女血崩：用木贼、香附子各一两，朴硝半两，共研为末。每服三钱，血色黑者用酒一碗煎，血色赤者用水一碗煎，连渣服下。一天服二次。脐下痛者，加乳香、没药、当归各一钱同煎。忌食生冷硬物及猪、鱼、面等。此方名雷氏木贼散。 ⒇月经不净：用木贼（炒）三钱，加水一碗煎至七成，温服，每天服一次。 (21)胎动不安：用木贼（去节）、川芎，等分为末。每服三钱，水一碗，加金银一钱煎服。 (22)小肠疝气：用木贼锉细，微炒为末。沸汤送服二钱，有效。以热酒送下亦可。 (23)治目赤医翳：木贼、蝉蜕、谷精草、甘草、苍术、蛇蜕、黄芩。水煎服。方中木贼疏风热、退目翳，为君药。（《证治准绳》木贼散） (24)治肠风下血：木贼（去节，炒）30g，木馍（炒），枳壳（制）、槐角（炒）、茯苓、荆芥各15g，上为末，每服6g，浓煎枣汤调下。方中木贼疏风热，为君药。（《仁斋直指方》木贼散） (25)治胎动不安：木贼（去节）、川芎等分。为末、每服9g，水1盏，入金银花3g煎服。方中木贼疏风热，为君药。（《圣济总录》）' where id=1929; -- 木贼
update herbs set effect='①治肺热喘咳：乌尾丁根五钱。水煎，冲白糖适量，分三次服。（《广西中草药》） ②治感冒，扁桃体炎，痢疾：毛冬青根五钱至一两。水煎服。（《浙江民间常用草药》） ③治血栓闭塞性脉管炎：毛冬青根三两，煨猪脚一只服食，每日一次；另取-毛冬青根三两，煎水浸泡伤口，每日一至二次，浸泡后外敷生肌膏（硼酸粉6725克，氧化锌16克，黄丹2.17克，梅片2.5克，石炭酸3毫升，凡士林375克）。（《浙江民间常用草药》） ④治刀枪伤及跌打肿痛：乌尾丁根适量。水煎，待冷，每日涂3～6次。（《广西中草药》）' where id=1930; -- 毛冬青
update herbs set taste='味甘；微苦；温；无毒。', channel='归肝、脾经。', effect='①治肝胃气痛：玫瑰花阴干，冲汤代茶服。（《纲目拾遗》） ②治肝郁吐血，月汛不调：玫瑰花蕊三百朵，初开者，去心蒂；新汲水砂铫内煎取浓汁，滤去渣，再煎，白冰糖一斤收膏，早晚开水冲服。瓷瓶密收，切勿泄气。如专调经，可用红糖收膏。（《饲鹤亭集方》玫瑰膏） ③治肺病咳嗽吐血：鲜玫瑰花捣汁炖冰糖服。（《泉州本草》） ④治新久风痹：玫瑰花（去净蕊蒂，阴干）三钱，红花、全当归各一钱。水煎去滓，好酒和服七剂。（《百草镜》） ⑤治肝风头痛：玫瑰花四至五朵，合蚕豆花三至四钱，泡开水代茶频饮。（《泉州本草》） ⑥治噤口痢：玫瑰花阴干煎服。（《纲目拾遗》） ⑦治乳痈初起，郁症宜此：玫瑰花初开者，阴干、燥者三十朵。去心蒂，陈酒煎，食后服。（《百草镜》） ⑧治乳痈：玫瑰花七朵，母丁香七粒。无灰酒煎服。（《纲目拾遗》） ⑨治肿毒初起：玫瑰花去心蒂，焙为末一钱。好酒和服。（《百草镜》） ⑩治肝郁胁痛、胃脘部书：玫瑰花、香附、川楝子、白芍各等分。水煎，分2次服。方中玫瑰花舒肝理气，止胸胁痛，为君药。（《全国中草药》玫瑰节瘀汤）' where id=1931; -- 玫瑰花
update herbs set taste='甘，微温。', channel='入脾、胃经。', effect='①快膈进食：麦芽四两，神曲二两，白术、橘皮各一两。为末，蒸饼丸梧子大。每人参汤下三、五十丸。（《纲目》） ②治产后腹中鼓胀，不通转，气急，坐卧不安：麦蘖一合，末，和酒服食，良久通转。（《兵部手集方》） ③治饱食便卧，得谷劳病，令人四肢烦重，嘿嘿欲卧，食毕辄甚：大麦蘖一升，椒一两（并熬），干姜三两。捣末，每服方寸匕，日三、四服。（《补缺肘后方》） ④治产后发热，乳汁不通及膨，无子当消者：麦蘖二两，炒，研细末。清汤调下，作四服。（《丹溪心法》）', tips='授乳期妇女不宜使用。 ①《食性本草》：久食消肾，不可多食。 ③《本草经琉》：无积滞，脾胃虚者不宜甩。’ ④《本草正》：妇有胎妊者不宜多服。 ⑤《药品化义》：凡痰火哮喘及孕妇，切不可用。 ⑥《别录》：“消食和中。”。 ⑦《本草纲目》：“消化一切米面诸果食积。”' where id=1932; -- 麦芽
update herbs set taste='味微苦；甘；性微寒。', channel='入肺、肝经。', effect='①治急性气管炎、百日咳等：木蝴蝶一钱，安南子三钱，桔梗一钱五分，甘草一钱，桑白皮三钱，款冬花三钱。水煎，加冰糖三两，溶化于药液，制成糖浆，一日数回，频频服之。（《现代实用中药》止咳糖浆） ②治肝气痛：木蝴蝶二、三十张，铜铫上焙燥研细，好酒调服。（《纲目拾遗》）', tips='利咽润肺；疏肝和胃；敛疮生肌。主咽痛喉痹；声音嘶哑；咳嗽；肝胃气痛；疮疡久溃不敛；浸淫疮。用于急性咽喉炎，声音嘶哑，支气管炎，百日咳，胃痛。 ①《云南通志》：焚为灰，可治心气痛。 ②《滇南本草》：定喘，消痰，破蛊积，除血蛊、气蛊之毒。又能补虚，宽中，进食。 ③《纲目拾遗》：治心气痛，肝气痛，下部湿热。又项秋子云，凡痈毒不收口，以此贴之。 ④《岭南采药录》：消痰火，除眼热。 ⑤《现代实用中药》：镇咳，治百日咳及干性气管炎。 ⑥《药材资料汇编》：治咽喉失音。 ⑦广州部队《常用中草药手册》：清肺热，利咽喉。治急慢性支气管炎，肺结核咳嗽，咽喉肿痛，扁桃体炎。' where id=1933; -- 木蝴蝶
update herbs set taste='甘辛；温；平。', channel='归肝、肺经。', effect='①治瘰疬：㈠猫爪草、夏枯草各适量。水煮，过滤取汁，再熬成膏，贴患处。㈡猫爪草四两。加水煮沸后，改用文火煎半小时，过滤取汁，加黄酒或江米甜酒（忌用白酒）为引，分四次服。第二天，用上法将原药再煎，不加黄酒服。二日一剂，连服四剂。间隔三至五天再续服。（《河南中草药手册》） ②治肺结核：猫爪草二两。水煎，分二次服。（《河南中草药手册》）', tips='解毒；化痰散结。主主治瘰疬；结核；咽炎；疔疮；蛇咬伤；疟疾；偏头痛；牙痛。用于瘰疬未溃、淋巴结结核。 ①《中药材手册》：治颈上瘰疬结核。 ②《河南中草药手册》：消肿，截疟。治瘰疬，肺结核。' where id=1934; -- 猫爪草
update herbs set taste='味甘；酸；性凉。', channel='入肝、肾经，', effect='①治吐血成盆：旱莲草和童便、徽墨春汁，藕节汤开服。（《生草药性备要》） ②治吐血：鲜早莲草四两。捣烂冲童便服；或加生柏叶共同用尤效。（《岭南采药录》） ③治咳嗽咯血：鲜旱莲草二两。捣绞汁，开水冲服。（《江西民间草药验方》） ④治鼻衄：鲜旱莲草一握。洗净后捣烂绞汁，每次取五酒杯炖热，饭后温服，日服两次。（《福建民间草药》） ⑤治小便溺血：车前草叶、金陵草叶。上二味，捣取自然汁一盏，空腹饮之。（《医学正传》） ⑥治肠风脏毒，下血不止：旱莲草子，瓦上焙，研末。每服二钱，米饮下。（《家藏经验方》） ⑦治热痢：旱莲草一两。水煎服。（《湖南药物志》） ⑧治刀伤出血：鲜旱莲草捣烂，敷伤处；干者研末，撒伤处。（《湖南药物志》） ⑨补腰膝，壮筋骨，强肾阴，乌髭发：冬青子（即女贞实，冬至日采）不拘多少，阴干，蜜、酒拌蒸，过一夜，粗袋擦去皮，晒干为末，瓦瓶收贮，旱莲草（夏至日采）不拘多少，捣汁熬膏，和前药为丸。临卧洒服。（《医方集解》二至丸） ⑩治正偏头痛：鳢肠汁滴鼻中。（《圣济总录》） ⑾治赤白带下：旱莲草一两。同鸡汤或肉汤煎服。（《江西民间草药验方》） ⑿治白浊：旱莲草五钱，车前子三钱，银花五钱，土茯苓五钱。水煎服。（《陆川本草》） ⒀治妇女阴道痒：墨斗草四两。煎水服；或另加钩藤根少许，并煎汁，加白矾少许外洗。（《重庆草药》） ⒁治肾虚齿疼：旱莲草，焙，为末，搽齿龈上。（《滇南本草》） ⒂治血淋：旱莲、芭蕉根（细锉）各二两。上二味，粗捣筛。每服五钱匕。水一盏半，煎至八分，去滓，温服，日二服。（《圣济总录》旱莲子汤） ⒃治白喉：旱莲草二至三两，捣烂，加盐少许，冲开水去渣服。服后吐出涎沫。（《岭南草药志》）' where id=1935; -- 墨旱莲
update herbs set taste='甘，平。', channel='入胃、大肠经。', effect='①治新久泄利：干木耳一两（炒），鹿角胶二钱半（炒）。为末，每服三钱，温酒调下，日二。（《御药院方》） ②治血痢日夜不止，腹中疴痛，心神麻闷：黑木耳一两，水二大盏，煮木耳令熟，先以盐、醋食木耳尽，后服其汁，日二服。（《圣惠方》） ③治崩中漏下：木耳半斤，炒见烟，为末。每服二钱一分，头发灰三分，共二钱四分，好酒调服出汗。（《孙天仁集效方》） ④治眼流冷泪：木耳一两（烧存性），木贼一两。为末。每服二钱。以清米泔煎服。（《惠济方》） ⑤治一切牙痛：木耳、荆芥等分。煎汤漱之，痛止为度。（《海上方》） ⑥用于创面肉芽过剩：取平柔、肥厚而无缺损的木耳，用温开水浸透涨大后，酒精消毒。伤口周围及肉芽用盐水清洗消毒后，将木耳平贴于肉芽上，纱布包扎，3～4天拆开观察1次。治疗2例，均于3天后痊愈。木耳疏松易收缩，吸水性强，能将肉芽中的水份大量吸收，使肉芽开始干萎；加之木耳干燥后，收缩皱凸，给与肉芽均匀压力，使肉芽过剩部分退平，上皮细胞随着向中心生长，伤口易于愈合。' where id=1936; -- 木耳
update herbs set taste='甘；苦；性微寒。', channel='入大肠、肝、脾经。', effect='①治大肠脱肛：槿皮或叶煎汤熏洗，后以白矾、五倍末敷之。（《救急方》） ②治赤白带下：槿根皮二两，切，以白酒一碗半，煎一碗，空心服之。（《纂要奇方》） ③治头面钱癣：槿树皮为末，醋调，重汤炖如胶，敷之。（《王仲勉经验方》）。 ④治牛皮癣：川槿皮一两，半夏五钱，大枫子仁十五个。上锉片，河、井水各一碗，浸露七宿，取加轻粉一钱，任水中，以秃笔蘸涂疮上，覆以青衣，夏月治尤妙。但忌浴数日，水有臭涎更效。（《扶寿精方》） ⑤治牛皮癣癞：川槿皮一斤，勿见火，晒燥磨末，以好烧酒十斤，加榆面四两，浸七日为度，不时蘸酒搽擦。二、三十年者，搽一年断根。如无川槿，土槿亦可代之。（《养生经验合集》） ⑥治癣疮：川槿皮煎，入肥皂浸水，频频擦之；或以槿皮浸汁磨雄黄（擦之）。（《简便单方》）' where id=1937; -- 木槿皮
update herbs set alias='蔓荆实，荆子，万荆子，蔓青子。', taste='味辛；苦；性微寒', effect='①治头风：蔓荆子二升（末），酒一斗。绢袋盛.浸七宿，温服三合，日三。（《千金方》） ②治风寒侵目，肿痛出泪，涩胀羞明：蔓荆子三钱，荆芥、白蒺藜各二钱，柴胡、防风各一钱，甘草五分。水煎服。（《本草汇言》） ③治劳役饮食不节，内障眼病：黄芪、人参各一两，炙甘草八钱，蔓荆子二钱半，黄柏三钱（酒拌炒四遍），白芍药三钱。上嚼咀，每服三、五钱，水煎。（《兰室秘藏》蔓荆子汤） ④治风头旋运，闷气则欲倒：蔓荆、甘菊花、半夏（汤泡）羚羊角（屑）、川芎、枳壳（麸炒）、茯神（去木）、黄芩、防风各23g，麦冬、石膏各30g，地骨皮、赤箭、细辛、甘草（炙）各15g。每服9g，水1盏，生姜15g，煎至六分，去渣，不拘时温服，忌热面饴糖羊肉。方中蔓荆子配伍川芎治头痛、身痛。（《医部全录·头门》蔓荆子散） ⑤治头风白屑痒，发落生发，主头肿旋闷：蔓荆子6g，生附子30枚，羊踯躅花120g，葶苈子120g，零陵香60g，莲子草1握。上六味切，以绵裹，用油2升，渍7日。每梳头常用之，若发稀及秃处，即以铁精30g，以此膏油于瓷器中研之。摩秃处，其发即生也。方中蔓荆子与诸药配伍有疏散风热，清利头目之功。（《外治秘方·广济方》蔓荆子膏） ⑥治头痛，目糊，齿痛，耳鸣或听力减退：蔓荆子、葛根、人参、黄芪各9g，黄柏3g，白芍6g，升麻4.5g，炙甘草3g。水煎，每日1剂，分2次温服。方中蔓荆子配伍黄芪人参等治劳役饮食不节，内障眼病。（《东垣十书》益气聪明汤）' where id=1938; -- 蔓荆子
update herbs set taste='甘苦，凉。', channel='脾；肺；肝经.', effect='①治下痢噤口：红木槿花去蒂，阴干为末，先煎面饼二个，蘸末食之。（《济急仙方》） ②治赤白痢：木槿花一两（小儿减半），水煎，兑白蜜三分服。赤痢用红花，白痢用白花，忌酸冷。（《云南中医验方》） ③治吐血、下血、赤白痢疾：木槿花九至十三朵。酌加开水和冰糖欺半小时，饭前服，日服二次。（《福建民间草药》） ④治风痰壅逆：木槿花晒干，焙研，每服一、二匙，空心沸汤下，白花尤良。（《简便单方》） ⑤治反胃：千叶白槿花，阴干为末，陈米汤调送三五口；不转，再将米饮调服。（《袖珍方》槿花散） ⑥治妇人白带：木槿花二钱，为末，人乳拌，饭上蒸熟食之。（《滇南本草》） ⑦治疗疮疖肿：木槿花（鲜）适量，甜酒少许，捣烂外敷。（《江西草药》） ⑧治疗细菌性痢疾：木槿花洗净晒干，研末备用。每次2克，小儿酌减，每隔2小时服1次，3～5天为一疗程。试治300例，症状控制者96.3％，一般服药后体温迅速下降，大便于2～3天内好转。', tips='清热利湿；凉血解毒。主肠风泻血；赤白下痢；痔疮出血；肺热咳嗽；咳血；白带；疮疖痈肿；烫伤。 ①《日华子本草》：治肠风泻血，赤白痢，并焙入药；作汤代茶，治风。 ②《纲目》：消疮肿，利小便，除湿热。 ③《本草汇言》：能除诸热，滑利能导积滞，善治赤白积痢，干涩不通，下坠欲解而不解，捣汁和生白酒温饮。 ④《本经逢原》：红者治肠风血痢，白者治白带白痢。 ⑤《安徽药材》：治皮肤病。 ⑥《江西中药》：白花与山雅雀同煮食，能止鼻血。' where id=1939; -- 木槿花
update herbs set alias='龙沙，卑相、卑盐，狗骨。', taste='辛、微苦，温。', channel='入肺、膀胱经。', effect='①治太阳病头痛发热，身疼腰痛，骨节疼痛，恶风无汗而喘者：麻黄三两（去节），桂枝二两（去皮），甘草一两（炙），杏仁七十个（去皮、尖）。上四味，以水九升，先煮麻黄，减二升，去上沫，纳诸药，煮取二升半，去滓，温服八合，覆取微似汗，不须啜粥。（《伤寒论》麻黄汤） ②治太阳病发汗后，不可更行桂枝汤，汗出而喘，无大热者：麻黄四两（去节），杏仁五十个（去皮、尖），甘草二两（炙），石膏半斤（碎，绵裹）。上四味，以水七升，煮麻黄，减二升，去上沫，纳诸药，煮取二升，去滓，温服一升。（《伤寒论》麻黄杏仁甘草石膏汤） ③治病者一身尽疼，发热，日晡所剧者，名风湿，此病伤于汗出当风，或久伤取冷所致：麻黄（去节）半两（汤泡），甘草一两（炙），薏苡仁半两，杏仁十个（去皮、尖，炒）。上锉麻豆大，每服四钱匕，水一盏半，煮八分，去滓，温服，有微汗避风。（《金匮要略》麻黄杏仁薏苡甘草汤） ④治风痹荣卫不行，四肢疼痛：麻黄五两（去根节了，秤），桂心二两。上捣细罗为散，以酒二升，慢火煎如饧。每服不计时候，以热酒调下一茶匙，频服，以汗出为度。（《圣惠方》） ⑤治伤寒热出表，发黄疸：麻黄三两，以淳酒五升，煮取一升半，尽服之，温服汗出即愈。冬月寒时用清酒，春月宜用水。（《千金方》麻黄淳酒汤） ⑥治感冒风邪，鼻塞声重，语音不出；或伤风伤冷，头痛目眩，四肢拘倦，咳嗽多痰，胸满气短：麻黄（不去节），杏仁（不去皮、尖）、甘草（生用）各等分。为粗末，每服五钱，水一盏半，姜五片，同煎至一盏，去滓。通口服，以衣被盖覆睡，取微汗为度。（《局方》三拗汤） ⑦治病疮疱倒黡黑者：麻黄（剪去节）半两，以蜜一匙同炒良久，以水半升煎，俟沸，去上沫，再煎，去三分之一，不用滓。乘热尽服之，避风，伺其疮复出。一法用无灰酒煎，但小儿不能饮酒者难服，然其效更速。（《本草衍义声）', tips='凡素体虚弱而自汗、盗汗、气喘者，均忌服。 恶辛夷、石韦。 ②《别录》：不可多服，令人虚。 ④《医学入门》：伤风有汗及阴虚伤食者禁用。 ⑤《本草经疏》：表虚自汗，阴虚盗汗；肺虚有热，多痰咳嗽以致鼻塞；疮疤热甚，不因寒邪所郁而自倒靥；虚人伤风，气虚发喘；阴虚火炎，以致眩晕头痛；南方中风瘫痪，及平日阳虚腠理不密之人皆禁用。' where id=1940; -- 麻黄
update herbs set taste='苦，平。', channel='入肝经。', effect='①治筋骨损伤：米粉四两（炒黄），入没药、乳香末各半两。酒调成膏，摊贴之。（《御药院方》） ②治杀伤不透膜者：乳香、没药各一皂子大，研烂，以小便半盏，好酒半盏，同药通口服。（《奇效良方》） ③治历节诸风，骨节疼痛，昼夜不可忍者：没药半两（研）；虎胫骨三两（涂酥，炙黄色），先捣罗为散，与没药同研令细。温酒调二钱，日三服。（《本草图经》） ④治一切心肚疼痛，不可忍者：没药、乳香各三钱，川山甲（炙）五钱，木鳖子四钱。上为末，每服半钱至一钱，酒大半盏，同煎温服，不计时候。（《宣明论方》没药散） ⑤治妇人内伤痛楚，血晕及脐腹疞刺者：没药研细，温酒调一钱。（《本草图经》） ⑥治产后血晕，语言颠倒，健忘失志：没药、血竭等分。细研为末，产后用童子小便与温酒各半盏，煎一、二沸，调下二钱，良久再服，其恶血自下。（《伤寒保命集》夺命散） ⑦消血块：滑石二钱，没药一钱，麒麟竭一钱。为末醋糊为丸。（《金匮钩玄》） ⑧治妇人月水不通：没药半两，硇砂半两，干漆半两（捣碎，炒令烟出），桂心一两，芫花半两（醋拌一宿，炒干），狗胆二枚（干者），水银三分（入少枣肉，研令星尽）。上药，捣罗为末，以枣肉和丸，如绿豆大。每于食前，以温醋汤下十丸。（《圣惠方》没药丸） ⑨治疗疮、无名肿毒：没药（去油）、辰砂、血竭、硼砂、乳香（去油）、雄黄、蟾酥（人乳浸化）、轻粉、冰片、麝香各等分。共乳细末，用乳捣和丸，如小麦大。每用三丸，含舌下，噙化咽下，出汗自消；如无汗，以热酒催之。（《疡医大全》舌化丹） ⑩治痈疽疮毒，腐去新生：乳香、没药各等分。安箬叶上，火炙去油，乳细搽上，以膏贴之。此药毒未尽则提脓外出，如毒巳尽则收口。（《疡医大全》海浮散） ⑾治五痔：没药一两（研），黄矾、白矾、溺垽（火煅）各半两，麝香一钱（研）。上五味并研令匀。每用时先以葱汤洗拭净，以药干敷。（《圣济总录》消毒没药散） ⑿治漏眼脓血：没药、大黄（蒸，少用）、朴硝。上为末。每服三钱，酒调下，茶亦可。（《银海精微》没药散） ⒀治血灌瞳人，外障疼痛：没药二两，麒麟竭一两，大黄一两半，芒硝一两半。上捣罗为末，令细。食后热茶调下一钱。（《眼科龙木论》没药散）' where id=1941; -- 没药
update herbs set taste='苦；性寒', channel='心；脾；肾；小肠；膀胱经。', effect='①治小儿心热（小肠有火，便亦淋痛，面赤狂躁，口糜舌疮，咬牙口渴）：生地黄、甘草（生）、木通各等分。上同为末，每服三钱，水一盏，入竹叶同煎至五分，食后温服。（《小儿药证直诀》导赤散） ②治尿血：木通、牛膝、生地黄、天门冬、麦门冬、五味子、黄柏、甘草。同煎服。（《本草经疏》） ③治水气，小便涩，身体虚肿：乌臼皮二两，木通一两（锉），槟榔一两。上件药，捣细罗为散，每服不计时候，以粥饮下二钱。（《圣惠方》） ④治涌水、肠鸣腹大：木通（锉）三两，桑根白皮（锉，炒）、石韦（去毛）、赤茯苓（去黑皮）、防己、泽泻各一两半，大腹（炮）四枚。上七味，粗捣筛，每服三钱匕，水一盏半，煎至一盏，去滓，食前温服，如入行五里再服。（《圣济总录》通草饮） ⑤治喉痹，心胸气闷，咽喉妨塞不通：本通二两（锉），赤茯苓二两，羚羊角屑一两半，川升麻一两半，马蔺根一两，川大黄一两半（锉碎，微炒），川芒硝二两，前胡二两（去芦头），桑根白皮二两（锉）。上件药，捣粗罗为散，每服三钱，以水一中盏，煎至六分，去滓，不计时候温服。（《圣惠方》木通散） ⑥治妇人经闭及月事不调：木通、牛膝、生地黄、延胡索。同煎服。（《本草经疏》） ⑦治产后乳汁不下：木通、钟乳各一两，漏芦（去芦头）二两，栝楼根，甘草各一两。上五味，捣锉如麻豆大，每服三钱匕，水一盏半，黍米一撮同煎，候米熟去滓，温服，不拘时。（《圣济总录》木通汤）' where id=1942; -- 木通
update herbs set taste='苦；性温。', channel='入肺、脾、肾经。', effect='①治小儿洞泄下痢，羸困：没石子（微煨），诃黎勒（煨）用皮半两。为细散。每服以粥饮调下半钱，日三、四服。量儿大小加减。（《普济方》没石子散） ②治小儿肠虚受热.下痢鲜血，或便赤汁，腹痛后重，昼夜不止，遍数频多：没石子、地榆各五钱，黄柏（锉、蜜炒）二两，黄连（炒、锉）一两五钱，酸石榴皮一两。捣罗为细末，以醋煮面糊和丸如麻子大。每服十丸至二十丸，温米饮下，食前服。（《局方》没石子丸） ③治血痢，不问远近：没石子一两。细研，以软饭和丸，如小豆大。每服于食前以粥饮下十丸。（《普济方》） ④治产后痢：没石子一个。烧，为末。和酒服方寸匕，冷即酒服，热即饮下。（《子母秘录》） ⑤治痔疾，下血无度，或发或歇：没石子三枚（烧灰），樗根白皮三两（锉、炒微黄），益母草三分，神曲二两（微炒），柏叶一两，桑耳一两。捣细罗为散。每于食前，以温粥饮调下一钱。（《圣惠方》没石子散） ⑥治阴汗：没石子烧灰，先以微温（汤）浴了，即以帛微裛后，傅灰囊上。（张仲景方） ⑦治小儿一切口疮，止疼痛：没石子三分（微火炙），甘草一分。上药捣细罗为散。每于疮上薄掺，盖令徧。（《圣惠方》） ⑧治牙齿疼痛：没石子不拘多少，捣罗为散。以绵裹一钱，当痛处咬之即定，有涎吐之。（《圣济总录》没石子散） ⑨治鼻面酒皶：南方没石子有孔者，水磨成膏，夜夜涂之。（《世医得效方》）' where id=1943; -- 没食子
update herbs set taste='辛，平。', effect='①治咽喉肿痛，咽物不得：蛇脱皮一条（烧令烟尽），马勃一分。上药细研为散，以绵裹一钱，含咽津。（《圣惠方》） ②治急喉闭：马屁勃、焰硝各一两。上为末，每用一字许，吹入喉内，吐涎血出，愈。（《经验良方》） ③治久嗽：马屁勃不以多少，细末，炼蜜为丸，如梧桐子大，每服二十丸，汤送下。（《普济方》马屁勃丸） ④治声失不出：马屁勃、马牙消等分，研末，沙糖和丸芡子大，噙之。（《摘元方》） ⑤治吐血：马屁包，为末，砂糖丸如弹子大，每服半丸，冷水下。（《袖珍方》） ⑥治妊娠吐衄不止：马勃末，浓米饮服半钱。（《圣惠方》） ⑦治大头天行，初觉憎寒体重，次传头面肿盛，口不能开，上喘，咽喉不利，口渴舌燥：黄芩（酒炒）、黄连（酒炒）各五钱，陈皮（去白）、生甘草、元参、柴胡、桔梗各二钱，连翘、板蓝根、马勃、鼠粘子、薄荷各一钱，僵蚕、升麻各七分。为末，汤调，时时服之。或蜜拌为丸，噙化。（李杲·普济消毒饮） ⑧治臁疮不敛：葱盐汤洗净，拭干，以马屁勃末敷之。（《稗史》） ⑨治痈疽：马勃擦粉，米醋调敷即消；并入连翘少许，煎服亦可。（《外科良方》）' where id=1944; -- 马勃
update herbs set taste='辛苦咸，寒。', channel='入胃、大肠经。', effect='①治阳明病，腹满而喘，有潮热，手足濈然汗出者，大便鞕：大黄四两（洒洗），厚朴半斤（炙，去皮），枳实五枚（炙），芒硝三合。上四味，以水一斗，先煮二物，取五升，去滓，纳大黄，更煮取二升，去滓，纳芒硝，更上微火一两沸，分温再服，得下，余勿服。（《伤寒论》大承气汤） ②治伤寒六、七日，结胸热实，脉沉而紧，心下痛，按之石鞕者：大黄六两（去皮），芒硝一升，甘遂一钱匕。上三味，以水六升，先煮大黄，取二升，去滓，纳芒硝，煮一两沸，纳甘遂末，温服一升，得快利，止后服。（《伤寒论》大陷胸汤） ③治关隔大小便不通，胀满欲死：芒硝三两，纸裹三、四重，炭火烧之，令内一升汤中尽服，当先饮汤一升，已吐出，乃服之。（《肘后方》） ④治食物过饱不消，遂成痞膈：马牙硝一两（碎之），吴茱萸半升（陈者）。煎取吴萸浓汁投硝，乘热服，良久未转，更进一服。（《经验方》） ⑤治小儿赤游行于体上下，至心即死：芒硝纳汤中，取浓汁以拭丹上。（《子母秘录》） ⑥治火丹毒：水调芒硝涂之。（《梅师集验方》） ⑦治眼有翳：芒硝一大两，置铜器中，急火上炼之，放冷后，以生绢细罗，点眼角中，每夜欲卧时一度点。（《孙真人食忌》） ⑧治小儿重舌：马牙消馀舌下。（《延龄至宝方》） ⑨治小儿鹅口：细研马牙消于舌上掺之，日三、五度。（《简要济众方》） ⑩治漆疮：芒硝五两，汤浸以洗之。（《千金方》） ⑾治代指：单煮川芒硝汤渍之。（《圣惠方》）' where id=1945; -- 芒硝
update herbs set effect='1. 治燥伤肺胃阴分。咽干口燥，或身热，或干咳，舌红少苔，脉细数者。沙参9g，玉竹6g，生甘草3g，冬桑叶4.5g，麦冬9g，生扁豆4.5g，花粉4.5g，水五杯，煮取2杯，日再服，久热久咳者，加地骨皮9g。方中甘寒，养阴润肺，为臣药。（《温病条辨》沙参麦冬汤） 2. 治文燥伤肺证。头痛身热，干咳无痰，气逆而喘，咽喉干燥，口渴鼻燥，胸膈满闷，舌干少苔，脉虚大而数。桑叶9g，石膏8g，甘草3g，人参2g，胡麻仁3g，真阿胶3g，麦门冬4g，杏仁2g，枇杷叶3g。水一碗，煎六分，频频二三次滚热服。方中麦冬甘寒，养阴润肺，为臣药。（《医门法律》清燥救肺汤） 3. 治白喉。喉间起白如腐，不易拭去，咽喉肿痛，初起或发热或不发热，鼻干唇燥，或咳或不咳，呼吸有声，四喘非喘，脉数无力或细数。大生地12，麦冬9，生甘草3，玄参9，贝母5，丹皮5，薄荷3，炒白芍5。水煎服。方中麦冬养阴清肺，为臣药。（《重楼玉钥》养阴清肺汤）' where id=1946; -- 麦冬
update herbs set taste='辛味辛；苦；性温。', channel='入肺、肝、脾经。', effect='①治一切走注，气痛不和：广木香，温水磨浓汁，入热酒调服。（《简便单方》） ②治内钓腹痛：木香、乳香、没药各五分。水煎服之。（《阮氏小儿方》） ③治一切气，攻刺腹胁胀满，大便不利：木香三（二）两，枳壳二两（麸炒微黄，去瓤），川大黄四两（锉碎，微炒），牵牛子四两（微炒），诃黎勒皮三两。上药，捣罗为末，炼蜜和捣，丸如梧桐子大。每服，食前以生姜汤下三十丸。（《圣惠方》木香丸） ④治一切沉积水气，两胁刺痛，中满不能食，头目眩者，可用茶调散，次服本方：木香、槟榔、青皮、陈皮、广茂（烧）、黄连（麸炒）各一两，黄柏、大黄各三两，香附子（炒）、牵牛各四两。上为细末，水丸如小豆大。每服三十丸，食后，生姜汤送下。（《儒门事亲》木香槟榔丸） ⑤治肠胃虚弱，冷热不调，泄泻烦渴，米谷不化，腹胀肠鸣，胸膈痞闷，胁肋胀满；或下痢脓血，里急后重，夜起频并，不思饮食；或小便不利，肢体怠惰，渐即瘦弱：黄连（去芦、须）二十两（用茱萸十两同炒令赤，去茱萸不用），木香（不见火）四两八钱八分。上为细末，醋糊为丸，如梧桐子大，每服二十丸，浓煎米饮下，空心日三服。（《局方》大香连丸） ⑥治下痢脓血，里急后重，日夜无度：芍药一两，当归五钱，大黄、黄芩、黄连、木香各一钱半，槟榔一钱。为末。每服三、五钱，水一盏，煎至七分，去滓，温服；如未止，再服，不后重则止。（《紊问病机保命集》导气汤） ⑦治寒疝，以及偏坠小肠疝痛：川楝子三钱，小茴香五分，木香一钱，淡吴茱萸一钱。长流水煎服。（《医方简义》导气汤） ⑧治霍乱转筋：木瓜汁一盏，木香一钱匕。上二味，以热酒调下，不拘时。（《圣济总录》） ⑨治小儿阳明经风热湿气相搏，阴茎无故肿或痛缩：广木香、枳壳（麸炒）二钱半，实甘草二钱。水煎服。（《曾氏小儿方》） ⑩治腋臭：好醋浸青木香，置腋下夹之。（《必效方》） ⑾治恶蛇虺伤：青木香不拘多少，煎水服。（《袖珍方》）' where id=1947; -- 木香
update herbs set taste='酸，寒。', channel='入大肠，肝、脾经。', effect='①治血痢：马齿菜二大握（切），粳米三合。上以水和马齿苋煮粥，不着盐醋，空腹谈食。（《圣惠方》马齿粥） ②治产后血痢，小便不通，脐腹痛：生马齿菜，捣，取汁三大合，煎一沸，下蜜一合调，顿服。（《经效产宝》） ③治小便热淋：马齿苋汁服之。（《圣惠方》） ④治赤白带下，不问老稚孕妇悉可服：马齿苋捣绞汁三大合，和鸡子白一枚，先温令热，乃下苋汁，微温取顿饮之。（《海上集验方》） ⑤治阑尾炎：生马齿苋一握。洗净捣绞汁30毫升，加冷开水100毫升，白糖适量，每日服三次，每次100毫升。（《福建中医药》6（3）：113，1961） ⑥治痈久不瘥：马齿苋捣汁，煎以敷之。（《千金方》） ⑦治多年恶疮：马齿苋捣敷之。（《滇南本草》） ⑧治蛀脚臁疮：干马齿苋研末，蜜调敷上，一宿，其虫自出。（《海上方》） ⑨治翻花疮：马齿苋一斤烧为灰，细研，以猪脂调敷之。（《圣惠方》） ⑩治耳有恶疮：马齿苋一两（干者），黄柏半两（锉）。捣罗为末，每取少许，绵裹纳耳中。（《圣惠方》） ⑾治甲疽：墙上马齿苋（阴干）一两，木香、丹砂（研细），盐（研细）各一分。上四味，除丹砂、盐外，锉碎拌令匀，于熨斗内，炭火烧过，取出细研，即入丹砂、盐末，再研匀，旋取敷疮上，日三、两度。（《圣济总录》马齿散敷方） ⑿治小儿白秃：马齿苋煎膏涂之，或烧灰猪脂和涂。（《圣惠方》） ⒀治小儿火丹，热如火，绕腰即损：杵马齿苋敷之，日二。（《广利方》） ⒁治瘰疬：马齿苋阴干烧灰，腊月猪膏和之，以暖泔清洗疮，拭干敷之，日三。（《救急方》） ⒂治瘰疬未破：马齿苋同靛花捣掺，日三次。（《简便良方》） ⒃治肛门肿痛：马齿苋叶、三叶酸草等分。煎汤熏洗，一日二次有效。（《濒湖集简方》） ⒄治蜈蚣咬伤：马齿苋汁涂之。（《肘后方》） ⒅脚气浮肿，心腹胀满，小便涩少。用马齿苋和少量粳米、酱汁煮食。 ⒆产后虚汗。用马齿苋研汁三全服。如无新鲜者，以干者煮汁亦可。 ⒇产后血痢，小便不爱，脐腹疼痛。用生马齿苋菜捣汁三合，煎开，加蜜一合调服。 （21）肛门肿痛。用马齿苋叶、三叶酸草等分，煎汤熏洗。一天二次，有效。 （22）赤白逅眄。用马齿苋捣汁三合，倒入温热一两枚鸡蛋白中，乘微温一次服下。一般服两次见效。 （23）腹中白虫。用马齿苋煮水一碗，和盐醋空腹吃下。不久有白虫排出。 （24）风齿肿痛。用马齿苋一把，嚼汁浸患处，肿即消退。 （25）耳内外恶疮。用黄蘖半两、干马齿苋一两，共 研为末敷涂。 （26）小儿脐疮。用马齿苋烧过，研末敷涂。 （27）疔疮肿毒。有马齿苋二分、石灰三分，共研为末，加鸡蛋白调匀敷涂。 （28）积年恶疮。用马齿苋捣烂封住，或取汗煎浓敷涂。 （29）治血痢：马齿菜2大握（切），粳米3合。以上水和马齿菜煮粥，不着盐醋，空服淡食。方中马齿苋请热解毒，止血，为君药。（马齿粥 《太平圣惠方》） （30）治肠道辐射灼伤后，腹痛，下坠，大便带脓血：马齿苋30g，杭白芍15g，乌梅9g，白头翁15g，槐角、地榆各9g，败酱草30g，山楂15g，秦皮9g。水煎，每日1剂，日服2次。方中马齿苋请热解毒，止血，为君药。（《实用中医学》）' where id=1948; -- 马齿苋
update herbs set taste='苦；辛；微寒。', channel='入肝、脾经。', effect='①治伤风感冒、流感：鲜马鞭草一两五钱，羌活五钱，青蒿一两。上药煎汤二小碗，一日二次分服，连服二至三天。咽痛加鲜桔梗五钱。（《江苏验方草药选编》） ②治卒大腹水病：鼠尾草、马鞭草各十斤。水一石，煮取五斗，去滓更煎，以粉和为丸服，如大豆大二丸加至四：五丸。禁肥肉，生冷勿食。（《补缺肘后方》） ③治鼓胀烦渴，身干黑瘦：马鞭草细锉，曝干，勿见火。以酒或水同煮，至味出，去滓，温服。（《卫生易简方》） ④治痢疾：马鞭草二两，土牛膝五钱。将两药洗净，水煎服。每天一剂，一般服二至五剂。（《全展选编·传染病》） ⑤破腹中恶血，杀虫：马鞭草，生捣，水煮去滓，煎如饴，空心酒服一匕。（《药性论》） ⑥治妇人月水滞涩不通，结成癥块，腹肋胀大欲死：马鞭草根苗五斤，细锉，以水五斗，煎至一斗，去滓，别于净器中熬成煎。每于食前，以温酒调下半匙。（《圣惠方》） ⑦治妇人疝痛：马鞭草一两，酒煎滚服，以汤浴身，取汗甚妙。（《纂要奇方》） ⑧治酒积下血：马鞭草灰四钱，白芷灰一钱。蒸饼丸梧子大。每米饮下五十丸。（《摘元方》） ⑨治疟，无问新久者：马鞭草汁五合，酒三合，分三服。（《千金方》） ⑩治乳痈肿痛：马鞭草一握，酒一碗，生姜一块。擂汁服，渣敷之。（《卫生易简方》） ⑾治疳疮：马鞭草煎水洗之。（《生草药性备要》） ⑿治牙周炎，牙髓炎，牙槽脓肿：马鞭草一两，切碎晒干备用，水煎服，每天一剂。（《全展选编·五官科》） ⒀治喉痹深肿连颊，吐气数者（马喉痹）：马鞭草根一握，截去两头，捣取汁服。（《干金方》） ⒁治咽喉肿痛：鲜马鞭草茎叶捣汁，加人乳适量，调匀含咽。（江西《中草药学》） ⒂治黄疸：马鞭草鲜根（或全草）二两，水煎调糖服。肝肿痛者加山楂根或山楂三钱。（江西《草药手册》）' where id=1949; -- 马鞭草
update herbs set taste='咸湿，凉。', channel='入肝、肾经。', effect='（1）治眩晕：牡蛎六钱，龙骨六钱，菊花三钱，枸杞子四钱，何首乌四钱。水煎服。（《山东中草药手册》） （2）治百合病，渴不瘥者：栝蒌根、牡蛎（熬），等分。为细末，饮服方寸匕，日三服。（《金匮要略》栝蒌牡蛎散） （3）治一切渴：大牡蛎不计多少，黄泥裹煅通赤，放冷为末，用活鲫鱼煎汤调下一钱匕，小儿服半钱匕。（《经验方》） （4）治小便数多：牡蛎五两（烧灰），童便三升。煎至二升，分三服。（《乾坤生意》） （5）治小便淋閟，服血药不效者：牡蛎、黄柏（炒），等分。为末，每服一钱，小茴香汤下取效。（傅滋《医学集成》） （6）治崩中漏下赤白不止，气虚竭：牡蛎、鳖甲各三两。上二味，治下筛，酒服方寸匕，日三。（《千金方》） （7）治诸虚不足及新病暴虚，津液不固，体常自汗，夜卧即甚，久而不止，羸瘠枯瘦，心忪惊惕，短气烦倦：麻黄根（洗）、黄芪、牡蛎（米泔浸，烧赤）各一两。共为粗末，每服三钱，水一盏半，小麦百余粒，同煎至八分，去滓热服，日二，不拘时候。（《局方》） （8）治卧即盗汗，风虚头痛：牡蛎、白术、防风各三两。治下筛，酒服方寸匕，日二。（《千金方》牡蛎散） （9）治盗汗及阴汗：牡蛎研细粉，有汗处扑之。（《经验方》） （10）治温病下后，大便溏甚，周十二时三、四行，脉仍数者：生牡蛎二两。研细，水八杯，煎服三杯，分温三服。（《温病条辨》一甲煎） （11）治一切瘰疬：㈠牡蛎（煅）四两，玄参三两。捣罗为末，以面糊丸如桐子大，早晚食后、临卧各服三十丸，酒下。（《经验方》）㈡牡蛎粉五钱，和鸡胆汁为膏贴之。（《脉因证治》） （12）治胃酸过多：牡蛎、海螵蛸各五钱，浙贝母四钱。共研细粉，每服三钱，每日三次。（《山东中草药手册》） （13）治大病瘥后，小劳便鼻衄：左牡蛎十分，石膏五分。捣末，酒服方寸匕，日三、四次。亦可蜜丸如梧子大服之。（《补缺肘后方》） （14）治金疮出血：牡蛎粉敷之。（《肘后方》） （15）心脾气痛，有痰。用牡蛎煅成粉，酒送服二钱。 （16）疟疾寒热。用牡蛎粉、杜仲，等分为末，加蜜做成丸子，如梧子大。每服五十丸，温水送下。 （17）气虚盗汗。用牡蛎粉、杜仲，等分为末。每服一匙，酒送下。 （18）产后盗汗。用牡蛎粉、麦麸（炒黄）等分。每服一钱，猪肉汤调下。 （19）消渴饮水。用黄泥封固牡蛎，煅赤，研为末。每服一钱，活鲫鱼煎汤调下。 （20）百合变渴（由伤寒转成百合病，如寒无寒，如热无热，欲卧不卧，欲行不行，欲食不食，口苦，小便赤我，一般服药则有吐泻，变成渴疾，久治不愈）。用牡蛎（熬）二两、栝楼根二两，共研为末。每服一匙，米汤调下。一天服三次。 （21）病后常流鼻血。用牡蛎十分、石膏五分，共研为末。每服一匙，酒关下。亦可加蜜作丸子吃，一天三次。 （22）小便淋闭（服治血药无效者）。用牡蛎粉、黄蘖（炒），等分为末。每服一钱，小茄香汤送下。 （23）小便数多。用牡蛎五两，加小便三升，煎成二程式，分三次服。极效。 （24）梦遗便溏。用牡蛎粉。加醋、糊做成丸子，如梧子大。每服三十丸，米汤送下。一天服二次。 （25）阴囊水肿用牡蛎煅粉二两、干姜（炮）一两，共研为末，冷水调糊敷上。不久，囊热如火。药干即换，至小便通畅末，冷水调糊敷上。不久，囊热如火。药干即换，至小便通畅为愈。又方：改冷水调糊为葱汁，白面同调。不儿不用干姜。 （26）月经不止。用牡蛎煅过研细。加米醋揉成团，再煅再研，加米醋调艾叶末熬膏，做成丸子，如梧子大。每服四、五十丸，醋汤送下。 （27）刀伤出血。用牡蛎粉敷涂。 （28）痈肿初起。用牡蛎粉末调水涂搽。药干即换。 （29）瘰疬。用牡蛎煅过，研为末。取四两，加玄参末三两，和面糊做成丸子如梧子大。每服三十丸，酒送下。一天服三次，服尽除根。又方：瘰头疬不知已破未破，用牡蛎四两，甘草一两为末。每服一钱，饭后服，茶汤调下。其效极验。' where id=1950; -- 牡蛎
update herbs set taste='辛苦；凉；微寒。', channel='入心、肝、肾经。', effect='①治伤寒热毒发疮如豌豆：牡丹皮、山栀子仁、黄芩（去黑心）、大黄（锉、炒）、木香、麻黄（去根、节）。上六味等分，锉如麻豆大。每服三钱匕，水一盏，煎至七分，去滓，温服。（《圣济总录》牡丹汤） ②治妇人恶血攻聚上面，多怒：牡丹皮半两，干漆（烧烟尽）半两。水二钟，煎一钟服。（《诸证辨疑》） ③治伤寒及温病应发汗而不发汗之内蓄血者，及鼻衄、吐血不尽，内余瘀血，面黄，大便黑；消瘀血：犀角一两，生地黄八两，芍药三两，牡丹皮二两。上四味，细切，以水九升，煮取三升，分三服。（《千金方》犀角地黄汤） ④治胎前衄血：丹皮、黄芩、蒲黄、白芍、侧柏叶。共为细末，早米糊为丸。空心白汤下百丸。（《秘传内府经验女科》） ⑤治妇人骨蒸，经脉不通，渐增瘦弱：牡丹皮一两半，桂（去粗皮）一两，木通（锉、炒）一两，芍药一两半，鳖甲（醋炙，去裙襕）二两，土瓜根一两半，桃仁（汤浸，去皮、尖、双人，炒）。上七味粗捣筛。每五钱匕，水一盏半，煎至一盏，去滓，分温二服，空心食后各一。（《圣济总录》牡丹汤） ⑥治肠痈，少腹肿痞，按之即痛如淋，小便自调，时时发热，自汗出，复恶寒，其脉迟紧者，脓未成，可下之，当有血，脉洪数者，脓已成，不可下也：大黄四两，牡丹一两，桃仁五十个，瓜子半升，芒硝三合。上五味，以水六升，煮取一升，去滓，内芒硝，再煎沸，顿服之。有脓当下，如无脓当下血。（《金匮要略》大黄牡丹汤） ⑦治悬痈生于谷道之前，小便之后，初发甚痒，状如松子，-月赤肿如桃，迟治则破，而大小便皆从此出，先服国老汤不消者：牡丹皮、大黄、贝母、白芷、甘草、当归各五钱。共为细末，酒调服二钱，空心吃。（《本草汇言》将军散） ⑧治下部生疮，已决洞者：牡丹方寸匕，日三服。（《补缺肘后方》） ⑨治金疮内漏，血不出：牡丹皮为散，水服三指撮，立尿出血。（《千金方） ⑩治腕折瘀血：虻虫二十枚，牡丹一两。上二味治下筛，酒服方寸匕。（《千金方》） ⑾疝气（觉气胀不能动）。用牡丹皮、防风，等分为末，每服二钱，酒送下。 ⑿妇女恶血（血往上冲，脸红易怒）。用牡丹皮半两、干漆（烧至烟尽）半两，加水二杯，煎成一杯服下。 ⒀伤损瘀血。用牡丹皮二两、虻虫二十一个（熬过），同捣碎。每天早晨服一匙，温酒送下。 ⒁刀伤后内出血。用牡丹皮研细，水冲服少许。瘀血自尿中排出。 ⒂下部生疮（已破口）。取牡丹末一匙煎服。一天三次。 ⒃主治瘟病后期，邪伏阴分证。青蒿6g，鳖甲15g，细生地12g，知母6g，丹皮9g。上药以水五杯，煮取二杯，日再服。方中佐以牡丹皮辛苦性凉，泻阴中之伏火，使火退而阴升。（《瘟病条辨》青蒿鳖甲汤） ⒄主治热入血分证，热伤血络证。水牛角30g，生地黄24g，赤芍12g，牡丹皮9g上药四味，以水九升，煮取三升，分三服。方中丹皮苦辛微寒，入心肝肾，清热凉血，活血散瘀，可收化斑之效。（《备急千金要方》犀角地黄汤）' where id=1951; -- 牡丹皮
update herbs set taste='甘微苦，凉。', channel='入肺、肝经。', effect='①治产后无乳：杏叶沙参根四钱。煮猪肉食。（《湖南药物志》） ②治虚火牙痛：杏叶沙参根五钱至二两。煮鸡蛋服。（《湖南药物志》） ③治肺热咳嗽：沙参半两，水煎服之。（《卫生易简方》） ④治失血后脉微手足厥冷之症：杏叶沙参，浓煎频频而少少饮服。（《成都中草药》） ⑤治赤白带下，皆因七情内伤，或下元虚冷：米饮调沙参末服。（《证治要诀》） ⑥治燥伤肺卫阴分，或热或咳者：沙参三钱，玉竹二钱，生甘草一钱，冬桑叶一钱五分，麦冬三钱，生扁豆一钱五分，花粉一钱五分，水五杯，煮取二杯，日再服。久热久咳者，加地骨皮三钱。（《温病条辨》沙参麦冬汤）' where id=1952; -- 南沙参
update herbs set alias='犀黄，各一旺（蒙名）。', taste='味苦；甘；性凉。', channel='入心、肝经。', effect='①治温病邪入心包，神昏谵语，兼治卒厥，五痫，中恶，大人小儿痉厥之因于热者：牛黄一两，郁金一两，犀角一两，黄连一两，朱砂一两，梅片二钱五分，麝香二钱五分，真珠五钱，山栀一两，雄黄一两，黄芩一两。上为极细末，炼老蜜为丸，每丸一钱，金箔为衣，蜡护。脉虚者，人参汤下；脉实者，银花、薄荷汤下。每服一丸，大人病重体实者，日再服，甚至日三服；小儿服半丸，不知，再服半丸。（《温病条辨》安宫牛黄丸） ②治热入血室，发狂不认人者：牛黄二钱半，朱砂三钱，脑子一钱，郁金三钱，甘草一钱，牡丹皮三钱。上为细末，炼蜜为丸，如皂子大。新水化下。（《索问病机保命集》牛黄膏） ③治中风痰厥、不省人事，小儿急慢惊风：牛黄一分，辰砂半分，白牵牛（头末）二分。共研为末，作一服，小儿减半。痰厥温香油下；急慢惊风，黄酒入蜜少许送下。（《鲁府禁方》牛黄散） ④治小儿惊热，发歇不定：牛黄一分（细研），川大黄半两，蝉壳一分（微炒），子芩半两，龙齿半两（细研）。上药，捣罗为末，炼蜜和丸，如麻子大，不计时候，煎金、银、薄荷汤下三丸，量儿大小，加减服之。（《圣惠方》牛黄丸） ⑤治小儿心肺烦热，黄瘦，毛焦，睡卧多惊，狂语：朱砂半两，牛黄一分。上药，同研如面。每服，以水磨犀角，调下一字。（《圣惠方》） ⑥治初生胎热或身体黄者：真牛黄一豆大。入蜜调膏，乳汁化开，时时滴儿口中，形色不实者，勿多服。（《小儿药证直诀》） ⑦治小儿胎风热、撮口发噤：牛黄（研）一分，淡竹沥半合。每服牛黄一字匕，用淡竹沥调下，一、二岁儿服之；三、四岁儿每服半钱，日三服。量儿大小，以意加减。（《圣济总录》牛黄竹沥散） ⑧治乳岩（乳癌），横痃，瘰疬，痰核，流注，肺痈，小肠痈：犀黄三分，麝香一钱半，乳香、没药（各去油）各一两。各研极细末，黄米饭一两，捣烂为丸，忌火烘，晒干。陈酒送下三钱，患生上部，临卧服，下部空心服。（《外科全生集》犀黄丸） ⑨治胎毒疮疖及一切疮疡：牛黄三钱，甘草、金银花各一两，草紫河车五钱。上为末，炼蜜丸，量儿服。（《保婴撮要》牛黄解毒丸） ⑩治伤寒咽喉痛，心中烦躁，舌上生疮：牛黄（研）、朴硝（研）、甘草（炙，锉）各一两，升麻、山栀子（去皮）、芍药各半两。捣研为细散，再同研令匀。每服一钱匕，食后煎姜、蜜汤，放冷调下。（《圣济总录》牛黄散） ⑾治小儿鹅口疮，不能饮乳：牛黄一分，为末。上一味，用竹沥调匀，沥在儿口中。（《圣济总录》牛黄散） ⑿牛黄清心丸（《痘疹世医心法》）治温热之邪，内陷心包，身热，神昏谵语，烦躁不安，以及小儿高热惊厥，中风窍闭等证。牛黄1g，朱砂5g，黄连15g，黄芩9g，栀子9g，郁金6g。上为极细末，炼老蜜为丸，金箔为衣。大人病重体实者，日再服，甚至日三服；小儿服半丸，不知，在服半丸。方中牛黄味苦而凉，功能清心解毒，熄风定惊，豁痰开窍，为君药。', tips='脾虚便溏及孕妇慎服。 恶龙骨、地黄、龙胆、蜚蠊。畏牛膝。 ②《药性论》：恶常山。畏干漆。 ③《品汇精要》：妊妇勿服。 ④《本草经疏》：伤乳作泻，脾胃虚寒者不当用。' where id=1953; -- 牛黄
update herbs set taste='味苦；微苦；性凉。', effect='①治赤白痢疾：鸭公青、六合草，马齿苋、茶叶。煎汤服。(《四川中药志》) ②治热淋：鸭公青、木通，车前仁、石韦根。煎服。(《四川中药志》) ③治黄疸：鸭公头五钱，满天星四钱，黄栀子三钱，龙胆二钱。煎水服，每日二次。(《贵州民间药物》) ④治病后虚或干血痨：鸭公头一两，炖肉吃(《贵州民间药物》) ⑤退高烧：鸭公头根一两，煎水服。(《贵州草药》)', tips='清热利湿；活血解毒。主热淋；黄疸；痢疾；带下；崩漏；跌打损伤；风湿疼痛；痈肿疮毒。治赤白痢疾，黄疸，热淋，崩中带下。 ①《草木便方》："清热，利胀.治风湿脚痛，热淋，劳伤暗积，损伤。" ②《分类草药性》："治崩，红白痢症，血淋，丹田膨胀。" ③《天宝本草》："清心明目。治头晕虚热，咽喉热毒。" ④《贵州民间药物》："清热，除湿。治黄疸，高烧，痨伤。" ⑤《四川中药志》："治白带。"' where id=1954; -- 女儿红根
update herbs set alias='稻米，江米，元米。', taste='甘，温。', channel='入脾、胃、肺经。', effect='①治三消渴利：糯谷（旋炒作爆蓬）、桑根白皮（厚者，切细）等分。上每用秤一两许，水一大碗，煮取半碗，渴则饮，不拘时。（《三因方》梅花汤） ②治自汗不止：糯米、小麦麸（同炒）。为末，每服三钱，米饮下，或煮猪肉点食。（《纲目》） ③治久泄食减：糯米一升。水浸一宿，沥干，慢炒热，磨筛，入怀山药一两。每日清晨用半盏，入砂糖二匙，胡椒末少许，以极滚汤凋食，大有滋补，久服令人精暖，有子。（《刘长春经验方》） ④治下痢禁口：糯谷一升。炒出白花，去壳，用姜汁拌湿，再炒为禾，海服一匙，汤下，三服。（《经验良方》） ⑤治虚劳不足：糯米入猪肚内蒸干，捣作丸子，日日服之。（《纲目》） ⑥治腹痛：糯米一、二升。炒极热，盛长袋中，缚于痛处，细研八角茴香三钱，以盐酒随时服之。（《摄生众妙方》） ⑦治妊娠胎动，腹痛，或下黄赤汁：糯米一分，黄耆一两（锉），芎藭一两（锉）。上药，以水二大盏，煎至一盏三分，去滓，不计时候，分温三服。（《圣惠方》） ⑧治小儿头上生疮及肥疳疮：糯米饭烧灰，入轻粉，清油调敷。（《普济方》）' where id=1955; -- 糯米
update herbs set alias='恶实，鼠粘子，黍粘子，大力子，蝙蝠刺，毛然然子、黑风子，毛锥子，粘苍子，鼠尖子、弯巴钩子、万把钩，大牛子，牛子。', taste='味辛；苦；性寒。', channel='入肺、胃经。', effect='①疏风壅涎唾多，咽膈不利：牛蒡子（微炒）、荆芥穗各一两，甘草（炙）半两。并为末，食后夜卧，汤点二钱服，当缓取效。（《本草衍义》） ②治喉痹：牛蒡子六分，马蔺子八分.上二味捣为散，每空腹以暖水服方寸匕，渐加至一匕半，日再。（《广济方》） ③治风热闭塞咽喉，遍身浮肿：牛蒡子一合，半生半熟，杵为末，热酒调下一钱匕。（《经验方》） ④治风热客搏上焦，悬痈肿痛：恶实（炒）、甘草（生）各一两。上为散，每服二钱匕，水一盏，煎六分，旋含之，良久咽下。（《普济方》启关散） ⑤治瘄疹不起透：牛蒡子（研细）五钱，柽柳煎汤，调下立透。（《本草汇言》） ⑥治皮肤风热，遍身生瘾疹：牛蒡子、浮萍等分。以薄荷汤调下二钱，日二服。（《养生必用方》） ⑦治风肿斑毒作痒：牛蒡子、玄参、僵蚕、薄荷各五钱。为末，每服三钱，白汤调下。（《方脉正宗》） ⑧治痰厥头痛：旋覆花一两，牛蒡子一两（微炒）。上药捣细罗为散，不计时侯，以腊面茶清调下一钱。（《圣惠方》） ⑨治头痛连睛，并目昏涩不明：牛蒡子、苍耳子、甘菊花各三钱。水煎服。（《方脉正宗》） ⑩治风热成历节，攻手指作赤肿麻木，甚则攻肩背两膝，遇暑热或大便秘即作：牛蒡子三两（隔纸炒），新豆豉（炒），羌活（去芦）各一两，干生地黄二两半，黄耆一两半（蜜炙）。上为细末，汤调二钱服，空心食前，日三服。（《本事方》牛蒡子散） ⑾治头面风热，或颈项痰毒，风热牙痈：牛蒡子、薄荷、荆芥、山栀、丹皮、石斛、元参、夏枯草，水煎服。（《疡科心得集》牛蒡解肌汤） ⑿治风龋牙痛：牛蒡子炒，煎水含漱吐之。（《延年方》） ⒀治吹乳：鼠粘子加麝、酒吞下。（《袖珍方》） ⒁治便痈：鼠粘子三钱炒，细末，入蜜一匙，净朴硝一匙，温酒空心服。（《袖珍方》） (15)治小儿伤风，发热烦躁，鼻塞气喘，痰嗽惊啼，及诸疮赤紫，丹毒，咽喉肿痛：炒牛蒡子90 g，大黄45 g，防风、薄荷（去老梗）各90 g，荆芥（去老梗）120 g，甘草34.5g。上为粗末，每服6 g，水煎服。（《证治准绳·幼科》牛蒡汤） (16)治颐毒表邪已尽，耳项结肿，微热不红而疼痛者：牛蒡子、桔梗、陈皮、天花粉、黄连、川芎、赤芍药、甘草、苏木各3 g。水煎，食后服。（《外科正宗》牛蒡甘桔汤）' where id=1956; -- 牛蒡子
update herbs set taste='甘；苦；性凉。', channel='入肝、肾经。', effect='①补腰膝，壮筋骨，强阴肾，乌髭发：女贞子（冬至日采：不拘多少，阴干，蜜酒拌蒸，过一夜，粗袋擦去皮，晒干为末，瓦瓶收贮，或先熬干，旱莲膏旋配用），旱莲草（夏至日采，不拘多少），捣汁熬膏，和前药为丸，临卧酒服。（《医方集解》二至丸） ②治神经衰弱：女贞子、鳢肠、桑椹子各五钱至一两。水煎服。或女贞子二斤，浸米酒二斤，每天酌量服。（《浙江民间常用草药》） ③治风热赤眼：冬青子不以多少，捣汁熬膏，净瓶收固，埋地中七日，每用点眼。（《济急仙方》） ④治视神经炎：女贞子、草决明、青葙子各一两。水煎服。（《浙江民间常用草药》） ⑤治瘰疬，结核性潮热等：女贞子三钱，地骨皮二钱，青蒿一钱五分，夏枯草二钱五分.水煎，一日三回分服。（《现代实用中药》） ⑥治肾受燥热，淋浊溺痛，腰脚无力，久为下消：女贞子四钱，生地六钱，龟板六钱，当归、茯苓、石斛、花粉、萆薢、牛膝，车前子各二钱，大淡菜三枚。水煎服。（《医醇胜义》女贞汤） ⑦补肾滋阴。取女贞子，去梗叶，浸酒中一日夜，擦去皮，晒干，研为末，待早莲草出时，采数石，捣汁熬浓，和末做成丸子，如梧子大。每夜服百丸，酒送下。十多天之后，体力增加，老人不再起夜。又能变白发为黑色，强腰膝，起阴气。又方：用初冬采收后阴干的女贞实，酒浸一日，蒸透晒干，取一斤四两；夏季采收并阴干的旱莲草，取十两；晚春采收并阴干的桑椹子，取十两。三味共研为末，加炼蜜做成丸子如梧子大。每服七、八直丸，淡盐汤送睛。若是五月份采的又桑椹，八月份采的旱莲，则可直接捣汁和药，不用加蜜。 ⑧风热赤眼。用女贞子不限量，捣汁熬膏，净瓶收存，埋地中七日后，取以点眼。 ⑨口舌生疮，舌肿胀出。取女贞叶捣汁含浸吐涎。 ⑩一切眼疾，用女贞叶捣烂，加朴硝调匀贴眼部。' where id=1957; -- 女贞子
update herbs set taste='苦；酸；性平。', channel='入肝、肾经。', effect='①治小便不利，茎中痛欲死，兼治妇人血结腹坚痛：牛膝一大把并叶，不以多少，酒煮饮之。（《肘后方》） ②治室女月经不通，脐下坚结，大如杯升，发热往来，下痢羸瘦，此为血瘕：干漆（杵细，炒令烟尽），牛膝（酒浸一宿）各一两六钱（为末）。生地黄四两八钱，取汁，慢火熬，丸如桐子大。空心，米饮或温酒下二丸，日再，勿妄加，病去止药。（《三因方》万病丸） ③治暴癥，腹中有物如石，痛如刺，昼夜啼呼：牛膝二斤，以酒一斗，渍，密封，于热炭火中温令味出，服五合至一升，量力服之。（《补缺肘后方》） ④治胞衣不出：牛膝八两，葵子一两。以水九升，煎取三升，分三服。（《梅师集验方》） ⑤取胎：用雄土牛膝一两，真麝香一钱，捣匀，溶蜡搓成长条，插入阴户，即能坠胎。（《药鉴》） ⑥治喉痹、乳蛾：新鲜牛膝根一握，艾叶七片。捣，和人乳，取汁灌入鼻内，须臾痰涎从口鼻出。无艾亦可。（《纲目》） ⑦治痈疖已溃：牛膝根略刮去皮，插入疮口中，留半寸在外，以嫩橘叶及地锦草各一握，捣，（敷）其上，随干随换。（《陈日华经验方》） ⑧治口中及舌上生疮，烂：牛膝酒渍含漱之，无酒者空含亦佳。（《肘后方》） ⑨治风瘙隐疹、骨疽、癞病：牛膝为末，酒下方寸匕，日三。（《千金方》） ⑩治金疮痛：生牛膝捣敷疮上。（《梅师集验方》） ⑾治风湿痹，腰痛少力：牛膝一两（去苗），桂心三分，山茱萸一两。上件药，捣细罗为散。每于食前，以温酒调下二钱。（《圣惠方》） ⑿治湿热下流，两脚麻木，或如火烙之热：苍术六两（米泔浸三宿，细切，焙干），黄柏四两（切片，酒拌略炒），川牛膝（去芦）二两。上为细末，面糊为丸，如桐子大。每服五、七、十丸，空心姜盐汤下，忌鱼腥、荞麦、热面、煎炒等物。（《医学正传》三妙丸） ⒀治鹤膝风：牛膝、木瓜、五加皮、骨碎补、金银花、紫花地丁、黄柏、萆薢、甘菊根，水煎服。（《本草汇言》） ⒁治痿痹，补虚损，壮筋骨，除久疟：牛膝煎汁和曲米酿酒，或切碎袋盛浸酒，煮饮之。（《纲目》牛膝酒） ⒂治痨疟积久不断：长生大牛膝一虎口。切，以水六升，煮取二升，分再服，第一服取未发前一食顷服，第二服临发服。（《千金方》） ⒃治痢下先赤后白：牛膝三两。捣碎，以酒一升，渍经一宿，每服饮两杯，日三服。（《肘后方》） ⒄治消渴不止，下元虚损：牛膝五两，细判，为末，生地黄汁五升，浸，昼曝夜浸，汁尽为度，蜜丸桐子大，空心温酒下三十丸。（《经验后方》）' where id=1958; -- 牛膝
update herbs set taste='辛，温，有毒。' where id=1959; -- 闹羊花
update herbs set taste='苦涩，寒。', channel='肝；胃经。', effect='治闷瘄：茄梗（伏月采，风干），房中焚之；内用普洱茶二钱，煎服，少顷尽出。（《百草镜》）' where id=1960; -- 普洱茶
update herbs set taste='甘咸；凉；无毒。', channel='入肺、胃经。', effect='①治气闭痰结火结，喉胀不通：蓬砂一钱。放口中噙化（《方脉正宗》） ②治咽喉肿痛：蓬砂、白梅等分。捣丸芡子大。每噙化一丸。（《经验方》破棺丹） ③治咽喉肿痛及走马喉痹：蓬砂、马牙硝各一分，丹砂半分，斑蝥二枚（去头、翅、足，炒）。上四味，共研为末，以生姜自然汁煮面糊，和丸如梧桐子大，腊茶为衣。每服二丸，腊茶下。（《圣济总录》蓬砂丸） ④治缠喉风，风热喉痹：硼砂（生研）、白矾（生研）各一钱，西牛黄、人爪甲（焙脆，研）各一分。为极细末，以烂白霜梅肉三钱，研糊分作四丸，噙化，取涌顽痰。（《张氏医通》硼砂丹） ⑤治咽喉口齿新久肿痛及久嗽痰火咽哑作痛：玄明粉、硼砂各五钱，朱砂六分，冰片五分。共研极细末，吹搽患上，甚者日搽五、六次。（《外科正宗》冰硼散） ⑥治舌肿胀：好硼砂为细末，用薄批生姜蘸药揩舌肿处，少时即退。（《普济方》） ⑦治口臭、口干，口舌疮：硼砂二两，片脑、麝香各一钱，马牙硝（风化）四两，寒水石（煅）十两。上为细末，用甘草膏和丸，如麻子大，不拘时含一丸咽津。（《奋效良方》硼砂丸） ⑧治鹅口疮：硼砂二钱，雄黄三钱，甘草一钱，冰片二分五厘。上为细末，蜜水调涂或干掺。（《疡医大全》四宝丹） ⑨治噎食：荞麦秸烧灰淋汁，入锅内，煎取白霜一钱，入蓬砂一钱，研末，每酒服半钱。（《海上方》） ⑩解毒禽。并治恶疮疔毒：蓬砂四两，研细，真菜油一斤，瓶内浸之。遇有毒者，服油一小盏。（《本草汇言》） ⑾治慢性气管炎：硼砂、南星、白芥子各等量，共研细末。每日二次，每服六分。（内蒙古《中草药新医疗法资料选编》） ⑿治诸蛇咬痛肿：硼砂一两。研细为末，以园内生蒌葱，就上取却葱角尖，倾入硼砂末，却以角尖覆一七日，握出葱，倾硼砂汁于一张紧薄纸上，阴干。每在伤处，取钱孔大纸贴之。（《普济方》硼砂散） ⒀治腰部扭伤：西月石（法制）粉末少许，于晚上临睡前，放于目内眦角上，左侧扭伤点右眼角，右侧扭伤点左眼角。一般一至三次见效。放药后可能会流泪。（《浙江中医杂志》9（1）：24，1966） ⒁住痛解毒丸（《医部全录-目门》）治目痛肿胀：硼砂150g，川芎、荆芥、朴硝、白芷、石膏、菊花各30g，没药15g，麝香少许。上为细末，米糊丸，梧桐子大，温汤下。方中硼砂清热解毒，为君药。 ⒂乾咽妙功丸（《奇效良方》）治膈气，咽喉噎塞，咳嗽上气，痰盛喘满，气道痞滞，不得升降：硼砂6g，丹砂12g，巴豆霜9g，益智仁、官桂15g。上各别研为极细末，搅和匀，用糯米粥为丸，如麻子大。每服1-2丸，食后临寝干咽下。方中硼砂清热解毒，清热化痰，为君药。' where id=1961; -- 硼砂
update herbs set taste='酸；淡；平。', effect='①治感冒，消化不良，腹胀：布渣叶五钱至一两。水煎服。（广州部队《常用中草药手册》） ②治黄疸：破布叶二两，猪血四两。煎水服，一日一次，连服六日。（《岭南草药志》） ③治蜈蚣咬伤：布渣叶五钱至一两。水煎服。（广州部队《常用中草药手册》）', tips='清热利湿；健胃消滞。主感冒发热；黄疸；食欲不振；消化不良；脘腹胀痛；泄泻；疮疡；蜈蚣咬伤。用于感冒，中暑，食滞，消化不良，腹泻。 ①《本草求原》：解一切蛊胀药毒，清热，消积食，黄疸。 ②《陆川本草》：收敛去腐。治小儿盗汗；溃疡，煎汤外洗。' where id=1962; -- 破布叶
update herbs set effect='①治头风，鼻流清涕：枇杷花、辛夷等分。研末，酒服二钱，日二服。（《纲目》） ②治枯痨咳嗽，痰中带黑血：枇杷花二钱，鲜地棕根四两，珍珠七二两，石竹根二两，淫羊藿二两。炖肉服。（《重庆草药》）', tips='疏风止咳，通鼻窍。主感冒咳嗽，鼻塞流涕，虚劳久嗽，痰中带血。 ①《贵州民间方药集》：花蒸蜂蜜，治伤风感冒，润喉止咳。 ②《民间常用草药汇编》：治寒咳。' where id=1963; -- 枇杷花
update herbs set taste='甘辛，凉。', channel='入肝、心经。', effect='1.（湖南医药杂志，1982，（3）：6）主治冠状动脉粥样硬化性心脏病。取生蒲黄适量，每次3克，每天3次，口服，连服2个月。方中蒲黄活血、降脂。 2.蒲黄散（《千金要方》）治漏下不止：蒲黄10克，鹿茸、当归各60克。下筛，酒服5克，每日3次。 3.．蒲黄酒（《大同方剂学》）治风虚水气，通身肿及暴肿等症：蒲黄、小豆、大豆各10克。上3味，以清酒一斗，煮取3升，去豆，分3次服 4.治妇人月候过多，血伤漏下不止：蒲黄三两（微炒），龙骨二两半。艾叶一两。上三味，捣罗为末，炼蜜和丸，梧桐子大。每服二十丸，煎米饮下，艾汤下亦得，日再。（《圣济总录》蒲黄丸） 5.治产后血不下：蒲黄三两。水三升，煎取一升，顿服。（《梅师集验方》） 6.治产后恶露不快，血上抢心，烦闷满急，昏迷不省，或狂言妄语，气喘欲绝：干荷叶（炙）、牡丹皮、延胡索、生干地黄、甘草（炙）各三分，蒲黄（生）二两。上为粗末。每服二钱，水一盏，入蜜少许，同煎至七分，去滓温服，不拘时候。（《局方》蒲黄散） 7.治产后心腹痛欲死：蒲黄（炒香）、五灵脂（酒研，淘去砂土）各等分。为末，先用酽醋，调二钱，熬成膏，入水一盏，煎七分，食前热服。（《局方》失笑散） 8.催生：蒲黄、地龙（洗去土，于新瓦上焙令微黄）、陈橘皮等分。各为末，如经日不产，各抄一钱匕，新汲水调服。（《证类本草》） 9.治坠伤扑损，瘀血在内，烦闷者：蒲黄末，空心温酒服三钱。（《塞上方》） 10.治吐血、唾血：蒲黄一两。捣为散，每服三钱，温酒或冷水调。（《简要济众方》） 11.治肺热衄血：蒲黄、青黛各一钱。新汲水服之。或去青黛，入油发灰等分，生地黄汁调下。（《简便单方》） 12.治鼻衄经久不止：蒲黄二、三两，石榴花一两（末）。上药，和研为散，每服以新汲水调下一钱。（《圣惠方》） 13.治膀胱热，小便血不止：蒲黄（微炒）二两，郁金（锉）三两。上二味，捣罗为散，每服一钱匕，粟米饮调下，空心晚食前服。（《圣济总录》蒲黄散） 14.治卒下血：甘草、干姜、蒲黄各一分。三物下筛，酒服方寸匕，日三。（《僧深集方》蒲黄散） 15.治舌胀满口，不能出声：蒲黄频掺。（《本事方》） 16.治小儿重舌，口中生疮，涎出：蒲黄一分，露蜂房一分（微炙），白鱼一钱。上药，都研令匀。用少许酒凋，敷重舌、口中疮上，日三用之。（《圣惠方》蒲黄散） 17.治聤耳出脓：蒲黄末，掺之。（《圣惠方》） 18.治耳中出血：蒲黄、炒黑研末，掺入。（《简便单方》） 19.治脱肛：蒲黄二两。以猪脂和敷肛上，纳之。（《千金方》） 20.治阴蚀：蒲黄二两，桐皮二两，甘草二两。凡三物，捣筛，粉创上。（《令李方》蒲黄散） 21.治丈夫阴下湿痒：蒲黄末敷之。（《千金方》）' where id=1964; -- 蒲黄
update herbs set taste='甘；酸；平。', channel='入肺、脾、肾经。', effect='①强肾：琐琐葡萄、人参各一钱。火酒浸-宿，侵晨涂手心，摩擦腰脊，能助膂力强壮，若卧时摩擦腰脊，力能助肾坚强，服之尤为得力。（《本经逢原》） ②治热淋，小便涩少，碜痛沥血：葡萄（绞取汁）五合，藕汁五合，生地黄汁五合，蜜五两。上相和，煎为稀饧，每于食前服二合。（《圣惠方》葡萄煎） ③除烦止渴：生葡萄捣滤取汁，以瓦器熬稠，入熟蜜少许，同收，点汤饮。（《居家必用率类全集》） ④治吹乳：葡萄一枚，于灯焰上燎过，研细，热酒调服。（《圣济总录》葡萄洒） ⑤治牙龈肿痛，势欲成痈者：葡萄干去核，填满焰硝煅之。焰过，取置地上成炭，研末擦之，涎出，任吐自瘥。（《医级》葡硝散）' where id=1965; -- 葡萄
update herbs set taste='味苦；甘；性寒。', channel='入肝、胃经。', effect='①治乳痈：蒲公英（洗净细锉），忍冬藤同煎浓汤，入少酒佐之，服罢，随手欲睡，是其功也。（《本草衍义补遗》） ②治急性乳腺炎：蒲公英二两，香附一两。每日一剂，煎服二次。（内蒙古《中草药新医疗法资料选编》） ③治产后不自乳儿，蓄积乳汁，结作痈：蒲公英捣敷肿上，日三、四度易之。（《梅师集验方》） ④治瘰疬结核，痰核绕项而生：蒲公英三钱，香附一钱，羊蹄根一钱五分，山茨菇一钱，大蓟独根二钱，虎掌草二钱，小一枝箭二钱，小九古牛一钱。水煎，点水酒服。（《滇南本草》） ⑤治疳疮疔毒：蒲公英捣烂覆之，别更捣汁，和酒煎服，取汗。（《纲目》） ⑥治急性结膜炎：蒲公英、金银花。将两药分别水煎，制成两种滴眼水。每日滴眼三至四次，每次二至三滴。（《全展选编·五官》） ⑦治急性化脓性感染：蒲公英、乳香、汉药、甘草，煎服。（《中医杂志》（11）：31，1965） ⑧治多年恶疮及蛇螫肿毒：蒲公英捣烂，贴。（《救急方》） ⑨治肝炎：蒲公英干根六钱，茵陈蒿四钱，柴胡、生山栀、郁金、茯苓各三钱。煎服。或用干根、天名精各一两，煎服。 ⑩治胆囊炎：蒲公英一两。煎服。 ⑾治慢性胃炎、胃溃疡：蒲公英干根、地榆根各等分，研末，每服二钱，一日三次，生姜汤送服。（⑨方以下出《南京地区常用中草药》） ⑿治胃弱、消化不良，慢性胃炎，胃胀痛：蒲公英一两（研细粉），橘皮六钱（研细粉），砂仁三钱（研细粉）。混合共研，每服二至三分，一日数回，食后开水送服。（《现代实用中药》）' where id=1966; -- 蒲公英
update herbs set taste='味辛；性平。', channel='入脾、胃经。', effect='①治脾瘅口甘：兰草（煎汤服）。（《素问》） ②治五月霉湿，并治秽浊之气：藿香叶一钱，佩兰叶一钱，陈广皮一钱五分，制半夏一钱五分，大腹皮一钱（酒洗），厚朴八分（姜汁炒），加鲜荷叶三钱为引。煎汤服。（《时病论》芳香化浊法） ③治秋后伏暑，因新症触发：藿香叶一钱五分，佩兰叶二钱，薄荷叶-钱，冬桑叶二钱，大青叶三钱，鲜竹叶三十片。先用青箬叶一两，活水芦笋二两，煎汤代水。（《增补评注温病条辨》七叶芦根汤） ④治温暑初起，身大热，背微恶寒，继则但热无寒，口大渴，汗大出，面垢齿燥，心烦懊憹：藿香叶-钱，薄荷叶一钱，佩兰叶一钱，荷叶一钱。先用枇杷叶一两，水芦根一两，鲜冬瓜二两，煎汤代水。（《重订广温热论》五叶芦根汤）' where id=1967; -- 佩兰
update herbs set taste='苦、辛；寒；无毒。', channel='入肺、胃经。', effect='①治咳嗽，喉中有痰声：枇杷叶五钱，川贝母一钱五分，叭旦杏仁二钱，广陈皮二钱。共为末，每服一、二钱，开水送下。（《滇南本草》） ②治妇人患肺热久嗽，身如炙，肌瘦，将成肺痨：枇杷叶、木通、款冬花、紫菀、杏仁、桑白皮各等分，大黄减半，各如常制，治讫。同为末，蜜丸如樱桃大。食后夜卧，各含化一丸。（《本草衍义》） ③治声音嘶哑：鲜枇杷叶一两，淡竹叶五钱。水煎服。（《福建中草药》） ④治温病有热，饮水暴冷啘：枇杷叶（拭去毛）、茅根各半升。上二味切，以水四升，煮取二升，稍稍饮之，啘止则停。（《古今录验方》枇杷叶饮子） ⑤治哕逆不止，饮食不入：枇杷叶（拭去毛，炙）四两，陈橘皮（汤浸去白，焙）五两，甘草三两（炙，锉）。上三味粗捣筛。每服三钱匕，水一盏，入生姜一枣大，切，同煎至七分，去滓稍热服，不拘时候。（《圣济总录》枇杷叶汤） ⑥治小儿吐乳不定：枇杷叶一分（拭去毛；微炙黄），母丁香一分。上药捣细罗为散，如吐者，乳头上涂一字，令儿咂便止。（《圣惠方》枇杷叶散） ⑦治衄血不止：枇杷叶，去毛，焙，研末，茶服一、二钱，日二。（《圣惠方》） ⑧治肺风鼻赤酒齄：枇杷叶，去毛，焙干末之，茶调下一。二钱，日三服。（《本事方》） ⑨治痘疮溃烂：枇杷叶煎汤洗之。（《摘元方》）' where id=1968; -- 枇杷叶
update herbs set taste='苦，凉。', channel='归肝经。', effect='①治风热泪眼：青葙子五钱，鸡肝炖服。（《泉州本草》） ②治夜盲，目翳：青葙子五钱，乌枣一两。开水冲炖，饭前服。（《闽东本草》） ③治鼻衄出血不止：青葙子汁灌鼻中。（《广利方》） ④治头风痛：青葙子五钱至一两。煎水服。（《福建中草药》）' where id=1969; -- 青葙子
update herbs set alias='嘉宾（崔豹《古今注》），家雀，瓦雀，宾雀，麻禾雀，树麻雀、老家贼、只只，查母塞刀姆（朝名）。', taste='甘，温。', channel='归肾；肺；膀胱经', effect='①治老人脏腑虚损羸瘦，阳气乏弱：雀儿五只（治如食法），粟米一合，葱白三茎（切）。将雀儿炒热，次入酒一合，煮少时，入水二盏半，下米作粥欲熟，下葱白五味等，候熟空心食之。（《养老奉亲书》） ②治肾冷偏坠、疝气：生雀三枚，燎毛去肠，勿洗，以舶上茴香三钱，胡椒一钱，缩砂、肉桂各二钱，入肚内，湿纸裹，煨熟，空心服之，酒下。（《仁斋直指方》） ③治小肠气疼痛：带毛雀儿，取去肠肚，将金丝矾研细，装放雀儿肚满，缝合，用桑柴火缓缓煨烧成炭，研为细末，空心用无灰酒调下。恐恶心，入盐汤少许。年远者每服二枚，近者一枚。（《瑞竹堂经验方》飞黄丹） ④治眼昏，翳赤涩，远视似有黑花，及内障不见物：肉苁蓉（酒浸一宿，刮去皱皮，炙干），雀儿十个（去毛嘴爪翅足，存肠胃，去骨烂研），磁石（烧，醋淬七遍，细研，水飞过）、神曲（炒微黄）、青盐各一两，菟丝子二两（酒浸三日，曝干，别捣为末）。上药捣罗为末，以好酒二升，入少炼熟蜜，入雀肉及盐，研令极烂成膏，和诸药，丸如梧桐子大。每于空心及晚食前，以温酒下二十丸服。（《圣惠方》肉苁蓉丸） ⑤治痢疾：腊月雀儿，割开肠肚，皮共毛全，去皮巴豆一个，放在内，到沙石罐内盛，顿炭火烧作黑，研细，另用好酒煮黄蜡百十沸，将蜡取出，磁盏内化开黄蜡，即与雀儿末一处为丸，每服一、二十丸，不拘时候。如红痢甘草汤下，白痢干姜汤下，花红痢甘草、干姜汤下。（《普济方》） ⑥治百日咳：麻雀肉一只，冰糖三钱。炖熟，每服一只。（《吉林中草药》）' where id=1970; -- 麻雀肉
update herbs set taste='苦，辛，温。', channel='归肝、肾经。', effect='1．固精强骨：千年健、远志肉、白茯神、当归身各等分。为末，炼蜜丸，梧子大，每酒服50丸。方中千年健祛风湿，强筋骨，为君药。（《瀕户籍简方》） 2．治体弱老人寒湿膝痛、腰痛，尤其腰脊僵硬疼痛，屈伸不便者：千年健、川牛膝、海风藤、宣木瓜各9g，桑枝15g，杜仲9g，秦艽、桂枝各6g，熟地12g，当归身9g，虎骨胶（溶化）6g。水煎服。方中千年健祛风湿，强筋骨，止痹痛，为君药。（《贵州草药》） 3．治由于风寒湿邪引起的痹症，腰腿酸痛，四肢麻木，身体沉重，及跌打损伤，血瘀疼痛等症：千年检、没药、自然铜、钻地风、桂枝、牛膝、木瓜、甘草、杜仲、防风、羌活、独活各9g，马钱子（砂烫去毛）90g，乳香（醋炙）9g，麻黄120g。上共轧为细粉，炼蜜为丸，每丸重6g（含药量约2.4g）每服1丸，日服2次，温开水送下。孕妇忌服。方中千年健祛风湿，强筋骨，止痹痛，为君药。（疏风定痛丸《北京市中药成方选集》）' where id=1971; -- 千年健
update herbs set taste='苦、涩，微寒。', effect='1．拳参汤（《证治准绳》）治阴虚久咳，肺痨，喘嗽。拳参9g，蜜百合9g，沙参6g，炙甘草6g，水煎服。方中拳参清热解毒，收敛渗湿，为君药。 2．感冒退热冲剂：冲剂。主要成分为大青叶、板蓝根、拳参、连翘。有清热解毒的功能。用于上呼吸道感染，急性扁桃体炎、咽喉炎。开水冲服，一次18-36g，一日3次。方中拳参清热解毒，收敛渗湿，消肿，为君药。 3．验方：治肠炎、赤白痢疾。拳参30g，水煎服。方中拳参清热解毒，收敛渗湿，消肿止血，为君药' where id=1972; -- 拳参
update herbs set taste='苦；性寒。', channel='归心；肝；小肠；膀胱经。', effect='①治小便赤涩，或癃闭不通，及热淋血淋：瞿麦、萹蓄、车前子、滑石、山栀子仁、甘草（炙）、木通、大黄（面裹煨，去面切焙）各一斤。上为散。每服二钱，水一盏，入灯心，煎至七分，去渣，食后临卧温服。小儿量力少少与之。（《局方》八正散） ②治小便不利者，有水气，其人苦渴：栝蒌根二两，茯苓、薯蓣各三两，附子一枚（炮），瞿麦一两。上五味，末之，炼蜜丸梧子大；饮服三丸，日三服，不知，增至七、八丸，以小便利，腹中温为知。（《金匮要略》栝蒌瞿麦丸） ③治下焦结热，小便黄赤，淋闭疼痛，或有血出，及大小便俱出血者：山栀子（去皮，炒）半两，瞿麦穗一两，甘草（炙）三分。上为末。每服五钱至七钱，水一碗，入连须葱根七个，灯心五十茎，生姜五、七片，同煎至七分，时时温服。（《局方》立效散） ④治鱼脐毒疮肿：瞿麦，和生油熟捣涂之。（《崔氏纂要方》） ⑤治血妄行，九窍皆出，服药不住者：南天竺草（生瞿麦）拇指大一把（锉），大枣（去核）五枚，生姜一块（如拇指大），灯草如小指大一把，山栀子三十枚（去皮），甘草（炙）半两。上六味锉，入瓷器中，水一大碗，煮至半碗，去滓服。（《圣济总录》南天竺饮） ⑥治目赤肿痛，浸淫等疮：瞿麦炒黄为末，以鹅涎调涂眦头，或捣汁涂之。（《圣惠方》）', tips='脾、肾气虚及孕妇忌服。 ①《品汇精要》：妊娠不可服。 恶桑螵蛸。 ③《本草经疏》：凡肾气虚，小肠无大热者忌之；胎前产后一切虚人，患小水不利，法并禁用；水肿蛊胀，脾虚者不得施。' where id=1973; -- 瞿麦
update herbs set taste='苦微辛，寒。', channel='入肝、胆经。', effect='①治牙齿肿痛：青蒿一握，煎水漱之。（《济急仙方》） ②治虚劳，盗汗、烦热、口干：青蒿一斤，取汁熬膏，入人参末、麦冬末各一两，熬至可丸，丸如梧桐子大。每食后米饮下二十丸。（《圣济总录》青蒿丸） ③治骨蒸劳，体瘦、发渴、寒热：青蒿一斤（取叶曝干，捣罗为末），桃仁一斤（酒浸，去皮尖，麸炒令黄.研烂），甘草半（五）两（生捣罗为末）。另以童子小便三斗，于瓷瓮中盛，于糠火上煎令如稀饧，却倾于铜器中，下诸药，又于糠火上煎，以柳木篦搅之，看稀稠得所，候可丸，即丸如梧桐子大，以粗疏布袋盛。每日空心温童子小便下三十丸，日晚再服。（《圣惠方》青蒿圆） ④治温病夜热早凉，热退无汗，热自阴来者：青蒿二钱，鳖甲五钱，细生地四钱，知母二钱，丹皮三钱。水五杯，煮取二杯，日再服。（《温病条辨》青蒿鳖甲汤） ⑤治赤白痢下：青蒿、艾叶等分。同豆豉捣作饼，日干。每用一饼，以水一盏半煎服。（《圣济总录》蒿豉丹） ⑥治虚劳久疟：青蒿捣汁，煎过，如常酿酒饮。（《纲目》青蒿酒） ⑦治少阳三焦湿遏热郁，气机不畅，胸痞作呕，寒热如疟者：青蒿脑钱半至二钱，淡竹茹三钱，仙半夏钱半，赤茯苓三钱，青子芩钱半至三钱，生枳壳钱半，陈广皮钱半，碧玉散（包）三钱。水煎服。（《通俗伤寒论》蒿芩清胆汤） ⑧治鼻中衄血：青蒿捣汁服之，并塞鼻中。（《卫生易简方》） ⑨治劳瘦：青蒿（细锉）嫩者一升，以水三升，童子小便五升，同煎成膏，丸如梧桐子大。每服十丸，温酒下，不以时。（《鸡峰普济方》青蒿煎） ⑩治阑尾炎、胃痛：青蒿、毕拨等量。先将青蒿焙黄，共捣成细末。早、午、晚饭前白开水冲服，每次二克。（内蒙古《中草药新医疗法资料选编》） ⑾治疟疾寒热：青蒿一握，以水二升渍，绞取汁，尽服之。（《补缺肘后方》） ⑿治酒痔便血：青蒿（用叶不用茎，用茎不用叶）为末，粪前（便血用）冷水、粪后（便血用）水酒调服。（《永类钤方》） ⒀治温疟痰甚，但热不寒：青蒿二两（童子小便浸焙），黄丹半两。为末。每服二钱，白汤调下。（《仁存堂经验方》） ⒁治少阳疟疾，暮热早凉，汗解渴饮，脉左弦，偏于热重者：青蒿三钱，知母二钱，桑叶二钱，鳖甲五钱，丹皮二钱，花粉二钱。水五杯，煮取二杯。疟来前，分二次温服。（《温病条辨》青蒿鳖甲汤） ⒂治暑毒热痢：青蒿叶一两，甘草一钱。水煎服。（《圣济总录》） ⒃治聤耳脓血出不止：青蒿捣末，绵裹纳耳中。（《圣惠方》） ⒄治蜂螯人：青蒿捣敷之。（《补缺肘后方》） ⒅治金疮扑损：㈠青蒿捣封之。㈡青蒿、麻叶、石灰等分。捣和晒干，临时为末搽之。（《肘后方》）' where id=1974; -- 青蒿
update herbs set taste='辛，寒，有毒。', channel='入肝、肾经。', effect='①治诸疥疮：轻粉五钱匕，吴茱萸一两，赤小豆四十九粒，白蒺藜一两，白芜荑仁半两，石硫黄少许。上六味，捣研为散，令匀。每用生油调药半钱匕，于手心内摩热后，遍揩周身有疥处，便睡。（《圣济总录》神捷散） ②治人面上湿癣：轻粉、斑猫（去翅、足）。上研细，用温水以鸡翎扫之周围。（《普济方》轻粉散） ③治小儿生癣：猪脂和轻粉抹之。（《仁斋直指方》） ④治小儿头疮：葱汁调腻粉涂之。（《濒湖集简方》） ⑤治风虫牙疳，脓血有虫：轻粉一钱，黄连一两。为末掺之。（《普济方》） ⑥治杨梅疮癣：汞粉、大风子肉。等分为末，涂之。（《岭南卫生方》） ⑦治杨梅疮毒：轻粉、胡桃仁、槐花（炒，研）、红枣内各二钱（轻粉宜减量）。捣丸。分作三服，初日鸡汤下，二日酒下，三日茶下。三日服尽。（《杨诚经验方》） ⑧治杨梅：血丹、轻粉各等分。猪胆汁调搓。（《疡医大全》） ⑨治下疳阴疮：轻粉末干掺之。（《积善堂经验方》） ⑩治臁疮不合：轻粉五分，黄蜡一两。以粉掺纸上，以蜡铺之。敷在疮上，黄水出。（《永类钤方》） ⑾治小儿涎喘：无雄鸡子一个。用鸡子清入轻粉一分（宜减量），拌匀，银器盛置汤瓶上蒸熟，三岁儿食尽，当吐痰或泄。壮实者乃可用。（《串雅内编》轻粉顶） ⑿治水气肿满：汞粉一钱（乌鸡子去黄盛粉，蒸饼包，蒸熟取出），苦葶苈（炒）一钱。同蒸饼杵丸绿豆大。每车前汤下三、五丸，日三服。（《医垒元戎》） ⒀治血痢：腻粉五钱，定粉三钱。同研匀，用水浸蒸饼心少许，和为丸如绿豆大。每服七丸或十丸，艾一枝，水一盏，煎汤下。艾汤多亦妙。（《秘宝方》） ⒁治大小便关格不通，腹胀喘急：腻粉一钱（宜减量），生麻油一合。相合，空腹服之。（《圣惠方》） ⒂治大便不通，十月秘者：枣一枚（去核），腻粉一钱（宜减量）。上以腻粉纳于枣中，和白面裹之，于火上炙令熟，碾罗为末。以煎汤调，顿服之。（《圣惠方》）' where id=1975; -- 轻粉
update herbs set taste='苦辛，寒，有毒。', channel='入肺，肾，大、小肠经。', effect='①治水肿:牵牛子末之，水服方寸匕，日一，以小便利为度。（《千金方》） ②治停饮肿满:黑牵牛头末四两，茴香一两（炒），或加木香一胡。上为细末，以生姜自然汁调一、二钱，临卧服。（《儒门事亲》禹功散） ③治水气蛊胀满:白牵牛、黑牵牛各二钱。上为末，和大麦面四两，为烧饼，临卧用茶汤一杯下，降气为验。（《宣明论方》一气散） ④治小儿腹胀，水气流肿，膀胱实热，小便赤涩:牵牛生研一钱。青皮汤空心下。一加木香减半，丸服。（《郑氏小儿方》） ⑤治四肢肿满:厚朴（去皮，姜汁制炒）半两，牵牛子五两（炒取末二两）。上细末。每服二钱，煎姜、枣汤调下。（《本事方》） ⑥治小儿肺胀喘满，胸高气急，两肋扇动，陷下作坑，两鼻窍张，闷乱嗽渴，声嗄不鸣，痰涎潮塞，俗云马脾风:白牵牛一两（半生半熟），黑牵牛，-两（半生半熟），川大黄、槟榔各一两。上为细末。三岁儿每服二钱，冷浆水调下，涎多加腻粉少许，无时，加蜜少许。（田氏《保婴集》牛黄夺命散） ⑦治脚气胫已满，捏之没指者:牵牛子，捣，蜜丸，如小豆大五丸，吞之。（《补缺肘后方》） ⑧治一切虫积:牵牛子二两（炒，研为束），槟榔一两，使君子肉五十个（微炒）。俱为末。每服二钱。沙糖调下，小儿减半。（《永类铃方》） ⑨治大肠风秘壅热结涩:牵牛子（黑色，微炒，捣取其中粉）一两，桃仁（末）半两。以熟蜜和丸如梧桐子。温水服三、二十丸。（《本草衍义》） ⑩治冷气流注，腰疼不能俯仰:延胡索二两，破故纸（炒）二两，黑牵牛子三两（炒）。上为细末，煅大蒜研搜丸，如梧桐子大。每服三十丸，煎葱须盐汤送下，食前服。（《杨氏家藏方》牵牛丸） ⑾治肾气作痛:黑、白牵牛等分。炒为末，每服三钱，用猪腰子切，入茴香百粒，川椒五十粒，掺牵牛末入内扎定，纸包煨熟，空心食之。酒下，取出恶物效。（《仁斋直指方》） ⑿治肠痈有脓，胀闭不出:牵牛子头末三钱，大黄二钱，穿山甲（煅）二钱，乳香、汉药各一钱。俱为末。每服三钱，白汤调服。（《张三丰仙传方》） ⒀治梅毒，横痃:白牵牛仁，每次五、六钱，煎汤内服。（《泉州本草》） ⒁治风热赤眼:黑丑仁为末，调葱白汤敷患处。（《泉州本草》）' where id=1976; -- 牵牛子
update herbs set taste='味辛、苦；性寒；小毒。', channel='入肺、胃经。', effect='①治肠炎，腹痛下痢：土青木香三钱，槟榔一钱五分，黄连一钱五分。共研细末。每次三至六分，开水冲服。（《现代实用中药》） ②治中暑腹痛：青木香根（鲜）三至五钱。捣汁，温开水送服；亦可用青木香根一至二钱，研末，温开水送服。（《江西草药》） ③治高血压：青木香根（鲜）二两。水煎服，红糖为引。（《江西草药》） ④治毒蛇咬伤：土青木香一两，香白芷二两。共研末，每用三钱，甜酒或温开水送服；另用不拘量，调敷伤口处。（《中医药实验研究》） ⑤治蛇咬及粪毒：肯木香、雄黄。共研末。调酒擦局部。（《四川中药志》） ⑥治疔肿复发：马兜铃根捣烂，用蜘蛛网裹敷。（《肘后方》） ⑦治指疔：鲜青木香，切碎，同适量的蜂蜜捣烂，敷于患处。（《江西民间草药验方》） ⑧治皮肤湿烂疮：青木香，研成细末，用麻油调搽。（《江西民间草药验方》） ⑨治蜘蛛疮（单纯疱疹）：土青木香，研极细末，柿漆（即柿油）调涂。（《中医药实验研究》） ⑩治牙痛：青木香鲜品一块，放牙痛处咬之。（《东北常用中草药手册》） ⑾治胸闷憋气、心绞痛：青木香、苏合香、冰片、乳香、檀香各等分。方中青木香理气宽胸、止痛，为君药。（《全国中草药》冠心苏合丸）' where id=1977; -- 青木香
update herbs set taste='苦辛，微温。', channel='入肝、胆经.', effect='①治肝气不和，胁肋刺痛如击如裂者：青橘皮八两（酒炒），白芥子、苏子各四两，龙胆草、当归尾各三两。共为末，每早晚各服三钱，韭菜煎汤调下。（《方脉正宗》） ②治心胃久痛不愈、得饮食米汤即痛极者：青皮五钱，玄胡索三钱（俱醋拌炒），甘草一钱，大枣三个。水煎服。（《方脉正宗》） ③治食痛、饱闷、噫败卵气：青皮、山查、神曲、麦芽、草果。为丸服。（《沈氏尊生书》青皮丸） ④治疝气冲筑，小便牵强作痛：青橘皮八两（醋炒），胡芦巴二两，当归、川芎、小茴香各一两（俱酒洗炒）。研为末，每早服三钱，白汤调下。（《方脉正宗》） ⑤治疟疾寒热：青皮一两（烧存性）。研末，发前温酒服一钱，临时再服。（《圣惠方》） ⑥治因久积忧郁，乳房内有核如指头，不痛不痒，五、七年成痈，名乳癌：青皮四钱。水一盏半，煎一盏，徐徐服之，日一服，或用酒服。（朱震亨） ⑦治伤寒呃逆：四花青皮（全者），研末。每服二钱，白汤下。（《医林集要》） ⑧治积聚：青皮、陈皮、黄连（姜汁炒）各30g，香附（童便浸）120g，苍术、半夏、针砂（醋炒）各60g，白术、苦参各15g，上为细末，面糊为丸。方中青皮舒肝破气，消积化滞，为君药。（《丹溪心法》小温中丸） ⑨治肝胀，胁下满而痛引小腹：青皮（醋炒）4.5g，柴胡（醋炒），乌药、陈皮、延胡索各3g，炮姜、木香各1.5g，蒺藜12g，郁金6g，花椒子（打碎）24粒。水煎服。方中青皮舒肝破气，消积化滞，为君药。（《圣济总录》青阳汤） ⑩治三焦胀，气满腹中，空空然响：青皮、枳壳、大腹皮各等分。水煎服。若上焦胀加桔梗；中焦胀加苏梗；下焦胀加木通。方中青皮舒肝破气，消积化滞，为君药。（《症因脉治》枳壳青皮饮）' where id=1978; -- 青皮
update herbs set effect='1．治吐血燥渴。《圣济总录》：用茜根、雄黑豆祛皮，炙甘草等份，研末，井水糊丸如弹子大，每次温水化服一丸。 2．黑髭乌发茜草500克，生地黄1500克取汁，用水五大碗，煎茜草绞汁，将渣再煎三次，用汁同地黄汁微火煎成膏，瓶装；每日空腹温酒服半匙，一月髭发如黑漆，忌萝卜，五辛。 3．鼻血不止《本事方》：茜根、艾叶各50克，乌梅肉15克，研末，炼蜜丸如梧桐子大，每次乌梅汤送服五十丸。 4．五十岁行经《唐药经验方》：妇人五十后，经水不止，作败血论。用茜根，又名过山姜50克，阿胶、侧柏叶、炙黄芩各25克，生地黄50克，小儿胎发一团烧灰，分作六剂，每剂用水一盏半，煎七分，入发灰服。 5．十灰散（《十药神书》）治血热妄行之上部出血。咳血、咯血、吐血，血色鲜红，舌红，脉数。大蓟、消极、荷叶、侧柏叶、白茅根、茜根、山栀、大黄、牡丹皮、棕榈皮各9—15g。温水调服，亦可作汤剂水煎服，食后服下。方中茜草活血化淤，使凉血止血而无留淤之患，为臣药。 6．固冲汤《医学衷中参西录》治妇女血崩及月经过多，色淡质稀，心悸气短，舌淡，脉虚大或细弱。炒白术30g，生黄芪18g，煅龙骨、 煅牡蛎各24g（先煎），山茱萸24g，白芍12g，海螵蛸12g，茜草10g，棕榈炭6g，五倍子（研末冲）1.5g。水煎服。方中茜草活血化瘀，为佐药。' where id=1979; -- 茜草
update herbs set alias='蛙鱼，蛙、长股，田鸡、青鸡，坐鱼、蛤鱼。', taste='味甘；性凉', channel='肺；脾；膀胱经', effect='①治浮肿，咳嗽痰中带血：青蛙一个，砂仁、莱菔子各三钱。置于青蛙腹中，缝好，外用黄泥包裹，烧存性，去泥研末。分作三次，黄酒冲服，日一次。（《吉林中草药》） ②治浮肿：青蛙去内脏，煮熟，加白糖，每次一个，日服一次，连续服用。（《吉林中草药》） ③治腹肿大，动摇有声，皮肤黑色，名水蛊：青蛙二枚（干者，涂酥炙微黄），蝼蛄七枚（干者，微炒），苦葫芦子半两（微炒）。上药，捣细罗为散.每日。空心以温酒调下二钱，三服。（《圣惠方》） ④治噎膈反胃：青蛙七个，泥封，火烧存性，研末，一次服，连服三日。（《吉林中草药》） ⑤治毒痢噤口：水蛙一个，并肠肚捣碎，瓦上烘热，入麝香五分，作饼贴脐上。气通即能进食。（《纲目》） ⑥治急性传染性肝炎：活青蛙二个，鲜仙人掌适量。捣烂，用绿豆面调成膏，贴肝区。（内蒙古《中草药新医疗法资料选编》） ⑦治时行面赤项肿，名虾蟆瘟：金线蛙，捣汁，水调，空腹顿饮。（《本草蒙筌》） ⑧治骨结核：青蛙一个，红糖二两，白酒二两，百部三钱。煮熟后一次食之，每日一次。（内蒙古《中草药新医疗法资料选编》）' where id=1980; -- 青蛙
update herbs set taste='苦辛，凉。', effect='①治漆疮：漆姑草。捣烂，加丝瓜叶汁，调菜油敷。 ②治虫牙：漆姑草叶。捣烂，塞入牙缝。 ③治跌打内伤：漆姑草五钱。水煎服。 ④治蛇咬伤：漆姑草、雄黄捣烂敷。（①方以下出《湖南药物志》） ⑤治瘰疬结核：羊儿草五钱至一两。煎服。外用鲜草捣绒敷。（南川《常用中草药手册》） ⑥治虚汗、盗汗：大龙叶一两。炖猪肉吃。（《贵州草药》） ⑦治咳嗽或小便不利：大龙叶一两。煨水服。（《贵州草药》） （8）治漆疮：漆姑草。捣烂，加丝瓜叶汁，调菜油敷。 （9）治虫牙：漆姑草叶。捣烂，塞入牙缝。 （10）治跌打内伤：漆姑草五钱。水煎服。 （11）治蛇咬伤：漆姑草、雄黄捣烂敷。(①方以下出《湖南药物志》) （12）治瘰疬结核：羊儿草五钱至一两。煎服。外用鲜草捣绒敷。(南川《常用中草药手册》) （13）治虚汗、盗汗：大龙叶一两。炖猪肉吃。(《贵外草药》) （14）治咳嗽或小便不利：大龙叶一两。煨水服。(《贵州草药》)' where id=1981; -- 漆姑草
update herbs set taste='味咸；性寒。', channel='入肝、肺、胃经。', effect='①治伤寒赤斑：青黛二钱。水研服。（《类证活人书》） ②治妊娠伤寒，热郁阳明，热极而发紫黑斑，脉洪数者，若不急治，胎殒在即：真青黛钱半，鲜生地二两（捣汁），生石膏八钱，升麻六分，黄芩二钱，焦栀子三钱，葱头三枚。水煎服。（《重订通俗伤寒论》青黛石膏汤） ③治吐血不止：青黛二钱，新水调下。（《端效方》青金散） ④治咯血：青黛一钱，杏仁四十粒（去皮、尖，以黄明蜡煎黄色，取出研细）。上二件再同研匀，却以所煎蜡少许，熔开和之，捏作钱大饼子。每服，用干柿一个，中破开，入药一饼，合定，以湿纸裹，慢火煨熟，取出，以糯米粥嚼下。（《中藏经》圣饼子） ⑤治咳嗽吐痰，面鼻发红者：青黛（水飞极细，晒干再研用）四钱，蛤粉三钱。二味炼蜜为丸，如指头大。临卧噙三丸。（《医学从众录》青黛蛤粉丸） ⑥治肺经咳嗽有热痰者：青黛、海石、瓜蒌仁、川贝母。（《症因脉治》青黛海石丸） ⑦治小儿惊痫：青黛，量大小，水研服之。（《生生编》） ⑧治产后发狂：四物汤加青黛。水煎服。（《摘元方》） ⑨治胃脘痛，病久成郁，郁则成热：青黛，以姜汁入汤调服。（《医学正传》） ⑩治口舌生疮：青黛一钱，细辛一分，黄柏一分（锉），地骨皮一分，密陀僧一分。上件药，捣细罗为散。每取少许，贴于疮上。有涎即吐之。（《圣惠方》） ⑾治一切热毒，脓窝疮：青黛一两，寒水石一两（煅过，苏为度）。上为细末，用香油调搽。（《普济方》青金散） ⑿治天泡疮：青黛适量，鲜丝瓜叶捣汁调敷患处。加少许菜油调和亦可。（《验方选集》） ⒀治小儿湿癣浸淫疮：白胶香二两（研），蛤粉半两，青黛二钱半。上研匀为细末，干掺疮上。（《田氏保婴集》青金散） ⒁治瘰疬未穿：靛花、马齿苋同捣，日日涂敷。（《简便单方》） ⒂治耳疳出汁：青黛、黄柏末。干搽。（《谈埜翁试验方》） ⒃治烂弦风眼：青黛、黄连。泡汤日洗。（《明目经验方》） ⒄治诸毒虫伤：青黛、雄黄等分。研末，新汲水服二钱。（《古今录验方》）' where id=1982; -- 青黛
update herbs set taste='苦、涩，寒。', channel='归肝、胆、大肠经。', effect='①治热痢下露者：白头翁二两，黄柏三两，黄连三两，秦皮三两。上四味，以水七升，煮取二升，去滓，温服一升。不愈，更服一升。（《伤寒论》白头翁汤） ②治慢性细菌性痢疾：秦皮四钱，生地榆、椿皮各三钱。水煎服。（《河北中药手册》） ③治腹泻：秦皮三钱。水煎加糖，分服。（《黑龙江常用中草药手册》） ④治赤眼及眼睛上疮：秦皮一大两。以清水一大升于白瓷碗中浸，春夏一食久以上，看碧色出，即以箸头缠绵，点下碧汁，仰卧点所患眼中，仍先从大眦中满跟着，微痛不畏，量久三、五度饭间，即侧卧沥却热汁，每日十度以上着，不过两日瘥。忌酢、萝卜（《近效方》） ⑤治麦粒肿，大便干燥：秦皮三钱，大黄二钱。水煎服。孕妇忌服。（《河北中药手册》） ⑥治妇人赤白带下，及血崩不止：秦皮三两，丹皮二两，当归身一两，俱酒洗，炒研为末，炼蜜为丸梧桐子大。每早服五钱，白汤下。（《本草汇言》） ⑦治小儿惊痫发热及变蒸发热：秦皮、茯苓各-钱，甘草五分，灯心廿根。水煎服。（《儿科撮要》） ⑧治牛皮癣：苦榴皮一至二两。加半面盆水煎，煎液洗患处，每天或隔二至三天洗一次。药液温热后仍可用，每次煎水可洗三次。洗至痊愈为止。（《全展选编·皮肤病》）', tips='脾胃虚寒者忌服。 恶茱萸。 ②《药性论》：恶苦瓠、防葵。 ③《本经逢原》：胃虚少食者禁用。' where id=1983; -- 秦皮
update herbs set taste='甘涩，平。', channel='入脾、肾经。', effect='①治梦遗漏精：鸡头肉末、莲花蕊末、龙骨（别研）、乌梅肉（焙干取末）各一两。上件煮山药糊为丸，如鸡头大。每服一粒，温酒、盐汤任下，空心。（《杨氏家藏方》玉锁丹） ②治精滑不禁：沙苑蒺藜（炒）、芡实（蒸）、莲须各二两，龙骨（酥炙）、牡蛎（盐水煮一日一夜，煅粉）各一两。共为末，莲子粉糊为丸，盐汤下。（《医方集解》金锁固精丸） ③治浊病：芡实粉、白茯苓粉。黄蜡化蜜和丸，梧桐子大。每服百丸，盐汤下。（《摘元方》分清丸） ④治老幼脾肾虚热及久痢：芡实、山药、茯苓、白术、莲肉、薏苡仁、白扁豆各四两，人参一两。俱炒燥为末，白汤调服。（《方脉正宗》） ⑤金锁玉关丸(《证治准绳·类方》)，治遗精白浊，心虚不宁。 ⑥暖肾助火汤(《揣摩有得集》)，治房室过度，肾经虚寒而致的缩阳症。 ⑦旺水汤(《辨证录》)，治纵欲过度，梦遗不止，腰足痿弱，骨内酸疼，夜热自汗，终宵不干，肾水涸竭者。 5.易黄汤(《傅青主女科》)，治黄带。' where id=1984; -- 芡实
update herbs set taste='苦；辛；微寒。', channel='入肝、胃、胆经。', effect='①治中风手足阳明经，口眼歪斜，恶风恶寒，四肢拘急：升麻、葛根、甘草（炙）、芍药、人参各半两，秦艽、白芷、防风、桂枝各三钱。上细切。每服一两，水二盏，连须葱白三茎，长二寸，煎至一盏，去滓，稍热服，食后。服药毕，避风寒处卧，得微汗出则止。（《卫生宝鉴》秦艽升麻汤） ②治背痛连胸：秦艽一钱五分，天麻、羌活、陈皮、当归、川芎各一钱，炙甘草五分，生姜三片，桑枝三钱（酒炒）。水煎服。（《医学心悟》秦艽天麻汤） ③治风中经络而痛：羌活一钱五分，当归二钱，川芎一钱，熟地三钱，秦艽、白芍（酒炒）、独活各一钱五分。（《不知医必要》秦艽汤） ④治黄：秦艽一大两。细锉，作两贴子，以上好酒一升，每贴半升，酒绞取汁，去滓。空腹分两服，或利便止。（《海上集验方》） ⑤治黄疸，皮肤眼睛如金黄色，小便赤：秦艽五两，牛乳三升。煮取一升，去滓。内芒硝一两服。（孙思邈） ⑥治虚劳潮热，咳嗽，盗汗不止：秦艽（去苗、土）、柴胡（去苗）、知母、甘草（锉、炙）各一两。上四味，粗捣筛。每服三钱匕，水一盏，煎至六分，去滓，温服，不计时候。（《圣济总录》秦艽汤） ⑦治骨蒸壮热，肌肉消瘦，唇红，颊赤，气粗，四肢困倦，夜有盗汗：柴胡、鳖甲（去裙，酥炙，用九肋者）、地骨皮各一两，秦艽、当归、知母各五钱。上六味，为粗末。每服五钱，水一盏，青蒿五叶，乌梅一个，煎至七分，去滓温服，空心、临卧，各一服。（《卫生宝鉴》秦艽鳖甲散） ⑧治消渴，除烦躁：秦艽二两（去苗），甘草三分（炙微赤，锉）。上件药，捣筛为散。每服四钱，以水一中盏，入生姜半分，煎至六分，去滓，不计时候温服。（《圣惠方》） ⑨治小便艰难，胀满闷：秦艽一两（去苗）。以水一大盏，煎取七分，去滓，食前分作二服。（《圣惠方》） ⑩治疮口不合：秦艽为末掺之。（《仁斋直指方》） ⑾治发背疑似者：秦艽，牛乳煎，当得快利三、五行。（《海上集验方》）', tips='久痛虚羸，溲多、便滑者忌服。 ②《药性论》：畏牛乳。 ③《本草经疏》：下部虚寒人，及小便不禁者勿服。 ④《本草汇言》：凡病阴虚血燥，精竭髓衰之证，非配大剂滋养药不可。 ⑤《本草从新》：大便滑者忌用。' where id=1985; -- 秦艽
update herbs set taste='味辛；苦；性温。', channel='入膀胱、肾经。', effect='①治感冒发热，扁桃体炎：羌活四至五钱，板蓝根、蒲公英各一两。水煎，每日一剂，分二次服。（上海中医学院附属龙华医院） ②治太阳伤寒无汗：羌活、独活、荆芥、防风、广皮、甘草。煎服。（《医级》羌活汤） ③解牙临寒：羌活、防风、苍术、细辛、川芎、白芷、生地、黄芩、甘草。水煎服，若急汗热服，以羹粥投之，若缓汗温服，而不用汤投之。（张元素九味羌活汤） ④治太阳经头痛：防风二分，羌活三分，红豆二个。为末，鼻内搐之。（《玉机微义》） ⑤治客寒犯脑，脑痛连齿，手足厥冷，口鼻气冷之证：羌活一钱，附子、干姜各五分，炙甘草八分。水煎服。（《医学心悟》羌活附子汤） ⑥治风湿相搏，身体疼烦，掣痛不可屈伸，或身微肿不仁：羌活（去芦），附子（炮，去皮脐），白术，甘草（炙）等分。每服四钱，水一盏半、生姜五片，煎至七分，去滓，温服不拘时候。（《济生方》羌附汤） ⑦治肩背痛不可回顾，脊痛项强，腰似折，项似拔者：羌活、独活各一钱，藁本：防风、甘草（炙）、川芎各五分，蔓荆子三分。都作一服，水二盏，煎至一盏，去渣，大温服，空心食前。（《内外伤辨》羌活胜湿汤）' where id=1986; -- 羌活
update herbs set taste='苦、涩；凉。', effect='①治疟疾：野蔷薇花，拌茶煎服。（《群芳谱》） ②治暑热胸闷，吐血口渴，呕吐不思饮食：白残花一钱五分至三钱。煎服。（《上海常用中草药》）' where id=1987; -- 蔷薇花
update herbs set taste='甘；微咸；性平。', effect='①治头风痛：千日红花三钱，马鞭草七钱。水煎服。（江西《草药手册》） ②治气喘：千日红的花头十个，煎水，冲少量黄酒服，连服三次。（《中国药植志》） ③治白痢：千日红花序十个，水煎，冲入黄酒少量服。（江西《草药手册》） ④治小便不利：千日红花序一至三钱，煎服。（《上海常用中草药》） ⑤治小儿风痫：千日红花十朵，蚱蜢干七个。酌加开水炖服。（《福建民间草药，） ⑥治小儿肝热：千日红鲜花序七至十四朵，水煎服。或加冬瓜糖同炖服。（《福建中草药》） ⑦治小儿夜啼：千日红鲜花序五朵，蝉衣三个，菊花七分，水煎服。（《福建中草药》）', tips='止咳平喘；清肝明目；解毒。主咳嗽；哮喘；百日咳；小儿夜啼；目赤肿痛；肝热头晕；头痛；痢疾；疮疖。用于支气管哮喘，急、慢性支气管炎，百日咳，肺结核咯血，头晕，视物模糊，痢疾。 ①《福建民间草药》：祛风，镇肝，退热，明目。 ②《南宁市药物志》：清肝明目，散结消瘿。治瘰疬初起，肝热目痛，血压高头痛。 ③《广西中药志》：花序：凉血消肿，止痉咳。治百日咳；外治疮疡肿痛。民间治月经不调。全株煲水外洗，治跌打疮疖。' where id=1988; -- 千日红
update herbs set taste='味辛；性平；有毒。', channel='归肝经。', effect='①治小儿惊风：蝎一个，不去头尾，薄荷四叶裹合，火上炙令薄荷焦，同研为末，作四服，汤下。大人风涎只一服。（《经验方》） ②治天钓惊风，翻眼向上：干蝎一个（瓦炒好），朱砂三绿豆大。为末，饭丸，绿豆大，外以朱砂少许，同酒化下一丸。（《圣惠方》） ③治乙型脑炎抽搐：全蝎一两，蜈蚣一两，僵蚕二两，天麻一两。共研细末，每服三至五分；严重的抽搐痉厥，可先服一钱，以后每隔四至六小时，服三、五分。（湖北《中草医药经验交流》） ④治小儿风痢：蝎三十枚，取一大石榴，割头去子作盆子，纳蝎于中，以纸筋和黄泥封裹，初炙干，渐烧令通赤，良久，去皮放冷，取其中焦黑者，细研成散。每服以乳汁调下一字。儿稍大，以防风汤调下半钱。（《圣惠方》） ⑤治癫痫：全蝎，郁金、明矾各等量。研粉混匀，每服五分，日三次。（内蒙古《中草药新医疗法资料选编》） ⑥治高血压病、动脉硬化引起的头痛：全虫、钩藤各二钱，丽参二钱。共研末，每口二次，每次服二钱。（内蒙古《中草药新医疗法资料选编》） ⑦治中风，口眼歪斜，半身不遂：白附子、白姜蚕、全蝎（去毒）各等分（并生用）。上为细末，每服一钱，热酒调下，不拘时候。（《杨氏家藏方》牵正散） ⑧治耳暴聋闭：全蝎去毒，为末，酒服一钱，以耳中闻水声即效。（《志雅堂杂钞》） ⑨治血栓闭塞性脉管炎，淋巴结结核，骨关节结核：全蝎、地龙、土元、蜈蚣各等分，研为细末，或水泛为丸。每次服八分，每日三次。（《山东中草药手册》） ⑩治风淫湿痹，手足不举，筋节挛疼：先与通关，次以全蝎七个，瓦炒，入麝香一字，研匀，酒三盏，空心调服：如觉已透则止，未透再服；如病未尽除，自后专以婆蒿根洗净，酒煎，日二服。（《仁斋直指方》） ⑾治破伤风：麝香（研）、干蝎各一分。为末，敷患处。（《普济方》麝香散） ⑿治初生小儿脐风撮口，多啼不乳，口出白沫：全蝎二十一个，用好酒涂炙为末，麝香一字（另研）。上和为细末。用半字，煎汤调服。（《摄生众妙方》宣风散） ⒀治小儿脐风撮口，面赤喘急，啼声不出：赤足金头蜈蚣一枚，蝎梢四尾，姜蚕七个，瞿麦半钱。上为末，先用鹅毛管吹药入鼻内，使嚏喷啼叫为可医，后用薄荷汤调服之。（《袖珍方》） ⒁治慢性气管炎：全蝎一个。水煎服。（内蒙古《中草药新医疗法资料选编》） ⒂治腋窝结核：全蝎七只，蝉蜕十四个。煎汤内服。（《泉州本草》） ⒃治腹股沟肿核，初起寒热如疟，有时愈而复发，每次增剧，终成象皮腿：㈠初起即用干蝎去脚头，火焙研末，泡酒内服。每次一钱至一钱五分。㈡全蝎七只去头足，放鸡蛋内蒸熟去蝎，单食鸡蛋。（《泉州本草》） ⒄治流行性腮腺炎：全蝎用香油炸黄，每次吃一个，每日二次，连服二日。（《山东中草药手册》） ⒅治诸疮毒肿：全蝎七枚，栀子七个。麻油煎黑去滓，入黄蜡，化成膏敷之。（《澹寮方》） ⒆治初发痔痒：全蝎不以多少，或三、二个，烧熏。（《油珍方》） ⒇治大肠风毒下血：白矾三（二）两，干蝎二两（微炒）。捣细罗为散，每于食前，以温粥凋下半钱。（《圣惠方》） （21）治蛇咬伤：全蝎二只，蜈蚣一条（炙）。研末，酒下。（《经验良方》）' where id=1989; -- 全蝎
update herbs set taste='苦、辛，平。', effect='①治一切诸风：青藤二、三月采之，不拘多少，入釜内，微火熬七日夜，成膏，收入瓷瓶内。用时先备梳三五把，量人虚实，以酒服一茶匙毕，将患人身上拍一掌，其后遍身发痒不可当，急以梳梳之。要痒止，即饮冷水-口便解。避风数日。（《濒湖集简方》青藤膏） ②治骨节风气痛：大青木香根或茎叶适量，煎水常洗痛处。（《贵州民间药物》）' where id=1990; -- 青风藤
update herbs set taste='味甘；咸；性温。', channel='入肾、大肠经。', effect='①治男子五劳七伤，阴痿不起，积有十年，痒湿，小便淋沥，溺时赤时黄：肉苁蓉、菟丝子、蛇床子、五味子、远志、续断、杜仲各四分。上七物，捣筛，蜜和为丸如梧子.平旦服五丸，日再。（《医心方》肉苁蓉丸） ②治下部虚损，腹内疼痛，不喜饮食，平补：肉苁蓉二斤，酒浸三日，细切，焙干，捣罗为末，分一半，醇酒煮作膏，和一半入臼中，捣丸如梧桐子大。每服二十丸，加至三十丸，温酒或米饮下，空心食前。（《圣济总录》肉苁蓉丸） ③补精败，面黑劳伤：苁蓉四两（水煮令烂，薄切细研），精羊肉，分为四度，下五味，以米煮粥，空心服之。（《药性论》） ④强筋健髓：苁蓉、蝉鱼。为末，黄精酒丸服之。（《本草拾遗》） ⑤治虚损，暖下元，益精髓，利腰膝：肉苁蓉（酒浸一宿，刮去皱皮，炙干）、蛇床子、远志（去心）、五味子、防风（去芦头）、附子（炮裂，去皮、脐）、菟丝子（酒浸三日，曝干，别捣为末）、巴戟、杜仲（去粗皮，炙微黄，锉）各一两。上药捣罗为末，炼蜜和丸如梧桐子大。每日空心，以温酒下二十丸，盐汤下亦得，渐加至四十丸为度。（《圣惠方》肉苁蓉丸） ⑥治肾虚白浊：肉苁蓉、鹿茸、山药、白茯苓等分。为末，米糊丸梧子大。枣汤每下三十丸。（《圣济总录》） ⑦治发汗利小便亡津液，大腑秘结，老人、虚人皆可服：肉苁蓉（酒浸，焙）二两，沉香（别研）一两。上为细末，用麻子仁汁打糊为丸，如梧桐子大。每服七十丸，空心用米饮送下。（《济生方》润肠丸） ⑧治高年血液枯槁，大便燥结，胸中作闷：大肉苁蓉三两，白酒浸，洗去鳞甲，切片，白汤三碗，煎一碗，顿服。（《医学广笔记》） ⑨治消中易饥：肉苁蓉、山茱萸、五味子。为末，蜜丸梧子大。每服盐汤下二十丸。（《医学指南》） ⑩劳伤，精败面黑。用肉苁蓉四两，水煮烂，切薄研细，炖羊肉吃。 ⑾肾虚白浊。用肉苁蓉、鹿茸、山药、白茯苓，等分为末，加米糊做成丸子，如梧子大，每服三十丸，枣汤送下。 ⑿汗多便秘（年老或体虚的病人）。用肉苁蓉（酒浸，焙过）二两、沉香末一两，共研为末。加麻子杜汁糊成丸子，如梧子大。每服七、八丸。白开水送下。 ⒀消中易饥（按：患此病者常多食，但身体很消瘦）。用肉苁蓉、山萸、五味子等分，共研为末，加蜜做成丸子，如梧子大。每服二十丸，盐酒送下。 ⒁破伤风（口禁，身强直）。用肉苁蓉切片晒干，烧成烟熏伤处，累效。' where id=1991; -- 肉苁蓉
update herbs set taste='味甘；性寒。', channel='入心、肺经。', effect='①治四时外感、发热口渴，或兼肢体酸痛者：忍冬藤（带叶或花，干者）一两（鲜者三两）。煎汤代茶频饮。（《泉州本草》） ②治热毒血痢：忍冬藤浓煎坎。（《圣惠方》） ③治痈疽发背、肠痈、奶痈、无名肿痛，憎寒壮热，类若伤寒：忍冬草（去梗）、黄芪（去芦）各五两，当归一两二钱，甘草（炙）八两。上为细末，每服二钱，酒一盏半，煎至一盏，若病在上食后服，病在下食前服，少顷再进第二服；留渣外敷。未成脓者内消，已成脓者即溃。（《局方》神效托里散） ④治一切痈疽：忍冬藤（生取）五两，大甘草节一两。上用水二碗，煎一碗，入无灰好酒一碗，再煎数沸，去滓，分三服，一昼夜用尽，病重昼夜二剂，至大小便通利为度；另用忍冬藤一把烂研，酒少许敷四周。（《外科精要》忍冬酒） ⑤治诸般肿痛，金刃伤疮，恶疮：金银藤四两，吸铁石三钱，香油一斤。熬枯去滓，入黄丹八两，待熬至滴水不散，如常摊用。（《乾坤生意秘韫》忍冬膏） ⑥治恶疮不愈：左缠藤一把。捣烂，入雄黄五分，水二升，瓦罐煎之，以纸封七重，穿一孔，待气出，以疮对孔熏之，三时久.大出黄水后，用生肌药取效。亦治轻粉毒痈。（《余居士选奇方》） ⑦治疮久成漏：忍冬草浸酒常服。（《证治要诀》） ⑧治风湿性关节炎：忍冬藤一两，稀莶草四钱，鸡血藤五钱，老鹤草五钱，白薇四钱，水煎服。（《山东中药》） ⑨治毒草中毒：鲜金银花嫩茎叶适量，用冷开水洗净，嚼细服下。（《上海常用中草药》）' where id=1992; -- 忍冬藤
update herbs set taste='辛；苦；温。', channel='入肺、大肠经。', effect='①治水湿胀如鼓，不食者，病可下：肉豆蔻、槟榔、轻粉各一分，黑牵牛一两半（取头末）。上为末，面糊为丸，如绿豆大。每服十丸至二十丸，煎连翘汤下，食后，日三服。（《宣明论方》肉豆蔻丸） ②治脾虚泄泻、肠鸣不食：肉豆蔻一枚，剜小窍子，入乳香三小块在内，以面裹煨，面熟为度，去面，碾为细末。每服一钱，米饮送下，小儿半钱。（《杨氏家藏方》肉豆蔻散） ③治脾肾虚弱，大便不实，饮食不思：肉豆蔻、补骨脂、五味子、吴茱萸各为末。生姜四两，红枣五十枚。用水一碗，煮姜、枣，去姜，水干，取枣肉丸桐子大。每服五、七十丸，空心食前服。（《内科摘要》四神丸） ④治脾泄气痢：豆蔻二颗，米醋调面裹之，置灰中煨令黄焦，和面碾末，更以炒党子末一两，相和。又焦炒陈廪米为末，每用二钱七，煎饮调前二物三钱匕，旦暮各一。（《续传信方》） ⑤治水泻无度、肠鸣腹痛：肉豆蔻（去壳，为末）一两，生姜汁二合，白面二两。上三味，将姜汁和面作饼子，裹肉豆蔻末煨令黄熟，研为细散。每服二钱匕，空心米饮调下，日午再服。（《圣济总录》肉豆蔻散） ⑥治霍乱呕吐不止：肉豆蔻一两（去壳），人参一两（去芦头），厚朴一两（去粗皮，涂生姜汁，炙令香熟）。上药捣，粗罗为散。每服三钱，以水一大盏，入生姜半分，粟米二撮，煎至五分，去滓，不计时候温服。（《圣惠方》） ⑦治水泻无度，肠鸣腹痛：肉豆蔻（去壳，为末）30克，生姜汁2合，白面60克。上3味，将姜汁和面作饼子，裹肉豆蔻末煨令黄熟，研为细散，每服4克。空心米饮调下，日午再服。（《圣济总录》肉豆蔻散） ⑧治脾肾俱虚所致的虚泻，冷痢：煨肉豆蔻、罂粟壳（蜜炙）、煨诃子肉各4.5克,白芍、白术、当归各15克，党参、炙甘草各8克，肉桂、木香各3克。研为粗末，每服6克，加生姜2片，大枣1枚，水煎服。（《太平惠民和剂局方》养脏汤）' where id=1993; -- 肉豆蔻
update herbs set taste='味辛；苦；微温。', channel='入心、肝、脾经。', effect='①治心气疼痛不可忍：乳香三两，真茶四两。为末，以腊月鹿血和丸，弹子大。每温醋化一丸服之。（《瑞竹堂经验方》） ②治急心痛：胡椒四十九粒，乳香一钱，为末，男用姜汤下，女用当归汤下。（《摄生众妙方》抽刀散） ③治气血凝滞，痃癖癥瘕，心腹疼痛，腿酸臂疼，内外疮疡，一切脏腑积聚，经络湮淤：当归五钱，丹参五钱，生明乳香五钱，生明没药五钱。上药四味作汤服，若为散，一剂分作四次服，温酒送下。（《医学衷中参西录》活络效灵丹） ④治产后瘀滞不清，攻刺心腹作痛：乳香、没药（俱瓦上焙出油）各三钱，五灵脂、延胡索、牡丹皮、桂枝各五钱（俱炒黄），黑豆一两（炒成烟炭）。共为末，每服三钱，生姜泡汤调下。（《李念先手集》） ⑤治跌扑折伤筋骨：乳香，真没药各一钱五分，当归尾，红花、桃仁各三钱。水煎服。（《本草汇言》） ⑥治发背脑疽，和一切恶疮内溃及诸恶毒冲心呕痛：乳香一两（通明者，用水外浸，以乳钵研细），真绿豆粉（研）叫两。上二味合研极细，每服一钱匕，新水调下，水不可多，要药在胸膈上也。（《圣济总录》托里汤） ⑦治疮疡疼痛不可忍：乳香、没药各二钱，寒水石（煅）、滑石各四钱，冰片一分。为细末，搽患处。（《外科发挥》乳香定痛散） ⑧治鱼肚痈及翻花起肛，久烂不堪者，消肿止痛：乳香、没药（各去油）各一两，麝香一钱半，雄精五钱（各研极细），黄米饭二两。捣烂为丸，如莱菔子大，忌火烘，晒干。每服陈酒送下三钱，醉盖取汗。（《外科全生集》醒消丸） ⑨治化脓性指头炎，急性乳腺炎：乳香五钱，白矾、花椒各二钱，葱白数根。水煎外洗，一日数次。（内蒙古《中草药新医疗法资料选编》） ⑩治阴寒呃忒不止：乳香、硫黄，艾各二钱。为细末，用好酒一钟，煎数沸，乘热气，使病人鼻嗅之。外用捣生姜擦胸前。（《伤寒全生集》乳香硫黄散） ⑾治梦寐遗精：乳香一块，拇指大，卧时嚼，含至三更，咽下。三、五服。（《医林集要》） ⑿治口目歪斜：乳香烧烟熏之，以顺其血脉。（《证治要诀》） ⒀治咽喉骨哽：乳香一钱，水研服之。（《卫生易简方》） ⒁治齿虫痛不可忍：嚼熏陆香咽其汁。（《梅师集验方》） ⒂熏陆香亦称乳香，商品也作乳香入药。为漆树科植物粘胶乳香树的树干经切伤后流出的树脂。主产于希腊、土耳其及地中海南岸地区。西医用为填齿料，并为制硬膏的原料，中医作乳香用。 ⒃没药散（《证治准绳》）治口疮：乳香、没药、雄黄各3g，轻粉1.5g，巴豆霜少许。上为末，擦患处。方中乳香消肿生肌，为臣药。 ⒄乳香丸（《普济本事方》）治小儿腹痛多啼，唇黑囊肿，惊风内钓，角弓反张：乳香、没药、沉香各30g，蝎尾4枚，槟榔45g（一方无槟榔）。上为末，炼蜜为丸，每服3丸，菖蒲、钓藤煎汤送下。方中乳香活血止痛，为君药。 ⒅乳香膏（《外科精义》）治恶疮，打扑，走注疼痛：乳香（研)松脂、白蜡各15g，白胶香60g，杏仁油1斤。先将松脂在炭火上熔开，下白胶香、白蜡化开，入油搅匀，过滤去渣，在水中持拔呈白色如银，再入乳香拔白色，摊贴患处。方中乳香活血止痛，消肿生肌，为君药。' where id=1994; -- 乳香
update herbs set taste='味甘；咸；性寒。', channel='入心、胃经。', effect='①辟瘟：人中黄不拘多少，饭为丸，绿豆大，下十五丸。（《松峰说疫》人中黄丸） ②治大热发渴：人中黄兑白糖开水服。（《四川中药志》） ③治瘟疫热盛：人中黄，黄连、石膏煎服。（《四川中药志》） ④治呕血吐痰，心烦骨蒸者：人中黄为末，每服三钱，茜根汁、竹沥、姜汁和匀服之。（《丹溪心法》） ⑤治丹毒：人中黄二钱，金银花一钱五分，丹皮一钱五分，生山栀二钱。水煎，一日三次分服。（《现代实用中药》） ⑥治河豚、菌毒及一切恶疮：人中黄、酒大黄，末，等分。无灰酒服，须臾泻利，毒即随出，虽大渴，不可饮水。（《本经逢原》）' where id=1995; -- 人中黄
update herbs set taste='辛甘，热，', channel='入肾、脾，膀胱经。', effect='①治肾气虚乏，下元惫冷，脐腹疼痛，夜多旋溺，脚膝缓弱，肢体倦怠，面色黧黑，不思饮食；脚气上冲，少腹不仁；虚劳不足，渴欲饮水，腰重疼痛，少腹拘急，小便不利；男子消渴，小便反多；妇人转胞，小便不通等证：牡丹皮、白茯苓、泽泻各三两，熟干地黄八两，山茱萸、山药各四两，附子（炮，去皮、脐）、肉桂（去粗皮）各二两。上为末，炼蜜丸如梧子大。每服十五丸至二十五丸，温酒下。空心食前，日二服。（《局方》八味丸，即《金匮》肾气丸） ②治元阳不足，命门火衰，脾胃虚寒，饮食少进，或呕恶膨胀；或翻胃噎膈，或怯寒畏冷，或脐腹多痛，或大便不实，泻痢频作，或小溲自遗，虚淋寒疝，或寒侵溪谷而肢节痹痛，或寒在下焦而水邪浮肿，及真阳不足之神疲气怯，心跳不宁，四体不收，阳衰无子等证：大怀熟地八两，山药（炒）四两，山茱萸（微炒）三两，枸杞（微炒）四两，鹿角胶（炒珠）四两，菟丝子（制）四两，杜仲（姜汤炒）四两，当归三两（便溏勿用），肉桂二两（渐可加至四两），制附子二两（渐可加至五、六两）。上药先将熟地蒸烂杵膏，加炼蜜丸如弹子大，每嚼服二、三丸，以滚白汤送下。（《景岳全书》右归丸） ③治冒暑伏热，引饮过多，脾胃受湿，水谷不分，清浊相干，阴阳气逆，霍乱呕吐，脏腑不调：甘草（锉，长寸）三十斤，干姜（炮炒）四斤，杏仁（去皮、尖，砂炒）四斤四两，肉桂（去粗皮，炙）四斤。上先将甘草用白砂炒及八分黄熟，次入干姜同炒，令姜裂，次入杏仁又同炒，候杏仁不作声为度，用筛隔净，后入桂一处捣罗为散。每服二钱，煎至七分，去滓温服。如烦躁，井华水调下，不计时候，以沸汤点服亦得。（《局方》大脚散。按干姜、杏仁制法、药量原缺，据《普济方》引三宜汤补） ④治冷气攻心腹痛，多呕，不欲饮食：桂心一两，高良姜一两（锉），当归一两（锉，微炒），草豆蔻一两半（去皮），厚朴二两（去粗皮，涂生姜汁（炒）令香熟），人参一两（去芦头）。上件药，捣筛为散，每服三钱，以水一中盏，煎至六分，去滓，不计时候，稍热服。（《圣惠方》桂心散） ⑤治久寒积冷，心腹污痛，胁肋胀满，泄泻肠鸣，自利自汗，米谷不化：荜茇、肉桂各四斤，干姜（炮）、高良姜各六斤。上为细末，水煮面糊为丸，如梧桐子大。每服二十粒，米饮汤下，食前服之。（《局方》大已寒丸） ⑥治九种心痛，妨闷：桂心半两。末，以酒一盏，煎至半盏，去滓，稍热服。（《圣惠方》） ⑦治濡泻水利久不止：桂（去粗皮）、附子（炮裂，去皮、脐）、干姜（炮）、赤石脂各一两。上四味，捣罗为末，炼蜜丸，如梧桐子大，每报二十丸，空心食前米饮下，日三服。（《圣济总录》桂附丸） ⑧治寒疝气，来往冲心腹痛：桂心四两，生姜三两，吴茱萸二两。上三味，切，以酒一大升，煎至三合，去滓，分温三服，如人行六、七里，一服。忌生葱。（《姚僧坦集验方》柱心汤） ⑨治奔豚疝瘕冲筑：肉桂、干姜、小茴香各五钱，牡丹皮、木香、槟榔各二钱，甘草五分；水煎服。（《方脉正宗》） ⑩治真寒腰痛，六脉弦紧，口舌青，阴囊缩，身战栗：内桂三钱，附子三、四钱（急则用生附子），杜仲二钱，热服。（《会约医镜》桂附杜仲汤） ⑾治产后腹中瘕痛：桂（末），温酒服方寸匕，日三。（《肘后方》） ⑿治产后馀寒，下痢便脓血赤白，日数十行，腹痛时时下血：桂心、甘草各二两，白蜜一升，干姜二两，当归三两，赤石脂十两（绵裹），附子一两（炮，去皮，破）。上七味，以水六升，煮取三升，纳蜜，再沸，分三服。（《千金翼方》桂心汤） ⒀治小儿下痢赤白。腹痛不可食：桂心、黄连各等分。上为末，白糊丸小豆大三十丸，米汤送下。（《普济方》桂连丸） ⒁治小儿睡中遗尿，不自觉者：官桂（为末）、雄鸡肝一具，等分。捣烂，丸如绿豆大，温汤送下，日三服。（《万病回春》桂肝丸） ⒂治鹤膝风，贴骨疽及一切阴疽：熟地一两，肉桂一钱（去粗皮，研粉），麻黄五分，鹿角胶三钱，白芥子二钱，姜炭五分，生甘草一钱。煎服。（《外科全生集》阳和汤） ⒃治打扑伤破，腹中有瘀血：桂心、当归各二两，蒲黄一升。上三味，治下筛。以酒服方寸匕，日三，夜一。（《千金方》） ⒄治牛皮癣：官桂、良姜、细辛各五分，斑蝥十个（研碎）。白酒三两，浸渍七天，每天震摇一次，浸出有效成分，滤取清汁，为缓和白酒的局部刺激，加入甘油三十毫升。先将患处用温水洗软，再用药水涂擦，每日或隔日一次。不宜饮酒和吃刺激性食品。（《中药通报》1：10，1957） ⒅治虚寒阴火之喉痛、喉痹：肉桂、干姜、甘草各五分。各研极细未，滚水冲淖，将碗顿于滚水内，再淖，慢以咽下。但先以鹅毛蘸桐油，入喉卷痰，痰出服药更效。（《外科全生集》杜姜汤）' where id=1996; -- 肉桂
update herbs set taste='甘、微苦，微温。', channel='入脾、肺经。', effect='①治营卫气虚，脏腑怯弱，心腹胀满，全不思食，肠鸣泄泻，呕哕吐逆：人参（去芦）、白术、茯苓（去皮）、甘草（炙）各等分。上为细末，每服二钱，水一盏，煎至七分，通口服，不拘时，入盐少许，白汤点亦得。常服温和脾胃，进益饮食，辟寒邪瘴雾气。（《局方》四君子汤） ②治胃虚冷，中脘气满，不能传化，善饥不能食：人参末二钱，生附子末半钱，生姜一分（切碎）。上三味和匀，用水七合，煎至二合，以鸡子一枚取清，打转，空心顿服。（《圣济总录》温胃煮散） ③治肺虚久咳：人参末二两，鹿角胶（炙，研）一两。每服三钱，用薄荷、豉汤一盏，葱少许，入铫子煎一、二沸，倾入盏内，遇咳时，温呷三、五口。（《食疗本草》） ④治三、二年间肺气上喘咳嗽，咯唾脓血，满面生疮，遍身黄肿：蛤蚧一对（全者，河水浸五宿，逐日换水，洗去腥，酥炙黄色），杏仁（去皮尖、炒），甘草（炙）各五两，知母、桑白皮、人参、茯苓（去皮），贝母各二两。上八味为末，净磁合子内盛。每日用如茶点服。（《卫生宝鉴》人参蛤蚧散） ⑤治阳虚气喘，自汗盗汗，气短头运：人参五钱，熟附子一两。分为四帖，每帖以生姜十片，流水二盏，煎一盏，食远温服。（《济生方》） ⑥治心气虚损，怔忡而自汗者：猪腰子一只，用水两碗，煮至一盏半，将腰子细切，入人参半两，当归（上去芦、下去细者，取中段）半两。并切，同煎至八分，吃腰子，以汁送下。有吃不尽腰子，同上二味药滓，焙干，为细末，山药糊丸如梧桐子大，每服三、五十丸。（《百一选方》） ⑦治心气不定，五脏不足，恍惚振悸，差错谬忘，梦寐惊魇，恐怖不宁，喜怒无时，朝差暮剧，暮差朝剧，或发狂眩：远志（去苗及心）、菖蒲各二两，人参、白茯苓（去皮）各三两。上为细末，炼蜜丸如梧桐子大，朱砂为衣。每服七丸，加至二十丸，温米饮下，食后临卧日三服。（《局方》定志丸） ⑧治消渴引饮无度：人参、瓜蒌根各等分。生为末，炼蜜为丸，梧桐子大，每服三十丸，麦冬汤送下。（《仁斋直指方》玉壶丸） ⑨治消渴引饮：人参为末，鸡孑清调服一钱，日三、四服。（《纲目》） ⑩止血后此药补之：大人参（去芦）二两，枣五枚。每服水二盏，煎一盏。细呷之，服后熟睡一觉，诸病除根。（《十药神书》独参汤） ⑾治吐血下血，因七情所感，酒色内伤，气血妄行，口鼻俱出，心肺脉散，血如涌泉：人参（焙）、侧柏叶（蒸焙）、荆芥穗（烧存性）各五钱。为末，用二钱，入飞罗面二钱，以新汲水调如稀糊服，少顷再啜。（《中藏经》） ⑿治小儿惊后瞳人不正者：人参、阿胶（糯米炒成珠）各一钱。水一盏，煎七分。温服，日再服，愈乃止。（《仁斋直指方》） ⒀治下痢噤口：人参、莲肉各三钱。以井华水二盏，煎一盏，细细呷之，或加姜汁炒黄连三钱。（《经验良方》） ⒁治胸痹心中痞气，气结在胸，胸满，胁下逆抢心：人参、甘草、干姜、白术各三两。上四味，以水八升，煮取三升，温服一升，日三服。（《金匮要略》人参汤） ⒂治霍乱心烦躁：桂心二分（末），人参半两（去芦头）。上以水一大盏，煎至七分，去滓，分温二服。（《圣惠方》） ⒃治虚疟发热：人参二钱二分，雄黄五钱。为末，用棕尖捣丸，梧子大。发日侵晨，井华水吞下七丸，发前再服。忌诸般热物。（《丹漠纂要》） ⒄治妊娠酸心吐清水，腹痛不能饮食：人参（去芦）、干姜（炮）各等分。上为末，用生地黄汁，丸如梧子大.每服五十丸，米汤下，食前服。（《局方》小地黄丸）' where id=1997; -- 人参
update herbs set alias='松花、松黄。', taste='甘，温。', channel='归肝、脾经。', effect='①治风眩头旋肿痹，皮肤顽急：松树始抽花心（状如鼠尾者佳，蒸细，切）二升，用绢囊裹，入酒五升，浸五日，空腹饮三合，再服大妙。（《元和纪用经》松花酒） ②治酒毒发作，头痛目眩，或咽喉闭闷，或下利清水，日数十行，形神萎顿：松花一两（焙），陈皮五钱，川黄连五钱，甘草二钱。俱微炒磨为末，与松花和匀。每早晚各服二钱，白汤调服。（《本草汇言》） ③治久痢不止，延及数月，缠绵不净：松花每服三钱，食前米汤调下。（《本草汇言》） ④治胃及十二指肠溃疡，慢性便秘：松花粉一钱，冲服。（广州部队《常用中草药手册》） ⑤治尿布皮炎：松花粉撒布患处。（《浙江民间常用草药》） ⑥外伤出血：松花粉外敷伤口。（《浙江民间常用草药》） ⑦治婴儿湿疹：松花粉一钱，炉甘石粉一钱，鸡卵黄三个。先将鸡卵煮熟，去白取黄，再放金属小锅煎熬，即有卵黄油析出，取油去渣，用此油调松花粉、炉甘石粉涂患部，一至三次（已化脓者无效）。（《健康报》1955年10月28日）' where id=1998; -- 松花粉
update herbs set effect='1．驱虫方（《海峰验方集》）治小儿虫积（不拘蛔虫、蛲虫、绦虫），症见腹痛，腹胀，食少，面黄肌瘦，睡卧不安，大便秘结或稀溏，有时虫体随大便排出或自口腔吐出：山慈姑（酒拌炒热）、续断子、鹤虱、雷丸、枯矾、明雄黄、川黄连、青黛、川干姜、炒吴萸、白芷、升麻各9g，使君子（去壳）10个，苦楝根皮（酒炒）、北口芪、党参、于术、全当归、阿胶、葛根、防风各30g。上药碾洗筛净，灌入宽口瓶中。1-2岁，日服1次，每次服1.5g，晨起后，空腹时开水调化服之，也可加适量白糖调服，连续3-5天；3-4岁，日服1次，每次服2.4g，服法、服次同上；5-6岁，日服1次，每次服3g，服法、服次同上；6岁以上，按5-6岁量为准，不必增加，服法、服次同上。方中山慈姑消痈散结，为君药。 2．紫金锭（《外科正宗》）治由湿温时邪引起的神昏胸闷，呕恶泄泻，及小儿痰壅惊闭；外治痈疽疔疮，肿核结毒等症：茅慈姑60，红芽大戟（醋炙）45g，五倍子、千金子霜各30g，朱砂12g，雄黄6g，麝香9g。制糊为锭，每服0.6-1.5g，日服1-2次，温开水磨服或捣碎冲服；外用醋磨调敷患处。孕妇忌服。方中山慈姑清热解毒，消痈散结，为君药。 3．（《乾坤生意》）治痈疽疔肿、恶疮及黄疸：慈姑（连根）、苍耳草等分。捣烂，以好久1钟，滤过温服；或干之为末，每酒服9。方中山慈姑清热解毒，消痈散结，为君药。', tips='清热解毒；消肿散结。主痈疽恶疮；瘰疬结核；咽痛喉痹；蛇、虫咬伤。' where id=1999; -- 山慈菇
update herbs set taste='苦；辛；凉。', effect='①治小儿高热惊厥：石老鼠根一钱，钩藤二钱，七叶一枝花根二钱，水煎服。（《江西草药》） ②治小儿风热，惊风和疝气痛：三叶青块根三至五钱，水煎服。（《浙江民间常用草药》） ③治肝炎：石老鼠根五钱，虎刺根、茜草根各一两，水煎服，每日一剂。（《江西草药》） ④治肺炎：石老鼠根，瓜子金、枸骨根各三钱，水煎服，每日一剂。（《江西草药》） ⑤治哮喘：石老鼠根、贝母、桔梗各一钱，水煎服，每日一剂。 ⑥治银环蛇咬伤：石猴子全草或块根，加冷水捣烂成浆，内服五钱，外涂擦伤处，此为主药。再用叶上针煎水，冷却后外洗，并内服适量，服药后只能饮冷水，不能饮热水。（湖南《中草药新医疗法资料选编》） ⑦治蛇咬：㈠银环蛇咬伤：有角乌蔹莓块根二至三个捣烂，剪去头发，敷头顶囟门处（百会穴）。㈡五步蛇咬伤：有角乌蔹莓块根五钱至一两，切碎，水煎服。（《浙江民间常用草药》） ⑧治痈疖疔毒，蜂窝织炎，咽炎，扁桃体炎，淋巴结结核等症：鲜雷胆子和水或酒磨成粘糊，涂擦患处，或以纱布蘸药液湿敷，日三至四次。凡属口腔、阴囊等薄嫩皮肤处以水磨较好。（湖南《中草药新医疗法资料选编》） ⑨治外伤出血：石老鼠根适量，晒干研末，撒敷包扎。（《江西草药》） ⑩治跌打损伤：石老鼠根一两，研末，黄酒送服。（《江西草药》）' where id=2000; -- 三叶青
update herbs set taste='咸，寒。', effect='①治慢性肝炎、肝硬化腹水：水红花子五钱，大腹皮四钱，黑丑三钱。水煎服。（《新疆中草药手册》） ②治腹中痞积：水红花或子一碗，以水三碗，用文武火熬成膏，量痞大小摊贴，仍以酒调膏服。忌荤腥油腻。（《保寿堂经验方》） ③治脾肿大，肚子胀：水红花子一斤，水煎熬膏。每次一汤匙，一日二次，黄酒或开水送服。并用水红花子膏摊布上，外贴患部，每天换药一次。（《新疆中草药手册》） ④治瘰疬，破者亦治：水荭子不以多少，微炒一半，余一半生用，同为末，好酒调二钱，日三服，食后夜卧各一服。（《本草衍义》）' where id=2001; -- 水红花子
update herbs set taste='味辛；性温。', channel='入胃经。', effect='①治心腹冷痛：山柰、丁香、当归、甘草等分。为末，醋糊丸，梧子大。每服三十丸，酒下。（《濒湖集简方》） ②治一切牙痛：山柰子二钱（用面裹煨热），麝香半钱。为细末，每用三字，口噙温水，随牙痛处一边鼻内搐之，漱水吐去，便可。（《海上方》麝香一字散） ③治风虫牙痛：肥皂一个，去穰，内入三赖、甘松各三分，花椒、盐不拘多少，以塞肥皂满为度，用面包，炼红，取研为末，每日擦牙。（《摄生众妙方》）' where id=2002; -- 山柰
update herbs set taste='甘、咸，平。', channel='归肝、肾经。', effect='①安神魂，定心志，治健忘，小便数，补心气：桑螵蛸、远志、菖蒲、龙骨、人参、茯神、当归、龟甲（醋炙）各一两。为末。夜卧，人参汤调下二钱。（《本草衍久》桑螵蛸散） ②治遗精白浊，盗汗虚劳：桑螵蛸（炙）、白龙骨等分。为细末。每服二钱，空心用盐汤送下。（《外台》） ③治妊娠小便数不禁：桑螵蛸十二枚。捣为散。分作两服，米饮下。（《产书方》） ④治小便不通及胞转：桑螵蛸捣末，米饮服方寸匕，日三。（《产书方》） ⑤治男妇疝瘕作痛：桑螵蛸一两，小茴香一两二钱。共为末。每服二钱，花椒汤调服。（《本草汇言》） ⑥治咽喉骨鲠：桑螵蛸，醋煎呷之。（《经验良方》） ⑦治产后遗尿或尿数：桑螵蛸（炙）半两，龙骨一两。为末。每米饮服二钱。（《徐氏胎产方》） ⑧治底耳：桑螵蛸一个。慢火炙及八分熟，存性，细研，入麝香一字，为末，掺在耳内，每用半字。如有脓，先用绵包子拈去，次后掺药末，入在耳内。（《经验方》） ⑨治小儿软疖：桑螵蛸炉存性，研末，油调敷之。（《世医得效方》）' where id=2003; -- 桑螵蛸
update herbs set taste='苦，寒，有毒。', channel='入肺、肝经。', effect='①治喉痹：㈠射干，细锉。每服五饯匕，水一盏半，煎至八分，去滓，入蜜少许，旋旋服。（《圣济总录》射干汤） ㈡射干，旋取新者，不拘多少。擂烂取汁吞下，动大腑即解。或用酽醋同研取汁噙，引出涎更妙。（《医方大成论》） ②治咽喉肿痛：射干花根、山豆根。阴干为末。吹喉。（《袖珍方》） ③治伤寒热病，喉中闭塞不通：生乌扇一斤（切），猪脂一斤。上二味合煎，药成去滓。取如半鸡子，薄绵裹之，纳喉中，稍稍咽之取瘥。（《千金方》） ④治咳而上气，喉中水鸡声：射干十三枚（一法三两），麻黄四两，生姜四两，细辛、紫菀、款冬花各三两，五味子半升，大枣七枚，半夏（大者，洗）八枚（一法半升）。上九味，以水一斗二升，先煮麻黄两沸，去上沫，纳诸药，煮取三升。分温三服。（《金匮要略》射干麻黄汤） ⑤治乳痈初肿：扁竹根（如僵蚕者）同萱草根为末。蜜调服。极有效。（《永类钤方》） ⑥治瘰疬结核，因热气结聚者：射干、连翘、夏枯草各等分。为丸。每服二钱，饭后白汤下。（《本草汇言》） ⑦治水蛊腹大，动摇水声，皮肤黑，阴疝肿刺：鬼扇细捣绞汁，服如鸡子，即下水。（《补缺肘后方》） ⑧治腮腺炎：射干鲜根三至五钱。酌加水煎，饭后服，日服两次。（《福建民间草药》）' where id=2004; -- 射干
update herbs set taste='苦；甘；性温。', channel='入肝、脾经。', effect='①治一切肿毒：松香八两，铜青二钱，蓖麻仁五钱，同捣作膏，摊贴甚妙。（《怪证奇方》） ②治疖肿，痈疽，疔疮：松香粉二两，酒精二百毫升，加热溶解，瓶口密封备用，以干棉球蘸取药液搽患处，每天一至二次。（《江苏省中草药新医疗法展览资料选编》） ③治痈疽肿毒溃破：脓水淋漓，脓头不出：炼过松脂一两，滴明乳香、真没药（俱放瓦上，焙出油）各五钱，樟脑一钱，共为细末，掺入毒内，拔脓散毒。（《外科全书》） ④治一切瘘：炼成松脂末，填疮孔令满，日三、四度。（《圣惠方》） ⑤治淋巴结核溃烂：黄香一两，研为细粉。有脓水者，干撒，干者用猪油调敷。（《青海省中医验方汇编》） ⑥治疥癣湿疮：松胶香研细，约酌少入轻粉，衮令匀，凡疥癣上，先用油涂了，擦末。（《刘涓子鬼遗方》） ⑦治瘙痒疮疥：用炼过松脂五钱，大黄、荜拨各一两；樟脑、槟榔各五钱。共为极细末，用猪油一两，和研为丸，加水银八钱再研，以水银散，不见点为度。每遇瘙痒疥癣，以药丸疮上磨之。（《刘涓子鬼遗方》） ⑧治神经性皮炎：松香、猪油各适量，煮成糊状，涂患处，日数次。（广西《中草药新医疗法处方集》） ⑨治阴囊湿痒欲溃者：板儿松香为末，纸卷作筒，每根入花椒三粒，浸灯盏内三宿，取出点烧，淋下油搽之；先以米泔洗过。（《简便单方》） ⑩治软疖频发：通明沥青八两，铜绿二两，麻油三钱，雄猪胆汁三个。先溶沥青，乃下油胆，倾入水中扯拨，器盛。每用绯帛摊贴，不须再换。（《纲目》翠玉膏） ⑾治小儿白秃疮：炼过松脂、黄丹各五钱，轻粉三钱。共为细末，菜油调搽；先用米泔汤洗净搽药，一日一次。（《简集方》） ⑿治头癣：明矾一斤半，煅枯研细，嫩松香三两，鲜猪油半斤。将松香包入油内，用松明柴点燃猪油，使松香油熔化滴下，冷却后加入枯矾，调匀，涂患处，使之结痂；隔天去痂再涂，不用水洗。（《全展选编·皮肤科》） ⒀治一切风热疮，小儿头疮：沥青、黄蜡、芝麻油各十两，巴豆十四个。上先将沥青、麻油、黄蜡熬成汁；次入巴豆，不住手搅，候巴豆焦黑，去巴豆不用；次入腻粉二钱，再搅极匀，放冷，敷疮上。（《卫生宝鉴》软青膏） ⒁治历节诸风，百节酸痛不可忍：松脂三十斤炼五十遍，酒煮十遍，二十遍亦可；炼酥三升，温，和松脂三升熟搅，令极调匀，旦空腹以酒服方寸匕，日三。（《千金方》） ⒂治历节风：松膏一升，酒三升，浸七日，服一合，日再，数剂愈。（《千金方》） ⒃治肝虚目泪：炼成松脂一斤，酿米二斗，水七斗，曲二斗，造酒频饮之。（《纲目》） ⒄治小儿紧唇：炙松脂贴之。（《圣惠方》） ⒅治风虫牙痛：刮松上脂，滚水泡化，漱口。（《濒湖集简方》） ⒆治虫蛀牙痛：炼过松脂一两，菜油三钱，火上熬化，将冷凝，加入真蟾酥五分，用筋搅匀，取米粒大，内入牙痛隙处。（《梅师集验方》） ⒇治耳久聋：松脂三两（炼），巴豆一两，相和熟捣，可丸，以薄棉裹入耳孔中塞之，日一度易。（《梅师集验方》） (21)治妇人白带：松香五两，酒二升，煮干，木臼杵细，酒糊丸，如梧子大。每服百丸，温酒下。（《摘元方》） (22)治疠风，皮肤瘙痒，须眉脱落，身面俱起紫泡：白松香不拘多少，于砂锅内煎九次，每煎一次，露一宿，九次煎如沙者良，方可服，若服此药，终生不可吃盐，若犯必发。（《滇南本草》）' where id=2005; -- 松香
update herbs set taste='性平，味辛、苦；', channel='入肝、肾经。', effect='①治脚膝挛痹，去风湿，活血脉，益元气：石南、白术、牛膝（三昧，酒同浸一宿，焙干）、防风、天麻、枸杞、黄芪（锉）各二两，桂（去粗皮）、鹿茸（酥炙，去毛）各一两半。上九味捣罗为末，用木瓜一枚，去皮瓤炊令烂熟，捣作膏和药末，更用面糊少许，同为丸，如梧桐子大。每服三十丸至五十丸，空心温酒下，盐汤亦得。（《圣济总录》石南丸） ②治女子神经性偏头痛：石楠叶三钱，川芎一钱，白芷一钱半，天麻一钱半，女贞子二钱。水煎，一日三回分服。（《现代实用中药》） ③治小儿误跌，或打着头脑受惊，肝系受风，致瞳人不正，观东则见西，观西则见东：石南一两，藜芦三分，瓜蒂五、七个。为末，每吹少许入鼻，一日三度，内服牛黄平肝药。（《普济方》石南散） ④治风瘾疹经旬不解：石南叶（去粗茎，生用）三两。捣罗为末。每服半钱至一钱匕，用酒三合，煎一沸，空心温服。（《圣济总录》石南酒） ⑤治鼠瘘：石南、生地黄、茯苓、黄连、雌黄各二两。为散。敷疮上，日再。（《补缺肘后方》） ��', tips='阴虚火旺者忌服。 ②《药性论》：恶小蓟。' where id=2006; -- 石南叶
update herbs set taste='味酸；涩；性温；小毒。', channel='入大肠、肾经。', effect='①治久痢不瘥：陈石榴焙干，为细末，米汤调下三、四钱。（《普济方》神授散） ②治妊身暴下不止，腹痛：安石榴皮二两，当归三两，阿胶二两（炙），熟艾如鸡子大二枚。上四物以水九升，煮取二升，分三服。（《产经方》石榴皮汤） ③治粪前有血，令人面黄：酢石榴皮，炙研末，每服二钱，用茄子枝煎汤服。（《千金方》） ④治脱肛：石榴皮、陈壁土，加白矾少许，浓煎熏洗，再加五倍子炒研敷托上之。（《医钞类编》） ⑤治诸虫心痛不可忍，多吐酸水：酸石榴皮一两（锉），桃符二两（锉），胡粉一两，酒二合，槟榔末二钱。上件药，以水二大盏，煎前二味至一盏，去滓，下胡粉、槟榔、酒，更煎一沸，稍热，分为三服。（《圣惠方》石榴皮散） ⑥驱绦虫、蛔虫：石榴皮、槟榔各等分，研细末，每次服二钱（小儿酌减），每日二次，连服二天。（《山东中草药手册》） ⑦治丁肿恶毒：以针刺四畔，榴皮着疮上，以面围四畔灸之，以痛为度，仍用榴末敷上，急裹，经宿，连根自出也。（《肘后方》） ⑧治牛皮癣：㈠石榴皮蘸极细的明矾粉搓患处，初搓时微痛。（《山东中草药手册，）㈡石榴皮（炒炭），研细末一份，麻油三份，调成糊状。用时将药油摇匀。以毛笔蘸药匀涂患处，每日二次。（《全展选编·皮肤科》） ⑨预防稻田皮炎：石榴皮二两，五倍子二两，地榆（炒黑）二两，明矾五两。取清水五斤，将前三味药放入水内煎沸后，再煎10分钟，然后加入明矾，用木棒不断搅拌，至明矾全部溶于水中，再煎至剩下药液3斤左右，去渣冷却备用。用时须在下水前将手、脚在药液中浸泡一下；也可用棉花球蘸涂。待药液干后入水工作。每次出水休息，必须如前浸涂后再下水工作。（《上海中医药杂志》（6）：170，1966） ⑩治脚肚生疮，初起如粟，搔之渐开，黄水浸淫，痒痛溃烂，遂致绕胫而成痼疾：酸榴皮煎汤冷定，日日扫之，取愈乃止。（《医学正宗》） ⑾治汤火烫伤：石榴果皮适量。研末，麻油调搽患处。（《贵州草药》）' where id=2007; -- 石榴皮
update herbs set taste='味辛；性温。', channel='入脾、肾经。', effect='①治小儿气胀，霍乱呕逆，腹冷食不下及胁痛：莳萝，为末，糊丸如绿豆大。三岁三十丸，青皮汤下。（《普济方》莳萝丸） ②治疝气偏坠，女子瘕病：莳萝一两二钱。炒褐色，为细末。无灰好酒调服。（《摄生众妙方》） ③治闪挫腰痛：莳萝，作末，酒服二钱匕。（《永类钤方》）' where id=2008; -- 莳萝子
update herbs set taste='苦；涩；性平。', channel='归胃经。', effect='①治呃逆：柿钱、丁香、人参等分。为细末，水煎，食后服。（《洁古家珍》柿钱散） ②治呃逆不止：柿蒂（烧灰存性）为末。黄酒调服，或用姜汁、砂糖等分和匀，炖热徐服。（《村居救急方》） ③治伤寒呕哕不止：干柿蒂七枚，白梅三枚。上二味，粗捣筛，只作一服，用水一盏，煎至半盏。去滓温服，不拘时。（《圣济总录》柿蒂汤） ④治胞满咳逆不止：柿蒂、丁香各一两。上细切，每服四钱，水一盏半，姜五片，煎至七分。去滓热服，不拘时候。（《济生方》柿蒂汤） ⑤治百日咳：柿蒂四钱（阴干），乌梅核中之白仁十个（细切），加白糖三钱。用水二杯，煎至一杯。一日数回分服，连服数日。（《江西中医药》（3）:20～22，1953） ⑥治血淋：干柿蒂（烧灰存性），为末。每服二钱，空心米饮调服。（《奇效良方》柿蒂散） ⑦治呃逆：柿钱、丁香、人参等分。上为细末，水煎，食后服。方中柿蒂降逆止呕，为君药。（《洁古家珍》柿钱散） ⑧治血淋：干柿蒂（烧炭存性）。为末，每服6g，空心米饮调服。方中柿蒂清热止血，为君药。（《奇效良方》柿蒂散） ⑨治胸满咳逆不止：柿蒂、丁香各30g。上细切，每服12g，水1.5盏，姜5片，煎至7分，去渣，热服，不拘时。方中柿蒂降逆止呕，为君药。（《济生方》柿蒂汤）', tips='降逆下气。主呃逆；噫气；反胃。 ①孟诜：治咳逆、哕气，煮汁服。 ②《滇南本草》：治气隔反胃。' where id=2009; -- 柿蒂
update herbs set taste='甘，温。', channel='入肝、肾经。', effect='①治精滑不禁：沙苑蒺藜（炒）、芡实（蒸）、莲须各二两，龙骨（酥炙）、牡蛎（盐水煮一日一夜，煅粉）各一两。共为末，莲子粉糊为丸，盐汤下。（《医方集解》金锁固精丸） ②治肾虚腰疼：沙苑子一两。水煎，日服二次。（《吉林中草药》） ③治脾胃虚，饮食不消，湿热成臌胀者：沙苑蒺藜二两（酒拌炒），苍术八两（米泔水浸一日，晒干，炒）。共研为末。每服三钱，米汤调服。（《本草汇言》） ④治目昏不明：沙苑子三钱，茺蔚子二钱，青葙子三钱。共研细末。每次一钱，日报二次。（《吉林中草药》）' where id=2010; -- 沙苑子
update herbs set taste='味甘；性温；小毒。', channel='入脾、胃经。', effect='①治小儿蛔虫咬痛，口吐清沫：使君子（去壳）为极细末，用米饮调，五更早空心服。（《补要袖珍小儿方论》使君子散） ②治小儿疳蛔：使君子十个（瓦上炒，为末），甘草（胆汁浸一夕）、白芜荑各一分，苦楝子五个（炮，去核）。上末之，每服一钱，水煎服。（《幼科准绳》使君子散） ③治小儿五疳，脾胃不和，心腹膨胀，时复疞痛，不进饮食，渐致羸瘦：厚朴（去皮，姜汁炙）、陈皮（去白）、川芎各一分，使君子仁（浸，去黑皮）一两。上为细末。炼蜜丸如皂子大。三岁以上一粒，三岁以下半粒，陈米饮化下。（《局方》使君子丸） ④治小儿痞块腹大，肌瘦面黄，渐成疳疾：使君子仁三钱，木鳖子仁五钱。为末，水丸龙眼大。每以一丸，用鸡子一个破顶，入药在内，饭上蒸热，空心食。（《简便单方》） ⑤治黄病爱吃生米、茶叶、桴炭、泥土、瓦屑之类：使君子肉二两（切碎，微炒），槟榔二两，南星三两（俱用姜汁拌炒）。共为末，红曲打糊为丸，如梧桐子大。每服百余丸，乌梅，花椒汤送下。（《万病回春》） ⑥治虫牙疼痛：使君子煎汤，频漱。（《濒湖集简方》） ⑦治头瘗面疮：使君子仁，以香油少许，浸三、五个，临卧时细嚼，香油送下，久而自愈。（《普济方》） ⑧小儿脾疳。用使君子、芦荟，等分为末。每服一钱，米汤送下。 ⑨小儿痞块（腹大，肌瘦而黄，渐成疳疾）。用使君子仁三钱、木鳖子仁五钱，共研为末，滴水做成丸子，如龙眼大。每取一丸，放入一个破了顶的鸡蛋中，饭上蒸熟，空心服。 ⑩蛔虫病。用使君子为末，五更时以米汤调服一钱。 ⑾小儿虚肿（头面、阴囊都有浮肿）。用使君子一两，去壳，加蜜五钱炙炙药，研细。每服一钱，饭后服，米汤送下。 ⑿虫牙疼痛。有使君子煎汤频嗽。' where id=2011; -- 使君子
update herbs set taste='苦；甘；性凉。', effect='①治痘疮倒靥黑陷：牛李子杵汁，石器内密封，每服皂子大，煎杏胶汤化下。（《小儿药证直诀》牛李膏，一名必胜膏） ②治诸疮寒热毒痹：鼠李生捣敷之。（《圣惠方》） ③治齿匿肿痛：牛李煮汁，空腹饮一盏，仍频含漱。（《圣济总录》）', tips='清热利湿；消积通便。主水肿腹胀；疝瘕；瘰疬；疮疡；便秘。用于支气管炎，肺气肿，龋齿痛，痈疖。 ①《本经》：主寒热，瘰疬疮。 ②《本草经集注》：主大热。 ③《唐本草》：下血及碎肉，除疝瘕积冷气，九蒸酒渍，服三合，日二。 ④《食疗本草》：主胀满、谷胀，和面作讲子，空心食之，少时当泻。 ⑤《日华子本草》：治水肿。 ⑥《品汇精要》：杀虫，消毒。 ⑦《纲目》：治痘疮黑陷及疥癣有虫。 ⑧《医林纂要》：取汁熬膏，滋阴，养肾，活血。' where id=2012; -- 鼠李
update herbs set taste='味甘；性温。', channel='入肝、肾经。', effect='①治痿：黄柏半斤（酒炒），龟板四两（酒炙），知母二两（酒炒），熟地黄、陈皮、白芍各二两，琐阳一两半，虎骨一两（炙），干姜半两。上为末，酒糊丸，或粥丸。（《丹溪心法》虎潜丸） ②治阳弱精虚，阴衰血竭，大肠燥涸，便秘不运：琐阳三斤。清水五斗，煎浓汁二次，总和，以砂锅内熬膏，炼蜜八两收成，入磁瓶内收贮，每早、午、晚各食前服十余茶匙，热酒化服。（《本草切要》） ③治肾虚遗精，阳萎：锁阳、龙骨、苁蓉、桑螵蛸、茯苓各等分。共研末，炼蜜为丸，每服三钱，早晚各一次。（《宁夏中草药手册》） ④治阳萎，早泄：锁阳五钱，党参、山药各四钱，覆盆子三钱。水煎服。（《陕甘宁青中草药选》） ⑤治老年气弱阴虚，大便燥结：锁阳、桑椹子各五钱。水煎取浓汁加白蜂蜜一两，分两次服。（《宁夏中草药手册》） ⑥治泌尿系感染尿血：锁阳、忍冬藤各五钱，茅根一两。水煎服。（《宁夏中草药手册》） ⑦治胃溃疡：锁阳、珠芽蓼各三钱。水煎服。 ⑧治消化不良：锁阳五钱。水煎服。 ⑨治白带：锁阳五钱，沙枣树皮三钱。水煎服。（⑦方以下出《陕甘宁青中草药选》） ⑩治二度子宫下垂：锁阳五钱，木通三钱，车前子三钱，甘草三钱，五味子三钱，大枣三个。水煎服。 ⑾治胃痛，胃酸过多：锁阳四两，寒水石（煅）五两，红盐一钱，龙胆草一两，冰糖十两。共为细末，每服三钱。 ⑿治心脏病：锁阳，冬季采集后用猪油（或奶油）炸后，经常冲茶服，二十日为一疗程。（⑩方以下出《中国沙漠地区药用植物》）' where id=2013; -- 锁阳
update herbs set alias='姜叶淫羊藿，美草，箭杆风，九龙盘，九姜连。', taste='味辛；性温。', effect='①治劳伤吐血：九姜连（童便泡七日，取出阴干用）三钱，一口血三钱，山高梁三钱。泡酒半斤，每服一两。 ②治虚弱咳嗽：㈠九姜连三钱，大鹅儿肠三钱。炖肉吃。㈡九姜连粉末一两，核桃仁一两。加蜂糖二两，混匀蒸热，制成龙眼大的丸子，含化吞服。 ③治久咳：九姜连根（石灰水泡一天，用淘米水和清水洗净，蒸热，晒干）二钱，白芷二钱，追风伞二钱。泡酒一斤，每服一两。（选方出《贵阳民间药草》）', tips='温中；散寒；祛风；活血。主脘腹冷痛；肺寒咳嗽；风湿痹痛；跌打损伤；月经不调；劳伤吐血。用于风湿性关节炎，跌打损伤，牙痛，胃痛。 ①陶弘景：腹中冷痛，煮服甚效。 ②《本草拾遗》：去恶气，温中。治中恶霍乱，心腹冷痛，功用如姜。 ③《草木便方》：解大毒，行血消瘀，透筋骨。治风湿四肢麻木，煎服；中风顽痹，煎汤洗。 ④《峨帽药植》：治无名肿毒。 ⑤《贵阳民间药草》：根茎和叶：温肺，散寒，止咳。 ⑥《四川中药志》：根茎：治劳伤吐血，跌损瘀血停滞，月经不调。' where id=2014; -- 山姜
update herbs set taste='味辛；甘；性凉。', channel='入肺、胃经。', effect='①治小儿发热，月余不凉：水芹菜、大麦芽、车前子。水煎服。（《滇南本草》） ②治小便淋痛：水芹菜白根者，去叶捣汁，井水和服。（《圣惠方》） ③治小便不利：水芹三钱。水煎服。（《湖南药物志》） ④治白带：水芹四钱，景天二钱。水煎服。（《湖南药物志》） ⑤治小便出血：水芹捣汁，日服六、七合。（《圣惠方》） ⑥治小儿霍乱吐痢：芹叶细切，煮熟汁饮。（《子母秘录》） ⑦治痄腮：水芹捣烂，加茶油敷患处。（《湖南药物志》）' where id=2015; -- 水芹
update herbs set taste='微苦；性寒。', effect='①治风湿痛，跌打损伤，高血压： 桑树根五钱至一两，大剂可至二两。水煎服。 (《上海常用中草药》) ②治赤眼： 鲜桑根一两。洗净，水适量煎服，或煮猪肝于早晨服。 (《闽南民间草药》) ③治血露不绝：锯截桑根取屑五指撮，取醇酒服之， 日三。(《肘后方》) ④中蜀椒、蜈蚣毒：煮桑根汁解之。(《补缺肘后方》)', tips='清热定惊；祛风通络。主惊痫；目赤；牙痛；筋骨疼痛。治惊痫，筋骨痛，高血压，目赤，鹅口疮。 ①《日华子本草》：研汁，治小儿天吊，惊痫客忤；敷鹅口疮。 ②《岭南采药录》：去骨节风痰。 ③《南京民间药草》：治筋骨痛，高血压。' where id=2016; -- 桑根
update herbs set taste='味辛；微苦；性温；小毒。', effect='①治胃痛、牙痛：竹叶椒果一至二钱，山姜根三钱。研末，温开水送服。（《江西草药》） ②治痧症腹痛：竹叶椒果三至五钱，水煎服；或研末，每次五分至一钱，黄酒送服。（《江西草药》）' where id=2017; -- 竹叶椒
update herbs set taste='甘；辛；性寒。', channel='入肺、脾经。', effect='①治小儿肺盛，气急喘嗽：地骨皮、桑白皮（炒）各一两，甘草（炙）一钱。锉散，入粳米一撮，水二小盏，煎七分，食前服。（《小儿药证直诀》泻白散） ②治咳嗽甚者，或有吐血殷鲜：桑根白皮一斤。米泔浸三宿，净刮上黄皮，锉细，入糯米四两，焙干，一处捣为末。每服米饮调下一、二钱。（《经验方》） ③治水饮停肺，胀满喘急：桑根白皮二钱，麻黄、桂枝各一钱五分，杏仁十四粒（去皮），细辛、干婪各一钱五分。水煎服。（《本草汇言》） ④治小便不利，面目浮肿：桑白皮四钱，冬瓜仁五钱，葶苈子三钱。煎汤服。（《上海常用中草药》） ⑤治卒小便多，消渴：桑根白皮，炙令黄黑，锉，以水煮之令浓，随意饮之；亦可纳少米，勿用盐。（《肘后方》） ⑥治糖尿病：桑白皮四钱，枸杞子五钱，煎汤服。（《上海常用中草药》） ⑦治传染性肝炎：鲜桑白皮二两，白糖适量。水煎，分二次服。（《福建中医药》（3）：26，1961） ⑧治产后下血不止：炙桑白皮，煮水饮之。（《肘后方》） ⑨治小儿尿灶丹，初从两股起，及脐间，走阴头，皆赤色者：水二升，桑皮（切）二升，煮取汁，浴之。（《千金方》） ⑩治石痈坚如石，不作脓者：蜀桑根白皮，阴干捣末，烊胶，以酒和敷肿。（《千金方》） ⑾治蜈蚣毒：桑根皮捣烂敷或煎洗。（《湖南药物志》） ⑿治坠马拗损：桑根白皮五斤。为末，水一升，煎成膏。敷于损处。（《经验后方》）', tips='肺虚无火，小便多及风寒咳嗽忌服。 ②《本草经疏》：肺虚无火，因寒袭之而发咳嗽者勿服。 ③《得配本草》：肺虚，小便利者禁用。' where id=2018; -- 桑白皮
update herbs set taste='味辛；性温。', channel='入心、脾、肝经。', effect='①治卒中风：青州白丸子，入麝香同研碎为末，生姜自然汁调灌之，如牙紧，可自鼻中灌入。（《魏氏家藏方》） ②治中风不醒：麝香二钱。研末，入清油二两，和匀灌之。（《济生方》） ③治痰迷心窍：麝香一分，月石、牙皂、明矾、雄精各一钱。上共研匀，密贮，每服五分。（《疡科遗编》） ④治中恶客忤垂死：空青一两（细研），麝香一分（细研），朱砂一两（细研，水飞过），雄黄半两（细研）。上药相和，研令匀，每服以醋一合、汤一合相和，调散半钱，不计时候服之，须臾即吐为效。（《圣惠方》） ⑤治小儿诸痼潮发，不省，困重：白僵蚕（汤洗，焙黄为末）半两，天竺黄一分（细研），真牛黄一钱（别研），麝香（研）、龙脑（研）各半钱。上拌研匀细，每服半钱，生姜自然汁调灌眼，无时。（《小儿卫生总微论方》白金散） ⑥治肾脏积冷，气攻心腹疼痛，频发不止：麝香半两（细研），阿魏半两（面裹煨，面熟为度），干蝎三分（微炒），桃仁五十枚（麸炒微黄）。上药捣罗为末，炼蜜和丸，如绿豆大，每服不计时候，以热洒下二十丸。（《圣惠方》麝香丸） ⑦治厥心痛：麝香（别研，每汤成旋下），木香一两（锉），桃仁（麸炒）三十五枚，吴茱萸（水浸一宿，炒干）一两，槟榔（煨）三枚。上五味，除麝香、桃仁外，粗捣筛，入桃仁，再同和研匀。每服三钱匕，水半盏，童子小便半盏，同煎至六分，去滓，入麝香末半钱匕，搅匀温服，日二服。（《圣济总录》麝香汤） ⑧治跌打气闭：牙皂、北细辛、南星、冰片、麝香等分。为末，吹鼻。（《医钞类编》吹药方） ⑨治痈疽发背及诸恶疮，去恶肉：麝香、雄黄、矾石、闾茹（一作’真朱’）各一两。上四味治下筛，以猪膏调如泥涂之，恶肉尽，止，却敷生肉膏。（《千金方》麝香膏） ⑩治鼠瘘：麝香（研）、雌黄（研）。上二味等分，并为散，取虾蟆背白汁和涂疮孔中，日一度。（《古今录验方》） ⑾治小儿疳，常渴，饮冷水不休：麝香一分，人中白一分。上药邡研令细，以蒸饼和丸，如麻子大。一、二岁儿，每服煎皂荚汤下二丸，空心、午后各一服。更量儿大小，以意加减。（《圣惠方》麝香丸） ⑿治牙痛：麝香大豆许，巴豆一粒，细辛末半两（钱）。上药同研令细，以枣瓤和丸，如粟米大。以新绵裹一丸，于痛处咬之，有涎即吐却，有蛀孔即纳一丸。（《圣惠方》麝香丸）' where id=2019; -- 麝香
update herbs set taste='味辛；苦；性温。', channel='入肾、脾经。', effect='①治阳不起：菟丝子、蛇床子、五味子各等分。上三味，末之，蜜丸如梧子。饮服三十丸，日三。（《千金方》） ②治白带因寒湿者：蛇床子八两，山茱萸肉六两，南五味子四两，车前子三两，香附二两（俱用醋拌炒），枯白矾五钱，血鹿胶（火炙酒淬）五钱。共为细末，山药打糊丸梧子大。每早空心服五钱，白汤送下。（《方脉正宗》） ③治妇人阴寒，温阴中坐药：蛇床子仁，一味末之，以白粉少许，和合相得，如枣大，绵裹纳之，自然温。（《金匮要略》蛇床子散） ④治妇人阴痒：蛇床子一两，白矾二钱。煎汤频洗。（《濒湖集简方》） ⑤治产后阴下脱：蛇床子一升，布裹炙熨之，亦治产后阴中痛。（《千金方》） ⑥治妇人子脏挺出：蛇床子一升，酢梅二七枚。水五升，煮取二升半，洗之，日十过。（《僧深集方》蛇床洗方） ⑦治滴虫性阴道炎：㈠蛇床子五钱，水煎，灌洗阴道。（江西《草药手册》）㈡蛇床子一两，黄柏三钱。以甘油明胶为基质做成（2克重）栓剂，每日阴道内置放一枚。（内蒙古《中草药新医疗法资料选编》） ⑧治男子阴肿胀痛：蛇床子末，鸡于黄调敷之。（《永类钤方》） ⑨治阴囊湿疹：蛇床子五钱，煎水洗阴部。（江西《草药手册》） ⑩治小儿癣：蛇床实，捣末，和猪脂敷之。（《千金方》） ⑾治小儿恶疮：腻粉三分，黄连一分（去须）。蛇床子三分。上药捣细罗为散，每使时，先以温盐汤洗疮令净，拭干，以生油涂之。（《圣惠方》） ⑿治小儿唇口边肥疮，亦治耳疮、头疮、瘑疮：白矾一两（烧灰），蛇床子一两。为末，干掺疮上。（《小儿卫生总微论方》） ⒀治湿疹，过敏性皮炎，漆树过敏，手足癣：蛇床子、桉树叶、苦楝树皮、鸭脚木、苦参、地肤子各适量，煎水泡洗患处，每日二次。（江西《草药手册》） ⒁治冬月喉痹肿痛，不可下药者：蛇床子烧烟于瓶中，口含瓶嘴吸烟，其痰自出。（《圣惠方》） ⒂治妇人子在脏偏僻。冷结无子：蛇床子、芫花各90g。上2味捣筛，取大枣，沙袋盛，内产门中，令没指，袋少长，便时须去，任意卧着，慎风冷。方中蛇床子温肾壮阳，升阳举陷，为君药。（《外台秘要》坐药方） ⒃治湿疹，过敏性皮炎，漆树过敏，手足癣：蛇床子、桉树叶、苦楝树皮、鸭脚木、苦参、地肤子各适量。方中蛇床子燥湿杀虫，为君药。（《江西草药手册》） ⒄治白带因寒湿者：蛇床子240g，山茱萸肉180g，南五味子120g，车前子90g，香附60g（俱用醋拌炒），枯白矾15g，血鹿胶（火炙酒淬）15g。共为细末，山药打糊丸，梧桐子大，每服15g，早空心白汤送下。方中蛇床子温肾壮阳，燥湿杀虫，为君药。(《方脉正宗》)' where id=2020; -- 蛇床子
update herbs set taste='味辛；苦；性微寒。', effect='①治疗急、慢性肝炎 取紫参2两，或加糯米稻草1两，水煎两次，煎液合并加红糖半两，两次分服（儿童减半）。治疗205例，治愈150例，进步33例，无效22例。其中急性169例，治愈126例，平均治愈日数36天；慢性36例，治愈24例。 ②治疗赤白带下 取石打穿2两，水煎服。每日一剂，连服5～7天。治疗800多例，有效率80％。', tips='活血化瘀；清热利湿；散结消肿。主月经不调；痛经；经闭；崩漏，便血；湿热黄疸；热热毒血痢；淋痛；带下；风湿骨痛；瘰疬；疮肿；乳痈；带状疱疹；麻风；跌打伤肿。用于黄疸型肝炎，癌症，肾炎，白带，痛经，淋巴结结核，象皮病；外用治面神经麻痹，乳腺炎，疖肿。 ①《纲目》：主骨痛，大风，痈肿。 ②《苏州本产药材》：治噎膈，痰饮气喘。 ③《江苏药材志》：治瘰疬。' where id=2021; -- 石见穿
update herbs set alias='萆根，京三棱，红蒲根，光三棱。', taste='味辛；涩；凉。', channel='入肝。脾经。', effect='①治癥瘕：三棱草（切）一石，以水五石，煮取一石，去渣，更煎取三斗，于铜器中重釜煎如稠糖，出，纳密器中，旦以酒一盏服一匕，日二服，每服常令酒气相续。（《千金翼方》三棱草煎） ②治五积六聚，七癥八瘕，破一切血，下一切气：大黄（煨）、硼砂、三棱（煨热，切）、干漆（炒烟尽）、巴豆（去皮、油）各一两。上为末，醋煮糊为丸，如绿豆大，每服三丸，或五丸、七丸，量人虚实加减服，空心米汤下。（《医学切问》三棱丸） ③治妇人、室女血寝，月经不通，脐下坚结大如杯，久而不治，必成血蛊：京三棱、蓬术各二两，芫花半两，青皮（去瓤净）一两半。上锉如豆大，用好醋一升，煮干，焙为细末，醋糊为丸，如桐于大，每服五十丸，食前用淡醋汤下。（《济生方》三棱煎丸） ④治血瘀经闭，小膜痛：三棱三钱，当归三钱，红花一钱，五分，生地四钱。水煎服。（《新疆中草药手册》） ⑤治产后癥块：京三棱一两（微煨，锉），木香半两，硇砂三分（细研），芫花半两（醋拌炒干），巴豆一分（去心、皮，纸裹压去油）。上药，捣罗为末，研入前件硇砂、巴豆令匀，以米醋二升，熬令减半，下诸药，慢火熬令稠可丸，即丸如绿豆大，每服，空心以醋汤下二丸。（《圣惠方》三棱丸） ⑥治食积腹胀：三棱、莱菔子各三钱。水煎服。（《新疆中草药手册》） ⑦治慢性肝炎或迁延性肝炎：三棱、莪术、当归各三钱，赤芍四钱，丹参八钱，白茅根一两，青皮三钱。水煎服。（《新疆中草药手册》）。' where id=2022; -- 三棱
update herbs set taste='微苦、辛，温。', channel='归肝、脾、肾经。', effect='①治风痹筋骨不舒：宽筋藤，每用三钱至一两，煎服。（《岭南采药录》） ②治关节酸痛：石松三钱，虎杖根五钱，大血藤三钱。水煎服。（《浙江民间常用草药》） ③治关节酸痛，手足麻痹：凤尾伸筋草一两，丝瓜络五钱，爬山虎五钱，大活血三钱。水、酒各半煎服。（江西《中草药学》） ④治小儿麻痹后遗症：凤尾伸筋、南蛇藤根、松节、寻骨风各五钱，威灵仙三钱，茜草二钱，杜蘅五分。煎服。（江西《中草药学》） ⑤消水肿：过山龙五分（研细末），糠瓢一钱五分（火煅存性），槟榔一钱。槟榔、糠瓢煨汤吃过山龙末，以泻为度。气实者用，虚者忌。（《滇南本草》） ⑥治带状疱疹：石松（焙）研粉，青油或麻油调成糊状，涂患处，一日数次。（《浙江民间常用草药》） ⑦治关节疼痛：石松9g，虎杖根15g，大血藤9g。水煎服。方中伸筋草祛风除湿，舒筋活络，为君药。（《浙江民间常用草药》） ⑧ 治关节疼痛，手足麻痹：凤尾伸筋草30g，丝瓜络、爬山龙各15g，大活血9g。水、酒各半煎服。方中伸筋草祛风除湿，舒筋活络，为君药。 （《江西中草药学》） ⑨治小儿麻痹后遗症：凤尾伸筋草、南蛇藤根、松节、寻骨风各15g，威灵仙9g，茜草6g，杜蘅1.5g。煎服。方中伸筋草舒筋活络，为君药。（《江西中草药学》）' where id=2023; -- 伸筋草
update herbs set taste='味辛；性温。', channel='入脾、胃经。', effect='①和胃气，消宿食，理腹痛，快膈，调脾:沉香一两，缩砂仁、乌药各二两，净香附四两，甘草（炙）一两二钱。上除沉香不过火，余四味锉焙，仍同沉香研为细末。每服一钱，用温盐汤无时调服，或空心烧盐汤调下亦好，紫苏，枣汤尤妙。（《活幼心书》缩砂饮） ②消食和中，下气止心腹痛:砂仁炒研，袋盛浸酒，煮饮。（《纲目》缩砂酒） ③治痰气膈胀:砂仁捣碎，以萝卜汁浸透，焙干为末。每服一、二钱，食远，沸汤服。（《简便单方》） ④治气虚肿满，痰饮结聚，脾胃不和，变生诸症者:人参一钱，白术二钱，茯苓二钱，甘草七分，陈皮八分，半夏一钱，砂仁八分，木香七分，生姜二钱。水煎服。（《古今名医方论》香砂六君子汤） ⑤治妊娠胃虚气逆，呕吐不食:缩砂仁不拘多少。上为细末。每服二钱，入生姜自然汁少许，沸汤点服，不拘时候。（《济生方》缩砂散） ⑥治冷滑下痢不禁，虚羸:缩砂仁、炮附子（末）、干姜、厚朴、陈橘皮等分。为丸。日二，服四十丸。（《药性论》） ⑦治妇人妊娠，偶因所触，或坠高伤打，致胎动不安，腹中痛不可忍者:缩砂不计多少。慢火炒令热透，去皮用仁，捣罗为末。每服二钱，用热酒调下，须臾觉腹中胎动处极热，而胎已安。（孙用和） ⑧治遍身肿满，阴亦肿者:缩砂仁、土狗一个，等分。研，和老酒服之。（《仁斋直指方》） ⑨治小儿滑泄，肛头脱出:缩砂一两。去皮为末，每用一钱，以猪腰子一片批开，入药末在内，绵系，米泔煮熟，与儿食之，次服白矾丸。（《小儿卫生总微论方》缩砂散） ⑩牙齿疼痛:缩砂常嚼之。（《仁斋直指方》） ⑾治一切食毒:缩砂仁末，水服一、二钱。（《事林广i2》） ⑿对于湿阻脾胃引起的食欲不振及呕吐泄泻等症，常配合白朮、陈皮等同用；对于脾胃气滞、脘腹胀满，常配合陈皮、厚朴、木香等同用；对于脾虚气滞，可与党参、白朮等同用。用于脾胃虚寒所致的腹痛泄泻，多与温中祛寒的干姜、熟附子，陈皮等同用。治胎动不安，常配合白朮、苏梗等同用；治妊娠恶阻，可配合半夏、竹茹等同用。 ⒀治寒喘，四肢逆冷，脉沉细：砂仁、干姜、苏子、厚朴、官桂、陈皮、甘草各3g，沉香、木香各1.5g，姜，水煎。磨二香同服。方中砂仁化湿行气，温脾止泻，为君药。（《万病回春》理中汤） ⒁治小儿宿食不消：砂仁、陈皮、三棱、莪术、神曲、麦芽各15，香附30。为末，面糊为丸，绿豆大。紫苏汤下。方中砂仁化湿行气，为臣药。（《婴童百问》消食丸） ⒂治伤饮食油腻瓜果，酒面乳茶等物：砂仁、苍术、草果、干葛、陈皮、茯苓、生姜各3g。水煎。分2次服。方中砂仁化湿行气，为君药。（《本草汇演》治伤饮食方）' where id=2024; -- 砂仁
update herbs set alias='山漆、金不换，血参，参三七，田三七、田漆，田七。', taste='味甘；微苦；性湿', channel='归肝；胃；心；肺；大肠经', effect='①治吐血，衄血：山漆一钱，自嚼，米汤送下。（《濒湖集简方》） ②治吐血：鸡蛋一枚，打开，和三七末一钱，藕汁一小杯，陈酒半小杯，隔汤炖熟食之。（《同寿录》） ③治咳血，兼治吐衄，理瘀血及二便下血：花蕊石三钱（煅存性），三七二钱，血余一钱（煅存性）。共研细末。分两次，开水送服。（《医学衷中参西录》化血丹） ④治亦痢血痢：三七三钱，研末，米泔水调服。 ⑤治大肠下血：三七研末，同淡白酒调一、二钱服。加五分入四物汤亦可。 ⑥治产后血多：三七研末，米汤服一钱。 ⑦治赤眼，十分重者：三七根磨汁涂四围。（④方以下出《濒湖集简方》） ⑧治刀伤，收口：好龙骨、象皮、血竭、人参三七、乳香、没药、降香末各等分。为末，温酒下。或掺上。（《纲目拾遗》七宝散） ⑨止血：人参三七、白蜡、乳香、降香、血竭、五倍、牡蛎各等分。不经火，为末。敷之。（《回生集》军门止血方） ⑩治无名痈肿，疼痛不止：山漆磨米醋调涂。已破者，研末干涂。（《纲目》） ⑾治咳血、吐血屡治无效，久而不愈，脉象微孔。生龙骨30g，生牡蛎30g，山萸肉30g，三七6g。研细，水煎服。方中三七化淤止血，为佐药。（《医学衷中参西录》补络补管汤）' where id=2025; -- 三七
update herbs set taste='味酸；咸；性凉。', channel='肝；肾经。', effect='①治疟病：鼠妇、豆豉二七枚，合捣，令相和，未发时服二丸，欲发时服一丸。（《补缺肘后方》） ②治经闭：鼠妇一钱，赤芍四钱，桃仁三钱，红花三钱，丹参五钱。水煎服。（《山东中草药手册》） ③治小儿撮口及发噤：鼠赖虫，绞取汁，与儿少许服之。（《圣惠方》） ④治产后小便不利：鼠妇七枚。熬为屑，作一服，酒调下。（《千金方》） ⑤治小便不利：鼠妇一钱五分，车前子四钱，泽泻三钱，灯心一钱。水煎服。（《山东中草药手册》） ⑥治血淋：鼠妇九个。焙干研细末，一次服下，日二次。（《吉林中草药》） ⑦治子宫功能性出血：鼠妇焙黄研末，每服二钱，童便送下。（内蒙古《中草药新医疗法资料选编》） ⑧治牙齿被虫蚀，有蛀孔疼痛：湿生虫一枚。绵裹于蛀疼处咬之。（《圣惠方》） ⑨治风牙疼痛：湿生虫、巴豆仁、胡椒各一枚。研匀，饭丸绿豆大，绵裹一丸咬之，良久涎出吐去。（《经验济世良方》） ⑩止痛镇静，治手术后疼痛：鼠妇虫洗净，温水杀死，干燥，研细，过筛，加入淀粉和糖，使成10％散剂，分装胶囊，每粒含鼠妇0.1克。每次服二至四粒。（《全展选编·外科》） ⑾治鹅口白疮：地鸡研水涂之。（《寿域神方》）' where id=2026; -- 鼠妇
update herbs set effect='1.用治于感冒发热，肺热咳嗽，咽喉肿痛，小便淋沥涩痛及痢疾、腹泻病症，可单用本品一两，煎服；也可配合蒲公英、乌蔹莓、鸭拓草等同用。用治热疖痈肿初启，可用鲜叶适量，洗净，加食盐少许，同捣烂，外敷患处。治下肢溃烂及汤火伤，可用干叶研成细粉，用麻油调涂患处。外治创伤出血，可用鲜叶洗净，捣烂外敷伤口；也可用干叶研细，撒敷在伤口上，外加包扎。 2.配绿茶叶，文火煎至浓缩成粘胶状，直接涂敷创面，随干随涂，以创面不痛为度，治一或二度烧伤。 3.附：单味应用 （1）.鲜叶洗净，加食盐少许同捣敷，治热毒疮疔。 （2）.鲜叶捣敷或干叶研细外撒，治外伤出血。', tips='清热解毒；生肌敛疮；活血止血。主肺热咳嗽；咽喉肿痛；痢疾；腹泻；胆道感染；尿路感染；冠心病心绞痛；烧烫伤；热毒痈肿；下肢溃疡；麻风溃疡；湿疹；冻疮；皲裂；血栓闭塞性脉管炎；外伤出血。 用于肺炎、急性咽喉炎、痢疾、胆道感染、尿路感染；外治烧伤、下肢溃疡、麻风溃疡。 ①《本草图经》：“烧灰，面膏涂之、治皲瘃殊效、兼灭瘢疵。”' where id=2027; -- 四季青
update herbs set taste='味苦；甘；性寒。', channel='入肺、肝经。', effect='①治太阴风温，但咳，身不甚热，微渴者：杏仁二钱，连翘一钱五分，薄荷八分，桑叶二钱五分，菊花一钱，苦梗二钱，甘草八分（生），苇根二钱。水二杯，煮取一杯，日二服。（《温病条辨》桑菊饮） ②治风眼下泪：腊月不落桑叶，煎汤日日温洗，或入芒硝。（《濒湖集简方》） ③洗天行时眼，风热肿痛，目涩眩赤：铁扇子二张，以滚水冲半盏，盖好，候汤温，其色黄绿如浓茶样为出味，然后洗眼，拭干；隔一、二时，再以药汁碗隔水炖热，再洗，每日洗三、五次。（《养素园传信方》） ④治肝阴不足，眼目昏花，咳久不愈，肌肤甲错，麻痹不仁：嫩桑叶（去蒂，洗净，晒干，为末）一斤，黑胡麻子（淘净）四两，将胡麻擂碎，熬浓汁，和白蜜一斤，炼至滴水成珠，入桑叶末为丸，如梧桐子大。每服三钱，空腹时盐汤、临卧时温酒送下。（《医级》桑麻丸） ⑤治吐血：晚桑叶，微焙，不计多少，捣罗为细散。每服三钱匕，冷腊茶调如膏，入麝香少许，夜卧含化咽津。只一服止，后用补肺药。（《圣济总录》独圣散） ⑥治霍乱已吐利后，烦渴不止：桑叶一握，切，以水一大盏，煎至五分，去滓，不计时候温服。（《圣惠方》） ⑦治小儿渴：桑叶不拘多少，用生蜜逐叶上敷过，将线系叶蒂上绷，阴干，细切，用水煎汁服之。（《胜金方》） ⑧治大肠脱肛：黄皮桑树叶三升，水煎过，带温罨纳之。（《仁斋直指方》） ⑨治穿掌毒肿：新桑叶研烂盫之。（《通玄论》） ⑩治痈口不敛：经霜黄桑叶，为末敷之。（《仁斋直指方》） ⑾治火烧及汤泡疮：经霜桑叶，焙干，烧存性，为细末，香油调敷或干敷。（《医学正传》） ⑿治咽喉红肿，牙痛：桑叶三至五钱，煎服。（《上海常用中草药》） ⒀治头目眩晕：桑叶三钱，菊花三钱，枸杞子三钱，决明子二钱。水煎代茶饮。（《山东中草药手册》） ⒁治摇头风（舌伸出，流清水，连续摇头）：桑叶一至二钱，水煎服。（江西《草药手册》） ⒂治手足麻木 不知痛痒：霜降后桑叶煎汤频洗．（《急救方》） ⒃治乳硬作痛：嫩桑叶 生采 研．以米饮调 摊纸花贴病处[4]．（《妇人良方》） ⒄治风温初起，咳嗽，身热不甚，口微渴，舌苔薄白，脉浮数：桑叶7.5g, 菊花3g，杏仁、桔梗、芦根各6g，连翘4.5g，薄荷、甘草各2.4g。水煎。每日2服。若气粗而喘，燥在气分者，加石膏、知母；舌绛蓦热，邪初入营；加元参、犀角；在血分者，去薄荷、芦根，加麦门冬、生地黄、玉竹、牡丹皮；肺热甚，加黄芩；渴者，加天花粉。方中桑叶味甘苦性凉，疏散上焦风热，且善走肺络能清宣肺热而止咳嗽，用以为君。（《瘟病条辨》桑菊饮） ⒅治燥热伤肺，气促，干渴无痰或少痰，咽喉口鼻干燥，舌干苔少：桑叶9g，石膏15～30g，人参（一般都用孩儿参或沙参）3g左右，甘草3g，麻仁9g，阿胶6～9g，麦冬、杏仁、枇杷叶各9g。日服1剂，水煎，分2次服。方中重用桑叶质轻性寒，清透肺中燥热之邪，为君药。（《医门法律》清燥救肺汤） ⒆主治外感温燥，邪在肺卫。桑叶6克、杏仁9克，沙参12克，象贝母6克，香豉6克，栀皮6克，梨皮6克。水煎服。方中桑叶轻宣燥热，杏仁苦辛温润、宣利肺气，共为主药。（《温病条辩》桑杏汤） (20)桑叶善于散风热而泄肺热，对外感风热、头痛、咳嗽等，常与菊花、银花、薄荷、前胡、桔梗等配合应用。桑叶不仅可用于风热引起的目赤羞明，且可清肝火，对肝火上炎的目赤肿痛，可与菊花、决明子、车前子等配合应用。至于肝阴不足，眼目昏花，桑叶还可配滋养肝肾的女贞子、枸杞子、黑芝麻等同用。 (21)桑叶轻清发散，能散风热，但作用较弱。临床主要用于清泄肺肝，如风热袭肺、咳嗽多痰，或燥热伤肺、干咳无痰；以及风热上攻或肝火上炎、目赤肿痛等症，为常用的药品。配牛蒡子、前胡，则散风清肺；配石膏、麦冬，则清燥润肺；配菊花、决明子，则清肝明目。' where id=2028; -- 桑叶
update herbs set taste='味甘；微苦；性微寒', effect='①肺热咳嗽∶沙参半两。水煎服之。（《卫生易简方》） ②猝得疝气∶小腹及阴中相引痛如绞，自汗出，欲死者。沙参，捣筛为末，酒服方寸匕，立瘥。（《肘后方》） ③妇人白带∶多因七情内伤或下元虚冷所致。沙参为末，每服二钱，米饮调下。《证治要诀》' where id=2029; -- 沙参
update herbs set taste='甘，平。', channel='归肺经。', effect='①治一切劳咳嗽，雍滞胸膈痞满：雄黄、佛耳草，鹅管石、款冬花各等分。上为末，每服用药一钱，安在炉子上焚着，以开口吸烟在喉中。（《宣明论方》焚香透膈散） ②治咳嗽痰多：鼠曲草全草五、六钱，冰糖五、六钱。同煎服。（《江西民间草药》） ③治支气管炎、寒喘：鼠曲草、黄荆子各五钱，前胡、云雾草各三钱，天竺子四钱，荠尼根一两。水煎服。连服五天。一般需服一个月。（《浙江民间常用草药》） ④治风寒感冒：鼠曲草全草，五、六钱。水煎服。（《江西民间草药》） ⑤治蚕豆病：田艾二两，车前草、凤尾草各-两，茵陈半两。加水1200毫升，煎成800毫升，加白糖当茶饮。（《广东医药卫生科技资料选编》） ⑥治筋骨痛，脚膝肿痛，跌打损伤：鼠曲草一至二两。水煎服。（《湖南药物志》） ⑦治白带：鼠曲草、凤尾草、灯芯草各五钱，土牛膝三钱。水煎服。（《浙江民间常用草药》） ⑧治脾虚浮肿：鲜鼠曲草二两。水煎服。（《福建中草药》） ⑨治无名肿痛、对口疮：鲜鼠曲草一两。水煎服；另取鲜叶调米饭捣烂敷患处。（《福建中草药》） ⑩治毒疔初起：鲜鼠曲草合冷饭粒及食盐少许捣敷。（《泉州本草》） ⑾治疗慢性气管炎：据73例和91例的观察，总有效率约为81％，显效率分别为20.72％和29.6％。对咳、喘、痰均有不同程度疗效。制剂及用法：每日用鼠曲草干品1.2两制成浓缩煎液，3次分服；或每日1两，2次煎服。10天为一疗程，连服二疗程。副反应：初服时少数病例诉胃痛、胃部不适、恶心，个别觉口干，头昏，乏力，及出现大便稀薄。此外，用鼠曲草配合车前草，或连翘等组成复方治疗，疗效似有提高。' where id=2030; -- 鼠曲草
update herbs set taste='甘苦，寒，有毒。', effect='1.治疗白喉： 取三皮风鲜草，捣成泥状，加2倍量的冷开水浸泡4-6小时，过滤即成50%浸剂。服时加糖调味，日服4次。3岁以下首次量50ml，以后每次20-30ml； 3-5岁首次80ml，以后每次40-50ml；6-10岁首次100ml，以后每次60ml；10岁以 上首次150ml，以后每次100ml。经治471例；治愈率85%。 2.治疗细菌性痢疾： 以蛇莓制丸，每服3钱，或制成糖浆，每次20-40ml(小儿减半)，日 服3次，5-7天为一疗程。对高热、脱水、腹痛等配合常规处理。观察50例，治愈46例，好转1例，无效3例。治愈病例多数征1-2天内退热(最短4小时，最长6天)；2-3天内症状及 体征消失(最短 1天，最长6天)；大便在3-5天内转为正常，培养转阴。用药最短2天，最长 11天。治程中少数有恶心、呕吐、上腹部不适，余未发现其他不良反应。 3.治疗急性穿孔性阑尾炎：取鲜蛇莓2-4两(干品1-2两)、鲜白骨树根(乌柏树根Sapium s ebiferum Roxb．)5钱(干品3钱)，水煎二次分服。每天1-2剂。加减法：阑尾脓肿病例加 皂角刺3钱，急性阑尾炎合并局限性或弥漫性腹膜炎加用行气活血之药，并稍加大蛇莓用 量(每日鲜品不得超过6两，干品不得超过4两)；如为急性穿孔性阑尾炎则配合通里攻下药， 如铁扁担(鸢尾科蝴蝶花Iris tectorumMaxim，)鲜根5钱，磨水成浆顿服，或甘遂末每次3分 冲服。卧床休息。合并局限性腹膜炎，特别合并弥漫性腹膜炎病人，须采取斜坡卧位。其他酌情给予流质、半流质或短暂禁食。禁食者须注意水及电解质平衡，纠正酸中毒。共治疗50 例，其中阑尾脓肿 11例，合并局限性腹膜炎21例，弥漫性腹膜炎18例。结果治愈(自觉症状 消失；体温、白细胞正常，腹部体征完全消失)38例，近愈(自觉症状消失，体温、白细胞正常，但腹部有轻度深压痛或遗留有索条状硬结)8例，无效4例。住院因数最短4天，最长43天，平均17天。治程中体温、白细胞计数及分类恢复正常，腹痛及压痛消失所需最短时间分别 为1、2、3、5天，平均为5、8、5、11天。蛇莓、乌桕均有毒，但蛇莓1天量用至4-6两(鲜 )，白骨树根每天3-5钱，均未见毒性反应。部分病人服药质可有轻度阵发性腹痛，这是白骨树根导泻作用使肠蠕动增强所致，大便后阵痛即失。 4.治天行热盛，口中生疮： 蛇莓自然汁，捣绞一斗，煎取五升，稍稍饮之。(《 伤寒类要》) 5.治伤暑，感胃： 干蛇莓五至八钱，酌加水煎，日服二次。(《福建民间草药》) 6.治吐血咯血； 鲜蛇莓草二、三两，捣烂绞汁一杯，冰糖少许炖服。(《闽东本草》) 7.治咽喉肿痛： 鲜蛇莓草炖汤内服及漱口。(《闽东本草》) 8.治小儿口疮： 蛇泡草(研末)、枯矾末，混合，先用盐水加枯矾洗患处，再撒上药粉。( 《贵阳民间药草》) 9.治疟疾，黄疸， 鲜蛇莓叶捣烂，用蚕豆大一团敷桡骨动脉处，布条包扎。(《江西民间 草药》) 10.治痢疾： 鲜蛇莓全草一两，水煎服。(江西《草药手肠》)、 11.治蛇头疔，乳痈，背疮，疔疮： 鲜蛇莓草，捣烂，加蜜敷患处。初起未化脓者，加蒲公 英一两，共杵烂，绞汁一杯，调黄酒二两炖服，渣敷患处。(《闽东本草》) 12.治蛇窜丹： 蛇泡草适量，雄黄五分，大蒜一个。共捣烂，布包，外搽。(《贵阳民间药 草》) 13.治脓疱疮： 蛇泡草炖肉吃， 并捣烂外敷。(《贵阳民间药草》)1 14.治跌打损伤： 鲜蛇莓捣烂，甜酒少许，共炒热外敷。(《江西草药》) 15.治蛇咬伤，毒虫咬伤： 鲜蛇莓草，捣烂敷患处。(《江西民间草药》) 16.治小面积烧伤： 鲜蛇莓捣烂外敷。如创面有脓，加鲜犁头草；无脓，加冰片少许。( 《江西草药》) 17.治癌肿、疔疮： 蛇莓三钱至一两，煎服。(《上海常用中草药》) 18.治瘰疬： 鲜蛇莓草一至二两，洗净，煎服。(《上海常用中草药》)', tips='清热，凉血，消肿，解毒。治热病，惊痫，咳嗽，吐血，咽喉肿痛，痢疾，痈肿，疔疮，蛇虫咬伤，汤火伤。 ①《别录》：主胸腹大热不止。 ②陶弘景：疗伤寒太热。 ③《食疗本草》：主胸胃热气；主孩子口噤，以汁灌口中。 ④《日华子本草》：通月经，熁疮肿，敷蛇虫咬。 ⑤《纲目》：敷汤火伤。 ⑥《生草药性备要》：治跌打，消肿止痛，去瘀生新，浸酒壮筋骨。 ⑦《植物名实图考长编》：捣敷红线疔。 ⑧《四川中药志》：凉血，通经。治惊痫寒热，疗咽喉肿痛。 ⑨《闽东本草》：化痰止咳，祛风，活血。治伤风感冒，咳嗽，哮喘，风火牙痛，口舌生疮' where id=2031; -- 蛇莓
update herbs set taste='甘微苦，平。', channel='入心、肝经。', effect='①治彻夜不寐，间日轻重，如发疟：夜交藤（切）四钱，真珠母八钱，龙齿二钱，柴胡（醋炒）一钱，薄荷一钱，生地六钱，归身二钱，白芍（酒炒）一钱五分，丹参二钱，柏子仁二钱，夜合花二钱，沉香五分，红枣十枚。水煎服。（《医醇媵义》甲乙归脏汤） ②治腋疽：首乌藤、鸡屎藤叶各适量。捣烂，敷患处。（《广西民间常用草药》） ③治痔疮肿痛：首乌藤、假蒌叶、杉木叶各适量。煎水洗患处。（《广西民间常用草药》）' where id=2032; -- 首乌藤
update herbs set taste='甘咸，平。', channel='入心、肝经。', effect='1.苏木散(《痧胀玉衡》)，用治痧毒血瘀成块，坚硬突起不移者。 2.治妇人月水不通，烦热疼痛：苏枋木二两（锉），硇砂半两（研），川大黄（末）一两。上药，先以水三大盏，煎苏木至一盏半，去滓，入硇砂、大黄末，同熬成膏。每日空心，以温酒调下半大匙。（《圣惠方》苏枋木煎） 3.治产后气滞作喘：苏木、人参、麦门冬，水煎服。（《妇科玉尺》苏木汤） 4.治产后血运，腹闷，气喘急欲死：苏枋木（末）二两，荷叶（炙）一枚，芍药一两半，桂（去粗皮）一两，鳖甲（去裙襕，醋炙）一两半。上五味，锉如麻豆大，以水五盏，藕汁一合。同煎取二盏，去滓，入红雪一两，分温二服，粥食前，如人行三、五里再服。（《圣济总录》苏枋饮） 5.治血晕：苏木五钱，煎水，加童便一杯，顿服。（《陆川本草》） 6.治被打伤损，因疮中风：苏木（槌令烂，研）二两。用酒二升，煎取一升。分三服，空心、午时、夜卧各一服。（《圣济总录》苏木酒） 7.治破伤风：苏枋木不拘多少，捣罗为细散。每服三钱匕，酒调服之。（《圣济总录》独圣散） 8.治指断，亦治其余皮肤刀矢伤：真正沉重苏木，为细末，敷断指间，外用蚕茧包缚完固。（《摄生众妙方》接指方） 9.治偏坠肿痛：用苏木二两，好酒一壶。煮熟频饮。（《濒湖集简方》）' where id=2033; -- 苏木
update herbs set alias='枣仁，酸枣核。', taste='甘，平。', channel='入心、脾、肝、胆经。', effect='①治虚劳虚烦，不得眠：酸枣仁二升，甘草一两，知母二两，茯苓二两，芎劳二两。上五味，以水八升，煮酸枣仁得六升，纳诸药煮取三升，分温三服。（《金匮要略》酸枣仁汤） ②治骨蒸，心烦不得眠卧：酸枣仁二两。以水二大盏半，研滤取汁，以米二合煮作粥，候临熟，入地黄汁一合，更微煮过，不计时候食之。（《圣惠方》酸枣仁粥） ③治胆虚睡卧不安，心多惊悸：酸枣仁一两。炒熟令香，捣细罗为散。每服二钱，以竹叶汤调下，不计时候。（《圣惠方》） ④治心脏亏虚，神志不守，恐怖惊惕，常多恍惚，易于健忘，睡卧不宁，梦涉危险，一切心疾：酸枣仁（微炒，去皮）、人参各一两，辰砂（研细，水飞）半两，乳香（以乳钵坐水盆中研卜分。上四味研和停，炼蜜丸如弹子大。每服一粒，温酒化下，枣汤亦得，空心临卧服。（《局方》宁志膏） ⑤治胆风毒气，虚实不调，昏沉睡多：酸枣仁一两（生用），全梃蜡茶二两，以生姜汁涂炙，令微焦，捣罗为散。每服二钱，水七分，煎六分，无时温服。（《简要济众方》） ⑥治睡中盗汗：酸枣仁、人参、茯苓各等分。上为细末，米饮调下半盏。（《普济方》）' where id=2034; -- 酸枣仁
update herbs set alias='林兰、禁生，杜兰、石蓫，金钗花、千年润，黄草，吊兰花。', taste='甘淡微咸，寒。', channel='入胃、肺，肾经。', effect='①治温热有汗，风热化火，热病伤津，温疟舌苔变黑：鲜石斛三钱，连翘（去心）三钱，天花粉二钱，鲜生地四钱，麦冬（去心）四钱，参叶八分。水煎服。（《时病论》清热保津法） ②治中消：鲜石斛五钱，熟石膏四钱，天花粉三钱，南沙参四钱，麦冬二钱，玉竹四钱，山药三钱，茯苓三钱，广皮一钱，半夏一钱五分。甘蔗三两，煎汤代水。（《医醇腆义》祛烦养胃汤） ③治眼目昼视精明，暮夜昏暗，视不见物，名曰雀目：石斛、仙灵脾各一两，苍术（米泔浸，切，焙）半两。上三味，捣罗为散，每服三钱匕，空心米饮调服，日再。（《圣济总录》石斛散） ④治神水宽大渐散，昏如雾露中行，渐睹空中有黑花，渐睹物成二体，久则光不收，及内障神水淡绿色、淡白色者：天门冬（焙）、人参、茯苓各二两，五味（炒）半两，兔丝子（酒浸）七钱，干菊花七钱，麦门冬一两，熟地黄一两，杏仁七钱半，干山药、枸杞各七钱，牛膝七钱半，生地黄一两，蒺藜、石斛、苁蓉、川芎、炙草、枳壳（麸炒），青葙子、防风、黄连各五钱，草决明八钱，乌犀角半两，羚羊角半两。为细末，炼蜜丸，桐子大。每服三、五十丸，温酒、盐汤任下。（《原机启微》石斛夜光丸）', tips='温热病早期阴未伤者、湿温病未化燥者、脾胃虚寒者均禁服。 恶凝水石、巴豆。畏僵蚕、雷丸。 ②《百草镜》：惟胃肾有虚热者宜之，虚而无火者忌用。' where id=2035; -- 石斛
update herbs set alias='葚，桑实，文武实，黑椹，桑枣，桑葚子，桑果，桑粒，桑藨。', taste='甘、酸，寒。', channel='入肝、肾经。', effect='①治心肾衰弱不寐，或习惯性便秘：鲜桑椹一至二两，水适量煎服。（《闽南民间草药》） ②治瘰疬：文武实，黑熟者二斗许，以布袋取汁，熬成薄膏，白汤点一匙，日三服。（《素问病机保命集》文武膏） ③治阴症腹痛：桑椹，绢包风干过，伏天为末。每服三钱，热酒下，取汗。（《湃湖集简方》）' where id=2036; -- 桑椹
update herbs set taste='味辛；苦；性微温。', channel='入口、肝、脾经。', effect='①治癫痫：九节菖蒲（去毛焙干），以木臼杵为细末，不可犯铁器，用黑豮猪心以竹刀批开，砂罐煮汤送下，每日空心服二、三钱。（《医学正传》） ②治少小热风痫，兼失心者：菖蒲（石上一寸九节者），宣连、车前子、生地黄、苦参、地骨皮各一两。上为末，蜜和丸，如黍米大，每食后服十五丸，不拘早晚，以饭下。忌羊肉、血、饴糖、桃、梅果物。（《普济方》菖蒲丸） ③治痰迷心窍：石菖蒲、生姜。共捣汁灌下。（《梅氏验方新编》） ④治温热、湿温、冬温之邪，窜入心包，神昏谵语，或不语，舌苔焦黑，或笑或痉：连翘三钱（去心），犀角一钱，川贝母三钱（去心），鲜石菖蒲一钱。加牛黄至宝丹一颗，去蜡壳化冲。（《时病论》） ⑤治好忘：远志、人参各四分，茯苓二两，菖蒲一两。上四味治下筛，饮服方寸匕，日三。（《千金方》开心散） ⑥治心气不定，五脏不足，甚者忧愁悲伤不乐，忽忽喜忘。朝差暮剧，暮差朝发，狂眩：菖蒲、远志各二两，茯苓、人参各三两。上四味末之，蜜丸，饮服如梧子大七丸，日三。（《千金方》定志小丸） ⑦治诸食积、气积、血积、鼓胀之类：石菖蒲八两（锉），斑猫四两（去翅足，二味同炒焦黄色，拣去斑猫不用）。上用粗布袋盛起，两人牵掣去尽猫毒屑了，却将菖蒲为细末，（丸）如梧桐子大，每服三五十丸，温酒或白汤送下。（《奇效良方》） ⑧治风冷痹，身体俱痛：菖蒲（锉）、生地黄（去土，切）、枸杞根（去心）各四两，乌头（炮裂，去皮脐，锉）二两，生商陆根（去土，切）四两，生姜（切薄片）八两。上六味，以清酒三升渍一宿，暴干，复纳酒中，以酒尽为度，暴干，捣筛为细散。每服，空心温酒调一钱匕，日再服。（《圣济总录》菖蒲散） ⑨治耳聋：菖蒲根一寸，巴豆一粒（去皮心）。二物合捣，筛，分作七丸，绵裹，卧即塞，夜易之。（《补缺肘后方》菖蒲根丸） ⑩治耳聋耳鸣如风水声：菖蒲（米泔浸一宿，锉，焙）二两，猪肾（去筋膜，细切）一对，葱白一握（擘碎），米（淘）三合。上四味，以水三升半，（先）煮菖蒲，取汁二升半，去滓，入猪肾、葱白、米及五味作羹，如常法空腹食。（《圣济总录》菖蒲羹） ⑾治中暑腹痛：石苗蒲根三至五钱。磨水顿服。（《江西草药》） ⑿治噤口恶痢，粒米不入者：石菖蒲一两，川黄连、甘草、五谷虫各三钱.为末，蜜汤调送少许。（《本草汇言》） ⒀治霍乱吐泻不止：菖蒲（切焙）、高良姜、青橘皮（去白，焙）各一两，白术，甘草（炙）各半两。上五味捣为粗末，每服三钱匕，以水一盏，煎十数沸，倾出，放温顿服。（《圣济总录》菖蒲饮） ⒁治赤白带下：石菖蒲、破故纸，等分。炒为末，每服二钱，更以菖蒲浸酒调服，日一服。（《妇人良方》） ⒂治小便一日一夜数十行：-菖蒲、黄连，二物等分。治筛，酒服方寸匕。（《范汪方》） ⒃治痈肿发背：生菖蒲捣贴，若疮干，捣末，以水调涂之。（《经验方》） ⒄治跌打损伤：石菖蒲鲜根适量，甜酒糟少许，捣烂外敷。（《江西草药》） ⒅治喉痹肿痛：菖蒲根捣汁，烧铁秤锤淬酒一杯饮之。（《圣济总录》） ⒆治诸般亦眼，攀睛云翳：菖蒲自然汁，文武火熬作膏，日点之。（《圣济总录》） ⒇治阴汗湿痒：石菖蒲、蛇床子等分，为末。日搽二三次。（《济急仙方》）', tips='阴虚阳亢、烦躁汗多、咳嗽、吐血、精滑者慎服。 恶地胆、麻黄。 ②《日华子本草》：忌饴糖、羊肉。勿犯铁器，令人吐逆。 ③《医学入门》：心劳、神耗者禁用。' where id=2037; -- 石菖蒲
update herbs set taste='甘；辛；微苦，凉。', channel='入肺、脾、胃经。', effect='①治伤寒，温疫，风热壮热，头痛，肢体痛，疮疹已发未发：干葛（锉细）、升麻、芍药、甘草（锉，炙）各等分。上同为粗末，每服四钱，水一盏半，煎至一盏，量大小与之，温服无时，（《阎氏小儿方论》升麻葛根汤） ②治小儿痘、痧疹不明，发热头痛，伤风咳嗽，乳蛾痄腮：升麻五分，前胡八分，甘葛五分，黄芩一钱，栀子八分，炒牛蒡子一钱，甘草三分，桔梗五分，薄荷五分，川芎一钱。引用灯心煎服。（《滇南本草》升麻汤） ③治天行发斑疮，头面及身须臾周匝，状如火疮，皆戴白浆，随决随生（不即疗，剧者数日必死，疗得差后，疮瘢紫暗，弥岁方灭，此恶毒之气也）：水浓煮升麻，渍绵洗之。苦酒渍煮弥佳，但燥痛难忍。（《肘后方》） ④治雷头风，头面疙瘩肿痛，憎寒壮热，状如伤寒：升麻、苍术各五钱，荷叶一枚。煎服。（《医方集解》清震汤，即《素问病机保命集》升麻汤） ⑤治咽喉闭塞，津液不通：川升麻半两，马蓟子一分，白矾一分，马牙消一分，玄参一分。上药，捣罗为末，炼蜜和丸如楝子大。用薄绵裹，常含一丸咽津。（《圣惠方》升麻丸） ⑥治喉痹作痛：升麻片含咽，或以半两煎服取吐。（《仁斋直指方》） ⑦治阳毒为病，面赤斑斑如锦文，咽喉痛，唾脓血（五日可治，七日不可治）：升麻二两，当归一两，蜀椒（炒去汗）一两，甘草二两，鳖甲手指大一片（炙），雄黄半两（研）。上六味，以水四升，煮取一升，顿服之。老小再服取汗。（《金匮要略》升麻鳖甲汤） ⑧治口热生疮：升麻三十铢，黄连十八铢。上二味末之，绵裹含，咽汁。（《千金方》） ⑨治牙龈肉绽有根，牙疳肿痛，牙动摇欲落，牙齿不长，牙黄口臭：羌活一两，草龙胆（酒洗）一两五钱，羊胫骨灰二两，升麻四两。上为细末，以纱罗子罗骨灰，作微尘末，和匀。卧时贴在牙龈上。（《兰室秘藏》牢牙散） ⑩治胃热齿痛：升麻煎汤，热漱咽之。（《仁斋直指方》） ⑾治噤痢：绿色升麻（醋炒）一钱，莲肉（去心，炒焦黄）三十枚，人参三钱。水一钟，煎半钟饮之，蜜和为丸更妙，每四钱一服，白汤吞。（《医学广笔记》） ⑿治血崩：升麻五分，柴胡五分，川芎一钱，白芷一钱，荆芥穗六钱，当归六钱。水二碗，煎一碗，食远服，即止，多不过五、六服。（《墨宝斋集验方》） ⒀治产后忍物不尽，或经-月、半岁，一岁：升麻三两。以清酒五升，煮取二升，去滓，分再服，当吐下恶物，勿怪。（《千金方》） ⒁治心有风热，生浸淫疮徧体：升麻、大黄（锉，微炒）、黄芩（去黑心）、枳实（去瓤，麸炒令黄）、芍药各一两，甘草（炙）、当归（切，焙）各半两。粗捣筛，每服五钱匕，用水一盏半，入灯心一握，煎至一盏，去滓，空心晚食前服。（《圣济总录》升麻汤） ⒂治卒毒肿起，急痛：升麻苦酒磨敷上良。（《补缺肘后方》） ⒃治痈疽始作，坚硬，皮色紫亦，恶寒壮热，一、二日未成脓者：升麻、连翘、大黄（锉，炒）、生地黄（切，焙）、木香各一两，白鼓、玄参各三分。上七味，粗捣筛。每服五钱匕，水二盏，煎至一盏，入芒硝末半钱匕，去滓，空心温服，取利为度，未利再服。（《圣济总录》升麻汤） ⒄治肺痈吐脓血，作臭气，胸乳间皆痛：川升麻、桔梗（炒）、薏苡仁、地榆、子芩（刮去皮）、牡丹皮、白芍药各半两，甘草三分，上锉粗末，每服一两，水一升半，煎至五合，去滓，日二、三服。（《本事方》升麻汤） ⒅治热痹瘙痒：升麻煎汤饮，并洗之。（《千金方》） ⒆治大头瘟。恶寒发热，头面红肿痛，目不能开，喉咙不利，舌燥口渴，舌红苔黄，脉数有力。黄芩、黄连各15g，陈皮、甘草、玄参、柴胡、桔梗各10g，连翘、板蓝根、马勃、牛蒡子、薄荷各5g，僵蚕、升麻各3g。水煎服。方中升麻与柴胡配伍疏散风热，并引诸药上达头面，使风热疫毒之邪宣散透发，为佐使药。（《东垣试效方》普济消毒饮） ⒇治胃火上攻证。牙痛牵引头脑，面颊发热，其齿恶热喜冷；或牙宣出血，或牙龈肿痛溃烂；或唇舌颊腮肿痛；口气热臭，口干舌燥，舌红苔黄，脉滑大而数。生地黄、当归身各6g，牡丹皮9g，黄连6g，升麻6g。作汤剂，水煎服。方中升麻辛甘微寒，入胃与大肠经，清热解毒，升而能散，为臣药。（《脾胃论》清胃散） (21)治脾不升清证。头晕目眩，视物昏花，耳鸣耳聋，少气懒言，语声低微，面色萎黄，纳差便溏，舌淡脉弱。气虚发热证。中气下陷证。黄芪18g，炙甘草9g，人参（去芦）、升麻、柴胡、橘皮、当归身（酒洗）、白术各6g。水三盏，煎至一盏，去渣，早饭后温服。方中升麻轻清升散，为佐使药。（《内外伤辨惑论》补中益气汤）' where id=2038; -- 升麻
update herbs set taste='苦；甘；性平。', channel='入肝、肾经。', effect='①治腰背痛，肾气虚弱，卧冷湿地当风所得：独活三两，寄生、杜仲、牛膝、细辛、秦艽、茯苓、桂心、防风、芎藭、人参、甘草、当归、芍药、干地黄各二两。上十五味细锉，以水一斗，煮取三升。分三服。温身勿冷也。（《千金方》独活寄生汤） ②治妊娠眙动不安，心腹刺痛：桑寄生一两半，艾叶半两（微炒），阿胶一两（捣碎，炒令黄燥）。上药，锉，以水一大盏半，煎至一盏，去滓。食前分温三服。（《圣惠方》） ③治下血止后，但觉丹田元气虚乏，腰膝沉重少力：桑寄生，为末。海服一钱，非时白汤点服，（《杨氏护命方》） ④治毒痢脓血，六脉微小，并无寒热：桑寄生二两，防风、大芎二钱半，炙甘草三钱。为末。每服二钱，水一盏，煎八分，和滓服。（《杨氏护命方》） ⑤治膈气：生桑寄生捣汁一盏。服之。（《濒湖集简方》）', tips='补肝肾；强筋骨；祛风湿；安胎。主腰膝酸痛；筋骨痿弱；肢体偏枯；风湿痹痛；头错目眩；胎动不安，崩漏下血。用于风湿痹痛，腰膝酸软，筋骨无力，崩漏经多，妊娠漏血，胎动不安；高血压。 ①《本经》：主腰痛，小儿背强，痈肿，安胎，充肌肤，坚发、齿，长须眉。 ②《别录》：主金疮，去痹，女子崩中，内伤不足，产后余疾，下乳汁。 ③《药性论》：能令胎牢固，主怀妊漏血不止。 ④《日华子本草》：助筋骨，益血脉。 ⑤《滇南本草》：生槐树者，主治大肠下血、肠风带血、痔漏。生桑树者，治筋骨疼痛，走筋络，风寒湿痹。生花椒树者，治脾胃寒冷，呕吐恶心翻胃；又用治梅疮毒，妇人下元虚寒或崩漏。 ⑥《本草蒙筌》：散疮疡，追风湿，却背强腰痛。 ⑦《生草药性备要》：消热，滋补，追风。养血散热，作茶饮，舒筋活络。 ⑧《玉楸药解》：治痢疾。 ⑨《医林纂要》：坚肾泻火。 ⑩《本草再新》：补气温中，治阴虚，壮阳道，利骨节，通经水，补血和血，安胎定痛。 ⑾《药材学》：治动脉硬化性高血压。 ⑿《辽宁经济植物志》：治郁血性肾炎，月经困难，咯血，瘰疬，心脏诸病及早期肺病。 ⒀《湖南药物志》：治肝风昏眩，四肢麻木，酸痛，内伤咳嗽，小儿抽搐。 ⒁《广西药植名录》：除风湿，消肿，清热，祛痰，顺气，止咳。治痢疾，疮疥，吐血，子宫脱垂。' where id=2039; -- 桑寄生
update herbs set taste='味苦、微辛，性寒。', effect='①治水肿、食肿、气肿：水泽兰一两，臭草根五钱，五谷根四钱，折耳根三钱，石菖蒲三钱。煎水服，日服三次。（《贵州民间药物》） ②治水肿：水泽兰一两。煎水服。（《贵州草药》） ③治跌打伤肿痛：水泽兰适量，捣绒敷患处；另用水泽兰五钱，煎酒服。（《贵州草药》）', tips='利水除湿，活血散瘀，止血，解毒。主水肿，小便不利，黄疸，带下，痢疾，闭经，跌打损伤，尿血，崩漏，毒蛇咬伤。 ①《天宝本草》：通经活血。治跌打损伤，妇女崩带，瘰疬。 ②《贵州民间药物》：消肿利水，行气。' where id=2040; -- 水泽兰
update herbs set alias='真珠母，鳆鱼甲（陶弘景），九孔螺，千里光，鲍鱼皮，金蛤蜊皮。', taste='味咸；性寒。', channel='入肝、肾经。', effect='①治风毒气攻入头，眼昏暗及头目不利：石决明、羌活（去芦头）、草决明、菊花各一两，甘草（炙锉）半两。上五味，捣罗为散，每服二钱匕，水一盏，煎至六分，和滓，食后临卧温服。（《圣济总录》石决明散） ②治眩晕：石决明八钱，菊花四钱，枸杞子四钱，桑叶三钱。水煎服。（《山东中草药手册》） ③治目生白翳：石决明六钱，元明粉二钱，大黄一钱五分，菊花三钱，蝉蜕三钱，白蒺藜三钱。水煎服。（《山东中草药手册》） ④治眼生丁翳，根脚极厚，经久不差：石决明三分（捣碎细研，水飞过），乌贼鱼骨半两，龙脑一钱，真珠末三分，琥珀三分。同研令细，每以铜箸取如大豆大，日三度点之。（《圣惠方》石决明散） ⑤治眼生外障：石决明（火煅）、薄荷叶各一两，蒺藜子（炒去刺）、荆芥穗各二两，人参半两（蜜炙）。上于地上出火毒，研为末。食后，砂糖冷水调服。（《经验良方》石决明散） ⑥治青盲雀目：石决明一两（烧过存性），苍术三两（去皮）。为末，每服三钱，以猪肝披开，入药末在内扎定，砂罐煮熟，以气熏目，待冷食肝饮汁。（《眼科龙木论》） ⑦治怕日羞明：千里光、海金砂、甘草、菊花等分。上细切，每服八钱，水一盅半，煎至一盅，去渣，食后温服。（《眼科龙木论》千里光汤） ⑧治小肠五淋：石决明去粗皮，捣研细。上件药，如有软硬物淋，即添朽木细末，热水调下二钱匕。（《胜金方》） ⑨治锁喉风：石决明火烧醋炙三次，研细末，用米醋调，鹅羽蘸擦喉内，吐痰效。（《本草汇言》） ⑩治外伤出血：石决明适量，煅制成疏松细粉，过筛。将伤口洗净，撒上药粉，紧紧压迫即可。（内蒙古《中草药新医疗法资料选编》）' where id=2041; -- 石决明
update herbs set taste='甘；咸；凉；无毒。', effect='①治伤寒小便不通，小腹胀满：石燕火煅为末。葱白汤调下一字。（《小儿卫生总微论方》石燕散） ②治小便淋痛：石燕子七枚（捣黍米大），新桑根白皮三两（锉）。拌匀，分作七贴。每贴用水一盏，煎七分，空心、午前各一服。（《简要济众方》） ③治血淋心烦：石燕子、商陆、赤小豆、红花等分。为末。每服-钱，葱白汤调下。（《圣惠方》） ④治沙石淋痛不可忍：石燕子（烧令通赤，水中淬一两次，捣研水飞，焙干）、滑石、石苇（去毛）、瞿麦穗各一两。为末，糊丸如梧桐子大。煎瞿麦、灯心汤下十丸，食前服，日二、三。（《三因方》石燕丸） ⑤治赤白带下，多年不止：石燕一枚。磨水服。（《徐氏家传方》） ⑥治久患肠风痔漏，一、二十年不差，面色虚黄，饮食无味，及患脏腑损伤，多患泄泻，暑月常浑不止，及诸般淋沥，久患消渴，妇人月侯湛浊，赤白带下，多年不差：用石燕温水磨服，如弹丸大者一个，分三服，大小以此为准，晚食前更一服。若欲作散，须研细，水飞过，取白汁如泔乳者，澄，去水，曝干。每服半钱至一钱，清饭饮调下，温水亦得。（《灵苑方》） ⑦治拳毛倒睫：石燕子一对。磨水点搽眼。先以镊子摘去拳毛，乃点药，后以黄连水洗之。（《乾坤生意》） ⑧牢牙止痛：石燕三对（火煅醋淬七次），青盐、乳香各一两，细辛半两。为末揩之，荆芥汤漱口。一方去乳香、细辛，加麝香。（《纲目》）' where id=2042; -- 石燕
update herbs set taste='微苦；性平。', channel='入肝经。', effect='①治臂痛：桑枝一小升。细切，炒香，以水三大升，煎取二升，一日服尽，无时。（《本事方》） ②治水气脚气：桑条二两。炒香，以水一升，煎二合，每日空心服之。（《圣济总录》） ③治高血压：桑枝、桑叶、茺蔚子各五钱。加水1000毫升，煎成600毫升。睡前洗脚30～40分钟，洗完睡觉。（辽宁《中草药新医疗法展览会资料选编》双桑降压汤） ④治紫癜风：桑枝十斤（锉），益母草三斤（锉）。上药，以水五斗，慢火煎至五升，滤去渣，入小铛内，熬为膏。每夜卧时，用温酒调服半合。（《圣惠方》桑枝煎）', tips='祛风湿；通经络；行水气。主风湿痹痛；中风半身不遂；水肿脚气；肌体风痒。用于肩臂、关节酸痛麻木。 ①《本草图经》：疗遍体风痒干燥，脚气风气，四肢拘挛，上气，眼晕，肺气嗽，消食；利小便，兼疗口干。 ②《本草蒙筌》：利喘嗽逆气，消焮肿毒痈。 ③《本草汇言》：去风气挛痛。 ④《本草备要》：利关节，养津液，行水祛风。 ⑤《玉楸药解》：治中风歪斜，咳嗽。 ⑥《本草再新》：壮肺气，燥湿，滋肾水，通经，止咳除烦，消肿止痛。 ⑦《岭南采药录》：去骨节风疾，治老年鹤膝风。 ⑧《现代实用中药》：嫩枝及叶熬膏服，治高血压，手足麻木。' where id=2043; -- 桑枝
update herbs set taste='甘；苦；辛；涩；凉。', channel='肝；肺经。', effect='①治吐血咳嗽：㈠宝珠山茶，瓦上焙黑色，调红砂糖，日服不拘多少。㈡宝珠山茶十朵，红花五钱，白芨一两，红枣四两。水煎一碗服之，渣再服，红枣不拘时亦取食之。（王玷桂《不药良方》） ②治赤痢：大红宝珠山茶花，阴干为末，加白糖拌匀，饭锅上蒸三、四次服。（《救生苦海》） ③治痔疮出血：宝珠山茶，研末冲服。（《纲目拾遗》） ④治乳头开花欲坠、疼痛异常：宝珠山茶，焙研为末，用麻油调搽。（《纲目拾遗》）', tips='凉血止血；散瘀；消瘀肿。主吐血；衄血；咳血；便血；痔血；赤血痢；血淋；血崩；带下；烫伤；跌扑损伤。用于吐血，衄血，便血，血崩；外用治烧烫伤，创伤出血。 ①朱震亨：吐血、衄血、肠风下血，并用红者为末，入童溺、姜汁及酒调服，可代郁金。 ②《纲目》：汤火伤灼，研末麻油调涂。 ③《医林纂要》：补肝缓肝，破血去热。 ④《百草镜》：凉血、破血、止血。消痈肿跌扑，断久痢、肠风下血，崩带血淋，鼻衄吐血；外敷炙疮。 ⑤《本草再新》：治血分，理肠风，清肝火，润肺养阴。' where id=2044; -- 山茶花
update herbs set taste='甘，平。', channel='入肺、脾、肾经。', effect='①治脾胃虚弱，不思进饮食：山芋、白术各一两，人参三分。上三味，捣罗为细末，煮白面糊为丸，如小豆·大，每服三十丸，空心食前温米饮下。（《圣济总录》山芋丸） ②治湿热虚泄：山药、苍术等分，饭丸，米饮服。（《濒湖经验方》） ③治噤口痢：干山药一半炒黄色，半生用，研为细末，米饮调下。（《百一选方》） ④治心腹虚膨，手足厥冷，或饮过苦涩凉剂，晨朝未食先呕，或闻食即吐，不思饮食，此乃脾胃虚弱：山药一味，锉如小豆大，一半炒热，一半生用，为末，米饮调下。（《普济方）） ⑤补下焦虚冷，小便频敷，瘦损无力：薯蓣于沙盆内研细，入铫中，以酒一大匙，熬令香，旋添酒一盏，搅令匀，空心饮之，每旦一服。（《圣惠方》） ⑥治诸风眩运，益精髓，壮脾胃：薯蓣粉，同曲米酿酒；或同山茱萸、五味子、人参诸药浸酒煮饮。（《纲目》山药酒） ⑦治小便多，滑数不禁：白茯苓（去黑皮），干山药（去皮，白矾水内湛过，慢火焙干用之）。上二味，各等分，为细末，稀米饮调服。（《儒门事亲》） ⑧治痰气喘急：山药捣烂半碗，入甘蔗汁半碗，和匀，顿热饮之。（《简便单方》） ⑨治肿毒：山药，蓖麻子，糯米为一处，水浸研为泥，敷肿处。（《普济方》） ⑩治项后结核，或赤肿硬痛：生山药一挺（去皮），蓖麻子二个。同研贴之。（《救急易方》） ⑾治乳癖结块及诸痛日久，坚硬不溃：鲜山药和芎藭、白糖霜共捣烂涂患处。涂上后奇痒不可忍，忍之良久渐止。（《本经逢原》） ⑿治冻疮：山药少许，于新瓦上磨为泥，涂疮口上。（《儒门事亲》）', tips='有实邪者忌服。' where id=2045; -- 山药
update herbs set taste='辛；甘；温；无毒。', channel='入肺、肝经。', effect='①治骨蒸，殗殜，肺痿，卒心痛，霍乱吐利，时气瘴疟，赤白暴利，瘀血月闭，痃癖，丁肿，惊痫，小儿吐乳：白术、青木香、乌犀屑、香附子（炒去毛）、朱砂（研水飞）、诃黎勒（煨，去皮）、白檀香、安息香（别为末，用无灰酒一升熬膏）、沉香、麝香（研）、丁香、荜拨各二两，龙脑（研）、苏合香油（入安息香膏内）各一两，熏陆香（别研）一两。上为细末，入研药匀，用安息香膏，并炼白蜜和剂。每服旋丸如梧桐子大，井华水化服四丸，老人小儿可服一丸；温酒化服亦得，并空心服之。（《局方》苏合香丸） ②治卒大腹水病：真苏合香、水银、白粉等分。蜜丸，服如大豆二丸，日三，当下水。节饮，好自养。（《补缺肘后方》） ③治冻疮：苏合香溶解于酒精中涂敷之。（《现代实用中药》）' where id=2046; -- 苏合香
update herbs set taste='味酸；性微温。', channel='入肝、肾经。', effect='①治五种腰痛，下焦风冷，腰脚无力：牛膝一两（去苗），山茱萸一两，桂心三分，上药捣细罗为散，每于食前，以温酒调下二钱。（《圣惠方》） ②益元阳，补元气，固元精，壮元神：山茱萸（酒浸）取肉一斤，破故纸（酒浸一日，焙干）半斤，当归四两，麝香一钱。上为细末，炼蜜丸，梧桐子大。每服八十一丸，临卧酒盐汤下。（《扶寿精方》草还丹） ③治脚气上入少腹不仁：干地黄八两，山茱萸、薯蓣各四两，泽泻、茯苓、牡丹皮各三两，桂枝、附子（炮）各一两。上八味，末之，炼蜜和丸梧子大，酒下十五丸，日再服。（《金匮要略》崔氏八味丸） ④治肾怯失音，囟开不合，神不足，目中白睛多，面色刮白：熟地黄八钱，山萸肉、干山药各四钱，泽泻、牡丹皮、白茯苓（去皮）各三钱。上为末，炼蜜丸如梧子大。空心服，温水化下三丸。（《小儿药证直诀》地黄丸） ⑤治老人小水不节，或自遗不禁：山茱萸肉二两，益智子一两，人参、白才L各八钱，分作十剂，水煎服。（《方龙潭家秘》） ⑥治寒温外感诸症，大病差后不能自复，寒热往来，虚汗淋漓；或但热不寒，汗出而热解，须臾又热又汗，目睛上窜。势危欲脱，或喘逆，或怔忡，或气虚不足以息：萸肉二两（去净核），生龙骨一两（捣细），生牡蛎一两（捣细），生杭芍六钱，野台参四钱，甘草三钱（蜜炙）。水煎服。（《医学衷中参西录》来复汤） ⑦治脾气虚弱，冲脉不固之血崩。血崩或月经过多，色淡质稀，面色恍白，心悸气短，腰膝酸软，四肢乏力，舌淡，脉细弱。白术30g，生黄芪18g，龙骨24g，牡蛎24g，萸肉24g，生杭芍12g，海螵蛸12g，茜草9g，棕边炭16g，五倍子1.5g。水煎服。方中山茱萸和白芍为伍补益肝肾，调补冲任，敛阴摄血，为臣药。（《医学衷中参西录》固冲汤） ⑧ 治真阴不足证。腰酸腿软，头晕眼花，耳聋失眠，遗精滑泄，自汗盗汗，口燥舌干，舌红少苔，脉细。大怀熟地240g，山药、枸杞、山茱萸肉、川牛膝、菟丝子、鹿胶、龟胶各120g。用滚汤或淡盐汤送下。亦可水煎服。方中山茱萸养肝滋肾，涩精敛汗。为佐药。（《景岳全书》左归丸）', tips='凡命门火炽，强阳不痿，素有湿热，小便淋涩者忌服。 恶桔梗、防风、防己。' where id=2047; -- 山茱萸
update herbs set taste='味甘；性温。', channel='入肝、肾经。', effect='①治男妇精血不足，营卫不充等患：大怀熟地（取味极甘者，烘晒干以去水气）八两，沉香一钱（或白檀三钱亦可），枸杞（用极肥者，亦烘晒，以去润气）四两。每药一斤，可用高烧酒十斤浸之，不必煮，但浸十日之外，即可用。凡服此者，不得过饮，服完又加酒六、七斤，再浸半月，仍可用。（《景岳全书》地黄醴） ②治诸虚不足，腹胁疼痛，失血少气，不欲饮食，噏噏发热，及妇人经病，月事不调：熟干地黄（切，焙）、当归（去苗，切，焙）各等分。为细末后，炼蜜和丸梧桐子大，每服二、三十粒，食前白汤下。（《鸡峰普济方》万病丸） ③治喑痱，肾虚弱厥逆，语声不出，足废不用：熟干地黄、巴戟（去心）、山茱萸、石斛、肉苁蓉（酒浸，焙）、附子（炮）、五味子、宫桂、白茯苓、麦门冬（去心）、菖蒲、远志（去心）等分。上为末，每服三钱，水一盏半，生姜五片，枣一枚，薄荷同煎至八分，不计时候。（《宣明论方》地黄饮子） ④治骨蒸体热劳倦：热地黄、当归、地骨皮、枳壳（麸炒）、柴胡、秦艽、知母、鳖甲（炙）等分。末，水一盏，乌梅半个，煎七分，和梅热服。（《幼幼新书》地黄散） ⑤调益荣卫，滋养气血，治冲任虚损，月水不调，脐腹疞痛，崩中漏下，血瘕块硬，发歇疼痛，妊娠宿冷，将理失宜，胎动不安，血下不止，及产后乘虚，风寒内搏，恶露不下，结生瘕聚，少腹坚痛，时作寐热：当归（去芦，酒浸，炒）、川芎、白芍药、热干地黄（酒洒蒸）各等分。上为粗末，每服三钱，水一盏半，煎至八分，去渣热服，空心食前。（《局方》四物汤） ⑥治小便数而多：龙骨一两，桑螵蛸一两，熟干地黄一两，栝蒌根一两，黄连一两（去须）。上药，捣细罗为散，每于食前，以粥坎调下二钱。（《圣惠方》） ⑦治小儿肾怯失音，顖开不合，神不足，目中白睛多，面色咣白等：熟地黄八钱，山萸肉、干山药各四钱，泽泻、牡丹皮、白茯苓（去皮）各三钱。上为末，炼蜜丸，如梧子大，空心，温水化下三丸。（《小儿药证直诀》地黄丸） ⑧治气短似喘，呼吸促急，提不能升，咽不能降，气道噎塞，势极垂危者：熟地黄七、八钱，甚者一、二两，炙甘草二、三钱，当归二、三钱。水二盅，煎八分，温服。（《景岳全书》贞元饮） ⑨治水亏火盛，六脉浮洪滑大，少阴不足，阳明有余，烦热干渴，头痛牙疼失血等证：生石膏三、五钱，熟地三、五钱或一两，麦冬二钱，知母、牛膝各钱半。水一钟半，煎七分，温服或冷服。若大便溏泄者，乃非所宜。（《景岳全书》玉女煎） ⑩治肝木乘胃，胃脘当心而痛，及胁痛吞酸，吐酸，疝瘕，一切肝病：北沙参、麦冬、地黄、当归、枸杞、川楝。（《柳洲医话》一贯煎）' where id=2048; -- 熟地黄
update herbs set taste='味辛；性温。', channel='入肺、胃、脾经。', effect='①治感冒风寒：生姜五片，紫苏叶一两。水煎服。（《本草汇言》） ②治呕吐，百药不差：生姜一两，切如绿豆大，以醋浆七合，于银器煎取四合，空腹和滓旋呷之。（《食医心镜》） ③治病人胸中似喘不喘，似呕不呕，似哕不哕，心中愤愤然无奈者：半夏半升，生姜汁一升。上二味以水三升，煮半夏取二升，内生姜汁，煮取一升半，小冷。分四服，日三夜一服，止，停后服。（《金匮要赂》生姜半夏汤） ④治冷痰嗽：生姜二两，饧糖一两。水三碗，煎至半碗，温和徐徐饮。（《本草汇言》） ⑤治三十年咳嗽：白蜜一斤，生姜二斤（取汁）。上二味，先秤铜铫知斤两讫，内蜜复秤知数，次内姜汁以微火煎，令姜汁尽，惟有蜜斤两在，止。旦服如枣犬，含一丸，日三服。禁一切杂食。（《千金方》） ⑥治劳嗽：蜂蜜、姜汁各四两，白萝卜汁、梨汁、人乳各一碗。共熬成膏，早晚滚汤服数匙。（《经验广集》五汁膏） ⑦治伤寒汗出，解之后，胃中不和，心下痞梗，干噫食臭，胁下有水气，腹中雷鸣下利者：生姜（切）四两，甘草（炙）三两，人参三两，干姜一两，黄芩三两，半夏（洗）半升，黄连一两，大枣（擘）十二枚。上八味，以水一斗，煮取六升，去滓，再煎取三升。温服一升，日三服。（《伤寒论》生姜泻心汤） ⑧治心胸胁下有邪气结实，硬痛胀满者：生姜一斤，捣渣，留汁，慢炒待润；以绢包，于患处款款熨之，冷，再以汁炒，再熨良久，豁然宽快也。（《伤寒六书》） ⑨治霍乱心腹胀痛，烦满短气，未得吐下：生姜一斤。切，以水七升，煮取二升，分作三服。（《肘后方》） ⑩风湿痹痛：生姜汁和黄明胶熬贴。（《本草从新》） ⑾治中气昏厥，亦有痰闭者：生姜五钱，半夏、陈皮、木香各一钱五分，甘草八分。水煎，临服时加童便一盏。（《本草汇言》） ⑿治时行寒疟：生姜四两，白术二两，草果仁一两。水五大碗，煎至二碗，未发时早饮。（《本草汇言》） ⒀治胃气虚，风热，不能食：姜汁半鸡子壳，生地黄汁少许，蜜一匙头。和水三合，顿服。（《食疗本草》） ⒁治腹满不能服药：煨生姜，绵裹纳下部中，冷即易之。（《梅师集验方》） ⒂治手脱皮：鲜姜一两。切片，用酒二两单，浸二十四小时后，涂搽局部，一日二次。（内蒙古《中草药新医疗法资料选编》） ⒃治秃头：生姜捣烂，加温，敷头上，约二、三次。（《贵州中医验方》） ⒄治诸疮痔漏，久不结痂：生姜连皮切大片，涂白矾末，炙焦研细，贴之勿动。（《普济方》） ⒅治发背初起：生姜一块，炭火炙一层刮一层，为末，以猪胆汁调涂。（《海上方》） ⒆治赤白癜风：生姜频擦之良。（《易简方》） ⒇治猘犬咬人，重发：捣姜根汁饮之。（《补缺肘后方》） （21）治蝮蛇毒：末姜薄之，干复易。（《千金方》） （22）治跌扑伤损：姜汁和酒调生面贴之。（《易简方》） （23）牙齿疼痛，日夜呻吟：老生姜切片，安瓦上，用炭火，却将白矾掺姜上，候焦为末，擦疼处。（《海上方》赴筵散，又名晋矾散） （24）治百虫入耳：姜汁少许滴之。（《易简方》）' where id=2049; -- 生姜
update herbs set taste='味苦；咸；性寒。', effect='①治出血：牛、羊角及蹄甲，洗净后，放入密闭容器里焚烧炭化，研成细粉过筛。内出血，每日三次，每次二克，口服；外出血，撒于患处。（内蒙古《中草药新医疗法资料选编》） ②治喉痹肿塞欲死者：沙牛角，烧，刮取灰，细筛，和酒服枣许大，水调亦得。又小儿饮乳不快觉似喉痹者，亦取此灰涂乳上，咽下。（《海上集验方》） ③治石淋，破血：牛角烧灰，酒服方寸匕，日五服。（《圣济总录》） ④治血上逆心，烦闷刺痛：水牛角，烧末，酒服方寸匕。（《子母秘录》） ⑤治牛程攓肿痛，肿高突起，支脚难行，久则破裂，脓水相流：牛角尖（烧灰）、水龙骨、松香、轻粉各等分。共为末。牛骨髓调搽，虚弱者辣服十全大补汤。（《外科正宗》牛角散） ⑥治赤秃发落：牛角、羊角（烧灰）等分。猪脂调涂。（《圣惠方》） ⑦治蜂螫人：牛角烧灰，苦酒和，涂之。（《补缺肘后方》）' where id=2050; -- 水牛角
update herbs set taste='味咸；苦；性平；有毒。', channel='入肝、膀胱经。', effect='①治妇人经水不利下，亦治男子膀胱满急有瘀血者：水蛭三十个（熬），虻虫三十个（去翅、足，熬），桃仁二十个（去皮、尖），大黄三两（酒浸）。上四味为末，以水五升，煮取三升，去滓，温服一升。（《金匮要略》抵当汤） ②治妇人腹内有瘀血，月水不利，或断或来，心腹满急：桃仁三两（汤浸，去皮、尖、双仁，麸炒微黄），虻虫四十枚（炒微黄，去翅、足），水蛭四十枚（炒微黄），川大黄三两（锉碎微炒）。上药捣罗为末，炼蜜和捣百余杵，丸如梧桐子大。每服，空心以热酒下十五丸。（《圣惠方》桃仁丸） ③治月经不行，或产后恶露，脐腹作痛：熟地黄四两，虻虫（去头、翅炒）、水蛭（糯米同炒黄，去糯米）、桃仁（去皮、尖）各五十枚。上为末，蜜丸，桐子大。每服五、七丸，空心温酒下。（《妇人良方》地黄通经丸） ④治漏下去血不止：水蛭治下筛，酒服一钱许，日二，恶血消即愈。（《千金方》） ⑤治折伤：水蛭，新瓦上焙干，为细末，热酒调下一钱，食顷，痛可，更一服，痛止。便将折骨药封，以物夹定之。（《经验方》） ⑥治金疮，打损及从高坠下、木石所压，内损瘀血，心腹疼痛，大小便不通，气绝欲死：红蛭（用石灰慢火炒令焦黄色）半两，大黄二两，黑牵牛二两。上各为细末，每服三钱，用热酒调下，如人行四、五里，再用热酒调牵牛末二钱催之，须脏腑转下恶血，成块或成片，恶血尽即愈。（《济生方》夺命散）' where id=2051; -- 水蛭
update herbs set taste='酸甘；微温；无毒。', channel='入脾、胃、肝经。', effect='①治一切食积：山楂四两，白术四两，神曲二两。上为末，蒸饼丸，梧于大，服七十丸，白汤下。（《丹溪心法》） ②治食肉不消：山楂肉四两，水煮食之，并饮其汁。（《简便单方》） ③治诸滞腹痛：山楂一味煎汤饮。（《方脉正宗》） ④治痢疾赤白相兼：山楂肉不拘多少，炒研为末，每服一、二钱，红痢蜜拌，白痢红白糖拌，红白相兼，蜜砂糖各半拌匀，白汤调，空心下。（《医钞类编》） ⑤治肠风：酸枣并肉核烧灰，米饮调下。（《百一选方》） ⑥治老人腰痛及腿痛：棠梂子、鹿茸（炙）等分。为末，蜜丸梧子大，每服百丸，日二服。（《纲目》） ⑦治寒湿气小腹疼，外肾偏大肿痛：茴香、柿楂子。上等分为细末，每服一钱或二钱，盐、酒调，空心热服。（《百一选方》） ⑧治产妇恶露不尽，腹中疼痛，或儿枕作痛：山楂百十个，打碎煎汤，入砂糖少许，空心温服。（朱震亨）' where id=2052; -- 山楂
update herbs set effect='1．治疗小儿哮喘。蜂房6克，地龙10克，桔梗6克，苏子12克，白果10克，百部10克，天竺黄3克，诃子6克。水煎服，每日1剂，日服2次。（蜂龙汤《丁金元方》） 2．治疗慢性支气管炎。板蓝根20克，黄芩10克，浙贝10克，橘红10克，天竺黄15克，元参12克，炒杏仁10克，白前10克，鱼腥草15克，芦根20克，炙紫菀12克，甘草10克。水煎服，轻者，日服1剂，2次服，重者，每日2剂，日服4-6次。（清肺化痰汤《郭中元方》）', tips='清热豁痰，凉心定惊。用于热病神昏，中风痰迷，小儿痰热惊痫、抽搐、夜啼。' where id=2053; -- 天竺黄
update herbs set effect='1．治渐加羸瘦。天门冬一两半（去心、焙），前胡三分（去芦头），赤茯苓一两，甘草三分（炙微赤、锉），川升麻三分，百合半两，黄芩三分，白前半两，柴胡一两（去苗），杏仁二分（汤浸，去皮尖双仁，麸炒微黄），桑根白皮一两（锉），桔梗一两（去芦头）。上为粗散，每服四钱，以水一中盏，加生姜半分，煎至六分，去滓，食后温服。（天门冬散《圣惠方》卷三十一） 2．治润肺补肺，久服补五脏，养肌肤。天冬不拘多少。上药滚汤泡去皮，取起晒干，半捶去心，捣如泥，入砂锅内，水煮成稀糊，布滤过，再入蜜糖，和匀煮稠，瓷罐收贮。每服三、五钱，早、晚、日中随意滚水或酒送下。（天冬膏《惠直堂方》卷一） 3．治唇焦舌干，腮颊生疮。天门冬（慢火炙），玄参（汤洗、焙干），牛蒡节子（炒）各一两，白药煎、紫苏叶各半两、甘草（炙），人参各一两半。上为细末，炼蜜为丸。每服一丸。食后噙化、咽津。（天门冬丸《御药院方》卷九）', tips='养阴润燥，清肺生津。用于肺燥干咳，顿咳痰黏，咽干口渴，肠燥便秘。' where id=2054; -- 天冬
update herbs set taste='苦，凉。', effect='①治乳痈初起：㈠白芷、土贝母等分。为细末，每服三钱，陈酒热服，护暖取汗即消。重者再一服。如壮实者，每服五钱。㈡白芷梢、土贝母、天花粉各三钱，乳香（去油）一钱五分。共炒研末，白酒浆调搽，再用酒浆调服三钱。（《纲目拾遗》） ②治乳岩：阳和汤加土贝母五钱煎服。（《纲目拾遗》） ③治乳岩已破：大贝母、核桃桶、金银花。连翘各三钱。酒、水煎服。（《姚希周经验方》） ④治手发背：生甘草、炙甘草各五钱，皂刺二钱五分，土炒土贝五钱五分，半夏一钱五分，甲片二钱五分（炒黑），知母二钱五分。加葱、姜、水、酒煎。（《慈惠小编》） ⑤治疬串不论已破未破皆治：土贝母半斤，牛皮胶四两（敲碎，牡蛎粉炒成珠，去粉为细末）。水发丸，绿豆大，每日早晚，用紫背天葵根三钱，或用海藻、昆布各钱半，煎汤吞丸三钱。 ⑥治疬串：牛皮胶（水熬化）一两，入土贝母末五钱，摊油纸上贴之。 ⑦治鼠疮：大鲫鱼一尾，皂角内独子，每岁一个，川贝母二钱，土贝母二钱。将皂角子、贝母、入鱼肚内，黄泥包裹，阴阳瓦炭火焙干，存性，研细末。每服三钱，食后黄酒调服，忌荤百日。（⑤方以下出《纲目拾遗，） ⑧治颈淋巴结核未破者：土贝母三钱，水煎服，同时用土贝母研粉，醋调外敷。（《陕西中草药》） ⑨治毒蛇咬：急饮麻油一碗，免毒攻心，再用土贝母四、五钱为末，热酒冲服，再饮尽醉，安卧少时，药力到处，水从伤口喷出，侯水尽，将碗内贝母渣敷伤口。（《祝穆试效方》） ⑩治刀割斧砍，夹剪、枪、箭伤损：土贝母末默之，止血收口。（《年希尧集验良方》）', tips='清热化痰；散结拔毒。主乳痈；瘰疬痰核；疮疡肿毒；蛇虫啼伤。用于乳痈，瘰疬，乳腺炎，颈淋巴结结核，慢性淋巴结炎，肥厚性鼻炎。 ①《本草从新》：治外科痰毒。 ②《百草镜》：能散痈毒，化脓行滞，解广疮结毒，除风湿，利痰，敷恶疮敛疮口。 ③《陕西中草药》：清热解毒消肿。治淋巴腺结核，急性乳腺炎初起，痈肿。' where id=2055; -- 土贝母
update herbs set taste='味甘；微苦；性微寒。', channel='入肺、胃经。', effect='①治百合病渴：栝蒌根、牡蛎（熬）等分。为散，饮服方寸匕。（《永类钤方》） ②治大渴：深掘大栝蒌根，厚削皮至白处止，以寸切之，水浸一日一夜，易水经五日，取出烂舂碎研之，以绢袋滤之，如出粉法干之。水服方寸匕，日三、四，亦可作粉粥，乳酪中食之，不限多少，取差，止。（《千金方》） ③治消渴，除肠胃热实：栝蒌根、生姜各五两，生麦门冬（用汁）、芦根（切）各二升，茅根（切）三升.上五味细切，以水一斗，煮取三升，分三服。（《千金方》） ④治黑疸危疾：瓜蒌根一斤，捣汁六合，顿服，随有黄水从小便出，如不出，再跟。（《简便单方》） ⑤治小儿忽发黄，面目皮肉并黄：生栝蒌根捣取汁二合，蜜一大匙，二味暖相和，分再服。（《广利方》） ⑥治虚热咳嗽：天花粉一两，人参三钱。为末，每服一钱，米汤下。（《濒湖集简方》） ⑦治痈未溃：栝楼根、赤小豆等分。为末，醋调涂之。（《证类本草》） ⑧治胃及十二指肠溃疡：天花粉一两，贝母五钱，鸡蛋壳十个。研面，每服二钱，白开水送下。（《辽宁常用中草药手册》） ⑨治痈肿：栝蒌根，苦酒熬燥，捣筛之。苦酒和涂纸上摊贴。（《食疗本草》） ⑩治乳头溃疡：天花粉二两，研末，鸡蛋清调敷。（内蒙古《中草药新医疗法资料选编》） ⑾治产后吹乳，肿硬疼痛，轻则为妒乳，重则为乳痈：栝蒌根一两，乳香一钱。为末，温酒调下，每服二钱。（《永类钤方》） ⑿治天泡疮：天花粉、滑石等分。为末，水调搽。（《苷济方》） ⒀治杨梅天泡：天花粉、川芎藭各四两，槐花一两。为末，米糊丸，梧子大。每空心淡姜汤下七、八十丸。（《简便单方》） ⒁治跌打损伤，胸膛痛疼难忍，咳嗽多年不止：天花粉不拘多少，每服二钱，用石膏豆腐卤调服。（《滇南本草》） ⒂治疮疹入眼成翳：栝蒌根半两，蛇皮二钱。上同为细末，用羊肝一个，批开，入药末二钱，麻缠定，米泔煮熟，频与食之。未能食肝，乳母多食。（《阎氏小儿方论》）', tips='脾胃虚寒大便滑泄者忌服。 恶干姜。畏牛膝、干漆。反乌头。 ②《本草汇言》：汗下之后，亡液而作渴者不可妄投；阴虚火动，津液不能上承而作渴者，不可概施。 ③《得配本草》：胃虚湿痰，亡阳作渴，病在表者禁用。 ④《本草经疏》：脾胃虚寒作泄者勿服。 ⑤《本经逢原》：凡痰饮色勺清稀者，忌用。' where id=2056; -- 天花粉
update herbs set taste='味辛、苦，性温。有小毒。。', effect='①治风气疼痛，不拘远年近日：透骨草二两，穿山甲二两，防风二两，当归三两，白蒺藜四两，白芍三两，稀莶四两（去茎用叶，九蒸九晒），海风藤二两，生地四两，广皮一两，甘草一两。以上为末，用猪板油一斤，炼蜜为丸梧桐子大。早晚各服五钱，酒下。（《周益生家宝方》） ②治风湿性关节炎，筋骨拘挛：透骨草三钱，制川乌、制草乌各一钱，伸筋草二钱。水煎服。（《陕甘宁青中草药选》） ③治肿毒初起：透骨草、漏芦、防风、地榆等分。煎汤绵蘸，乘热不住荡之。（《杨诚经验方》） ④治阴囊湿疹，疮疡肿毒：透骨草、蛇床子、白藓皮、艾叶。煎水外洗。（《陕甘宁青中草药选》）' where id=2057; -- 透骨草
update herbs set taste='辛；苦；寒。', channel='入肺、膀胱经。', effect='①治肺壅咳嗽脓血，喘嗽不得睡卧：甜葶苈二两半（隔纸炒令紫）。为末，每服二钱，水一盏，煎至六分，不拘时温服。（《世医得效方》葶苈散） ②治嗽：葶苈子一两（纸衬熬令黑），知母一两，贝母一两。三物同捣筛，以枣肉半两，别销沙糖一两半，同入药中为丸，大如弹丸，每服以新绵裹一丸含之，徐徐咽津，甚者不过三丸。（《箧中方》含膏丸） ③治上气咳嗽，长引气不得卧，或水肿，或遍体气肿，或单面肿，或足肿：葶苈子三升，微熬，捣筛为散，以清酒五升渍之，春夏三日，秋冬七日。初服如胡桃许大，日三夜一，冬日二夜二，量其气力，取微利为度，如患急困者，不得待日满，亦可以绵细绞即服。（《外台秘要方》） ④治咳嗽痰涎喘急：葶苈半两，半夏（生姜汁浸软，切作片子）半两，巴豆四十九粒（去皮，同上二味一处炒，候半夏黄为度）。上件除巴豆不用，只用上二味为细末，每服一钱，以生姜汁入蜜少许同调下，食后。（《杨氏家藏方》葶苈散） ⑤治肺痈喘不得卧：葶苈（熬令黄色、捣，丸如弹子大），大枣十二枚。上先以水三升，煮枣取二升，去枣内葶苈，煮取一升，顿服。（《金匮要略》葶苈大枣泻肺汤） ⑥治卒大腹水病：葶苈一两，杏仁二十枚。并熬黄色，捣，分十服，小便去，瘥。（《补缺肘后方》） ⑦治阳水暴肿，面赤烦渴，喘急，小便涩：甜葶苈一两半（炒，研末），汉防己（末）二两。以绿头鸭血及头，合捣万杵，丸如梧子大，甚者，空腹白汤下十丸，轻者五丸，日三、四服，五日止。小便利为验。（《外台秘要方》） ⑧治肿满腹大，四肢枯瘦，小便涩浊：甜葶苈（纸隔炒）、荠菜根等分。上为末，蜜丸如弹子大。每服一丸，陈皮汤嚼下，只三丸，小便清，数丸，腹当依旧。（《三因方》葶苈大丸） ⑨治男女大小头面手足肿：苦葶苈炒研，枣肉和丸，小豆大，每服十丸，煎麻子汤下，日三服，五七日小便多，则消肿也。忌咸酸生冷。（《外科精义》） ⑩治腹满口舌干燥，此肠间有水气：防己、椒目、葶苈（熬）、大黄各一两。上四味，末之，蜜丸如梧子大。先食饮服一丸，日三服，稍增，口中有津液，渴者，加芒硝半两。（《金匮要赂》已椒苈黄丸） ⑾治头风疼痛：葶苈子为末，以酒淋汁沐头，三、四度。（《肘后方》） ⑿治瘰疬结核：葶苈子二合，豉半斤（汤浸令软）。上药，都捣熟，捻作饼子如钱厚，安在疬子上，以艾炷如小指大，灸饼上，五日一度，灸七壮。（《圣惠方》葶苈饼子法） ⒀治小儿白秃：葶苈捣末，以汤洗讫涂上。（《子母秘录》） ⒁治月经不通：葶苈一升。为末，蜜丸如弹子大。绵裹纳阴中，入三寸，每丸一宿易之，有汁出止。（《千金方》） ⒂治疳虫蚀齿：葶苈，雄黄等分。为末，腊月猪脂和成，以绵裹槐枝蘸点。（《金匮要略》）', tips='肺虚喘咳、脾虚肿满者忌服。 得酒良。恶僵蚕、石龙芮。 ②《别录》：久服令人虚。 ③《本草经疏》：不利于脾胃虚弱及真阴不足之人。凡肿满由于脾虚不能制水，水气泛溢；小便不通由于膀胱虚无气以化者，法所咸忌。 ④《本草便读》：寒饮、阴水等证及虚弱者，不可用也。' where id=2058; -- 葶苈子
update herbs set taste='味辛，温。', channel='入脾，胃、肺经。', effect='①治心腹诸痛，属半虚半实者：丹参一两，白檀香、砂仁各一钱半。水煎服。（《医学金针》丹参饮） ②治心腹冷痛：白檀香三钱（为极细末），干姜五钱。泡汤调下。（《本草汇言》） ③治噎膈饮食不入：白檀香4.5g，茯苓、橘红各6g。为极细末，人参汤调下。方中檀香散寒开胃，为君药。（《本草汇言》） ④治阴寒霍乱：白檀香、藿香梗、木香、肉桂各4.5g,为极细末，每用3g，炮姜15g，汤调下。方中檀香行气止痛，为君药。（《本草汇言》） ⑤解恶毒风肿：白檀香、沉香各一块，重一分，槟榔一枚。上三味各于砂盆中以水三盏细磨取尽，滤去滓，银石铫内煎沸，候温，分作三服。（《圣济总录》檀香饮） ⑥治胃有停饮，或伤冷食胸痞脘痛，呕吐黄水：檀香、炙甘草各1.5g，姜半夏、茯苓各9g，砂仁2.4g，炒陈皮6g。水煎服。若痛甚加白蔻末0.6g，瓦楞子末3g；呕甚加控涎丹2.4g包煎。方中檀香行气止痛，散寒开胃，为君药。（《重订通俗伤寒论》香砂二陈汤）' where id=2059; -- 檀香
update herbs set taste='味辛；淡；性平。', channel='入肺、大肠、肝经。', effect='①治赤白痢，泄泻：金石榴全草五钱至一两，水煎服。（《湖南药物志》） ②治吐血：鲜金锦香一两，当归二钱。水煎服。（《泉州本草》） ③治便血、下痢：金锦香、木槿花。炖服。一方以金锦香一两，冰糖五钱，开水适量冲炖服。（《闽东本草》） ④治脱肛：金锦香二至五钱，水煎服。（《闽东本草》） ⑤治月经不调：金锦香干根一至二两，益母草三钱，水煎调酒、糖服。（《福建中草药》） ⑥治跌打损伤：鲜金锦香一两，捣绞汁泡温酒服。（《泉州本草》） ⑦治久伤胸闷痛：金锦香全草五钱至一两，酒水煎服。（《福建中草药》） ⑧治风寒咳嗽：金锦香五钱，水煎服。（《湖南药物志》） ⑨治小儿疳积：天香炉、山地粘等分。为末，每服五分，蒸瘦猪肉服。（《广西中药志》） ⑩治风火牙痛：蜂窝草炖猪肉服。（《四川中药志》）', tips='化痰利湿；祛瘀止血；解毒消肿。主咳嗽；哮喘；痢疾；泄泻；吐血；咯血；便血；经闭；疳积；风湿骨痛；跌打损伤。 ①《生草药性备要》：治痢去痰；牙痛煲水含；通经捶汁开酒服。 ②《岭南采药录》：止痛，去蛇毒，理疮疡。 ③《陆川本草》：去腐止血。治口腔炎，小儿头上热气疮，咳血。 ④《南宁市药物志》：去瘀生新，止痛收敛。治内外出血，疳积，牙疳，牙痛，咳嗽。 ⑤《广西中药志》：治红白痢疾，热泻。 ⑥《四川中药志》：祛风湿，止咳嗽。治风湿骨痛，小儿百日咳，蜂窝疮。 ⑦《泉州本草》：主跌打损伤，妇人经闭，产后瘀血作痛，亦治胸胃气痛，白浊。 ⑧《岭南草药志》：化湿消滞，解热镇痛。 ⑨《闽东本草》：治脱肛便血。' where id=2060; -- 天香炉
update herbs set taste='甘；微苦；微酸；性寒。', effect='①治男妇诸淋，小便不通：土牛膝连叶，以酒煎服数次。血淋尤验。（《岭南采药录》） ②治血滞经闭：鲜土牛膝一至二两，或加马鞭草鲜全草一两。水煎，调酒服。（《福建中草药》） ③治风湿性关节痛：鲜土牛膝六钱至一两（干的四至六钱）和猪脚一个（七寸），红酒和水各半煎服。（《福建民间草药》） ④治肝硬变水肿：鲜土牛膝六钱至一两（干的四至六钱）。水煎，饭前服，日服两次。（《福建民间草药》） ⑤治痢疾：土牛膝五钱，地桃花根五钱，车前草三钱，青荔三钱。水煎，冲蜜糖服。（《广西中草药》）。 ⑥治白喉：鲜土牛膝一至二两，加养阴清肺汤（生地、元参、麦冬、川贝母、丹皮、白芍，甘草、薄荷）。水煎服，每日一至二剂；另用朱砂一分，巴豆一粒，捣烂，置于膏药上，贴印堂穴，六至八小时皮肤起泡后取下。 ⑦治白喉并发心肌炎：鲜土牛膝五钱，鲜万年青根三钱，捣烂取汁，加白糖适量，温开水冲服。 ⑧治扁桃腺炎：土牛膝、百两金根各四钱，冰片二钱。研极细末，喷喉。 ⑨治急性中耳炎：鲜土膝适量，捣汁，滴患耳。（⑥方以下出《江西草药》） ⑩治足腿红肿放亮，其热如火，名流火丹：土牛膝捣烂，和马前子及旧锈铁磨水，豆腐渣凋匀，微温敷之。（《岭南采药录》） ⑾治跌打损伤：土牛膝三至五钱。水煎，酒对服。（《江西草药》）' where id=2061; -- 土牛膝
update herbs set taste='味苦；性微寒。', effect='①治喉头炎，口腔溃烂：大苦藤泡水服。（《云南思茅中草药选》） ②治肠胃炎，胃痛，黄疸型肝炎：扁藤根茎一两。水煎服。（《红河中草药》） ③治疔疮肿毒：通光散鲜叶适量。捣烂外敷。（《云南经济植物》） ④治各种癌症：通光散一两至一两五钱，白胡椒十粒。煎服。（《云南中草药选》）', tips='清热解毒；止咳平喘；通利湿通乳；搞癌。主咽喉肿痛；肺热咳喘；湿热黄疸；小便不利；乳汁不通；疮疖；癌肿。用于上呼吸道感染，支气管炎，支气管哮喘，乳汁不通，小便不利，癌肿；叶外用治痈疖疮疡。 ①《云南中草药选》：消炎，止咳，平喘，抗癌。治支气管炎，支气管哮喘，各种癌症，风湿，跌打，骨折，眼底疾患，胃病。 ②《云南思茅中草药选》：清热解毒，消炎止痛。治咽喉炎，胃肠积热，肺炎，扁桃体炎，膀胱炎。 ③《贵州药植目录》：活血生肌，催乳，止咳。治咳嗽，跌打，筋断骨折，乳少。' where id=2062; -- 通光散
update herbs set taste='甘淡，平。', channel='入肝、胃经。', effect='①治杨梅疮毒：土茯苓一两或五钱，水酒浓煎服。（《滇南本草》） ②治杨梅风十年二十年，筋骨风泡肿痛：土茯苓三斤，川椒二钱，甘草三钱，黑铅一斤，青藤三钱。将药用袋盛，以好酒煮服之妙。（《赤水玄珠》） ③治血淋：土茯苓、茶根各五钱。水煎服，白糖为引。（《江西草药》） ④治风湿骨痛，疮疡肿毒：土茯苓一斤，去皮，和猪肉炖烂，分数次连滓服。（《浙江民间常用草药》） ⑤治风气痛及风毒疮癣：土茯苓（不犯铁器）八两。石臼内捣为细末，糯米一斗，蒸熟，白酒药造成醇酒用，酒与糟俱可食。（《万氏家抄方》土茯苓酒） ⑥治大毒疮红肿，未成即滥：土茯苓，为细末，好醋调敷。（《滇南本草》） ⑦治瘰疬溃烂：冷饭团，切片或为末，水煎服。或入粥内食之，须多食为妙。忌铁器、发物。（《积德堂经验方》） ⑧治皮炎：土茯苓二至三两。水煎，当茶饮。（《江西草药》） ⑨治妇人红崩、白带：土茯苓，水煨，引用红沙糖治红崩，白沙糖治白带。（《滇南本草》） ⑩治小儿疳积面黄肌瘦，肚子大，烦躁爱哭，啼哭无声，不想吃东西，大便失调，皮肤粗糙：土茯苓三钱，野棉花根三钱。研细末，加猪肝二两与水炖服，或米汤冲服。（《草医草药简便验方汇编》） ⑾治瘿瘤：土茯苓五钱，金锁银开、黄药子各三钱，白毛藤五钱，乌蔹莓根、蒲公英各四钱，甘草、金银花各二钱，煎服。（《浙江民间中药》） ⒇治杨梅疮，不拘初起溃烂：土茯苓120g，桔梗30g，防风30g，乳香1.5g，没药1.5g。水5碗煎至3碗，温服1日服尽。方中土茯苓解毒，为君药。（《万病回春》茯苓汤） (21)治时疮，不拘初起溃烂：土茯苓15g，当归、白皂角刺各3g，木瓜2.1g，薏苡仁3g，白鲜皮、木通、金银花各2.1g，炙甘草1.5g。水煎，每日一剂，日服2次。方中土茯苓解毒，除湿，为君药。（《外科枢要》换肌消毒散） (22)治杨梅风十年二十年，筋骨风泡肿痛：土茯苓3斤，川椒6g，甘草9g，黑铅1斤，青藤9g。将药用袋盛，以好酒煮服之妙。方中土茯苓解毒，除湿，利关节，为君药。（《赤石玄珠》）' where id=2063; -- 土茯苓
update herbs set effect='① 治月经不调：一鲜铁苋菜二两，水煎服。（《青海常用中草药手册》）二铁苋菜全草。熬膏，每次服一至二钱，早晚服。（《内蒙古中草药》） ② 治崩漏：铁苋菜，蒲黄炭各三钱，藕节炭五钱，水煎服。（《青海常用中草药手册》） ③ 治吐血，衄血：铁苋菜、白茅根各一两，水煎服。（《内蒙古中草药》） ④ 治血淋：鲜铁苋菜一两，蒲黄炭、小蓟、木通各三钱，水煎服。（《青海常用中草药手册》） ⑤ 治疮痈肿毒，蛇虫咬伤：鲜铁苋菜适量，捣烂外敷。（《内蒙古中草药》）', tips='清热解毒，利湿，收敛止血。用于肠炎，痢疾，吐血、衄血、便血、尿血，崩漏；外治痈疖疮疡，皮炎湿疹。 ①《东北药植志》：止血。 ②《黑龙江中药》：用于月经不调，妇女血病。 ③《东北常用中草药手册》：治月经不调，崩漏，肺结核咯血，尿血。' where id=2064; -- 铁苋菜
update herbs set taste='辛甘，平。', channel='入肝、肾经。', effect='①补肾气，壮阳道，助精神，轻腰脚：菟丝子一斤（淘净，酒煮，捣成饼，焙干），附子（制）四两。共为末，酒糊丸，梧子大，酒下五十丸。（《扁鹊心书》菟丝子丸） ②治腰痛：菟丝子（酒浸）、杜仲（去皮，炒断丝）等分。为细末，以山药糊丸如梧子大。每服五十丸，盐酒或盐汤下。（《百一选方》） ③治丈夫腰膝积冷痛，或顽麻无力：菟丝（洗）一两，牛膝一两。同用酒浸五日，曝干，为末，将原浸酒再入少醇酒作糊，搜和丸，如桶子大。空心酒下二十丸。（《经验后方》） ④治腰膝风冷，益颜色，明目：菟丝子一斗。酒浸良久，沥出曝干，又漫，令酒干为度，捣细罗为末。每服二钱，以温酒调下，日三。服后吃三，五匙水饭压之，至三七日，更加至三钱服之。（《普济方》） ⑤治劳伤肝气，目暗：菟丝子二两。酒浸三日，曝干，捣罗为末，鸡子白和丸梧桐子大。每服空心以温酒下三十丸。（《圣惠方》） ⑥治膏淋：菟丝子（酒浸，蒸，捣，焙）、桑螵蛸（炙）各半两，泽泻一分。上为细末，炼蜜为丸，如梧桐子大。每服二十丸，空心用清米饮送下。（《奇效良方》菟丝丸） ⑦治小便赤浊，心肾不足，精少血燥，口干烦热，头晕怔忡：菟丝子、麦门冬等分。为末，蜜丸梧子大，盐汤每下七十丸。（《纲目》） ⑧治心气不足，思虑太过，肾经虚损，真阳不固，溺有余沥，小便白浊，梦寐频泄：菟丝子五两，白茯苓三两，石莲子（去壳）二两。上为细末，酒煮糊为丸，如梧桐子大。每服三十丸，空心盐汤下。常服镇益心神，补虚养血，清小便。（《局方》茯菟丸） ⑨治小便多或不禁：菟丝子（酒蒸）二两，桑螵蛸（酒炙）半两，牡蛎（煅）一两，肉苁蓉（酒润）二两，附子（炮，去皮、脐）、五味子各一两，鸡膍胵半两（微炙），鹿茸（酒炙）一两。上为末，酒糊丸，如梧子大。每服七十丸，食前盐酒任下。（《世医得效方》菟丝子丸） ⑩治脾元不足，饮食减少，大便不实：菟丝子四两，黄耆、于白术（土拌炒）。人参、木香各一两，补骨脂、小茴香各八钱。饧糖作丸。早晚各服三钱，汤酒使下。（《方脉正宗》） ⑾治消渴：菟丝子不拘多少，拣净，水淘，酒浸三宿，控干，乘润捣罗为散，焙干再为细末，炼蜜和丸，如梧桐子大.食前饮下五十粒，一日二，三服；或作散，饮调下三钱。（《全生指迷方》菟丝子丸） ⑿治阴虚阳盛，四肢发热，逢风如炙如火：菟丝子、五味子各一两，生干地黄三两。上为细末。米饮调下二钱，食前。（《鸡峰普济方》菟丝子煎） ⒀治痔下部痒痛如虫啮：菟丝子熬令黄黑，末，以鸡子黄和涂之。（《肘后方》） ⒁治眉炼癣疮：菟丝子炒，研，油调敷之。（《山居四要》）', tips='①《本草经集注》：得酒良。 ②《本草经疏》：肾家多火，强阳不痿者忌之，大便燥结者亦忌之。 ③《得配本草》：孕妇、血崩、阳强、便结、肾脏有火、阴虚火动，六者禁用。' where id=2065; -- 菟丝子
update herbs set taste='味苦；辛；性温；有毒。', channel='入肺、肝、脾经。', effect='①治卒中昏不知人，口眼歪斜，半身不遂，咽喉作声，痰气上壅，无问外感风寒，内伤喜怒，或六脉沉伏，或指下浮盛，并宜服之。兼治痰厥气逆，及气虚眩晕：南星（生用）一两，木香一分，川乌（生，去皮）、附子（生，去皮）各半两。上细切，每服半两，水二大盏，姜十五片，煎至八分，去滓，温服，不拘时侯。（《局方》三生饮） ⑤治暴中风口眼歪斜：天南星为细末，生姜自然汁调摊纸上贴之，左歪贴右，右歪贴左，才正便洗去。（《杨氏家藏方》天南星膏） ⑥治风痫：天南星（九蒸九晒）为末，姜汁糊丸，梧子大。煎人参、菖蒲汤或麦门冬汤下二十丸。（《中藏经》） ④治破伤风：㈠天南星、防风各-两。上二味，捣罗为末，先用童子小便洗疮口，后以此药末酒调贴之。（《圣济总录》夺命散）㈡白芷、南星、白附子、天麻、羌活、防风各一两。研末调敷伤处。如破伤风初起，角弓反张，牙关紧急，每用三钱，热童便调服。（《医宗金鉴》玉真散） ⑤治小儿惊风，大人诸风：生半夏七两，生天南星三两，生白附子二两，生川乌头半两（去皮及脐）。上捣罗为细末，以生绢袋盛，用井花水摆，未出者，更以手揉令出，如有滓，更研，再入绢袋摆尽为度，放磁盆中，日晒夜露，至晓弃水，别用井花水搅，又晒，至来日早，再换新水搅，如此春五日、夏三日、秋七日、冬十日，去水，晒干后如玉片，研细，以糯米粉煎粥清，丸绿豆大。每服三、五丸，薄荷汤下，大人每服二十丸，生姜汤下，瘫痪风温酒下，并不以时候服。（《阎氏小儿方论》青州白丸子） ⑥治诸风口噤：天南星（炮，锉），大人三钱，小儿三字，生姜五片，苏叶一钱。水煎减半，入雄猪胆汁少许，温服。（《仁斋直指方》） ⑦治风痰头痛不可忍：天南星（大者，去皮）、茴香（炒）。上等分，为细末，入盐少许在面内，用淡醋打糊为丸，如梧桐子大，每服三、五十丸，食后姜汤下。（《魏氏家藏方》上清丹） ⑧治小儿走马疳，蚀透损骨：天南星大者一枚，雄黄皂子大。上二味，先用天南星当心剜作坑子，次安雄黄一块在内，甩大麦面裹合，炭火内烧令烟尽，取出候冷，入麝香一字同研为细末。先以新绵揾血，然后于疮上掺药。一日三次。（《圣济总录》天南星散） ⑨治喉闭：白僵蚕、天南星（并生用）等分。为末，以生姜自然汁调一字许，用笔管灌在喉中，仍咬干姜皂子大，引涎出。（《中藏经》） ⑩治头面及皮肤生窟，大者如拳，小者如栗，或软或硬，不疼不痒，不可辄用钎灸：生天南星一枚（洗，切。如无生者，以干者为末），滴醋研细如膏，将小针制病处，令气透，将膏摊贴纸上如瘤大贴之，觉痒即易，日三、五上。（《圣济总录》天南星膏） ⑾治痰湿臂痛，右边者：天南星、苍术等分。生姜三片，水煎服之。（《摘元方》） ⑿治身面疣子：醋调南星末涂之。（《简易方论》）', tips='阴虚燥咳，热极、血虚动风者禁服，孕妇慎服。生天南星使用不当易致中毒，症状有口腔粘膜糜烂，甚至坏死脱落，唇舌咽喉麻木肿胀，运动失灵，味觉消失，大量流涎；声音嘶哑，言语不清，发热，头昏，心慌，四肢麻木，严重者可出现昏迷，惊厥；窒息，呼吸停止。 恶莽草。 ②《日华子本草》：畏附子、干姜、生姜。 ③《本草备要》：阴虚燥痰禁用。 ④《会约医镜》：孕妇忌之。' where id=2066; -- 天南星
update herbs set effect='①治折伤，接骨：土鳖焙存性，为末，每服10~15克。（《医方摘要》） ②治小儿夜啼如腹痛：蟅虫（熬令烟尽）、芍药（炙）、川芎（熬）各等分。上三味捣末，服如（一）刀圭，日三，以乳服之。（《外台》引《古今录验》） ③治五淋：蟅虫五分（熬，一作虻虫），斑猫二分（去翅、足，熬），地胆二分（去足，熬），猪苓三分。上四味，捣筛为散。每服四分，日进三服，夜二服。但少腹有热者，去猪苓。服药二月后，以器盛小便，当有所下。肉淋者下碎肉；血淋者下如绳，若如肉脓；气淋者如羹上肥；石淋者下石或下砂。剧者十日即愈。禁食羹猪肉、生鱼、葱、盐、醋。以小麦汁服之良。（《外台》引《范汪方》） ④治小儿脐赤肿或脓血清水出者：干蚵蚾火煅为灰，研末，敷之。（《小儿卫生总微论方》） ⑤治瘘疮肿：干地鳖末、麝香各研少许。上二味，研匀。干掺或贴，随干湿治之。（《圣济总录》） ⑥治疯狗咬伤：土鳖虫七个（去足，炒），生大黄15克，桃仁七粒（去皮，尖）。白蜜15克，黄酒一碗，煎至七分服。（《吉林中草药》） ⑦治瘰疬：鲜地鳖虫、陈瓦花（在屋上隔年者佳，瓦上煅存性）。同捣烂。用膏药贴上，未溃即消，已溃即敛。（《中医杂志》） ⑧治五劳虚极羸瘦腹满 不能饮食食伤 忧伤饮伤 房室伤饥伤 劳伤经络荣卫气伤 内有干血肌肤甲错 两目黯黑．缓中补虚：大黄十分（蒸），黄芩100克， 甘草150克，桃仁一升， 杏仁一升，芍药200克， 干地黄500克，干漆50克， 虻虫—升，水蛭百枚， 蛴螬一升，蟅虫半升。上十二味 末之炼蜜和丸 小豆大．酒饮服五丸日三服．（《金匮要略》大黄蟅虫丸） ⑨治产妇腹痛腹中有干血着脐下， 亦主经水不利：大黄150克， 桃仁二十枚， 蟅虫二十枚（熬去足）。上三味 末之炼蜜和为四丸．以酒一升 煎一丸取八合 顿服之新血下如豚肝．（《金匮要略》下瘀血汤） ⑩治血鼓 腹皮上有青筋：桃仁40克 大黄2.5克 蟅虫三个 甘遂2.5克（为末冲服 或八分）．水煎服．与膈下逐瘀汤轮流服之．（《医林改错》古下瘀血汤）' where id=2067; -- 土鳖虫
update herbs set taste='苦甘；平；无毒。', channel='心；肝；大肠；肺；脾经。', effect='①治妇人室女，血闭不通，五心烦热：桃仁（焙）、红花、当归（洗焙）、杜牛膝等分为末。每服三钱，温酒调下，空心食前。（《杨氏家藏方》桃仁散） ②治产后腹痛，干血着脐下，亦主经水不利：大黄三两，桃仁二十枚，蟅虫二十枚（熬，去足）。上三味，末之，炼蜜和为四丸，以酒一升煎一丸，取八合。顿服之，新血下如豚肝。（《金匮要略》下瘀血汤） ③治产后血闭：桃仁二十枚（去皮、尖），藕一块。水煎服之。（《唐瑶经验方》） ④治产后恶露不净，脉弦滞涩者：桃仁三钱，当归三钱，赤芍、桂心各钱半，沙糖三钱（炒炭）。水煎，去渣温服。（《医略六书》桃仁煎） ⑤治血癥，漏下不止：桃仁（去皮、尖，熬）、芍药、桂枝、茯苓、牡丹（去心）各等分。上五味为末，炼蜜和丸如兔屎大。每日食前服一丸，不知，加至三丸。（《金匮要略》桂枝茯苓丸） ⑥治太阳病不解，热结膀胱，其人如狂，少腹急结：桃仁五十个（去皮、尖），大黄四两，桂枝二两（去皮），甘草（炙）二两，芒硝二两。上五味，以水七升，煮取二升半，去滓，内芒硝，更上火微沸，下火。先食温服五合，日三服，当微利。（《伤寒论》桃核承气汤） ⑦治伤寒蓄血，发热如狂，少腹鞕满，小便自利：桃仁二十个（去皮、尖），大黄三两（酒洗），水蛭（熬）、虻虫（去翅、足，熬）各三十个。上四味，以水五升，煮取三升，去滓。温服一升，不下，更服。（《伤寒论》抵当汤） ⑧治热邪干于血分，溺血蓄血者：桃仁三钱（研如泥），丹皮、当归、赤芍各一钱，阿胶二钱，滑石五钱。水煎服。（《瘟疫论》桃仁汤） ⑨治上气咳嗽，胸膈痞满，气喘：桃仁三两，去皮、尖，以水一大升，研汁，和粳米二合，煮粥食。（《食医心镜》） ⑩治老人虚秘：桃仁、柏子仁、火麻仁、松子仁等分。同研，烙白蜡和丸如桐子大，以少黄丹汤下。（《汤液本草》） ⑾治里急后重，大便不快：桃仁（去皮）三两，吴茱萸二两，盐一两。上三味，同炒熟，去盐并茱萸。只以桃仁，空心夜卧不拘时，任意嚼五、七粒至一、二十粒。（《圣济总录》） ⑿治从高坠下，胸腹中有血，不得气息：桃仁十四枚，大黄、消石、甘草各一两，蒲黄一两半，大枣二十枚。上六味，细切，以水三升，煮取一升，绞去滓，适寒温尽服之。当下，下不止，渍麻汁一杯，饮之即止。（《千金方》桃仁汤） ⒀治疟：桃仁一百个，去皮、尖，于乳钵中细研成膏，不得犯生水，候成膏，入黄丹三钱，丸如梧桐子大。每服三丸，当发日用温酒吞下，如不饮酒，井花水亦得。（《证类本草》） ⒁治风劳毒肿挛痛，或牵引小腹及腰痛：桃仁一升，去皮、尖，熬令黑烟出，热研如脂膏。以酒三升，搅和服，暖卧取汗。（《食医心镜》） ⒂治崩中漏下赤白不止，气虚竭：烧桃核为末，酒服方寸匕，日三。（《千金方》） ⒃治小儿烂疮初起，膘浆似火疮：杵桃仁面脂敷上。（《子母秘录》） ⒄治聤耳：桃仁熟捣，以故绯绢裹，纳耳中，日三易，以瘥为度。（《千金方》） ⒅治风虫牙痛：针刺桃仁，灯上烧烟出，吹灭，安痛齿上咬之。（《卫生家宝方》）', tips='孕妇忌服。 ①《医学入门》：血燥虚者慎之。 ③《本草经疏》：凡经闭不通由于血枯，而不由于瘀滞；产后腹痛由于血虚，而不由于留血结块；大便不通由于津液不足，而不由于血燥秘结，法并忌之。' where id=2068; -- 桃仁
update herbs set taste='味甘；淡；性微寒。', channel='入肺、胃经。', effect='①治热气淋涩，小便亦如红花汁者：通草三两，葵子一升，滑石四两（碎），石苇二两。上切，以水六升，煎取二升，去滓，分温三服；如人行八、九里，又进一服。忌食五腥、热面、炙煿等物。（《普济方》通草饮子） ②治一身黄肿透明。亦治肾肿：通草（蜜涂炙干）、木猪苓（去里皮）各等分。上为细末，并入研细去土地龙、麝香少许。每服半钱或一钱，米饮调下。（《小儿卫生总微论方》通草散） ③治伤寒后呕哕：通草三两，生芦根（切）一升，橘皮一两，粳米三合。上四味，以水五升煮，取二升随便稍饮；不差，更作，取差止。（《千金方》） ④治鼻痈，气息不通，不闻香臭，并有息肉：木通、细辛、附子（炮，去皮、脐）各等分。上为末，蜜和。绵裹少许，纳鼻中。（《三因方》通草散） ⑤催乳：通脱木、小人参，炖猪脚食。（《湖南药物志》）' where id=2069; -- 通草
update herbs set taste='酸涩，平，有毒。', channel='入肝、胆经。', effect='①治眼生肤翳垂珠管：铜青一两，细墨半两。上二味含研为末，和醋丸如白豆大，每用一丸，以乳汁、新汲水各少许浸化，以铜箸点之。（《圣济总录》铜青丸） ②治烂弦风眼：铜青。水调涂碗底，以艾熏干刮下，涂烂处。（《卫生易简方》） ③治风眩赤跟：铜青黑豆大一块，防风一寸许，杏仁二粒（去尖，不去皮）。上各细切，于盏中，新汲水浸，汤瓶上顿令极热，洗之。如痛者，加当归数片。（《奇效良方》铜青汤） ④治痈疽肿毒，脓头不出：铜青一钱（为末），沥青一两，麻油二钱。先将油熬滚，入沥青熔化，再入铜青末搅匀，用单油纸摊贴毒上，脓头即出，后换长肉膏贴之。（《窦氏外科方》） ⑤治走马牙疳：铜青、滑石、杏仁等分。为末，擦之。（《秘传经验方》） ⑥治口鼻疳疮：铜青、枯矾等分。研敷之。（《纲目》） ⑦治肾经黑色铁皮疳及牙宣：铜绿五分，腰黄一钱，冰片七厘五毫。如牙龈与口唇内皮烂如云片，或龈中出血，或口碎，吹之。（《囊秘喉书》铜绿散） ⑧治舌上生疮：铜绿、铅白霜。等分，为细末。每用少许，干撒舌上。（《杨氏家藏方》绿云散） ⑨治臁疮顽癣：铜绿七分（研），黄蜡一两。化熬，以厚纸拖过表里，别以纸隔贴之，出水妙。亦治杨梅疮及虫咬。（《卫生杂兴》） ⑩治杨梅毒疮：铜绿醋煮研末，烧酒调搽，极痛出水，次日即干。或加白矾等分，研撒。（《简便单方》） ⑾治百虫入耳：生油调铜绿滴入。（《卫生家宝方》） ⑿治众蛇毒：铜青敷疮上。（《千金方》） ⒀治痰涎壅盛，卒中不语：铜绿二两，净洗，于乳钵内研细，以水化去石，澄清，慢火熬令干，再研匀，入麝香一分，同研，以糯米和丸，如弹子大，阴干。如卒中者，每丸作二服，用薄荷酒研下。瘫缓一切风，用朱砂酒研化下，候吐涎出沫青碧色，泻下恶物。（《经验方》碧琳丹） ⒁治小儿痰涎潮盛：铜绿不计分两，研细如粉，用醋面糊和丸如鸡头大。每有中者，才觉便用薄荷酒磨下一丸，须臾便吐，其涎如胶，令人以手拔之。（《经验方》绿云丹）' where id=2070; -- 铜绿
update herbs set taste='甘；辛；平；无毒。', channel='入肝经。', effect='①治偏正头痛，首风攻注，眼目肿疼昏暗，头目旋运，起坐不能：天麻一两半，附子（炮制，去皮、脐）一两，半夏（汤洗七遍，去滑）一两，荆芥穗半两，木香半两，桂（去粗皮）一分，芎藭半两。上七味，捣罗为末，入乳香匀和，滴水为丸如梧桐子大。每服五丸，渐加至十丸，茶清下，日三。（《圣济总录》天麻丸） ②消风化痰，清利头目，宽胸利膈，治心忪烦闷，头晕欲倒，项急，肩背拘倦，神昏多睡，肢节烦痛，皮肤瘙痒，偏正头痛，鼻齆，面目虚浮：天麻半两，芎藭二两。为末，炼蜜丸如芡子大。每食后嚼一丸，茶酒任下。（《昔济方》天麻丸） ③治中风手足不遂，筋骨疼痛，行步艰难，腰膝沉重：天麻二两，地榆一两，没药三分（研），玄参、乌头（炮制，去皮，脐）各一两，麝香一分（研）。上六味，除麝香、没药细研外，同捣罗为末，与研药拌匀，炼蜜和丸如梧桐子大。每服二十丸，温酒下，空心晚食前服。（《圣济总录》天麻丸） ④妇人风痹，手足不遂：天麻（切）、牛膝、附子、杜仲各二两。上药细锉，以生绢袋盛，用好酒一斗五升，浸经七日，每服温饮下一小盏。（《十便良方》天麻酒） ⑤治风湿脚气，筋骨疼痛，皮肤不仁：天麻（生用）五两，麻黄（去根、节）十两，草乌头（炮，去皮）、藿香叶、半夏（炮黄色）、白面（炒）各五两。上六味，捣罗为细末，滴水丸如鸡头大，丹砂为衣。每服一丸，茶酒嚼下，日三服，不拘时。（《圣济总录》天麻丸） ⑥治小儿风痰搐搦，急慢惊风，风痫：天麻曲两（酒洗，炒），胆星三两，僵蚕二两（俱炒），天竺黄一两，明雄黄五钱。俱研细，总和匀，半夏曲二两，为末，打糊丸如弹子大。用薄荷、生姜泡浓汤，调化一丸，或二、三丸。（《本草汇言》） ⑦治小儿诸惊：天麻半两，全蝎（去毒，炒）一两，天南星（炮，去皮）半两，白僵蚕（炒，去丝）二钱。共为细末，酒煮面糊为丸，如天麻子大。一岁每服十丸至十五丸。荆芥汤下，此药性温，可以常服。（《魏氏家藏方》天麻丸）' where id=2071; -- 天麻
update herbs set taste='苦，温。', channel='肝；脾；肾经。', effect='①治产后腹痛不止及一切血气腹痛：天仙藤五两。炒焦，为细末。每服二钱。腹痛，炒生姜、小便和酒调下；血气，温酒调服。（《普济方》天仙藤散） ②治疝气作痛：天仙藤一两，好酒一碗，煮至半碗服之。（《孙天仁集效方》） ③治癥瘕积聚及奔豚疝气：天仙藤一两（炒），乳香、没药、玄胡索（醋炒）、吴萸、干姜各二钱，小茴香五钱。共为末，每服三钱，好酒调服。（《本草汇言》） ④治妇人有水气而成胎，以致两腿足浮肿：天仙藤（洗，略炒）、香附子（炒），陈皮、甘草、乌药（软白者、辣者，良）各五分。为末，上每服五钱，生姜、木瓜、苏叶各三片，水煎，日三服。（《妇人良方》天仙藤散） ⑤治痰注臂痛：天仙藤、羌活、白术、白芷梢各三钱；片姜黄六钱，半夏（制）半两。上锉，每服三钱，姜五片煎服。间下千金五苓丸。（《仁斋直指方》天仙散） ⑥治乳腺炎：鲜天仙藤适量。揉软外敷，每日换药一次。（《江西草药》） ⑦治毒蛇毒虫咬伤，痔疮肿痛：天仙藤鲜品捣烂敷患处。（《东北常用中草药手册》）' where id=2072; -- 天仙藤
update herbs set taste='甘；微苦；性微寒。', channel='归脾、肺经。', effect='治自汗：太子参三钱，浮小麦五钱，水煎服。（《陕西中草药》）' where id=2073; -- 太子参
update herbs set taste='苦；凉；无毒；平。', effect='①治咳嗽气急：问荆二钱，地骷髅七钱。水煎服。（《中医药实验研究》） ②治急淋：鲜问荆一两，冰糖为引。水煎服。 ③治腰痛：鲜问荆二两，豆腐二块。水煎服。 ④治刀伤：问荆烧灰存性，撒伤口。 ⑤治跌打损伤：骨整复后，鲜问荆一握，加红糖捣烂外敷。（②方以下出江西《草药手册》）', tips='止血；利尿；明目。主吐血；咯血；便血；崩漏；鼻衄；外伤出血；目赤翳膜；淋病。用于小便不利，鼻衄，月经过多。 ①《本草拾遗》：主结气瘤痛，上气气急。 ②《国药的药理学》：利尿。 ③《中药新编》：治鼻衄，月经过多，肠出血，咯血，痔出血等。 ④《四川中药志》：清热止咳。治吐血，衄血及女子倒经。 ⑤《陕西中草药》：清热利尿，止血，消肿。治尿路感染，小便涩痛，骨折，鼻衄，咯血，肠出血，月经过多。' where id=2074; -- 问荆
update herbs set taste='味酸；性平。', channel='入肝、脾、肺、大肠经。', effect='①治久咳不已：乌梅肉（微炒）、罂粟壳（去筋膜，蜜炒）等分，为末。每服二钱，睡时蜜汤调下。（《纲目》） ②治久痢不止，肠垢已出：乌梅肉二十个，水一盏，煎六分，食前，分二服。（《肘后方》） ③治天行下痢不能食者：黄连一升，乌梅二十枚（炙燥）。并得捣末，蜡如棋子大，蜜一升，合于微火上，令可丸，丸如梧子大。一服二丸，日三。（《补缺肘后方》，即《圣惠方》乌梅丸） ④治痢兼渴：麦门冬三两（去心），乌梅二大枚。上二味，以水一大升煮取强半，绞去滓，待冷，细细咽之，即定，仍含之。（孟诜（必效方》） ⑤治便痢脓血：乌梅一两，去核，烧过为末。每服二钱，米饮下。（《圣济总录》） ⑥治大便下血不止：乌梅三两（烧存性），为末，用好醋打米糊丸，如梧桐子大，每服七十丸，空心米饮下。（《济生方》） ⑦治小便尿血：乌梅烧存性，研末，醋糊丸，梧子大。每服四十丸，酒下。（《纲目》） ⑧治妇人血崩：乌梅烧灰，为末，以乌梅汤调下。（《妇人良方》） ⑨治消渴，止烦闷：乌梅肉二两（微炒），为末。每服二钱，水二盏，煎取一盏，去滓，入豉二百粒，煎至半盏，去滓，临卧时服。（《简要济众方》） ⑩治伤寒四、五日，头痛壮热，胸中烦痛：乌梅十四个，辣五合。水一升，煎取一半服，吐之。（《梅师集验方》） ⑾治伤寒蛔厥及久痢：乌梅三百枚，细辛六两，干姜十两，黄连十六两，当归四两，附子六两（炮，去皮），蜀椒四两（出汗），桂枝（去皮）六两，人参六两，黄柏六两。上十味，异捣筛，合治之，以苦酒渍乌梅一宿，去核，蒸之五斗米下，饭熟捣成泥，和药令相得，内臼中，与蜜杵二千下，丸如梧桐子大。先食饮服十丸，日三服，稍加至二十丸。禁生冷滑物臭食等。（《伤寒论》乌梅丸） ⑿治蛔虫上行口鼻：乌梅肉噙之，或煎汤饮自下。（《日用本草》） ⒀治伤寒下部生匿疮：乌梅肉二两，炒令燥，捣细罗为末，炼蜜和丸，如梧桐子大。每服食前，以石榴根皮汤下十丸。（《圣惠方》） ⒁治劳疟劣弱者：乌梅十四枚，豆豉二合，桃、柳枝各一虎口握，甘草三寸长，生姜一块。以童子小便二升，煎七合，温服。（《本草图经》） ⒂治一切疮肉出：乌梅烧为灰，杵末敷上，恶肉立尽。（《刘涓子鬼遗方》） ⒃治咽喉肿痛：乌梅一两，双花二两，雄黄四钱。共为细末，炼蜜为丸，每丸一钱。一次一丸，含化徐徐咽下，日三次。（辽宁《中草药新医疗法资料选编》） ⒄治化脓性指头炎：乌梅肉加适量的食醋研烂，或用乌梅二份，凡士林一份，制成乌梅软膏外敷，每日上药一次。此方对脉管炎所引起的指（趾）头溃疡也有效。（《草医草药简便验方汇编》） ⒅治小儿头疮，积年不差：乌梅肉，烧灰细研，以生油调涂之。（《圣惠方》） ⒆治久咳肺虚证。久咳不已，咳甚则气喘自汗，痰少而粘，脉虚数：人参、款冬花、桑白皮、桔梗、五味子、阿胶、乌梅各10g，贝母、罂粟壳各15g。上为末，每服三钱，白汤点服，咳住止后服。方中乌梅酸涩收敛肺气，加强敛肺止咳之效，为臣药。（《卫生宝鉴》九仙散） ⒇治回厥证，腹痛时作，心烦呕吐，时发时止，手足厥冷。亦治久痢久泻：乌梅30g，细辛3g，干姜9g，黄连6g，当归6g，附子6g，蜀椒6g，桂枝6g，人参6g，黄柏6g。苦酒渍乌梅一宿，、蒸之五斗米下，饭熟，捣成泥，合药，与米杵二千下，丸如梧桐子大，服十丸，日三服。禁食生冷滑物，臭食等。方中乌梅安蛔，使蛔静而痛止，为君药。（《伤寒论》乌梅丸） (21)治虫积腹痛。不思饮食，食则吐蛔，或者烦躁，厥逆，且有面赤，口燥，舌红，脉数身热等症：胡黄连3g，川椒2g，白雷丸9g，乌梅肉5g，生川柏2g，尖槟榔10g.水煎，一剂煎三次，早晨空腹服两次，下午空腹服一次。方中乌梅安蛔。（《通俗伤寒论》连梅安蛔汤）' where id=2075; -- 乌梅
update herbs set taste='性寒，味苦。', effect='①治痢疾：天青地白根五钱。煎水服，一日三、四次，服二、三日。 ②治久痢不止：天青地白、白木槿花各五钱，煎水吃。 ③治赤痢腹痛：天青地白细末五分。开水吞服，饭前服用。 ④治风湿麻木瘫痪，筋骨久痛：天青地白、大风藤、五香血藤、兔耳风各半斤，泡酒连续服用，每日早晚各服一两。 ⑤治风瘫：天青地白（鲜）一斤。泡酒二斤，每次服一、二两。第二次用量同样。另加何首乌一两（痛加指甲花根二两）。 ⑥治疔疮初起：天青地白根一两。煎水服。 ⑦刀伤止血生肌：天青地白叶（干）研末外擞；或鲜根捣烂外敷。 ⑧治癫痫：天青地白根（去心）一两，白矾三钱。加酒浸泡，温热内服，连发连服，服后再服白矾粉一钱。（选方出《贵阳民间药草》）' where id=2076; -- 委陵菜
update herbs set taste='性平，味甘。', channel='肺；胃；大肠经。', effect='①治咽喉刺痛：无花果鲜果晒干，研末，吹喉。（《泉州本草》） ②治肺热声嘶：无花果五钱，水煎调冰糖服。（《福建中草药》） ③治痔疮，脱肛，大便秘结：鲜无花果生吃或干果十个，猪大肠一段，水煎服。（《福建中草药》） ④治久泻不止：无花果五至七枚，水煎服。（《湖南药物志》） ⑤发乳：无花果二两，树地瓜根二两，金针花根四至六两，奶浆藤二两。炖猪前蹄服。（《重庆草药》） ⑥无花果150克，水煎加冰糖适量服，治肺热声嘶，咳嗽咽痛。 ⑦无花果两个生食，或用干果十个与猪大肠一段，共煮熟食，治痔疮、脱肛、大便秘结。 ⑧鲜无花果十个，水煎洗患处，治外痔。 ⑨无花果两个，小茴香10克，水煎服，治疝气。 ⑩无花果枝适量，水煎服，每日两三次，治肠炎。 ⑾无花果捣汁半杯，开水冲服，每日一次，以愈为度，治哮喘。 ⑿无花果叶10克，水煎代茶饮，治黄疸。 ⒀无花果根去粗皮，打碎，开水泡服，治喉痒。 ⒁无花果鲜嫩叶，洗净捣烂绞汁，每次温开水和服半杯，治误食鱼蟹类中毒，腹痛，呕吐。 ⒂无花果猪肉汤：猪瘦肉250克，切小块，无花果100克（干品），同煮汤，用适量食盐调味食用。有理肠健胃，解毒消炎作用，治痔疮，慢性肠炎。', tips='清热生津；健脾开胃；解毒消肿。主咽喉肿痛；燥咳声嘶；乳汁稀少；肠热便秘；食欲不振；消化不良，泄泻痢疾；痈肿；癣疾。用于咳喘，咽喉肿痛，便秘，痔疮。根、叶：肠炎，腹泻；外用治痈肿。 ①《滇南本草》：敷一切无名肿毒，痈疽疥癞癣疮，黄水疮，鱼口便毒，乳结，痘疮破烂；调芝麻油搽之。 ②《便民图纂》：治咽喉疾。 ③汪颖《食物本草》：开胃，止泄痢。 ④《纲目》：治五痔，咽喉痛。 ⑤《生草药性备要》：洗痔疮。子，煲肉食，解百毒。蕊，下乳汁。 ⑥《医林纂要》：益肺，通乳。 ⑦《随息居饮食谱》：清热，润肠。 ⑧《江苏植药志》：鲜果的白色乳汁外涂去疣。 ⑨《云南中草药》：健胃止泻，祛痰理气。治食欲不振，消化不良，肠炎，痢疾，咽喉痛，咳嗽痰多，胸闷。' where id=2077; -- 无花果
update herbs set taste='辛；苦；热；小毒。', channel='入肝、胃经。', effect='①治肾气上哕，肾气自腹中起上筑于咽喉，逆气连属而不能吐，或至数十声，上下不得喘息：吴茱萸（醋炒）、橘皮、附子（去皮）各一两。为末，面糊丸，梧子大。每姜汤下七十丸。（《仁存堂经验方》） ②治醋心，每醋气上攻如酽醋：茱萸一合。水三盏，煎七分，顿服。纵浓，亦须强服。（《兵部手祭方》） ③治食已吞酸，胃气虚冷者：吴茱萸（汤泡七次，焙）、干姜（炮）等分。为末，汤服一钱。（《圣惠方》） ④治肝火：黄连六两，吴茱萸一两或半两。上为末，水丸或蒸饼丸。白汤下五十丸。（《丹溪心法》左金丸，一名回令丸） ⑤治呕而胸满，及干呕吐涎沫，头痛者：吴茱萸一升，人参三两，生姜六两，大枣十二枚。上四味，以水五升，煮取三升，温服七合，日三服。（《金匮要略》吴茱萸汤） ⑥治头风：吴茱萸三升。水五升，煮取三升，以绵拭发。根。（《干金翼方》） ⑦治痰饮头疼背寒，呕吐酸汁，数日伏枕不食，十日一发：吴茱萸（汤泡七次）、茯苓筹分。为末，炼蜜丸悟子大。每热水下五十丸，（《朱氏集验方》） ⑧治多年脾泄，老人多此，谓之水土同化：吴茱萸三钱。泡过，煎汁，入盐少许，通口服，盖茱萸能暖膀胱，水道既清，大肠自固，他药虽热，不能分解清浊也。（《仁存堂经验方》） ⑨治脾受湿气，泄利不止，米谷迟化，脐腹刺痛；小儿有疳气下痢，亦能治之：黄连（去须）、吴茱萸（去梗，炒）、白芍药各五两。上为细末，面糊为丸，如梧桐子大。每服二十丸，浓煎米饮下，空心日三服。（《局方》戊己丸） ⑩治脚气入腹，困闷欲死，腹胀：吴茱萸六升，木瓜两颗（切）。上二味，以水一斗三升，煮取三升，分三服，相去如人行十里久，进一服，或吐、或汗、或利、或大热闷，即瘥。（《千金方》苏长史茱萸汤） ⑾治脚气疼痛，如人感风湿流注，脚足痛不可忍，筋脉浮肿，宜服之：槟榔七枚，陈皮（去白）、木瓜各一两，吴茱萸、紫苏叶各三钱，桔梗（去芦）、生姜（和皮）各半两。上细切，水煎，次日五更，分作三、五服，只是冷服。冬天略温服亦得。（《证治准绳》鸡鸣散） ⑿治远年近日小肠疝气，偏坠搐疼，脐下撮痛，以致闷乱，及外肾肿硬，日渐滋长，阴间湿痒成疮：吴茱萸（去枝梗）一斤（四两用酒浸，四两用醋浸，四两用汤浸，四两用童子小便浸，各浸一宿，同焙干），泽泻（去灰土）二两。上为细末，酒煮面糊丸如梧桐子大。每服五十丸，空心食前盐汤或酒吞下。（《局方》夺命丹） ⒀治小儿肾缩（乃初生受寒所致）：吴茱萸、硫黄各半两。同大蒜研涂其腹，仍以蛇床子烟熏之。（《圣惠方》） ⒁治口疮口疳：茱萸末，醋调涂足心。亦治咽喉作痛。（《濒湖集简方》） ⒂治牙齿疼痛：茱萸煎酒含漱之。（《食疗本草》） ⒃治湿疹：炒吴茱萸一两，乌贼骨七钱，硫黄二钱。共研细末备用。湿疹患处渗出液多者撒干粉；无渗出液者用蓖麻油或猪板油化开调抹，隔日一次，上药后用纱布包扎。（《全展选编·皮肤科》） ⒄治阴下湿痒生疮：吴茱萸一升，水三升，煮三、五沸，去滓，以洗疮。诸疮亦治之。（《古今录验方》）', tips='阴虚火旺者忌服。 恶丹参、消石、白垩，畏紫石英。 ②《本草蒙筌》：肠虚泄者尤忌。 ③《纲目》：走气，动火，昏目，发疮。 ④《本草经疏》：呕吐吞酸属胃火者不宜用；咳逆上气，非风寒外邪及冷痰宿水所致者不宜用；腹痛属血虚有火者不宜用；赤白下痢，因暑邪入于肠胃，而非酒食生冷、停滞积垢者不宜用；小肠疝气，非骤感寒邪及初发一、二次者不宜用；霍乱转筋，由于脾胃虚弱冒暑所致，而非寒湿生冷于犯肠胃者不宜用；一切阴虚之证及五脏六腑有热无寒之人，法所咸忌。' where id=2078; -- 吴茱萸
update herbs set taste='味辛；咸；微苦；性温；小毒。', channel='归膀胱；肝经。', effect='①治手足麻痹，时发疼痛；或打扑伤损，痛不可忍，或瘫痪等症：威灵仙（炒）五两，生川乌头，五灵脂各四两。为末，醋糊丸，梧子大。每服七丸，用盐汤下。忌茶。（《普济方》） ②治中风手足不遂，口眼歪斜，筋骨关节诸风，腰膝疼痛，伤寒头痛，鼻流清涕，皮肤风痒，瘰疬，痔疮，大小肠秘，妇人经闭：威灵仙洗焙为末，以好酒和令微湿，入竹筒内，牢塞口，九蒸九曝，如干，添酒重洒之，以白蜜和为丸，如梧桐子大。每服二十至三十丸，酒汤下。（《海上集验方》） ③治肾脏风壅，腰膝沉重：威灵仙末。蜜丸，梧子大。温酒服八十丸。平明微利恶物如青脓胶，即是风毒积滞，如未利，再服一百丸，取下，后食粥补之一月，仍常服温补药。（孙兆·放杖丸） ④治腰脚疼痛久不瘥：威灵仙五两。捣细罗为散。每于食前以温洒调下一钱，逐日以微利为度。（《圣惠方》威灵仙散）又方：用威灵仙一斤，洗干净，在好酒中泡七天，取出研为末，加面糊成丸子，如梧子大。每服二十丸，用泡药的酒送下。 ⑤治脚气入腹，胀闷喘急：威灵仙末，每服二钱，酒下。痛减一分则药亦减一分。（《简便单方》） ⑥治疟疾：威灵仙，以酒一钟，水一钟，煎至一钟，临发温服。（《本草原始》） ⑦治噎塞膈气：威灵仙一把，醋、蜜各半碗，煎五分服，吐出宿痰。（《唐瑶经验方》） ⑧治停痰宿饮，喘咳呕逆，全不入食：威灵仙（焙）、半夏（姜汁浸焙）。为末，用皂角水熬膏，丸绿豆大。每服七丸至十丸，姜汤下，一日三服，一月为验。忌茶、面。（《纲目》） ⑨治痞积：威灵仙、楮桃儿各一两。上为细末。每服三钱重，用温洒调下。（《普济方》化铁散） ⑩治癖积：威灵仙为末。炼蜜丸，如弹子大，红绢袋盛一丸，同精猪肉四两煮烂。去药吃肉，以知为度。（《幼科指掌》威灵仙丸） ⑾治大肠冷积：威灵仙末。蜜丸，梧子大。一更时，生姜汤下十丸至二十丸。（《经验良方》） ⑿治男妇气痛，不拘久近：威灵仙五两，生韭根二钱半，乌药五分，好酒一盏，鸡子一个。灰火煨一宿，五更视鸡子壳软为度。去渣温服，以干物压之，侧睡，向块边；渣再煎，次日服，觉刺痛，是其验也。（《摘元方》） ⒀治肠风病甚不瘥：咸灵仙（去土）、鸡冠花各二两。上二味，锉劈，以米醋二升煮干，更炒过，捣为末，以生鸡子清和作小饼子，炙干，再为细末。每服二钱匕，空心，陈米饮调下，午复更一服。（《圣济总录》灵仙散） ⒁治痔疮肿痛：威灵仙三两。水一斗，煎汤，先熏后洗，冷再温之。（《外科精义》） ⒂治便毒：威灵仙、贝母、知母各-两。为末。每服三钱，空心酒调下，如不散再服。（《痈疽神秘验方》威灵仙散） ⒃治破伤风病：威灵仙半两，独头蒜一个，香油一钱。同捣烂，热酒冲服，汗出。（《卫生易简方》） ⒄治鸡鹅骨鲠：赤茎威灵仙五钱。井华水煎服。（《圣济总录》） ⒅治渚骨鲠咽。威灵仙一两二钱，砂仁一两，沙糖-盏。水二钟，煎一钟，温服。（《纲目》） ⒆治牙痛：威灵仙、毛茛各等量。制法：鲜药洗净，捣烂取汁，1000毫升药汁加75％酒精10毫升，用以防腐。用法：用棉签沾药水擦痛牙处。注意不可多擦，以免起泡。（《全展选编·五官科》）' where id=2079; -- 威灵仙
update herbs set taste='味辛；性温；有毒。', channel='入肝经。', effect='①治中风抽掣及破伤后受风抽掣者：生箭芪六钱，当归四钱，羌活二钱，独活二钱，全蝎二钱，全蜈蚣大者两条。煎汤服。（《医学衷中参西录》逐风汤） ②治口眼歪斜。口内麻木者：蜈蚣三条（一蜜炙，一酒浸，一纸裹煨，并去失足），天南星一个，切作四片（一蜜炙，一酒浸，一纸裹煨，一生用），半夏、白芷各五钱。通为末，入麝少许。每服一钱，熟（酒）调下，日一服。（《世医通变要法》） ③治中风口眼歪斜：蜈蚣一条。焙干研末，猪胆汁调敷患处（《吉林中草药》） ④治惊痫：蜈蚣、全蝎各等分。研细末，每次三至五分，日服二次。（《吉林中草药》） ⑤治小儿急惊：蜈蚣一条（全者、去足，炙为末），丹砂、轻粉等分。研匀，乳汁和丸，绿豆大，每岁一丸，乳汁下。（《圣惠方》万金散） ⑥治破伤风：蜈蚣头、乌头尖、附子底、蝎梢各等分。为细末。每用一字，或半字，热酒调下。如禁了牙关，用此药，斡开灌之。（《儒门事亲》蜈蚣散） ⑦治破伤风邪在表，寒热拘急，口噤咬牙：蜈蚣二条，江鳔三钱，南星、防风各二钱五分。共研细末，每用二钱，黄酒调服，一日二服。（《医宗金鉴》蜈蚣星风散） ⑧治瘰疬溃疮：茶、蜈蚣。二味炙至香熟，捣筛为末，先以甘草汤洗净，敷之。（《神枕方》） ⑨治丹毒瘤：蜈蚣一条（干者），白矾（皂子大），雷丸一个，百步二钱。秤、同为末。醋调涂之。（《本草衍义》） ⑩治蛇头疔初起，红肿发热，疼痛彻心者：大蜈蚣一条，全蝎七个，雄黄三钱。共为末。用鸡子清调敷患处，外以猪胆皮套上。（《疡医大全》蜈蚣散） ⑾治蛇头疔：蜈蚣一条，雄黄二钱。共研细末，用鸡蛋清调敷。（《吉林中草药》） ⑿治便毒初起：蜈蚣一条。瓦焙存性，为末，酒调服，取汗即散。（《济生秘览》） ⒀治聤耳出脓：娱蚣末吹之。（《鲍氏小儿方》） ⒁治趾疮，甲内恶肉突出不愈：蜈蚣一条。焙研敷之。外以南星末醋和敷四围。（《医方摘要》） ⒂治痔疮疼痛：㈠赤足蜈蚣（焙为末）。入片脑少许，调敷。（《仁斋直指方》）㈡蜈蚣三、四条。香油煮一、二沸，浸之，再入五倍子末二、三钱，瓶收密封，如遇痛不可忍，点上油。（《孙天仁集效方》） ⒃治风癣：大蜈蚣一两，乌梢蛇二两。共焙研细末，体强者每服一钱，弱者每服五分，日二次，开水下。（《江苏中医》（6）：37，1961） ⒄治蛇咬：白芷一两（取白色者），雄黄五钱，蜈蚣三条，樟脑三钱。各为极细末。以香油调搽肿处，随干随扫。（《洞天奥旨》蜈蚣散） ⒅治下肢慢性溃疡：患部用紫金牛煎洗后，撒上蜈蚣末适量，用药膏覆盖，日换一次，十天为一疗程。（江西《草药手册》）' where id=2080; -- 蜈蚣
update herbs set taste='性平，味甘。', channel='①《本草再新》：“入心、脾二经。”', effect='①治饮酒多发积，为酷热蒸熏，五脏津液枯燥，血泣小便并多，肌肉消烁，专嗜冷物寒浆:万寿果二两，麝香一钱。为末，面糊丸，如梧子大。每服三十丸，空心盐汤吞下。（《世医得效方》，枳棋子丸） ②治酒色过度，成劳吐血:拐枣四两，红甘蔗一根。炖猪心肺服。（《重庆草药》） ③治小儿惊风：万寿果实一两。水煎服。《湖南药物志》 ④治手足抽搐：万寿果五钱，四匹瓦五钱，蛇莓五钱。水煎服。《湖南药物志》 ⑤治小儿黄瘦：万寿果实一两。水煎服。《湖南药物志》', usage='', tips='①《得配本草》：“脾胃虚寒者禁用。” ①《得配本草》：“脾胃虚寒者禁用。”' where id=2081; -- 万寿果
update herbs set alias='不留行、王不流行，禁宫花、剪金花，金剪刀草，金盏银台，麦蓝子。', taste='味苦、平。', channel='入肝、胃经。', effect='①治妇人因气，奶汁绝少：瞿麦穗、麦门冬（去心）、王不留行，紧龙骨、穿山甲（炮黄）各等分。上五味为末，每服一钱，热酒调下；后食猪蹄羹少许，投药，用木梳左右乳上梳三十来梳，一日三服，食前服，三次羹汤投，三次梳乳。（《卫生宝鉴》涌泉散） ②治难产逆生，胎死腹中：王不留行、酸浆草（死胎焙用）、茺蔚子、白蒺藜（去刺）、五灵脂（行血俱生用）。各等分为散。每服三钱，取利。山水一盏半。入白花刘寄奴子一撮，同煎温服。（《普济方》胜金散） ③治血淋不止：王不留行一两，当归身、川续断、白芍药、丹参各二钱。分作二剂，水煎服。（《东轩产科方》） ④治诸淋及小便常不利，阴中痛，日数十度起，此皆劳损虚热所致：石韦（去毛）、滑石，瞿麦、王不留行、葵子各二两。捣筛为散。每服方寸匕，日三服之。（《外台》） ⑤治痈肿：王不留行（成末）二升，甘草五两，冶葛二两，桂心四两，当归四两。上五物，治合下筛。以酒服方寸匕，日三夜一。（《医心方》王不留行散） ⑥治乳痈初起：王不留行一两，蒲公英、瓜蒌仁各五钱，当归梢三钱。酒煎服。（《本草汇言》） ⑦治疔肿初起：王不留行子为末，蟾酥丸黍米大。每服一丸，酒下。汗出即愈。（《濒湖集简方》） ⑧治金疮，被刀斧所伤，亡血，寸口脉浮微而涩：王不留行十分，蒴藋细叶十分，桑根白皮十分，甘草十八分，川椒三分（除目及闭口，去汗），黄芩二分，干姜二分，芍药二分，厚朴二分。上九味，桑根皮以上三味烧灰存性，勿令灰过；各别杵筛，合治之为散。服方寸匕，小疮即粉之，大疮但服之，产后亦可服。如风寒，桑根勿取之。前三物皆阴于百日。（《金匮宴略》王不留行散） ⑨治鼻衄不止：剪金花连茎叶，阴干，浓煎汁，温服。（《指南方》） ⑩治粪后下血：王不留行末，水服一钱。（《圣济总录》） ⑾治头风白屑：王不留行、香白芷等分为末。干掺一夜，篦去。（《圣惠方》）' where id=2082; -- 王不留行
update herbs set taste='甘苦，凉，有毒。', effect='①治肝火迫眼，红肿羞明，或视物不明：羊角豆子五钱至一两，冰糖一两，酌冲开水炖服。（《福建民间草药》） ②治疟疾：望江南子炒后研末，每次服二至三钱，日二次。（《福建中草药》） ③治高血压：望江南子炒焦研末，每次一钱，砂糖酌量，冲开水代茶常服。（《福建中草药》）', tips='清肝，健胃，通便，解毒。主目赤肿痛，头晕头胀，消化不良，胃痛，痢疾，便秘，痈肿疔毒。 ①《纲目拾遗》：治疔、痈。 ②李承祜《药用植物学》：健胃，利尿，解热，补血，止痢。 ③《现代实用中药》：健胃整肠。治下痢腹痛，慢性便秘，头胀。 ④《福建民间草药》：益肝，明目。治肝火迫眼，红肿羞明。 ⑤《江西中药》：治胃痛，消化不良。 ⑥《药材学》：治哮喘。种子炒后治疟。 ⑦《广西中药志》：清肝，明目，治头晕。' where id=2083; -- 望江南子
update herbs set taste='苦，寒。', effect='①治肿毒：金豆子叶，晒研，醋和敷，留头即消；或酒下二、三钱。（《纲目拾遗》） ②治蛇头疔：鲜羊角豆叶一握，和白麻子捣烂敷贴患处。（《福建民间草药》） ③治蛇伤：鲜羊角豆叶一握，捣烂绞自然汁服，渣敷患处。（《福建民间草药》） ④治血淋：羊角豆全草一两，水煎服。（《福建民间草药》）', tips='肃肺，清肝，利尿，通便，解毒消肿。主咳嗽气喘，头痛目赤，小便血淋，大便秘结，痈肿疮毒，蛇虫咬伤。消肿解毒。治咳嗽，哮喘，脘腹痞痛，血淋，便秘，头痛，目赤，疔疮肿毒，虫、蛇咬伤。 ①《中国药植志》：治咳嗽，胃病，气块、气胀。 ②《福建民间草药》：杀虫解毒。治毒虫螫伤，蛇头疔，血淋，肚痈。 ③《南宁市药物志》：平肝火，明目。治热性眼痛。 ④《南方主要有毒植物》：治慢性便秘，哮喘。' where id=2084; -- 望江南
update herbs set taste='味甘；性平。', channel='入肝、肾经。', effect='①治虚劳客热，肌肉消瘦，四肢倦怠，五心烦热，咽干颊赤，心怯潮热，盗汗减食，咳嗽脓血：人参、黄芪、柴胡、前胡、黄连、黄柏、当归、白茯苓、熟地黄、生地黄、白芍药、五味子、知母、贝母、川芎、白术各五钱。上为粗末，用雄鸡乌骨者，重二斤以上一只，须新生肥壮者，去毛、血洗净，入前药在肚，以线缝定，用好腊酒入锅中，放鸡在内，酒约过鸡背上一寸为度，肠脏放在鸡外，同煮极烂，拆开，同药晒干，研为细末，用原汁打蒸饼糊为丸，如梧桐子大。每服一百丸，空心，食前，米汤或沸汤送下。（《杏苑生春》乌鸡丸） ②治噤口痢因涩药太过伤胃，闻食口闭，四肢逆冷：乌骨鸡一只，去毛、肠，用茴香、良姜、红豆、陈皮、白姜、花椒、盐，同煮熟烂。以鸡令患者嗅之，使闻香气，如欲食，令饮食汁内，使胃气开。亦可治久痢。（《普济方》乌鸡煎） ③治脾虚滑泄：乌骨母鸡一只，治净。用豆蔻一两，草果2枚，烧存性，掺入鸡腹内，扎定煮熟。空腹食之。（《纲目》） ④治妇人虚劳血气，赤白带下：当归、黄芪各六两，生、熟地黄、香附子各四两，茯苓三两，人参、官桂、地骨皮各二两。上药用（雄）乌骨白鸡一只，笼住，将黄芪末和炒面丸鸡头大喂鸡服，生眵，吊死，肠肚洗净，捋毛椎碎骨，入前药鸡腹内，用酒、醋各一瓶，煮一宿，取骨焙枯，研，共为细末，用汁打糊丸如梧桐子大。每服五十丸，盐汤下。（《袖珍方》乌鸡煎丸） ⑤治亦白带下及遗精白浊，下元虚惫者：白果、莲肉、江米各五钱，胡椒一钱，为末。乌骨鸡一只，如常治净，装入鸡腹煮熟。空心食之。（《纲目》） ⑥治久疽中朽骨：乌骨鸡胫骨，以信砒实之，盐泥固济，火煅通红，地上出火毒，用骨研细，饭丸如粟米大。以纸皮拈送入窍内，外以拔毒膏药封之。（《医学正传》）' where id=2085; -- 乌骨鸡
update herbs set taste='味苦；甘；性温。', channel='入肝、脾经。', effect='①治产后恶露不快，腰痛，少腹如刺，时作寒热，头痛不思饮食；又治久有瘀血，月水不调，黄瘦不食；亦疗心痛：五灵脂水淘净，炒末一两，以好米醋调稀，慢火熬膏，入真蒲黄和丸龙眼大。每服一丸，以水与童子小便各半盏，煎至七分，温服，少顷再服；经闭者，酒磨服下。（《产乳集验方》紫金丸） ②治妇人经血不止：五灵脂末，炒令过熟，出尽烟气。每服大两钱，用当归两片，酒一中盏，与药末同煎至六分，去滓热服，连三、五服。（《经效方》） ③治产后心腹痛欲死：蒲黄（炒香）、五灵脂（酒研，淘去砂土）等分。为末，先用酽醋调二钱，熬成膏，入水一盏，煎七分，食前热服。（《局方》失笑散） ④治丈夫脾积气痛，妇人血崩诸痛：飞过五灵脂（炒烟尽），研末。每服一钱，温酒调下。（《永类钤方》灵脂散） ⑤治卒暴心痛，不可忍者：五灵脂，为细末。每服二钱，热洒下，妇人醋汤下。（《鸡峰昔济方》） ⑥治风冷气血闭，手足身体疼痛，冷麻：五灵脂二两，没药一两，乳香半两，川乌头一两半（炮去皮）。同为末，滴水丸如弹子大。每用一丸，生姜温酒磨服。（《本草衍义》） ⑦治肠风下血：飞过五灵脂，炒烟尽，研末。每服一钱，煎乌梅、柏叶汤下。（《永类钤方》） ⑧治血妄行入胃，吐不止：五灵脂一两，黄耆半两。为末，新汲水服二钱。（《纲目》） ⑨治虫心痛欲绝：五灵脂（末）二钱匕，白矾（火飞）半钱匕。同研，每服一、二钱，水一盏，煎五分，温服，无时。（《阎氏小儿方论》） ⑩治骨折肿痛：五灵脂、白芨各一两，乳香、没药各三钱。为末，热水同香油调涂患处。（《乾坤生意秘韫》） ⑾治损伤，接骨：五灵脂一两，茴香一钱。上二味为细末；另研乳香为细末，于极痛处掺上，用小黄米粥涂了，后用二味药末掺于上，再用帛子裹了，用木片子缠了。（《儒门事亲》接骨丹） ⑿治火风疮癞：油调五灵脂末涂之。（《摘元方》） ⒀治蜈蚣蛇蝎毒虫伤：以五灵脂末涂之。（《金匮钩玄》） ⒁治肺胀：五灵脂（研）二两，柏子仁半两，胡桃八枚（去壳研）。上三味研成膏，滴水为丸，如小豆大，煎木香甘草汤下十五丸。（《圣济总录》皱肺丸） ⒂治目生浮翳：五灵脂、海螺蛸各等分。为细末，熟猪肝日蘸食。（《明目经验方》） ⒃治重舌、喉痹：五灵脂一两，为细末，用米醋一大碗煎，旋噙漱口。（《经验良方》） (24)治积年口疮 五灵脂50克，杏仁四十九枚（汤浸去皮、尖、双仁），黄丹半两（炒令紫色）。上件药，捣细罗为散，用生蜜调令得所，每取少许涂于疮上，有涎即吐之。（《圣惠方》） (25)治恶血牙痛 ①川五灵脂，以米醋煎汁含咽。（《直指方》灵脂醋）②五灵脂50克，川椒25克。共末，擦患处。（《疑难急症简方》）' where id=2086; -- 五灵脂
update herbs set taste='味咸；性寒；小毒。', channel='膀胱；胃；大肠经。', effect='①治小儿胎热撮口：蜗牛子一十枚（去壳细研初泥），莳萝末半分。上药，同研令匀，用奶汁和涂于口畔。（《圣惠方》） ①治消渴引饮不止：㈠蜗牛十四枚，形圆而大者。以水三合，密器浸一宿，取水饮之。（《海上集验方》）㈡蜗牛（焙）半两，蛤粉、龙胆草、桑根白皮（炒）各二钱半。研末，每服一钱，楮叶汤下。（《圣惠方》） ②治小便不通：蜗牛捣贴脐下，以手摩之。加麝香少许更妙。（《简易方论》） ④治小便不通：蜗牛五钱。水煎，日服三次。（《吉林中草药》） ⑤治血热冲肺，鼻衄不止：蜗牛（煿干）一分，乌贼鱼骨半钱。上二味，捣研为散，含水一口，搐一字入鼻内。（《圣济总录》蜗牛散） ⑥治喉痹：㈠蜗牛绵裹，水浸含咽。（《纲目》）㈡蜗牛七枚，白梅三枚（取肉）。同研烂，绵裹如枣核大，含咽。（《圣惠方》） ⑦治无名肿毒：鲜蜗牛一两，马齿苋一两，陈石灰一两。共捣烂，敷患处。（《吉林中草药》） ⑧治疔毒：蜗牛适量，捣碎，敷患处。（《吉林中草药》） ⑨治瘰疬未溃：连壳蜗牛七个，丁香七粒。同烧研，纸花贴之。（《世医得效方》） ⑩治瘰疬，溃与未溃，皆可贴：蜗牛不拘多少，以竹索串，瓦上晒干，烧存性，为末，入轻粉少许，猪骨髓调，用纸花量病大小贴之。（《三因方》蜗牛散） ⑾治发背：蜗牛一百个，活者。以一升净瓶入蜗牛，用新汲水一盏，浸瓶中，封系，自晚至明。取出蜗牛放之，其水如涎。将真蛤粉不以多少，旋调敷，以鸡翎扫之疮上，日可十余度。（《姚僧坦集验方》） ⑿治烂脚：蜗牛一个。放冰片少许于壳内后，用此蜗牛水搽。（江西《草药手册》） ⒀治耳腮痄肿及喉下诸肿：蜗牛同面研敷之。（《纲目》） ⒁治眼热生淫肤赤白翳：生蜗牛二枚。纳少许朱砂末于中，微火上炙令沸，以绵捩取，以敷眦上，数敷。（《圣惠方》） ⒂治痔疮：蜗牛一枚，麝香三分。用小砂合子，盛蜗牛，以麝香糁之，次早取汁，涂痔处。（《济生方》蜗牛膏） ⒃治脱肛：蜗牛一两，诃子五钱。焙干，研细末，用猪油调匀，敷患处。（《吉林中草药》） ⒄治蜈蚣咬：蜗牛挎取汁，滴入咬处。（《圣惠方》） ⒅治耳聋：蜗牛子一分，石胆一分，钟乳一分。同细研，用一瓷瓶盛之，以炭火烧令通亦，候冷取出，研入龙脑少许，每用油引药少许入耳。（《圣惠方》）' where id=2087; -- 蜗牛
update herbs set taste='酸；涩；寒。', channel='入肺、胃、大肠经。', effect='①治泻痢不止：五陪子一两。半生半烧，为末，糊丸梧子大。每服三十丸，红痢烧酒下，白痢水酒下，水泄米汤下。（《纲目》） ②治脱肛不收：五倍子末三钱，入白矾一块，水一碗，煎汤洗之。（《三因力》） ③治产后肠脱：五倍子末掺之；或以五倍子、白矾煎汤薰洗。（《妇人良方》） ④治寐中盗汗：五倍子末、荞麦面等分。水和作阱，煨熟。夜卧待饥时，干吃二、三个，勿饮茶水。（《纲目》） ⑤治自汗盗汗：五倍子研末，津调填脐中，缚定。（《纲目》） ⑥治虚劳遗浊：五倍子一斤，白茯苓四两，龙骨二两。为末，水糊丸，梧子大。每服七十丸，食前用盐汤送下，日三服。（《局方》玉锁丹） ⑦治消渴饮水：五倍子为末，水服方寸匕，日二服。（《世医得效方》） ⑧治粪后下血，不拘大人小儿：五倍子末，艾汤服一钱。（《全幼心鉴》） ⑨治小便尿血：五倍子末，盐梅捣和丸，梧子大，每空心酒服五十丸。（《濒湖集简方》） ⑩治鼻出血：五倍子末吹之，仍以末同鲜绵灰等分，米饮服二钱。（《纲目》） ⑾治牙缝出血不止：五倍子，烧存性，研末敷之。（《卫生易简力》） ⑿治孕妇漏胎：五倍子末，酒服二钱。（《朱氏集验医方》） ⒀治金疮血不止：五倍子，生，为细散，干贴。（《圣济总录》五倍散） ⒁治一切肿毒：五倍子、大黄、黄柏各一两。剉，共捣罗为散，新汲水调如糊，日三、五度，涂敷患处。（《圣济总录》五倍子散） ⒂治软硬疖，诸热毒庖疮：五倍子，炒焦为末，油调，纸花贴。一方水调涂，仍入麻油数点。（《昔济方》独珍膏） ⒃治头疮热疮，风湿诸毒：五倍子、白芷等分。研末掺之，脓水即干。如干者，以清油调涂。（《卫生易简方》） ⒄治咽中悬痈，舌肿塞痛：五倍子末、白僵蚕末、甘草末等分。白梅肉捣和丸，弹子大，噙咽，其痈启破。（《朱氏集验医方》） ⒅治走马牙疳：五倍子、青黛、枯矾、黄檗等分。为末，以盐汤漱净，掺之。（《痘疹便览》） ⒆治聘耳：五倍子，先以绵拈干，置末半字许入耳中。（《苦济方》） ⒇治风毒上攻，眼肿庠涩痛不可忍者，或上下睑眦赤烂，浮肉瘀翳侵睛：五倍子一两，蔓荆子一两半。同杵末，每服二钱，水二盏，铜石器内煎及一盏，澄滓，热淋洗；留滓二服，又依前煎淋洗。（《博济方》神效驱风散） 21.治阴囊湿疮，出水不瘥：五倍子、腊茶各五钱，腻粉少许。研末，先以葱椒汤洗过，香油调搽。（《圣惠方》） 22.治疮口不收：五倍子，焙，研末，以腊醋脚调涂四围。（《纲目》） 23.治手足皲裂：五倍子末，同牛骨髓填纳缝中。（《医方大成论》） 24.防治水田皮炎 五倍子1斤研成细末，放入白醋8斤中溶解，在下水田前，涂抹四肢受水浸泡处，使呈一黑色保护层。如已患水田皮炎，涂抹后半至1天内，患处渗出停止，疼痛减轻。 25.治疗盗汗 五倍子研成细末，每晚睡前取1～3钱用冷开水调成糊状，敷于脐窝，纱布覆盖，胶布固定。重症每晚可敷2次。一般1～3次即可生效。共观察肺结核、矽肺合并肺结核等病的盗汗患者61例，均取得不同程度的疗效。 26.治疗宫颈糜烂 用五倍子、枯矾各等量研细末，加甘油调成糊剂，用带线的小纱布块涂药贴塞于宫颈糜烂处，12小时后取出。每周复查一次。观察18例，4例糜烂处完全光滑，14例好转。 27.治疗枕部疖肿 先剃光枕部头发，清洁消毒后拔除疖子脓栓，用五倍子粉适量与醋调成膏状敷于疖肿上，厚约2毫米。每日更换1～2次，每次换药需清洁创面。共治20例，除2例不断出现新疖外，余18例均经3～9天治愈。 28.治疗睫毛倒卷 用五倍子1两研细末，加入蜂蜜或醋适量调匀，拌成糊状。用时先洗净眼睑皮肤，然后再将适量的糊剂涂于距睑缘2毫米处，每日1次，一般连涂3～10次，可望倒睫矫正。 29.用于拔牙创止血 牙齿拔除后，如继续出血不止，可用五倍子粉末适量撒于创内（避免唾液浸入），3～5分钟内拔牙创表面即为一层黄白色薄膜所覆盖，血块凝固于薄膜之下，无须咬棉纱条压迫。上颁牙拔除，粉末撒入不易，有时须稍加压迫以促进血块凝固。试用此法于拔牙后止血54人（63只牙），止血效果均满意。 30.治倒睫毛（《中草药外治验方选》）：五倍子15克，大白及9克。上2药分别碾成极细末再和匀，用糯米粉或炼蜂蜜少许调成糊状，涂敷于眼皮上，待干。 31.独珍膏（《普济方》）：治软硬疖，诸热毒疱疮。五倍子，炒焦为末，油调，纸花贴。一方水调涂，仍入麻油数点。 32.治手脚皲裂（《福建中医药》）：五倍子10克，紫草5克，共研为细粉，撒于皲裂周围肤上，外用胶布贴住。 33.治消渴饮水（《世臣得效方》）：五倍子为末，水服2～3克，日二服。' where id=2088; -- 五倍子
update herbs set taste='味辛；苦；微甘；性温。', channel='入肝、肾经。', effect='①治男子妇人脚气，骨节皮肤肿湿疼痛，进饮食，行有力，不忘事：五加皮四两（酒浸），远志（去心）四两（酒浸令透，易为剥皮）。上曝干，为末，春秋冬用浸药酒为糊，夏则用酒为糊，丸如梧桐子大。每服四、五十丸，空心温酒送下。（《瑞竹堂经验方》五加皮丸） ②治一切风湿痿痹，壮筋骨，填精髓：五加皮，洗刮去骨，煎汁和曲米酿成饮之；或切碎袋盛，浸酒煮饮，或加当归、牛膝、地榆诸药。（《纲目》五加皮酒） ③治腰痛：五加皮、杜仲（炒）。上等分，为末，酒糊丸，如梧桐子大。每服三十丸，温酒下。（《卫生家宝方》五加皮散） ④治鹤膝风：五加皮八两，当归五两，牛膝四两，无灰酒一斗。煮三炷香，日二服，以醺为度。（《外科大成》五加皮酒） ⑤治四、五岁不能行：真五加皮、川牛膝（酒浸二日）、木瓜（干）各等分。上为末，每服二钱，空心米汤调下，一日二服，服后再用好酒半盏与儿饮之，仍量儿大小。（《保婴撮要》五加皮散） ⑥治虚劳不足：五加皮、枸杞根皮各一斗。上二味细切，以水一石五斗，煮取汁七斗，分取四斗，浸麴一斗，余三斗用拌饭，下米多少，如常酿法，熟压取服之，多少任性。（《千金方》五加酒） ⑦治妇人血风劳，形容憔悴，肢节困倦，喘满虚烦，吸吸少气，发热汗多，口干舌涩，不思饮食：五加皮、牡丹皮、赤芍药、当归（去芦）各一两。上为末，每服一钱，水一盏，将青铜钱一文，蘸油入药，煎七分，温服，日三服。（《局方》油煎散） ⑧治损骨：小鸡一只，约重五、六两（连毛），同五加皮一两，捣为糊，搦在伤处，一炷香时，解下后，用山栀三钱，五加皮四钱，酒一碗，煎成膏贴之，再以大瓦松煎酒服之。（梅氏《验方新编》） (9)五加酒(《备急千金要方》)：用治产后癖瘦。 (10)油煎散(《太平惠民和剂局方》)，治妇人血风劳，形容憔悴，肢体困倦，喘满虚烦，呼吸少气，发热汗多，口干舌涩，不思饮食。 (11)五加皮汤(《三因极一病症方论》)，主治肾劳虚寒，恐虑失志，伤精损髓，嘘吸短气，遗泄白浊，小便赤黄，阴下湿痒，腰脊如折，颜色枯悴。 (12)五皮散(《太平惠民和剂局方》)。 (13)五加皮丸(《瑞竹堂经验方》)，主治男子妇人脚气，骨节皮肤肿湿疼痛。' where id=2089; -- 五加皮
update herbs set effect='治痨伤、风湿：乌骨藤七钱，见血飞：铁筷子、五香血藤各五钱。泡酒一斤，日服三次，每次五钱。', tips='祛风湿；通经活血；止血。主风湿痹痛；月经不调；跌打损伤；骨折；外伤出血 ⑴《贵州民间药物》：“治痨伤，除风湿。” ⑵《全国中草药汇编》：“通经活血，止血。主治风湿骨痛，跌打损伤，月经不调，外用治骨折，外伤出血。”' where id=2090; -- 乌骨藤
update herbs set taste='甘咸，平。', channel='入肝、脾经。', effect='①治胃痛吐酸水，噫气，甚则吐血者： 瓦楞子（醋煅七次）九两，乌贼骨六两，广皮三两（炒）。研极细末，每日三次，每次服二钱，食后开水送下。（《经验方》） ②治一切气血癥瘕，次能消痰：瓦垄子烧，以醋淬三度，埋令坏，醋膏丸。（《万氏家抄方》瓦垄子丸） ③治临经阵痛血不行，按之硬满，属实痛者：瓦垄子（煅红色，醋淬七次）、香附、桃仁、丹皮、川芎、川大黄、当归、红花。酒糊丸。（《女科指掌》瓦楞子丸）' where id=2091; -- 瓦楞子
update herbs set effect='①治急性黄疸型肝炎、较重的慢性肝炎：穿破石二市斤，五指毛桃半市斤，葫芦茶三两，加水浸煮两次，浓缩至1500毫升，加白糖300克，入防腐剂，静置，过滤。较重者每天服90毫升，分二次服；轻者，每天服45毫升，一次服完.以一个月为一疗程，（广州市卫生管理局《新医药通讯》（2）：18～19，1972） ②产后无乳：五指牛奶2两，炖猪脚服。（《广西中草药》） ③白带：五指牛奶1两，一匹绸2两，水煎服。（《广西中草药》）', tips='健肿补肺，行气利湿。治肺痨咳嗽，盗汗，肢倦无力，食少腹胀，水肿，风湿痹痛，肝炎，白带，产后无乳。 ①广州部队《常用中草药手册》：健脾化湿，行气止痛，除痰止咳。治肝硬化腹水，慢性肝炎，肝脾作痛，水肿，风湿性关节炎，劳伤咳嗽。 ②广州空军《常用中草药手册》：益气固表，舒筋活络，行气化湿。治肺结核咳嗽，慢性支气管炎，盗汗，病后体弱，产后无乳，妇女白带，胃痛，胸痛，无名肿毒。' where id=2092; -- 五指毛桃根
update herbs set taste='淡；苦；凉。', effect='治疥疮：蜈蚣草（全草）二两，一扫光四两。大蒜杆（干的）四两。煎水洗，一日三次。并须内服消毒药：白土茯苓、白鲜皮、蒲公英各一两，八爪金龙四钱。煎水服，一日三次。（《贵州民间药物》）', tips='祛风除湿；舒筋活络；解毒杀虫。主风湿筋骨疼痛；腰痛；肢麻屈伸不利；半身不遂；跌打损伤；感冒；痢疾；乳痈；疮毒；疥疮；蛔虫症；蛇早咬伤。 ①《湖南药物志》：辟疫，消肿，退热。治腹痛，痢疾，蜈蚣咬伤，无名肿毒。 ②《贵州民间药物》：治疥疮。' where id=2093; -- 蜈蚣草
update herbs set effect='1、主治白癜风，及身体顽麻。功效：祛风止痒，燥湿消痰，温通血脉。 乌蛇90克（酒浸去皮骨，炙令黄），白僵蚕60克（微炒），肉桂15克，独活60克，天麻60克，川乌15克（炮裂，去皮脐），细辛15克，防风15克（去芦头），胡麻子60克，枳实15克（炒微黄），蝉壳15克，白附子15克（炮裂），天南星0.3克（炮裂）。上药捣细罗为散，每服不计时候，以温酒调下7.6克。（《医方类聚》乌蛇散） 2、主治一切干湿癣。功效：祛风除湿，清热散瘀，理气 通络。 乌蛇（酒浸，去皮骨，炙）30克，干荷叶15克,枳壳（去瓤，麸炒）1克上3味，捣为散。每服7～10克,空心蜜酒调下，日、晚再服。（《圣济总录》三味乌蛇散） 3、治牛皮癣。 乌蛇、白藓皮、丹参、银花、地肤子各30克，荆芥、防风、蝉衣、苦参、赤芍、连翘各20克，浮萍、紫草各15克，甘草10克。共为末，日服2次，每次9克，开水送服。（《浙江中医杂志》1986；（2）乌梢蛇散） 4、治干疥瘙痒久不差。 黄芪60克（锉），乌蛇120克（酒浸、去皮骨、炙令黄），川乌头90克（炮裂去皮脐），附子60克（去苗），上七味，捣罗为末，炼蜜和捣三、二百杵，丸如梧桐子大。每服30克，食后以荆芥汤下，以差为度。（《圣济总录》黄芪丸）', tips='祛风，通络，止痉。用于风湿顽痹，麻木拘挛，中风口眼歪斜，半身不遂，抽搐痉挛，破伤风，麻风疥癣，瘰疬恶疮。' where id=2094; -- 乌梢蛇
update herbs set taste='辛，温。', channel='入脾、肺、肾、膀胱经。', effect='①治风气攻疰四肢，骨节疼痛，遍身顽麻，头目旋晕；瘫痪，语言蹇涩，筋脉拘挛；脚气步履艰难，脚膝软弱；妇人血风，老人冷气，上攻胸臆，两胁刺痛，心腹膨胀，吐泻肠呜：麻黄（去根、节）、陈皮（去瓤）、乌药（去木）各二两，白僵蚕（去丝、嘴，炒）、川芎、枳壳（麸炒）、甘草（炒）、白芷、桔梗各一两，干姜（炮）半两。上为细末，每服三钱，水一盏，姜三片，枣一枚，煎至七分，温服。（《局方》乌药顺气散） ②治冷气、血气、肥气、息贲气、伏梁气、奔豚气，抢心切痛，冷汗，喘息欲绝：天台乌药（小者，酒浸一夜，炒）、茴香（炒）、青橘皮（去白，炒）、良姜（炒）。等分为末，温酒、童便调下。（《卫生家宝方》） ③治心腹气痛：乌药，水磨浓汁一盏，入橘皮一片，苏一叶，煎服。（《濒湖集简方》） ④治胀满痞塞，七情忧思所致：天台乌药、香附、沉香、砂仁、橘红、半夏，为末。每服二钱，灯心汤调。（《亦水玄珠》乌药顺气散） ⑤治浑身胀痛，气血凝滞者：香附（盐、酒、便、醋四分制之）、乌药，共细末，酒下四、五分。（《慎斋遗书》香附散） ⑥治七情伤感，上气喘息，妨闷不食：人参、槟榔、沉香、天台乌药。上药各浓磨水，和作七分盏，煎三、五沸，放温服。（《济生方》四磨汤） ⑦治气厥头痛，妇人气盛头痛及产后头痛：川芎藭、天台乌药等分，为末。每服二钱，葱、茶调下。（《纲目》） ⑧治产后逆气，食滞胀痛：陈皮、藿香、枳壳各钱半，厚朴一钱，泽泻、乌药、香附各二钱，木香七分至一钱，煎服。（《沈氏尊生书》排气饮） ⑨治胎前产后血气不和，腹胀痛：乌药、香附、当归、川芎（俱酒炒）各三钱。水煎服。（《本草切要》） ⑩治产后腹痛：天台乌药、杜当归，为末，豆淋酒调下。（《朱氏集验医方》乌药散） ⑾治小肠疝气乌药一两，升麻八钱。水二钟，煎一钟，露一宿，空心热服。（《孙天仁集效方》） ⑿治干湿脚气乌药一两，莳萝一分（二味炒令黄色）。同为末，温酒下二钱。若是干脚气，用苦楝子一个，柏浆水一升，煎至五合，调下。（《博济方》乌药散） ⒀治脚气掣痛，初发时：土乌药，不犯铁器，布揩去土，瓷瓦刮屑，好酒浸一宿，次早空心温服，溏泄即愈，入麝少许尤佳，痛入腹者，以乌药同鸡子，瓦罐中水煮一日，去鸡子，切片蘸食，以汤送下。（《永类钤力》） ⒁治肾经虚寒，小便滑数及白浊等疾：天台乌药（细锉）、益智子（大者，去皮，炒）。上等分，为末，别用山药炒黄为末，打糊丸，如梧桐子大，曝干。每服五十丸，嚼茴香数十粒，盐汤或盐酒下。（《魏氏家藏方》固真丹，即《妇人良方》缩泉丸） ⒂治小儿慢惊，昏沉或搐：乌药磨水灌之。（《济急仙方》） ⒃治小儿疳积：天台乌药、鸡内金、五谷虫各等分，加入青黛％5（例如台乌药净末用一两，青黛用五分）。共研细末，和匀。每晨空腹用温开水送服一至三钱，连服一月。（《浙江中医杂志》乌金散。12：32（560），1958） ⒄治泻血，血痢：乌药不以多少，炭火烧存性，捣罗为末，陈粟米饭和丸，如梧桐子大。每服三十丸，米饮下。（《圣济总录》乌金丸） ⒅治跌打损伤（背部伤尤宜）：乌药一两，威灵仙五钱。水煎服。（《江西草药》） ⒆风湿麻痹。用乌药一百两、沈香五十两、人参三两、甘草四两，共研为末。每服半钱，空心服，姜盐汤送下。此方名乌沈汤。 ⒇一切气痛。用乌药（酒浸一夜后炒）、茴香（炒）、青桔皮（去白，炒）、良姜（炒），等分为末，以温酒加童便调下。 （21）几种常见病。用香附、乌药，等分为末，每服一至二钱，饮食不进，姜枣汤送下；疟疾，干姜白盐汤送下；腹中有虫，槟榔汤送下；头风虚肿，茶汤送下；妇女冷气，米汤送下；产后血攻心、脾痛。童便送下；妇女血海痛，男子疝痛，茴香汤送下。 （22）小肠疝气。用乌药一两、升麻八钱，加水二碗，煎成一碗，露一宿，煨热，空心服。 （23）脚气扯痛。用乌药刮屑，浸酒中一宿，次早空心温服。溏泄好愈。加麝香少许更好。 （24）血痢。用乌药烧存性，研为末，加陈米饭做成刃丸子，如梧子大。每服三十丸，米汤送下。 （25）咽喉闭痛。用生乌药，加酸醋二碗，煎成一碗，先噙后咽，吐出痰涎好愈。' where id=2095; -- 乌药
update herbs set taste='味酸；性温。', channel='入肺、肾经，', effect='①治肺经感寒，咳嗽不已：白茯苓四两，甘草三两，干姜三两，细辛三两，五味子二两半。上为细末。每服二钱，水一盏，煎至七分，去滓，温服，不以时。（《鸡峰普济方》五味细辛汤） ②治嗽：大罂粟壳（去瓤擘破，用白饧少许入水，将壳浴过令净，炒黄色）四两，五味子（新鲜者，去梗，须北方者为妙）二两。上为细末，白饧为丸，如弹子大。每服一丸，水一盏，捺破，煎六分，澄清，临睡温服，不拘时候。（《卫生家宝方》五味子丸） ③治痰嗽并喘：五味子、白矾等分。为末。每服三钱，以生猪肺炙熟，蘸末细嚼，白汤下。（《普济方》） ④治肺虚寒：五味子，方红熟时，采得，蒸烂、研滤汁，去子，熬成稀膏。量酸甘入蜜，再上火待蜜熟，俟冷，器中贮，作汤，时时服。（《本草衍义》） ⑤治热伤元气，肢体倦怠，气短懒言，口干作渴，汗出不止；或湿热火行，金为火制，绝寒水生化之源，致肢体痿软，脚欹眼黑：人参五钱，五味子、麦门冬各三钱。水煎服。（《千金方》生脉散） ⑥治虚劳羸瘦，短气，夜梦，骨肉烦痛，腰背痰痛，动辄微喘：五味子二两，续断二两，地黄一两，鹿茸一两（切片，酥炙），附子一两（炮，去皮脐）。上为末，酒糊丸，如梧桐子大。每服二十丸，盐汤下。（《卫生家宝方》五味子丸） ⑦治梦遗虚脱：北五味子一斤，洗净，水浸一宿，以手按去核，再用温水将核洗取余味，通用布滤过，置砂锅内，入冬蜜二斤，慢火熬之，除砂锅斤两外，煮至二斤四两成膏为度。待数日后，略去火性，每服一、二匙，空心白滚汤调服。（《医学入门》：五味子膏） ⑧治肾泄：五味子二两（拣），吴茱萸半两（细粒绿色者）。上二味同炒香熟为度，细末。每服二钱，陈米饮下。（《本事方》五味子散） ⑨治白浊及肾虚，两腰及背脊穿痛：五味子一两，炒赤为末，用醋糊为丸，醋汤送下三十丸。泻，用蕲艾汤吞下。（《经验良方》五味子丸） ⑩治烂弦风眼：五味子、蔓荆子，煎汤频洗之。（《谈野翁试验方》） ⑾治疮疡溃烂，皮肉欲脱者：五味于炒焦，研末，敷之，可保全如故。（《本草新编》）', tips='外有表邪，内有实热，或咳嗽初起、痧疹初发者忌服。 恶萎蕤。胜乌头。 ②《本草经疏》：痧疹初发及一叨停饮，肝家有动气，肺家有实热，应用黄芩泻热者，皆禁用。 ③《本草正》：感寒初嗽当忌，恐其敛束不散。肝旺吞酸当忌，恐其助木伤土。' where id=2096; -- 五味子
update herbs set taste='辛苦，微温，有毒。', effect='①治风湿性关节炎，关节拘挛疼痛：北五加皮、穿山龙、白鲜皮各五钱。用白酒泡24小时。每天服10毫升。 ②治筋骨软弱，脚痿行迟：北五加皮、木瓜、牛膝等分为末。每服一钱，每日三次。 ③治水肿，小便不利：北五加皮、陈皮、生姜皮、茯苓皮、大腹皮各三钱，水煎服。（①方以下出《陕甘宁青中草药选》） ④治水肿：香加皮一钱五分至三钱。煎服。（《上海常用中草药》）' where id=2097; -- 香加皮
update herbs set taste='酸咸，寒。', channel='入心、肝经。', effect='①治温热暑疫，痉厥昏狂，谵语发斑，舌色干光，或紫绛，或圆硬，或黑苔；兼治痘瘄毒重，夹带紫斑，暨痘疹后余毒内炽，口糜咽腐，目赤神烦：乌犀角尖（磨汁）、石菖蒲、黄芩各六两，真怀生地（冷水洗净浸透捣绞汁）、银花（鲜者捣汁用尤良）各-斤，粪清、连翘各十两，板蓝根九两，香豉八两，元参七两，花粉、紫草各四两。各生晒研细（忌用火炒），以犀角、地黄汁、粪清和捣为丸（切勿加蜜，如难丸可将香豉煮烂），每重三钱。凉开水化服，日二次。小儿减半。如无粪清，可加人中黄四两研丸。（《温热经纬》神犀丹） ②治太阴温病，神昏谵语者：犀角尖二钱（冲磨），元参心三钱，莲子心五分，竹叶卷心二钱，连乔心二钱，连心麦冬三钱。水煎服。（《温病条辨》清宫汤） ③治伤寒热毒内盛，身发赤斑：犀角（镑）、麻黄（去根节）、石膏各一两，黄连（去须）三分，山栀子仁一两半。上五味，粗捣筛，每服五钱匕，水一盏半，煎至一盏，去滓，温服。（《圣济总录》犀角汤） ④治急黄，心膈烦躁，眼目赤痛：犀角屑一两，茵陈二两，黄芩一两，栀子仁一两，川升麻一两，川芒硝二两。上药，捣筛为散。每服四钱，以水一中盏，又竹叶三七片，煎至六分，去滓，不计时候温服。（《圣惠方》犀角散） ⑤治伤寒及温病，应发汗而不汗之内蓄血者，及鼻衄、吐血不尽，内余瘀血，面黄，大便黑。消瘀血：犀角一两，生地黄八两，芍药三两，牡丹皮二两。上四味，细切，以水九升，煮取三升，分三服。（《千金方》犀角地黄汤） ⑥治吐血似鹅鸭肝，昼夜不止：犀角二两（镑屑生用），桔梗二两（生用）。上二味，捣罗为散。暖酒调下二钱匕。（《圣济总录》生犀散） ⑦治下痢鲜血：犀角（屑）、干地黄、地榆各二两。上三味，捣筛，蜜丸如弹子大。每服一丸，水一升，煎取五合，去滓，温服之。（《古今录验方》） ⑧治小儿疮疹，不恶寒，但烦躁，小便赤涩，多渴，或赤斑点者：犀角（镑）、甘草（炙）各半两，防风二两，黄芩半两。上为粗末。每服抄三钱，水一盏，煎至七分，去渣温服，不拘时候。（《奇效良方》犀角散） ⑨治孩子惊痫不知人，迷闷、嚼舌、仰目者：犀角末半钱匕，水二大合，服之。（《广利方》） ⑩治小儿丹毒，遍身游走，风热烦躁昏愤：牛蒡子（炒）、荆芥、防风、黄芩各一钱，犀角五钱，生甘草五分。水煎服。外用精牛肉切片贴之，干则另换。（《奇方类编》犀角消毒饮） ⑾治热病咽喉赤肿，口内生疮，不能下食：犀角屑一两川升麻一两，川大黄（锉碎，微炒）一两，马牙硝半两，黄柏（锉）半两，黄芩一两。上药捣筛为散，以水四大盏，煎至一大盏，去滓，入蜜三合相和，煎一两沸，放温，徐徐含咽。（《圣惠方》犀角煎） ⑿治亦眼肿痛：犀角末半两，秦艽（去苗、土）二两，黄连（去须）、滑石（碎）、马牙硝各一两，杏仁（汤浸，去皮尖、双仁，出油）半两。上六味，捣研为末，和匀，以沙糖水一处入药熬成膏，每用皂子大，沸汤化洗之。（《圣济总录》犀角膏） ⒀治瘭疽：饮犀角汁。（《千金方》）', tips='恶乌头、乌喙。 ②《雷公炮炙论》：妇人有妊勿服，能消胎气。 恶藋菌、雷丸。 ④《本草经疏》：痘疮气虚无太热者不宜用；伤寒阴证发躁，不宜误用。' where id=2098; -- 犀角
update herbs set taste='味甘；苦；性寒。', channel='归心；肝；肾经。', effect='①治消渴：生地黄三斤（细切），生姜半斤（细切），生麦门冬二斤（去心）。上三味一处于石臼内捣烂，生布绞取自然汁，慢火熬，稀稠得所，以磁盒贮，每服一匙，用温汤化下，不拘时。（《圣济总录》地黄煎） ②补虚除热，去痈疖痔疾：生地黄随多少，三捣三压，取汁令尽，铜器中汤上煮，勿盖，令泄气，得减半，出之，布绞去粗碎结浊滓秽，更煎之令如饧，酒服如弹丸许，日三。（《千金方》地黄煎） ③治劳瘦骨蒸，日晚寒热，咳嗽唾血：生地黄汁二合。煮白粥，临熟入地黄汁搅令匀，空心食之。（《食医心镜》） ④治暑温脉虚夜寐不安，烦渴舌赤，时有讝语，目常开不闭，或喜闭不开：犀角三钱，生地五钱，元参三钱，竹叶心一钱，麦冬三钱，丹参二钱，黄连一钱五分，银花三钱，连翘二钱（连心用）。水八杯，煮取三杯，日三服。舌白滑者，不可与也。（《温病条辨》清营汤） ⑤治伤寒及温病应发汗而不汗之内畜血者，及鼻衄吐血不尽，内余瘀血，面黄，大便黑，消瘀血：犀角一两，生地黄八两，芍药三两，牡丹皮二两。右四味组切，以水九升，煮取三升，分三服。（《千金方》犀角地黄汤） ⑥治阳乘于阴，以致吐血、衄血：生荷叶、生艾叶、生柏叶、生地黄各等分。上研，丸鸡子大。每服一丸，水煎服。（《妇人良方》四生丸） ⑦治吐血经日：生地黄汁一升，川大黄一两（锉碎，微炒末）。上药相和，煎至半升，分为二服，温温食后服。（《圣惠方》） ⑧治肺损吐血不止：生地黄八两（研取汁），鹿角胶一两（炙燥，研为末）。上二味，先以童子小便五合，于铜器中煎，次下地黄汁及胶末，打令匀，煎令熔，十沸后，分作三服。（《圣济总录》地黄饮） ⑨治产后崩中，下血不止，心神烦乱：生地黄汁半小盏，益母草汁半小盏。上药，入酒一小盏相和，煎三、五沸，分为三服，频频服之。（《圣惠方》地黄酒） ⑩治坠马伤折手足，痛甚：生地黄一斤，生姜四两。捣细末，入糟一斤同炒匀，乘热以布裹罨伤处，冷即易之，先能止痛，后整骨。（《夷坚志》）' where id=2099; -- 鲜地黄
update herbs set effect='①治伤寒中脘有痰，令人壮热，项筋紧急，时发寒热，皆类伤风，但不头痛为异：前胡三两，荆芥四两，半夏一两（洗，姜汁浸），赤芍药二两，细辛一两，甘草一两（炙），旋复花三两。上捣罗为未，每服二钱，水。一盏，生姜五片，枣子一枚，同煎至六分，去滓，热服，未知再服，类证活人书》金沸草散） ②治积年上气：旋复花（去梗，焙）一两，皂艾（炙，去皮。子）一两一分，大黄（挫、炒）一两半。上三味，捣罗为末，炼蜜九如梧桐子大。每服十丸至十五九，温汤下，日三服，（《圣济总录》旋复花丸） ③治肝着，亦治妇人半产漏下：旋复花三两，葱十四茎，新绛少许。以水三升，煮取一升，顿服之。（《金匿要略》旋复花汤）④治痰饮在胸膈呕不止，心下痞者：旋复花、半夏、茯苓、青皮。水煎服。（《产科发蒙》旋复半夏汤）⑤治风痰呕逆，饮食不下，头目昏闷：旋复花、枇杷叶、川芎、细辛、各一钱，前胡一钱五分。姜、枣水煎服，（《妇人良方》旋复花汤）⑥治伤寒发汗，若吐若下，解后，心下痞，噫气不除者：旋复花三两，人参二两，生姜五两，代赭石一两，甘草三两（炙），半夏半升（洗），大枣十二枚（擘），上七味，以水一斗，煮取六升，去滓，再煎取三升，温服一升，日三服，（《伤寒论》旋复代赭汤）⑦治风湿痰饮上攻，头目眩胀眵：旋复花、天麻、甘菊花各等分。为末，每晚服二钱，白汤下，（《本草汇言》）⑧治小便不行，因痰饮留闭者：旋复花一握，捣汁，和生由酒服。（《本草汇言》） ⑨治单腹胀：旋复、鲤鱼。将鱼肠去净，药入鱼肚内，煎服。小便利，肿胀即消。 ⑩治风火牙痛：旋复花为末，搽牙根上，良久，去其痰涎，疼止。 11、治乳岩、乳痈：旋复花二钱，蒲公英一钱，甘草节八分，白芷一钱，青皮一钱。水酒为引，水煎服。（⑨方以下出《滇南本草》） 12、治月蚀耳疮：旋复花烧研，羊脂和涂之。（《濒湖集简方》' where id=2100; -- 旋覆花
update herbs set taste='辛，温。', channel='入肺、胃经。', effect='①治鼻内窒塞不通，不得喘息：辛夷、芎藭各-两，细辛（去苗）七钱半，木通半两。上为细末。每用少许，绵裹塞鼻中，湿则易之。五，七日瘥。（《证治准绳》芎藭散） ②治鼻炎、鼻窦炎：㈠辛夷三钱，鸡蛋三个。同煮，吃蛋饮汤。（《单方验方调查资料选编》）㈡辛夷四份，鹅不食草一份。用水浸泡4～8小时后蒸馏，取芳香水，滴鼻。（广东《中草药处方选编》） ③治鼻内作胀或生疮（此系酒毒者多）：辛夷一两，川黄连五钱，连翘二两。俱微炒，研为末。每饭后服三钱，白汤下。（《缪氏方选》） ④治鼻渊：辛夷半两，苍耳子二钱半，香白芷一两，薄荷叶半钱。上并晒干，为细末。每服二钱，用葱、茶清食后调服。（《济生方》苍耳散） ⑤治鼻漏，鼻孔中长出一块：辛夷（去毛）、桑白皮（蜜炙）各四两，栀子一两，枳实、桔梗、白芷各二两。共为细末。每服二钱，淡萝卜汤调服。（《疡医大全》） ⑥治鼻塞不知香味：皂角、辛夷、石菖蒲等分。为末。绵裹塞鼻中。（《梅氏验方新编》） ⑦治齿牙作痛，或肿或牙龈浮烂：辛夷一两，蛇床子二两，青盐五钱。共为末掺之。（《本草汇言》） ⑧治头眩昏冒欲呕（此属寒痰）：辛夷一两，制半夏、胆星、天麻、干姜、川芎各八钱。为末，水泛为丸。每晚服三钱，白汤下。（《本草汇言》） ⑨治头面肿痒如虫行（此属风痰）：辛夷一两，白附子、半夏、天花粉、白芷、僵蚕、玄参、赤芍各五钱，薄荷八钱。分作十剂服。（《古今医准》）', tips='阴虚火旺者忌服。 恶五石脂。畏菖蒲、蒲黄、黄连、石膏、黄环。 ②《本草汇言》：气虚之人，虽偶感风寒，致诸窍不通者，不宜用。 ③《本草经巯》：凡气虚人忌，头脑痛属血虚火炽者忌，齿痛属胃火者忌。' where id=2101; -- 辛夷
update herbs set taste='味苦；性寒。', channel='入肝、胆、睥、胃经。', effect='①治小儿惊痫瘈疭：熊胆二大豆许，和乳汁及竹沥服。并得去心中诞。（《食疗本草》） ②治小儿一切疳疾，心腹虚胀，爱食泥土，四肢壮热：熊胆一钱（研），麝香半钱（研），壁宫一枚（去头、足、尾，面裹煨熟，研），黄连（去须，取末）一钱。上同研极细，以蟾酥和丸，黍米大。每服五丸，米汤送下。量大小加减，无时。（《小儿卫生总微论方》熊胆麝香丸） ③治疳羸瘦：熊胆、使君子仁各等分。研细，放入瓷器中，蒸熔，宿蒸饼，就丸麻子大。米饮送下二十丸，无时。（《小儿卫生总微论方》熊胆丸） ④治小儿奶疳黄瘦，体热心烦：熊胆一分，青黛半两，蟾酥半两，黄连末半两，牛黄一分。上药，都研如粉，以猪胆汁和丸，如绿豆大。每服以粥饮下五丸，日三服，量儿大小，加减服之。（《圣惠方》） ⑤治蛔心痛：熊胆如大豆，和水服。（《外台》） ⑥治目赤障翳：熊胆少许。化开，入冰片一、二片，铜器点之。或泪痒，加生姜粉些须。（《齐东野语》熊胆丸） ⑦治五痔十年不瘥：涂熊胆，取瘥止。（《千金方》） ⑧治风虫牙痛：熊胆三钱，片脑四分。上为末，用猪胆汁调搽患处。（《摄生众妙方》） ⑨治小儿疳疮蚀鼻：熊胆半分。以汤化，调涂于鼻中。（《圣惠方》）' where id=2102; -- 熊胆
update herbs set taste='味苦；辛；咸；微温。', channel='归肺、脾、胃、大肠经。', effect='①治伤寒中脘有痰，令人壮热，项筋紧急，时发寒热，皆类伤风，但不头痛为异：前胡三两，荆芥四两，半夏一两（洗，姜汁浸），赤芍药二两，细辛一两，甘草一两（炙），旋复花三两。上捣罗为末，每服二钱，水一盏，生姜五片，枣子一枚，同煎至六分，去滓，热服，未知再服。（《类证活人书》金沸草散） ②治伤寒发汗，若吐若下，解后，心下痞鞕，噫气不除者：旋复花三两，人参二两，生姜五两，代赭石一两，甘草三两（炙），半夏半升（洗），大枣十二枚（擘），上七味，以水-斗，煮取六升，去滓，再煎取三升，温服一升，日三服。（《伤寒论》旋复代赭汤） ③治风湿痰饮上攻，头目眩胀眵蔑：旋复花、天麻、甘菊花各等分。为末，每晚服二钱，白汤下。（《本草汇言》） ④治风痰呕逆，饮食不下，头目昏闷：旋复花、枇杷叶、川芎、细辛、赤茯苓各一钱，前胡一钱五分。姜、枣水煎服。（《妇人良方》旋复花汤） ⑤治积年上气：旋复花（去梗，焙）一两，皂荚（炙，去皮、子）一两一分，大黄（锉、炒）一两半。上三味，捣罗为末，炼蜜丸如梧桐子大。每服十丸至十五丸，温汤下，日三服。（《圣济总录》旋复花丸） ⑥治风火牙痛：旋复花为末，搽牙根上，良久，去其痰涎，疼止。 ⑦治肝着，亦治妇人半产漏下：旋复花三两，葱十四茎。新绛少许。以水三升，煮取一升，顿服之。（《金匮要略》旋复花汤） ⑧治痰饮在胸膈呕不止，心下痞粳者：旋复花、半夏、茯苓、青皮。水煎服。（《产科发蒙》旋复半夏汤） ⑨治小便不行，因痰饮留闭者：旋复花一握，捣汁，和生白酒服。（《本草汇言》） ⑩治单腹胀：旋复、鲤鱼。将鱼肠去净，药入鱼肚内，煎服。小便利，肿胀即消。 ⑾治乳岩、乳痈：旋复花二钱，蒲公英一钱，甘草节八分，白芷一钱，青皮一钱。水酒为引，水煎服。（⑨方以下出《滇南本草》） ⑿治月蚀耳疮：旋复花烧研。羊脂和涂之。（《濒湖集简方》）' where id=2103; -- 旋复花
update herbs set taste='味辛、微苦、酸、温。', channel='入肝、肺、脾经。', effect='①治鼓胀：陈香橼一枚（连瓤），大核桃肉二枚（连皮），缩砂仁二钱（去膜）。各煅存性为散，砂糖拌调。空心顿服。（《本经逢原》） ②治嗽：香橼（去核）薄切作细片，以时酒同入砂瓶内，煮令熟烂，自昏至五更为度，用蜜拌匀。当睡中唤起，用匙挑服。（《养疴漫笔》） ③治气逆不进饮食或呕哕：陈极香橼二个，真川贝三两（去心），当归一两五钱（炒黑），白通草（烘燥）一两，陈西瓜皮一两，甜桔梗三钱。共研细末，用白檀香劈碎煎浓汁泛为丸，如桐子大，每服三钱，开水送下。大虚者酌用。（《梅氏验方新编》香橼丸） ④治气逆呕吐，饮食不佳，腹胀嗳气：陈香橼50g，川贝母50g，炒当归30g，通草20g，陈西瓜皮15g，共为细末，白檀香劈碎水煎泛丸，每服10g，日服2次。方中香橼舒肝理气，宽中，化痰，为君药。（《医宗金鉴》香橼丸） ⑤验方：治咳嗽：香橼适量，制为粗粉，水煮烂熟，以炼蜜拌匀成膏。睡中嗽起，每服二匙。方中香橼舒肝理气，宽中，化痰，为君药。 ⑥本品能促进胃肠蠕动，有祛痰、抑制血栓形成作用。 ⑦鲜香橼一两个，切碎放在有盖的碗中，加入等量的麦芽糖，隔水蒸数小时，以香橼稀烂为度，每服一匙，早晚各一次，有化痰、行气、止咳、平喘之效。 ⑧盐渍香橼：香缘切片，于通风处晾干，用适量食盐腌渍放入玻璃瓶或瓷罐中备用。每用10～20克，用开水冲至咸淡适宜为度时服用。有行气，止痛，健胃，化食作用。适用于胃痛，腹痛，气痛，食滞胃胀痛等症。 ⑨鲜香缘12～15克（干品6克），开水冲泡代茶饮，可治肝痛，胃气痛。 ⑩陈香缘30克（焙干），花椒、小茴香各12克，共研细末，每次服3克，每日两次，温开水送服，治胃痛胸闷，消化不良。' where id=2104; -- 香橼
update herbs set taste='苦；甘；微寒。', effect='①治肾炎：菥蓂鲜全草一至二两。水煎服。（《福建中草药》） ②治产后子宫内膜炎：菥蓂干全草五钱。水煎，调红糖服。（《福建中草药》）', tips='清热解毒，利水消肿。主目赤肿痛；肺痈；肠痈；泄泻；痢疾；白带；产后瘀血腹痛；消化不良；肾炎水肿；肝硬化腹水；痈疮肿毒。用于阑尾炎，肺脓疡，痈疖肿毒，丹毒，子宫内膜炎，白带，肾炎，肝硬化腹水，小儿消化不良。' where id=2105; -- 菥蓂
update herbs set taste='辛；苦；温。', channel='肝；肺经。', effect='①治风寒外感：香椿子、鹿衔草。煎水服。（《四川中药志》） ②治胸痛：香椿子、龙骨。研末冲开水服。（《湖南药物志》） ③治风湿关节痛：香椿子炖猪肉或羊肉服。（《四川中药志》） ④治疝气痛：香椿子五钱。水煎服。（《湖南药物志》） ⑤治痔漏：香椿子、饴糖。蒸服。（《贵州中医验方》）', tips='祛风；散寒；止痛。主外感风寒；风湿痹痛；胃痛；疝气痛；痢疾。治风寒外感，心胃气痛，风湿关节疼痛，疝气。 ①《民间常用草药汇编》：发汗，治心胃气痛。 ②《四川中药志》：除风寒，治冷骨风及风湿关节痛。' where id=2106; -- 香椿子
update herbs set taste='味辛；性微温。', channel='入肺、胃经。', effect='①治脾胃不和，胸膈痞滞，内感风冷，外受寒邪，憎寒壮热，身体疼痛，肢节倦怠，霍乱呕吐，脾疼翻胃，中酒不醒，四时伤寒头痛：香薷（去土）二两，甘草（炙）半两，白扁豆（炒）、厚朴（去皮，姜汁炒）、茯神各一两。上为细末。每服二钱，沸汤入盐点服。（《局方》香薷汤） ②治霍乱吐利，四肢烦疼，冷汗出，多渴：香薷二两，蓼子一两。上二味粗捣筛。每服二钱匕，水一盏，煎七分，去渣温服，日三。（《圣济总录》香薷汤） ③治霍乱腹痛吐痢：生香薷（切）一升，小蒜一升（碎），厚朴六两（炙），生姜十两。上四味切，以水一斗，煮取三升，分三服，得吐痢止，每服皆须温。（《救急方》香薷汤） ④治暴水风水气，水肿，或疮中水，通身皆肿：干香薷一斤，白术七两。上二味捣术下筛；浓煮香薷取汁，和术为丸，如梧子大。每服十丸，日夜四、五服，利小便极良。夏取花、叶合用亦佳。忌青鱼、海藻、菘菜、桃、李、雀肉。（《僧深集方》香薷术丸） ⑤治舌上忽出血如钻孔者：香薷汁服一升，日三。（《肘后方》） ⑥伤暑（暑天卧湿当风，或生冷不节，头痛发热，转筋，干呕，四肢发冷等）。用香薷一斤、厚朴（姜汁炙过）、白扁豆（微炒）各半斤，锉散。每服五钱，加水二碗，酒半碗，煎成一碗，放水中等冷定后服下。连进二服，很有效。此方名香薷饮。方中的扁豆，可用黄连（姜汁炒）代替。 ⑦水肿：香薷五十斤，锉入锅中，加水久煮，去渣再浓煎，浓到可以捏丸时，即做成丸子，如梧子大。每服五丸，一天服三次，药量可以逐日加一点以小便能畅为愈。此方名香薷煎。又方：香薷叶一斤，水一斗，熬烂，去渣，再熬成膏，加白术末七两作成丸子，如梧子大。每服十丸，米汤送下。此方名深师薷术丸。 ⑧心烦胁痛。用香薷捣捣汁一、二升服。 ⑨鼻血不止。用香薷研累，水冲服一钱。' where id=2107; -- 香薷
update herbs set taste='味辛；性温。', effect='①治恶庄心痛，闷绝欲死：鬼督邮一两（末），安息香一两（酒浸，细研，去滓，慢火煎成膏）。上药，以安息香煎和丸如梧桐子大。不计时候，以醋汤下十丸。（《圣惠方》） ②治腰痛，胃寒气痛，肝硬化腹水：徐长卿二至四钱。水煎服。（《中草药土方土法战备专辑》） ③治腹胀：徐长卿三钱。酌加水煎成半碗，温服。（《吉林中草药》） ④治牙痛：徐长卿根（干）五钱。洗净，加水1500毫升，煎至500毫升；也可将其根制成粉剂。痛时服水剂90毫升，服时先用药液漱口1～2分钟再咽下；如服粉剂，每次五分至一钱，均每天二次。（《全晨选编·口腔疾病》） ⑤治风湿痛：徐长卿根八钱至一两，猪精肉四两，老酒二两。酌加水煎成半碗，饭前服，日二次。（《福建民间草药》） ⑥治经期腹痛：对叶莲根三钱，月月红二钱，川芎一钱。切细，泡酒四两，内服。（《贵阳民间药草》） ⑦治痢疾，肠炎：痢止草一至二钱。水煎服，每天一剂。（《全展选编·传染病》） ⑧治精神分裂症（啼哭、悲伤、恍惚）：徐长卿五钱。泡水当茶饮。（《吉林中草药》） ⑨治皮肤瘙痒：徐长卿适量。煎水洗。（《吉林中草药》） ⑩治带状疱疹，接触性皮炎，顽固性荨麻疹，牛皮癣：徐长卿二至四钱。水煎内服，并外洗患处。（《中草药土方土法战备专楫》） ⑾治跌打肿痛，接骨：鲜徐长卿适量，捣烂敷患处。（《中草药土方土法战备专楫》）' where id=2108; -- 徐长卿
update herbs set alias='薤根，藠头，大头菜子，野蒜、小独蒜，小蒜、宅蒜，薤白头。', taste='味辛；苦；性温。', channel='归肺、胃、大肠经。', effect='①治胸痹之病，喘息咳唾，胸背痛，短气，寸口脉沉而迟，关上小紧数：栝楼实一枚（捣），薤白半斤，白酒七升。上三味，同煮，取二升。分温再服。（栝楼薤白白酒汤） ②治胸痹，不得卧，心痛彻背者：栝楼实，一枚（捣），薤白三两，半夏半升，白酒一斗。上四味，同煮，取四升。温服一升，日三服。（栝楼薤白半夏汤） ③治胸痹，心中痞气，气结在胸，胸满，胁下逆抢心：枳实四枚，厚朴四两，薤白半斤，桂枝一两，栝楼实一枚（捣）。上五味，以水五升，先煮枳实、厚朴取二升，去滓，纳诸药，煮数沸，分温三服。（枳实薤白桂枝汤。①方以下出《金匮要略》） ④治赤痢：薤、黄柏。煮服之。（《本草拾遗》） ⑤治赤白痢下：薤白一握。切，煮作粥食之。（《食医心镜》） ⑥治奔豚气痛：薤白捣汁饮之。（《肘后方》） ⑦治霍乱干呕不息：薤一虎口。以水三升煮，取半，顿服，不过三作。（《独行方》） ⑧治灸疮肿痛：薤白（切）一升，猪脂一升（细切）。以苦酒浸经宿，微火煎三上三下，去滓，敷上。（《梅师集验方》） ⑨治手足瘑疮：生薤一把。以热醋投入，封疮上。（《千金方》） ⑩治咽喉肿痛：薤根，醋捣，敷肿处，冷即易之。（《圣惠方》） ⑾治鼻渊：薤白三钱，木瓜花三饯，猪鼻管四两。水煎服。（《陆川本草》） ⑿治食诸鱼骨鲠：小嚼薤白令柔，以绳系中，持绳端，吞薤到鲠处，引之。（《补缺肘后方》） ⒀治妊娠胎动，腹内冷痛；薤白一升，当归四两。水五升，煮二升，分二服。（《古今录验方》） ⒁治赤白痢疾：薤头60克，糯米60克，煮稀饭食。 ⒂治小儿疳痢（包括慢性肠炎）：鲜薤头洗净，捣烂如泥，用米粉和蜜糖适量拌和做饼，烤熟食之。 ⒃治胸痹心痛：薤白10克，瓜蒌仁10克，半夏5克，水煎去渣，黄酒冲服，一日两次。 ⒄薤白粥，薤白10-15克（鲜者30-45克），与粳米100克共煮粥。煮熟后油盐调味食用。有宽胸行气止痛作用，适用于冠心病之胸闷不舒或心绞痛，老年人慢性肠炎、菌痢。 ⒅薤白汤（《奇效良方》）治霍乱，干呕不止：薤白（切细）1握，生姜（切细）15g，陈皮（去白）9g。上用水2大盏，煎至七分，去渣，分2次温服。方中薤白温中通阳，下气散结，为君药。 ⒆薤白粥（《奇效良方》）治反胃，无问久新冷热皆治：薤白2茎，鸡子（去黄）3个，人参（切细，以水1大升，煎取3合）,白粟米10g。上3味（薤白，鸡子黄，白粟米）同煮煎，搅匀，与温热人参汤相和调，不拘早晚，顿服，如思食，即与粟米粥饮，渐渐加粳米和之。方中薤白温中通阳，下气散结，为君药。' where id=2109; -- 薤白
update herbs set effect='1．治小便黄赤：小通草6g，木通4.5g，车前子9g（布包）。煎服。（《安徽中药志》） 2．治热病烦躁，小便不利：小通草6g，栀子、生地、淡竹叶、知母、黄芩各9g。煎服。（《安徽中药志》） 3、治急性尿道炎：小通草6g，地肤子、车前子（布包）各15g。煎服，（《安徽中药志》） 4．治小便不利：小通草15g。车前仁15g，水菖蒲15g，火洒草3g，生石膏3g煎服。（《湖南药物志》） 5．治淋病，小便不利：滑石30g，甘草6g，小通草9g。小煎服。（《甘肃中草药手册》） 6．治产后乳汁不通：小通草6g，王不留行9g，黄蜀葵根12g。煎水当茶饮。如因血虚乳汁多，加猪蹄1对，炖烂去药渣，吃肉喝汤，（《安徽中草药》） 7．治乳少：黄芪30g，当归15g小通草9g。水煎。（《甘肃中草药手册》） 8．治闭经：小通花、川牛膝各9-15g，水煎服。（《浙江药用植物志》） 9．治心烦失眠：（通条树）髓3-4.5g拌朱砂。水煎服。（《广西本草选编》）' where id=2110; -- 小通草
update herbs set effect='①治崩漏：蝎子七、鹿衔草各三钱，金丝带、太羌活、狮子七各二钱。水煎服。（《陕西中草药》） ②治痢疾：蝎子七二至四钱。开水煎服，加红、白糖适量。（《陕西中草药》）', tips='清热解毒；止血；活血。主咽喉肿痛；乳蛾；痛疮肿毒；湿热泄泻；痢疾；赤白带下；吐血；衄血；崩漏；肠风下血；外伤出血；跌打损伤；腰痛；关节疼痛。治吐血，衄血，血崩，白带，痢疾，跌打损伤。 ①《陕西中草药》：收敛，止血，止带。治痢疾，腹泻，肠风下血，崩漏，白带，吐血，外伤出血。 ②《高原中草药治疗手册》：治跌损红肿，血瘀疼痛，捣烂敷患部。' where id=2111; -- 蝎子七
update herbs set taste='味辛；咸；性温；小毒。', effect='①治小水不道，痛胀不止：蟋婶一个。阴阳瓦焙干，为末。白滚汤下，小儿减半。（《医方集听》） ②治跌扑伤小肚，尿闭不出：蟋蟀一枚。煎服。（《养素园传信方》） ③治老人尿闭：蟋蟀四只，蝼蛄四只，生甘草一钱。煎汤，分三次温服。（《现代实用中药》） ④治小儿遗尿：蟋蟀一个。焙，末，滚水下，照岁（数）服，如儿十一岁者，每次服一个，服至十一个为止。（《慈航活人书》） ⑤治肾虚阳痿：蟋蟀、蜻蜒，狗肾。共为末，兑酒服。（《四川中药志》）' where id=2112; -- 蟋蟀
update herbs set effect='①治一切喉证，肿痛白腐，退炎消肿：西瓜霜五钱，西月石五钱，飞朱砂六分，僵蚕五分，冰片五分。研极细末，吹患处。阴虚白喉忌用。（《喉痧症治概要》玉钥匙） ②治白喉：西瓜霜二两，人中白一钱（煅），辰砂二钱，雄精二分，冰片一钱。共研细末，再乳无声，如非白喉，减去雄精。（《治喉捷要》瓜霜散）' where id=2113; -- 西瓜霜
update herbs set alias='麒麟竭，海蜡（侯宁极《药谱》），麒麟血，木血竭。', taste='味甘；咸；性平；小毒', channel='入心、肝经。', effect='①治伤损筋骨，疼痛不可忍：麒麟血一两，没药一两，当归一两（锉，微炒），白芷二两，赤芍药一两，桂心一两。捣细罗为散，每服，以温酒调下二钱，日三、四服。（《圣惠方》麒麟血散） ②治腹中血块：血竭、没药、滑石、牡丹皮（同煮过）各一两。为末，醋糊丸，梧桐子大，服之。（《摘元方》） ③治产后败血冲心，胸满气喘：真血竭，研为细末，温酒调服。（《朱氏集验医方》血竭散） ④治鼻衄：血竭、蒲黄等分。为末，吹之。（《医林集要》） ⑤治瘰疬已破，脓水不止者：血竭（炒）二钱半，大枣二十个（烧为灰），干地黄半两（别为末）。上三味，都细研如粉，以津唾调贴疮上。（《博济方》血竭散） ⑥治一切不测恶疮，年深不愈：血竭一两，铅丹半两（炒紫色）。上二味，捣研为散，先用盐畅洗疮后贴之。（《圣济总录》血竭散） ⑦治臁疮不合：血竭末敷之，以干为度。（《济急仙方》） ⑧治痔漏疼痛不可忍：血竭，为细末，用自津唾调涂，频为妙。（《杨氏家藏方》血竭散） ⑨治嵌甲疼痛：血竭末调敷之。（《医林集要》） ⑩治白虎风，走转疼痛，两膝热肿：麒麟竭一两，硫黄一两（细研）。捣罗为散，研令匀，以温酒调下一钱。（《圣惠方》）' where id=2114; -- 血竭
update herbs set taste='味苦；性寒。', effect='①治急性黄疸型肝炎：溪黄草配酢浆草、铁线草，水煎服。 ②治急性胆囊炎而有黄疸者：溪黄草配田基黄、茵陈蒿、鸡骨草、车前草，水煎服。 ③治湿热下痢：㈠溪黄草鲜叶，捣汁冲服：㈡溪黄草配天香炉、野牡丹，水煎服。（①方以下出《中医方药学》） ④治痢疾，肠炎：鲜四方蒿叶。洗净，捣汁内服。每天一次，每次五毫升，儿童二至三毫升。（《全展选编·传染病》） ⑤治瘙闭：鲜香茶菜二两，鲜石韦、鲜车前草各一两。水煎服。（江西《草药手册》）' where id=2115; -- 溪黄草
update herbs set taste='甘苦，温（大苞雪莲花有毒）。', effect='①治阳痿：雪莲花、冬虫夏草，泡酒饮。（《高原中草药治疗手册》） ②治妇女崩带：雪莲花、蛾参，党参，炖鸡吃。（《高原中草药治疗手册》） ③治风湿性关节炎，妇女小腹冷痛，闭经，胎衣不下：雪莲五钱，加白酒或黄酒100毫升，泡七天。每服10毫升，一日二次。（《新疆中草药手册》） ④治雪盲，牙痛：雪莲花二至四钱。生吃或水煎服。（《云南中草药》） ⑤治外伤出血：雪莲花适量，敷患处。（《云南中草药》）' where id=2116; -- 雪莲花
update herbs set alias='龙豆，属折，接骨、南草，接骨草，川断。', taste='味苦；辛；性微温。', channel='入肝、肾经。', effect='①治腰痛并脚酸腿软：续断二两，破故纸、牛膝、木瓜、萆薢；杜仲各一两。上为细末，炼蜜为丸桐子大。空心无灰酒下五、六十丸。（《扶寿精方》续断丸） ②治老人风冷，转筋骨痛：续断、牛膝（去芦，酒浸）。上为细末，温酒调下二钱，食前服。（《魏氏家藏方》续断散） ③治妊娠胎动两三月堕：川续断（酒浸）、杜仲（姜汁炒去丝）各二两。为末，枣肉煮烊，杵和丸梧子大。每服三十丸，米饮下。（《纲目》） ④治滑胎：菟丝子四两（炒，炖），桑寄生二两，川续断二两，真阿胶二两。上药将前三味轧细，水化阿胶和为丸一分重（干足一分）。每服二十丸，开水送下，日再服。（《医学衷中参西录》寿胎丸） ⑤治打扑伤损，闪肭骨节：接骨草捣烂盫之。（《卫生易简方》） ⑥治产后血运，心腹鞕，乍寒乍热：续断三两，粗捣筛，每服二钱匕，以水一盏，煎至七分，去滓温服。（《圣济总录》续断汤） ⑦治乳汁不行：川续断五钱，当归、川芎各一钱五分，麻黄、川山甲（火煅）各二钱，天花粉三钱。水二大碗，煎八分，食后服。（《本草汇言》） ⑧治乳痈初起可消，久患可愈：川续断八两（酒浸，炒），蒲公英四两（日干，炒）。俱为末，每早晚，各服三钱，白汤调下。（《本草汇言》） ⑨治水肿：续断根，炖猪腰子食。（《湖南药物志》） (10)泰山磐石散（《古今医统大全》）治气血虚弱，胎元不固证。胎动不安，堕胎，滑胎，面色淡白，倦怠乏力，不思饮食，舌淡苔薄白，脉滑无力。人参、黄芪各3g，白术、炙甘草各1.5g，当归3g，川芎、白芍药、熟地黄各2.4g，续断3g，糯米一撮，黄芩3g，砂仁1.5g。水煎服。方中续断补肾安胎，为佐药。 (11)续断汤（《外台秘要》）治下焦虚寒损，或便前转后见血，此为近血，或痢下，或不痢，因劳冷而发。续断、当归、桔梗、阿胶（炙）各12g，桂心（炙）9g，干姜、干地黄、川芎各12g，蒲黄3g，甘草（炙）6g。水煎服，阿胶烊化，下蒲黄，分为3服。方中续断具有补肝肾，止血，通利血脉之功效。', tips='恶雷丸。 ②《得配本草》：初痢勿用，怒气郁者禁用。' where id=2117; -- 续断
update herbs set effect='①治高血压、脑瘤或脑栓塞所致偏瘫：鲜夏天无捣烂。每次大粒四至五粒，小粒八至九粒，每天一至三次，米酒或开水送服，连服三至十二个月。（《浙江民间常用草药》） ②治各型高血压：㈠夏天无研末冲服，每次二至四克。㈡夏天无、钩藤、桑白皮、夏枯草。煎服。 ③治风湿性关节炎：夏天无粉每次服三钱，日二次。 ④治腰肌劳损：夏天无全草五钱。煎服。（②方以下出江西《中草药学》）', tips='祛风除湿；舒筋活血；通络止痛；降血压。主风湿性关节炎；中风偏瘫；坐骨神经痛；小儿麻痹后遗症；腰肌劳损；跌扑损伤；高血压。用于中风偏瘫，跌扑损伤，风湿性关节炎，坐骨神经痛。 ①《浙江民间常用草药》：行血，活血，止血，止痛，镇痉。 ②江西《中草药学》：降压止痛，行气活血。治各型高血压、偏瘫症，风湿性关节炎，腰肌劳损。' where id=2118; -- 夏天无
update herbs set taste='辛，温，有毒。', channel='入肾、肝经。', effect='①治阳痿、耳鸣：仙茅、金樱子根及果实各五钱。炖肉吃。（《贵州草药》） ②治老年遗尿：仙茅一两。泡酒服。（《贵州草药》） ③壮筋骨，益精神，明目：仙茅二斤（糯米泔浸五日，去赤水，夏月浸三日，铜刀刮锉，阴干，取一斤），苍术二斤（米泔浸五日，刮皮，焙干，取一斤），枸杞子一斤，车前子十二两，白茯苓（去皮）、茴香（炒）、柏子仁（去壳）各八两，生地黄（焙）、热地黄（焙）各四两。为末，酒煮糊丸，如梧子大。每服五十丸，食前温酒下，日二服。（《圣济总录》仙茅丸） ④定喘，补心肾，下气：白仙茅半两（米泔浸三宿，晒干，炒），团参一分，阿胶一两三分（炒），鸡膍胵两半。上为末，每服二钱，糯米饮调，空腹服。（《三因方》神秘散） ⑤治冲任不调症状的高血压病：仙茅、仙灵脾、巴戟、知母、黄柏、当归，六味等分，煎成浓缩液。日服二次，每次五钱至一两。（《中医研究工作资料汇编》二仙汤） ⑥治妇人红崩下血，已成漏症：仙茅三钱（为末），全秦归、蛇果草各等分，以二味煎汤，点水酒将仙茅末送下。（《滇南本草》） ⑦治痈疽火毒，漫肿无头，色青黑者：仙茅不拘多少，连根须煎，点水酒服；或以新鲜者捣烂敷之。有脓者溃，无脓者消。（《滇南本草》） ⑧治蛇咬：天棕同半边莲捣烂贴患处。（《草药单方临床病例经验汇编》）' where id=2119; -- 仙茅
update herbs set taste='味甘；苦；咸；性微寒。', channel='入肺、肾经。', effect='①治伤寒发汗吐下后，毒气不散，表虚里实，热发于外，故身斑如锦文，甚则烦躁谵语，兼治喉闭肿痛：玄参、升麻、甘草（炙）各半两。上锉如麻豆大，每服抄五钱匕，以水一盏半，煎至七分，去滓服。（《类证活人书》玄参升麻汤） ②治三焦积热：玄参、黄连、大黄各一两。为末，炼蜜丸梧子大。每服三、四十丸，白汤下。小儿丸粟米大。（《丹溪心法》） ③治阳明温病，无上焦证，数日不大便，当下之，若其人阴素虚，不可行承气者：玄参一两，麦冬（连心）八钱。水八杯，煮取三杯，口干则与饮令尽。不便，再作服。（《温病条辨》增液汤） ④治伤寒上焦虚，毒气热壅塞，咽喉连舌肿痛：玄参、射干、黄药各一两。上药捣筛为末，每服五钱，以水一大盏，煎至五分，去滓，不拘时温服。（《圣惠方》玄参散） ⑤治急喉痹风，不拘大人小儿：玄参、鼠粘子（半生半炒）各一两。为末，新汲水服一盏。（《圣惠方》） ⑥治瘰疬初起：元参（蒸）、牡蛎（醋煅，研）、贝母（去心，蒸）各四两。共为末，炼蜜为丸。每服三钱，开水下，日二服。（《医学心悟》消瘰丸） ⑦解诸热，消疮毒：玄参、生地黄各一两，大黄五钱（煨）。上为末，炼蜜丸，灯心、淡竹叶汤下，或入砂糖少许亦可。（《补要袖珍小儿方论》） ⑧治赤脉贯瞳：玄参为末，以米泔煮猪肝，日日蘸食之。（《济急仙方》）' where id=2120; -- 玄参
update herbs set taste='味甘；性凉；无毒。', channel='归心；胃；膀胱经。', effect='①治肾脏炎，水肿：西瓜皮（须用连髓之厚皮，晒干者入药为佳，若中药店习用之西瓜翠衣则无著效；干者一两三钱，白茅根鲜者二两。水煎，一日三回分服。（《现代实用中药》） ②治闪挫腰疼，不能屈伸者：西瓜青为片，阴干为细末，以盐酒调，空心服。（《摄生众妙方》） ③治牙痛：经霜西瓜皮烧灰，敷患处牙缝内。（《本草汇言》）' where id=2121; -- 西瓜皮
update herbs set taste='味甘；微苦；性凉。', channel='入肝、脾经。', effect='①治心热吐血口干：生藕汁，生牛蒡汁、生地黄汁、小蓟根汁各二合，白蜜一匙。上药相和，搅令匀，不计时候，细细呷之。（《圣惠方》） ②治舌上出血，兼治大衄：刺蓟一握，研，绞职汁，以酒半盏调服。如无生汁，只捣干者为末，冷水调下三钱匕。（《圣济总录》清心散） ③治呕血、咯血：大蓟、小蓟、荷叶、扁柏叶、茅根、茜草、山栀、大黄、牡丹皮、棕榈皮各等分。烧灰存性，研极细末，用纸包，碗盖于地上一夕，出火毒，用时先将白藕汁或萝卜汁磨京墨半碗调服五钱，食后下。（《十药神书》十灰散） ④治下焦结热血淋：生地黄（洗）四两，小蓟根、滑石、通草、蒲黄（炒）、淡竹叶、藕节、当归（去芦，酒浸）、山栀子仁、甘草（炙）各半两。上细切，每服四钱，水一盏半，煎至八分，去滓温服，空心食前。（《济生方》） ⑤治崩中下血：小蓟茎、叶（洗，切）研汁一盏，入生地黄汁一盏，白术半两，煎减半，温服。（《千金方》） ⑥治妊娠胎堕后出血不止：小蓟根叶（锉碎）、益母草（去根，切碎）各五两。以水三大碗，煮二味烂熟去滓至一大碗，将药于铜器中煎至一盏，分作二服，日内服尽。（《圣济总录》小蓟饮） ⑦治妇人阴庠：小蓟煎汤，日洗三次。（《广济方》）' where id=2122; -- 小蓟
update herbs set taste='辛；温；小毒。', channel='入肺、肾经。', effect='①治风冷头痛，痛则如破，其脉微弦而紧：细辛一两（净），川芎一两，附子（炮）半两净，麻黄一分。上细切，入连根葱白、姜、枣。每服五钱，水一盏半，煎至一盏，连进三服。（《普济方》细辛散） ②治偏头痛：雄黄（研）、细辛（去苗叶，为末）等分。上二味，再同研匀。每服一字，左边疼搐入右鼻，右边痛搐入左鼻。（《圣济总录》至灵散） ③治伤风鼻塞：细辛、紫苏、防风、杏仁、桔梗、薄荷、桑白皮。煎服。（《方脉正宗》） ④治伤寒表不解，心下有水气，干呕发热而咳，或渴、或利、或噎、或小便不利；少腹满，或喘者：麻黄（去节）、芍药、细辛、干姜、甘草（炙）、桂枝（去皮）各三两，五味子半升，半夏半升（洗）。上八味，以水一斗，先煮麻黄，减二升，去上沫，纳诸药，煮取三升，去滓。温服一升。（《伤寒论》小青龙汤） ⑤治鼻塞不通：细辛末少许，吹入鼻中。（《普济方》） ⑥治牙齿痛久不瘥：细辛（去叶苗）、荜拨。上二味等分，粗捣筛。每用半钱匕，水一盏，煎十数沸，热漱冷吐。（《圣济总录》细辛汤） ⑦治牙齿疼痛：荆芥、细辛、露蜂房各等分。上为粗末，每用三钱，水一大盏，煎至七分，去滓，温漱冷吐。（《御药院方》细辛散） ⑧治牙痛：细辛一钱，黄柏一钱。煎水漱口，不可嚼下。（《吉林中草药》） ⑨治痰饮，冲气即低，而反更咳、胸满者：茯苓四两，甘草、干姜、细辛各三两，五味子半升。上五味，以水八升，煮取三升，去滓。温服半升，日三。（《金匮要略》苓甘五味姜辛汤） ⑩治少阴病，始得之，反发热，脉沉者：麻黄二两（去节），细辛二两，附子一枚（炮、去皮，破八片）。上三味，以水一斗，先煮麻黄，减二升，去上沫，纳诸药，煮取三升，去滓。温服一升，日三服。（《伤寒论》麻黄附子细辛汤） ⑾治风入腹，切痛烦冤：细辛、吴茱萸、干姜各半两，当归、防风各一两，芍药二两。上为末，每以半两，水二升，煮一升。温分三服，相续进之。（《元和纪用经》细辛汤） ⑿治小儿口疮：细辛末，醋调，贴脐上。（《卫生家宝方》） ⒀治口臭及匿齿肿痛：细辛煮取浓汁，热含冷吐。（《圣惠方》） ⒁治耳聋：细辛末，溶黄蜡丸鼠屎大。绵裹一丸，塞之。须戒怒气。（《龚氏经验方》聪耳丸） ⒂治虚寒呕哕，饮食不下：细辛（去叶）半两，丁香二钱半。为末。每服一钱，柿蒂汤下。（《纲目》） ⒃治暗风卒倒，不省人事：细辛末，吹入鼻中。（《世医得效方》）' where id=2123; -- 细辛
update herbs set taste='味辛；微寒；无毒。', channel='入肝、三焦经。', effect='①治-切气疾心腹胀满，胸膈噎塞，噫气吞酸，胃中痰逆呕吐及宿酒不解，不思饮食：香附子（炒，去毛）三十二两，缩砂仁八两，甘草（爁）四两。上为细末。每服一钱，用盐汤点下。（《局方》快气汤） ②治心腹刺痛，调中快气：乌药（去心）十两，甘草（炒）一两，香附子（去皮毛，焙干）二十两。上为细末。每服一钱，人盐少许，或不着盐，沸汤点服。（《局方》小乌沉汤） ③治心气痛、腹痛、少腹痛、血气痛不可忍者：香附子二两，蕲艾叶半两。以醋汤同煮熟，去艾，炒为末，米醋糊为丸梧子大。每白汤服五十丸。（《濒湖集简方》） ④解诸郁：苍术、香附、抚芎、神曲、栀子各等分。为末，水丸如绿豆大。每服一百丸。（《丹溪心法》越鞠丸） ⑤治停痰宿饮，风气上攻，胸膈不利：香附（皂荚水漫）、半夏各一两，白矾末半两。姜汁面糊丸，梧子大。每服三、四十丸，姜汤随时下。（《仁存堂经验方》） ⑥治偏正头痛：川芎二两，香附子（炒）四两。上为末。以茶调服，得腊茶清尤好。（《澹寮方》） ⑦治吐血：童便调香附末或白及末服之。（《丹溪治法心要》） ⑧治小便尿血：香附子、新地榆等分。各煎汤。先服香附汤三、五呷，后服地榆汤至尽，未效再服。（《全生指迷方》） ⑨治下血不止或成五色崩漏：香附子（去皮毛，略炒）为末。每服二钱，清米饮调下。（《本事方》） ⑩治肛门脱出：香附子、荆芥穗等分。为末。每用三匙，水一大碗，煎十数沸，淋。（《三因方》香荆散） ⑾治老小痃癖往来疼痛：香附、南星等分。为末，姜汁糊丸，梧子大。每姜汤下二、三十丸。（《圣惠方》） ⑿治颓疝胀痛及小肠气：香附末二钱，海藻一钱。煎酒空心调下，并食海藻。（《濒湖集简方》） ⒀安胎：香附子，炒，去毛，为细末，浓煎紫苏汤调下一钱。（《中藏经》铁罩散） ⒁治元脏虚冷，月侯不调，头眩，少食，浑身寒热，腹中急痛，赤白带下，心怔气闷，血中虚寒，胎气不固：香附半斤。醋煮，焙为末，醋和丸桐子大。每服三、四十丸，米饮下。（《妇人良方》醋附丸） ⒂治瘰疬流注肿块，或风寒袭于经络，结肿或痛：香附为末，酒和，量疮大小，做饼覆患处，以热熨斗熨之。未成者内消，已成者自溃。若风寒湿毒，宜用姜汁作饼。（《外科发挥》） ⒃治乳痈，一切痈肿：香附（细末）一两，麝香二分。上二昧研匀，以蒲公英二两，煎酒去渣，以酒调药。热敷患处。（《医学心悟》香附饼） ⒄治耳卒聋闭：香附子（瓦炒）研末，萝卜子煎汤，早夜各服二钱，忌铁器。（《卫生易简方》） ⒅治聤耳出汁：香附末，以绵杖送入。（《经验良方》） ⒆治四时瘟疫、伤寒：陈皮（不去白）二两，香附子（炒香，去毛）、紫苏叶各四两，甘草（炙）一两。上为粗末。每服三钱，水一盏，煎七分，去滓热服，不拘时，日三服。若作细末，每服二钱，入盐点服。（《局方》香苏散） ⒇治跌打损伤：炒香附四钱，姜黄六钱。共研细末。每日服三次，每次服一钱。孕妇忌服。（徐州《单方验方新医疗法选编》） （21）治鸡眼，疣：香附、木贼各五钱。制法：加水1300毫升，文火煎至100毫升，备用。用法：㈠先将患处洗净，去硬茧，以不出血为度。再以少量药液加热，用棉签蘸药液涂患处，每日二次。㈡将备用之药液倒入小容器内2～5毫升，加热，再扣在疣上3～5分钟，连续五次即可。（内蒙古《中草药新医疗法资料选编》）' where id=2124; -- 香附
update herbs set taste='味苦；辛；性寒。', channel='入肝、胆经。', effect='①治瘰疬马刀，不问已溃未溃，或日久成漏：夏枯草六两，水二钟，煎至七分，去滓，食远服。虚甚当煎浓膏服，并涂患处，多服益善。（《摄生众妙方》夏枯草汤） ②治乳痈初起：夏枯草、蒲公英各等分。酒煎服，或作丸亦可。（《本草汇言》） ③治肝虚目睛疼，冷泪不止，筋脉痛，及眼羞明怕日：夏枯草半两，香附子一两，共为末。每服一钱，腊茶调下，无时。（《简要济众方》补肝散） ④��血崩不止：夏枯草为末。每服方寸匕，米饮调下。（《圣惠方》） ⑤治赤白带下：夏枯草花，开时采，阴干为末。每服二钱，食前米饮下。（《纲目》） ⑥治产后血晕，心气欲绝者：夏枯草捣绞汁，服一盏。（《纲目》） ⑦治口眼歪斜：夏枯草一钱，胆南星五分，防风一钱，钓钩藤一钱。水煎，点水酒临卧时服。（《滇南本草》） ⑧治头目眩晕：夏枯草（鲜）二两，冰糖五钱。开水冲炖，饭后服。（《闽东本草》） ⑨治羊痫风、高血压：夏枯草（鲜）三两，冬蜜一两。开水冲炖服。（《闽东本草》） ⑩预防麻疹：夏枯草五钱至二两。水煎服，一日一剂，连服三天。（徐州《单方验方新医疗法选编》） ⑾治小儿菌痢：二岁以下，夏枯草一两，半枝莲五钱；二至六岁，夏枯草、半枝莲各一两；六至十二岁，夏枯草、半枝莲各一两半。水煎服。（《全展选编·传染病》） ⑿治急性扁桃体炎，咽喉疼痛：鲜夏枯草全草二至三两。水煎服。（《草医草药简便验方汇编》） ⒀治扑伤金疮：夏枯草捣烂，罯上。（《卫生易简方》） ⒁打伤、刀伤。把夏枯草在口中嚼碎后敷在伤处。 ⒂汗斑白点。用夏枯草煎成浓汁，每天洗患处。', tips='脾胃虚弱者慎服。 ②《得配本草》：气虚者禁用。' where id=2125; -- 夏枯草
update herbs set taste='辛苦，温，有毒。', channel='入心、肝、胃经。', effect='①治瘑疥：雄黄一两，黄连二两，松脂三两，发灰如弹丸。四物熔猪膏与松脂合，热捣，以薄疮上。（《补缺肘后方》） ②治癣：雄黄粉，大酢和。先以新布拭之，令癣伤，敷之。（《千金翼方》） ③治遍身虫疥虫癣：雄黄、蛇床子各等分，俱研细，水银减半。以猪油和捣匀，入水银再研，以不见星为度。早晚以汤洗净，搽药。（《姜月峰家传方》） ④治白秃头疮：雄黄、猪胆汁。和敷之。（《圣济总录》） ⑤治痈疽坏烂及诸疮发毒：雄黄五钱，滑石倍用。上为末，洗后掺疮上，外用绵子覆盖相护。凡洗后破烂者，用此贴之。（《世医得效方》生肉神异膏） ⑥治对口疼痛：雄黄一钱，吴茱萸一两。为末，香油熬熟调搽。（《经验广集》雄吴散） ⑦治疔肿：针刺四边及中心，涂雄黄末。（《千金方》） ⑧治走马牙府，臭烂出血：雄黄豆大七粒。每粒以淮枣去核包之，铁线串于灯上烧化为末。每以少许掺之，去涎，以愈为度。（《全幼心鉴》） ⑨治蛇缠疮：雄黄为末，醋调徐，仍用酒服。凡为蛇伤及蜂虿、蜈蚣、毒虫、颠犬所伤，皆可用。（《世医得效方》） ⑩治破伤风：雄黄一钱，防风二钱，草乌一钱。上为细末，每服-字，温酒调下。里和至愈可服，里不和不可服。（《素同病机保命集》发表雄黄散） ⑾治蛇咬伤：雄黄一两，生五灵脂一两。共研细末，分成十包，每二小时服一包，每日四至八次，开水送下，另取雄黄二两，研细末，用香油一两调匀，涂于患处，每日更换2～3次。（《山东医刊》（4）：23，1963） ⑿治腋臭：雄黄、石膏各半斤，白矾一斤。石膏研末，放锅内煅成白色，再将雄黄、白矾研细过筛，混合搅匀，密闭保存。用时将手指沾水湿润后，沾适量药粉（约一钱），使成浆糊状（勿过稠或过稀），涂于腋窝部，每日一次，连续涂药至愈。（《全展选编·皮肤疾病》） ⒀治臁疮日久：雄黄二钱。陈皮五钱。青布卷作大捻，烧烟熏之。（《卫生杂兴》） ⒁治杨梅疮：雄黄一钱半，杏仁三十粒（去皮），轻粉一钱。为末，洗净，以雄猪胆汁调上。（《积德堂经验方》） ⒂治赤鼻：雄黄五钱（用透明成块、无石、红色者为佳），硫黄五钱，陈水粉（真正者）。共研细末，合一处，用乳汁调敷。（《摄生众妙方》） ⒃治大麻疯：真漆一两（入蟹黄五钱拌匀，晒之，渐渐去浮面上水），明雄黄、牙皂各五钱。和匀为丸，不可见日，阴干。每服三分，酒下。（《疡医大全》雄漆丸） ⒄治伤寒狐惑，毒蚀下部，肛门如匿，痛痒不止.雄黄半两。先用瓶子一个，口稍大者，内入灰上（土），如装香火，将雄黄烧之，候烟出，以瓶口当病处熏之。（《圣惠方》） ⒅治缠喉急喉风，双蛾肿痛，汤药难下：雄黄一两，巴豆（去油）十四个，郁金一钱。为末，醋糊丸如绿豆大。茶清下七丸，吐出顽痰即苏。如口噤，以物斡开灌之。（《丹溪心法》雄黄解毒丸） ⒆治小儿诸痫：雄黄、朱砂等分。为末，每取一钱，猪心血入虀水调。（《仁斋直指方》） ⒇治癫痫卒倒，常愈常发：雄黄（水飞过）、胆星（俱研细）、萆麻内务等分。共研匀，米糊为丸，如绿豆大。每早饭后服一钱，白汤下。（《方脉正宗》） （21）治偏头疼：雄黄、细辛等分。研令细。每用一字已下，左边疼吹入右鼻，右边疼吹入左鼻。（《博济方》至灵散） （22）治腹胁痞块：雄黄一两，白矾一两。为末，面糊调膏摊贴。（《集玄方》） （23）治痔疮并肠红：雄黄一钱五分，五倍子一两，白矾二钱。共研末，乌梅肉为丸。每服一钱，空心白汤下。（《医方易简》） （24）治积年冷痿，出黄水不瘥：雄黄半两（细研），清油三两，乱发半两，硫黄半两（细研），黄蜡半两。上先以油煎乱发令焦尽，去滓，便入雄黄、硫黄及黄蜡，以慢火熬搅成膏，摊帛上贴之。（《圣惠方》雄黄膏） （25）治布鲁氏菌痢病后遗症：雄黄一两，大蒜六十瓣。将雄黄研细，大蒜捣烂，配制成六十丸，每次一丸，一日三次。连服二十天为一疗程。（《全展选编·传染病》）' where id=2126; -- 雄黄
update herbs set taste='味苦、涩，性平。', effect='①治肺痨咯血：鲜仙鹤草一两（干者，六钱），白糖一两。将仙鹤草捣烂，加冷开水叫、碗，搅拌，榨取液汁，再加入白糖，一次服用。（《贵州民间方药集》） ②治吐血：仙鹤草、鹿衔草、麦瓶草。熬水服。（《四川中药志》） ③治鼻血及大便下血：仙鹤草、蒲黄、茅草根、大蓟。煎服。（《四川中药志》） ④治亦白痢及咯血、吐血：龙芽草三钱至六钱，水煎服。（《岭南采药录》） ⑤治妇人月经或前或后，有时腰痛、发热。气胀之症：黄龙尾二钱，杭芍三钱，川芎一钱五分，香附一钱，红花二分，水煎，点酒服。如经血紫黑，加苏木、黄芩；腹痛加延胡索、小茴香。（《滇南本草》） ⑥治赤白带或兼白浊：黄龙尾三钱，马鞭梢根一钱，黑锁梅根二钱。点水酒服。（《滇南本草》） ⑦治贫血衰弱，精力痿顿（民间治脱力劳伤）：仙鹤草一两，红枣十个。水煎，一日数回分服。（《现代实用中药》） ⑧治小儿疰夏：仙鹤草五钱，红枣七粒，水煎服。（《浙江天目山药植志》） ⑨治小儿疳积：龙芽草五至七钱，去根及茎上粗皮，合猪肝三至四两，加水同煮至肝熟，去渣，饮汤食肝。（《江西民间草药验方》） ⑩治疟疾，每日发作，胸腹饱胀：仙鹤草三钱，研成细末，于发疟前用烧酒吞服，连用三剂。（《贵州民间方药集》） ⑾治过敏性紫癜：仙鹤草三两，生龟版一两，枸杞根、地榆炭各二两。水煎服。（苏医《中草药手册》） ⑿治痈疽结毒：鲜龙芽草四两，地瓜酒半斤，冲开水，炖，饭后服。初起者服三、四剂能化解，若已成脓，连服十余剂，能消炎止痛。（《闽东本草》） ⒀治乳痈，初起者消，成脓者溃，且能令脓出不多：龙芽草一两，白酒半壶，煎至半碗，饱后服。（《百草镜》） ⒁治跌伤红肿作痛：仙鹤草、小血藤、白花草（酒炒，外伤破皮者不用酒炒）。捣绒外敷，并泡酒内服。（《四川中药志》） ⒂治蛇咬伤：鲜龙芽草叶，洗净，捣烂贴伤处。（《福建民间草药》）' where id=2127; -- 仙鹤草
update herbs set effect='1.治一切气刺门气胀，心腹痞塞诸症：茴香、蓬术、萝卜子、桂心各30g，陈皮30.3g，干姜1g，甘草39g，白术、牵牛各15g，三棱105g。水煎，每日一剂，分2次服。方中小茴香理气和胃，为君药。（《奇效良方》万和散） 2.治梦泄遗精，关锁不固等症：茴香、葫芦巴、补骨脂、白龙骨各30g，木香45g，胡桃（研膏）30个，羊肾（切开盐擦，炙熟捣膏）3对。上7味，前5味为末，和2膏研匀，酒浸煮，丸如梧子大，每服30-50丸，盐汤下。方中小茴香祛寒止痛，理气和胃，为君药。（《大同方剂学》金锁丹） 3.治耳聋，气闭不通：茴香、木香、全蝎、陈皮、菖蒲、玄胡索各3g，羌活、僵蚕、川芎、蝉蜕各1.5g，甘草4.5g，穿山甲6g。上为细末，每服9g，温酒调服。方中小茴香理气，为君药。（《奇效良方》通气散）' where id=2128; -- 小茴香
update herbs set taste='辛苦，温，有毒。', channel='归肺、脾、肾经。', effect='①治太阳中风，下利呕逆，表解，其人絷絷汗出，发作有时，头痛，心下痞鞕满，引胁下痛，干呕短气，汗出不恶寒者：芫花（熬），甘遂、大戟。上三味，等分，各别捣为散，以水一升半，先煮大枣肥者十枚，取八合，去滓，内药末，强人飘一钱匕。羸人服半钱，温服之，平旦服。若下少病不除者，明日更服，加半钱，得快下利后，糜粥自养。（《伤寒论》十枣汤） ②治卒得咳嗽：芫花一升。水三升，煮取一升，去滓，以枣十四枚，煎令汁尽，一日一食之，三日讫。（《补缺肘后方》） ③治水病通身微肿，腹大，食饮不消：芫花（微炒），甘遂（微炒），大黄（锉碎、醋炒拌干）、葶苈（炒令紫色）各一两，巴豆（去心，皮，麸炒，研出油尽）四十枚。上五味，捣罗为末，炼蜜为丸，如小豆大，每服，饮下三丸，不知，稍增至五丸，以知为度。（《圣济总录》小消化丸） ④治蛊胀：枫壳、芫花各等分。上用酽醋浸芫花透，将醋再煮枳壳烂，擂芫花末，和为丸，如梧桐子大。每服数丸，温白汤送下。（《普济方》枳壳丸） ⑤治时行毒病七、八日，热积聚胸中，烦乱欲死：芫花一升，以水三升，煮取一升半，渍故布薄胸上。不过三薄，热即除，当温暖四肢护厥逆也。（《千金方》凝雪汤） ⑥治疟母弥年，经吐、汗、下，荣卫亏损，邪气伏藏胁间，结为癥癖，腹胁坚痛：芫花（炒），朱砂（研）各等分。为末，炼蜜丸，如小豆。每服十丸，浓煎枣汤下，下后即与养胃汤。（《仁斋直指方》消癖丸） ⑦治痈：尧花为末，胶和如粥敷之。（《千金方》） ⑧治急性乳腺炎，兼治深部脓肿：芫花二钱至一两，鸡蛋三至五个。二味同煮，蛋熟后剥去壳，刺数小洞放入再煮，至蛋发黑为度，吃蛋喝汤，每天一至二次，每次一至二个。服后有头昏、恶心者，可吃蛋不喝汤。如反应甚者，以菖蒲煎服解之。孕妇忌服。勿与甘草同服。（《江苏省中草药新医疗法展览资料选编》） ⑨治白秃头疮：芫花末，猪脂和涂之。（《集效方》） ⑩治牙痛，诸药不效者：芫花碾为末，擦痛处令热。（《魏氏家藏方》芫花散） ⑾治小瘤：先用甘草煎膏，笔蘸妆瘤傍四围，干后复妆，凡三次，然后以药：大戟、芫花、甘草（等分），上为末，米醋调，别笔妆敷其中，不得近著甘草处。次日缩小，又以甘草膏壮小晕三次，中间仍用大戟、芫花、甘草如前法，自然焦缩。（《世医得效方》） ⑿治心痛有虫：芫花一两（蜡炒），雄黄一钱。为末，每服一字，温醋汤下。（《乾坤生意》） ⒀治诸般气痛：芫花（醋煮）半两，延胡索（炒）一两半。为末，每服一钱。疟疾，乌梅汤下；妇人血气痛，当归酒下；诸气痛，香附汤下；小肠气痛，茴香汤下。（《仁存堂经验方》） ⑷治酒疸，心懊痛，足胫满，小便黄，饮酒发赤斑黄黑，由大醉当风入水所致：芫花、椒目等分。烧末，服半钱，日一两遍。（《补块肘后方》） ⒂治一切菌毒：芫花生研，新汲水服一钱，以利为度。（《世医得效方》） ⒃治妇人积年血气癥块结痛：芫花一两（醋拌炒令干），当归一两（锉，微炒），桂心一两，上药，捣罗为末，以软饭和丸，如梧桐子大。每服，食前以热酒下十丸。（《圣惠方》） ⒄突发咳嗽：用芫花一升，加水三升煮汁一升，以枣十四枚，放入汁中煮干，一天吃五枚，必愈。 ⒅咳嗽有痰：用芫花一两（炒），加水一升，煮开四次，去渣，再加入白糖半斤。每服约一个枣子大的量。忌食酸咸物。 ⒆干呕胁痛（伤寒有时头痛，心下痞满，痛引两胁，干呕短气，汗出而不恶寒）：用芫花（熬过）、甘遂、大戟，等分为末。以大枣十枚、水一升半，煮成八合后，去渣纳药。体壮者服一钱，弱者半钱，清晨服下。能下泻则病除，否则次晨再服药。此方名十枣汤。 ⒇水肿：用上方（十枣汤）加大黄、甘草五物各一两，大枣十枚，同煮，如法服。另方：药中再加硭硝一两。 （21）久疟，腹胁坚痛：用芫花（炒）二两，朱砂五钱，共研为末，加蜜做成丸子，如梧子大。每服十丸，枣汤送下。 （22）水盅胀满：用芫花、枳壳等分，先以醋把芫花煮烂，再加可枳壳煮烂，一起捣匀做丸子，如梧子大。每服三十丸，白汤送下。 （23）子宫结块，月经不通：用芫花根三两，锉细，炒黄，研为末。每服一钱，桃仁煎汤调下。泻下恶物即愈。 （24）牙痛难忍，诸药不效：用芫花末擦牙令热。痛定后，以温水漱口。 （25）痈肿初起：用芫花末和胶涂搽。 （26）痔疮：用芫根一把，捣烂，慢火煎成膏，将丝线于膏内度过，以线系痔，当有微痛的感觉。等痔疮干落后，即以纸捻蘸膏纳入肛门中，可以便痔疮断根。另方：只捣汁浸线一夜即用，不必熬膏。', tips='体质虚弱及孕妇禁服。孕妇禁用；不宜与甘草同用。 反甘草。' where id=2129; -- 芫花
update herbs set taste='苦辛，凉。', effect='①治疔疮：野菊花和黄糖捣烂贴患处。如生于发际，加梅片、生地龙同敷。（《岭南草药志》） ②治一切痈疽脓疡，耳鼻咽喉口腔诸阳症脓肿：野菊花一两六钱，蒲公英一两六钱，紫花地丁一两，连翘一两，石斛一两。水煎，一日三回分服。（《本草推陈》） ③治夏令热疖及皮肤湿疮溃烂：用野菊花或茎叶煎浓汤洗涤，并以药棉或纱布浸药汤掩敷，一日数回。（《本草推陈》） ④治胃肠炎，肠鸣泄泻腹痛：干野菊花三、四钱。煎汤，一日二、三回内服。（《本草推陈》） ⑤治肠风：野菊花六两（晒干，炒成炭），怀熟地八两（酒煮，捣膏），炮姜四两，苍术三两；地榆二两，北五味二两。炼蜜为丸梧桐子大，每服五钱，食前白汤送下。（《本草汇言》） ⑥预防流脑：野菊花一斤。将上药粉碎，加水十斤，熬煎至70％煎液，过滤去渣。在流脑流行期，用上项药液滴鼻二至三滴，每日两次。（辽宁《中草药新医疗法资料选编》） ⑦治大、小叶性肺炎，支气管炎，阑尾炎及一般急性炎症疾病：野菊花一两，一点红五钱，金银花藤叶一两，积雪草五钱，犁头草五铰，白茅根五钱。水煎服，每日一至二剂。（《江西草药》） ⑧治泌尿系统感染：野菊花一两，海金砂一两。水煎服，每日二剂。（《江西草药》） ⑨治扩散型肺结核：野菊花一两五钱，地胆草一两，兰香草二两。水煎服，每日一剂。（《江西草药》） ⑩治头癣、湿疹、天抱疮：野菊花、苦楝根皮、苦参根各适量。水煎外洗。（《江西草药》） ⑾治肝肾风毒，气上冲，眼痛。甘菊花、牛蒡子各240g，白蒺藜（去刺）30g，甘草45g，防风90g，上为细末，每服6g，熟水调下。食后临卧服。方中菊花清热解毒，为君药。（菊花散《本事方》） ⑿治头风鼻塞，或偏正头痛。菊花、川芎、荆芥穗、羌活、白芷、甘草各30g，防风23g，细辛15g，蝉壳、薄荷、白僵蚕各7.5g。上为细末，每服6g，茶清食后调下。方中菊花清热。（菊花茶调散《丹溪心法》） ⒀治头面游风。菊花30g，细辛、附子、桂心、干姜、巴戟、人参、石楠叶、天雄、茯苓、秦艽、山茱萸、防己、防风、白术、薯蓣各90g，蜀椒15g。上17味，治下筛酒，每服10g，每日3次。（菊花散《医部全录·头风》）' where id=2130; -- 野菊花
update herbs set taste='味苦；性寒；小毒。', effect='①治里急后重：鸦胆去壳留肉，包龙眼肉，每岁一粒，白滚水下。（《吉云旅钞》） ②治热性亦痢，及二便因热下血：鸦胆子去皮，每服二十五粒，极多至五十粒，白糖水送下。此物囫囵吞服，去皮时仁有破者，去之勿服，服之恐作呕吐。（《医学衷中参西录》） ③治疟疾：鸦胆子果仁十粒，入桂圆肉内吞服，日三次，第三日后减半量，连眼五日。（《广西中草药》） ④治早期血吸虫病：鸦胆子果仁十粒，日二次，连服四、五天。（《广西中草药》） ⑤治痔：鸦胆子七粒，包圆眼肉，吞下。（《纲目拾遗》） ⑥治疣：鸦胆子去皮，取白仁之成实者，杵为末，以烧酒和涂少许，小作疮即愈。（《医学衷中参西录》） ⑦治脚鸡眼；鸦胆子二十个，砸开取仁，用针尖戳住，放灯头以上少烤，烤至黄色，再放一小块胶布上，用刀将该药按成片，粘于患处（在粘前用开水将患处洗净，用刀将厚皮割去），每日换一次，二十天左右即痊愈。（《新中医药》8（12）：583，1957） ⑧治滴虫性阴道炎：鸦胆子二十个，去皮，水一茶杯半，用砂壶煎至半茶杯，倒入消毒碗内，用消过毒的大注射器将药注入阴道，每次注二十至四十毫升。轻者一次，重者二至三次。（《河北中医药集锦》）' where id=2131; -- 鸦胆子
update herbs set taste='辛；苦；温；无毒。', channel='入肝、胃经。', effect='①治热瓢心痛，或发或止，久不愈，身热足寒者：玄胡索（去皮）、金铃子肉等分。为末。每温酒或白汤下二钱。（《圣惠方》） ②治下痢腹痛：延胡索三钱，米饮服之，痛即减，调理而安。（《纲目》） ③治咳喘：醋制玄胡七成，枯矾三成。共研细粉。一日三次，每服一钱。（沈阳《中草药、验方、制剂、栽培选编》） ④治室女血气相搏，腹中刺痛，痛引心端，经行涩少，或经事不调，以致疼痛：玄胡索（醋煮去皮）；当归（去芦，酒浸锉略炒）各一两，橘红二两.上为细末，酒煮米糊为丸，如梧桐子大。每服七十丸，加至一百丸，空心艾汤卞，米饮亦得。（《济生方》三神丸） ⑤治产后恶露下不尽，腹内痛：延胡索末，以温酒调下一钱。（《圣惠方》） ⑥治坠落车马，筋骨疼痛不止：延胡索一两。捣细罗为散，不计时候，以豆淋酒调下二钱。（《圣惠方》） ⑦治跌打损伤：玄胡炒黄研细，每服一至二钱，开水送服，亦可加黄酒适量同服。（《单方验方调查资料选编》） ⑧治疝气危急：玄胡索（盐炒）、全竭（去毒，生用）等分。为末，每服半钱，空心盐酒下。（《仁斋直指方》） ⑨治小儿盘肠气痛：延胡索、茴香等分。炒研，空心米饮，量儿大小与服。（《卫生易简方》） ⑩治偏正头痛不可忍者：玄胡索七枚，青黛二钱，牙皂二个（去皮子）。为末，水和丸如杏仁大。每以水化一丸，灌入病人鼻内，当有涎出。（《永类钤方》） ⑾治小便尿血：延胡索一两，朴消七钱半。为末，每服四钱，水煎服。（《类证活人书》） ⑿咳嗽。用延胡索一两、朴硝七钱半，共研为末。每服二钱，软糖一块和药含咽。 ⒀尿血。用延胡索一两、朴硝七钱半，共研为末。每服四钱，水煎服。 ⒁皮下气痛或气块痛。用延胡索研细，将猪胰一个，切成小块，灸热蘸药末随时吃下。 ⒂久患心痛，身热足寒。用延胡索（去皮）、金铃子肉，等分为末。每服二钱，温酒或白开水送下。 ⒃下痢腹痛。用延胡索三钱，米汤送下。 ⒄妇女血气前（月经不调，腹中刺痛）。用延胡索（去皮，醋炒）、当归（酒浸，炒）各一两，桔红二两，共研为末，酒煮米糊和药做成丸子，如梧子大。每服一百丸，空心服，艾醋汤送下。 ⒅产后诸病（血污不净，产后血晕，腹满心梗，寒热不足，手足烦热等）。用延胡索炒后研细，每服二钱，酒送下，甚效。 ⒆疝气。用延胡索（盐炒）、全蝎（去毒，生用），等分为末。每服半钱，空心服，盐酒送下。 ⒇腰 体痛。用延胡索、当归、桂心，等分为末。每服三、四钱，温酒送下。 （21）偏、正头风。用延胡索七枚、青黛二钱、牙皂（去皮，去子）二个，共研为末，滴水各丸，如杏杜大。每次水化一丸，灌入鼻内。偏头产，则在痛侧的鼻孔灌药。同时，令病人咬铜钱一个，当有涎汁大量流出，病即渐愈。' where id=2132; -- 延胡索
update herbs set alias='益智子，摘艼子。', taste='味辛；性温。', channel='入脾，肾经。', effect='①治伤寒阴盛，心腹痞满，呕吐泄利，手足厥冷，及一切冷气奔冲，心胁脐腹胀满绞痛：川乌（炮，去皮、脐）四两，益智（去皮）二两，干姜（炮）半两，青皮（去白）三两。上件为散。每服三钱，水二盏，入盐一捻，生姜五片，枣二个，擘破，同煎至八分，去滓，温服，食前。（《局方》益智散） ②治腹胀忽泻，日夜不止，诸药不效，此气脱也：益智子仁二两。浓煎饮之。（《世医得效方》） ③治梦泄：益智仁二两（用盐二两炒，去盐），乌药二两，上为末，用山药一两为糊，和丸如梧桐子大，每服五十丸，空心临卧盐汤下，以朱砂为衣。（《世医得效方》三仙丸） ④治脬气虚寒，小便频数，或遗尿不止，小儿尤效：乌药、益智仁等分。上为末，酒煮山药末为栅，丸桐子大。每服七十丸，盐酒或米饮下。（《妇人良方》缩泉丸，即《魏氏家藏方》固真丹） ⑤治小儿遗尿，亦治白浊：益智仁、白茯苓各等分，上为末。每服一钱，空心米汤调下。（《补要袖珍小儿方论》益智仁散） ⑥治妇人崩中：益智子，炒研细，米饮入盐服一钱。（《经效产宝》） ⑦治漏胎下血：益智仁半两，缩砂仁一两。为末。每服三钱，空心白汤下，日二服。（胡氏《济阴方》） ⑧治疝痛，连小腹挛搐，叫呼不已：益智仁、干姜（炮）、甘草（炙）、茴香（炒）各三钱，乌头（炮，去皮）、生姜各半两，青皮（去白）二钱。上细切。每服四钱，水二盏，入盐少许，煎至七分，去滓，空心食前温服。（《济生方》益智仁汤） ⑨治白浊腹满，不拘男妇：益智仁（盐水浸炒）、厚朴（姜汁炒）等分。姜三片，枣一枚，水煎服。（《永类钤方》） ⑩治小便赤浊：益智仁、茯神各二两，远志、甘草（水煮）各半斤。为末，酒糊丸，梧子大。空心姜汤下五十丸。（《纲目》）' where id=2133; -- 益智仁
update herbs set taste='甘，平。', channel='归肺、肝、大肠经。', effect='①治大风疾，遍身瘾疹瘙痒：胡麻子、牛蒡子、枸杞子、蔓荆子各半两（一处同炒，令烟出为度），苦参半两，瓜蒌根、防风（去芦）各半两，白蒺藜半两。上八味，同杵为末，每十五钱药末，入轻粉二钱，一处拌匀。每服-钱生末，调茶下，空心、日午、临卧各一服。服药后五、七日间，先于齿牙缝内，出臭黄涎，浑身疼痛，次后，便利下脓血，此是病根。（《博济方》醉仙散） ②治溢脂性脱发：鲜柳枝、亚麻仁各一两。煎服。（江西《中草药学》） ③治咳嗽气喘：亚麻仁、文旦皮，煎服。（江西《中草药学》）' where id=2134; -- 亚麻子
update herbs set effect='①治小儿雀目，至暮无所见：仙灵脾根半两，晚蚕蛾半两（微炒），射干一分，甘草一分（炙微亦，锉）。捣细罗为散。用羊子肝一枚，切开，掺药二钱在内，以线系定，用黑豆一合，米泔一大盏，煮熟取出，分为二服，以汁下之。（《圣惠方》仙灵脾散） ②治痈疽成脓不溃：淫羊藿干根一两，水煎，调酒和红糖服。（《福建中草药》）' where id=2135; -- 淫羊藿根
update herbs set effect='1. 治高血压 动脉硬化大动脉炎 闭塞性脉管炎心绞痛 心肌梗死 脑栓塞 再生障碍性贫血：707片（白果叶制剂 每片含黄酮2mg）每次2片 每日3次．（《陕甘宁青中草药选》） 2. 治冠心病心绞痛①白果叶、瓜蒌、丹参各15g 薤白12g 郁金9g 生甘草5g．煎服．（《安徽中草药》）②银杏叶、首乌、钩藤各4.5g 制成片剂 一日量 吞服；或银杏叶水煎浓缩成浸膏片（每片含黄酮量约2mg 相当于生药0.5g） 每次舌下含服1-2片 每日3次． 3. 治血清胆固醇过高症银杏叶提取主要成分黄酮 制成糖衣片 每片含黄酮1.14mg 每次4片 每日3次．（2-3方出自《全国中草药汇编》） 4. 治泻痢（银杏）叶 为末 和面作饼 煨熟食之．（《品汇精要》） 5. 治小儿肠炎银杏叶3-9g．煎水擦洗患儿脚心、手心、心口（巨阙穴周围）严重者擦洗头顶 每日2次．（《全国中草药汇编》） 6. 治雀斑采白果叶 捣烂 搽 甚妙．（《滇南本草》）', usage='', tips='有实邪者忌用。吃多了会中毒，引发肌肉抽搐，瞳孔放大。孕妇与儿童更要谨慎。 有实邪者忌用。吃多了会中毒，引发肌肉抽搐，瞳孔放大。孕妇与儿童更要谨慎。' where id=2136; -- 银杏叶
update herbs set taste='味甘；性平。', channel='入肺、胃、肾经。', effect='①治老年痰喘：秋白梨一个，去心，入燕窝一钱，先用开水泡，再入冰糖一钱蒸熟。每日早晨服下，勿间断。（《文堂集验方》） ②治噤口痢：白燕窝二钱，人参四分。水七分，隔汤顿熟，徐徐食之。（《救生苦海》） ③治翻胃久吐：服人乳，多吃燕窝。（《纲目拾遗》） ④治老年疟疾及久疟，小儿虚疟，胎热：燕窝三钱，冰糖半钱。顿食数次。（《内经类编试效方》）' where id=2137; -- 燕窝
update herbs set taste='甘，平。', channel='入肺、胃经。', effect='①治发热口干，小便涩：萎蕤五两。煮汁饮之。（《外台》） ②治秋燥伤胃阴：玉竹三钱，麦冬三钱，沙参二钱，生甘草一钱。水五杯，煮取二杯，分二次服。（《温病条辨》玉竹麦门冬汤） ③治阳明温病，下后汗出，当复其阴：沙参三钱，麦门冬五钱，冰糖一钱，细生地五钱，玉竹一钱五分（炒香）。水五杯，煮取二杯，分二次服，渣再煮一杯服。（《温病条辨》益胃汤） ④治阴虚体感冒风温，及冬温咳嗽，咽干痰结：生萎蕤二至三钱，生葱白二至三枚，桔梗一钱至钱半，东白禳五分至一钱，淡豆豉三至四钱，苏薄荷一钱至钱半，炙草五分，红枣两枚。煎服。（《通俗伤寒论》加减萎蕤汤） ⑤治卒小便淋涩痛：芭蕉根四两（切），萎蕤一两（锉）。上药，以水二大盏，煎至一盏三分，去滓，入滑石末三钱，搅令匀。食前分为三服，服之。（《圣惠方》） ⑥治男妇虚症，肢体酸软，自汗，盗汗：葳参五钱，丹参二钱五分。不用引，水煎服。（《滇南本草》） ⑦治赤眼涩痛：萎蕤、赤芍药、当归、黄连等分。煎汤熏洗。（《卫生家宝方》） ⑧治眼见黑花，赤痛昏暗：萎蕤（焙）四两。为粗末，每服一钱匕，水一盏，入薄荷二叶，生姜一片，蜜少许，同煎至七分，去滓，食后临卧服。（《圣济总录》甘露汤） ⑨治虚咳：玉竹五钱至一两。与猪肉同煮服。（《湖南药物志》） ⑩玉竹30克，芭蕉120克，水煎取汁，冲入滑石粉10克，分作三次于饭前服，可治小便不畅，小便疼痛。 ⑾玉竹、党参、丹参各15克，川芎10克，水煎服，每日一剂，治心悸，口干，气短，胸痛或心绞痛。 ⑿玉竹、北沙参各15克，麦冬、北五味子各10克，川贝5克，水煎服，每日一剂，可治久咳，痰少，咽干，乏力等症。 ⒀玉竹、北沙参、石斛、麦冬各15克，乌梅五枚，水煎取汁，加冰糖适量代茶饮用，可治热病伤阴，或夏天出汗多引起的口干思饮，大便干燥。 ⒁玉竹20～50克，猪瘦肉250克，同煮汤服食，可治久咳痰少，气虚乏力等症。 ⒂玉竹、首乌、黄精、桑椹子各10克，水煎服，可治贫血萎黄，气阴两伤，病后体弱等症。' where id=2138; -- 玉竹
update herbs set effect='治疗肠炎腹泻及细菌性痢疾，可单用本品一两，煎服；也可配合老鹳草一两同用。在治疗夜盲症时，可用鲜草一两至二两，加鸭肝二、三个同炖汤，熟后，吃鸭肝及汤。', tips='清热利尿，明目，消积。用于肾炎水肿，泌尿系感染、结石，肠炎，痢疾，小二疳积，眼角膜炎，黄疸型肝炎；外用治青竹蛇咬伤。' where id=2139; -- 叶下珠
update herbs set taste='辛，温，有毒。', effect='1.治哮喘：曼陀罗花两五，火硝一钱，川贝一两，法夏八钱，泽兰六钱，冬花五钱。上共研细末，用老姜一斤，捣烂取汁，将药末合匀，以有盖茶盅-只盛贮封固，隔水蒸一小时久，取出，以熟烟丝十两和匀，放通风处，吹至七、八成干（不可过于干燥，恐其易碎）时，贮于香烟罐中备用。每日以旱烟筒或水烟袋，如寻常吸烟法吸之。（《外科十三方考》立止哮喘烟） 2.治小儿慢惊：曼陀罗花七朵（重一字），天麻二钱半，全蝎（炒）十枚，天南星（炮），丹砂、乳香各二钱半。为末。每服半钱，薄荷汤调下。（《御药院方》） 3.治阳厥气逆多怒而狂：朱砂（水飞）半两，曼陀罗花二钱半。上为细末。每服二钱，温酒调下，若醉便卧，勿令惊觉。（《证治准绳》祛风一醉散） 4.治（病）人难忍艾火灸痛，服此即昏睡不痛，亦不伤人：山茄花（八月收）、火麻花（八月收一说七月收）。阴干，共研末。每服三钱，小儿只一钱，茶酒任下。一服后即昏睡，可灸五十壮，醒后再服再灸。（《扁鹊心书》睡圣散） 5.治诸风痛及寒湿脚气：曼陀罗花，茄梗、大蒜梗、花椒叶。煎水洗。（《四川中药志》） 6.治面上生疮：曼陀罗花，晒干研末，少许贴之。（《卫生易简方》） 7.用于麻醉 相传我国名医华佗早在公元200余年，就曾应用麻沸散作为麻醉剂为病人施行刮骨、剖腹手术。近年来，继针刺麻醉之后，又进一步采用了以洋金花为主的中药麻醉，获得初步成功。基本处方为：洋金花，生草乌、川芎、当归。给药途径：目前计采用口服、灌肠、肌肉注射、静脉点滴、穴位注射（耳穴、鼻穴）及耳根非穴位麻醉等6个途径给药，麻醉效果相似。据临床应用425人次的介绍，其中有高年老人及乳婴；有肝硬变、高血压病患者、休克病人、恶液质患者等，共施行大小手术81种，手术时间最长者达9小时以上，洋金花生药用量。1次高达20克，术后一般恢复良好。上述病例采用中麻手术无1例失败，麻醉效果满意者（指麻醉平稳，病人安静，能顺利完成手术，或手术刺激反应较明显，但不需改用其他麻醉，仍能完成手术操作者）占90％左右。 禁忌症：㈠青光眼或有眼压增高者；㈡心动过速或有心动过速病史者以及心肺功能明显代偿不全者；㈢高热病人；㈣严重高血压患者；㈤肝肾功能严重损害者。 存在问题：㈠麻醉深度不够：临床观察及脑电图表明，过去大部分中药麻醉病人的麻醉深度，相当于乙醚麻醉的Ⅲ期一级。因此，对上腹部手术，部分病人肌肉松弛不够满意，内脏牵拉反应明显，使手术操作有一定困难，如在术前或术中配合使用八角枫、锡生藤及汉防己等，或封闭两侧足三里穴等方法，可有助于腹肌松弛。㈡苏醒时间长：采用口服或灌汤法，苏醒时间多在10～12小时；注射给药，苏醒时间约为6～8小时。有报告在手术将结束时，肌肉注射槟榔注射液1～2毫升，同时静脉注射美解眠40毫升，能使苏醒提前3小时左右。对采取口服给药的病例，亦可在手术结束前从胃管抽去剩余药液，并注入甘草绿豆汤，亦能提早清醒。㈢窦性心动过速：可用1％普鲁卡因静滴代替冬眠药物，既能提早苏醒时间，又能控制心率。 8.治疗慢性气管炎 用洋金花注射液每5天肌注1次，一般注射4～5次，每次注射液中含东莨菪碱0.5～1.0毫克，根据病人年龄、性别、体质强弱等具体情况，用量略有不同。一般于注射后10～15分钟出现反应迟钝；15～20分钟进入浅睡，40～60分钟进入深睡；3～4小时后苏醒，醒后呼吸通顺，略有倦意。共治疗慢性气管炎1200例，临床控制率为70％，显效率为17％，用药后作心、肝、肾功能测定，未见有损害。此外，有用曼陀罗组成复方气管炎片、气管炎注射液作穴位（肺俞、定喘穴）交叉注射，10次为一疗程，验证640例，其中临床近控率36％，显效率23％或用曼陀罗叶100克（鲜叶用600克），甘草50克，制成25％曼陀罗合剂内服，每次4～5毫升，10天一疗程，共治44例，均取得较好疗效。 9.治疗精神分裂症 将曼陀罗花用白酒浸成10％酊剂，或制成20％煎剂。每日早餐后服1次，连服6天，停服1天。用量由10毫升开始，根据反应程度，逐渐增加至40～80毫升，以用药后1小时左右出现迷睡，并维持2～3小时为适宜。服药后有胃部不适及食欲减退的副作用，可在每次服药当天上下午给胃蛋白酶或稀盐酸，并采用0.5％毛果芸香碱眼膏以减轻瞳孔散大及视力模糊。接受此种治疗后，患者的临床表现一般可分三个阶段：第一阶段，服药15分钟左右开始出现轻度不安，口干。瞳孔散大，视物不清。并可出现幻视，意识蒙胧，定向障碍，步态不稳。部分患者有尿意频繁，少数有躁动恐怖情绪。这一阶段约持续1/2～2小时。第二阶段，主要为迷睡状态，可出现肌张力增强或减退，口涎增加，呼吸深缓，这一阶段约2～10小时不等。第三阶段为醒转期，醒后自感头脑清醒，除胸闷、不思饮食、口干外，前述的临床表现均消失。根据对62例精神分裂症患者的观察，单独使用曼陀罗的疗效似不高，但对精神运动性兴奋有良好的宁静作用。 10.中毒可出现口干，皮肤干燥，瞳孔散大，脉快，颜面潮红，甚则使血压下降而致死。解救可服吐剂，洗胃并服鞣酸制剂，后给以盐类泻剂，强心剂，镇静剂。亦有用绿豆皮4两，金银花2两，连翘1两，甘草5钱。水1000毫升，煎至200毫升，1次服，每2小时服1次。' where id=2140; -- 洋金花
update herbs set effect='1.煎剂：牛藤全草1两，加水煎成30ml，痛时顿服，必要时日服3次。观察手术后疼痛、麻风反应性疼痛等各种痛症共113例，一般服药后15分钟开始止痛，药效可持续4小时。 2.丸剂：每丸相当生药1两。日服2-3次，每次1-2丸。治疗外伤疼痛、内脏疼痛。手术后疼痛、神经痛、头痛等40余例，均收镇静止痛效果，其中显效者占73%。 3.片剂：每片相当生药2.5g，痛时顿服4-6片。用于各种手术后疼痛40余例，一般服药后30分钟左右开始止痛，药效持续3小时。 4.注射剂：每次肌肉注射2ml（相当于生药5g）。止痛生效和持续时间与煎剂基本相同。另有报道，用七叶莲制成注射液，每次2ml（相当于干叶3g）肌肉注射，亦有止痛效果。据12例观察，一般注射后5-15分钟见效，持续止痛效果4-10小时。', tips='祛风和络；活血止痛；利尿消肿。主风湿痹痛；胃、肠道及胆道疾患之疼痛；三叉神经痛；跌打损伤；痛经；小便不利；水肿。 ①《国药的药理学》：为强心、利尿药。 ②《广西植物名录》：藤，止痛；藤及根，利尿。' where id=2141; -- 野木瓜
update herbs set alias='葽绕、蕀蒬，棘菀，苦远志。', taste='辛；苦；性微温。', channel='入心、肾经。', effect='①心气不足，五脏不足，甚者忧愁悲伤不乐，忽忽喜忘，朝瘥暮剧，暮瘥朝发，发则狂眩：菖蒲、远志（去心）、茯苓各二分，人参三两。上四味，捣下筛，服方寸匕，后食，日三，蜜和丸如梧桐子，服六、七丸，日五，亦得。（《古今录验》定志小丸） ②治神经衰弱，健忘心悸，多梦失眠：远志（研粉），每服一钱，每日二次，米汤冲服。（《陕西中草药》） ③治久心痛：远志（去心）、菖蒲（细切）各一两。上二味，粗捣筛，每服三钱匕，水一盏，煎至七分，去滓，不拘时温服。（《圣济总录》远志汤） ④治痈疽、发背、疖毒，恶候浸大，不问虚实寒热：远志（汤洗去泥，捶去心）为末，酒一盏，调末三钱，迟顷，澄清饮之，以滓敷病处。（《三因方》远志酒） ⑤治喉痹作痛：远志肉为末，吹之，涎出为度。（《仁斋直指方》） ⑥治脑风头痛不可忍：远志（去心），捣罗为细散，每用半字，先含水满口，即搐药入鼻中，仍揉痛处。（《圣济总录》远志散） ⑦治气郁成鼓账，诸药不效者：远志肉四两（麸拌炒）。每日取五钱，加生姜三片煎服。（《本草汇言》） ⑧治小便赤浊：远志半斤（甘草水煮，去心），茯神（去木），益智仁各二两。上为细末，酒煮面糊为丸，如梧子大。每服五十丸，临卧枣汤送下。（《朱氏集验医方》远志丸） ⑨治吹乳：远志酒煎服，滓敷患处。（《袖珍方》） ⑩善忘症。取远志为末，冲服。 ⑾胸痹心痛（逆气膈中，饮食不下）。用远志、桂心、干姜、细辛、蜀椒（炒）各三两，附子二分（炮），一起捣细，加蜜和成丸子，如梧子大。每服三丸，米汁送下。一天服三次。如不见效，可稍增加药量。忌食猪肉、冷水、生葱菜。此方名小草丸。 ⑿喉痹作痛。用远志肉为末，吹扑痛处，以涎出为度。 ⒀脑风头痛。把远志末吸入鼻中。 ⒁吹乳肿痛。用远志焙干研细，酒冲服二钱。药渣敷患处。 ⒂各种痈疽。用远志放入淘米水中浸洗过，捶去心，研细。每服三钱，以温酒一杯调澄。清汁饮下，药渣敷患处。 ⒃小便赤浊。用远志（甘草水煮过）半斤，茯神、益智仁各二两，共研为末，加酒、糊做成丸子，如梧子大。每服五十丸，空心服，枣汤送下。' where id=2142; -- 远志
update herbs set taste='味辛；苦；性寒。', channel='入心、肺、肝经。', effect='①治心悬急懊痛：郁金半两，黄芩一两，赤芍药一两，枳壳一两（麸炒微黄，去瓤），生干地黄一两，大腹皮一两（锉）。上药，细锉和匀。每服一分，以水一中盏，入生姜半分，煎至六分，去滓，不计时候，稍熬服。（《圣惠方》郁金饮子） ②治一切厥心（痛）、小肠膀胱痛不可忍者：附子（炮）、郁金、干姜。上各等分为细末，醋煮糊为丸，如梧桐子大，朱砂为衣。每服三十丸，男子温洒下，妇人醋汤下，食远服。（《奇效良方》辰砂一粒金丹） ③治妇人胁肋胀满，因气逆者：郁金、木香、莪术、牡丹皮。白汤磨服。（《女科方要》） ④治产后心痛，血气上冲欲死：郁金烧存性为末二钱，米醋一呷，调灌。（《袖珍方》） ⑤治癫狂因忧郁而得，痰涎阻塞包络心窍者：白矾三两，郁金七两。米糊为丸，梧子大。每服五十丸，水送下。（《本事方》白金丸） ⑥治痫疾：川芎二两，防风、郁金、猪牙皂角、明矾各一两，蜈蚣二条（黄、赤脚各一）。上为末，蒸饼丸，如桐子大。空心茶清下十五丸。（《摄生众妙方》郁金丹） ⑦治风痰：郁金一分，藜芦十分。各为末，和令匀。每服一字，用温浆水一盏，先以少浆水调下，馀者水漱口都服，便以食压之。（《经验后方》） ⑧治衄血吐血：郁金为末，水服二钱，甚者再服。（《简易方论》） ⑨治呕血：用韭汁、姜汁、童便磨郁金，同饮之。（《丹溪心法》） ⑩治尿血不定：郁金一两，捣为末，葱白一握相和，以水一盏，煎至三合，去滓，温服，日须三服。（《经验方》） ⑾治血淋，心头烦，水道中涩痛，及治小肠积热，尿血出者：生干地黄、郁金、蒲黄。上等分，为细末。每于食前，煎车前子叶汤调下一钱，酒调下亦得。（《普济方》郁金散） ⑿治阳毒入胃下血，频疼痛不可忍：郁金五个大者，牛黄一皂荚子（别研细）。二味同为散。每服用醋浆水一盏，同煎三沸，温服。（孙用和） ⒀治谷疽，唇口先黄，腹胀气急：郁金一两，牛胆一枚（干者），麝香（研）半钱.上三味，捣研为细散。每服半钱匕，新汲水调下，不拘时。（《圣济总录》郁金散） ⒁治胆石及黄疸：郁金、熊胆、明矾、火硝。研细为丸或作散剂。每服一至三分。（《四川中药志》） ⒂治肠梗阻：郁金、桃仁、瓜蒌各三钱。水煎后加麻油五两，一次温服。（内蒙古《中草药新医疗法资料选编》） ⒃治耳内极痛：郁金末，研细，每用一字，以净水调，倾入耳内，却急倾出。（《圣济总录》） ⒄治自汗不止：郁金末，卧时调涂于乳上。（《濒湖集简方》） ⒅治痔疮肿痛：郁金末，水调涂之。（《医方摘要》）' where id=2143; -- 郁金
update herbs set taste='味辛；甘；性温。', channel='入肝、肾经。', effect='①治偏风，手足不遂，皮肤不仁：仙灵脾一斤，细锉，以生绢袋盛，于不津器中，用无灰酒二斗浸之，以厚纸重重密封，不得通气，春夏三日，秋冬五日。每日随性暖饮之，常令醺醺，不得大醉。（《圣惠方》） ②治风走注疼痛，来往不定：仙灵牌一两，威灵仙一两，芎藭一两，桂心一两，苍耳子一两。上药，捣细罗为散。每服，不计时候，以温酒调下一钱。（《圣惠方》仙灵脾散） ③治目昏生翳：仙灵脾、生王瓜（即小栝楼红色者）等分。为末，每服一钱，茶下，日二服。（《圣济总录》） ④治牙疼：仙灵脾，不拘多少，为粗末，煎汤漱牙齿。（《奇效良方》固牙散） ⑤治肾经虚损，腰腿遍身疼痛。淫羊藿（酒浸）、杜仲（酒炒）、炒小茴香、大茴香各150g，远志（去心）120g，巴戟天、肉苁蓉（酒浸）各180g，青盐240g。上为末，每服6g。方中淫羊藿配伍巴戟天治阳萎，腰膝冷痛及妇女宫冷不孕。（《寿世保元》壮肾散） ⑥治妇人中风偏枯，手足一边不遂，肌骨瘦细，皮肤顽痹。淫羊藿30g，羚羊角1g，独活、防风（去芦头）、桂心、当归、牛膝（去苗）、薏苡仁、附子各30g，五加皮1g，萆薢、虎胫骨各30g。上为细末，炼蜜和捣，每服12g，食前温酒下。方中淫羊藿温肾助阳，祛风除湿。（《太平圣惠方》仙灵脾丸）', tips='阴虚而相火易动者忌服。阴虚火旺阳强易举者禁服。 ②《日华子本草》：紫芝为使。得酒良。 ③《本草经疏》：虚阳易举，梦遗不止，便赤口干，强阳不痿并忌之。' where id=2144; -- 淫羊藿
update herbs set taste='辛；苦甘；平；无毒。', channel='入脾、大小肠经。' where id=2145; -- 郁李仁
update herbs set taste='甘；淡；微寒。', channel='入脾、肺、肾经。', effect='①治病者一身尽疼，发热，日晡所剧者，名风湿，此病伤于汗出当风，或久伤取冷所致：麻黄（去节）半两（汤泡），甘草一两（炙），薏苡仁半两，杏仁十个（去皮、尖，炒）。上锉麻豆大，每服四钱，水一盏半，煮八分，去滓温服，有微汗避风。（《金匮要略》麻黄杏仁薏苡甘草汤） ②治风湿痹气，肢体痿痹，腰脊酸疼：薏苡仁一斤，真桑寄生、当归身、川续断、苍水（米泔水浸炒）各四两。分作十六剂，水煎服。（《广济方》） ③治久风湿痹，补正气，利肠胃，消水肿，除胸中邪气，治筋脉拘挛：薏苡仁为末，同粳米煮粥，日日食之。（《纲目》薏苡仁粥） ④去风湿，强筋骨，健脾胃：薏苡仁粉，同曲米酿酒，或袋盛煮酒饮之。（《纲目》薏苡仁酒） ⑤治水肿喘急：郁李仁二两。研，以水滤汁，煮薏苡仁饭，日二食之。（《独行方》） ⑥治肺痿唾脓血：薏苡仁十两。杵碎，以水三升，煎一升，入酒少许服之。（《梅师集验方》） ⑦治肺痈咳唾，心胸甲错者：以淳苦酒煮薏苡仁令浓，微温顿服之。肺若有血，当吐出愈。（《范汪方》） ⑧治肺痈咯血：薏苡仁三台。捣烂，水二大盏，入酒少许，分二服。（《济生方》） ⑨治肠痈，其身甲错，腹皮急，按之濡如肿状，腹无积聚，身无热，脉数，此为肠内有痈脓：薏苡仁十分，附子二分，败酱五分。上三味，杵为末，取方寸匕，以水二升，煎减半，顿服，小便当下。（《金匮要略》薏苡附子败酱散） ⑩治肠痈：薏苡仁一升，牡丹皮、桃仁各三两，瓜瓣人二升。上四味，以水六升，煮取二升，分再服。（《千金方》） ⑾治消渴饮水：薏苡仁煮粥饮，并煮粥食之。（《纲目》） ⑿治沙石热淋，痛不可忍：玉秫（子、叶、根皆可用），水煎热饮，夏月冷饮，以通为度。（《杨氏经验方》）' where id=2146; -- 薏苡仁
update herbs set taste='味甘；淡；性平。', effect='①治水肿：玉蜀黍须二两。煎水服，忌食盐。（《贵阳市秘方验方》） ②治肾脏炎，初期肾结石：玉蜀黍须，分量不拘，煎浓汤，频服。（《贵阳市秘方验方》） ③治肝炎黄疸：玉米须、金钱草、满天星、郁金、茵陈，煎服。 ④治劳伤吐血：玉米须。小蓟，炖五花肉服。 ⑤治吐血及红崩：玉米须，熬水炖肉服。 ⑥治风疹块（俗称风丹）和热毒：玉米须烧灰，兑醪糟服。（③方以下出《四川中药志》） ⑦治糖尿病：玉蜀黍须一两。煎服。（《浙江民间草药》） ⑧治原发性高血压病：玉米须、西瓜皮、香蕉。煎服。（《四川中药志》） ⑨治脑漏：玉蜀黍须晒干，装旱烟筒上吸之。（《浙江民间草药》）' where id=2147; -- 玉米须
update herbs set taste='辛，寒。', channel='肝；肺经。', effect='①治肺痈吐脓吐血：鱼腥草、天花粉、侧柏叶等分。煎汤服之。（《滇南本草》） ②治肺痈：蕺，捣汁，入年久芥菜卤饮之。（《本草经疏》） ③治病毒性肺炎，支气管炎，感冒：鱼腥草、厚朴、连翘各三钱。研末，桑枝一两，煎水冲服药末。（《江西草药》） ④治肺病咳嗽盗汗：侧耳根叶二两，猪肚子一个。将侧耳根叶置肚子内炖汤服。每日一剂，连用三剂。（《贵州民间方药集》） ⑤治痢疾：鱼腥草六钱，山查炭二钱。水煎加蜜糖服。（《岭南草药志》） ⑥治热淋、白浊、白带：鱼腥草八钱至一两。水煎服。（《江西民间草药》） ⑦治痔疮：鱼腥草，煎汤点水酒服，连进三服。其渣熏洗，有脓者溃，无脓者自消。（《滇南本草》） ⑧治慢性鼻窦炎：鲜蕺菜捣烂，绞取自然汁，每日滴鼻数次。另用蕺菜七钱，水煎服。（《陕西草药》） ⑨治痈疽种毒：鱼腥草晒干，研成细末，蜂蜜调敷。未成脓者能内消，已成脓者能排脓（阴疽忌用）。（《江西民间草药》） ⑩治疔疮作痛：鱼腥草捣烂敷之，痛一、二时，不可去草，痛后一、二日愈。（《积德堂经验方》） ⑾治妇女外阴瘙痒，肛痈：鱼腥草适量，煎汤熏洗。（《上海常用中草药》） ⑿治恶蛇虫伤：鱼腥草、皱面草、槐树叶、草决明。一处杵烂敷之。（《救急易方》）' where id=2148; -- 鱼腥草
update herbs set taste='味辛；苦；性微进', channel='归肝；肾；心包经', effect='①治瘀血块结：益母草一两，水，酒各半煎服。（方以下出《闽东本草》） ②治难产：益母草捣汁七大合，煎减半，顿服，无新者，以干者一大握，水七合煎服。（《独行方》） ③治胎死腹中：益母草捣熟，以暖水少许和，铰取汁，顿服之。（《独行方》） ④治产后血运，心气绝：益母草，研，绞汁，服一盏。（《子母秘录》） ⑤治产后恶露不下：益母草，捣，绞取汁，每服一小盏，入酒一合，暖过搅匀服之。（《圣惠方》） ⑥妇人分娩后服之，助子宫之整复：益母草九钱，当归三钱。水煎，去渣，一日三回分服。（《现代实用中药》） ⑦治尿血：益母草汁（服）一升。（《外台秘要方》） ⑧治肾炎水肿：益母草一两。水煎服。（《福建省中草药新医疗法资料选编》） ⑨治小儿疳痢，痔疾：益母草叶煮粥食之，取汁饮之亦妙。（《食医心镜》） ⑩治折伤内损有痪血，每天阴则疼痛，兼疗产妇产后诸疾：三月采益母草一重担，以新水净洗，晒令水尽，用手捩断，可长五寸，勿用刀切，即置镬中，量水两石，令水高草三、二寸，纵火煎，候益母草糜烂，水三分减二，漉去草，以绵滤取清汁，于小釜中慢火煎，取一斗如稀饧。每取梨许大，暖酒和服之，日再服，和羹粥吃并得。如远行不能，将稀煎去，即更炼令稠硬，停作小丸服之。或有产妇恶露不尽及血运，一两服即瘥。其药辣疗风益力。无所忌。（《近效方》） ⑾治疔肿至甚：益母草茎叶，烂捣敷疮上，又绞取汁五合服之，即内消。（《圣惠方》） ⑿治妇人勒乳后疼闷，乳结成痈：益母草，捣细末，以新汲水调涂于奶上，以物抹之，生者捣烂用之。（《圣惠方》） ⒀治疖子已破：益母捣敷疮。（《斗门方》） ⒁治喉闭肿痛：益母草捣烂，新汲水一碗，绞浓汁顿饮；随吐愈，冬月用根。（《卫生易简方》） ⒂治马咬：益母草细切，和醋炒，封之。（孙思邈）' where id=2149; -- 益母草
update herbs set taste='甘；温；无毒。', channel='肝；肾经。', effect='①治月经不调：鲜月季花每次五至七钱，开水泡服，连服数次。（《泉州本草》） ②治肺虚咳嗽咯血：月季花合冰糖炖服。（《泉州本草》） ③治筋骨疼痛，脚膝肿痛，跌打损伤：月季花瓣干研末，每服一钱，酒冲服。（《湖南药物志，） ④治产后阴挺：月季花一两炖红酒服。（《闽东本草》）' where id=2150; -- 月季花
update herbs set taste='甘，温。', channel='入肺，脾、膀胱经。', effect='①治风癫：云母，服三方寸匕，取瘥。（《千金翼方》） ②治痰饮头痛，往来寒热：云母粉二两，常山一两。上二味捣筛为散。热汤服一方寸匕，吐之止；吐不尽，更服。（《千金翼方》） ③治疟多寒：蜀漆（洗去腥），云母（烧二日夜）、龙骨等分。上三味，杵为散，未发前以浆水服半钱。（《金匮要略》蜀漆散） ④治小儿赤白痢及水痢：云母粉半大两，研作粉煮白粥调，空腹食之。（《食医心镜》） ⑤治带下：云母粉服三方寸匕，三五服。（《千金翼方》） ⑥治妇人难产，经日不生：云母粉半两，温酒调服。（《积德堂经验方》） ⑦治金疮、一切恶疮：云母粉涂之。（《千金翼方》） ⑧治痔病：云母服三力寸匕.慎房室、血食油腻。（《千金翼方》）', tips='畏鮀甲及流水。 ②《药性论》：恶徐长卿。忌羊血。 ③《本经逢原》：阴虚火炎者，慎勿误与。' where id=2151; -- 云母
update herbs set taste='甘；淡；平；无毒', effect='润肺，止咳，滋补：白木耳二钱，竹参二钱，淫羊藿一钱。先将白木耳及竹参用冷水发胀，次取出，加水一小碗及冰糖、猪油适量调和，最后取淫羊藿稍加碎截，置碗中共蒸，服时去淫羊藿渣，参、耳连汤内服。（《贵州民间方药集》）' where id=2152; -- 银耳
update herbs set effect='1．治各种疔毒，痈疮疔肿，局部红肿热痛，或发热，舌红脉数者：金银花9g，野菊花、蒲公英、紫花地丁、紫背天葵子各3.6g。先水煎，后加五灰酒半盏；药渣再加如法煎服，盖被取汗。方中紫花地丁清热解毒，为臣药。（五味消毒饮《医宗金鉴-外科心法要诀》） 2．治喉痹：箭头草叶，研，入酱少许，笔蘸入喉中，吐。方中紫花地丁清热解毒，为君药。（《普济方》） 3．治如炊饼一切毒：黄花地丁（即蒲公英）、紫花地丁各240g。以长流水洗净，用水煎汁去渣，又成膏摊贴。方中紫花地丁清热解毒，为君药。（地丁膏《惠直堂经验方》）', tips='清热解毒；凉血消肿。主用于疔疮肿毒；痈疽发背；丹毒；毒蛇咬伤。用于疔疮肿毒，痈疽发背，丹毒，毒蛇咬伤。' where id=2153; -- 紫花地丁
update herbs set taste='味苦；辛；性温。', channel='归肺经。', effect='①治久咳不瘥：紫菀（去芦头）、款冬花各一两，百部半两。三物捣罗为散，每服三钱匕，生姜三片，乌梅一个，同煎汤调下，食后、欲卧各一服。（《本草图经》） ②治伤寒后肺痿劳嗽，唾脓血腥臭，连连不止，渐将羸瘦：紫菀一两，桔梗一两半（去芦头），天门冬一两（去心），贝母一两（煨令微黄），百合三分，知母三分，生干地黄一两半。上药捣筛为散，每服四钱，以水一中盏，煎至六分，去滓，温服。（《圣惠方》紫菀散） ③治小儿咳逆上气，喉中有声，不通利：紫菀一两，杏仁（去皮尖）、细辛、款冬花各一分。上四味，捣罗为散，二三岁儿，每服半钱匕，米饮调下，日三，更量大小加减。（《圣济总录》紫菀散） ④治妊娠咳嗽不止，胎动不安：紫菀一两，桔梗半两，甘草、杏仁、桑白皮各二钱半，天门冬一两。上细切，每服三钱。竹茹一块，水煎，去滓，入蜜半匙，再煎二沸，温服。（《伤寒保命集》紫菀汤） ⑤治吐血、咯血、嗽血：真紫菀、茜根等分。为细末，炼蜜为丸，如樱桃子大，含化一丸，不以时。（《鸡峰普济方》紫菀丸） ⑥治妇人卒不得小便：紫菀末，井华水服三指撮。（《千金方》） ⑦肺伤咳嗽：用紫菀花五钱，加水一碗，煎至七成，温服。一天服三次。 ⑧吐血咳嗽：用紫苑、五味子炒过，共研为末，加蜜做成丸子，如芡子大。每次含化一丸。 ⑨产后下血：用紫菀末五撮，水冲服。 ⑩缠喉风痹：用紫菀根一条，洗净，放入喉部，有涎出，病即渐愈。' where id=2154; -- 紫菀
update herbs set taste='甘，温。', channel='入心、肝经。', effect='①治怔忡惊悸，魂魄不宁，或心虚不寐，精神烦乱：紫石英一两（火煅醋淬七次，研细末，水飞过），当归、远志、枣仁、川贝母、茯苓、柏子仁各二两，川黄连三钱（俱用盐水拌炒）。研为末，炼蜜丸。每早晨服三钱，临睡服四钱，俱用黑枣汤下。（《郑子来家秘》） ②治妇人胎胞虚冷，久不受孕，或受孕多小产者：紫石英二两（火煅醋淬七次，研细末，水飞过），香附（醋炒）、当归、川芎（俱酒炒）、白术（土拌炒）各三两，枸杞子（酒洗，炒）、熟地黄（酒煮，捣膏）。炼蜜丸梧子大。每早晚各服三钱，好酒送下。（《青囊秘方》） ③治肺寒咳逆上气：紫石英火煅醋淬七次，研细末，水飞过。每早用五分，花椒十粒，泡汤下。（《青囊秘方》） ④除热瘫痫：紫石英、寒水石、石膏、滑石、白石脂、赤石脂各六两，大黄、干姜、龙骨各四两，桂枝三两，甘草、牡蛎各二两。上十二味，粗筛，以韦囊盛之，取三指撮，井花水三升，煮三沸，温服一升。（《金匮要略》风引汤） ⑤治虚劳惊悸，补虚止惊，令人能食：紫石英五两。打如豆大，水淘一遍，以水一斗，煮取三升，细细服，或煮粥食，水尽可再煮之。（张文仲） ⑥治痈肿毒等：紫石英醋淬，捣为末，生姜、米醋煎敷之，摩亦得。（《日华子本草》）' where id=2155; -- 紫石英
update herbs set taste='苦辛，寒，有毒。', channel='入心、肝经。', effect='①治风毒暴肿：重台草、木鳖子（去壳）、半夏各一两。上药捣细罗为散，以酽醋调涂之；凡是热肿，熁之。（《圣惠方》重台草散） ②治妇人奶结，乳汁不通，或小儿吹乳：重楼三钱。水煎，点水酒服。（《滇南本草》） ③治耳内生疮热痛：蚤休适量。醋磨涂患处。（《广西民间常用草药》） ④治喉痹：七叶一枝花根茎二分。研粉吞服。（《浙江民间草药》） ⑤治小儿胎风，手足搐搦：蚤休为末。每服半钱，冷水下。（《卫生易简方》） ⑥治慢惊：栝蒌根二钱，白甘遂一钱。上用慢火炒焦黄色，研匀。每服一字，煎麝香，薄荷汤调下，无时。（《小儿药证直诀》栝蒌汤） ⑦治肺痨久咳及哮喘：蚤休五钱。加水适量，同鸡肉或猪肺煲服。（《广西民间常用草药》） ⑧治新旧跌打内伤，止痛散瘀：七叶一枝花，童便浸四、五十天，洗净晒干研末。每服三分，酒或开水送下。（《广西药植图志》） ⑨治脱肛：蚤休，用醋磨汁。外涂患部后，用纱布压送复位，每日可涂二至三次。（《广西民间常用草药》） ⑩治蛇咬伤：七叶一枝花根二钱，研末开水送服，每日二至三次；另以七叶一枝花鲜根捣烂，或加甜酒酿捣烂敷患处。（《浙江民间常用草药》） ⑾治中鼠莽毒.金线重楼根。磨水服。（《濒湖集简方》） ⑿治风毒暴肿：重台草、木鳖子（去壳）半夏各30g。上药捣细罗为散，以酽醋调涂之；凡是热肿，敷之。方中蚤休清热解毒，消肿止痛，为君药。（《太平圣惠方》重台草散） ⒀治痈肿疮毒，疔毒内攻：黄连，金银花、甘草、赤芍、蚤休。方中蚤休清热解毒，消肿止痛，为君药。（《外科全生集》夺命丹） ⒁治慢惊：瓜蒌根6g，白甘遂3g。上用慢火炒焦黄色，研匀。每服1字，煎麝香、薄荷汤调下，无时。方中蚤休息风定惊，为臣药。（《小儿药证直诀》瓜蒌汤）' where id=2156; -- 蚤休
update herbs set alias='提母，芪母，蚔母、连母、野蓼、地参、水参、水浚、货母、蝭母，女雷、女理、儿草、鹿列、韭逢、儿踵草、东根、水须、苦心，昌支（（唐本草》），穿地龙。', taste='味苦；性寒。', channel='入肺、胃、肾经。', effect='①治伤寒邪热内盛，齿牙干燥，烦渴引饮，目昧唇焦：知母五钱，石膏三钱，麦门冬二钱，甘草一钱，人参八钱。水煎服。（《伤寒蕴要》） ②治温疟壮热，不能食：知母、鳖甲（炙），地骨皮各三两，常山二两，竹叶（切）一升，石膏四两（碎）。上六味切，以水七升，煮取二升五合，去滓，分三服。忌蒜、猪肉、苋菜、生葱、生菜。（《延年方》知母鳖甲汤） ③治火冲眩晕，暴发倒仆，昏不知人，甚则遗尿不觉，少顷汗出而轻，仍如平人，右关脉细敷，脾阴不足者：知母、黄柏、黄芪、当归身。水煎服。（《症因脉治》知柏补血汤） ④治消渴：生山药一两，生黄芪五钱，知母六钱，生鸡内金（捣细）二钱，葛根钱半，五味子三钱，天花粉三钱。水煎服。（《医学衷中参西录》玉液汤） ⑤治气虚劳伤，面黄肌瘦，气怯神离，动作倦怠，上半日咳嗽烦热，下午身凉气爽，脉数有热者：知母三钱，黄柏三钱，人参二钱，麦冬五钱，广皮一钱，甘草五分。水煎服。（《症因脉治》知柏参冬饮） ⑥治肺劳实热，面目苦肿，咳嗽喘急，烦热颊赤，骨节多痛，乍寒乍热：知母、贝母（去心膜）、杏仁（去皮尖，炒）、甜葶苈（略炒）、半夏（汤泡七次）、秦艽（去芦）、橘红各一两，甘草（炙）半两。上细切，每服四钱，水-盏半，姜五片，煎至八分，去滓温服，不拘时候。（《济生方》二母汤） ⑦治肺家受燥，咳嗽气逆：知母、石膏、桔梗、甘草、地骨皮。水煎服。（《症因脉治》知母甘桔汤） ⑧治妊娠子烦，因服药致胎气不安，烦不得卧者：知母一两，洗焙为末，枣肉丸弹子大。每服一丸，人参汤下。医者不识此病，作虚烦治，反损胎气。（《产乳集验方》） ⑨痰嗽。用知母、贝母各一两，研细：巴豆三十枚，去油，研匀。每夜，切生姜三片，二面蘸上药末，放在口里细嚼咽下，随即睡觉。次日必泻，痰嗽渐止。体弱者，不用巴豆。 ⑩久嗽气急：用知母五钱（去毛切片，隔纸炒过）、杏仁五钱（姜水泡，去皮尖，焙过），同煎服。另以萝卜子、杏仁，等分为末，加米糊做成丸子。每服五十丸，姜汤送下，以绝病根。 ⑾妊娠不足月，腹痛欲产：用知母二两，研细，和蜜做成丸子，如梧子大。每服二十丸，米粥送下。 ⑿紫癜风疾：用醋磨知母涂搽。 ⒀甲疽：用知母，烧存性，研末敷患处。 ⒁治伤寒数日不解，心躁烦乱，小腹胀急，闷痛，大渴喘乏：知母、芍药、麦门冬、柴胡、泽泻各1g，石膏45g，黄芩、甘草15g，竹叶3-7片，姜，水煎，每日1剂，分2次服。（《圣济总录》八味知母汤） ⒂治温疟，壮热不能食：知母、鳖甲、地骨皮各10g，常山6g，竹叶6g，石膏32g。水煎，疟疾发作前服用。（《外台密要》延年知母鳖甲汤） ⒃治产后恶露上攻，流入于肺经咳嗽宜服，如伤风痰喘，却以寻常伤风药治之：知母、贝母、茯苓、人参各15g，桃仁、杏仁各0.3g。水煎，每日1剂，日服2次，如觉腹痛，并服之，立有神效。（《得效方》二母散） 常见配伍 ⒄用于温热病、高热烦燥、口渴、脉洪大等肺胃实热之症及肺热喘咳、痰黄而稠。知母苦寒，上能清肺热，中能清胃火，故适用于肺胃有实热的病症。本品常和石膏同用，可以增强石膏的清热泻火作用。 ⒅用于阴虚发热、虚劳咳嗽及消渴等症。知母能泻肺火而滋肾，故不仅能清实热，且可清虚热。在临床上多与黄柏同用，配入滋阴药中，如知柏地黄丸，治阴虚火旺、潮热骨蒸等症。又本品配养阴润肺药如沙参、麦冬、川贝等品，可用于肺虚燥咳；配清热生津药如天花粉、麦冬、粉葛根等品，可用治消渴。 ⒆知母性味苦寒而不燥，上能清肺，中能凉胃，下能泻肾火。配以黄芩，则泻肺火；配石膏，则清胃热；配黄柏，则泻肾火。知母既能清实热，又可退虚热，但它滋阴生津的功效较弱，用于阴虚内热、肺虚燥咳及消渴等症，须与滋阴药配伍，始能发挥它的作用。本品能润燥滑肠，故脾虚便溏者不宜使用。' where id=2157; -- 知母
update herbs set taste='苦，平。', effect='1．治咯血：干紫珠叶末1.5～2.1g。调鸡蛋清，每4h服1次；继用干紫珠叶末6g，水煎，代茶常饮。（《福建民间草药》） 2．治肺结核咯血，胃十二指肠溃疡出血：紫珠叶、白及各等量。共研细粉。每服6g，每日3次。（《全国中草药汇编》） 3．治胃溃疡出血：紫珠叶120g。水煎服。（《浙江药用植物志》） 4．治衄血：干紫珠叶6g。调鸡蛋清服；外用消毒棉花蘸叶末塞鼻。（《福建民间草药》） 5．治拔牙后出血不止：用消毒棉花蘸紫珠叶末塞之。（《福建民间草药》） 6．治子宫功能性出血：紫珠叶、地菍、梵天花根各30g。水煎，加红糖30g。在出血的第1日服下，连服数日。（《浙江药用植物志》） 7．治血小板减少性紫癜：紫珠叶、猪殃殃、细毛鹿茸草各15g，地菍、栀子根各30g。水煎服。（《浙江药用植物志》） 8．治创伤出血：鲜紫珠叶，用冷开水洗净，捣匀后敷创口；或用干紫珠叶研末撒敷，外用消毒纱布包扎之。（《福建民间草药》） 9．治跌打内伤出血：鲜紫珠叶和实60g，冰糖30g。开水炖，分2次服。（《闽东本草》） 10．治扭伤肿痛：紫珠草叶30g，鹅不食草30g，威灵仙15g。水煎服；或加松节油共捣烂外敷患处。（《青岛中草药手册》） 11．治上呼吸道感染，扁桃体炎，肺炎，支气管炎：紫珠叶、紫金牛各15g，秦皮9g。水煎服，每日1剂。（《全国中草药汇编》） 12．治赤眼：鲜紫珠草头30g。洗净切细，水2碗，煎1碗服。（《闽南民间草药》） 13．治痈肿，喉痹，蛇虫、狂犬等毒：紫荆（紫珠）煮汁服之，亦可洗。（《卫生易简方》） 14．治阴道炎，宫颈炎：150%紫珠叶溶液，每次10ml，涂抹阴道，或用阴道栓，每日1次。1星期为1疗程。（《全国中草药汇编》） 15．治瘰疬，甲状腺肿大：杜虹花根60g，三桠苦根15g。水煎服。（《福建药物志》）', tips='收敛止血；清热解毒。主呕血；咯血；衄血；便血；尿血；牙龈出血；崩漏；皮肤紫癜；外伤出血；痈疽肿毒；毒蛇咬伤；烧伤。用于衄血，咯血，胃肠出血，子宫出血，上呼吸道感染，扁桃体炎，肺炎，支气管炎；外用治外伤出血，烧伤。 ①《本草拾遗》：解诸毒物，痈疽，喉痹，毒肿，下痿，蛇虺虫螫,狂犬毒,并煮汁服;亦煮汁洗疮肿,除血长肤。 ②《福建民间草药》：活瘀，止血，消炎，解郁。 ③《浙江中药资源名录》：治脾虚，退热。研末搽皮肤痒痛，又杀虫。 ④《中国药植图鉴》：对食道静脉出血，肠胃溃疡出血，鼻出血，创伤出血，肺出血以及拔牙出血均有良效。 ⑤《闽东草药》：治崩漏带下，恶寒发热。' where id=2158; -- 紫珠
update herbs set taste='味甘；淡；寒。', channel='入心、肺、胆、胃经。', effect='①疗热渴：淡竹叶五升，茯苓、石膏（碎）各三两，小麦三升，栝楼二两。上五味，以水二斗煮竹叶，取八升，下诸药，煮取四升，去滓分温服。（《外台秘要方》竹叶汤） ②治伤寒解后，虚羸少气，气逆欲吐：竹叶二把，石膏一升，半夏（洗）半斤，人参二两，麦冬（去心）一升，甘草（炙）二两，粳米半升。（《伤寒论》竹叶石膏汤） ③治霍乱利后，烦热躁渴，卧不安：浓煮竹叶汁，饮五、六合。（《圣济总录》竹叶汤） ④治小儿心脏风热，精神恍惚：淡竹叶一握，粳米一合，茵陈半两。上以水二大盏，煮二味取汁一盏，去滓，投米作粥食之。（《圣惠方》淡竹叶粥） ⑤治产后中风发热，面正赤，喘而头痛：竹叶一把，葛根三两，防风一两，桔梗、甘草各一两，桂枝一两，人参一两，附子（炮）一枚，大枣十五枚，生姜五两。上十味以水一斗煮取二升半，分温三服。温覆使汗出。（《金匮要略》竹叶汤） ⑥治诸淋：淡竹叶、车前子、大枣、乌豆（炒，去壳）、灯心、甘草各一钱半。上作一服，用水二盏，煎至七分，去滓，不拘时温服。（《奇效良方》淡竹叶汤） ⑦治心移热于小肠，口糜淋痛：淡竹叶二钱，木通一钱，生甘草八分，车前子（炒）三钱，生地黄六钱，水煎服。（《医力简义》导赤散） ⑧治产后血气暴虚，汗出：淡竹叶，煎汤三合，微温服之，须臾再服。（《经效产宝》） ⑨治头疮乍发乍差，赤焮疼痛：竹叶一斤烧灰，捣罗为末，以鸡子白和匀，日三、四上涂之。（《圣惠方》） 10.辛凉透表，清热解毒，主治温病初起，发热无汗，或有汗不畅，微恶风寒，头痛口渴，咳嗽咽痛，舌尖红，苔薄白黄，脉象浮数。(《温病条辨》银翘散)。 11.清热生津，益气和胃，主治伤寒，温热，暑病之后，余热未清，气津两伤，身热多汗，心胸烦闷，气逆欲呕，口干喜饮，或虚烦不寐，舌红少苔，脉象虚实数。(《伤寒论》竹叶石膏汤)。 12.清营透热，养阴活血，主治邪热传营，身热夜甚，神烦少寐，时有谵语，口渴或不渴，或斑疹隐隐，舌降而干，脉数。(《温病条辨》清营汤)。 13.清心解毒，养阴生津。主治温病误汗，液伤邪陷，心包受邪，症见发热，神昏谵语等。(《温病条辨》清宫汤)。 14.透疹解表，清泄肺胃，主治痧疹透发不畅，喘嗽，烦闷躁乱，咽喉肿痛者。(《先醒斋医学广笔记》竹叶柳蒡汤)。 15.清心养阴，利水通淋，主治心经热盛，心胸烦热，口渴面赤，意欲冷饮，以及口舌生疮，或心热移于小肠，症见小溲赤涩刺痛。(《小儿药证直诀》导赤散)。 16.宣畅气机，清利湿热，用治湿温初起及暑温夹湿。(《温病条辨》三仁汤)。 17.凉血止血，利水通淋，主治下焦瘀热，而致血淋，尿中带血，小便频数，赤涩热痛，或尿血，舌红脉数。(《济生方》小蓟饮子)。 18.治眼赤：竹叶10g，黄连4枚，青钱20文，大枣（去皮核）20枚，栀子7枚，车前草10g。上6味，以水4升，煮取1升以洗眼，每日6-7遍。忌猪肉。方中竹叶清热除烦，为君药。（《外台秘要》竹叶汤） 19.治诸淋：竹叶、车前子、大枣、乌豆（炒、去壳）、灯心、甘草各4.5g。上为1服，用水2盏，煎至七分，去渣，不拘时温服。方中竹叶清热除烦，利尿，为君药。（《奇效良方》竹叶汤）' where id=2159; -- 竹叶
update herbs set effect='①治卒中风口歪：大皂荚一两（去皮、子，研末下筛）。以三年大酢和，左歪涂右，右歪涂左，干更涂之。（《千金方》） ②治头风头痛，暴发欲死：长皂荚一挺（去皮、弦、于）。切碎，蜜水拌微炒，研为极细末。每用一、二厘吹入鼻内，取嚏；再用一分，以当归川芎各一钱，煎汤调下。（《余居士选奇方》） ③治痰喘咳嗽：长皂荚三条（去皮、子），一荚入巴豆十粒，一荚入半夏十粒，一荚入杏仁十粒，用姜汁制杏仁，麻油制巴豆，蜜制半夏，一处火炙黄色，为末。每用一字，临卧以姜汁调下。（《余居士选奇方》） ④治大肠风毒，泻血不止：皂荚（长一尺二寸者）五挺（去黑皮，涂酥三两，炙尽为度），白羊精肉十两。上药，先捣皂荚为末，后与肉同捣令熟，丸如梧桐子大。每于食前以温水下二十丸。（《圣惠方》） ⑤治便毒痈疽：皂角（用尺以上者）一条，法醋煮烂，研成膏，敷之。（《仁斋直指方》） ⑥治大风诸癞：长皂角二十条。炙，去皮子，以酒煎稠，滤去渣，候冷，入雪糕，丸如梧子大。每酒下五十丸。（《仁斋直指方》皂角丸） ⑦治风癣疥癞或皮肤麻木，死肌，风痹顽皮等证：大皂荚二十条（去皮、子、弦）。切碎，水十五碗，熬成稠膏。每日用少许搽患处；再以十茶匙枸杞子汤调服。（《马敬思自得录方》）' where id=2160; -- 皂荚
update herbs set alias='苏子，黑苏子，野麻子、铁苏子。', taste='味辛；性温。', channel='入肺、大肠经。', effect='①治小儿久咳嗽，喉内痰声如拉锯，老人咳嗽吼喘：苏子一钱，八达杏仁一两（去皮、尖），年老人加白蜜二钱。共为末，大人每服三钱，小儿服一钱，白滚水送下。（《滇南本草》苏子散） ②治气喘咳嗽，食痞兼痰：紫苏子、白芥子、萝卜子。上三味，各洗净，微炒，击碎，看何证多，则以所主者为君，余次之，每剂不过三钱，用生绢小袋盛之，煮作汤饮，随甘旨，代茶水吸用，不宜煎熬太过。若大便素实者，临服加熟蜜少许，若冬寒，加生姜三片。（《韩氏医通》三子养亲汤） ③顺气、滑大便：紫苏子、麻子仁。上二味不拘多少，研烂，水滤取汁，煮粥食之。（《济生方》紫苏麻仁粥） ④治脚气及风寒湿痹，四肢挛急，脚踵不可践地：紫苏子二两，杵碎，水二升，研取汁，以苏子汁煮粳米二合作粥，和葱、豉、椒、姜食之。（《圣惠方》） ⑤治消渴变水，服此令水从小便出：紫苏子（炒）三两，萝卜子（炒）三两。为末，每服二钱，桑根白皮煎汤服，日二次。（《圣济总录》） ⑥治食蟹中毒：紫苏子捣汁饮之。（《金匮要略》）' where id=2161; -- 紫苏子
update herbs set taste='味苦；辛；性微温。', channel='入肝、脾经。', effect='①治经候微少，渐渐不通，手足骨肉烦痛，日就羸瘦，渐生潮热，其脉微数：泽兰叶三两，当归、白芍药各一两，甘草半两。上为粗末。每服五钱匕，水二盏，煎至一盏，去滓温服，不以时。（《鸡峰普济方》泽兰汤） ②治经闭腹痛：泽兰、铁刺菱各三钱，马鞭草、益母草各五钱，土牛膝一钱。同煎服。（《浙江民间草药》） ③治产后水肿，血虚浮肿：泽兰、防己等分为末。每服二钱，酸汤下。（《随身备急方》） ④治产后阴翻，产后阴户燥热，遂成翻花：泽兰四两，煎汤熏洗二、三次，再入枯矾煎洗之。（《濒湖集简方》） ⑤治小儿褥疮：嚼泽兰心封之。（《子母秘录》） ⑥治疮肿初起，及损伤瘀肿：泽兰捣封之。（《濒湖集简方》） ⑦治痈疽发背：泽兰全草二至四两，煎服；另取鲜叶一握，调冬蜜捣烂敷贴，日换两次。（《福建民间草药》） ⑧治蛇咬伤：泽兰全草二至四两，加水适量煎服；另取叶一握捣烂，敷贴伤口。（《福建民间草药》）' where id=2162; -- 泽兰
update herbs set taste='苦；寒', channel='入心包络、肝经。', effect='①发斑疹：钩藤钩子、紫草茸各等分。上为细末，每服一字或五分、一钱，温酒调下，无时。（《小儿药证直诀》紫草散） ②治疮疹才初出，便急与服之，令毒减轻可：紫草（去粗梗）二两，陈橘皮（去白，焙干）一两。上为末，每服一大钱，水一盏，入葱白二寸，煎至六分，去渣温服，无时。乳儿与乳母兼服之，断乳令自服。（《小儿卫生总微论方》紫草如圣汤） ③预防麻疹：紫草三钱，甘草一钱。水煎，日服二次。（《吉林中草药》） ④治过敏性紫癜：紫草五钱，蝉蜕二钱，当归四钱，竹叶三钱，西河柳三钱，牛蒡子三钱，黄柏三钱，知母三钱，苦参三钱。水煎服。（新疆中草药手册》） ⑤治血小板减少性紫癜：紫草二钱，海螵蛸五钱，茜草二钱。水煎服。（《新疆中草药手册》） ⑥治热疮：紫草茸、黄连、黄柏、漏芦各半两，赤小豆、绿豆粉各一合。上药捣细，入麻油为膏，日三敷，常服黄连阿胶丸清心。（《仁斋直指方》紫草膏） ⑦治小儿胎毒，疥癣，两眉生疮，或延及遍身瘙痒，或脓水淋沥，经年不愈：紫草、白芷各二钱，归身五钱，甘草一钱，麻油二两。同熬，白芷色黄为度，滤清，加白蜡、轻粉各二钱，取膏涂之。（《疡医大全》紫草膏） ⑧治火烫，发泡腐烂：紫草一钱，当归五钱，麻油四两。上三味，同熬药枯，滤清去渣，将油再熬，加黄蜡五钱，熔化，倾入碗内，顿冷，涂之。（《幼科金针》紫草润肌膏） ⑨治痈疽便闭：紫草、栝楼等分。新水煎服。（《仁斋直指方》） ⑩治小便卒淋：紫草一两。为散，每食前用井华水服二钱。（《千金翼方》） ⑾治血淋：紫草、连翘、车前子各等分，水煎服。（《证治准绳》） ⑿治吐血衄血不大凶，亦不尽止，起居如故���软食如常，一岁之间，或发二、三次，或发五、六次，久必成痨：紫草、怀生地各四两，白果肉百个，茯苓、麦门冬各三两。煎膏，炼蜜收，每早、晚各服十余匙，白汤下。（《方脉正宗》） ⒀治五疸热黄：紫草三钱，茵陈草一两。水煎服。（《本草切要》） ⒁治赤游丹毒，红晕如云头：用小锋刀或磁碗锋画去毒血，紫草五钱，鼠粘子一两。研细，水煎服。（《本草汇言》） ⒂治小儿白秃：紫草煎汁涂之。（《圣惠方》） ⒃治豌豆疮，面齄，恶疮，瘑癣：紫草煎油涂之。（《医学入门》） ⒄治恶虫咬：油浸紫草涂之。（《圣惠方》）' where id=2163; -- 紫草
update herbs set taste='味甘；咸；性温。', channel='入肺、肝、肾经。', effect='①治劳瘵虚损，骨蒸等症：紫河车一具（洗净，杵烂），白茯苓半两，人参一两，干山药二两。上为末，面糊和入河车，加三味，丸梧子大。每服三、五十丸。空心米饮下，嗽甚，五味子汤下。（《妇人良方》河车丸） ②治五劳七伤，吐血虚瘦：初生胞衣，长流水洗去恶血，待清汁出乃止，以酒煮烂，捣如泥，入白茯神末，和丸梧子大，每米饮下百丸，忌铁器（《朱氏集验医方》） ③治无子，月水不调，小产，难产，其补阴之功极重。久服耳聪目明，须发乌黑：紫河车一具（米泔洗净，新瓦焙干，或以淡酒蒸熟，捣晒研末），败龟版（童便浸三日，酥炙黄）二两，黄柏（去皮，盐酒浸炒）一两半，杜仲（去皮，酥炙）一两半，牛膝（去苗，酒浸晒）一两二钱，生地黄二两半（入砂仁六钱，白茯苓二两，绢袋盛，入瓦罐酒煮七次，去茯苓、砂仁不用，杵地黄为膏听用），天门冬（去心），麦门冬（去心），人参（去芦）各一两二钱。夏月加五味子七钱。各不犯铁器，为末，同地黄膏入酒、米糊丸入小豆大。每服八、九十丸，空心盐汤下，冬月酒下。女人带下，并加牡蛎粉一两。（《诸证辨疑》大造丸） ④治久癫失志，气虚血偌者：紫河车治净，煮烂食之。（《刘氏经验方》） ⑤治乳汁不足：紫河车一个，去膜洗净，慢火炒焦，研末，每日晚饭后服五分至一钱。（《吉林中草药》）' where id=2164; -- 紫河车
update herbs set alias='珠牡、珠母，明珠母。', taste='味甘；咸；性寒。', channel='味甘；咸；性寒。', effect='①治肝阳上升，头晕头痛，眼花耳呜，面颊燥热:珍珠母五钱至一两，制女贞、旱莲草各三钱。水煎服。（《常用中草药图谱》） ②治心悸失眠:珍珠母五钱至一两，远志一钱，酸枣仁三钱，炙甘草一钱五分。水煎服。（《常用中草药图谱》） ③治内眼疾患（晶体混浊，视神经萎缩）:珍珠母二两，苍术八钱，人参一钱。水煎，日服二次。（《吉林中草药》） ③治化脓性伤口感染和疖疮。珍珠层粉、炉甘石、龙骨、赤石脂、轻粉。研极细末，每3克加入冰片0.6克，外敷患处。（《中药临床应用》珍珠散） ④主治高血压。取珍珠母适量，研成细粉。1次3克，每天3次，开水冲服。（《高血压冠心病单验方》单味方）' where id=2165; -- 珍珠母
update herbs set alias='败棕子，棕树果。', taste='味苦；甘；涩；性平。', effect='①治高血压，多梦遗精：棕树果二钱至一两。水煎服。（《云南中草药》）', tips='止血；涩肠；固精。主肠同；崩漏；带下；泻痢；遗精。 ①《本草拾遗》：涩肠，止泻痢、肠风、崩中、带下，养血。' where id=2166; -- 棕榈子
update herbs set alias='暂无皂荚，鸡栖子，皂角，猪牙皂角，牙皂，乌犀，小皂，眉皂、小皂荚。', taste='辛咸，温，有毒。', channel='入肺、胃、大肠经。', effect='①治卒中风，风涎潮于上膈，痹气不通，昏昏若醉，形体惛闷，四肢不收，或倒或不倒，或口角似利微有涎出：猪牙皂角四挺（削去黑皮），晋矾一两。二味同捣罗为细末，再研为散，如有患者，可服半钱，重者三字匕，温水调灌下，不大呕吐，只是微微涎稀冷出，或一升二升，当时惺惺，次缓而调治，不可便大段吐之，恐过，伤人命。（孙用和救急稀涎散） ②治中风口噤不开，涎潮壅上：皂角一挺（去皮），猪脂涂炙黄色，为末，每服一钱，温酒调下，气壮者二钱，以吐出风涎为度。（《简要济众方》） ③治诸窍不通，因气、因痰、因风、因火，暴病闭塞者：猪牙皂荚（去皮、弦、子，炒），为细末，吹入鼻内即通。（《本草汇言》） ④治卒头痛：皂荚末吹鼻中，令嚏则止。（《斗门方》） ⑤治脑宣：皂角（去皮、弦、子）蜜炙捶碎，水中揉成浓汁，熬成膏子，鼻内搐之，口中咬箸，良久涎出为度。（《儒门事亲》） ⑥治风邪痫疾：皂荚（烧存性）四两，苍耳根茎叶（日干）四两，密陀僧一两。为末，成丸梧子大，朱砂为衣，每服三四十丸。枣汤下，日二服，稍退，只服二十丸。（《永类钤方》抵柱丸） ⑦治急喉闭，逡巡不救：皂荚（去皮子）生半两，为末，每服少许，以箸头点肿处，更以醋调药末，厚敷项下，须臾便破，少血出即愈。（《灵苑方》） ⑧治咽喉肿痛：牙皂一挺（去皮，米醋浸炙七次，勿令太焦）。为末，每吹少许，八咽吐涎即止。（《圣济总录》） ⑨治咳逆上气，时时唾浊，但坐不得眠：皂荚八两（刮去皮，用酥炙）末之，蜜丸梧子大，以枣膏和汤服三丸，日三夜一服。（《金匮要略》皂荚丸） ⑩治一切阳邪积滞，凡气积、血积、虫积、食积、伤寒、实热秘结等证：牙皂角（耖微黄）一两六钱，川大黄一斤。上为末，用汤浸蒸饼捣丸，绿豆大，每用五分或一钱、或二、三钱，酌宜用引送下，或用蜜为丸亦可。（《景岳全书》百顺丸） ⑾治大小便不通，关格不利：烧皂荚细研，粥饮下三钱。（孙思邈） ⑿治霍乱转筋：皂荚末，吹一小豆入鼻中，得嚏便瘥。（《梅师集验方》） ⒀治足上风疮作痒甚者：皂角炙热烙之。（《纲目》） ⒁治肾风阴痒：稻草烧皂角，烟熏十余次，即止。（《济急仙方》） ⒂治卒外肾偏疼：皂荚和皮为末，水调敷之。（《梅师集验方》） ⒃治鼻齆：炙皂荚，末之，如小豆，以竹管吹鼻中。（《千金方》） ⒄治小儿头疮粘肥及白秃：皂角烧黑，为末，去痂敷之。（《卫生杂兴》） ⒅治吹乳：猪牙皂角（去皮、弦），蜜炙为末，酒调服之。（《袖珍方》） ⒆治风热牙痛：皂角一挺，去子，入盐满壳，仍加白矾少许，黄泥固济，煅研，每日擦之。（《杨诚经验方》） ⒇治脚气肿痛：皂角、赤小豆。为末。酒醋调贴肿处。（《永类钤方》）', tips='体弱者及孕妇忌服。孕妇及咯血、吐血患者禁用。 恶麦门冬。畏空青、人参、苦参。 ②《品汇精要》：妊娠不可服。 ③《本草备要》：年老气虚人忌用。 ④《得配本草》：阴虚痰盛，热极生风者禁用。' where id=2167; -- 猪牙皂
update herbs set taste='辛，温。', channel='入肺、脾经。', effect='①治伤风发热：苏叶、防风、川芎各一钱五分，陈皮一钱，甘草六分。加生姜二片煎服。（《不知医必要》苏叶汤） ②治卒得寒冷上气：干苏叶三两，陈橘皮四两，酒四升煮取一升半，分为再服。（《补缺肘后方》） ③治咳逆短气：紫苏茎叶（锉）一两，人参半两。上二味，粗捣筛，每服三钱匕，水一盏，煎至七分，去滓，温服，日再。（《圣济总录》紫苏汤） ④治伤寒啘不止：赤苏一把，水三升，煮取二升，稍稍饮。（《补缺肘后方》） ⑤治胎气不和，凑上心腹，胀满疼痛，谓之子悬：大腹皮、川芎、白芍药、陈皮（去白）、紫苏叶、当归（去芦，酒浸）各一两，人参、甘草（炙）各半两。上细切，每服四钱，水一盏半，生姜五片，葱白七寸，煎至七分，空心温服。（《济生方》紫苏饮） ⑥治乳痈肿痛：紫苏煎汤频服，并捣封之。（《海上仙方》） ⑦治金疮出血：嫩紫苏叶、桑叶，同捣贴之。（《永类钤方》） ⑧治攧扑伤损：紫苏捣敷之，疮口自合。（《谈野翁试验方》） ⑨治蛇虺伤人：紫苏叶捣汁饮之。（《千金方》） ⑩治食蟹中毒：紫苏煮汁饮之。（《金匮要略》） ⑾治伤风发热；苏叶、防风、川芎各4.5g，陈皮3g，甘草1.8g。加生姜2片煎服。方中紫苏解表散寒。（《不知医必要》苏叶汤） ⑿治子悬胎气不和，胀满疼痛，兼临产惊恐，气结连日不下：紫苏茎叶30g，大腹子、人参、川芎、陈皮、白芍药各15g，当归9g，炙甘草3g。水煎服。方中紫苏行气和胃。（《普济本事方》紫苏饮） ⒀治肺感风寒咳嗽：紫苏叶、桑白皮（蜜炙）、青皮、五味子、炒杏仁、麻黄、炙甘草各等份。为末，每次6g，水煎服。方中紫苏解表散寒。（《普济本事方》紫苏散）' where id=2168; -- 紫苏叶
update herbs set alias='韶脑，潮脑，脑子，油脑、树脑。', taste='辛；热；有小毒', channel='心；脾经', effect='①治痧秽腹痛：㈠樟脑一分，净没药二分，明乳香三分。研匀，茶调服三厘。（《本草正义》）㈡精制樟脑10克，白兰地或高梁酒50毫升。浸一天，溶解后，每次服1毫升。（《现代实用中药》） ②治脚气肿痛：樟脑二两，乌头三两。为末，醋糊丸，弹子大。每置一丸于足心踏之，下以微火烘之，衣被围覆，汗出如涎为效。（《医林集要》） ③治疥疮有脓者：樟脑八钱，硫黄一钱五分，川椒一钱（炒），枯矾-钱。共研末，真芝麻油调匀，不可太稀，摊在新粗夏布上，包好，线扎紧，先将疥疮针刺去脓，随以药包炭火烘热，对患处按之，日按数次，俟其不能复赶脓，用药包乘热擦之。（《不知医必要》樟脑散） ④治小儿秃疮：韶脑一钱，花椒二钱，脂麻二两。为末，洗后搽之。（《简便单方》） ⑤治大人小孩满口糜烂：樟脑三钱，花椒二钱。共研末，置铜锅内，用碗盖好，并用盐泥将碗周围敷好，置火上数分钟，药升至碗上，刮取，吹入口中。（《贵州中医验方》） ⑥治远年烂脚，皮蛀作痒，臭腐疼痛，日渐痒大，难以收敛：樟脑、黄柏（末）各等分。再取豆粞一撮，和匀涂患处，用布扎紧七日，患处作痒忍之，数日则愈。（《中医杂志》25：10，1927） ⑦治臁疮：樟脑五、六钱，猪脂油，葱白。共捣烂，厚敷疮上，油纸裹好，旧棉花扎紧，一日一换，不可见风。（《经验广集》樟脑膏） ⑧治疬疮溃烂，牵至胸前两腋，块如芥子大，或牵至两眉上，四、五年不能疗者：樟脑三钱，雄黄三钱。为末。先用荆芥根下一段，剪碎，煎沸汤，温洗良久，看烂破处紫黑，以针一刺去血，再洗三、四次，然后用樟脑、雄黄末，麻油调，扫上，出水，次日再洗扫，以愈为度。专忌酒色。（《洞天奥旨》樟脑丹） ⑨治汤火疮、定痛：樟脑合香油研敷，如疮湿，干掺上止痛，火毒不入内也。（《品汇精要》） ⑩治冻疮：潮脑三钱，猪脂一两。先将猪脂炼好，去渣，再将炼好之猪油倾入锅内，下潮脑，微火炼十余分钟下锅，冷为膏，用瓶装好，封口备用，敷三、五次即愈。（《健康报》1958年10月26日） ⑾治牙痛：韶脑一钱，朱砂一钱。为末，每用少许搽疼处。（《神效方》） ⑿治牙齿虫痛：樟脑、黄丹、肥皂（去皮、核）等分。研匀，蜜丸，塞孔中。（《余居士选奇方》）' where id=2169; -- 樟脑
update herbs set alias='蜚蠊，蜚、蠦蜰，飞蟅，负盘（《尔雅》郭瑛注），石姜，滑虫，茶婆虫、香娘子，赃郎，偷油婆，酱虫，黄贼。', taste='味咸；性寒', effect='①治儿疳初起：蟑螂，去头、足、翅，新瓦焙干，常与食之。（《百草镜》） ②治臌胀：蟑螂一个（焙干），萝卜子一撮。共炒为末，好酒吞。（《周益生家宝方》） ③治疔疮：蟑螂大者七个，去头、足，壳，将砂糖少许，同捣烂，敷疔四围，露出头。（《纲目拾遗》） ④解诸疔毒：灶上红蟑螂五个。研烂，热酒冲服。取汗为度。（《养素园传信方》） ⑤治喉蛾：偷油婆、人指甲（煅）、开喉箭。为末吹喉。（《四川中药志》） ⑥治白火丹：蟑螂，瓦上焙干，为末，白滚汤服一、二个。兼治疔疮。（《纲目拾遗》） ⑦治对口：桂州荔枝肉二、三枚，蟑螂二、三个。同捣如泥，敷，露头。（《慈航活人书》） ⑧治无名肿毒：蟑螂十个，盐一撮。同捣烂敷之，留头。（《慈航活人书》） ⑨治吐血：蟑螂五个，止去翅净，在火盆净瓦上焙干，为末，用湿腐皮包一个，滚汤吞下。每日如此，吞五日，不可间断。（《纲目拾遗》） ⑩治梅毒：偷油婆、蛞蝓。焙焦，研末，兑猪胆汁服。（《四川中药志》） ⑾治蜈蚣及蛇、虫咬伤：偷油婆、剪刀草、海椒叶。共捣绒涂。（《四川中药志》）' where id=2170; -- 蟑螂
update herbs set taste='寒；苦.', effect='①治伤风，肺有实痰、实火，肺热咳嗽： 栀子花三朵。蜂蜜少许同煎服。(《滇南本草》) ②治鼻血不止： 栀子花数片，焙干为末，吹鼻。(《滇南本草》)', tips='清肺止咳；凉血止血。主肺热咳嗽；鼻衄' where id=2171; -- 栀子花
update herbs set taste='甘苦，寒。', channel='入心、胃经，', effect='①治中风口噤不知人：淡竹沥一升服。（《千金方》） ②治风痱四肢不收，心神恍惚，不知人，不能言：竹沥二升，生葛汁一升，生姜汁三合。上三味相和温暖，分三服，平旦、日晡、夜各一服。（《千金方》竹沥汤） ③治卒消渴，小便多：作竹沥恣饮数日愈。（《肘后方》） ④治产后身或强直，口噤面青，手足强反张：饮竹沥一、二升。（《梅师集验方》） ⑤主妊娠恒若烦闷，此名子烦：茯苓三两，竹沥一升，水四升，合竹沥煎取二升，分三服，不差重作，亦时时服竹沥。（《梅师集验方》竹沥汤） ⑥治小儿惊风天吊，四肢抽搐：竹沥一盏，加生姜汁三匙，胆星末五分，牛黄二厘调服。（《全幼心鉴》） ⑦治小儿口噤，体热：用竹沥二合，暖之，分三、四服。（《兵部手集方》） ⑧治乙脑、流脑高热，呕吐：竹沥代茶饮。（江西《中草药学》） ⑨治金疮中风，口噤欲死：竹沥半大升，微微暖服之。（《广利方》） ⑩治小儿大人咳逆短气，胸中吸吸，咳出涕唾，嗽出臭脓涕粘：淡竹沥一合服之，日三、五服，大人一升。（《兵部手集方》） ⑾治小儿吻疮：竹沥和黄连、黄檗、黄丹，敷之。（《全幼心鉴》） ⑿治小儿赤目：淡竹沥点之，或入人乳。（《古今录验方》） ⒀治小儿重舌：竹沥渍黄檗，时时点之。（《简便单方》）', tips='寒嗽及脾虚便溏者忌服。 ②《本草经疏》：寒痰湿痰及次食生痰不宜用。 ③《本草备要》：寒胃滑肠，有寒湿者勿服。' where id=2172; -- 竹沥
update herbs set effect='①治感冒咳嗽：浙贝母、知母、桑叶、杏仁各三钱，紫苏二钱，水煎服，（《山东中草药手册》） ②治痈毒肿痛：浙贝母、连翘各三钱，金银花六钱，蒲公英八钱，水煎服。（《山东中草药手册》） ③治咽喉十八症；大黑枣每个去核，装入五倍子（去虫，研）一个、象贝（去心，研）一个。用泥裹，煨存性，共研极细末，加薄荷叶末少许，冰片少许，贮瓷瓶内。临用吹患处，任其呕出痰涎。（《经验广集》吹喉散） ④治对口：象贝母研末敷之。（《杨春涯经验方》）' where id=2173; -- 浙贝母
update herbs set taste='甘，平。', effect='①治各种痞结：藏红花每服一朵，冲汤下。忌食油荤、盐，宜食淡粥。（《纲目拾遗》） ②治伤寒发狂，惊怖恍惚：撒法即二分。水一盏，浸一宿，服之。（《医林集要》） ③治吐血（不论虚实、何经所吐之血），藏红花一朵，无灰酒一盏。将花入酒内，隔汤顿出汁服之。（《纲目拾遗》）' where id=2174; -- 藏红花
update herbs set taste='性微寒，味甘。', channel='入胃、胆经。', effect='①治哕逆：橘皮二斤，竹茹二升，大枣三十枚，生姜半斤，甘草五两，人参一两。上六味，以水一斗，煮取三升，温服一升，日三服。（《金匮要略》橘皮竹茹汤） ②治妊娠恶阻呕吐，不下食： 青竹茹、橘皮各十八铢，茯芩、生姜各一两，半夏三十铢。上五味以水六升，煮取二升半，分三服，不瘥，频作。（《千金方》） ③治妇人乳中虚，烦乱呕逆，安中益气：生竹茹二分，石膏二分，桂枝一分，甘草七分，白薇一分。上五味，末之，枣肉和丸弹子大。以饮服一丸，日三夜二服。有热者倍白薇，烦喘者加柏实一分。（《金匮要隙》竹皮大丸） ④治产后虚烦，头痛短气欲绝，心中闷乱不解：生淡竹茹一升，麦门冬五合，甘草一两，小麦五合，生姜三两，大枣十四枚。上六味以水一斗，煮竹茹、小麦，取八升，去滓，乃纳诸药，煮取一升，去滓，分二服，羸人分作三服。（《千金方》淡竹茹汤） ⑤治大病后，虚烦不得眠：半夏（汤洗七次）、竹茹、枳实（麸炒，去穰）各二两，陈皮三两，甘草一两（炙），茯苓一两半。上为锉散，每服四大钱，水一盏半，姜五片，枣一枚，煎七分，去滓，食前服。（《三因方》温胆汤） ⑥治伤暑烦渴不止：竹茹一合（新竹者），甘草一分（锉），乌梅两枚（椎破）。上三味，同用水一盏半，煎取八分，去滓放温，时时细呷。（《圣济总录》竹茹汤） ⑦治肺热咳嗽，咳吐黄痰：竹二青三钱。水煎服。（《上海常用中草药》） ⑧治小儿痫：青竹茹三两，醋三升，煎一升，去滓，服一合。兼治小儿口噤体热病。（《子母秘录》） ⑨治妇人病未平复，因有所动，致热气上冲胸，手足拘急搐搦，如中风状：栝楼根二两，淡竹茹半升。上以水二升半，煮取一升二合，去滓，分作二、三服。（《类证活人书》青竹茹汤） ⑩治齿龈间血出不止：生竹茹二两，醋煮含之。（《千金方》） ⑾治黄泡热疮：真麻油二两，青木香二两，青竹茹一小闭，杏仁二十粒（去皮、尖）。上药入麻油内，慢火煎令杏仁黄色，去渣，入松脂（研）半两，熬成膏，每用少许擦疮上。（《济生方》竹茹膏）' where id=2175; -- 竹茹
update herbs set taste='辛甘，微温。', channel='归脾；胃；肺经。', effect='①治伤寒胸中痞满，心腹气滞，不思饮食：紫苏茎（锉）一两，陈橘皮（汤浸去白，焙）二两，赤茯苓（去黑皮）一两半，大腹皮（锉）、旋覆花各一两，半夏（汤洗七遍，焙）半两。上六味，细切如麻豆大，每服五钱匕，水一盏半，入生姜一分（拍碎），枣三枚（擘破），同煎至七分，去渣，温服。（《圣济总录》苏橘汤） ②治水肿：紫苏梗八钱，大蒜根三钱，老姜皮五钱，冬瓜皮五钱。水煎服。（《湖南药物志》）', tips='理气，舒郁，止痛，安胎。治气郁，食滞，胸膈痞闷，脘腹疼痛，胎气不和。 ①《本草图经》：宣通风毒。 ②《本草蒙筌》：下诸气略缓，体稍虚者用宜。 ③《本草通玄》：能行气安胎。 ④《本草崇原》：主宽中行气，消饮食，化痰涎。治噎膈反胃，止心腹痛。 ⑤《得配本草》：疏肝，利肺，理气，和血，解郁，止痛，定嗽，安胎。' where id=2176; -- 紫苏梗
update herbs set taste='味甘；淡；性寒。', channel='入肾、膀胱经。', effect='①治臌胀水肿：白术、泽泻各半两。上为细末，煎服三钱，茯苓汤调下，或丸亦可，服三十丸。（《素问病机保命集》白术散） ②治心下有支饮，其人苦冒眩：泽泻五两，白术二两。上二味，以水二升，煮取一升，分温服。（《金匮要略》泽泻汤） ③治冒暑霍乱，小便不利，头晕引饮：泽泻、白术、白茯苓各三钱。水-盏，姜五片，灯心十茎，煎八分，温服。（《纲目》三白散） ④治妊娠遍身浮肿，上气喘急，大便不通，小便赤涩：泽泻，桑白皮（炒）、槟榔、赤茯苓各五分。姜水煎服。（《妇人良方》泽泻散） ⑤治湿热黄疸，面目身黄：茵陈、泽泻各一两，滑石三钱。水煎服。（《千金方》） ⑥治寒湿脚气，有寒热者：泽泻、木瓜、柴胡、苍术、猪苓，木通、萆薢各五钱。水煎服。（《外科正宗》） ⑦治小儿齁蛤，膈上壅热，涎潮：泽泻一分，蝉衣（全者）二十一个，黄明胶（手掌大一片，炙令焦）。上为细末.每服一钱，温米汤调下，日进二服，未愈再服。（《宣明论方》，泽泻散） ⑧治酒风，身热解惰，汗出如浴，恶风少气：泽泻、术各十分，麋衔五分。合，以三指撮，为后饭。（《素问》） ⑨治风虚多汗，恶风寒颤：泽泻、防风（去皮）、牡蛎（煅赤）、苍术（米泔浸，去皮，炒）各一两，桂（去租皮）三分。上五味，捣罗为细散。每服二钱匕，温粥饮调下，不计时。（《圣济总录》泽泻散） ⑩治肾脏风生疮：泽泻、皂荚，水煮烂，焙干为末，炼蜜为丸，如桐子大。空心，以温酒下十五丸至二十丸。（《经验方》） ⑾治虚劳膀胱气滞，腰中重，小便淋：泽泻一两，牡丹三分，桂心三分，甘草三分（炙微赤，锉），榆白皮三分（锉），白术三分，赤茯苓一两，木通一两（锉）。上药粗捣罗为散。每服三钱，以水一中盏，煎至六分，去滓，食前温服。（《圣惠方》泽泻散） ⑿治五种腰痛：泽泻半两，桂（去粗皮）三分，白术、白茯苓（去黑皮）、甘草（炙，锉）各一两，牛膝（酒浸，切，焙）、干姜（炮）各半两，杜仲（去粗皮，锉，炒）三分。上八味，粗捣筛。每服三钱匕，水一盏，煎至七分，去滓，空心、日午，夜卧温服。（《圣济总录》泽泻汤） ⒀水湿肿胀。用白术、泽泻各一两，共三工业区末，或做成丸子。每服三钱，茯苓汤送下。 ⒁暑天吐泻（头晕，渴饮，小便不利）。用泽泻、白术，白茯苓各三钱，加水一碗、姜五片、类灯心十根，煎至八成，温服。' where id=2177; -- 泽泻
update herbs set taste='甘，温。', channel='入肺，肾经。', effect='①治肺虚壅喘急，连绵不息：生钟乳五两（细研如粉），黄蜡三两（锉）。上二味，先职黄蜡盛于细瓷器，用慢火化开，投入钟乳粉末，搅和令匀，取出，用物封盖定，于饭甑内蒸熟，研如膏，旋丸如梧桐子大。每服一、二丸，温水下。（《圣济总录》钟乳丸） ②治五劳七伤，损肺气，阳气绝，手足冷，心中少气，髓虚腰疼脚痹，身烦口干不能食：钟乳二两（别研令细），菟丝子一两（酒浸一宿，别捣），石斛一两，吴茱萸半两。上四味，别捣筛为末，炼蜜丸如梧子。空腹服七丸，日再服之讫，行数百步，温清酒三合饮之，复行二、三百步，口胸内热，热如定，即食干饭豆酱；过一日，食如常，暖将息。（《千金翼方》草钟乳丸） ③治积冷上气，坐卧不得，并风虚劳损，腰脚弱：钟乳三两，研如面，以夹帛练袋盛，稍宽容，紧系头，纳牛奶一大升中煎之，三分减一分即好，去袋空（腹）饮乳汁。若患冷人，即用酒蒸，患热人即用水煎。若用水及酒例须减半。不可啖热面、猪、鱼、蒜等。（《崔氏纂要方》乳煎钟乳） ④治虚损，通顺血脉，极补下气：钟乳五两，附子、甘菊各二两，石斛、苁蓉各五两。上五味，以清酒三斗渍。服二合，日再，稍增至一升。（《千金方》钟乳酒） ⑤治无乳汁：石钟乳、漏芦各二两。上二味，治下筛。饮服方寸匕。（《千金方》） ⑥治吐血损肺：炼成钟乳粉，每服二钱，糯米汤下。（《十便良方》） ⑦治大肠冷滑不止：钟乳粉一两，肉豆蔻（煨）半两。为末，煮枣肉丸梧子大。每服七十丸，空心米饮下。（《济生方》）', tips='阴虚火旺肺热咳嗽者忌服。 畏紫石、蘘草。殷孽，恶防己，畏术。 ②《药性论》：忌羊血。' where id=2178; -- 钟乳石
update herbs set effect='①治小儿惊风，大人中风：竹黄，煎服效。 ②治胃气痛：竹黄一两，烧酒一斤，共浸泡三、五天。每日服二次，每次服一小酒盅。' where id=2179; -- 竹黄
update herbs set taste='辛，温。', effect='①治痈疽恶毒，外发内发，欲破未破，在四肢肩背肚腹之外者，则痛极大肿，在胸膈腰胁肚腹肠胃之内者，则痛极大胀：皂荚刺飞尖一两，乳香、没药、当归、川芎、甘草各二钱，白芷、花粉、金银花各五钱。水、酒各二碗，煎一碗半。毒在上，食后服；毒在中半饱服；毒在下空心服。未成可消，已成即溃。（《医鉴初集》） ②治癌瘭恶疮：皂角刺（烧存性，研）、白及少许，为末，敷之。（《仁斋直指方》） ③治妇人乳痈：皂角刺（烧存性）一两，蚌粉一钱。和研，每服一钱，温酒下。（《仁斋直指方》） ④治疮无头者：皂角刺（阴干烧灰），为末，每服三钱，酒调，嚼葵菜子三、五个，前药送下。（《儒门事亲》） ⑤治痔疾，肛边痒痛不止：皂荚刺二两（烧令烟尽），臭樗皮一两（微炙），防风一两（去芦头），赤芍药一两，枳壳一两（麸炒微黄，去瓤）。上药，捣罗为末，用酽醋一斤，熬一半成膏，次下余药，和丸，如小豆大，每于食前，煎防风汤下二十丸。（《圣惠方》皂荚刺丸） ⑥治腹内生疮在肠脏：皂角刺不拘多少，好酒一碗，煎至七分，温服。不饮酒者，水煎亦可。（《蔺氏经验方》） ⑦治大风疠疮，体废肢损，形残貌变者：皂角刺飞尖一斤（微炒，研为极细末），赤链蛇一条（切碎，酒煮，去骨取肉，焙），胡麻仁三两，生半夏二两，真铅粉一两。俱炒燥，研为末，和皂荚刺末，一总水泛为丸，如绿豆大，晒干，入净磁瓶内。每早晚各服三钱，白汤下。（《本草汇言》） ⑧治胎衣不下：皂角刺烧为末，每服一钱，温酒调下。（《妇人良方补遗》） ⑨治小便淋闭：皂角刺（烧存性）、破故纸等分。为末，无灰酒服。（《圣济总录》） ⑩治小儿重舌：皂角刺灰，入朴硝或脑子少许，漱口，掺入舌下，涎出自消。（《圣惠方》）' where id=2180; -- 皂角刺
update herbs set taste='苦；寒。', channel='入心、肝、肺、胃经。', effect='①治伤寒发汗、吐。下后，虚烦不得眠，心中懊憹：栀子十四个（剖），香豉四合（绵裹）。上二味，以水四升，先煮柜子得二升半，纳豉，煮取一升半，去滓，分为二服。温进一服，得吐者止后服。（《伤寒论》栀子豉汤） ②治伤寒大病瘥后劳复者：枳实三枚（炙），栀子十四个（剖），豉一升（绵裹）。上三味，以清浆水七升，空煮取四升，内枳实、栀子，煮取二升，下豉，更煮五、六沸，去滓，温分再服，覆令微似汗。若有宿食者，内大黄如博棋子五、六枚。（《伤寒论》枳实栀子豉汤） ③治伤寒身黄发热：肥栀子十五个（剖），甘草一两（炙），黄柏二两。上三味，以水四升，煮取一升半，去滓，分温再服。（《伤寒论》栀子柏皮汤） ④治湿热黄疸：山栀四钱，鸡骨草、田基黄各一两。水煎，日分三次服。（《广西中草药》） ⑤治尿淋，血淋：鲜栀子二两，冰糖一两。煎服。（《闽东本草》） ⑥治小便不通：栀子仁二七枚，盐花少许，独颗蒜一枚。上捣烂，摊纸花上贴脐，或涂阴囊上，良久即通。（《普济方》） ⑦治急性胃肠炎，腹痛，上吐下泻：山栀三钱，盘柱南五味（紫金皮）根五钱，青木香二钱。上药炒黑存性，加蜂蜜五钱。水煎，分二次服。（《单方验方调查资料选编》） ⑧治口疮、咽喉中塞痛，食不得：大青四两，山栀子、黄柏各一两，白蜜半斤。上切，以水三升，煎取一升，去滓，下蜜更煎一两沸，含之。（《普济方》栀子汤） ⑨治目赤：取山栀七枚，钻透，入煻灰火煨熟，以水一升半，煎至八合，去滓，人大黄末三钱匕，搅匀，食后旋旋温服。（《圣济总录》栀子汤） ⑩治胃脘火痛，大山栀子七枚或九枚，炒焦，水一盏，煎七分，入生姜汁饮之。（《丹溪纂要》） ⑾治鼻中衄血：山栀子烧灰吹之。（《简易方论》） ⑿治肺风鼻赤酒齄：老山栀为末，黄蜡等分溶和。为丸弹子大。空心茶、酒嚼下。忌酒、炙煿。（《本事方》） ⒀治赤白痢并血痢：山栀子仁四七枚。锉，以浆水一升半，煎至五合，去滓。空心食前分温二服。（《圣济总录》栀子仁汤） ⒁治热水肿：山栀子五钱，木香一钱半，白术二钱半。细切，水煎服。（《丹溪心法》） ⒂治妇人子肿湿多：炒山栀子一合。为末，米饮吞下，或丸服。（《丹溪心法》） ⒃治折伤肿痛：栀子、白面同捣，涂之。（《濒湖集简方》） ⒄治火丹毒：栀子，捣和水调敷之。（《梅师集验方》） ⒅治火疮未起：栀子仁灰，麻油和封，惟厚为佳。（《千金方》） ⒆治疮疡肿痛：山栀、蒲公英，银花各四钱。水煎，日分三次服。另取生银花藤适量，捣烂，敷患处。（《广西中草药》） ⒇治烧伤：栀子末和鸡子清浓扫之。（《救急方》） （21）血淋涩痛。用生栀子末、滑石等分，葱汤送服。 （22）下泻鲜血。用栀子仁烧灰，水送服一匙。 （23）热毒血痢。用栀子十四枚，去皮，捣为末，加蜜做成丸子，如梧子大。每服三丸，一天服三次，疗效显著。亦可用水煎服。 （24）临产下简。用栀子烧过。研为末，米汤送服三钱。若上焦热，则连壳用。 （25）霍乱转筋，心腹胀满，吐泻不得。用栀子十几枚，烧过，研为末，熟酒送服。 （26）热病食劳复（按：指热病之后因饮食不慎或房事不慎而使旧病复发）。用栀子三十枚，加水三升，煎取一升服下。须出微汗为好。 （27）小儿狂躁（蓄热在下，身热狂躁，昏迷不食）。用栀子仁七枚、豆豉五钱，加水一碗，煎至七成服下，或吐或不吐，均有效。 （28）眼来肠秘。用山栀子七个，钻孔煨熟，加水一程式，煎至半升，去渣，放入大黄不三钱，温服。 （29）风痰头痛。用栀子末和蜜浓敷舌上，得吐即止痛。 （30）火焰丹毒。用栀子捣烂和水涂搽。 （31）眉中练癣。用栀子烧过，研为末，调油敷涂。' where id=2181; -- 栀子
update herbs set taste='苦；辛；寒', channel='脾；胃；肝；心经', effect='①治痞，消食，强胃:白术二两，枳实（麸炒黄色，去瓤）一两。上同为极细末，荷叶裹炒，饭为丸，如梧桐子大。每服五十丸，多用白汤下，无时。（《内外伤辨》枳术丸） ②治胸痹心中痞气，气结在胸，胸满胁下逆抢心:枳实四枚，厚朴四两，薤白半升，桂枝一两，栝楼实一枚（捣）。上五味，以水五升，先煮枳实、厚朴，取二升，去滓，纳诸药，煮数沸，分温三服。（《金匮要略》枳实薤白桂枝汤） ③治卒患胸痹痛:枳实捣（末），宜服方寸匕，日三，夜一服。（《补缺肘后方》） ④治伤寒后，卒胸膈闭痛:枳实，麸炒为末。米饮服二钱，日二服。（《简要济众方》） ⑤治大便不通:枳实、皂荚等分。为末，饭丸，米饮下。（《世医得效方》） ⑥治伤湿热之物，不得施化而作痞满，闷乱不安:大黄一两，枳实（麸炒，去瓤）、神曲（炒）各五钱，茯苓（去皮）、黄芩（去腐）、黄连（拣净）、白术各三钱，泽泻二钱。上件为细末，汤浸蒸饼为丸，如梧桐子大。每服五十丸至七十九温水送下，食远，量虚实加减服之。（《内外伤辨》枳实导滞丸） ⑦治少小久痢淋沥，水谷不调，形羸不堪大汤药者:枳实二两。治下筛。三岁已上饮服方寸匕，若儿小以意服，日三。（《千金方》枳实散） ⑧治肠风下血:枳实半斤（麸炒，去瓤），绵黄耆半斤（洗，锉，为末），米饮非时下二钱匕，若难服，以糊丸，汤下三五十丸。（《经验方》） ⑨治积冷利脱肛:枳实一枚。石上磨令滑泽，钻安柄，蜜涂、炙令暖熨之，冷更易之，取缩入止。（《千金方》） ⑩治产后腹痛，烦满不得卧:枳实（烧令黑，勿太过）、芍药等分。杵为散。服方寸匕，日三服。并主痈脓，以麦粥下之。（《金匮要略》）枳实芍药散） ⑾治大病瘥后劳复:枳实三枚（炙），柜子十四个（擘），豉一升（绵裹）。上三味以清浆水七升，空煮取四升，纳枳实、栀子，煮取二升，下豉，更煮五六沸，去滓，温分再服，覆令微似汗。若有宿食者，加大黄如博棋子大五、六枚。（《伤寒论》枳实栀子豉汤） ⑿治风疹:枳实以醋渍令湿，火炙令热，适寒温用熨上。（《延年方》） ⒀治妇人阴肿坚痛:枳实半斤。碎，炒，令熟帛裹熨之，冷即易。（《子母秘录》） ⒁治小儿头疮:枳实烧灰，猪脂调涂。（《圣惠方》）' where id=2182; -- 枳实
update herbs set taste='甘咸，寒。', channel='入心、肝经。', effect='①治大人惊悸怔忡，癫狂恍惚，神志不宁，及小儿气血未定，遇触即惊，或急慢惊风，痫痓搐搦：真珠一钱（研极细末），茯苓、钩藤、半夏曲各-两，甘草、人参各六钱（同炒黄，研极细末）。总和匀，炼蜜丸龙眼核大。每服一丸，生姜汤化下。（《本草汇言》） ②治小儿惊啼及夜啼不止：真珠末、伏龙肝、丹砂各一分，麝香一钱。同研如粉，炼蜜和丸如绿豆大。候啼即温水下一丸；量大小，以意加减。（《圣济总录》真珠丸） ③治小儿中风，手足拘急：真珠末（水飞）一两，石膏末一钱。每服一钱，水七分，煎四分，温服，日三。（《圣惠方》） ④治风痰火毒、喉痹，及小儿痰搐惊风：珍珠三分，牛黄一分。上研极细，或吹或掺；小儿痰痓，以灯心调服二、三分。（《医级》珠黄散） ⑤治口内诸疮：珍珠三钱，硼砂、青黛各一钱，冰片五分，黄连、人中白各二钱（煅过）。上为细末，凡口内诸疮皆可掺之。（《丹台玉案》珍宝散） ⑥治眼久积顽翳，盖覆瞳人：真珠一两，地榆三两（锉）。以水二大盏，同煮至水尽，取出真珠，以醋浸五日后，用热水淘令无醋气，即研令极细。每以铜箸，取少许点翳上，以瘥为度。（《圣惠方》） ⑦治风热眼中生赤脉，冲贯黑睛，及有花翳：真珠一分，龙脑半分，琥珀一分，朱砂半分，硼砂二豆大。同细研如粉。每日三、五度，以铜箸取少许，点在眦上。（《圣惠方》真珠散） ⑧治一切诸毒疽疮，穿筋溃络，烂肌损骨，破关通节，脓血淋漓，溃久不收之证：真珠一钱（研极细末），胞衣一具（烘燥，研极细末）；白蜡一两，猪脂油一两，火上共熔化，和入胞衣末、真珠末，调匀。先以猪蹄汤淋洗毒疮净，将蜡油药，轻轻敷上，再以铅粉麻油膏药贴之。（《本草汇言》油蜡膏） ⑨治下疳皮损肉烂，痛极难忍，及诸疮新肉已满，不能生皮，又汤泼火烧皮损内烂，疼痛不止者：青缸花五分，珍珠一钱（研极细），真轻粉一两。上三味共研千转，细如飞面。凡下疳初起皮损，搽之；腐烂疼痛者，甘草汤洗净，猪脊髓调搽；如诸疮不生皮者，用此干掺。又妇人阴蚀疮。亦可搽。汤泼火烧痛甚者，用玉红膏调搽之。（《外科正宗》珍珠散） ⑩治发斑：珠子七个研碎，用新水调匀服之。（《儒门事亲》发斑药）' where id=2183; -- 珍珠
update herbs set taste='甘，微寒；有毒。', channel='入心经。', effect='①治风邪诸痢，狂言妄走，精神恍惚，思虑迷乱，乍歌乍哭，饮食失常，疾发扑地，口吐白沫，口噤戴眼，年岁深远者：辰砂（光明者，研）一两，酸枣仁（微炒，研），乳香（光莹者，研）各半两。上三味合研令匀，先令病人尽量饮酒沉醉，次取药五钱匕，酒一盏，调下，于静室中安睡，勿令惊动。（《圣济总录》丹砂丸） ②治喜怒无极，发狂：辰砂、白矾、郁金。为末，蜜丸。薄荷汤送下十丸。（《士材三书》辰砂丸） ③治一切惊忧思虑或梦思恍惚，作事多忘，但是一切心气不足，癫痫狂乱，悉皆治之：颗块朱砂二两，獖猪心二个，灯心三两。上将猪心切开，入朱砂、灯心在内，麻线系合，于银石器内煮一伏时出，不用猪心及灯心，只将朱砂研极细，用真茯神末二两，酒煮薄糊，和朱砂为丸，如桐子大。每服九丸至十五丸，加至二十一丸，用去心麦门冬煎汤下。癫痫至甚者，乳香、人参汤下。夜寝不寐或多乱梦，炒酸枣仁汤下。（《百一选方》归神丹） ④治产后颠狂，败血及邪气入心：辰砂一、二钱。研细飞过，用饮儿乳汁三、四茶匙调湿，以紫项地龙一条，入药滚三滚，刮净，去地龙，入无灰酒一盏，分作三、四次服。（《纲目》） ⑤治心神昏乱，惊悸怔忡，寝寐不安：朱砂、黄连各半两，当归二钱，生地黄三钱，甘草二钱。上为细末，酒泡蒸饼，丸如麻子大，朱砂为衣。每服三十丸，卧时津液下。（《医宗金鑑》朱砂安神丸） ⑥治心虚遗精：猪心一个，批片相连，以飞过朱砂末掺入，线缚：白水煮熟食之。（《唐瑶经验方》） ⑦治眼昏暗，能令彻视见远：朱砂半两（细研），青羊胆一枚。上以朱砂末入胆中，悬屋西北角，阴干，白日取出，丸如小豆大。每于食后，以粥饮下十丸。（《圣惠方》朱砂丸） ⑧明目：光明砂（丹砂中之最上者）一两，神曲四两，磁石二两。上三味末之，炼蜜为丸，如梧子大。饮服三丸，日三，不禁，常服益眼力。（《千金方》神曲丸） ⑨治喉咽肿痛，咽物妨闷：丹砂一分（研，水飞），芒硝一两半（研）。上二味再同研匀，每用一字，时时吹入喉中。（《圣济总录》丹砂散） ⑩治诸般吐血：丹砂（研飞），蛤粉。上二味等分，研细合和令匀，每服二钱匕，温洒调下。（《圣济总录》朱粉散） ⑾治沙蜂叮螫：朱砂末，水涂之。（《摘元方》）' where id=2184; -- 朱砂
update herbs set taste='甘淡；平。', channel='脾；肾；肺；膀胱经。', effect='①治脉浮发热，渴欲饮水，小便不利：猪苓（去皮）、茯苓、泽泻、阿胶、滑石（碎）各一两。上五味以水四升，先煮四味，取二升，去滓，纳阿胶烊消，温服七合，日三服。（《伤寒论》猪苓汤） ②治妊娠从脚上至腹肿，小便不利，微渴引饮：猪苓五两，末，以熟水服方寸匕，日三服。（《子母秘录》） ③治痃疟不分新久：猪苓一两，茯苓五钱，柴胡四钱，半夏三钱，甘草一钱，生姜三片，大枣二枚。水三碗，煎一碗。未发前服，渣再煎，发后服。（《方脉家宝》） ④治肠胃寒湿，濡泻无度，嗜卧不食：猪苓（去黑皮）半两，肉豆蔻（去壳，炮）二枚，黄柏（去粗皮，炙）一分。上三味捣罗为末，米饮和丸，如绿豆大，每服十丸，食前熟水下。（《圣济总录》猪苓丸） ⑤治子淋：猪苓五两。捣筛，以白汤三合，和方寸匕为一服，渐至二匕，日三夜二，尽，不瘥，宜转下之，服甘遂散。（《小品方》） ⑥治年壮气盛，梦遗白浊：半夏一两，猪苓一两。上半夏锉如豆大，猪苓为末。先将半夏炒令黄色，不令焦，地上去火毒半日，取半夏为末；以一半猪苓末调匀和丸，如桐子大，更用余猪苓末拌丸，使干，入不油砂瓶中养之。每服四十丸，空心温酒盐汤下，于申未间冷酒下。（《济生方》猪苓丸） ⑦治呕吐而病在膈上，思水者：猪苓、茯苓、白术各等分。上三味，杵为散，饮服方寸匕，日三服。（《金匮要略》猪苓散） ⑧伤寒口渴。用猪苓、茯苓、泽泻、滑石、阿胶各一两，加水四升，煮成二升。每服七合。一天服三次。此方名猪苓汤。 ⑨通身肿满，小便不利。用猪苓五两，研为还想，每服一匙，熟水送下。一天服三次。 ⑩妊娠肿渴（郐、腹皆肿，小便不利）。治方同上。' where id=2185; -- 猪苓
commit;

